CREATE VIEW dbo.MentalACT
AS
SELECT        dbo.Provider.Id, dbo.Provider.UId, dbo.Provider.PracticeId, dbo.Provider.PUserId, dbo.Provider.LastName, dbo.Provider.FirstName, dbo.Provider.Middle, dbo.Provider.Suffix, dbo.Provider.Prefix, dbo.Provider.FacilityId, 
                         dbo.Provider.IsActive, dbo.Provider.License, dbo.Provider.Signature, dbo.Provider.TOC, dbo.Provider.Slot, dbo.Provider.SSN, dbo.Provider.SpecialtyId, dbo.Provider.Specialty, dbo.Provider.BillUnderGroupNPI, 
                         dbo.Provider.CreatedBy, dbo.Provider.CreatedDate, dbo.Provider.ModifiedBy, dbo.Provider.ModifiedDate, dbo.Provider.IsDefault, dbo.Provider.Address1, dbo.Provider.Address2, dbo.Provider.City, dbo.Provider.State, 
                         dbo.Provider.ZipCode, dbo.Provider.PractitionerServiceId, dbo.Provider.IsBillUnderSupervisor, dbo.Provider.SupervisorId, dbo.Provider.SupervisionTypeId, dbo.ConfigPractitionerService.Id AS Expr1, 
                         dbo.ConfigPractitionerService.ProvidingService, dbo.ConfigPractitionerService.ProfessionalAbbreviation, dbo.ConfigPractitionerService.CPTModifier_Id, dbo.ConfigPractitionerService.IsActive AS Expr2, 
                         dbo.ConfigSupervisionType.Id AS Expr3, dbo.ConfigSupervisionType.SupervisionType, dbo.CPTModifier.Id AS Expr4, dbo.CPTModifier.VisitType, dbo.CPTModifier.Code, dbo.CPTModifier.Description, 
                         dbo.CPTModifier.IsActive AS Expr5, dbo.CPTModifier.UId AS Expr6, dbo.ConfigServiceCircumstance.Id AS Expr7, dbo.ConfigServiceCircumstance.Circumstance, dbo.ConfigServiceCircumstance.CPTModifier_Id AS Expr8, 
                         SuperVisor.Id AS Expr9, SuperVisor.UId AS Expr10, SuperVisor.PracticeId AS Expr11, SuperVisor.PUserId AS Expr12, SuperVisor.LastName AS Expr13, SuperVisor.FirstName AS Expr14, SuperVisor.Middle AS Expr15, 
                         SuperVisor.Suffix AS Expr16, SuperVisor.Prefix AS Expr17, SuperVisor.FacilityId AS Expr18, SuperVisor.IsActive AS Expr19, SuperVisor.License AS Expr20, SuperVisor.Signature AS Expr21, SuperVisor.TOC AS Expr22, 
                         SuperVisor.Slot AS Expr23, SuperVisor.SSN AS Expr24, SuperVisor.SpecialtyId AS Expr25, SuperVisor.Specialty AS Expr26, SuperVisor.BillUnderGroupNPI AS Expr27, SuperVisor.CreatedBy AS Expr28, 
                         SuperVisor.CreatedDate AS Expr29, SuperVisor.ModifiedBy AS Expr30, SuperVisor.ModifiedDate AS Expr31, SuperVisor.IsDefault AS Expr32, SuperVisor.Address1 AS Expr33, SuperVisor.Address2 AS Expr34, 
                         SuperVisor.City AS Expr35, SuperVisor.State AS Expr36, SuperVisor.ZipCode AS Expr37, SuperVisor.PractitionerServiceId AS Expr38, SuperVisor.IsBillUnderSupervisor AS Expr39, SuperVisor.SupervisorId AS Expr40, 
                         SuperVisor.SupervisionTypeId AS Expr41
FROM            dbo.Provider INNER JOIN
                         dbo.ConfigPractitionerService ON dbo.Provider.PractitionerServiceId = dbo.ConfigPractitionerService.Id INNER JOIN
                         dbo.ConfigSupervisionType ON dbo.Provider.SupervisionTypeId = dbo.ConfigSupervisionType.Id INNER JOIN
                         dbo.CPTModifier ON dbo.ConfigPractitionerService.CPTModifier_Id = dbo.CPTModifier.Id INNER JOIN
                         dbo.ConfigServiceCircumstance ON dbo.ConfigServiceCircumstance.CPTModifier_Id = dbo.CPTModifier.Id INNER JOIN
                         dbo.Provider AS SuperVisor ON dbo.Provider.SupervisorId = SuperVisor.Id

GO

