CREATE View vw_ClaimStatusEnquiry
AS
SELECT A.ClaimId,C.StatuCode,C.StatuCodeDescription,STRING_AGG(C.ErrorMessage ,', ') ErrorMessage
	FROM ClaimStatusInquiry(NOLOCK) A 
INNER JOIN ClaimStatusInquiryChild (NOLOCK)C ON C.ClaimStatusInquiryId=A.Id
WHERE A.Id =(SELECT MAX(Id) FROM ClaimStatusInquiry(NOLOCK) B WHERE B.ClaimId=A.ClaimId)
group by A.ClaimId,C.StatuCode,C.StatuCodeDescription
GO

CREATE View vw_ConfigAdjustmentReasonCode
AS
SELECT  Id,'SYSTEM' FLAG,  GroupCode,Code,ReasonCode,CodeDescription Description,CAST(0 AS BIT)AS IsForWriteOff FROM ConfigAdjustmentReasonCode
UNION
SELECT Id+9000 [Id],'CUSTOM' FLAG, GroupCode,Code,ReasonCode,Description,ISNULL(IsForWriteOff,0)IsForWriteOff FROM AdjustmentReasonCode

GO

CREATE VIEW vw_GetChargeDetailByAccessionNumber
AS                                                                                      
WITH SelfChargeAmount AS                                                  
 (                                                  
     SELECT  pc.ChargeId,ISNULL(v.IsSelfPayment,0)[IsSelfPayment],SUM(ISNULL(pc.PaidAmount,0)) [PaidAmount]
     FROM PaymentCharge(NOLOCK) pc 
     LEFT JOIN Payment(NOLOCK) p on p.Id = pc.PaymentId                                                  
     LEFT JOIN Voucher(NOLOCK) v on v.Id = p.VoucherId
	 WHERE ISNULL(v.IsSelfPayment,0)=1 
	 GROUP BY pc.ChargeId,ISNULL(v.IsSelfPayment,0)
 ),
  InsuranceChargeAmount AS                                                  
 (                                                  
     SELECT  pc.ChargeId,ISNULL(v.IsSelfPayment,0)[IsSelfPayment],SUM(ISNULL(pc.PaidAmount,0)) [PaidAmount]
     FROM PaymentCharge(NOLOCK) pc 
     LEFT JOIN Payment(NOLOCK) p on p.Id = pc.PaymentId                                                  
     LEFT JOIN Voucher(NOLOCK) v on v.Id = p.VoucherId
	 WHERE ISNULL(v.IsSelfPayment,0)=0 
	 GROUP BY pc.ChargeId,ISNULL(v.IsSelfPayment,0)
 ),                  
 SelfAdjustmentAmount AS                                                  
 (                                                  
     SELECT  pc.ChargeId, ISNULL(v.IsSelfPayment,0)[IsSelfPayment],SUM(ISNULL(pa.Amount,0)) [TotalAdjustment]          
     FROM PaymentCharge(NOLOCK) pc
     LEFT JOIN Payment(NOLOCK) p on p.Id = pc.PaymentId                                                  
     LEFT JOIN Voucher(NOLOCK) v on v.Id = p.VoucherId                                                 
     LEFT JOIN PaymentAdjustment(NOLOCK) pa on pc.Id = pa.PaymentChargeId and pa.IsAccounted = 1   and pa.IsDenial = 0                    
	 WHERE ISNULL(v.IsSelfPayment,0)=1 --AND AccessionNUmber='Test88898'
	 GROUP BY pc.ChargeId,ISNULL(v.IsSelfPayment,0)
 ),
 InsuranceAdjustmentAmount AS                                                  
 (                                                  
     SELECT  pc.ChargeId, ISNULL(v.IsSelfPayment,0)[IsSelfPayment],SUM(ISNULL(pa.Amount,0)) [TotalAdjustment]          
     FROM PaymentCharge(NOLOCK) pc
     LEFT JOIN Payment(NOLOCK) p on p.Id = pc.PaymentId                                                  
     LEFT JOIN Voucher(NOLOCK) v on v.Id = p.VoucherId                                                 
     LEFT JOIN PaymentAdjustment(NOLOCK) pa on pc.Id = pa.PaymentChargeId and pa.IsAccounted = 1   and pa.IsDenial = 0                    
	 WHERE ISNULL(v.IsSelfPayment,0)=0 --AND AccessionNUmber='Test88898'
	 GROUP BY pc.ChargeId,ISNULL(v.IsSelfPayment,0)
 )  
 
 SELECT INV.AccessionNumber,
		SUM(C.Amount)[ChargeAmount],
		SUM(ISNULL(PT.PaidAmount,0))[PatientPaid],
		SUM(ISNULL(INS.PaidAmount,0))[InsurancePaid],
		SUM(ISNULL(INSA.TotalAdjustment,0))[InsuranceAdjustment],
		SUM(ISNULL(PTA.TotalAdjustment,0))[PatientAdjustment]

	FROM Charge(NOLOCK) C
 INNER JOIN Invoice INV ON INV.Id=C.InvoiceId
 LEFT JOIN  SelfChargeAmount PT ON PT.ChargeId=C.Id
 LEFT JOIN  InsuranceChargeAmount INS ON INS.ChargeId=C.Id
 LEFT JOIN  SelfAdjustmentAmount PTA ON PTA.ChargeId=C.Id
 LEFT JOIN  InsuranceAdjustmentAmount INSA ON INSA.ChargeId=C.Id
 GROUP BY INV.AccessionNumber
GO

CREATE View vw_GetChargeDetailsByClaimIdForERA
AS
	SELECT DISTINCT A.ChargeNo,A.CPTCode,A.InvoiceId,C.Id[ClaimId],CONVERT(CHAR(8),b.BillFromDate,112)ServiceDate
	FROM Charge(NOLOCK) A
		INNER JOIN Invoice(NOLOCK) B ON A.InvoiceId=B.Id
		INNER JOIN Claim(NOLOCK) C ON B.Id=C.InvoiceId
	

GO

CREATE VIEW vw_GetChargeForPendingPayment
AS                                                                                      
                                        
  WITH ChargeAmount AS                                                  
 (                                                  
     SELECT  c.Id [ChargeId], c.InvoiceId, c.PatientCaseId,c.Amount As ChargeAmount,
		ISNULL(pc.PaidAmount,0) [PaidAmount],c.ChargeNo
     FROM Charge(NOLOCK) c                    
     LEFT JOIN PaymentCharge(NOLOCK) pc on c.Id = pc.ChargeId                                                  
 ),
 ChargeAdjustmentAmount AS                                                  
 (                                                  
     SELECT  c.Id [ChargeId], c.InvoiceId, c.PatientCaseId,c.Amount As ChargeAmount,ISNULL(pa.Amount,0) [TotalAdjustment],
	 c.ChargeNo
     FROM Charge(NOLOCK) c                                 
     LEFT JOIN PaymentCharge(NOLOCK) pc on c.Id = pc.ChargeId                                                  
     LEFT JOIN Payment(NOLOCK) p on p.Id = pc.PaymentId                                                       
     LEFT JOIN PaymentAdjustment(NOLOCK) pa on pc.Id = pa.PaymentChargeId and pa.IsAccounted = 1   and pa.IsDenial = 0                    
 )                  
 , ChargeSUM AS                                                  
 (                  
    SELECT CA.ChargeId, CA.InvoiceId, CA.PatientCaseId,                                                  
    CA.ChargeAmount,SUM(CA.PaidAmount) [PaidAmount]    
    FROM ChargeAmount CA                  
    GROUP BY CA.ChargeId,CA.InvoiceId, CA.PatientCaseId,                                     
    CA.ChargeAmount,CA.ChargeNo       
 ),                 
 ChargeAdjustmentSUM AS                                                  
 (                  
    SELECT CA.ChargeId, CA.InvoiceId, CA.PatientCaseId,                                       
    CA.ChargeAmount,SUM(CA.TotalAdjustment) [TotalAdjustment],         
     CA.ChargeNo                    
    FROM ChargeAdjustmentAmount CA                  
    GROUP BY CA.ChargeId,CA.InvoiceId, CA.PatientCaseId,                                     
    CA.ChargeAmount,CA.ChargeNo
 )                  
    SELECT DISTINCT cs.ChargeAmount,c.*,                   
   (ISNULL(cs.PaidAmount,0) + ISNULL(ca.TotalAdjustment,0)) [TotalPaidAmount],            
  ISNULL(cs.PaidAmount,0) [PaidAmount],
   ISNULL(ca.TotalAdjustment,0) [TotalAdjustment],
   (cs.ChargeAmount - (ISNULL((cs.PaidAmount) + (ca.TotalAdjustment),0)))[DueAmount],
   '' BatchNo, CAST(1 as BIT) IsActive,inv.AccessionNumber,inv.ClaimId,d.IsFacilityCharge   ,Inv.AuxillaryProviderId,INV.RefDoctorId ,
   CSE.StatuCodeDescription,CSE.ErrorMessage,INV.InvoiceType,INV.ReviewNeeded,INV.ReviewComments,INV.IsBillable,INV.NonBillableComments,INV.IsAROldCharges,
   INV.UId[InvoiceUId],CB.SentDate,PC.UId [PatientCaseUId]
      FROM ChargeSUM cs            
   JOIN ChargeAdjustmentSUM ca On ca.ChargeId = cs.ChargeId                  
   JOIN Charge(NOLOCK) c on cs.ChargeId=c.Id                    
   JOIN CptCode(NOLOCK) D on d.CPTCode=c.CPTCode
   JOIN Invoice(NOLOCK) INV on INV.Id=c.InvoiceId
   JOIN PatientCase(NOLOCK) PC on INV.PatientCaseId=PC.Id
   LEFT JOIN Claim(NOLOCK) CB ON CB.Id=INV.ClaimId
   LEFT JOIN vw_ClaimStatusEnquiry CSE ON CSE.ClaimId=INV.ClaimId

