     FROM Charge(NOLOCK) c                    
     LEFT JOIN PaymentCharge(NOLOCK) pc on c.Id = pc.ChargeId                                                  
 ),
 ChargeAdjustmentAmount AS                                                  
 (                                                  
     SELECT  c.Id [ChargeId], c.InvoiceId, c.PatientCaseId,c.Amount As ChargeAmount,ISNULL(pa.Amount,0) [TotalAdjustment],
	 c.ChargeNo
     FROM Charge(NOLOCK) c                                 
