--DROP VIEW [dbo].[vw_GetChargeForPendingPayment_Dashboard]
CREATE VIEW [dbo].[vw_GetChargeForPendingPayment_Dashboard]
AS                                                                                      
                                        
                                       
  WITH ChargeAmount AS                                                    
 (                                                    
     SELECT  c.Id [ChargeId], c.InvoiceId, c.PatientCaseId,c.Amount As ChargeAmount,  
  ISNULL(pc.PaidAmount,0) [PaidAmount],c.ChargeNo, CASE WHEN pc.PaidAmount IS null THEN 0 ELSE 1 END [PaymentReceived]  
     FROM Charge(NOLOCK) c                      
     LEFT JOIN PaymentCharge(NOLOCK) pc on c.Id = pc.ChargeId                                                    
 ),  
 ChargeAdjustmentAmount AS                                                    
 (                                                    
     SELECT  c.Id [ChargeId], c.InvoiceId, c.PatientCaseId,c.Amount As ChargeAmount,ISNULL(pa.Amount,0)  [TotalAdjustment],  
  c.ChargeNo  
     FROM Charge(NOLOCK) c                                   
     LEFT JOIN PaymentCharge(NOLOCK) pc on c.Id = pc.ChargeId                                                    
     LEFT JOIN Payment(NOLOCK) p on p.Id = pc.PaymentId                                                         
     LEFT JOIN PaymentAdjustment(NOLOCK) pa on pc.Id = pa.PaymentChargeId and pa.IsAccounted = 1   and pa.IsDenial = 0                      
 )                    
 , ChargeSUM AS                                                    
 (                    
    SELECT CA.ChargeId, CA.InvoiceId, CA.PatientCaseId,                                                    
    CA.ChargeAmount,SUM(CA.PaidAmount) [PaidAmount]  ,PaymentReceived    
    FROM ChargeAmount CA                    
    GROUP BY CA.ChargeId,CA.InvoiceId, CA.PatientCaseId,                                       
    CA.ChargeAmount,CA.ChargeNo ,PaymentReceived        
 ),                   
 ChargeAdjustmentSUM AS                                                    
 (                    
    SELECT CA.ChargeId, CA.InvoiceId, CA.PatientCaseId,                                         
    CA.ChargeAmount,SUM(CA.TotalAdjustment) [TotalAdjustment],           
     CA.ChargeNo                      
    FROM ChargeAdjustmentAmount CA                    
    GROUP BY CA.ChargeId,CA.InvoiceId, CA.PatientCaseId,                                       
    CA.ChargeAmount,CA.ChargeNo  
 )                    
    SELECT DISTINCT cs.ChargeAmount,c.*,                     
   (ISNULL(cs.PaidAmount,0) + ISNULL(ca.TotalAdjustment,0)) [TotalPaidAmount],              
  ISNULL(cs.PaidAmount,0) [PaidAmount],  
   ISNULL(ca.TotalAdjustment,0) [TotalAdjustment],  
   (cs.ChargeAmount - (ISNULL((cs.PaidAmount) + (ca.TotalAdjustment),0)))[DueAmount],  
   CB.BatchNo, CB.IsActive,inv.AccessionNumber,inv.ClaimId  ,  
   cs.PaidAmount[ClaimReceivedAmount],  
   I.CompanyName [InsuranceCompanyName],d.FacilityDescription [Location],d.State [LocationState],x.CompanyType [FinancialClass],  
   CC.InsuranceCompanyId,CS.PaymentReceived,ISNULL(INV.ReviewNeeded,0) ReviewNeeded,ISNULL(Inv.IsBillable,1)Billable,ReviewComments,
   ISNULL(INV.FeeAmount,0)FeeAmount
      FROM ChargeSUM cs              
   LEFT JOIN ChargeAdjustmentSUM ca On ca.ChargeId = cs.ChargeId                    
   JOIN Charge(NOLOCK) c on cs.ChargeId=c.Id      
   JOIN Invoice(NOLOCK) INV on INV.Id=c.InvoiceId  
   INNER JOIN ChargeStat(NOLOCK) CC ON CC.Id=c.Id  
   LEFT JOIN InsuranceCompany(NOLOCK) I ON I.Id=CC.InsuranceCompanyId  
   LEFT JOIN Facility(NOLOCK) D ON D.Id= PerformingFacilityId  
   LEFT JOIN ConfigInsuranceCompanyType(NOLOCK) X ON X.Id=CompanyTypeId  
   JOIN ChargeBatch(NOLOCK) CB ON CB.Id=INV.ChargeBatchId 

GO

CREATE VIEW vw_GetChargeForPendingPayment_New
AS                                                                                      
                                        
  WITH ChargeAmount AS                                                  
 (                                                  
     SELECT  c.Id [ChargeId], c.InvoiceId, c.PatientCaseId,c.Amount As ChargeAmount,
