    FROM ChargeAmount CA                  
    GROUP BY CA.ChargeId,CA.InvoiceId, CA.PatientCaseId,                                     
    CA.ChargeAmount,CA.ChargeNo       
 ),                 
 ChargeAdjustmentSUM AS                                                  
 (                  
    SELECT CA.ChargeId, CA.InvoiceId, CA.PatientCaseId,                                       
    CA.ChargeAmount,SUM(CA.TotalAdjustment) [TotalAdjustment],         
     CA.ChargeNo                    , CAST(0 AS bit)IsPayment   
