CREATE VIEW [dbo].[vw_GetChargeForPendingPaymentForStatement]    
AS                                                                                          
                                            
  WITH ChargeAmount AS                                                      
 (                                                      
     SELECT  c.Id [ChargeId], c.InvoiceId, c.PatientCaseId,c.Amount As ChargeAmount,    
  ISNULL(pc.PaidAmount,0) [PaidAmount],c.ChargeNo, c.CreatedDate, c.Description, c.CPTCode,  
  c.DueByFlagCD, c.BillFromDate AS DOS  ,C.ShiftDate
     FROM Charge(NOLOCK) c                        
     LEFT JOIN PaymentCharge(NOLOCK) pc on c.Id = pc.ChargeId      
  WHERE (c.DueByFlagCD = '' OR LOWER(c.DueByFlagCD) = 'patient')   
 ),    
 ChargeAdjustmentAmount AS                                                      
 (                                                      
     SELECT  c.Id [ChargeId], c.InvoiceId, c.PatientCaseId,c.Amount As ChargeAmount,ISNULL(pa.Amount,0) [TotalAdjustment],    
  c.ChargeNo, c.CreatedDate, c.Description, c.CPTCode,  c.DueByFlagCD  
     FROM Charge(NOLOCK) c                                     
     LEFT JOIN PaymentCharge(NOLOCK) pc on c.Id = pc.ChargeId                                                      
     LEFT JOIN Payment(NOLOCK) p on p.Id = pc.PaymentId                                                           
     LEFT JOIN PaymentAdjustment(NOLOCK) pa on pc.Id = pa.PaymentChargeId and pa.IsAccounted = 1   and pa.IsDenial = 0      
   WHERE (c.DueByFlagCD = '' OR LOWER(c.DueByFlagCD) = 'patient')   
 )                      
 , ChargeSUM AS                                                      
 (                      
    SELECT CA.ChargeId, CA.InvoiceId, CA.PatientCaseId,                                                      
    CA.ChargeAmount,SUM(CA.PaidAmount) [PaidAmount], CA.CreatedDate, CA.Description, CA.CPTCode,  CA.DueByFlagCD, CA.DOS  
	,CA.ShiftDate
    FROM ChargeAmount CA                      
    GROUP BY CA.ChargeId,CA.InvoiceId, CA.PatientCaseId,                                         
    CA.ChargeAmount,CA.ChargeNo, CA.CreatedDate, CA.Description, CA.CPTCode,  CA.DueByFlagCD, CA.DOS  ,CA.ShiftDate
 ),                     
 ChargeAdjustmentSUM AS                                                      
 (                      
    SELECT CA.ChargeId, CA.InvoiceId, CA.PatientCaseId,                                           
    CA.ChargeAmount,SUM(CA.TotalAdjustment) [TotalAdjustment],             
     CA.ChargeNo                        
    FROM ChargeAdjustmentAmount CA                      
    GROUP BY CA.ChargeId,CA.InvoiceId, CA.PatientCaseId,                                         
    CA.ChargeAmount,CA.ChargeNo    
 )                      
    SELECT DISTINCT cs.ChargeAmount As Amount, cs.CreatedDate, cs.Description, cs.CPTCode,  cs.DueByFlagCD, cs.DOS,    
 cs.PatientCaseId, cs.ChargeId As Id,  
   (ISNULL(cs.PaidAmount,0) + ISNULL(ca.TotalAdjustment,0)) [TotalPaidAmount],                
  ISNULL(cs.PaidAmount,0) [PaidAmount],    
   ISNULL(ca.TotalAdjustment,0) [TotalAdjustment],    
   (cs.ChargeAmount - (ISNULL((cs.PaidAmount) + (ca.TotalAdjustment),0)))[DueAmount] ,
   ShiftDate
   
   --CB.BatchNo, CB.IsActive         
      FROM ChargeSUM cs                
   JOIN ChargeAdjustmentSUM ca On ca.ChargeId = cs.ChargeId                      
   --JOIN Charge(NOLOCK) c on cs.ChargeId=c.Id                        
   --JOIN Invoice(NOLOCK) INV on INV.Id=c.InvoiceId    
   --JOIN ChargeBatch(NOLOCK) CB ON CB.Id=INV.ChargeBatchId 

GO

CREATE VIEW [dbo].[vw_GetChargeForPendingPaymentForTesting]                        
AS
WITH ChargeAmount AS
(
	  SELECT  c.Id [ChargeId], v.IsSelfPayment, c.InvoiceId, c.PatientCaseId,
	  (CASE WHEN c.MultiplyQty = 1 THEN ISNULL((c.Amount * c.Qty),0)
	  WHEN c.MultiplyQty = 0 THEN ISNULL(c.Amount,0)
	  ELSE 0
	  END) As ChargeAmount,
	  ISNULL(pc.PaidAmount,0) [PaidAmount],
	  ISNULL(pa.Amount,0) [TotalAdjustment],
	  cb.BatchNo, cb.IsActive, c.ChargeNo
	  FROM Charge(NOLOCK) c
	  LEFT JOIN Invoice inc on inc.Id = c.InvoiceId
	  LEFT JOIN ChargeBatch cb on cb.Id = inc.ChargeBatchId
      LEFT JOIN PaymentCharge(NOLOCK) pc on c.Id = pc.ChargeId
      LEFT JOIN Payment(NOLOCK) p on p.Id = pc.PaymentId
      LEFT JOIN Voucher(NOLOCK) v on v.Id = p.VoucherId
      LEFT JOIN PaymentAdjustment(NOLOCK) pa on pc.Id = pa.PaymentChargeId and pa.IsAccounted = 1
)
, ChargeSUM AS
(
	SELECT ChargeId,IsSelfPayment, InvoiceId, PatientCaseId,
	ChargeAmount,SUM(PaidAmount) PaidAmount,SUM(TotalAdjustment) TotalAdjustment,
	BatchNo, IsActive, ChargeNo
	FROM ChargeAmount
	GROUP BY ChargeId,IsSelfPayment, InvoiceId, PatientCaseId,
	ChargeAmount,BatchNo, IsActive, ChargeNo
)
  SELECT DISTINCT cs.IsActive,cs.BatchNo,cs.IsSelfPayment, cs.ChargeAmount,c.*
  ,(cs.PaidAmount + cs.TotalAdjustment) [TotalPaidAmount],cs.PaidAmount [PaidAmount],
  cs.TotalAdjustment [TotalAdjustment], (cs.ChargeAmount - (cs.PaidAmount + cs.TotalAdjustment)) [DueAmount]
  FROM ChargeSUM cs
  JOIN Charge c on cs.ChargeId=c.Id
  WHERE (cs.ChargeAmount - (cs.PaidAmount + cs.TotalAdjustment)) >= 0

GO

CREATE VIEW [dbo].[vw_Payments]  
AS  
  
 SELECT TOP 100 PERCENT *  
 FROM  vw_PaymentsAdjustments  
 
 ORDER BY PaymentEffectiveDate DESC

GO

--DROP VIEW [dbo].[vw_PaymentsAdjustments]         
CREATE VIEW [dbo].[vw_PaymentsAdjustments]         
AS         
        
 Select chg.ChargeNo [ChargeNum],        
 '' ReasonCode,        
 chg.Amount [ChargeAmount],  SUM(PaidAmount + ISNULL(adj.Amount, 0)) As PaymentOrAdjAmount, 1 AS 'IsPayment', pay.CreatedDate as PaymentDate, chg.EntryDate as ChargeDate,         
chg.BillFromDate as DOS, pay.Id as PaymentNum, chg.CPTCode, chg.PerformingProviderId, d.FirstName as DoctorFirstName,         
d.LastName as PerformingProvider, d.LastName as DoctorLastName, per.BillingID as BillingID,         
per.LastName + ', ' + per.FirstName as Patient, d2.FirstName as BillingDoctorFirstName,         
d2.LastName as BillingDoctorLastName, inv.BillProviderId As BillingDoctorID,
cat.CategoryName as 'Category',        
CASE WHEN voc.InsuranceCompanyId IS NULL THEN         
1 END as PayorPatient,         
CASE WHEN voc.PatientId Is Null THEN         
1 END as PayorInsurance, chg.IsDeleted, inv.AccessionNumber, voc.EffectiveDate AS PaymentCreatedBy,         
voc.PatientID AS PatientID,         
voc.EffectiveDate AS PaymentEffectiveDate,          
pay.ModifiedBy AS PaymentModifiedBy,         
pay.ModifiedDate AS PaymentModifiedDate,         
pay.CreatedDate,         
chg.PatientCaseId,  
voc.Id As VoucherId  ,pay.IsCommitted,inv.AuxillaryProviderId, d3.FirstName as AuxillaryDoctorFirstName,d3.LastName as AuxillaryDoctorLastName ,PerformingFacilityId   ,Inv.RefDoctorId    
 from         
 Charge(NOLOCK) chg JOIN PaymentCharge pmt ON chg.Id = pmt.ChargeId 
 LEFT JOIN PaymentAdjustment(NOLOCK) adj ON pmt.Id = adj.PaymentChargeId AND adj.IsBonus = 1 AND adj.IsAccounted = 1   AND adj.IsDenial = 0
 JOIN Payment(NOLOCK) pay ON pmt.PaymentId = pay.Id         
 JOIN Voucher(NOLOCK) voc ON pay.VoucherId = voc.Id        
 LEFT JOIN [Provider](NOLOCK) d on d.Id = chg.PerformingProviderId         
 LEFT JOIN PatientCase(NOLOCK) ca on ca.Id = chg.PatientCaseId         
LEFT JOIN Patient (NOLOCK)per ON per.Id = ca.PatientId         
LEFT JOIN Invoice(NOLOCK) inv ON inv.Id = chg.InvoiceId         
LEFT JOIN [Provider](NOLOCK) d2 on d2.Id = inv.BillProviderId         
LEFT JOIN [Provider](NOLOCK) d3 on d3.Id = inv.AuxillaryProviderId
LEFT JOIN CPTCategory(NOLOCK) cat on cat.ID = (SELECT TOP 1 CPTCategoryId FROM CPTCode(NOLOCK) cpt                 
WHERE cpt.CPTCode = chg.CPTCode         
ORDER BY cpt.[Description], cat.CategoryName)        
 group by chg.ChargeNo, pay.CreatedDate,  chg.EntryDate, chg.BillFromDate,         
 pay.Id, chg.CPTCode, chg.PerformingProviderId, d.FirstName, d.LastName, per.BillingID,        
 per.LastName, per.FirstName, d2.FirstName, d2.LastName, inv.BillProviderId, cat.CategoryName,        
 voc.InsuranceCompanyId, voc.PatientId,  chg.IsDeleted, inv.AccessionNumber,voc.EffectiveDate,pay.ModifiedBy,        
 pay.ModifiedDate, chg.PatientCaseId , chg.Amount, voc.Id,pay.IsCommitted ,inv.AuxillaryProviderId,
         d3.FirstName, d3.LastName,PerformingFacilityId,Inv.RefDoctorId
        
 UNION        
        
 Select  chg.ChargeNo,        
 adj.ReasonCode,        
 chg.Amount [ChargeAmount],  SUM(adj.Amount) As PaymentOrAdjAmount , 0 AS 'IsPayment' , pay.CreatedDate as PaymentDate,chg.EntryDate as ChargeDate,        
 chg.BillFromDate as DOS, pay.Id as PaymentNum, chg.CPTCode, chg.PerformingProviderId, d.FirstName as DoctorFirstName,         
d.LastName as PerformingProvider, d.LastName as DoctorLastName, per.BillingID as BillingID,         
per.LastName + ', ' + per.FirstName as Patient,        
        
d2.FirstName as BillingDoctorFirstName,         
d2.LastName as BillingDoctorLastName, inv.BillProviderId As BillingDoctorID,         
cat.CategoryName as 'Category',        
CASE WHEN voc.InsuranceCompanyId IS NULL THEN         
1 END as PayorPatient,         
CASE WHEN voc.PatientId Is Null THEN         
1 END as PayorInsurance, chg.IsDeleted, inv.AccessionNumber, voc.EffectiveDate AS PaymentCreatedBy,         
voc.PatientID AS PatientID,         
voc.EffectiveDate AS PaymentEffectiveDate,         
pay.ModifiedBy AS PaymentModifiedBy,         
pay.ModifiedDate AS PaymentModifiedDate,         
pay.CreatedDate,         
chg.PatientCaseId,  
voc.Id As VoucherId  ,pay.IsCommitted,inv.AuxillaryProviderId,d3.FirstName as AuxillaryDoctorFirstName,d3.LastName as AuxillaryDoctorLastName   ,PerformingFacilityId    ,Inv.RefDoctorId 
        
 from PaymentCharge(NOLOCK) pmtchg         
 JOIN PaymentAdjustment(NOLOCK) adj ON pmtchg.Id = adj.PaymentChargeId AND adj.IsAccounted = 1   AND adj.IsDenial = 0       
 JOIN Charge(NOLOCK) chg ON chg.Id = pmtchg.ChargeId        
 JOIn Payment(NOLOCK) pay ON pmtchg.PaymentId = pay.Id         
 JOIN Voucher(NOLOCK) voc ON pay.VoucherId = voc.Id        
 LEFT JOIN [Provider](NOLOCK) d on d.Id = chg.PerformingProviderId         
 LEFT JOIN PatientCase(NOLOCK) ca on ca.Id = chg.PatientCaseId         
LEFT JOIN Patient(NOLOCK) per ON per.Id = ca.PatientId         
LEFT JOIN Invoice(NOLOCK) inv ON inv.Id = chg.InvoiceId         
LEFT JOIN [Provider](NOLOCK) d2 on d2.Id = inv.BillProviderId   
LEFT JOIN [Provider](NOLOCK) d3 on d3.Id = inv.AuxillaryProviderId
LEFT JOIN CPTCategory cat on cat.ID = (SELECT TOP 1 CPTCategoryId FROM CPTCode(NOLOCK) cpt        
WHERE cpt.CPTCode = chg.CPTCode         
ORDER BY cpt.[Description], cat.CategoryName)                 
 group by chg.ChargeNo, pay.CreatedDate, chg.EntryDate,        
 chg.BillFromDate, pay.Id, chg.CPTCode, chg.PerformingProviderId, d.FirstName, d.LastName,        
 per.BillingID, per.LastName, per.FirstName, d2.FirstName, d2.LastName,inv.BillProviderId ,        
 cat.CategoryName,voc.InsuranceCompanyId, voc.PatientId,  chg.IsDeleted, inv.AccessionNumber,voc.EffectiveDate,pay.ModifiedBy,        
 pay.ModifiedDate, chg.PatientCaseId , chg.Amount        
 , adj.ReasonCode, voc.Id   ,pay.IsCommitted,inv.AuxillaryProviderId,d3.FirstName, d3.LastName,PerformingFacilityId,Inv.RefDoctorId

GO

--Select * from vw_PaymentsAdjustments_New
CREATE VIEW [dbo].[vw_PaymentsAdjustments_New]         
AS         
        
 Select DISTINCT chg.ChargeNo [ChargeNum],        
 '' ReasonCode,        
 chg.Amount [ChargeAmount],  SUM(PaidAmount) As PaymentOrAdjAmount, 1 AS 'IsPayment', pay.CreatedDate as PaymentDate, chg.EntryDate as ChargeDate,         
chg.BillFromDate as DOS, pay.Id as PaymentNum, chg.CPTCode, chg.PerformingProviderId, d.FirstName as DoctorFirstName,         
d.LastName as PerformingProvider, d.LastName as DoctorLastName, per.BillingID as BillingID,         
per.LastName + ', ' + per.FirstName as Patient, d2.FirstName as BillingDoctorFirstName,         
d2.LastName as BillingDoctorLastName, inv.BillProviderId As BillingDoctorID,         
cat.CategoryName as 'Category',        
CASE WHEN voc.InsuranceCompanyId IS NULL THEN         
1 END as PayorPatient,         
CASE WHEN voc.PatientId Is Null THEN         
1 END as PayorInsurance, chg.IsDeleted, inv.AccessionNumber, pay.CreatedBy AS PaymentCreatedBy,         
voc.PatientID AS PatientID,         
pay.CreatedDate AS PaymentEffectiveDate,          
pay.ModifiedBy AS PaymentModifiedBy,         
pay.ModifiedDate AS PaymentModifiedDate,         
pay.CreatedDate,         
chg.PatientCaseId,  
voc.Id As VoucherId,
voc.EffectiveDate As EffectiveDate,
pay.IsCommitted As IsCommitted
        
 from         
 Charge chg LEFT JOIN PaymentCharge pmt         ON chg.Id = pmt.ChargeId 
 JOIN Payment pay  ON pmt.PaymentId = pay.Id         
 JOIN Voucher voc ON pay.VoucherId = voc.Id        
 LEFT JOIN [Provider] d on d.Id = chg.PerformingProviderId         
 LEFT JOIN PatientCase ca on ca.Id = chg.PatientCaseId         
LEFT JOIN Patient per ON per.Id = ca.PatientId         
LEFT JOIN Invoice inv ON inv.Id = chg.InvoiceId         
LEFT JOIN [Provider] d2 on d2.Id = inv.BillProviderId         
LEFT JOIN CPTCategory cat on cat.ID = (SELECT TOP 1 CPTCategoryId FROM CPTCode cpt         
        
WHERE cpt.CPTCode = chg.CPTCode         
ORDER BY cpt.[Description], cat.CategoryName)         
        
 group by chg.ChargeNo, pay.CreatedDate,  chg.EntryDate, chg.BillFromDate,         
 pay.Id, chg.CPTCode, chg.PerformingProviderId, d.FirstName, d.LastName, per.BillingID,        
 per.LastName, per.FirstName, d2.FirstName, d2.LastName, inv.BillProviderId, cat.CategoryName,        
 voc.InsuranceCompanyId, voc.PatientId,  chg.IsDeleted, inv.AccessionNumber,pay.CreatedBy,pay.ModifiedBy,        
 pay.ModifiedDate, chg.PatientCaseId , chg.Amount, voc.Id,voc.EffectiveDate,pay.IsCommitted
         
        
 UNION        
        
 Select  DISTINCT chg.ChargeNo,        
 adj.ReasonCode,        
 chg.Amount [ChargeAmount],  SUM(adj.Amount) As PaymentOrAdjAmount , 0 AS 'IsPayment' , pay.CreatedDate as PaymentDate,chg.EntryDate as ChargeDate,        
 chg.BillFromDate as DOS, pay.Id as PaymentNum, chg.CPTCode, chg.PerformingProviderId, d.FirstName as DoctorFirstName,         
d.LastName as PerformingProvider, d.LastName as DoctorLastName, per.BillingID as BillingID,         
per.LastName + ', ' + per.FirstName as Patient,        
        
d2.FirstName as BillingDoctorFirstName,         
d2.LastName as BillingDoctorLastName, inv.BillProviderId As BillingDoctorID,         
cat.CategoryName as 'Category',        
CASE WHEN voc.InsuranceCompanyId IS NULL THEN         
1 END as PayorPatient,         
CASE WHEN voc.PatientId Is Null THEN         
1 END as PayorInsurance, chg.IsDeleted, inv.AccessionNumber, pay.CreatedBy AS PaymentCreatedBy,         
voc.PatientID AS PatientID,         
pay.CreatedDate AS PaymentEffectiveDate,         
pay.ModifiedBy AS PaymentModifiedBy,         
pay.ModifiedDate AS PaymentModifiedDate,         
pay.CreatedDate,      
chg.PatientCaseId,  
voc.Id As VoucherId,
voc.EffectiveDate As EffectiveDate,
pay.IsCommitted As IsCommitted
        
 from PaymentCharge pmtchg         
 LEFT JOIN PaymentAdjustment adj ON pmtchg.Id = adj.PaymentChargeId        AND adj.IsAccounted=1    
 LEFT JOIN Charge chg ON chg.Id = pmtchg.ChargeId        
 LEFT JOIn Payment pay ON pmtchg.PaymentId = pay.Id         
 LEFT JOIN Voucher voc ON pay.VoucherId = voc.Id        
 LEFT JOIN [Provider] d on d.Id = chg.PerformingProviderId         
 LEFT JOIN PatientCase ca on ca.Id = chg.PatientCaseId       
LEFT JOIN Patient per ON per.Id = ca.PatientId         
LEFT JOIN Invoice inv ON inv.Id = chg.InvoiceId         
LEFT JOIN [Provider] d2 on d2.Id = inv.BillProviderId         
LEFT JOIN CPTCategory cat on cat.ID = (SELECT TOP 1 CPTCategoryId FROM CPTCode cpt         
        
WHERE cpt.CPTCode = chg.CPTCode     
ORDER BY cpt.[Description], cat.CategoryName)         
        
 group by chg.ChargeNo, pay.CreatedDate, chg.EntryDate,        
 chg.BillFromDate, pay.Id, chg.CPTCode, chg.PerformingProviderId, d.FirstName, d.LastName,        
 per.BillingID, per.LastName, per.FirstName, d2.FirstName, d2.LastName,inv.BillProviderId ,        
 cat.CategoryName,voc.InsuranceCompanyId, voc.PatientId,  chg.IsDeleted, inv.AccessionNumber,pay.CreatedBy,pay.ModifiedBy,        
 pay.ModifiedDate, chg.PatientCaseId , chg.Amount        
 , adj.ReasonCode, voc.Id,voc.EffectiveDate,pay.IsCommitted
  




GO


	CREATE FUNCTION dbo.fn_diagramobjects() 
	RETURNS int
	WITH EXECUTE AS N'dbo'
	AS
	BEGIN
		declare @id_upgraddiagrams		int
		declare @id_sysdiagrams			int
		declare @id_helpdiagrams		int
		declare @id_helpdiagramdefinition	int
		declare @id_creatediagram	int
		declare @id_renamediagram	int
		declare @id_alterdiagram 	int 
		declare @id_dropdiagram		int
		declare @InstalledObjects	int

		select @InstalledObjects = 0

		select 	@id_upgraddiagrams = object_id(N'dbo.sp_upgraddiagrams'),
			@id_sysdiagrams = object_id(N'dbo.sysdiagrams'),
			@id_helpdiagrams = object_id(N'dbo.sp_helpdiagrams'),
			@id_helpdiagramdefinition = object_id(N'dbo.sp_helpdiagramdefinition'),
			@id_creatediagram = object_id(N'dbo.sp_creatediagram'),
			@id_renamediagram = object_id(N'dbo.sp_renamediagram'),
			@id_alterdiagram = object_id(N'dbo.sp_alterdiagram'), 
			@id_dropdiagram = object_id(N'dbo.sp_dropdiagram')

		if @id_upgraddiagrams is not null
			select @InstalledObjects = @InstalledObjects + 1
		if @id_sysdiagrams is not null
			select @InstalledObjects = @InstalledObjects + 2
		if @id_helpdiagrams is not null
			select @InstalledObjects = @InstalledObjects + 4
		if @id_helpdiagramdefinition is not null
			select @InstalledObjects = @InstalledObjects + 8
		if @id_creatediagram is not null
			select @InstalledObjects = @InstalledObjects + 16
		if @id_renamediagram is not null
			select @InstalledObjects = @InstalledObjects + 32
		if @id_alterdiagram  is not null
			select @InstalledObjects = @InstalledObjects + 64
		if @id_dropdiagram is not null
			select @InstalledObjects = @InstalledObjects + 128
		
		return @InstalledObjects 
	END
	
GO

--DROP FUNCTION [dbo].[tfn_Charge]       
CREATE FUNCTION [dbo].[tfn_Charge]       
 (@CurrentOnly bit)    
RETURNS TABLE AS    
    
RETURN (      
 SELECT      
     c.*,    
 ISNULL(inv.AccessionNumber,'') ReferenceNumber,          
 ISNULL(inv.ChargeBatchId,0)[BatchId],  
 ISNULL(inv.ClaimId,0)[ClaimId],AuxillaryProviderId ,RefDoctorId 
        
 FROM  Charge (NOLOCK) c      
 INNER JOIN Invoice (NOLOCK) inv ON inv.ID=c.InvoiceId      
 WHERE     
    ( c.EntryDate = ( SELECT MAX(EntryDate)      
         FROM Charge (NOLOCK)c2      
         WHERE c2.ChargeNo = c.ChargeNo )          
    AND c.IsDeleted = 0)       
) 

GO

--select dbo.tfn_PmtAdjustmentReasonCode(2649)  
CREATE FUNCTION [dbo].[tfn_GetPatientResponsibilityAmount]      
(@ChargeNo nvarchar(10)) RETURNS Money
AS Begin      
DECLARE @Amount Money
    
SELECT @Amount = SUM(Amount)  FROM PaymentAdjustment A(NOLOCK)      
INNER JOIN PaymentCharge B(NOLOCK) ON A.PaymentChargeId=B.Id   
WHERE A.ReasonCode in ('PR1','PR2','PR3') AND  B.ChargeId=@ChargeNo  
     
RETURN ISNULL(@Amount,0) end  
  
  
  
  

GO

CREATE FUNCTION [dbo].[tfn_pm_PrimaryPaymentsApplied]
(  
 @FromDate datetime = NULL,  
 @ToDate  datetime = NULL  
) RETURNS TABLE  
AS RETURN(  
  
 SELECT   ISNULL(MAX(InsuranceCompany), 'UNKNOWN') as 'InsuranceCompany',  
     ISNULL(MAX(CompanyAddress), '') as 'Address',  
     BillingID,  
     Patient,  
     DOS,  
     ProcedureCode as 'ProcedureCode',  
     CONVERT(decimal(10,2), Amount) as 'Charge',  
     CONVERT(decimal(10,2), SUM(InsPayment)) as 'InsPayment',  
     CONVERT(decimal(10,2), SUM(InsAdjustment)) as 'InsAdjustment',  
     CONVERT(decimal(10,2), SUM(PtPayment)) as 'PtPayment',  
     CONVERT(VARCHAR(10), PaymentEffectiveDate, 101) as 'PaymentDate',  
     PrimaryDXCode AS 'PrimaryDXCode',   
     DXDescription AS 'PrimaryDXDesc'  
 FROM (  
  SELECT  ic.CompanyName as InsuranceCompany,  
     ic.CompanyAddress1 + ' ' + ic.CompanyAddress2 + ' ' +  
      ic.CompanyCity + ', ' + ic.CompanyState +  
      '  ' + ic.CompanyZip as CompanyAddress,  
     pt.BillingID,  
     pt.LastName + ',' +Pt.FirstName + Pt.MI [Patient],  
     p.DOS [DOS],  
     p.CPTCode [ProcedureCode],  
     p.ChargeAmount [Amount],  
	 					CASE WHEN p.PayorInsurance IS NOT NULL AND p.IsPayment = 0 THEN 
							PaymentOrAdjAmount END as InsPayment,
					CASE WHEN p.PayorInsurance IS NOT NULL AND p.IsPayment = 0 THEN 
							PaymentOrAdjAmount END as InsAdjustment,
					CASE WHEN p.PayorPatient IS NOT NULL THEN
							PaymentOrAdjAmount END as PtPayment,

     PaymentEffectiveDate,  
     ISNULL(d.ICDCode, '') as 'PrimaryDXCode',  
     ISNULL(d.[Description], '') as 'DXDescription'  
  FROM  vw_PaymentsAdjustments p  
  LEFT JOIN InsurancePolicy ip ON ip.PatientCaseId = p.PatientCaseId  
  LEFT JOIN Patient pt ON pt.BillingID = p.BillingID
  LEFT JOIN InsuranceCompany ic ON ic.Id = ip.InsuranceCompanyId  
  LEFT JOIN   vw_CHARGE_Latest c ON c.ChargeNo = p.ChargeNum 
  LEFT JOIN   InvDiagnosis d on d.InvoiceID = c.InvoiceId   
    
  WHERE   
  -- (p.PayorLevel IS NULL OR p.PayorLevel = 1)  
  --AND  
     (@FromDate IS NULL  
      OR (p.DOS BETWEEN @FromDate AND @ToDate  
      AND p.DOS IS NOT NULL)  
  ))A   
 GROUP BY  BillingID, Patient, DOS, ProcedureCode, Amount, PaymentEffectiveDate, PrimaryDXCode, DXDescription  
 HAVING   SUM(InsPayment) IS NOT NULL OR SUM(InsAdjustment) IS NOT NULL  
   
 ) 

 --select * from vw_PaymentsAdjustments

GO

