CREATE FUNCTION [dbo].[tfn_PmtAdjustmentReasonCode]      
(@ChargeNo nvarchar(10)) RETURNS varchar(100)     
AS Begin      
DECLARE @PaymentReasonCode VARCHAR(100)     
    
SELECT @PaymentReasonCode = COALESCE(@PaymentReasonCode + ', ', '') + ReasonCode  FROM PaymentAdjustment A(NOLOCK)      
INNER JOIN PaymentCharge B(NOLOCK) ON A.PaymentChargeId=B.Id   
WHERE A.IsDenial = 1 AND B.ChargeId=@ChargeNo  
     
RETURN ISNULL(@PaymentReasonCode,'') end  
  
  
  
  

GO

