CREATE FUNCTION [dbo].[tfn_PmtAdjustmentReasonCode_ChargesReport_OnlyWriteOff]
(@ChargeNo nvarchar(10)) RETURNS varchar(100)     
AS Begin      
DECLARE @PaymentReasonCode VARCHAR(100)  

DECLARE @Temp TABLE
(
	ReasonCode VARCHAR(50)
)
INSERT INTO @Temp
SELECT  distinct  ReasonCode  FROM PaymentAdjustment A(NOLOCK)      
INNER JOIN PaymentCharge B(NOLOCK) ON A.PaymentChargeId=B.Id   
WHERE B.ChargeId=@ChargeNo  AND A.ReasonCode IN 
(select REPLACE(ReasonCode,'-','') from AdjustmentReasonCode where ISNULL(IsForWriteOff,0)=1)
    
SELECT  @PaymentReasonCode = COALESCE(@PaymentReasonCode + ', ', '') +  ReasonCode  FROM @Temp

     
RETURN ISNULL(@PaymentReasonCode,'') 
end  

GO

CREATE FUNCTION [dbo].[tfn_PmtAdjustmentReasonCode_ChargesReport_TABLEFORMAT]
(@ChargeNo INT)  
RETURNS @Result table 
(	
	ChargeId INT,
	ReasonCode1 VARCHAR(50),
	ReasonCode2 VARCHAR(50),
	ReasonCode3 VARCHAR(50),
	ReasonCode4 VARCHAR(50),
	RemarkCode1 VARCHAR(50),
	RemarkCode2 VARCHAR(50),
	RemarkCode3 VARCHAR(50),
	RemarkCode4 VARCHAR(50)
)
AS Begin     
	DECLARE @Temp TABLE
	(
		Id INT IDENTITY(1,1),
		ReasonCode VARCHAR(50)	
	)

	INSERT INTO @Temp
	SELECT  distinct  TOP 4 ReasonCode  FROM PaymentAdjustment A(NOLOCK)      
	INNER JOIN PaymentCharge B(NOLOCK) ON A.PaymentChargeId=B.Id   
	WHERE B.ChargeId=@ChargeNo -- ORDER BY A.Id DESC
    
	DECLARE @Count INT=1
	DECLARE @Id INT
	SELECT @Id= MIN(Id) FROM @Temp
	WHILE @Id IS NOT NULL
	BEGIN
		DECLARE @Val VARCHAR(50)=''

		SELECT @Val=ReasonCode FROM @Temp WHERE Id=@Id

		IF @Count=1
		BEGIN 
			INSERT INTO @Result (ChargeId,ReasonCode1)
			Values(CAST(@ChargeNo AS INT),@Val)
		END
		IF @Count=2
		BEGIN 
			UPDATE @Result SET ReasonCode2=@Val
		END
		IF @Count=3
		BEGIN 
			UPDATE @Result SET ReasonCode3=@Val
		END
		IF @Count=4
		BEGIN 
			UPDATE @Result SET ReasonCode4=@Val
		END

		SELECT @Id= MIN(Id) FROM @Temp WHERE Id>@Id
		SET @Count=@Count+1
	END

	DECLARE @RemarkTemp TABLE
	(
		Id INT IDENTITY(1,1),
		ReasonCode VARCHAR(50)	
	)

	INSERT INTO @RemarkTemp
	SELECT  distinct  TOP 4 RemarkCode FROM PaymentRemarkCode A(NOLOCK)      
	INNER JOIN PaymentCharge B(NOLOCK) ON A.PaymentChargeId=B.Id   
	WHERE B.ChargeId=@ChargeNo -- ORDER BY A.Id DESC

	DECLARE @RemarkCount INT=1
	DECLARE @RemarkId INT
	SELECT @RemarkId= MIN(Id) FROM @RemarkTemp

	WHILE @RemarkId IS NOT NULL
	BEGIN
		DECLARE @RemarkVal VARCHAR(50)=''

		SELECT @RemarkVal=ReasonCode FROM @RemarkTemp WHERE Id=@RemarkId

		IF @RemarkCount=1
		BEGIN 
			UPDATE @Result SET RemarkCode1=@RemarkVal
		END
		IF @RemarkCount=2
		BEGIN 
			UPDATE @Result SET RemarkCode2=@RemarkVal
		END
		IF @RemarkCount=3
		BEGIN 
			UPDATE @Result SET RemarkCode3=@RemarkVal
		END
		IF @RemarkCount=4
		BEGIN 
			UPDATE @Result SET RemarkCode4=@RemarkVal
		END

		SELECT @RemarkId= MIN(Id) FROM @RemarkTemp WHERE Id>@RemarkId
		SET @RemarkCount=@RemarkCount+1
	END
	RETURN 
end  

GO

