CREATE FUNCTION [dbo].[tfn_Split]
(
	@Value NVARCHAR(MAX),
	@Delimiter NVARCHAR(10)
)  
RETURNS @Result table 
(
	Id INT IDENTITY,
	Value NVARCHAR(MAX)
) 
AS  
BEGIN
	IF @Value IS NOT NULL AND @Value <> ''
	BEGIN
		DECLARE @DelimiterLength INT = DATALENGTH(@Delimiter) / 2

		WHILE CHARINDEX(@Delimiter, @Value) > 0
		BEGIN
			DECLARE @NextDelimiterIndex INT = CHARINDEX(@Delimiter, @Value)
			DECLARE @CurrentValueLength INT = DATALENGTH(@Value) / 2

			IF @NextDelimiterIndex = 1 
				INSERT INTO @Result (Value)
				SELECT ''
			ELSE
				INSERT INTO @Result (Value)
				SELECT SUBSTRING(@Value, 1, @NextDelimiterIndex - 1)
 
			SET @Value = SUBSTRING(@Value, @NextDelimiterIndex + @DelimiterLength, @CurrentValueLength)
		END
       
		INSERT INTO @Result (Value)
		SELECT @Value
	END
 
	RETURN
END


GO

CREATE FUNCTION [dbo].[tfn_Split_ChargeReport_AdjustmentsCodes]
(
	@ChargeId INT,
	@Value NVARCHAR(MAX),
	@Delimiter NVARCHAR(10)
)  
RETURNS @Result table 
(
	ChargeId INT,
	ReasonCode1 VARCHAR(50),
	ReasonCode2 VARCHAR(50),
	ReasonCode3 VARCHAR(50),
	ReasonCode4 VARCHAR(50),
	RemarkCode1 VARCHAR(50),
	RemarkCode2 VARCHAR(50),
	RemarkCode3 VARCHAR(50),
	RemarkCode4 VARCHAR(50)
) 
AS  
BEGIN
	IF @Value IS NOT NULL AND @Value <> ''
	BEGIN
		DECLARE @DelimiterLength INT = DATALENGTH(@Delimiter) / 2
		DECLARE @Count INT =1
		WHILE CHARINDEX(@Delimiter, @Value) > 0
		BEGIN
			DECLARE @NextDelimiterIndex INT = CHARINDEX(@Delimiter, @Value)
			DECLARE @CurrentValueLength INT = DATALENGTH(@Value) / 2
			IF @Count=1
			BEGIN
				INSERT INTO @Result(ChargeId,ReasonCode1)
				SELECT @ChargeId,SUBSTRING(@Value, 1, @NextDelimiterIndex - 1)
			END
			IF @Count=2
			BEGIN
				UPDATE @Result set ReasonCode2=SUBSTRING(@Value, 1, @NextDelimiterIndex - 1)
			END
			IF @Count=3
			BEGIN
				UPDATE @Result set ReasonCode3=SUBSTRING(@Value, 1, @NextDelimiterIndex - 1)
			END
			--SELECT SUBSTRING(@Value, 1, @NextDelimiterIndex - 1)
 
			SET @Value = SUBSTRING(@Value, @NextDelimiterIndex + @DelimiterLength, @CurrentValueLength)
			SET @Count=@Count+1
		 END

			IF @Count=1
			BEGIN
				INSERT INTO @Result(ChargeId,ReasonCode1)
				SELECT @ChargeId,@Value
			END
			IF @Count=2
			BEGIN
				UPDATE @Result set ReasonCode2=@Value
			END
			IF @Count=3
			BEGIN
				UPDATE @Result set ReasonCode3=@Value
			END
			IF @Count=3
			BEGIN
				UPDATE @Result set ReasonCode3=@Value
			END
			IF @Count=4
			BEGIN
				UPDATE @Result set ReasonCode4=@Value
			END
       	
		--INSERT INTO @Result (Value)
		UPDATE @Result SET ReasonCode1 = ReasonCode2,
			ReasonCode2 = ReasonCode1
		WHERE ReasonCode1 IN ('PR1','PR2','PR3')
		AND ReasonCode2 IS NOT NULL;

		
	END
 
	RETURN
END

GO

