CREATE FUNCTION [dbo].[tfn_WriteOffAdjustment_ChargesReport]
(@ChargeNo nvarchar(10)) RETURNS Money
AS Begin      

DECLARE @Adjustment MONEY=0

SELECT  @Adjustment=SUM(pa.Amount)
		FROM Charge(NOLOCK) c                                   
     LEFT JOIN PaymentCharge(NOLOCK) pc on c.Id = pc.ChargeId                                                         
     LEFT JOIN PaymentAdjustment(NOLOCK) pa on pc.Id = pa.PaymentChargeId and pa.IsAccounted = 1   and pa.IsDenial = 0   
	 INNER JOIN AdjustmentReasonCode(NOLOCK) arc on REPLACE(arc.ReasonCode,'-','')=pa.ReasonCode AND ISNULL(IsForWriteOff,0)=1
	 AND c.Id=@ChargeNo

     
RETURN @Adjustment
end  

GO

CREATE FUNCTION [dbo].[ufn_ActiveInsuranceForCaseNo]
	(@Date datetime,
	 @Level tinyint,
	 @CaseId integer)
RETURNS INT
AS
BEGIN
	DECLARE @InsuranceCompanyID  AS INTEGER = -1

	SELECT	@InsuranceCompanyID = ip.InsuranceCompanyID
	FROM	InsurancePolicy ip
	WHERE	ip.Id = (	SELECT TOP 1
										Id
							FROM		InsurancePolicy ip2
							WHERE		ip2.PatientCaseId = @CaseId
							AND			ip2.[InsuranceLevel] = @Level
							AND			CAST(ip2.PlanEffectiveDate AS DATE) <= CAST(@Date AS DATE)
							AND			(ip2.PlanExpirationDate IS NULL
								OR		CAST(ip2.PlanExpirationDate AS DATE) >= CAST(@Date AS DATE))
							ORDER BY	PlanEffectiveDate DESC )

	RETURN @InsuranceCompanyID
			
END



GO

CREATE FUNCTION [dbo].[ufn_ActiveInsuranceForCaseNo_InsuranceCompanyCode]
	(@Date datetime,
	 @Level tinyint,
	 @CaseId integer)
RETURNS NVARCHAR(100)
AS
BEGIN
	DECLARE @InsuranceCompanyID  AS INTEGER = -1
	DECLARE @CompanyCode AS NVARCHAR(100)=''

	SELECT	@InsuranceCompanyID = ip.InsuranceCompanyID
	FROM	InsurancePolicy ip
	WHERE	ip.Id = (	SELECT TOP 1
										Id
							FROM		InsurancePolicy(NOLOCK) ip2
							WHERE		ip2.PatientCaseId = @CaseId
							AND			ip2.[InsuranceLevel] = @Level
							AND			ip2.PlanEffectiveDate <= @Date
							AND			(ip2.PlanExpirationDate IS NULL
								OR		ip2.PlanExpirationDate >= @Date)
							ORDER BY	PlanEffectiveDate DESC )

	IF(@InsuranceCompanyID>0)
	BEGIN
		SELECT @CompanyCode=CompanyCode FROM InsuranceCompany(NOLOCK) WHERE Id=@InsuranceCompanyID
	END

	RETURN TRIM(@CompanyCode)
			
END


GO

