CREATE FUNCTION ufn_GetMonthName(@monthId INT)
RETURNS VARCHAR(10)
AS
BEGIN
	DECLARE @MonthName VARCHAR(100)
	IF @monthId=1
		SET @MonthName='Jan';
	IF @monthId=2
		SET @MonthName='Feb';
	IF @monthId=3
		SET @MonthName='March';
	IF @monthId=4
		SET @MonthName='April';
	IF @monthId=5
		SET @MonthName='May';
	IF @monthId=6
		SET @MonthName='June';
	IF @monthId=7
		SET @MonthName='July';
	IF @monthId=8
		SET @MonthName='Aug';
	IF @monthId=9
		SET @MonthName='Sep';
	IF @monthId=10
		SET @MonthName='Oct';
	IF @monthId=11
		SET @MonthName='Nov';
	IF @monthId=12
		SET @MonthName='Dec';
	RETURN @MonthName
END
GO

CREATE FUNCTION [dbo].[ufn_GetPaymentReasonsCodeByChargeNumber_Denial](@ChargeNumber INT)      
RETURNS VARCHAR(100)      
AS       
--BEGIN      
-- DECLARE @tmp varchar(MAX)      
-- SET @tmp = ''      
-- SELECT  @tmp = @tmp +  ReasonCode + ', ' FROM BL_Payment_ReasonCodes      
-- WHERE ChargeNumber=@chargeNumber ANd ReasonCode IN       
-- (SELECT RemarkCode FROm ARSCategoryRemarksCodes) AND ReasonCode IS NOT NULL   
      
-- RETURN SUBSTRING(@tmp, 0, LEN(@tmp))      
--END      
  
BEGIN        
 DECLARE @tmp varchar(MAX)        
 SET @tmp = ''        
 SELECT  @tmp = @tmp +  AdjustmentType + ', ' FROM BL_PaymentsAdjustmentWithPayorLevel        
 WHERE ChargeNumber=@chargeNumber ANd AdjustmentType IN         
 (SELECT ReasonCode FROm ARSCategoryReasonCodes) AND ClaimAdjustmentGroupCode IS NOT NULL     
        
 RETURN SUBSTRING(@tmp, 0, LEN(@tmp))        
END

GO

Create Procedure DeletePaymentsByCheckNumber    
@CheckNumber nvarchar(100)    
AS    
    
Delete From PaymentRemarkCode Where PaymentChargeId In (    
(Select Id From PaymentCharge Where PaymentId In (    
Select Id from Payment Where VoucherId =     
(Select Id from Voucher Where ReferenceNo  = @CheckNumber))))    
    
DELETE from PaymentAdjustment Where PaymentChargeId In (    
(Select Id From PaymentCharge Where PaymentId In (    
Select Id from Payment Where VoucherId =     
(Select Id from Voucher Where ReferenceNo  = @CheckNumber))))    
    
DELETE From PaymentCharge Where PaymentId In (    
Select Id from Payment Where VoucherId =     
(Select Id from Voucher Where ReferenceNo  = @CheckNumber))    
    
DELETE from Payment Where VoucherId =     
(Select Id from Voucher Where ReferenceNo  = @CheckNumber)    
    
DELETE from Voucher Where ReferenceNo  = @CheckNumber    
    
Delete From ERAClaimChargeRemark Where ERAClaimChargePaymentId In (    
(Select Id From ERAClaimChargePayment Where ERAClaimID In (    
Select Id from ERAClaim Where ERARootID =     
(Select Id from ERARoot Where CheckNumber  = @CheckNumber))))    
    
Delete From ERAClaimChargeAdjustment Where ERAClaimChargePaymentId In (    
(Select Id From ERAClaimChargePayment Where ERAClaimID In (    
Select Id from ERAClaim Where ERARootID =     
(Select Id from ERARoot Where CheckNumber  = @CheckNumber))))    
    
Delete From ERAClaimChargePayment Where ERAClaimID In (    
Select Id from ERAClaim Where ERARootID =     
(Select Id from ERARoot Where CheckNumber  = @CheckNumber))    
    
Delete from ERAClaim Where ERARootID =     
(Select Id from ERARoot Where CheckNumber  = @CheckNumber)    
    
DELETE from ERARoot Where CheckNumber  = @CheckNumber 
GO

CREATE PROCEDURE [dbo].[rpt_AdjustmentPatientDetailByDOS]               
(@FromDate DATE,                      
 @ToDate   DATE                      
)                      
AS                      
         BEGIN                      
             SELECT C.Id [Acctno],                      
     (C.LastName + ', ' + C.FirstName + ' ' + C.MI)  [PatientName],              
                    (D.LastName+','+D.FirstName) [Provider],                      
                    A.DOS [DOS],                      
                    A.CPTCode [CPT],                      
                    SUM(A.PaymentOrAdjAmount) [AdjustmentAmount],                      
                    A.ChargeNum,                      
                    A.ReasonCode [AdjustmentDesc],                 
    --'' As [AdjustmentDesc],            
                    B.CaseIdNumber [CaseNo]                      
             FROM vw_PaymentsAdjustments A               
                   JOIN PatientCase B  ON A.PatientCaseId = B.Id                 
                  JOIN Patient C  ON B.PatientId = C.Id              
                  JOIN [Provider] D  ON C.ProviderId = D.Id                      
             WHERE              
    CAST(A.PaymentEffectiveDate AS DATE) BETWEEN @FromDate AND @ToDate                      
                   AND               
       A.ChargeNum > 0 AND A.PatientCaseId > 0 AND A.IsPayment = 0                    
             GROUP BY C.Id,                      
                      (C.LastName + ', ' + C.FirstName + ' ' + C.MI) ,              
                      D.LastName+','+D.FirstName,                      
                      A.DOS,                      
                      A.CPTCode,                      
                      A.ChargeNum,                      
                                    
                      B.CaseIdNumber,           
       A.ReasonCode;                      
         END; 
GO

--rpt_Aging_Patient_Detail_By_InsuranceCompany '18 may 2021'
CREATE PROCEDURE [dbo].[rpt_Aging_Patient_Detail_By_InsuranceCompany]                       
(        
@ToDate   DATETIME = NULL,    
@InsuranceCompanyId INT = -1    
)                      
AS                      
         BEGIN                       

EXEC rpt_InsuranceAgaingPatientReport @ToDate,@InsuranceCompanyId
RETURN;
                 
             PRINT 'Execution Started : '+CONVERT(VARCHAR(30), GETDATE(), 114);                      
             DECLARE @TempData AS TABLE                      
(AcctNo        INT,                      
 PatientName   NVARCHAR(500),         
 DOB   DATE,                     
 ProviderName  NVARCHAR(500),                      
 InsCompanyId  INT,                      
 CompanyName   NVARCHAR(500),                      
 CompanyCode   NVARCHAR(500),                      
 DOS           DATE,                      
 CPTCode       NVARCHAR(50),                      
 Modifiers     NVARCHAR(50),                      
 ChargeAmt     NUMERIC(18, 2),                      
 PriDX         NVARCHAR(50),                      
 POS           NVARCHAR(50),                      
 ChargeNo      NUMERIC(18, 0)                      
 PRIMARY KEY,                      
 Payments      NUMERIC(18, 2),                      
 Adjustments   NUMERIC(18, 2),                      
 PaymentBat    NVARCHAR(100),                      
 Due           NUMERIC(18, 2),                      
 RevenueCentre NVARCHAR(500),                      
 ZeroDay       NUMERIC(18, 2),                      
 ThirtyDays    NUMERIC(18, 2),                      
 SixtyDays     NUMERIC(18, 2),                      
 NinetyDays    NUMERIC(18, 2),                      
 OneTwentyDays NUMERIC(18, 2),                      
 TotalOwing    NUMERIC(18, 2),                      
 ShiftDate     DATE,                      
 FromDate      DATE,                      
 CaseNumber    NUMERIC(18, 0),                      
 CompanyType   NVARCHAR(50) ,
 DueByFlagCD VARCHAR(20)
);                      
             DECLARE @TempPaymentData AS TABLE                      
(ChargeNo   NUMERIC(18, 0)                      
 PRIMARY KEY,                      
 PaymentAmt NUMERIC(18, 2)                      
);                      
             DECLARE @TempAdjustmentData AS TABLE                      
(ChargeNo      NUMERIC(18, 0)                      
 PRIMARY KEY,                      
 AdjustmentAmt NUMERIC(18, 2)                      
);                      
             DECLARE @TempInsPolicy AS TABLE                      
(InsCompanyId       INT,                      
 PatientId          INT,                      
 PolicyId           BIGINT,                      
 CaseNumber         NUMERIC(18, 0),                      
 InsLevel           INT,                      
 PlanEffectiveDate  DATE,                      
 PlanExpirationDate DATE,                      
 PRIMARY KEY(PatientId, PolicyId)                      
);                      
             INSERT INTO @TempData                      
(AcctNo,                      
 PatientName,           
 DOB,                   
 ProviderName,                      
 InsCompanyId,                      
 CompanyName,                      
 DOS,                      
 CPTCode,                      
 Modifiers,                      
 ChargeAmt,                      
 PriDX,                      
 POS,                      
 ChargeNo,                      
 Payments,                      
 Adjustments,                      
 PaymentBat,                      
 Due,                      
 RevenueCentre,                      
 ZeroDay,                      
 ThirtyDays,                      
 SixtyDays,                      
 NinetyDays,                      
 OneTwentyDays,                      
 CompanyCode,                      
 TotalOwing,                                    
 FromDate,                      
 CaseNumber,                      
 CompanyType ,
 DueByFlagCD
)   
     SELECT DISTINCT D.Id,                      
                           CONCAT(D.LastName, ',', D.FirstName, ' ', D.MI) [PatientName],            
       D.DOB,                  
                           CONCAT(E.LastName, ',', E.FirstName),                                           
                           0,                      
          '',                      
                           CAST(A.BillFromDate AS DATE),                      
   A.CPTCode [CPT],                      
                           CONCAT(A.Mod1, A.Mod2, A.Mod3, A.Mod4) [Mods],                      
                           A.Amount,                                
    '',                    
      '',                      
       A.ChargeNo,                      
                           0 [Payments],                      
                           0 [Adjustments],                      
                           '',                      
                           0 [Due],                    
                           K.[CategoryName] [RevenueCentre],                      
                           0 [ZeroDay],                      
                           0 [ThirtyDays],                      
                           0 [SixtyDays],                      
                           0 [NinetyDays],                      
                           0 [OneTwentyDays],                      
           '' [CompanyCode],                      
                           0 [TotalOwing],                      
                                                
                           A.BillFromDate,                      
                           C.CaseIdNumber,                      
                           '' AS CompanyType,A.DueByFlagCD             
                    FROM vw_CHARGE_Latest A(NOLOCK)                      
                         INNER JOIN Invoice B(NOLOCK) ON A.InvoiceId = B.Id         
                         AND A.IsDeleted = 0 AND A.ChargeNo > 0 AND A.PatientCaseId > 0  AND A.Amount > 0  
						 AND A.DueByFlagCD  in  ('Secondary','PRIMARY')
                         JOIN PatientCase C(NOLOCK) ON C.Id = B.PatientCaseId                      
                         JOIN Patient D(NOLOCK) ON C.PatientId = D.Id                      
                         JOIN [Provider] E(NOLOCK) ON D.ProviderId = E.Id                             
                         LEFT JOIN CPTCode J(NOLOCK) ON J.CPTCode = A.CPTCode                      
                         LEFT JOIN CPTCategory K(NOLOCK) ON K.Id = J.CPTCategoryId                      
                    WHERE CAST(A.BillFromDate AS DATE) <= @ToDate      and CAST(A.BillFromDate AS DATE)>'1 May 2020'                
                                                
                      
             PRINT 'SQL Passed : '+CONVERT(VARCHAR(30), GETDATE(), 114);                      
             INSERT INTO @TempPaymentData                      
(ChargeNo,                      
 PaymentAmt                      
)                      
                    SELECT Z.ChargeNum,                      
                           COALESCE(SUM(Z.PaymentOrAdjAmount), 0)                      
                    FROM vw_PaymentsAdjustments Z (NOLOCK)                      
                   Where  z.IsDeleted = 0 AND Z.ChargeNum > 0  and Z.PatientCaseId > 0                     
and Datediff(dd,Z.PaymentEffectiveDate,@ToDate) >= 0       and Z.IsPayment = 1              
Group By ChargeNum                      
                      
                      
             INSERT INTO @TempAdjustmentData                      
(ChargeNo,                      
 AdjustmentAmt                      
)                      
                    SELECT Z.ChargeNum,                      
                           COALESCE(SUM(Z.PaymentOrAdjAmount), 0)                      
                    FROM vw_PaymentsAdjustments Z (NOLOCK)       
       Where  z.IsDeleted =0  AND Z.ChargeNum > 0  and Z.PatientCaseId > 0                      
and Datediff(dd,Z.PaymentEffectiveDate,@ToDate) >= 0    and Z.IsPayment = 0               
Group By ChargeNum                      
                      
             PRINT 'Generatae Temp Payment and Adjustment Passed : '+CONVERT(VARCHAR(30), GETDATE(), 114);                      
             UPDATE @TempData                      
               SET                      
                   Payments = B.PaymentAmt                      
             FROM @TempData A                      
                  JOIN @TempPaymentData B ON A.ChargeNo = B.ChargeNo;                      
             PRINT 'Update Payments Passed : '+CONVERT(VARCHAR(30), GETDATE(), 114);                      
             UPDATE @TempData                      
               SET                      
                   Adjustments = B.AdjustmentAmt                      
             FROM @TempData A                      
                  JOIN @TempAdjustmentData B ON A.ChargeNo = B.ChargeNo;                      
             PRINT 'Update Adjustments Passed : '+CONVERT(VARCHAR(30), GETDATE(), 114);                      
             INSERT INTO @TempInsPolicy                
(InsCompanyId,                   
 PatientId,                      
 PolicyId,                      
 CaseNumber,                      
 InsLevel,                      
 PlanEffectiveDate,                      
 PlanExpirationDate                      
)                      
                    SELECT ip2.InsuranceCompanyID,                      
                           pc.PatientId,               
                           ip2.Id,                      
                           pc.CaseIdNumber,                      
                           ip2.[InsuranceLevel],                      
                           ip2.PlanEffectiveDate,                      
                           ip2.PlanExpirationDate                      
                    FROM InsurancePolicy ip2(NOLOCK)        
     LEFT JOIN PatientCase pc (NOLOCK) ON ip2.PatientCaseId = pc.Id        
     ;                      
             PRINT 'Generate Temp Insurance Policy Passed : '+CONVERT(VARCHAR(30), GETDATE(), 114);                      
             UPDATE @TempData                      
               SET                      
                   InsCompanyId = B.InsCompanyId                      
             FROM @TempData A                      
                  JOIN @TempInsPolicy B ON A.AcctNo = B.PatientId                      
             AND B.CaseNumber = A.CaseNumber                      
                               AND B.InsLevel = (CASE WHEN A.DueByFlagCD='Primary' THEN 1 WHEN A.DueByFlagCD='Secondary' THEN 2 END)                      
                                           AND B.PlanEffectiveDate <= A.DOS                      
                                           AND (B.PlanExpirationDate IS NULL                      
                                                OR B.PlanExpirationDate >= A.DOS);                   
             PRINT 'Update Insurance Policy : '+CONVERT(VARCHAR(30), GETDATE(), 114);                      
             UPDATE @TempData                      
               SET                      
                   Due = ChargeAmt - (Payments + Adjustments),                      
                   CompanyName = J.CompanyName,                      
                   CompanyCode = J.CompanyCode,                      
                   CompanyType = ic.CompanyType                      
             FROM @TempData I                      
                  LEFT JOIN InsuranceCompany J ON I.InsCompanyId = J.Id                      
                  LEFT JOIN ConfigInsuranceCompanyType (NOLOCK) ic ON ic.Id = J.CompanyTypeId;                      
             PRINT 'update Due Amount Passed : '+CONVERT(VARCHAR(30), GETDATE(), 114);                      
                      
    UPDATE @TempData          
           SET                      
                   ZeroDay = CASE                      
                                 WHEN(DATEDIFF(dd, DOS, @ToDate) <= 29)                      
                                 THEN Due                      
                                 ELSE 0                      
                             END,                      
                   ThirtyDays = CASE               
                                    WHEN(DATEDIFF(dd, DOS, @ToDate) >= 30)                      
                                        AND (DATEDIFF(dd, DOS, @ToDate) <= 59)                      
                                    THEN Due                      
                                    ELSE 0                      
                                END,                      
                   SixtyDays = CASE                      
                                   WHEN(DATEDIFF(dd, DOS, @ToDate) >= 60)                      
                                       AND (DATEDIFF(dd, DOS, @ToDate) <= 89)                      
                                   THEN Due                      
                                   ELSE 0                      
END,                      
                   NinetyDays = CASE                      
                                    WHEN(DATEDIFF(dd, DOS, @ToDate) >= 90)                      
                                        AND (DATEDIFF(dd, DOS, @ToDate) <= 999999999999)                      
                                    THEN Due                      
                                    ELSE 0                      
                                END,         
                   OneTwentyDays = CASE                  
                                WHEN(DATEDIFF(dd, DOS, @ToDate) >= 120)                      
                                       THEN Due                      
                                       ELSE 0                      
                                   END                                 
                      
                      
             PRINT 'update ageing Passed : '+CONVERT(VARCHAR(30), GETDATE(), 114);                      
             UPDATE @TempData                      
               SET                      
                   TotalOwing = ZeroDay + ThirtyDays + SixtyDays + NinetyDays --+ OneTwentyDays;                                                      
                  
                      
             PRINT 'Ageing By Patient Passed : '+CONVERT(VARCHAR(30), GETDATE(), 114);                            
                            
                            
-- Aging By Insurance                            
             SELECT X.PatientName,        
            x.AcctNo AS AccountNo,   
			--x.DOB,
    Convert(varchar,x.DOB,101)[DOB],                        
                    SUM(X.ZeroDay) [ZeroDays],                      
    SUM(X.ThirtyDays) [ThirtyDays],                      
                    SUM(X.SixtyDays) [SixtyDays],                      
                    SUM(X.NinetyDays) [NintyDays],                      
                    SUM(X.OneTwentyDays) [OneTwentyDays],                      
                    SUM(X.TotalOwing) [TotalOwing],        
    '' AS PaymentPlan,        
    (Select Top 1 CAST(CreatedDate AS DATE) AS PaymentDate from Payment where PatientId = x.AcctNo        
order by PaymentDate desc) AS LastPaymentDate                 
             FROM @TempData X                      
             WHERE TotalOwing <> 0 AND (X.InsCompanyId = @InsuranceCompanyId OR @InsuranceCompanyId = -1)       
             GROUP BY X.PatientName,        
      X.AcctNo,        
      X.DOB        
                                     
             ORDER BY X.PatientName;                      
             PRINT 'Aging By Insurance Passed : '+ CONVERT(VARCHAR(30), GETDATE(), 114);         
 
             
  
         END; 



GO

CREATE PROCEDURE [dbo].[rpt_Aging_Summary_By_Insurance]               
(        
@ToDate   DATETIME = NULL              
)              
AS              
         BEGIN           
		 exec rpt_InsuranceAgaingReport @ToDate
		RETURN;    
         
             PRINT 'Execution Started : '+CONVERT(VARCHAR(30), GETDATE(), 114);              
             DECLARE @TempData AS TABLE              
(AcctNo        INT,              
 PatientName   NVARCHAR(500),              
 ProviderName  NVARCHAR(500),              
 InsCompanyId  INT,              
 CompanyName   NVARCHAR(500),              
 CompanyCode   NVARCHAR(500),              
 DOS           DATE,              
 CPTCode       NVARCHAR(50),              
 Modifiers     NVARCHAR(50),              
 ChargeAmt     NUMERIC(18, 2),              
 PriDX         NVARCHAR(50),              
 POS           NVARCHAR(50),              
 ChargeNo      NUMERIC(18, 0)              
 PRIMARY KEY,              
 Payments      NUMERIC(18, 2),              
 Adjustments   NUMERIC(18, 2),              
 PaymentBat    NVARCHAR(100),              
 Due           NUMERIC(18, 2),              
 RevenueCentre NVARCHAR(500),              
 ZeroDay       NUMERIC(18, 2),              
 ThirtyDays    NUMERIC(18, 2),              
 SixtyDays     NUMERIC(18, 2),              
 NinetyDays    NUMERIC(18, 2),              
 OneTwentyDays NUMERIC(18, 2),              
 TotalOwing    NUMERIC(18, 2),              
 ShiftDate     DATE,              
 FromDate      DATE,              
 CaseNumber    NUMERIC(18, 0),              
 CompanyType   NVARCHAR(50)              
);              
             DECLARE @TempPaymentData AS TABLE              
(ChargeNo   NUMERIC(18, 0)              
 PRIMARY KEY,              
 PaymentAmt NUMERIC(18, 2)              
);              
             DECLARE @TempAdjustmentData AS TABLE              
(ChargeNo      NUMERIC(18, 0)              
 PRIMARY KEY,              
 AdjustmentAmt NUMERIC(18, 2)              
);              
             DECLARE @TempInsPolicy AS TABLE              
(InsCompanyId       INT,              
 PatientId          INT,              
 PolicyId           BIGINT,              
 CaseNumber         NUMERIC(18, 0),              
 InsLevel           INT,              
 PlanEffectiveDate  DATE,              
 PlanExpirationDate DATE,              
 PRIMARY KEY(PatientId, PolicyId)              
);              
             INSERT INTO @TempData              
(AcctNo,              
 PatientName,              
 ProviderName,              
 InsCompanyId,              
 CompanyName,              
 DOS,              
 CPTCode,              
 Modifiers,              
 ChargeAmt,              
 PriDX,              
 POS,              
 ChargeNo,              
 Payments,              
 Adjustments,              
 PaymentBat,              
 Due,              
 RevenueCentre,              
 ZeroDay,              
 ThirtyDays,              
 SixtyDays,              
 NinetyDays,              
 OneTwentyDays,              
 CompanyCode,              
 TotalOwing,              
 ShiftDate,              
 FromDate,              
 CaseNumber,              
 CompanyType              
)              
                    SELECT DISTINCT D.Id [PatientID],              
                           CONCAT(D.LastName, ',', D.FirstName, ' ', D.MI) [PatientName],              
                           CONCAT(E.LastName, ',', E.FirstName),                              
     -- dbo.ufn_ActiveInsuranceForCaseNo(COALESCE(A.ShiftDate, A.FromDate),1, C.CaseNumber),                 
                           0,              
                           '',              
                           CAST(A.BillFromDate AS DATE),              
                           A.CPTCode [CPT],              
                           CONCAT(A.Mod1, A.Mod2, A.Mod3, A.Mod4) [Mods],              
                           A.Amount,              
                     --      H.ICD9_CM [PriDx],              
                       --    I.Descr [POS],              
                          '',              
        '',              
        A.ChargeNo,              
                           0 [Payments],              
                           0 [Adjustments],              
                           '',              
                           0 [Due],            
                           K.[CategoryName] [RevenueCentre],              
                           0 [ZeroDay],              
                           0 [ThirtyDays],              
                           0 [SixtyDays],              
                           0 [NinetyDays],              
                           0 [OneTwentyDays],              
         '' [CompanyCode],              
                           0 [TotalOwing],              
                          A.BillFromDate [ShiftDate],              
                           A.BillFromDate,              
                           C.CaseIdNumber,              
                           '' AS CompanyType              
                    FROM vw_CHARGE_Latest A(NOLOCK)              
                         INNER JOIN Invoice B(NOLOCK) ON A.InvoiceId = B.Id AND A.IsDeleted =0 AND A.BillToInsurance = 1  
        AND A.ChargeNo > 0 AND A.PatientCaseId > 0              
                         JOIN PatientCase C(NOLOCK) ON C.Id = B.PatientCaseId              
                         JOIN Patient D(NOLOCK) ON C.PatientId = D.Id              
                         JOIN [Provider] E(NOLOCK) ON D.ProviderId = E.Id              
       --JOIN BL_Inv_dx H(NOLOCK) ON H.InvoiceID = B.ID       AND H.DiagnosisNumber = 1              
       --JOIN BL_POS_Config I(NOLOCK) ON I.Code = A.PlaceOfService              
                         LEFT JOIN CPTCode J(NOLOCK) ON J.CPTCode = A.CPTCode              
                         LEFT JOIN CPTCategory K(NOLOCK) ON K.ID = J.CPTCategoryId             
                    WHERE CAST(A.BillFromDate AS DATE) <= @ToDate              
                                        
              
             PRINT 'SQL Passed : '+CONVERT(VARCHAR(30), GETDATE(), 114);              
             INSERT INTO @TempPaymentData              
(ChargeNo,              
 PaymentAmt              
)              
                    SELECT Z.ChargeNum,              
                           COALESCE(SUM(Z.PaymentOrAdjAmount), 0)              
                    FROM vw_PaymentsAdjustments Z (NOLOCK)              
                   Where z.IsDeleted = 0  AND Z.ChargeNum > 0  and Z.PatientCaseId > 0  AND Z.IsPayment = 1            
and Datediff(dd,Z.PaymentEffectiveDate ,@ToDate) >= 0                
Group By ChargeNum              
              
              
             INSERT INTO @TempAdjustmentData              
(ChargeNo,              
 AdjustmentAmt              
)              
                    SELECT Z.ChargeNum,              
                           COALESCE(SUM(Z.PaymentOrAdjAmount), 0)              
                    FROM vw_PaymentsAdjustments Z (NOLOCK)              
                    Where z.IsDeleted =0 AND Z.ChargeNum > 0  and Z.PatientCaseId > 0 AND Z.IsPayment = 0             
and Datediff(dd,Z.PaymentEffectiveDate,@ToDate) >= 0                
Group By ChargeNum              
              
             PRINT 'Generatae Temp Payment and Adjustment Passed : '+CONVERT(VARCHAR(30), GETDATE(), 114);              
             UPDATE @TempData              
               SET              
                   Payments = B.PaymentAmt              
             FROM @TempData A              
                  JOIN @TempPaymentData B ON A.ChargeNo = B.ChargeNo;              
             PRINT 'Update Payments Passed : '+CONVERT(VARCHAR(30), GETDATE(), 114);              
             UPDATE @TempData              
               SET              
                   Adjustments = B.AdjustmentAmt              
             FROM @TempData A              
                  JOIN @TempAdjustmentData B ON A.ChargeNo = B.ChargeNo;              
             PRINT 'Update Adjustments Passed : '+CONVERT(VARCHAR(30), GETDATE(), 114);              
    INSERT INTO @TempInsPolicy              
(InsCompanyId,        
 PatientId,              
 PolicyId,              
 CaseNumber,              
 InsLevel,              
 PlanEffectiveDate,              
 PlanExpirationDate              
)              
                    SELECT ip2.InsuranceCompanyID,              
                           p.Id [PatientID],       
                           ip2.Id [PolicyID],              
                           pc.CaseIdNumber [CaseNumber],              
                           ip2.InsuranceLevel [Level],              
                           ip2.PlanEffectiveDate,              
                           ip2.PlanExpirationDate              
                    FROM InsurancePolicy ip2(NOLOCK)  
     Left Join PatientCase pc ON pc.Id = ip2.PatientCaseId  
     Left Join Patient p On p.Id = pc.PatientId  
  
             PRINT 'Generate Temp Insurance Policy Passed : '+CONVERT(VARCHAR(30), GETDATE(), 114);              
             UPDATE @TempData              
               SET              
                   InsCompanyId = B.InsCompanyId              
             FROM @TempData A              
                  JOIN @TempInsPolicy B ON A.AcctNo = B.PatientId              
             AND B.CaseNumber = A.CaseNumber              
                               AND B.InsLevel = 1              
                                           AND B.PlanEffectiveDate <= A.DOS              
                                           AND (B.PlanExpirationDate IS NULL              
                                                OR B.PlanExpirationDate >= A.DOS);           
             PRINT 'Update Insurance Policy : '+CONVERT(VARCHAR(30), GETDATE(), 114);              
             UPDATE @TempData              
               SET              
                   Due = ChargeAmt - (Payments + Adjustments),              
                   CompanyName = J.CompanyName,              
                   CompanyCode = J.CompanyCode,              
                   CompanyType = ic.CompanyType              
             FROM @TempData I              
                  LEFT JOIN InsuranceCompany J ON I.InsCompanyId = J.Id              
                  LEFT JOIN ConfigInsuranceCompanyType(NOLOCK) ic ON ic.Id = J.CompanyTypeId;              
             PRINT 'update Due Amount Passed : '+CONVERT(VARCHAR(30), GETDATE(), 114);              
                          
    UPDATE @TempData              
               SET              
                   ZeroDay = CASE WHEN(DATEDIFF(dd, DOS, @ToDate) <= 29) THEN Due ELSE 0 END,              
                   ThirtyDays = CASE WHEN(DATEDIFF(dd, DOS, @ToDate) >= 30) AND (DATEDIFF(dd, DOS, @ToDate) <= 59) THEN Due ELSE 0 END,              
                   SixtyDays = CASE WHEN(DATEDIFF(dd, DOS, @ToDate) >= 60) AND (DATEDIFF(dd, DOS, @ToDate) <= 89) THEN Due ELSE 0 END,              
                   --NinetyDays = CASE WHEN(DATEDIFF(dd, DOS, @ToDate) >= 90) AND (DATEDIFF(dd, DOS, @ToDate) <= 119) THEN Due ELSE 0 END,              
       NinetyDays = CASE WHEN(DATEDIFF(dd, DOS, @ToDate) >= 90) AND (DATEDIFF(dd, DOS, @ToDate) <= 999999999999) THEN Due ELSE 0 END,              
                   OneTwentyDays = CASE WHEN(DATEDIFF(dd, DOS, @ToDate) >= 120) THEN Due ELSE 0 END                         
              
              
             PRINT 'update ageing Passed : '+CONVERT(VARCHAR(30), GETDATE(), 114);              
             UPDATE @TempData              
               SET              
                   TotalOwing = ZeroDay + ThirtyDays + SixtyDays + NinetyDays --+ OneTwentyDays;                
                
                 
/*                  
--Ageing By Patient                    
Select X.AcctNo, X.PatientName, Sum(X.ZeroDay) [0Days], Sum(X.ThirtyDays) [30Days], Sum(X.SixtyDays) [60Days], Sum(X.NinetyDays) [90Days], Sum(X.OneTwentyDays) [120Days], Sum(TotalOwing) [Total] from @TempData X                    
Where TotalOwing <> 0                
Group By X.AcctNo, X.PatientName       
Order by acctno             
  */            
              
             PRINT 'Ageing By Patient Passed : '+CONVERT(VARCHAR(30), GETDATE(), 114);                    
                    
                    
-- Ageing By Insurance                    
             SELECT X.InsCompanyId InsuranceCompanyID,              
                    ISNULL(X.CompanyName, 'SELF_PAY') [CompanyName],              
                    ISNULL(X.CompanyCode, 'SELF_PAY') [CompanyCode],              
                    SUM(X.ZeroDay) [ZeroDays],              
               SUM(X.ThirtyDays) [ThirtyDays],              
                    SUM(X.SixtyDays) [SixtyDays],              
                    SUM(X.NinetyDays) [NintyDays],              
                    SUM(X.OneTwentyDays) [OneTwentyDays],              
                    SUM(X.TotalOwing) [TotalOwing]              
             FROM @TempData X              
             WHERE TotalOwing <> 0              
             GROUP BY X.InsCompanyId,              
                      X.CompanyName,              
                      X.CompanyCode              
             ORDER BY X.CompanyName;              
             PRINT 'Ageing By Insurancec Passed : '+CONVERT(VARCHAR(30), GETDATE(), 114);                    
                
       
                
/*             
                    
-- Ageing By Revenue Centre                    
Select X.RevenueCentre, Sum(X.ZeroDay), Sum(X.ThirtyDays), Sum(X.SixtyDays), Sum(X.NinetyDays), Sum(X.OneTwentyDays), Sum(X.TotalOwing) from @TempData X                    
Where TotalOwing <> 0                
Group By X.RevenueCentre                    
Order By X.RevenueCentre                    
                
Print 'Ageing By Revenue Center Passed : ' + convert(varchar(30),getdate(),114)                        
  */              
              
/*                    
Select DATEPART(MONTH,X.DOS) [Month], Sum(X.ChargeAmt) [Charges], Sum(X.Payments) [Payments], Sum(X.Adjustments) [Adjustments] from @TempData X                    
Group By DATEPART(MONTH,X.DOS)                    
*/              
              
         END;  
  
  
  
GO



CREATE PROCEDURE [dbo].[rpt_Aging_Summary_By_InsuranceCompanyType]  (                                                    
@ToDate DateTIME = null                                
)                
as                
Begin        
  
Print 'Execution Started : ' + convert(varchar(30),getdate(),114)            
Declare @TempData as Table (                
AcctNo   int,            
PatientName  Nvarchar(500),                
ProviderName Nvarchar(500),                
InsCompanyId  int,            
CompanyName  Nvarchar(500),                
CompanyCode  Nvarchar(500),                
DOS    Date,                
CPTCode   Nvarchar(50),                
Modifiers  Nvarchar(50),                
ChargeAmt  Numeric(18,2),                
PriDX   Nvarchar(50),                
POS    Nvarchar(50),                
ChargeNo  Numeric(18,0) Primary Key,                
Payments  Numeric(18,2),                
Adjustments  Numeric(18,2),                
PaymentBat  Nvarchar(100),                
Due    Numeric(18,2),                
RevenueCentre Nvarchar(500),                
ZeroDay   Numeric(18,2),                
ThirtyDays  Numeric(18,2),                
SixtyDays  Numeric(18,2),                
NinetyDays  Numeric(18,2),                
OneTwentyDays Numeric(18,2),          
OneFiftyDays  Numeric(18,2),          
TotalOwing Numeric(18,2),            
ShiftDate Date,            
FromDate Date,            
CaseNumber Numeric(18,0),            
CompanyType Nvarchar(50)              
                
)                
            
            
Declare @TempPaymentData as Table (             
            
ChargeNo   Numeric(18,0) Primary Key,                
PaymentAmt  Numeric(18,2)            
)            
            
Declare @TempAdjustmentData as Table (            
               
ChargeNo   Numeric(18,0) Primary Key,                
AdjustmentAmt  Numeric(18,2)                
)            
            
Declare @TempInsPolicy as Table (            
InsCompanyId int,            
PatientId int,            
PolicyId   bigint,            
CaseNumber  Numeric(18,0),            
InsLevel int,            
PlanEffectiveDate Date,            
PlanExpirationDate Date,            
Primary Key(            
PatientId,            
PolicyId            
))             
                
Insert Into @TempData                
(  AcctNo,   PatientName,  ProviderName,                
  InsCompanyId,  CompanyName ,  DOS,                
  CPTCode,  Modifiers,   ChargeAmt,                
  PriDX,   POS,    ChargeNo,                
  Payments,  Adjustments,  PaymentBat,                
  Due,   RevenueCentre,  ZeroDay,                
  ThirtyDays,  SixtyDays,   NinetyDays,                
  OneTwentyDays, OneFiftyDays, CompanyCode, TotalOwing,            
   FromDate, CaseNumber, CompanyType            
)                
select DISTINCT D.Id,  CONCAT ( D.LastName, ',', D.FirstName, ' ', D.MI ) [PatientName],  CONCAT(E.LastName, ',', E.FirstName) ,                          
     -- dbo.ufn_ActiveInsuranceForCaseNo(COALESCE(A.ShiftDate, A.FromDate),1, C.CaseNumber),             
  0,'',     Cast(  A.BillFromDate as date) ,                            
      A.CPTCode [CPT], CONCAT(A.Mod1, A.Mod2, A.Mod3, A.Mod4) [Mods],A.Amount [Charge],                          
    --  H.ICD9_CM [PriDx],            
    --I.Descr [POS],            
    '','',              A.ChargeNo,                
   0 [Payments],  0 [Adjustments],  '',                
   0 [Due],   K.[CategoryName], 0 [ZeroDay],                
   0 [ThirtyDays], 0 [SixtyDays],  0 [NinetyDays],                
   0 [OneTwentyDays] , 0 [OneFiftyDays],     ''   [CompanyCode], 0 [TotalOwing],            
    A.BillFromDate, C.CaseIdNumber, '' AS CompanyType            
from vw_CHARGE_Latest A  (NOLOCK)            
                
INNER JOIN Invoice B (NOLOCK) ON A.InvoiceId =B.Id         
join  PatientCase C (NOLOCK) ON C.Id = B.PatientCaseId                 
join Patient D (NOLOCK) ON C.PatientID = D.Id                 
join [Provider] E (NOLOCK) ON D.ProviderID = E.Id                
                
--join BL_Inv_dx H (NOLOCK) ON H.InvoiceID = B.ID and H.DiagnosisNumber = 1         
--join BL_POS_Config I (NOLOCK) ON I.Code = A.PlaceOfService                  
left join CPTCode J (NOLOCK) ON J.CPTCode = A.CPTCode                
left join CPTCategory K (NOLOCK) ON K.Id = J.CPTCategoryId            
--left join InsuranceCompany (NOLOCK) com ON com.InsuranceCompanyID = 0                
--left join InsuranceCompanyTypes (NOLOCK) ic ON ic.CTID = com.CompanyType               
                
WHERE  CAST(A.BillFromDate AS DATE) <= @ToDate           
 and A.IsDeleted =0 and A.DueByFlagCD = 'PRIMARY' AND A.ChargeNo > 0 and A.PatientCaseId > 0              
 
               
            
Print 'SQL Passed : ' + convert(varchar(30),getdate(),114)            
            
            
Insert Into @TempPaymentData            
( ChargeNo, PaymentAmt)            
Select Z.ChargeNum, Coalesce(Sum(Z.PaymentOrAdjAmount),0) from vw_PaymentsAdjustments Z  (NOLOCK)          
Where  z.IsDeleted =0    AND z.ChargeNum > 0 and Z.PatientCaseId > 0  AND Z.IsPayment = 1          
and Datediff(dd,Z.PaymentEffectiveDate,@ToDate) >= 0             
Group By ChargeNum                   
            
Insert Into @TempAdjustmentData            
(ChargeNo, AdjustmentAmt)            
Select Z.ChargeNum, Coalesce(Sum(Z.PaymentOrAdjAmount),0) from vw_PaymentsAdjustments Z (NOLOCK)           
Where z.IsDeleted =0 AND z.ChargeNum > 0  and Z.PatientCaseId > 0 and Z.IsPayment = 0             
and Datediff(dd,Z.PaymentEffectiveDate,@ToDate) >= 0                 
Group By ChargeNum                   
            
Print 'Generatae Temp Payment and Adjustment Passed : ' + convert(varchar(30),getdate(),114)            
            
update @TempData               
Set Payments = B.PaymentAmt             
From @TempData A  join @TempPaymentData B On A.ChargeNo = B.ChargeNo            
            
Print 'Update Payments Passed : ' + convert(varchar(30),getdate(),114)            
            
update @TempData                
Set Adjustments = B.AdjustmentAmt             
From @TempData A  join @TempAdjustmentData B On A.ChargeNo = B.ChargeNo            
            
Print 'Update Adjustments Passed : ' + convert(varchar(30),getdate(),114)            
            
                
            
Insert Into @TempInsPolicy            
(InsCompanyId,  PatientId, PolicyId, CaseNumber, InsLevel, PlanEffectiveDate, PlanExpirationDate)            
SELECT  ip2.InsuranceCompanyId, p.Id, ip2.Id, pc.CaseIdNumber, ip2.[InsuranceLevel], ip2.PlanEffectiveDate, ip2.PlanExpirationDate            
FROM  InsurancePolicy ip2 (NOLOCK)           
Left Join PatientCase pc (NOLOCK) ON pc.Id = ip2.PatientCaseId
Left join Patient p (NOLOCK) ON pc.PatientId = p.Id
            
            
Print 'Generate Temp Insurance Policy Passed : ' + convert(varchar(30),getdate(),114)            
            
update @TempData            
Set InsCompanyId = B.InsCompanyId            
FROM @TempData A  Join @TempInsPolicy B On A.AcctNo = B.PatientId              
       and  B.CaseNumber =A.CaseNumber            
       AND   B.InsLevel = 1            
       AND   B.PlanEffectiveDate <= A.DOS            
       AND   (B.PlanExpirationDate IS NULL            
        OR  B.PlanExpirationDate >= A.DOS)            
                   
            
Print 'Update Insurance Policy : ' + convert(varchar(30),getdate(),114)            
            
update @TempData                
Set Due = ChargeAmt - (Payments +  Adjustments),                
CompanyName = J.CompanyName  ,              
CompanyCode = J.CompanyCode,            
CompanyType = ic.CompanyType              
From @TempData I left join InsuranceCompany J (NOLOCK) On I.InsCompanyId = J.Id             
left join ConfigInsuranceCompanyType (NOLOCK) ic ON ic.Id = J.CompanyTypeId
 
            
Print 'update Due Amount Passed : ' + convert(varchar(30),getdate(),114)            
               
                
update @TempData                
Set                 
ZeroDay = Case when (Datediff(dd,DOS,@ToDate) <= 29) Then Due Else 0 End,   
ThirtyDays = Case when (Datediff(dd,DOS,@ToDate) >= 30) And (Datediff(dd,DOS,@ToDate) <= 59) Then Due  Else 0 End,                
SixtyDays = Case when (Datediff(dd,DOS,@ToDate) >= 60) And (Datediff(dd,DOS,@ToDate) <= 89) Then Due  Else 0 End,                
NinetyDays = Case when (Datediff(dd,DOS,@ToDate) >= 90) And (Datediff(dd,DOS,@ToDate) <= 119) Then Due  Else 0 End,                
OneTwentyDays = Case when (Datediff(dd,DOS,@ToDate) >= 120) And (Datediff(dd,DOS,@ToDate) <= 149) Then Due  Else 0 End,          
OneFiftyDays = Case when (Datediff(dd,DOS,@ToDate) >= 150)  Then Due  Else 0 End            
               
                
Print 'update ageing Passed : ' + convert(varchar(30),getdate(),114)            
            
update @TempData            
Set TotalOwing =  ZeroDay +  ThirtyDays   + SixtyDays   + NinetyDays --+ OneTwentyDays  + OneFiftyDays          
            
             
/*              
--Ageing By Patient                
Select X.AcctNo, X.PatientName, Sum(X.ZeroDay) [0Days], Sum(X.ThirtyDays) [30Days], Sum(X.SixtyDays) [60Days], Sum(X.NinetyDays) [90Days], Sum(X.OneTwentyDays) [120Days], Sum(TotalOwing) [Total] from @TempData X                
Where TotalOwing <> 0            
Group By X.AcctNo, X.PatientName                
Order by acctno                
  */            
                
Print 'Ageing By Patient Passed : ' + convert(varchar(30),getdate(),114)                
                
                
-- Ageing By Insurance                
Select X.InsCompanyId InsuranceCompanyID,        
 ISNULL(X.CompanyName, 'SELF_PAY') AS [CompanyName],      
  ISNULL(X.CompanyCode, 'SELF_PAY') AS [CompanyCode],      
  ISNULL(x.CompanyType, 'SELF_PAY') AS [CompanyType],                  
    Sum(X.ZeroDay) [ZeroDays],               
    Sum(X.ThirtyDays) [ThirtyDays],              
     Sum(X.SixtyDays) [SixtyDays],              
      Sum(X.NinetyDays) [NintyDays],               
      Sum(X.OneTwentyDays) [OneTwentyDays],          
   Sum(X.OneFiftyDays) [OneFiftyDays],          
      Sum(X.TotalOwing) [TotalOwing]               
                    
       from @TempData X                
    Where TotalOwing <> 0            
Group By X.InsCompanyId, X.CompanyName   , X.CompanyCode , x.CompanyType             
            
Order by X.CompanyName                
                
Print 'Ageing By Insurancec Passed : ' + convert(varchar(30),getdate(),114)                
     
            
/*            
                
-- Ageing By Revenue Centre                
Select X.RevenueCentre, Sum(X.ZeroDay), Sum(X.ThirtyDays), Sum(X.SixtyDays), Sum(X.NinetyDays), Sum(X.OneTwentyDays), Sum(X.TotalOwing) from @TempData X                
Where TotalOwing <> 0            
Group By X.RevenueCentre                
Order By X.RevenueCentre                
            
Print 'Ageing By Revenue Center Passed : ' + convert(varchar(30),getdate(),114)                    
  */             
                
/*                
Select DATEPART(MONTH,X.DOS) [Month], Sum(X.ChargeAmt) [Charges], Sum(X.Payments) [Payments], Sum(X.Adjustments) [Adjustments] from @TempData X                
Group By DATEPART(MONTH,X.DOS)                
*/                
                
End






GO

CREATE procedure [dbo].[rpt_Aging_Summary_By_Patient]      
(      
@ToDate DateTIME = null      
)               
as              
               
Begin         
  
  EXEC rpt_PatientAgaingReport @ToDate
  RETURN;

Print 'Execution Started : ' + convert(varchar(30),getdate(),114)            
Declare @TempData as Table (                
AcctNo   int,            
PatientName  Nvarchar(500),                
ProviderName Nvarchar(500),                
InsCompanyId  int,            
CompanyName  Nvarchar(500),                
CompanyCode  Nvarchar(500),                
DOS    Date,                
CPTCode   Nvarchar(50),                
Modifiers  Nvarchar(50),                
ChargeAmt  Numeric(18,2),                
PriDX   Nvarchar(50),                
POS    Nvarchar(50),                
ChargeNo  Numeric(18,0) Primary Key,                
Payments  Numeric(18,2),                
Adjustments  Numeric(18,2),                
PaymentBat  Nvarchar(100),                
Due    Numeric(18,2),                
RevenueCentre Nvarchar(500),                
ZeroDay   Numeric(18,2),                
ThirtyDays  Numeric(18,2),                
SixtyDays  Numeric(18,2),                
NinetyDays  Numeric(18,2),                
OneTwentyDays Numeric(18,2),            
TotalOwing Numeric(18,2),            
ShiftDate Date,            
FromDate Date,            
CaseNumber Numeric(18,0)                
                
)                
            
            
Declare @TempPaymentData as Table (             
            
ChargeNo   Numeric(18,0) Primary Key,                
PaymentAmt  Numeric(18,2)            
)            
            
Declare @TempAdjustmentData as Table (            
               
ChargeNo   Numeric(18,0) Primary Key,                
AdjustmentAmt  Numeric(18,2)                
)            
            
Declare @TempInsPolicy as Table (            
InsCompanyId int,            
PatientId int,            
PolicyId   bigint,            
CaseNumber  Numeric(18,0),            
InsLevel int,            
PlanEffectiveDate Date,            
PlanExpirationDate Date            
,            
Primary Key(            
PatientId,            
PolicyId            
))             
                
Insert Into @TempData                
(  AcctNo,   PatientName,  ProviderName,                
  InsCompanyId,  CompanyName ,  DOS,                
  CPTCode,  Modifiers,   ChargeAmt,                
  PriDX,   POS,    ChargeNo,                
  Payments,  Adjustments,  PaymentBat,                
  Due,   RevenueCentre,  ZeroDay,                
  ThirtyDays,  SixtyDays,   NinetyDays,                
  OneTwentyDays ,CompanyCode, TotalOwing,            
  FromDate, CaseNumber            
)                
select DISTINCT D.Id,  CONCAT ( D.LastName, ',', D.FirstName, ' ', D.MI ) [PatientName],  CONCAT(E.LastName, ',', E.FirstName) ,                          
     -- dbo.ufn_ActiveInsuranceForCaseNo(COALESCE(A.ShiftDate, A.FromDate),1, C.CaseNumber),             
  0,'',     Cast(A.BillFromDate as date) ,                            
      A.CPTCode [CPT], CONCAT(A.Mod1, A.Mod2, A.Mod3, A.Mod4) [Mods], A.Amount,                          
   --   H.ICD9_CM [PriDx],           
   --I.Descr [POS],          
'','',                 A.ChargeNo,                
   0 [Payments],  0 [Adjustments],  '',                
   0 [Due],   K.[CategoryName] [RevenueCentre], 0 [ZeroDay],                
   0 [ThirtyDays], 0 [SixtyDays],  0 [NinetyDays],                
   0 [OneTwentyDays] ,     ''   [CompanyCode], 0 [TotalOwing],            
  A.BillFromDate, C.CaseIdNumber            
from vw_CHARGE_Latest A  (NOLOCK)              
                
INNER JOIN Invoice B (NOLOCK) ON A.InvoiceId=B.Id         
join  PatientCase C (NOLOCK) ON C.Id = B.PatientCaseId                 
join Patient D (NOLOCK) ON C.PatientId = D.Id                
join [Provider] E (NOLOCK) ON D.ProviderID = E.Id                

--join BL_Inv_dx H (NOLOCK) ON H.InvoiceID = B.ID and H.DiagnosisNumber = 1                
--join BL_POS_Config I (NOLOCK) ON I.Code = A.PlaceOfService                  
left join CPTCode  (NOLOCK) J ON J.CPTCode = A.CPTCode                
left join CPTCategory (NOLOCK) K ON K.Id = J.CPTCategoryId                
                
WHERE  CAST(A.BillFromDate AS DATE) <= @ToDate             
and A.IsDeleted =0 and A.BillToInsurance = 0 AND A.ChargeNo > 0  And A.PatientCaseId > 0          
           
               
            
Print 'SQL Passed : ' + convert(varchar(30),getdate(),114)            
            
            
Insert Into @TempPaymentData            
( ChargeNo, PaymentAmt)            
Select Z.ChargeNum, Coalesce(Sum(Z.PaymentOrAdjAmount),0) from vw_PaymentsAdjustments Z            
Where z.IsDeleted =0 AND Z.ChargeNum > 0  and Z.PatientCaseId > 0  and Z.IsPayment = 1        
and Datediff(dd,Z.PaymentEffectiveDate,@ToDate) >= 0            
Group By ChargeNum                   
            
Insert Into @TempAdjustmentData            
(ChargeNo, AdjustmentAmt)            
Select Z.ChargeNum, Coalesce(Sum(Z.PaymentOrAdjAmount),0) from vw_PaymentsAdjustments Z            
Where  z.IsDeleted =0  AND Z.ChargeNum > 0   and Z.PatientCaseId > 0 and Z.IsPayment = 0      
and Datediff(dd,Z.PaymentEffectiveDate,@ToDate) >= 0                
Group By ChargeNum                   
            
Print 'Generatae Temp Payment and Adjustment Passed : ' + convert(varchar(30),getdate(),114)            
            
update @TempData               
Set Payments = B.PaymentAmt             
From @TempData A  join @TempPaymentData B On A.ChargeNo = B.ChargeNo            
            
Print 'Update Payments Passed : ' + convert(varchar(30),getdate(),114)            
            
update @TempData                
Set Adjustments = B.AdjustmentAmt             
From @TempData A  join @TempAdjustmentData B On A.ChargeNo = B.ChargeNo            
            
Print 'Update Adjustments Passed : ' + convert(varchar(30),getdate(),114)            
            
                
            
Insert Into @TempInsPolicy            
(InsCompanyId,  PatientId, PolicyId, CaseNumber, InsLevel, PlanEffectiveDate, PlanExpirationDate)            
SELECT  ip2.InsuranceCompanyID, pc.PatientId, ip2.Id, pc.CaseIdNumber, ip2.[InsuranceLevel], ip2.PlanEffectiveDate, ip2.PlanExpirationDate            
FROM  InsurancePolicy ip2 (NOLOCK)            
Left Join PatientCase pc (NOLOCK) ON pc.Id = ip2.PatientCaseId

            
            
Print 'Generate Temp Insurance Policy Passed : ' + convert(varchar(30),getdate(),114)            
            
update @TempData            
Set InsCompanyId = B.InsCompanyId            
FROM @TempData A  Join @TempInsPolicy B On A.AcctNo = B.PatientId              
       and  B.CaseNumber =A.CaseNumber            
       AND   B.InsLevel = 1            
       AND   B.PlanEffectiveDate <= A.DOS            
       AND   (B.PlanExpirationDate IS NULL            
        OR  B.PlanExpirationDate >= A.DOS)            
                   
            
Print 'Update Insurance Policy : ' + convert(varchar(30),getdate(),114)            
            
update @TempData                
Set Due = ChargeAmt - (Payments +  Adjustments),                
CompanyName = J.CompanyName  ,              
CompanyCode = J.CompanyCode              
From @TempData I left join InsuranceCompany J On I.InsCompanyId = J.Id                
            
Print 'update Due Amount Passed : ' + convert(varchar(30),getdate(),114)            
               
                
update @TempData                
Set                 
ZeroDay = Case when (Datediff(dd,DOS,@ToDate) <= 29) Then Due Else 0 End,                
ThirtyDays = Case when (Datediff(dd,DOS,@ToDate) >= 30) And (Datediff(dd,DOS,@ToDate) <= 59) Then Due  Else 0 End,                
SixtyDays = Case when (Datediff(dd,DOS,@ToDate) >= 60) And (Datediff(dd,DOS,@ToDate) <= 89) Then Due  Else 0 End,                
--NinetyDays = Case when (Datediff(dd,DOS,@ToDate) >= 90) And (Datediff(dd,DOS,@ToDate) <= 119) Then Due  Else 0 End,                
NinetyDays = Case when (Datediff(dd,DOS,@ToDate) >= 90) And (Datediff(dd,DOS,@ToDate) <= 999999999999) Then Due  Else 0 End,                
OneTwentyDays = Case when (Datediff(dd,DOS,@ToDate) >= 120) Then Due  Else 0 End           
             
               
Print 'update ageing Passed : ' + convert(varchar(30),getdate(),114)            
            
update @TempData            
Set TotalOwing =  ZeroDay +  ThirtyDays   + SixtyDays   + NinetyDays --+ OneTwentyDays            
            
             
              
--Ageing By Patient                
Select               
   X.AcctNo PatientID,              
   X.PatientName,               
   Sum(X.ZeroDay) [ZeroDays],              
   Sum(X.ThirtyDays) [ThirtyDays],              
   Sum(X.SixtyDays) [SixtyDays],              
   Sum(X.NinetyDays) [NintyDays],              
   Sum(X.OneTwentyDays) [OneTwentyDays],      
   Sum(X.TotalOwing) [TotalOwing]      
    from @TempData X              
   Where TotalOwing <> 0          
Group By X.AcctNo, X.PatientName           
           
Order by acctno              
                
Print 'Ageing By Patient Passed : ' + convert(varchar(30),getdate(),114)                
       
          
                
End





GO



CREATE procedure [dbo].[rpt_Aging_Summary_By_Revenue_Center]   (                    
                       
@ToDate DateTIME  =  null,
@PracticeId INT = 1             
)                       
as                  
Begin         
  
Print 'Execution Started : ' + convert(varchar(30),getdate(),114)              
Declare @TempData as Table (                  
AcctNo   int,              
PatientName  Nvarchar(500),                  
ProviderName Nvarchar(500),                  
InsCompanyId  int,              
CompanyName  Nvarchar(500),                  
CompanyCode  Nvarchar(500),                  
DOS    Date,                  
CPTCode   Nvarchar(50),                  
Modifiers  Nvarchar(50),                  
ChargeAmt  Numeric(18,2),                  
PriDX   Nvarchar(50),                  
POS    Nvarchar(50),                  
ChargeNo  Numeric(18,0) Primary Key,                  
Payments  Numeric(18,2),                  
Adjustments  Numeric(18,2),                  
PaymentBat  Nvarchar(100),                  
Due    Numeric(18,2),                  
RevenueCentre Nvarchar(500),                  
ZeroDay   Numeric(18,2),                  
ThirtyDays  Numeric(18,2),                  
SixtyDays  Numeric(18,2),                  
NinetyDays  Numeric(18,2),                  
OneTwentyDays Numeric(18,2),              
TotalOwing Numeric(18,2),              
ShiftDate Date,              
FromDate Date,              
CaseNumber Numeric(18,0) 

                  
)                                
              
Declare @TempPaymentData as Table (               
              
ChargeNo   Numeric(18,0) Primary Key,                  
PaymentAmt  Numeric(18,2)              
)              
              
Declare @TempAdjustmentData as Table (              
                 
ChargeNo   Numeric(18,0) Primary Key,                  
AdjustmentAmt  Numeric(18,2)                  
)              
              
Declare @TempInsPolicy as Table (              
InsCompanyId int,              
PatientId int,              
PolicyId   bigint,              
CaseNumber  Numeric(18,0),              
InsLevel int,              
PlanEffectiveDate Date,              
PlanExpirationDate Date,              
Primary Key(              
PatientId,              
PolicyId              
))               
                  
Insert Into @TempData                  
(  AcctNo,   PatientName,  ProviderName,                  
  InsCompanyId,  CompanyName ,  DOS,                  
  CPTCode,  Modifiers,   ChargeAmt,                  
  PriDX,   POS,    ChargeNo,                  
  Payments,  Adjustments,  PaymentBat,                  
  Due,   RevenueCentre,  ZeroDay,                  
  ThirtyDays,  SixtyDays,   NinetyDays,                  
  OneTwentyDays ,CompanyCode, TotalOwing,              
   FromDate, CaseNumber              
)                  
select DISTINCT D.Id,  CONCAT ( D.LastName, ',', D.FirstName, ' ', D.MI ) [PatientName],  CONCAT(E.LastName, ',', E.FirstName) ,                            
     -- dbo.ufn_ActiveInsuranceForCaseNo(COALESCE(A.ShiftDate, A.FromDate),1, C.CaseNumber),               
  0,'',     Cast(A.BillFromDate as date) ,                              
      A.CPTCode [CPT], CONCAT(A.Mod1, A.Mod2, A.Mod3, A.Mod4) [Mods],       A.Amount,                            
                
   --H.ICD9_CM [PriDx],           
   --I.Descr [POS],                   
   '',          
   '',          
        A.ChargeNo,                  
   0 [Payments],  0 [Adjustments],  '',                  
   0 [Due],   K.[CategoryName] [RevenueCentre], 0 [ZeroDay],                  
   0 [ThirtyDays], 0 [SixtyDays],  0 [NinetyDays],                  
   0 [OneTwentyDays] ,     ''   [CompanyCode], 0 [TotalOwing],              
    A.BillFromDate, C.CaseIdNumber   
from vw_CHARGE_Latest A  (NOLOCK) 
       
INNER JOIN Invoice B (NOLOCK) ON A.InvoiceId=B.Id and A.IsDeleted =0 
AND A.ChargeNo > 0  And A.PatientCaseId > 0 And A.BillToInsurance in (0,1) AND B.PracticeId = A.PracticeId
join  PatientCase C (NOLOCK) ON C.Id = B.PatientCaseId  AND C.PracticeId = B.PracticeId                 
join Patient D (NOLOCK) ON C.PatientId = D.Id  AND D.PracticeId = C.PracticeId                 
join [Provider] E (NOLOCK) ON D.ProviderID = E.Id  AND E.PracticeId = D.PracticeId 

--left join BL_Inv_dx H (NOLOCK) ON H.InvoiceID = B.ID and H.DiagnosisNumber = 1                  
--join BL_POS_Config I (NOLOCK) ON I.Code = A.PlaceOfService          
left join CPTCode  (NOLOCK) J ON J.CPTCode = A.CPTCode                  
left join CPTCategory (NOLOCK) K ON K.Id = J.CPTCategoryId                  
                  
WHERE  CAST(A.BillFromDate AS DATE) <= @ToDate               
AND A.PracticeId = @PracticeId
                 
              
Print 'SQL Passed : ' + convert(varchar(30),getdate(),114)              
              
              
Insert Into @TempPaymentData              
( ChargeNo, PaymentAmt)              
Select Z.ChargeNum, Coalesce(Sum(Z.PaymentOrAdjAmount),0) from vw_PaymentsAdjustments Z              
Where  z.IsDeleted =0  AND Z.ChargeNum > 0 AND Z.PatientCaseId > 0         
and Datediff(dd,Z.PaymentEffectiveDate,@ToDate) >= 0  AND Z.IsPayment =1 
Group By ChargeNum                    
              
Insert Into @TempAdjustmentData              
(ChargeNo, AdjustmentAmt)              
Select Z.ChargeNum, Coalesce(Sum(Z.PaymentOrAdjAmount),0) from vw_PaymentsAdjustments Z              
Where z.IsDeleted =0 AND Z.ChargeNum > 0    AND Z.PatientCaseId > 0 
and z.IsPayment = 0           
and Datediff(dd,Z.PaymentEffectiveDate,@ToDate) >= 0                    
Group By ChargeNum                     
              
Print 'Generatae Temp Payment and Adjustment Passed : ' + convert(varchar(30),getdate(),114)              
              
update @TempData                 
Set Payments = B.PaymentAmt               
From @TempData A  join @TempPaymentData B On A.ChargeNo = B.ChargeNo              
              
Print 'Update Payments Passed : ' + convert(varchar(30),getdate(),114)              
              
update @TempData                  
Set Adjustments = B.AdjustmentAmt               
From @TempData A  join @TempAdjustmentData B On A.ChargeNo = B.ChargeNo              
              
Print 'Update Adjustments Passed : ' + convert(varchar(30),getdate(),114)              
              
                  
              
Insert Into @TempInsPolicy              
(InsCompanyId,  PatientId, PolicyId, CaseNumber, InsLevel, PlanEffectiveDate, PlanExpirationDate)              
SELECT  ip2.InsuranceCompanyID, pc.PatientId, ip2.Id, pc.CaseIdNumber, ip2.[InsuranceLevel], ip2.PlanEffectiveDate, ip2.PlanExpirationDate              
FROM  InsurancePolicy ip2 (NOLOCK) 
Left Join PatientCase pc (NOLOCK) ON pc.Id = ip2.PatientCaseId

              
              
Print 'Generate Temp Insurance Policy Passed : ' + convert(varchar(30),getdate(),114)              
              
update @TempData              
Set InsCompanyId = B.InsCompanyId              
FROM @TempData A  Join @TempInsPolicy B On A.AcctNo = B.PatientId                
       and  B.CaseNumber =A.CaseNumber              
       AND   B.InsLevel = 1              
       AND   B.PlanEffectiveDate <= A.DOS              
       AND   (B.PlanExpirationDate IS NULL              
        OR  B.PlanExpirationDate >= A.DOS)              
                     
              
Print 'Update Insurance Policy : ' + convert(varchar(30),getdate(),114)              
              
update @TempData                  
Set Due = ChargeAmt - (Payments +  Adjustments),                  
CompanyName = J.CompanyName  ,                
CompanyCode = J.CompanyCode                
From @TempData I left join InsuranceCompany J On I.InsCompanyId = J.Id                  
       
Print 'update Due Amount Passed : ' + convert(varchar(30),getdate(),114)              
                 
                  
update @TempData                  
Set                   
ZeroDay = Case when (Datediff(dd,DOS,@ToDate) <= 29) Then Due Else 0 End,                  
ThirtyDays = Case when (Datediff(dd,DOS,@ToDate) >= 30) And (Datediff(dd,DOS,@ToDate) <= 59) Then Due  Else 0 End,                  
SixtyDays = Case when (Datediff(dd,DOS,@ToDate) >= 60) And (Datediff(dd,DOS,@ToDate) <= 89) Then Due  Else 0 End,                  
NinetyDays = Case when (Datediff(dd,DOS,@ToDate) >= 90) And (Datediff(dd,DOS,@ToDate) <= 119) Then Due  Else 0 End,                  
OneTwentyDays = Case when (Datediff(dd,DOS,@ToDate) >= 120)  Then Due  Else 0 End            
            
                  
Print 'update ageing Passed : ' + convert(varchar(30),getdate(),114)              
              
update @TempData              
Set TotalOwing =  ZeroDay +  ThirtyDays   + SixtyDays   + NinetyDays --+ OneTwentyDays              
         
Print 'Ageing By Patient Passed : ' + convert(varchar(30),getdate(),114)                  
                  
-- Ageing By Revenue Centre                  
Select Coalesce(X.RevenueCentre,'Non Revenue Center') RevenueCenter,                    
 Sum(X.ZeroDay) [ZeroDays],                     
 Sum(X.ThirtyDays) [ThirtyDays],                    
  Sum(X.SixtyDays) [SixtyDays],                    
   Sum(X.NinetyDays) [NintyDays],                    
    Sum(X.OneTwentyDays) [OneTwentyDays],        
    Sum(x.TotalOwing) [TotalOwing]        
    from @TempData X                 
Group By X.RevenueCentre                      
Order By X.RevenueCentre              
Print 'Ageing By Revenue Center Passed : ' + convert(varchar(30),getdate(),114)                          
              
                  
End



GO

--EXEC rpt_CCPA_By_Provider_Report '2020-04-01', '2020-08-31'    
CREATE PROCEDURE [dbo].[rpt_CCPA_By_Provider_Report]                         
 @FromDate datetime = NULL,                                          
 @ToDate  datetime = NULL,                                          
 @ProviderID int = -1                                          
AS                                          
    --declare @FromDate  datetime = '4/1/2018',                         
    --@ToDate   datetime = '4/30/2018',  @ProviderID  int = -1                          
     
;WITH AllCharges AS                         
(                        
SELECT v.ChargeNo, 
	   v.CreatedDate,
	   u.Id,
	   u.FirstName,
	   u.LastName, 
	   v.Amount,
	   v.ClaimId,
	   v.Id As ChargeId
FROM   vw_CHARGE_Latest v (NOLOCK)                         
	   LEFT JOIN [Provider] u (NOLOCK) on v.PerformingProviderId=u.Id                        
WHERE  (@FromDate IS NULL OR (cast(v.CreatedDate as date) >=@FromDate AND cast(v.CreatedDate as date)<=@ToDate  ))                          
		AND (@ProviderID = -1 OR v.PerformingProviderId = @ProviderID)                        
		AND v.ChargeNo > 0 AND v.PatientCaseId > 0 AND v.IsDeleted =0
		AND v.Amount > 0
),                        
    
Charges AS                         
(                        
 SELECT Month(v.CreatedDate) MonthNo,                        
        Year(v.CreatedDate) YearNo,                        
        v.Id DoctorId,                         
        v.FirstName,
		v.LastName,                        
        COUNT(1) TCount,                          
        CAST(SUM(v.Amount) as decimal(10,2))   Total	
 FROM  AllCharges v 
 GROUP BY v.FirstName,v.LastName, v.Id,                        
        Month(v.CreatedDate),                        
        Year(v.CreatedDate)                        
 ),                        
    

ClaimsSent AS
(
SELECT Month(v.CreatedDate) MonthNo,                        
       Year(v.CreatedDate) YearNo,                        
       v.Id DoctorId,                         
       v.FirstName,
	   v.LastName ,                        
       COUNT(1) TCount,                          
       CAST(SUM(v.Amount) as decimal(10,2))   Total	
 FROM  AllCharges v (NOLOCK)      
       LEFT JOIN Claim c (NOLOCK) on v.ClaimId = c.Id
 WHERE c.[Status] = 'SENT'
 GROUP BY v.FirstName,v.LastName,v.Id,                        
    Month(v.CreatedDate),                        
    Year(v.CreatedDate)	
),



ClaimsNotSent AS                         
(                        
SELECT Month(v.CreatedDate) MonthNo,                        
       Year(v.CreatedDate) YearNo,                        
       v.Id DoctorId,                         
       v.FirstName,
	   v.LastName,                        
       COUNT(1) TCount,                          
       CAST(SUM(v.Amount) as decimal(10,2))   Total	
 FROM  AllCharges v (NOLOCK)       
       LEFT JOIN Claim c (NOLOCK) on v.ClaimId = c.Id
 WHERE (c.[Status] = 'CREATED' 
       OR v.ChargeId NOT IN (Select ChargeId from ClaimCharge))
 GROUP BY v.FirstName,v.LastName,v.Id,                        
    Month(v.CreatedDate),                        
    Year(v.CreatedDate)                      
 ),       
 

 AllPayments AS
 (
SELECT u.FirstName,
	   u.LastName,
	   v.PerformingProviderId,                        
       PaymentEffectiveDate,                                                      
       PaymentOrAdjAmount,
	   IsPayment,
	   ChargeNum
FROM vw_PaymentsAdjustments v (NOLOCK)                       
      LEFT JOIN [Provider] u (NOLOCK) on v.PerformingProviderId =u.Id                        
WHERE ((CAST(v.PaymentEffectiveDate AS DATE) >= CAST(@FromDate AS DATE)          
                             OR @FromDate IS NULL)          
    AND (CAST(v.PaymentEffectiveDate AS DATE) <= CAST(@ToDate AS DATE)          
    OR @ToDate IS NULL))      
   AND v.ChargeNum > 0 AND v.PatientCaseId > 0   
    AND v.IsDeleted = 0     
 ),


 MonthlyPayment AS                        
 (                        
SELECT v.FirstName,
	   v.LastName,
	   v.PerformingProviderId [DoctorId],                        
       Month(PaymentEffectiveDate) MonthNo,                        
       Year(PaymentEffectiveDate)YearNo,                        
       SUM(PaymentOrAdjAmount) TPMT	
FROM AllPayments v (NOLOCK)  
WHERE  v.IsPayment = 1
GROUP BY  v.FirstName,v.LastName ,v.PerformingProviderId,                        
    Month(PaymentEffectiveDate) ,                        
    Year(PaymentEffectiveDate)                        
 ),                        


 MonthlyAdjustment AS                         
 (                        
SELECT v.FirstName,
	   v.LastName,
	   v.PerformingProviderId [DoctorId],     
       Month(PaymentEffectiveDate) MonthNo,                        
       Year(PaymentEffectiveDate)YearNo,                        
       SUM(PaymentOrAdjAmount) TPMT	
FROM AllPayments v (NOLOCK)                       
WHERE  v.IsPayment = 0                
GROUP BY  v.FirstName,v.LastName ,v.PerformingProviderId,     
     Month(PaymentEffectiveDate) ,                        
     Year(PaymentEffectiveDate)                        
 ), 
 
 
 ChargeWisePayment AS                        
 (                        
 SELECT  v.FirstName,
		 v.LastName,
		 v.PerformingProviderId [DoctorId],                        
         Month(PaymentEffectiveDate) MonthNo,                        
         Year(PaymentEffectiveDate)YearNo,                        
         SUM(PaymentOrAdjAmount) CTPMT	
 From AllPayments v (NOLOCK)                       
 WHERE v.IsPayment = 1 AND   
	   v.ChargeNum IN (SELECT v.ChargeNo FROM  AllCharges v)                   
 GROUP BY  v.FirstName,v.LastName, v.PerformingProviderId,                        
    Month(PaymentEffectiveDate),                        
    Year(PaymentEffectiveDate)                        
 ),      


 ChargeWiseAdjustment AS                         
 (                        
SELECT v.FirstName,
	   v.LastName, 
	   v.PerformingProviderId [DoctorId],     
       Month(PaymentEffectiveDate) MonthNo,                        
       Year(PaymentEffectiveDate)YearNo,                        
       SUM(PaymentOrAdjAmount) CTPMT	
From AllPayments v (NOLOCK)	   
WHERE v.IsPayment = 0    
      AND v.ChargeNum IN (SELECT v.ChargeNo FROM  AllCharges v)
GROUP BY  v.FirstName, v.LastName ,v.PerformingProviderId,     
     Month(PaymentEffectiveDate) ,                        
    Year(PaymentEffectiveDate)                        
 ), 

 unAll as                        
 (                        
     SELECT FirstName,                        
    LastName ,                        
    DoctorID,                        
    C.MonthNo,                        
    C.YearNo                        
    FROM   Charges C  (NOLOCK)  
   UNION ALL      
  SELECT FirstName,                        
    LastName ,                        
    DoctorID,                        
    C.MonthNo,                        
    C.YearNo                        
    FROM   ClaimsSent C  (NOLOCK)  
    UNION ALL      
	 SELECT FirstName,                        
    LastName ,                        
    DoctorID,                        
    C.MonthNo,                        
    C.YearNo                        
    FROM   ClaimsNotSent C  (NOLOCK)  
    UNION ALL      
    SELECT FirstName,                        
    LastName ,                        
   DoctorID,                        
    C.MonthNo,                        
    C.YearNo                        
    FROM   MonthlyPayment c   (NOLOCK)              
                        
                    
    UNION ALL                        
    SELECT FirstName,                        
    LastName ,                        
   DoctorID,                        
    C.MonthNo,                        
    C.YearNo                        
    FROM   MonthlyAdjustment c  (NOLOCK)   
	
	 UNION ALL                        
    SELECT FirstName,                        
    LastName ,                        
    DoctorID,                        
    C.MonthNo,                        
    C.YearNo                        
    FROM   ChargeWisePayment c  (NOLOCK)   

	UNION ALL                        
    SELECT FirstName,                        
    LastName ,                        
    DoctorID,                        
    C.MonthNo,                        
    C.YearNo                        
    FROM   ChargeWiseAdjustment c  (NOLOCK)  
),  

AllData AS(                        
    SELECT distinct U.LastName + ' ' + u.FirstName Provider,                        
    C.Total ChargeTotal,     
    CS.Total ClaimSentTotal, 
	CNS.Total ClaimNotSentTotal, 
    P.TPMT PaymentTotal,                        
    A.TPMT AdjustmentTotal,   
	CP.CTPMT ChargeWisePaymentTotal,
	CA.CTPMT ChargeWiseAdjustmentTotal,
    convert(varchar(2), u.MonthNo) +'-'+convert(varchar(4),u.YearNo) PostMonth                        
                        
    FROM unAll u  (NOLOCK)                       
    LEFT JOIN Charges c (NOLOCK) on  C.DoctorId = u.DoctorId and C.MonthNo = U.MonthNo AND C.YearNo = U.YearNo     
   
    LEFT JOIN ClaimsSent CS (NOLOCK) on  CS.DoctorId = u.DoctorId and CS.MonthNo = U.MonthNo AND CS.YearNo = U.YearNo    

	LEFT JOIN ClaimsNotSent CNS (NOLOCK) on  CNS.DoctorId = u.DoctorId and CNS.MonthNo = U.MonthNo AND CNS.YearNo = U.YearNo    
                        
    LEFT JOIN MonthlyPayment p (NOLOCK) on  p.DoctorId = u.DoctorId and p.MonthNo = U.MonthNo AND p.YearNo = U.YearNo                        
                        
    LEFT JOIN MonthlyAdjustment a (NOLOCK) on a.DoctorId = u.DoctorId and a.MonthNo = U.MonthNo AND a.YearNo = U.YearNo     
	
	LEFT JOIN ChargeWisePayment cp (NOLOCK) on cp.DoctorId = u.DoctorId and cp.MonthNo = U.MonthNo AND cp.YearNo = U.YearNo   
	
	LEFT JOIN ChargeWiseAdjustment ca (NOLOCK) on ca.DoctorId = u.DoctorId and ca.MonthNo = U.MonthNo AND ca.YearNo = U.YearNo   
)                        
SELECT * FROM AllData  ORDER BY PostMonth DESC 


GO


CREATE PROCEDURE [dbo].[rpt_ChargeDetailsByDOSByCategory]  
 @FromDate datetime=NULL,  
 @ToDate  datetime=NULL   
AS   
 SELECT    
    p.LASTNAME + ', ' + p.FIRSTNAME as Patient,  
    CAST(ch.BillFromDate AS DATE) as DOS,   
    ch.CPTCode,  
    CAST(ch.Amount as decimal(10,2)) as ChargeAmount,  
    cc.CategoryName as RevCenter  
       
 FROM  vw_CHARGE_Latest ch  
 LEFT JOIN PatientCase pc  
  ON  pc.Id = ch.PatientCaseId  
 LEFT JOIN Patient p  
  ON  p.Id = pc.PatientId  
 LEFT JOIN CPTCode cpt  
  ON  cpt.CPTCode = ch.CPTCODE  
 LEFT JOIN CPTCategory cc  
  ON  cc.ID = cpt.CPTCategoryId   
 WHERE  (@FromDate IS NULL  
     OR CAST(ch.BillFromDate AS DATE) BETWEEN @FromDate AND DATEADD(day, -1, @ToDate))   
 order BY cc.CategoryName  
   
 SELECT  6, 6, 3, 6, 6 


GO


CREATE PROCEDURE [dbo].[rpt_ChargeDetailsByPostDate]    
 @FromDate datetime=NULL,    
 @ToDate  datetime=NULL,  
 @PracticeId INT = 1    
AS     
     
     
 SELECT  ch.EntryDate as [PostDate],    
    ch.BillFromDate as DOS,    
    --ISNULL(ch.ShiftDate, ch.FromDate) DOS,    
    cpt.CPTCode as CPT,    
    ch.MOD1 as [Mod],    
    cpt.[Description] as [Description],    
    cc.CategoryName as Category,    
    ch.Qty,    
    CAST(ch.Amount as decimal(10,2)) as Charge,    
    p.BillingID,    
    p.LastName + ', ' + p.FirstName as Patient,    
    ISNULL(ic.CompanyName, '') as Insurance,    
    perfDoc.LastName as [PerformingProvider],    
    billDoc.LastName as [BillingProvider],    
    ch.POSId  ,  
 ch.PracticeId  
 FROM  vw_CHARGE_Latest ch    
 LEFT JOIN PatientCase pc    
  ON  pc.Id = ch.PatientCaseId    
 LEFT JOIN Patient p    
  ON  p.Id = pc.PatientId    
 LEFT JOIN CPTCode cpt    
  ON  cpt.CPTCode = ch.CPTCODE    
 LEFT JOIN CPTCategory cc    
  ON  cc.ID = cpt.CPTCategoryId    
 LEFT JOIN [Provider] perfDoc    
  ON  perfDoc.Id = ch.PerformingProviderId    
 LEFT JOIN [Provider] billDoc    
  ON     billDoc.Id = ch.PerformingProviderId    
 --LEFT JOIN InsurancePolicy ip    
 -- ON  ip.CaseNumber =Ch.CaseNo AND ip.Level=1 -- dbo.ufn_PrimaryInsurance(p.PatientID, ch.FromDate)    
 LEFT JOIN InsuranceCompany ic    
  ON  ic.Id = dbo.ufn_ActiveInsuranceForCaseNo(ch.BillFromDate,1,ch.PatientCaseId)    
 WHERE  (@FromDate IS NULL OR (CAST(ch.CreatedDate as DATE) >= @FromDate AND CAST(ch.CreatedDate as DATE) <= DATEADD(day, -1, CAST(@ToDate AS DATE))))    
  AND ch.IsDeleted = 0 AND ch.ChargeNo > 0 AND ch.PatientCaseId > 0 AND ch.PracticeId = @PracticeId    
 ORDER BY ch.EntryDate,  ch.IsDeleted DESC    
     
 SELECT  6, 6, 5, 3, 15, 5, 4, 6, 5, 8, 10, 7, 7, 3 


GO

--rpt_ChargesDOSReport '1 sep 2021','30 sep 2021'
CREATE PROCEDURE [dbo].[rpt_ChargesDOSReport]      
 @FromDate datetime=NULL,      
 @ToDate  datetime=NULL,      
 @ProviderID int = NULL,
 @FacilityID int = NULL,
 @AuxillaryProviderId int = NULL,
 @RefferingProviderId int = NULL,
 @IsExcel int = 1
WITH RECOMPILE      
AS      
	IF (@IsExcel=0)
	BEGIN
		SELECT distinct  pc.CaseIdNumber as 'AcctNo',      
			p.LASTNAME + ', ' + p.FIRSTNAME as 'PatientName',      
			--(select concat([Provider].LastName,', ',[Provider].FirstName) from [Provider] where [Provider].Id=ch.PerformingProviderId) as 'Providers',      
			concat(perfDoc.LastName,', ',perfDoc.FirstName) Providers,
			ic.CompanyCode + ' - '+ ISNULL(ic.CompanyName, '') as 'PrimaryInsurance',      
			ch.BillFromDate as DOS,           
			cpt.CPTCode as CPT,       
			ch.MOD1 as [Mod],      
			CAST(ch.Amount as decimal(10,2)) as Charge,      
			ch.ICD1 as 'PriDX',      
			fac.FacilityDescription [POS],  
		 ch.PracticeId,ch.PaidAmount,ch.TotalAdjustment,ch.DueAmount ,ch.BillFromDate, ch.EntryDate, ch.IsDeleted 
          
		 FROM  vw_GetChargeForPendingPayment ch      
		 LEFT JOIN PatientCase(NOLOCK) pc      
		  ON  pc.Id = ch.PatientCaseId      
		 LEFT JOIN Patient(NOLOCK) p      
		  ON  p.Id = pc.PatientId      
		 LEFT JOIN CPTCode(NOLOCK) cpt      
		  ON  cpt.CPTCode = ch.CPTCODE      
		 LEFT JOIN CPTCategory(NOLOCK) cc      
		  ON  cc.Id = cpt.CPTCategoryId      
		 LEFT JOIN [Provider](NOLOCK) perfDoc      
		  ON  perfDoc.Id = ch.PerformingProviderId      
       
		 LEFT JOIN InsuranceCompany(NOLOCK) ic      
		  ON  ic.Id = dbo.ufn_ActiveInsuranceForCaseNo(ch.BillFromDate,1,ch.PatientCaseId)      
		 LEFT JOIN Facility(NOLOCK) fac on fac.Id = ch.PerformingFacilityId        
		 --WHERE  (@FromDate IS NULL OR CAST(ISNULL(ch.ShiftDate, ch.FromDate) AS DATE) BETWEEN @FromDate AND DATEADD(day, -1, @ToDate2))      
		 WHERE  (CAST(@FromDate AS date) IS NULL OR CAST(ch.BillFromDate AS DATE) BETWEEN CAST(@FromDate AS date) AND CAST(@ToDate AS date))      
       
		  AND ch.IsDeleted = 0 AND ch.ChargeNo > 0 AND ch.PatientCaseId > 0       
		  AND  (@ProviderID is NULL OR @ProviderID = ch.PerformingProviderId)  
		  AND  (@FacilityID is NULL OR @FacilityID= ch.PerformingFacilityId)
		  AND  (@AuxillaryProviderId is NULL OR @AuxillaryProviderId = ch.AuxillaryProviderId)  
		  AND  (@RefferingProviderId is NULL OR @RefferingProviderId = ch.RefDoctorId)  
		  AND ch.PracticeId = 1 AND ch.DueAmount>=0
		 ORDER BY ch.BillFromDate, ch.EntryDate, ch.IsDeleted DESC      

	END
	ELSE
	BEGIN
		SELECT distinct pc.CaseIdNumber as 'AcctNo',      
			p.LASTNAME + ', ' + p.FIRSTNAME as 'PatientName',      
			--(select concat([Provider].LastName,', ',[Provider].FirstName) from [Provider] where [Provider].Id=ch.PerformingProviderId) as 'Providers',      
			concat(perfDoc.LastName,', ',perfDoc.FirstName) Providers,
			ic.CompanyCode + ' - '+ ISNULL(ic.CompanyName, '') as 'PrimaryInsurance',      
			CONVERT(varchar,ch.BillFromDate,1) as DOS,           
			cpt.CPTCode as CPT,       
			ch.MOD1 as [Mod],      
			CAST(ch.Amount as decimal(10,2)) as Charge,      
			ch.ICD1 as 'PriDX',      
			fac.FacilityDescription [POS],  
		 ch.PaidAmount,ch.TotalAdjustment,ch.DueAmount,ch.BillFromDate, ch.EntryDate, ch.IsDeleted 
          
		 FROM  vw_GetChargeForPendingPayment ch      
		 LEFT JOIN PatientCase(NOLOCK) pc      
		  ON  pc.Id = ch.PatientCaseId      
		 LEFT JOIN Patient(NOLOCK) p      
		  ON  p.Id = pc.PatientId      
		 LEFT JOIN CPTCode(NOLOCK) cpt      
		  ON  cpt.CPTCode = ch.CPTCODE      
		 LEFT JOIN CPTCategory(NOLOCK) cc      
		  ON  cc.Id = cpt.CPTCategoryId      
		 LEFT JOIN [Provider](NOLOCK) perfDoc      
		  ON  perfDoc.Id = ch.PerformingProviderId      
       
		 LEFT JOIN InsuranceCompany(NOLOCK) ic      
		  ON  ic.Id = dbo.ufn_ActiveInsuranceForCaseNo(ch.BillFromDate,1,ch.PatientCaseId)      
		 LEFT JOIN Facility(NOLOCK) fac on fac.Id = ch.PerformingFacilityId        
		 --WHERE  (@FromDate IS NULL OR CAST(ISNULL(ch.ShiftDate, ch.FromDate) AS DATE) BETWEEN @FromDate AND DATEADD(day, -1, @ToDate2))      
		 WHERE  (CAST(@FromDate AS date) IS NULL OR CAST(ch.BillFromDate AS DATE) BETWEEN CAST(@FromDate AS date) AND CAST(@ToDate AS date))      
       
		  AND ch.IsDeleted = 0 AND ch.ChargeNo > 0 AND ch.PatientCaseId > 0       
		  AND  (@ProviderID is NULL OR @ProviderID = ch.PerformingProviderId)  
		  AND  (@FacilityID is NULL OR @FacilityID= ch.PerformingFacilityId)
		  AND  (@AuxillaryProviderId is NULL OR @AuxillaryProviderId = ch.AuxillaryProviderId)  
		  AND  (@RefferingProviderId is NULL OR @RefferingProviderId = ch.RefDoctorId)  
		  AND ch.PracticeId = 1 AND ch.DueAmount>=0
		 ORDER BY ch.BillFromDate, ch.EntryDate, ch.IsDeleted DESC      
	END




GO

--rpt_CPA_By_AuxillaryProvider_By_PostDate_Report '1 July 2021','10 July 2021'
CREATE PROCEDURE [dbo].[rpt_CPA_By_AuxillaryProvider_By_PostDate_Report]
@FromDate datetime = NULL,                                        
 @ToDate  datetime = NULL,                                        
 @ProviderID int = -1                                        
AS                                        
    --declare @FromDate  datetime = '4/1/2018',                       
    --@ToDate   datetime = '4/30/2018',  @ProviderID  int = -1    

;WITH Charges AS                       
(                      
 SELECT Month(v.CreatedDate) MonthNo,                      
    Year(v.CreatedDate) YearNo,                      
    u.Id DoctorId,                       
     u.FirstName,u.LastName ,                      
    COUNT(1) TCount,                        
    CAST(SUM(v.Amount) as decimal(10,2))   Total                      
 FROM  vw_CHARGE_Latest v (NOLOCK)                       
  LEFT JOIN [Provider] u (NOLOCK) on v.AuxillaryProviderID=u.Id                      
  WHERE  (@FromDate IS NULL OR (cast(v.CreatedDate as date) >=@FromDate AND cast(v.CreatedDate as date)<=@ToDate  ))                        
  AND  (@ProviderID = -1 OR v.AuxillaryProviderID= @ProviderID)                      
  AND v.ChargeNo > 0 AND v.PatientCaseId > 0                  
  AND v.IsDeleted =0  
  AND v.AuxillaryProviderID IS NOT NULL
 GROUP BY u.FirstName,U.LastName,u.Id ,                      
    Month(v.CreatedDate),                      
    Year(v.CreatedDate)                      
 )
 ,                    
 Payment AS                      
 (                      
    SELECT  u.FirstName,u.LastName ,v.AuxillaryProviderID [DoctorId],                      
    Month(PaymentEffectiveDate) MonthNo,                      
    Year(PaymentEffectiveDate)YearNo,                      
    SUM(PaymentOrAdjAmount) TPMT                      
     From vw_PaymentsAdjustments v (NOLOCK)                     
 LEFT JOIN [Provider] u (NOLOCK) on v.AuxillaryProviderID =u.Id                      
    WHERE ((CAST(v.PaymentEffectiveDate AS DATE) >= CAST(@FromDate AS DATE)        
                         OR @FromDate IS NULL)        
                        AND (CAST(v.PaymentEffectiveDate AS DATE) <= CAST(@ToDate AS DATE)        
                             OR @ToDate IS NULL))    
    AND v.ChargeNum > 0 AND v.PatientCaseId > 0   and v.IsPayment = 1  
    AND v.IsDeleted = 0                                  
    GROUP BY  u.FirstName,u.LastName ,v.AuxillaryProviderID,                      
    Month(PaymentEffectiveDate) ,                      
    Year(PaymentEffectiveDate)                      
                      
 )
 ,                      
 adj as                       
 (                      
      SELECT  u.FirstName,u.LastName ,v.AuxillaryProviderID [DoctorId],   
     Month(PaymentEffectiveDate) MonthNo,                      
    Year(PaymentEffectiveDate)YearNo,                      
    SUM(PaymentOrAdjAmount) TPMT                      
     From vw_PaymentsAdjustments v (NOLOCK)                     
 LEFT JOIN [Provider] u (NOLOCK) on v.AuxillaryProviderID =u.Id    
    WHERE ((CAST(v.PaymentEffectiveDate AS DATE) >= CAST(@FromDate AS DATE)        
                         OR @FromDate IS NULL)        
                        AND (CAST(v.PaymentEffectiveDate AS DATE) <= CAST(@ToDate AS DATE)        
                             OR @ToDate IS NULL))    
     AND v.ChargeNum > 0 AND v.PatientCaseId > 0    and v.IsPayment = 0  
    AND v.IsDeleted = 0                   
    GROUP BY  u.FirstName,u.LastName ,v.AuxillaryProviderID,   
     Month(PaymentEffectiveDate) ,                      
    Year(PaymentEffectiveDate)                      
                      
 ),                      
 unAll as                      
 (                      
     SELECT FirstName,                      
    LastName ,           
    DoctorID,                      
    C.MonthNo,                      
    C.YearNo                      
    FROM   Charges C  (NOLOCK)                                    
    UNION ALL    
    SELECT FirstName,                      
    LastName ,                      
   DoctorID,                      
    C.MonthNo,                      
    C.YearNo                      
    FROM   Payment c   (NOLOCK)            
                      
                  
    UNION ALL                      
    SELECT FirstName,                      
    LastName ,                      
    DoctorID,                      
    C.MonthNo,                      
    C.YearNo                      
    FROM   adj c  (NOLOCK)                    
),                      
AllData AS(                      
    SELECT distinct U.LastName + ' ' + u.FirstName Provider,                      
    C.Total ChargeTotal,                      
    P.TPMT PaymentTotal,                      
    A.TPMT AdjustmentTotal,                          
    convert(varchar(2), u.MonthNo) +'-'+convert(varchar(4),u.YearNo) PostMonth                      
                      
    FROM unAll u  (NOLOCK)                     
    LEFT JOIN Charges c (NOLOCK) on  C.DoctorId=u.DoctorId and C.MonthNo=U.MonthNo AND C.YearNo=U.YearNo                      
                      
    LEFT JOIN Payment p (NOLOCK) on                      
    p.DoctorId=u.DoctorId and p.MonthNo=U.MonthNo AND p.YearNo=U.YearNo                      
                      
  LEFT JOIN adj a (NOLOCK) on                      
    a.DoctorId=u.DoctorId and a.MonthNo=U.MonthNo AND a.YearNo=U.YearNo                      
)                      
SELECT * FROM AllData  where Provider is not null

GO

--rpt_CPA_By_Facility_By_PostDate_Report '1 July 2021','31 July 2021',null
CREATE PROCEDURE [dbo].[rpt_CPA_By_Facility_By_PostDate_Report]
 @FromDate datetime = NULL,                                        
 @ToDate  datetime = NULL,                                        
 @FacilityId	INT=null,
 @IsExcel BIT=0
 AS                                        
    --declare @FromDate  datetime = '4/1/2018',                       
    --@ToDate   datetime = '4/30/2018',  @ProviderID  int = -1                        

DECLARE @Temp TABLE
(
Provider NVARCHAR(200),
ChargeTotal MONEY,
PaymentTotal MONEY,
AdjustmentTotal MONEY,
PostMonth NVARCHAR(50)
)
                      
;WITH Charges AS                       
(                      
 SELECT Month(v.CreatedDate) MonthNo,                      
    Year(v.CreatedDate) YearNo,                      
    u.Id DoctorId,                       
     u.FacilityDescription ,                      
    COUNT(1) TCount,                        
    CAST(SUM(v.Amount) as decimal(10,2))   Total                      
 FROM  vw_CHARGE_Latest v (NOLOCK)                       
  LEFT JOIN Facility u (NOLOCK) on v.PerformingFacilityId=u.Id                      
  WHERE  (@FromDate IS NULL OR (cast(v.CreatedDate as date) >=@FromDate AND cast(v.CreatedDate as date)<=@ToDate  ))                        
  AND (@FacilityId is null OR v.PerformingFacilityId = @FacilityId)   
  AND v.ChargeNo > 0 AND v.PatientCaseId > 0                      
    
  AND v.IsDeleted =0  
 GROUP BY u.FacilityDescription,u.Id ,                      
    Month(v.CreatedDate),                      
    Year(v.CreatedDate)                      
 ),                      
                      
 Payment AS                      
 (                      
    SELECT  u.FacilityDescription ,v.PerformingFacilityId [DoctorId],                      
    Month(PaymentDate) MonthNo,                      
    Year(PaymentDate)YearNo,                      
    SUM(PaymentOrAdjAmount) TPMT                      
     From vw_PaymentsAdjustments v (NOLOCK)                     
 LEFT JOIN Facility u (NOLOCK) on v.PerformingFacilityId=u.Id                      
    WHERE ((CAST(v.PaymentDate AS DATE) >= CAST(@FromDate AS DATE)        
                         OR @FromDate IS NULL)        
                        AND (CAST(v.PaymentDate AS DATE) <= CAST(@ToDate AS DATE)        
                             OR @ToDate IS NULL))  							 
  AND  (@FacilityId is null OR v.PerformingFacilityId = @FacilityId)
    AND v.ChargeNum > 0 AND v.PatientCaseId > 0   and v.IsPayment = 1  
    AND v.IsDeleted = 0                                  
    GROUP BY  u.FacilityDescription ,v.PerformingFacilityId,                      
    Month(PaymentDate) ,                      
    Year(PaymentDate)                      
                      
 ),                      
 adj as                       
 (                      
      SELECT  u.FacilityDescription ,v.PerformingFacilityId [DoctorId],   
     Month(PaymentDate) MonthNo,                      
    Year(PaymentDate)YearNo,                      
    SUM(PaymentOrAdjAmount) TPMT                      
     From vw_PaymentsAdjustments v (NOLOCK)                     
 LEFT JOIN Facility u (NOLOCK) on v.PerformingFacilityId =u.Id    
    WHERE ((CAST(v.PaymentDate AS DATE) >= CAST(@FromDate AS DATE)        
                         OR @FromDate IS NULL)        
                        AND (CAST(v.PaymentDate AS DATE) <= CAST(@ToDate AS DATE)        
                             OR @ToDate IS NULL))    							 
  AND  (@FacilityId is null OR v.PerformingFacilityId = @FacilityId)
     AND v.ChargeNum > 0 AND v.PatientCaseId > 0    and v.IsPayment = 0  
    AND v.IsDeleted = 0                   
    GROUP BY  u.FacilityDescription,v.PerformingFacilityId,   
     Month(PaymentDate) ,                      
    Year(PaymentDate)                      
                      
 ),                      
 unAll as                      
 (                      
     SELECT FacilityDescription ,           
    DoctorID,                      
    C.MonthNo,                      
    C.YearNo                      
    FROM   Charges C  (NOLOCK)                                    
    UNION ALL    
    SELECT FacilityDescription ,                      
   DoctorID,                      
    C.MonthNo,                      
    C.YearNo                      
    FROM   Payment c   (NOLOCK)            
                      
                  
    UNION ALL                      
    SELECT FacilityDescription,                      
    DoctorID,                      
    C.MonthNo,                      
    C.YearNo                      
    FROM   adj c  (NOLOCK)                    
),                      
AllData AS(                      
    SELECT distinct u.FacilityDescription Provider,                      
    C.Total ChargeTotal,                      
    P.TPMT PaymentTotal,                      
    A.TPMT AdjustmentTotal,                          
    convert(varchar(2), u.MonthNo) +'-'+convert(varchar(4),u.YearNo) PostMonth                      
                      
    FROM unAll u  (NOLOCK)                     
    LEFT JOIN Charges c (NOLOCK) on  C.DoctorId=u.DoctorId and C.MonthNo=U.MonthNo AND C.YearNo=U.YearNo                      
                      
    LEFT JOIN Payment p (NOLOCK) on                      
    p.DoctorId=u.DoctorId and p.MonthNo=U.MonthNo AND p.YearNo=U.YearNo                      
                      
  LEFT JOIN adj a (NOLOCK) on                      
    a.DoctorId=u.DoctorId and a.MonthNo=U.MonthNo AND a.YearNo=U.YearNo                      
)       
INSERT INTO @Temp
SELECT * FROM AllData  
IF @IsExcel=1
BEGIN
	select Provider[Facility],ChargeTotal,PaymentTotal,AdjustmentTotal,PostMonth from @Temp
END
ELSE
BEGIN 
	select *,@ToDate from @Temp
END







GO

CREATE PROCEDURE rpt_CPA_By_Facility_Report_ByDOSDate
 @FromDate datetime = NULL,                                          
 @ToDate  datetime = NULL,                                          
 @FacilityId int = -1                                  
AS                                          
BEGIN
		SELECT FacilityDescription[Provider],SUM(ChargeAmount)ChargeTotal,SUM(PaidAmount)[PaymentTotal],SUM(TotalAdjustment) [AdjustmentTotal],
		CONVERT(varchar(2), Month(@FromDate)) +'-'+CONVERT(varchar(4),Year(@FromDate)) PostMonth ,@ToDate
			FROM vw_GetChargeForPendingPayment (NOLOCK)A
		INNER JOIN Facility(NOLOCK) B ON A.PerformingFacilityId=B.Id
		WHERE  (@FromDate IS NULL OR (cast(A.BillFromDate as date) >=@FromDate AND cast(A.BillFromDate as date)<=@ToDate  )) 
		AND (@FacilityId <=0 OR A.PerformingFacilityId = @FacilityId)   
		AND A.IsDeleted=0 
		GROUP BY A.PerformingFacilityId,B.FacilityDescription
END
GO

--rpt_CPA_By_Facility_Report_ByDOSDate_LOOP '31 July 2021','1 Aug 2021'
CREATE PROCEDURE rpt_CPA_By_Facility_Report_ByDOSDate_LOOP
@StartDate DATE,
@EndDate DATE,
@FacilityId int = NULL,
@IsExcel BIT=0
AS
BEGIN
		DECLARE @Results TABLE 
		(
			ID INT IDENTITY(1,1) 
			, YearValue INT 
			, MonthValue INT 
			, MonthName NVARCHAR(50) 

		)

		DECLARe @Temp Table
		(
		Provider VARCHAR(100),
		ChargeTotal MONEY,
		PaymentTotal MONEY,
		AdjustmentTotal MONEY,
		PostMonth VARCHAR(15),
		PosMonthDate DATE
		)

		IF(@FacilityId is null)
		SET @FacilityId=-1

		IF @StartDate IS NULL OR @EndDate IS NULL 
		BEGIN 
			/*GET THE CURRENT CALENDAR YEAR*/
			SELECT 
				@StartDate = DATEFROMPARTS(year(getdate()),1,1)
				,@EndDate = DATEFROMPARTS(year(getdate()),12,31)
		END 

		WHILE @StartDate <= @EndDate 
		BEGIN 
			 INSERT INTO @Results (YearValue, MonthValue, MonthName) 
			 SELECT 
				DATEPART(year, @StartDate)
				, DATEPART(month, @StartDate) 
				, DATENAME(month,@StartDate) 
				--SELECT @StartDate,     EOMONTH(@StartDate)

				DECLARe @Todate DATE
				SET @Todate=CAST(EOMONTH(@StartDate) AS DATE)
				
				IF DATEPART(year, @EndDate)=DATEPART(year, @Todate) AND DATEPART(month, @EndDate) =DATEPART(month, @Todate) 				
				BEGIN				
					SET @Todate=@EndDate
					--select @Todate
				END


				insert into @Temp
				exec rpt_CPA_By_Facility_Report_ByDOSDate @StartDate, @Todate,@FacilityId
				

			SET @StartDate = DATEADD(DAY, 1, @Todate) 
		END 
		IF @IsExcel=1
		BEGIN
		select Provider[Facility],ChargeTotal,PaymentTotal,AdjustmentTotal,PostMonth from @Temp order by PosMonthDate asc
		END
		ELSE
		BEGIN
		select Provider,ChargeTotal,PaymentTotal,AdjustmentTotal,PostMonth from @Temp order by PosMonthDate asc
		END
		
END


GO

