    CAST(SUM(v.Amount) as decimal(10,2))   Total                        
 FROM  vw_CHARGE_Latest v (NOLOCK)                         
  LEFT JOIN [Provider] u (NOLOCK) on v.PerformingProviderId=u.Id                        
  WHERE  (@FromDate IS NULL OR (cast(v.BillFromDate as date) >=@FromDate AND cast(v.BillFromDate as date)<=@ToDate  ))                          
  AND  (@ProviderID is null OR v.PerformingProviderId = @ProviderID)
  AND  (@AuxillaryProviderId is null OR v.AuxillaryProviderId = @AuxillaryProviderId)
  AND  (@RefferingProviderId is null OR v.RefDoctorId = @RefferingProviderId)
  AND  (@FacilityId is null OR v.PerformingFacilityId = @FacilityId)
  AND v.ChargeNo > 0 AND v.PatientCaseId > 0                        
      
  AND v.IsDeleted =0    
 GROUP BY u.FirstName,U.LastName,u.Id ,                        
    Month(v.BillFromDate),                        
    Year(v.BillFromDate)                        
 ),                        
                        
 Payment AS                        
 (                        
    SELECT  u.FirstName,u.LastName ,v.PerformingProviderId [DoctorId], 
			Month(@FromDate) MonthNo, Year(@FromDate)YearNo, SUM(PaymentOrAdjAmount) TPMT                        
	From vw_PaymentsAdjustments v (NOLOCK)                       
	LEFT JOIN [Provider] u (NOLOCK) on v.PerformingProviderId =u.Id                        
    WHERE ChargeNum In 
	(	
		SELECT v.ChargeNo FROM  vw_CHARGE_Latest v (NOLOCK)                         
		LEFT JOIN [Provider] u (NOLOCK) on v.PerformingProviderId=u.Id                        
		WHERE  (@FromDate IS NULL OR (cast(v.BillFromDate as date) >=@FromDate AND cast(v.BillFromDate as date)<=@ToDate  ))                          
		AND  (@ProviderID is null OR v.PerformingProviderId = @ProviderID)
  AND  (@AuxillaryProviderId is null OR v.AuxillaryProviderId = @AuxillaryProviderId)
  AND  (@RefferingProviderId is null OR v.RefDoctorId = @RefferingProviderId)
  AND  (@FacilityId is null OR v.PerformingFacilityId = @FacilityId)
		AND v.ChargeNo > 0)
	AND v.IsCommitted = 1 and v.IsPayment = 1 AND v.IsDeleted = 0
	GROUP BY  u.FirstName,u.LastName ,v.PerformingProviderId--, Month(EffectiveDate) ,Year(EffectiveDate)                        
                        
 ),                        
 adj as                         
 (                        
      SELECT  u.FirstName,u.LastName ,v.PerformingProviderId [DoctorId],     
     Month(@FromDate) MonthNo,                        
    Year(@FromDate)YearNo,                        
    SUM(PaymentOrAdjAmount) TPMT                        
     From vw_PaymentsAdjustments v (NOLOCK)                       
	 LEFT JOIN [Provider] u (NOLOCK) on v.PerformingProviderId =u.Id      
    WHERE ChargeNum In 
	(	
		SELECT v.ChargeNo FROM  vw_CHARGE_Latest v (NOLOCK)                         
		LEFT JOIN [Provider] u (NOLOCK) on v.PerformingProviderId=u.Id                        
		WHERE  (@FromDate IS NULL OR (cast(v.BillFromDate as date) >=@FromDate AND cast(v.BillFromDate as date)<=@ToDate  ))                          
		AND  (@ProviderID is null OR v.PerformingProviderId = @ProviderID)
  AND  (@AuxillaryProviderId is null OR v.AuxillaryProviderId = @AuxillaryProviderId)
  AND  (@RefferingProviderId is null OR v.RefDoctorId = @RefferingProviderId)
  AND  (@FacilityId is null OR v.PerformingFacilityId = @FacilityId)
		AND v.ChargeNo > 0)
	AND v.IsCommitted = 1 and v.IsPayment = 0 AND v.IsDeleted = 0
	GROUP BY  u.FirstName,u.LastName ,v.PerformingProviderId--, Month(EffectiveDate) ,Year(EffectiveDate) 
                        
 ),                        
 unAll as                        
 (                        
     SELECT FirstName,                   
 LastName ,                    
    DoctorID,                        
 C.MonthNo,                        
    C.YearNo                        
    FROM   Charges C  (NOLOCK)                                      
    UNION ALL      
    SELECT FirstName,                        
    LastName ,                        
   DoctorID,                        
    C.MonthNo,                        
    C.YearNo                        
    FROM   Payment c   (NOLOCK)              
                        
                    
    UNION ALL                        
    SELECT FirstName,                        
    LastName ,                        
    DoctorID,                        
    C.MonthNo,                        
    C.YearNo                        
    FROM   adj c  (NOLOCK)                      
),                        
AllData AS(                        
    SELECT distinct U.LastName + ' ' + u.FirstName Provider,                        
    C.Total ChargeTotal,                        
    P.TPMT PaymentTotal,                        
    A.TPMT AdjustmentTotal,                            
    convert(varchar(2), u.MonthNo) +'-'+convert(varchar(4),u.YearNo) PostMonth                        
                        
    FROM unAll u  (NOLOCK)                       
    LEFT JOIN Charges c (NOLOCK) on  C.DoctorId=u.DoctorId and C.MonthNo=U.MonthNo AND C.YearNo=U.YearNo                        
                        
    LEFT JOIN Payment p (NOLOCK) on                        
    p.DoctorId=u.DoctorId and p.MonthNo=U.MonthNo AND p.YearNo=U.YearNo                        
                        
  LEFT JOIN adj a (NOLOCK) on                        
    a.DoctorId=u.DoctorId and a.MonthNo=U.MonthNo AND a.YearNo=U.YearNo                        
)                        
SELECT *,@ToDate FROM AllData    


GO


CREATE PROCEDURE rpt_CPA_By_Provider_Report_ByDOSDate_LOOP
@StartDate DATE,
@EndDate DATE,
@ProviderID int = null,    
 @AuxillaryProviderId int = null,
 @RefferingProviderId int = null,
 @FacilityId	INT=null
AS
BEGIN
		DECLARE @Results TABLE 
		(
			ID INT IDENTITY(1,1) 
			, YearValue INT 
			, MonthValue INT 
			, MonthName NVARCHAR(50) 

		)

		DECLARe @Temp Table
		(
		Provider VARCHAR(100),
		ChargeTotal MONEY,
		PaymentTotal MONEY,
		AdjustmentTotal MONEY,
		PostMonth VARCHAR(15),
		PosMonthDate DATE
		)


		IF @StartDate IS NULL OR @EndDate IS NULL 
		BEGIN 
			/*GET THE CURRENT CALENDAR YEAR*/
			SELECT 
				@StartDate = DATEFROMPARTS(year(getdate()),1,1)
				,@EndDate = DATEFROMPARTS(year(getdate()),12,31)
		END 

		WHILE @StartDate <= @EndDate 
		BEGIN 
			 INSERT INTO @Results (YearValue, MonthValue, MonthName) 
			 SELECT 
				DATEPART(year, @StartDate)
				, DATEPART(month, @StartDate) 
				, DATENAME(month,@StartDate) 
				--SELECT @StartDate,     EOMONTH(@StartDate)

				DECLARe @Todate DATE
				SET @Todate=CAST(EOMONTH(@StartDate) AS DATE)
				
				IF DATEPART(year, @EndDate)=DATEPART(year, @Todate) AND DATEPART(month, @EndDate) =DATEPART(month, @Todate) 				
				BEGIN				
					SET @Todate=@EndDate
					--select @Todate
				END
				
				insert into @Temp
				exec rpt_CPA_By_Provider_Report_ByDOSDate @StartDate, @Todate,@ProviderID,@AuxillaryProviderId,@RefferingProviderId,@FacilityId


			SET @StartDate = DATEADD(DAY, 1, @Todate) 
		END 

		select Provider,ChargeTotal,PaymentTotal,AdjustmentTotal,PostMonth from @Temp order by PosMonthDate asc
END

GO

