CREATE PROCEDURE [dbo].[rpt_CPAByProvider]            
 @FromDate datetime = NULL,            
 @ToDate  datetime = NULL,            
 @ProviderID int = -1            
AS            
--SELECT @ToDate = DATEADD(day, -1, @ToDate)            
            
 DECLARE @TotalsReport AS TABLE (PostDate datetime, ProviderLastName varchar(50),             
    PaymentTotal decimal(10,2), ChargeTotal decimal(10,2),            
    AdjustmentTotal decimal(10,2)            
   )            
            
 -- Get Payments            
 DECLARE @PaymentReport AS TABLE (PaymentDate datetime, PerformingProvider varchar(50), BillingProvider varchar(50),            
       CPTCode varchar(10),            
       Qty int, Total decimal(10,2))            
            
 INSERT INTO @PaymentReport            
 EXEC rpt_PaymentsToDoctors @FromDate, @ToDate, @ProviderID            
            
 -- Insert payments into totals report            
 INSERT INTO @TotalsReport            
 SELECT  PaymentDate, PerformingProvider, Total, 0, 0            
 FROM  @PaymentReport             
             
 -- Get Adjustments            
 DECLARE @AdjustmentReport AS TABLE (PaymentDate datetime, PerformingProvider varchar(50), BillingProvider varchar(50),            
       CPTCode varchar(10),            
       Qty int, Total decimal(10,2))            
             
 INSERT INTO @AdjustmentReport            
 SELECT  CAST(PaymentEffectiveDate AS DATE), p.LastName [DoctorLastName],p.LastName [BillingDoctorLastName],v.CPTCode [ProcedureCode],              
  COUNT(1) TCount,              
  CAST(SUM(PaymentOrAdjAmount) as decimal(10,2))   Total            
 FROM  vw_PaymentsAdjustments v              
 LEFT JOIN [Provider] p ON p.Id = v.PerformingProviderId            
 WHERE ((CAST(v.PaymentEffectiveDate AS DATE) >= CAST(@FromDate AS DATE)                  
                         OR @FromDate IS NULL)                  
                        AND (CAST(v.PaymentEffectiveDate AS DATE) <= CAST(@ToDate AS DATE)                  
                             OR @ToDate IS NULL))              
     AND v.ChargeNum > 0 AND v.PatientCaseId > 0                
    AND v.IsDeleted =0  AND v.IsPayment = 0       
 AND (v.PerformingProviderId = @ProviderID   OR @ProviderID = -1)
               
 GROUP BY CAST(PaymentEffectiveDate AS DATE),p.LastName ,p.LastName ,v.CPTCode             
            
 -- Insert adjustments into totals report            
 INSERT INTO @TotalsReport            
 SELECT  PaymentDate, PerformingProvider, 0, 0, Total            
 FROM  @AdjustmentReport            
            
 ----Payment total by provider            
 --SELECT  0 as IsTotal, PerformingProvider,             
 --   '$' + CONVERT(varchar(12), SUM(Total)) as Total            
 --FROM  #report            
 --GROUP BY PerformingProvider, BillingProvider            
            
 -- Get charges and insert into totals report            
            
 INSERT INTO @TotalsReport            
 SELECT  ch.BillFromDate as [Post Date], ISNULL(u.LastName, ''), 0,             
    CAST(ch.Amount as decimal(10,2)) as ChargeTotal, 0            
 FROM  vw_CHARGE_Latest ch            
 LEFT JOIN [Provider](NOLOCK) u on u.id = ch.PerformingProviderId            
 WHERE  (CAST(@FromDate AS DATE) IS NULL            
     OR CAST(ch.BillFromDate AS DATE) BETWEEN CAST(@FromDate AS DATE) AND  CAST(@ToDate AS DATE))    
  AND (ch.PerformingProviderId = @ProviderID OR @ProviderID = -1)
              
  AND  ch.PatientCaseId > 0            
 ORDER BY ch.EntryDate, ch.IsDeleted DESC            
            
 --Create total report table by order            
 DECLARE @TotalsReportOrder AS TABLE (PostDate VARCHAR(12), ProviderLastName varchar(50),             
    PaymentTotal VARCHAR(12), ChargeTotal VARCHAR(12),            
    AdjustmentTotal VARCHAR(12)            
   )            
            
 INSERT INTO @TotalsReportOrder            
 SELECT  CONVERT(VARCHAR(4),DATEPART(YEAR, PostDate)) + '-' + CONVERT(VARCHAR,DATEPART(MONTH, PostDate),120) AS 'PostMonth',            
    ProviderLastName,             
   '$' + CONVERT(VARCHAR(12), Sum(PaymentTotal)) ,            
   '$' + CONVERT(VARCHAR(12), SUM(ChargeTotal)) ,            
   '$' + CONVERT(VARCHAR(12), Sum(AdjustmentTotal))     
 FROM @TotalsReport             
 GROUP BY DATEPART(Year, PostDate), DATEPART(Month, PostDate),ProviderLastName            
 ORDER BY ProviderLastName             
            
 SELECT 0 AS IsTotal,            
   PostDate AS 'PostMonth',            
   ProviderLastName as 'Provider',            
   ChargeTotal as 'ChargeTotal',             
   PaymentTotal as 'PaymentTotal',            
   AdjustmentTotal as 'AdjustmentTotal'            
 FROM @TotalsReportOrder              
 --UNION ALL            
 --SELECT 1 AS IsTotal,            
 --  '' AS 'PostMonth',            
 --  'TOTAL', '$' + CONVERT(VARCHAR(12),            
 --  SUM(ChargeTotal)),             
 --  '$' + CONVERT(VARCHAR(12), SUM(PaymentTotal)),            
 --  '$' + CONVERT(VARCHAR(12), SUM(AdjustmentTotal))            
 --FROM @TotalsReport            
 --ORDER BY IsTotal            
            
 --SELECT  0, 15, 25, 15, 15,  15 
GO


CREATE PROCEDURE [dbo].[rpt_CPAByRevenueCenter]
	@FromDate	datetime = NULL,
	@ToDate		datetime = NULL,
	@ProviderID int = -1
AS
--SELECT @ToDate = DATEADD(day, -1, @ToDate)

	DECLARE @TotalsReport AS TABLE(PostDate datetime, RevenueCenter varchar(50), 
				PaymentTotal decimal(10,2), ChargeTotal decimal(10,2),
				AdjustmentTotal decimal(10,2)
			)

	-- Get Payments
	DECLARE @PaymentReport AS TABLE(PaymentDate datetime, RevenueCenter varchar(50), 
						 CPTCode varchar(10),
							Qty int, Total decimal(10,2))
	
	INSERT INTO @PaymentReport
	SELECT		CAST(PaymentEffectiveDate AS DATE), cc.CategoryName [Category], v.CPTCode [ProcedureCode],
				COUNT(1),
				CAST(SUM(PaymentOrAdjAmount) as decimal(10,2))
	FROM  vw_Payments v 
	LEFT JOIN CPTCode cp ON cp.CPTCode = v.CPTCode
	LEFT JOIN CPTCategory cc ON cc.Id = cp.CPTCategoryId
	LEFT JOIN	vw_CHARGE_Latest c on c.ChargeNo = v.ChargeNum
 --LEFT JOIN   BL_Claims cl on cl.INVOICE_NO = c.InvoiceNo
	WHERE v.PatientCaseId > 0            
                   AND v.ChargeNum > 0            
                   AND v.IsDeleted =0
       AND ((CAST(v.PaymentEffectiveDate AS DATE) >= CAST(@FromDate AS DATE)            
                         OR @FromDate IS NULL)            
                        AND (CAST(v.PaymentEffectiveDate AS DATE) <= CAST(@ToDate AS DATE)  
						OR @ToDate IS NULL))  AND v.IsPayment = 1
	GROUP BY	CAST(PaymentEffectiveDate AS DATE), cc.CategoryName,v.CPTCode

	-- Insert payments into totals report
	INSERT INTO @TotalsReport
	SELECT		PaymentDate, RevenueCenter, Total, 0, 0
	FROM		@PaymentReport

	-- Get Adjustments
	DECLARE @AdjustmentReport AS TABLE(PaymentDate datetime, RevenueCenter varchar(50), 
						 CPTCode varchar(10),
							Qty int, Total decimal(10,2))
	
	INSERT INTO @AdjustmentReport
	SELECT  CAST(PaymentEffectiveDate AS DATE),cc.CategoryName [Category],v.CPTCode [ProcedureCode],
				COUNT(1),
				CAST(SUM(TotalAdjustment) as decimal(10,2))
	FROM  vw_GetChargeForPendingPayment v  
	LEFT JOIN CPTCode cp ON cp.CPTCode = v.CPTCode
	LEFT JOIN CPTCategory cc ON cc.Id = cp.CPTCategoryId
	WHERE ((CAST(v.PaymentEffectiveDate AS DATE) >= CAST(@FromDate AS DATE)      
                         OR @FromDate IS NULL)      
                        AND (CAST(v.PaymentEffectiveDate AS DATE) <= CAST(@ToDate AS DATE)      
                             OR @ToDate IS NULL))  
    AND v.ChargeNo > 0 AND v.PatientCaseId > 0    
    AND v.IsDeleted =0
	GROUP BY CAST(PaymentEffectiveDate AS DATE), cc.CategoryName, v.CPTCode

	-- Insert adjustments into totals report
	INSERT INTO @TotalsReport
	SELECT		PaymentDate, RevenueCenter, 0, 0, Total
	FROM		@AdjustmentReport
	----Payment total by provider
	--SELECT		0 as IsTotal, PerformingProvider, 
	--			'$' + CONVERT(varchar(12), SUM(Total)) as Total
	--FROM		#report
	--GROUP BY	PerformingProvider, BillingProvider

	-- Get charges and insert into totals report

	INSERT INTO @TotalsReport
	SELECT		ch.EntryDate as [Post Date], cat.[CategoryName], 0, 
				CAST(ch.Amount as decimal(10,2)) as ChargeTotal, 0
	FROM		vw_CHARGE_Latest ch
	LEFT JOIN   CPTCode pc ON pc.CPTCode = ch.CPTCode
	LEFT JOIN	CPTCategory cat ON cat.Id = pc.CPTCategoryId
	WHERE		(CAST(@FromDate AS DATE) IS NULL
					OR CAST(ch.BillFromDate AS DATE) BETWEEN CAST(@FromDate AS DATE) AND  CAST(@ToDate AS DATE))
		
		AND		ch.PatientCaseId > 0
	ORDER BY	ch.EntryDate, ch.IsDeleted DESC

	--Populate Totals report

	SELECT 0 AS IsTotal, RevenueCenter as 'Revenue Center', '$' + CONVERT(VARCHAR(12), SUM(ChargeTotal)) as 'Charge Total', 
			'$' + CONVERT(VARCHAR(12), Sum(PaymentTotal)) as 'Payment Total',
			'$' + CONVERT(VARCHAR(12), Sum(AdjustmentTotal)) as 'Adjustment Total'
	FROM @TotalsReport
	GROUP BY RevenueCenter
	UNION
	SELECT 1 AS IsTotal, 'TOTAL', '$' + CONVERT(VARCHAR(12), SUM(ChargeTotal)), 
			'$' + CONVERT(VARCHAR(12), SUM(PaymentTotal)),
			'$' + CONVERT(VARCHAR(12), SUM(AdjustmentTotal))
	FROM @TotalsReport
	ORDER BY IsTotal

	SELECT		0, 25, 15, 15,  15


GO




CREATE PROCEDURE [dbo].[rpt_CPAByRevenueCenterReport]                            
 @FromDate datetime = NULL,                            
 @ToDate  datetime = NULL,                            
 @ProviderID int=-1                            
AS                            
                     
 DECLARE @TotalsReport TABLE (Providers varchar(50),PostDate datetime, RevenueCenter varchar(50),                             
    PaymentTotal decimal(10,2), ChargeTotal decimal(10,2),                            
    AdjustmentTotal decimal(10,2)                            
   )                            
                            
 -- Get Payments                            
 DECLARE @PaymentReport TABLE (Providers varchar(60),PaymentDate datetime, RevenueCenter varchar(50),                             
       CPTCode varchar(10),                            
       Qty int, Total decimal(10,2))                  
                    
    DECLARE @PaymentReport1 TABLE (Providers varchar(60),PaymentDate datetime, RevenueCenter varchar(50),                             
       CPTCode varchar(10),                            
       Qty int, Total decimal(10,2))                           
                             
 INSERT INTO @PaymentReport                            
 SELECT  concat(u.LastName,', ',u.FirstName),v.CreatedDate [PaymentDate], ISNULL(cat.[CategoryName] ,'Non Revenue Center') RevCenter,v.CPTCode [ProcedureCode],                            
    COUNT(1),                            
    CAST(SUM(PaymentOrAdjAmount) as decimal(10,2))        
                           
 FROM  vw_PaymentsAdjustments v (NOLOCK)                           
 left join [Provider] u (NOLOCK) on u.Id = v.PerformingProviderId    
   LEFT JOIN   CPTCode pc (NOLOCK) ON pc.CPTCode = v.CPTCode                             
 LEFT JOIN CPTCategory cat  (NOLOCK) ON cat.Id = pc.CPTCategoryId 
 WHERE  (@FromDate IS NULL and (@ProviderID = -1 or v.PerformingProviderId =@ProviderID) OR                
  CAST(PaymentEffectiveDate AS DATE) BETWEEN @FromDate AND @ToDate  )                   
  AND v.PatientCaseId > 0 AND v.ChargeNum > 0   AND v.IsDeleted =0 AND v.IsPayment = 1
 GROUP BY concat(u.LastName,', ',u.FirstName),v.CreatedDate, v.CPTCode ,ISNULL(cat.[CategoryName] ,'Non Revenue Center')                        
                            
 -- Insert payments into totals report                            
 INSERT INTO @TotalsReport                            
 SELECT  Providers,PaymentDate, RevenueCenter, Total, 0, 0                            
 FROM  @PaymentReport                   
                 
  INSERT INTO @PaymentReport1                           
 SELECT  concat(u.LastName,', ',u.FirstName),v.CreatedDate [PaymentDate], ISNULL(cat.[CategoryName] ,'Non Revenue Center') RevCenter, v.CPTCode [ProcedureCode], 
    COUNT(1),                            
    CAST(SUM(PaymentOrAdjAmount) as decimal(10,2))                       
 FROM  vw_PaymentsAdjustments v (NOLOCK)                          
 left join [Provider] u (NOLOCK) on u.Id = v.PerformingProviderId      
  LEFT JOIN   CPTCode pc (NOLOCK) ON pc.CPTCode = v.CPTCode
 LEFT JOIN CPTCategory cat  (NOLOCK) ON cat.Id = pc.CPTCategoryId                       
 WHERE  (@FromDate IS NULL and (@ProviderID = -1 or v.PerformingProviderId =@ProviderID) OR CAST(PaymentEffectiveDate AS DATE) BETWEEN @FromDate AND @ToDate  )                             
    AND v.PatientCaseId > 0 AND v.ChargeNum > 0    AND v.IsDeleted =0 AND v.IsPayment = 0
 GROUP BY concat(u.LastName,', ',u.FirstName),v.CreatedDate, v.CPTCode , ISNULL(cat.[CategoryName] ,'Non Revenue Center')                  
                 
 -- Insert adjustments into totals report                            
 INSERT INTO @TotalsReport                            
 SELECT  Providers,PaymentDate, RevenueCenter, 0, 0, Total                           
 FROM  @PaymentReport1                             
                            
 -- Get charges and insert into totals report                            
                            
 INSERT INTO @TotalsReport                            
 SELECT                              
 (select concat([Provider].LastName,', ',[Provider].FirstName) from [Provider] where [Provider].Id=ch.PerformingProviderId) as 'Providers'                            
 ,ch.BillFromDate as [Post Date], ISNULL(cat.[CategoryName] ,'Non Revenue Center') RevCenter, 0,                             
    CAST(ch.Amount as decimal(10,2)) as ChargeTotal, 0                           
 FROM  vw_CHARGE_Latest ch  (NOLOCK)                          
 LEFT JOIN   CPTCode pc (NOLOCK) ON pc.CPTCode = ch.CPTCode                            
 LEFT JOIN CPTCategory cat  (NOLOCK) ON cat.ID = pc.CPTCategoryId                            
 WHERE  (@FromDate IS NULL AND (@ProviderID = -1 OR @ProviderID = ch.PerformingProviderId)                            
     OR ( CAST(BillFromDate AS DATE) >=@FromDate AND CAST(BillFromDate AS DATE)<=@ToDate  ))                            
  AND  ch.PatientCaseId > 0  AND ch.ChargeNo > 0 AND ch.IsDeleted =0
 ORDER BY ch.BillFromDate DESC                  
                 
                 
                           
                       
 --Populate Totals report                            
                            
 SELECT Providers, RevenueCenter as 'RevenueCenter',  SUM(ChargeTotal) as 'ChargeTotal',                             
      Sum(PaymentTotal) as 'PaymentTotal',                            
       Sum(AdjustmentTotal) as 'AdjustmentTotal'                            
 FROM @TotalsReport                            
 GROUP BY Providers,RevenueCenter                            
                
                           
                            
 --exec rpt_CPAByRevenueCenterReport '2018-04-01', '2018-04-30'                
 --select * FROM vw_PaymentsAdjustments where Ispayment = 0




