CREATE PROCEDURE [dbo].[rpt_CPADetailsByDOSByCPT]        
 @FromDate DATETIME      = NULL,                  
 @ToDate   DATETIME      = NULL,                  
 @CPTCodes VARCHAR(1000) = NULL                  
AS                  
BEGIN                 
          
          
        
  DECLARE @TempData AS TABLE                  
  (        
    AcctNo       NUMERIC(18, 0),                  
    PatientName  NVARCHAR(500),                  
    ProviderName NVARCHAR(500),                  
    CompanyId    NUMERIC(18, 0),                  
    CompanyName  NVARCHAR(500),                  
    DOS          DATE,                  
    CPTCode      NVARCHAR(50),                  
    Modifiers    NVARCHAR(50),                  
    ChargeAmt    NUMERIC(18, 2),                  
    PriDX        NVARCHAR(50),                  
    POS          NVARCHAR(50),                  
    ChargeNo     NUMERIC(18, 0),                  
    Payments     NUMERIC(18, 2),                  
    Adjustments  NUMERIC(18, 2),                  
    PaymentBat   NVARCHAR(100),                  
    PostDate     DATE,                
    ProviderId  int                  
  );                  
               
    INSERT INTO @TempData (AcctNo,PatientName,ProviderName,CompanyId,CompanyName,DOS,CPTCode,Modifiers,ChargeAmt,PriDX,                  
        POS,ChargeNo,Payments,Adjustments,PaymentBat,PostDate,ProviderId)                  
  EXEC usp_dos @FromDate,@ToDate;         
        
  ;WITH ClaimData As        
  (        
  --SELECT DISTINCT ChargeNumber,B.CLAIM_NO,B.DATE_MADE,B.DATE_SENT,        
  --CASE WHEN C.BatchStatus=0 THEN 'Batch doesn''t send'        
  -- WHEN C.BatchStatus=1 THEN 'Batch was sent'        
  -- WHEN C.BatchStatus=2 THEN 'Batch was successfully delivered'        
  -- WHEN C.BatchStatus=3 THEN 'Batch was delivered with errors'        
  -- END [BatchStatus]        
  --FROM BL_ClaimSvc A        
  --INNER JOIN BL_Claims B ON A.ClaimNumber=B.CLAIM_NO        
  --LEFT JOIN BL_Batch C ON C.ID=B.BATCH_NO        
  SELECT ChargeNo, B.Id As CLAIM_NO, B.ClaimDate As DATE_MADE, B.SentDate As DATE_SENT,        
  CASE WHEN C.BatchStatus=0 THEN 'Batch doesn''t send'        
   WHEN C.BatchStatus=1 THEN 'Batch was sent'        
   WHEN C.BatchStatus=2 THEN 'Batch was successfully delivered'        
   WHEN C.BatchStatus=3 THEN 'Batch was delivered with errors'        
   END [BatchStatus]        
  FROM ClaimCharge (NOLOCK)A        
  INNER JOIN Charge(NOLOCK) chg ON A.ChargeId = chg.Id      
  INNER JOIN Claim (NOLOCK)B ON A.ClaimId=B.Id        
  LEFT JOIN ClaimBatch (NOLOCK)C ON C.Id = B.ClaimBatchId          
  WHERE B.SentDate =        
       (SELECT MAX(Y.SentDate) FROM ClaimCharge(NOLOCK) X         
       INNER JOIN Claim(NOLOCK) Y ON X.ClaimId=Y.Id      
        WHERE X.ChargeId=A.ChargeId)        
  )                
                     
  SELECT t.AcctNo, t.PatientName, t.DOS, t.PostDate [PostingDate], t.CPTCode [CPT], t.ChargeAmt [Charge], t.Payments,                  
                    t.Adjustments, t.ChargeAmt - (t.Payments + t.Adjustments) [Owed],      
       
 (SELECT TOP 1 B.ModifiedDate FROM Payment B        
 INNER JOIN PaymentCharge(NOLOCK) pmtChg ON pmtChg.PaymentId = b.Id      
 INNER JOIN Charge(NOLOCK) chg ON pmtChg.ChargeId = chg.Id      
     WHERE ChargeNo = t.ChargeNo ORDER BY B.Id DESC)[LastPayment],      
        
  t.CompanyName [InsuranceName],          
        
  STUFF((SELECT ','+ Z3.BatchNo      
        FROM Payment (NOLOCK) Z2            
  INNER JOIN Voucher(NOLOCK) vch ON vch.Id = Z2.VoucherId      
        LEFT JOIN PaymentBatch(NOLOCK) Z3 ON Z3.Id = vch.PaymentBatchId                  
      WHERE Z2.PatientId = t.acctno FOR XML PATH('')), 1, 1, '') [PaymentBatches],        
         
    t.ProviderId,      
 C.CLAIM_NO,      
 C.DATE_MADE,      
 C.DATE_SENT,      
 C.BatchStatus                  
             FROM @TempData t             
    LEFT JOIN   ClaimData C ON T.ChargeNo=C.ChargeNo               
             WHERE ((t.CPTCode IN (SELECT [Value] FROM dbo.tfn_Split(@CPTCodes, ',') ) OR @CPTCodes IS NULL OR @CPTCodes =''))        
    ORDER BY t.ChargeNo desc        
END 
GO


CREATE PROCEDURE [dbo].[rpt_CPT_DX_Trending] @FromDate DATETIME = NULL,
                                     @ToDate   DATETIME = NULL
AS
         BEGIN
             SELECT blCh.CPTCode,
                    procList.Description,
                    COUNT (*)   AS PeriodCount,
                    MONTH(blCh.BillFromDate) CPTTrendMonth,
                    YEAR(blCh.BillFromDate) CPTTrendYear,
                   (CAST(DateName(month, DATEADD(month, MONTH(blCh.BillFromDate), 0) - 1) AS VARCHAR(3)) + RIGHT(YEAR(blCh.BillFromDate), 2)) PeriodMonth
             FROM Charge blCh(NOLOCK)
                  LEFT JOIN CPTCode procList(NOLOCK) ON procList.CPTCode = blCh.CPTCode                         
					 LEFT JOIN CPTCategory cat  (NOLOCK) ON cat.ID = procList.CPTCategoryId  
             WHERE(CAST(blCh.BillFromDate AS DATE) >= @FromDate
                   OR @FromDate IS NULL)
                  AND (CAST(blCh.BillFromDate AS DATE) <= @ToDate
                       OR @ToDate IS NULL)
                  AND blCh.PatientCaseId > 0
                  AND blCh.ChargeNo > 0
			   AND blCh.IsDeleted =0
             GROUP BY blCh.CPTCode,
                     MONTH(blCh.BillFromDate),
                    YEAR(blCh.BillFromDate),
                      procList.Description
             ORDER BY MONTH(blCh.BillFromDate) ASC;
         END


		
--rpt_CPT_DX_Trending '20180401' ,'20180430'


GO


CREATE PROCEDURE [dbo].[rpt_CPT_DX_Trending_By_Revenue_Center]  @FromDate DATETIME = NULL,
                                     @ToDate   DATETIME = NULL
AS
         BEGIN
             SELECT blCh.CPTCode,
                    procList.Description,
                    COUNT(*)   AS PeriodCount,
					ISNULL(cat.[CategoryName] ,'Non Revenue Center') RevCenter,
					CAST(SUM(blCh.Amount )as decimal(10,2)) as ChargeTotal
					FROM vw_CHARGE_Latest blCh(NOLOCK)
					 LEFT JOIN CPTCode procList(NOLOCK) ON procList.CPTCode = blCh.CPTCode                         
					 LEFT JOIN CPTCategory cat  (NOLOCK) ON cat.ID = procList.CPTCategoryId   
					WHERE(CAST(BillFromDate AS DATE) >= @FromDate
					  OR @FromDate IS NULL)
					  AND (CAST(BillFromDate AS DATE) <= @ToDate
                       OR @ToDate IS NULL)
					  AND blCh.PatientCaseId > 0
					  AND blCh.ChargeNo > 0
					  AND blCh.IsDeleted =0
					  GROUP BY 
							blCh.CPTCode,
						    procList.Description,
						    cat.[CategoryName]
					ORDER BY 
							blCh.CPTCode ASC;
         END

		 --rpt_CPT_DX_Trending_By_Revenue_Center '20180401' , '20180430'


GO

CREATE PROCEDURE [dbo].[rpt_CPTCodeReimbursementReport] @FromDate DATETIME = NULL,        
                                                @ToDate   DATETIME = NULL  ,      
             @CPTCodes VARCHAR(1000) = NULL           
AS        
         BEGIN        
             DECLARE @TempData AS TABLE        
(AcctNo       NUMERIC(18, 0),        
 PatientName  NVARCHAR(500),        
 ProviderName NVARCHAR(500),        
 CompanyId    NUMERIC(18, 0),        
 CompanyName  NVARCHAR(500),        
 DOS          DATE,        
 CPTCode      NVARCHAR(50),        
 Modifiers    NVARCHAR(50),        
 ChargeAmt    NUMERIC(18, 2),        
 PriDX        NVARCHAR(50),        
 POS          NVARCHAR(50),        
 ChargeNo     NUMERIC(18, 0),        
 Payments     NUMERIC(18, 2),        
 Adjustments  NUMERIC(18, 2),        
 PaymentBat   NVARCHAR(100),        
 PostDate     DATE,        
 CPTDesc      NVARCHAR(100)        
);        
             INSERT INTO @TempData        
(AcctNo,        
 PatientName,        
 ProviderName,        
 CompanyId,        
 CompanyName,        
 DOS,        
 CPTCode,        
 Modifiers,        
 ChargeAmt,        
 PriDX,        
 POS,        
 ChargeNo,        
 Payments,        
 Adjustments,        
 PaymentBat,        
 PostDate,        
 CPTDesc        
)        
             EXEC usp_PostDetail        
                  @FromDate,        
                  @ToDate;        
      
             SELECT t.DOS,        
                    t.AcctNo AccountNo,        
                    t.PatientName,        
     t.CompanyName [PrimaryInsurance],      
                    t.CPTCode,        
                    t.CPTDesc,        
                    t.ChargeAmt [Charge],        
                    t.POS  ,      
     t.Payments,        
     t.Adjustments       
             FROM @TempData t      
            WHERE ((t.CPTCode IN (SELECT [Value] FROM dbo.tfn_Split(@CPTCodes, ',') ) OR @CPTCodes IS NULL OR @CPTCodes =''));               
         END      
GO

CREATE PROCEDURE [dbo].[rpt_GetAssociatedARReport]         
( @FromDate DATE= NULL, @ToDate DATE= NULL)                
               
as                
Begin                
Print 'Execution Started : ' + convert(varchar(30),getdate(),114)            
            
Declare @TempData as Table (             
DOSMonth   date ,            
TotCharges  Numeric(18,2),            
TotAdjustments Numeric(18,2),            
TotPayments Numeric(18,2),            
TotDue  Numeric(18,2),            
Perc  Numeric(18,2)            
)            
            
Declare @TempDataOutput as Table (             
StartDate date,            
EndDate  date,            
DOSMonthID nvarchar(50),            
DOSMonth nvarchar(50),            
TotalCharges Numeric(18,2),            
TotalPayments Numeric(18,2),            
AdjustmentAmounts Numeric(18,2),            
ZeroDay   Numeric(18,2),                
ThirtyDays  Numeric(18,2),                
SixtyDays  Numeric(18,2),                
NinetyDays  Numeric(18,2),                
OneTwentyDays Numeric(18,2),            
TotalOwing Numeric(18,2)        
)            
            
Declare @TempRevData as Table (            
RevenuCentreName Nvarchar(50),            
ZeroDay   Numeric(18,2),                
ThirtyDays  Numeric(18,2),                
SixtyDays  Numeric(18,2),                
NinetyDays  Numeric(18,2),                
OneTwentyDays Numeric(18,2),            
TotalOwing Numeric(18,2)            
)            
            
Declare @MinEndDate Date            
Declare @MaxEndDate Date            
        
Declare @TempFromDate Date = dateadd(MONTH, -4, @FromDate)        
        
Print 'Start Date : ' + cast(@FromDate as nvarchar(10))        
Print 'Temporary Start Date : ' + cast(@TempFromDate as nvarchar(10))        
            
Insert Into  @TempData            
(DOSMonth, TotCharges)            
select            
  CAST(A.BillFromDate AS DATE) ,                            
       sum(A.Amount)                          
                 
from vw_CHARGE_Latest A  (NOLOCK)              
                
INNER JOIN Invoice B (NOLOCK) ON A.InvoiceId=B.Id and A.IsDeleted =0 and A.ChargeNo > 0 And A.PatientCaseId > 0 --and A.BillIns = 1            
join  PatientCase C (NOLOCK) ON C.Id = B.PatientCaseId                 
join Patient D (NOLOCK) ON C.PatientId = D.Id                 
join [Provider] E (NOLOCK) ON D.ProviderId = E.Id                
                
--join BL_Inv_dx H (NOLOCK) ON H.InvoiceID = B.ID and H.DiagnosisNumber = 1                
--join BL_POS_Config I (NOLOCK) ON I.Code = A.PlaceOfService                  
left join CPTCode  (NOLOCK) J ON J.CPTCode = A.CPTCode                
left join CPTCategory (NOLOCK) K ON K.Id = J.CPTCategoryId                
                
WHERE  CAST(A.BillFromDate AS DATE) between @TempFromDate and  @ToDate             
Group By CAST(A.BillFromDate AS DATE)            
            
Print 'SQL Passed : ' + convert(varchar(30),getdate(),114)            
            
            
Insert Into  @TempData            
(DOSMonth, TotPayments)            
Select cast(Z.PaymentEffectiveDate as date), Coalesce(Sum(Z.PaymentOrAdjAmount),0) from vw_PaymentsAdjustments Z            
Where  z.IsDeleted =0  AND Z.IsPayment = 1             
and Cast(Z.PaymentEffectiveDate as date) between @TempFromDate and  @ToDate  And Z.ChargeNum > 0 And Z.PatientCaseId > 0           
Group By cast(Z.PaymentEffectiveDate  as date)                 
            
Insert Into  @TempData            
(DOSMonth, TotAdjustments)            
Select cast(Z.PaymentEffectiveDate as date), Coalesce(Sum(Z.PaymentOrAdjAmount),0) from vw_PaymentsAdjustments Z            
Where z.IsDeleted =0 and z.IsPayment = 0      
and cast(Z.PaymentEffectiveDate as date) between @TempFromDate and  @ToDate  And Z.ChargeNum > 0 And Z.PatientCaseId > 0           
Group By cast(Z.PaymentEffectiveDate as date)                
            
Print 'Generatae Temp Payment and Adjustment Passed : ' + convert(varchar(30),getdate(),114)            
Insert Into @TempDataOutput            
(StartDate, EndDate, DOSMonthID, DOSMonth, TotalCharges, TotalPayments, AdjustmentAmounts)            
Select Cast(Cast(Datepart(YYYY,DOSMonth) as nvarchar(4)) + '-' + cast(DATEPart(month,DOSMonth) as nvarchar(2)) + '-01' as date),            
  EOMONTH(Cast(Datepart(YYYY,DOSMonth) as nvarchar(4)) + '-' + cast(DATEPart(month,DOSMonth) as nvarchar(2)) + '-01'),            
  Cast(Datepart(YYYY,DOSMonth) as nvarchar(4)) + '-' + cast(DATEPart(month,DOSMonth) as nvarchar(2)) [DOSMonthId],            
  Cast(Datepart(YYYY,DOSMonth) as nvarchar(4)) + '-' + cast(DATENAME(month,DOSMonth) as nvarchar(20)) [DOSMonth],             
  sum(TotCharges) [TotalCharges], sum(totpayments) [TotalPayments], sum(totadjustments) [AdjustmentAmounts]              
from @TempData            
Group By Cast(Cast(Datepart(YYYY,DOSMonth) as nvarchar(4)) + '-' + cast(DATEPart(month,DOSMonth) as nvarchar(2)) + '-01' as date),            
   EOMONTH(Cast(Datepart(YYYY,DOSMonth) as nvarchar(4)) + '-' + cast(DATEPart(month,DOSMonth) as nvarchar(2)) + '-01'),            
   Cast(Datepart(YYYY,DOSMonth) as nvarchar(4)) + '-' + cast(DATEPart(month,DOSMonth) as nvarchar(2)),            
   Cast(Datepart(YYYY,DOSMonth) as nvarchar(4)) + '-' + cast(DATENAME(month,DOSMonth) as nvarchar(20))            
Order BY 1 asc            
            
Select @MinEndDate = Min(A.EndDate) From @TempDataOutput A            
Select @MaxEndDate = Max(A.EndDate) From @TempDataOutput A            
            
delete from @TempRevData            
            
While (@MinEndDate <= @MaxEndDate)            
Begin            
            
Print 'Date : ' + Cast(@MinEndDate as nvarchar(50))            
            
Insert Into @TempRevData         
(RevenuCentreName ,            
ZeroDay ,                
ThirtyDays ,                
SixtyDays ,                
NinetyDays,                
OneTwentyDays ,            
TotalOwing )           
Exec rpt_Aging_Summary_By_Revenue_Center @MinEndDate            
            
update @TempRevData            
Set TotalOwing =  ZeroDay +  ThirtyDays   + SixtyDays   + NinetyDays --+ OneTwentyDays            
            
update @TempDataOutput            
Set ZeroDay = (Select sum(ZeroDay) from @TempRevData),            
ThirtyDays = (Select sum(ThirtyDays) from @TempRevData),            
SixtyDays = (Select sum(SixtyDays) from @TempRevData),            
NinetyDays = (Select sum(NinetyDays) from @TempRevData),            
OneTwentyDays = (Select sum(OneTwentyDays) from @TempRevData),            
TotalOwing = (Select sum(TotalOwing) from @TempRevData)        
Where EndDate = @MinEndDate            
            
Select @MinEndDate = Min(A.EndDate) From @TempDataOutput A Where A.EndDate  > @MinEndDate            
            
delete from @TempRevData            
            
End            
            
Select A.StartDate [FromDate], A.EndDate [ToDate], DATEPART(Month,A.EndDate) [MonthNo],             
DATEPART(Year,A.EndDate)  [YearNo], 0 [TotalMonth], A.TotalCharges [Charge],             
A.AdjustmentAmounts [ThisMonthAdj],  A.TotalPayments [ThisMonthPMT], 0 [ThisMonthBalance],0 [RunningAR],            
A.ZeroDay [CurrentAR],        
(A.ZeroDay/A.TotalCharges) * 100 [CurrentPercentage],        
A.ThirtyDays [ThirtyDaysAR],        
A.ThirtyDays / (select B.TotalCharges FROM @TempDataOutput B where dateadd(Month,-1,A.StartDate) =B.StartDate ) *100 [ThirtyDaysPerc],        
A.SixtyDays [SixtyDaysAR],        
A.SixtyDays/(select B.TotalCharges FROM @TempDataOutput B where dateadd(Month,-2,A.StartDate) =B.StartDate) * 100 [SixtyDaysPerc],        
A.NinetyDays [NinetyDaysAR],         
 A.NinetyDays/(select B.TotalCharges FROM @TempDataOutput B where dateadd(Month,-3,A.StartDate) =B.StartDate) * 100 [NinetyDaysPerc],        
 A.OneTwentyDays [One120DaysAR],         
 A.OneTwentyDays/(select B.TotalCharges FROM @TempDataOutput B where dateadd(Month,-4,A.StartDate) =B.StartDate) * 100 [OneTwentyDaysPerc],        
A.TotalOwing [ARTotal], 0 [BalanceTotal]  from @TempDataOutput A          
wHERE a.StartDate >= @FromDate        
          
Order By EndDate asc            
            
End 
GO

CREATE PROCEDURE rpt_GetDenialDetails  (      @FromDate DATETIME = NULL,      @ToDate   DATETIME = NULL,      @ReasonCodes VARCHAR(1000) = NULL                )AS              Declare @TempChargeData as Table (    ChargeNo  Numeric(18,0) Primary Key,    PatientID  int,    PatientName  NVARCHAR(100),    DeniedInsCompany  NVARCHAR(200),            CurrentInsCompany  NVARCHAR(200),            CPTCode NVARCHAR(50),      DOS  DATE,              ReasonCode VARCHAR(30),    Charge  Numeric(18,2),      Payment  Numeric(18,2),                        Adjustment  Numeric(18,2),     OwedAmount  Numeric(18,2)      )                      Declare @TempPaymentData as Table (                          ChargeNo   Numeric(18,0) Primary Key,         

               PaymentAmt  Numeric(18,2)                    )                                        Declare @TempAdjustmentData as Table (                                           ChargeNo   Numeric(18,0) Primary Key,         
               AdjustmentAmt  Numeric(18,2)                        )              Insert Into @TempChargeData                        (  ChargeNo, PatientID, PatientName, DeniedInsCompany, CurrentInsCompany, CPTCode, DOS, ReasonCode, Charge, Payment


, Adjustment, OwedAmount)      SELECT DISTINCT bch.ChargeNo, pat.Id AS AccountNo,      (pat.FirstName+' '+ISNULL(pat.MI, '')+' '+pat.LastName) AS [Name],      (          SELECT CompanyName          FROM InsuranceCompany          WHERE Id = dbo.ufn_ActiveInsuranceForCaseNo(bch.BillFromDate, 1, bch.PatientCaseId)      ) AS DeniedInsCompany,      com.CompanyName AS CurrentInsCompany,      bch.CPTCode AS CPT,      bch.BillFromDate AS DOS,                               --(Select dbo.ufn_GetPaymentReasonsCodeByChargeNumber_Denial(bch.ChgNo)) AS ReasonCode,    '' As ReasonCode,    bch.Amount,  0 As Payment, 0 AS Adjustment, 0 As OwedAmount     FROM vw_CHARGE_Latest bch(NOLOCK)              INNER JOIN PatientCase bcs(NOLOCK) ON bch.PatientCaseId = bcs.Id              INNER JOIN Patient pat(NOLOCK) ON bcs.PatientId = pat.Id              INNER JOIN Invoice inv(NOLOCK) ON inv.PatientCaseId = bch.PatientCaseId                INNER JOIN InsuranceCompany com(NOLOCK) ON com.Id = dbo.ufn_ActiveInsuranceForCaseNo(bch.BillFromDate, 1, bch.PatientCaseId)        WHERE CAST(bch.BillFromDate AS DATE) BETWEEN CAST(@FromDate AS DATE) AND CAST(@ToDate AS DATE)                                           AND bch.IsDeleted = 0              AND bch.ChargeNo > 0   

        AND bch.PatientCaseId > 0           group by bch.ChargeNo, pat.Id, pat.FirstName, pat.MI, pat.LastName, bch.BillFromDate, bch.PatientCaseId, com.CompanyName, bch.CPTCode, bch.Amount            Print 'Generate Temp Charges Passed : ' + convert(varchar(30),getdate(),114)                                Insert Into @TempPaymentData                     ( ChargeNo, PaymentAmt)                     Select Z.ChargeNum, Coalesce(Sum(Z.PaymentOrAdjAmount),0) from vw_PaymentsAdjustments Z           

        
  Where z.IsDeleted = 0  AND Z.ChargeNum > 0  and Z.PatientCaseId > 0 and Z.IsPayment = 1                  AND ((CAST(Z.PaymentEffectiveDate AS DATE) >= CAST(@FromDate AS DATE)                               OR @FromDate IS NULL)                       


       AND (CAST(Z.PaymentEffectiveDate AS DATE) <= CAST(@ToDate AS DATE)                                   OR @ToDate IS NULL)) Group By ChargeNum                                               Print 'Generate Temp Payments Passed : ' + convert(varchar(30),getdate(),114)                Insert Into @TempAdjustmentData(ChargeNo, AdjustmentAmt)                       Select Z.ChargeNum, Coalesce(Sum(Z.PaymentOrAdjAmount),0) from vw_PaymentsAdjustments Z                       Where z.IsDeleted = 0  AND Z.ChargeNum > 0   and Z.PatientCaseId > 0 AND Z.IsPayment =0                   AND ((CAST(Z.PaymentEffectiveDate AS DATE) >= CAST(@FromDate AS DATE)                         OR @FromDate IS NULL)                              AND (CAST(Z.PaymentEffectiveDate AS DATE) <= CAST(@ToDate AS DATE)                                   OR @ToDate IS NULL))    Group By ChargeNum                Print 'Generate Temp Adjustments Passed : ' + convert(varchar(30),getdate(),114)              update @TempChargeData                       Set Payment = B.PaymentAmt                     From @TempChargeData A  join @TempPaymentData B On A.ChargeNo = B.ChargeNo                                 Print 'Update Payments Passed Chargewise: ' + convert(varchar(30),getdate(),114)                                                     update @TempChargeData                        Set Adjustment = B.AdjustmentAmt                     From @TempChargeData A  join @TempAdjustmentData B On A.ChargeNo = B.ChargeNo  
                   Print 'Update Adjustments Passed Chargewise: ' + convert(varchar(30),getdate(),114)                                              update @TempChargeData                        Set OwedAmount = (A.Charge - (A.Payment + A.Adjustment)


)      From @TempChargeData A            Print 'Update Owed Amount: ' + convert(varchar(30),getdate(),114)              update @TempChargeData                        Set ReasonCode =(Select dbo.ufn_GetPaymentReasonsCodeByChargeNumber_Denial(A.ChargeNo))     From @TempChargeData A            Print 'Set ReasonCode Passed: ' + convert(varchar(30),getdate(),114)                    SELECT PatientID AS AccountNo,  PatientName As [Name], DeniedInsCompany, CurrentInsCompany,   CPTCode AS CPT, DOS, 

 ReasonCode, Charge, Payment, Adjustment,    OwedAmount from @TempChargeData chg       WHERE OwedAmount > 0          AND ((ReasonCode IN (SELECT [Value] FROM dbo.tfn_Split(@ReasonCodes, ',') ) OR @ReasonCodes IS NULL OR @ReasonCodes =''))            AND ReasonCode <> ''     GROUP BY chg.ChargeNo,               PatientID,             PatientName,             DeniedInsCompany,             CurrentInsCompany,             CPTCode,             DOS,             ReasonCode,       
		 Charge,             Payment, Adjustment, OwedAmount             Order by PatientName




GO



--EXEC rpt_GetInsuranceBalanceReport  '09 AUG 2019'
CREATE PROCEDURE [dbo].[rpt_GetInsuranceBalanceReport]        
(        
@ToDate   DATETIME = NULL        
)        
AS        
         BEGIN                       
              
    
Declare @TempData as Table (  
Charge  Numeric(18,2),
BillIns Bit,
PatientID   int,                           
PostDate Date,
ChargeNo  Numeric(18,0) Primary Key,                  
InsurancePayments  Numeric(18,2),                  
InsuranceAdjustments  Numeric(18,2),
PatientName nvarchar(200),
DOS  DATE,        
CPTCode NVARCHAR(50),
Due  Numeric(18,2),
CompanyId    NUMERIC(18, 0),        
CompanyName  NVARCHAR(200)      
)    


Declare @TempPaymentData as Table (               
              
ChargeNo   Numeric(18,0) Primary Key,                  
PaymentAmt  Numeric(18,2)              
)              
              
Declare @TempAdjustmentData as Table (              
                 
ChargeNo   Numeric(18,0) Primary Key,                  
AdjustmentAmt  Numeric(18,2)                  
)

Insert Into @TempData                  
(  Charge,   BillIns,  PatientID,                  
  PostDate,  ChargeNo, InsurancePayments, InsuranceAdjustments, PatientName, DOS, CPTCode, Due, CompanyId,        
 CompanyName 
) 
SELECT DISTINCT A.Amount, A.BillToInsurance, C.PatientId, A.EntryDate, A.ChargeNo, 0 [Payments],  0 [Adjustments],
CONCAT(D.LastName, ', ', D.FirstName, ' ', D.MI) [PatientName], A.BillFromDate AS FromDate, A.CPTCode, 0,
dbo.ufn_ActiveInsuranceForCaseNo(A.BillFromDate, 1, C.Id) As CompanyId, ''       
                      FROM vw_CHARGE_Latest A(NOLOCK)        
                           INNER JOIN Invoice B(NOLOCK) ON A.InvoiceId = B.Id        
                           JOIN PatientCase C(NOLOCK) ON C.Id = B.PatientCaseId      
                           JOIN Patient D(NOLOCK) ON C.PatientId = D.Id        
                           JOIN [Provider] E(NOLOCK) ON D.ProviderId = E.Id  
                           LEFT JOIN CPTCode (NOLOCK) J ON J.CPTCode = A.CPTCode        
                           LEFT JOIN CPTCategory (NOLOCK) K ON K.Id = J.CPTCategoryId 
                      WHERE A.IsDeleted =0
                            AND A.ChargeNo > 0        
                            AND A.PatientCaseId > 0        
                            AND CAST(A.BillFromDate AS DATE) <= @ToDate	
							AND  A.BillToInsurance = 1 AND C.Id IN (
											SELECT Distinct PatientCaseId FROM InsurancePolicy(NOLOCK)
											)

Print 'Generate Temp Charges Passed : ' + convert(varchar(30),getdate(),114)              

 UPDATE @TempData        
               SET        
                   CompanyName = J.CompanyName        
             FROM @TempData I        
                  LEFT JOIN InsuranceCompany J (NOLOCK) ON I.CompanyId = J.Id; 

Print 'Set Company Name Passed : ' + convert(varchar(30),getdate(),114)              


Insert Into @TempPaymentData              
( ChargeNo, PaymentAmt)              
Select Z.ChargeNum, Coalesce(Sum(Z.PaymentOrAdjAmount),0) from vw_PaymentsAdjustments Z              
Where z.IsDeleted =0 AND Z.ChargeNum > 0  and Z.PatientCaseId > 0 AND Z.IsPayment = 1          
AND Datediff(dd,Z.PaymentEffectiveDate,@ToDate) >= 0              

Group By ChargeNum
              
Print 'Generate Temp Payments Passed : ' + convert(varchar(30),getdate(),114)              

			Insert Into @TempAdjustmentData(ChargeNo, AdjustmentAmt)              
			Select Z.ChargeNum, Coalesce(Sum(Z.PaymentOrAdjAmount),0) 
				from vw_PaymentsAdjustments Z              
			Where  z.IsDeleted =0   AND Z.ChargeNum > 0   and Z.PatientCaseId > 0               
			AND Datediff(dd,Z.PaymentEffectiveDate,@ToDate) >= 0    AND Z.IsPayment = 0
			Group By ChargeNum 

Print 'Generate Temp Adjustments Passed : ' + convert(varchar(30),getdate(),114)

update @TempData                 
Set InsurancePayments = B.PaymentAmt               
From @TempData A  join @TempPaymentData B On A.ChargeNo = B.ChargeNo
              
 Print 'Update Insurance Payments Passed Chargewise: ' + convert(varchar(30),getdate(),114)                           
              
update @TempData                  
Set InsuranceAdjustments = B.AdjustmentAmt               
From @TempData A  join @TempAdjustmentData B On A.ChargeNo = B.ChargeNo   

Print 'Update Insurance Adjustments Passed Chargewise: ' + convert(varchar(30),getdate(),114)                          
        
update @TempData                  
Set Due = (A.Charge - (A.InsurancePayments + A.InsuranceAdjustments))
From @TempData A

Print 'Update Insurance Due Amount: ' + convert(varchar(30),getdate(),114)     
	  
	
SELECT CompanyName, PatientID As AccountNo,  PatientName, DOS, CPTCode, Charge, InsurancePayments, InsuranceAdjustments, 
Due from @TempData 
WHERE Due > 0  Order By CompanyName
END;


GO

--EXEC rpt_GetPatientBalanceReport '31 mar 2023'  
CREATE PROCEDURE [dbo].[rpt_GetPatientBalanceReport]          
(          
@ToDate   DATETIME = NULL          
)          
AS          
BEGIN                         
                
      
			Declare @TempData as Table (    
				Charge  Numeric(18,2),  
				BillIns Bit,  
				PatientID   int,                             
				PostDate Date,  
				ChargeNo  Numeric(18,0) Primary Key,                    
				PatientPayments  Numeric(18,2),                    
				PatientAdjustments  Numeric(18,2),  
				PatientName nvarchar(200),  
				DOS  DATE,          
				CPTCode NVARCHAR(50),  
				Due  Numeric(18,2)  
			)      
  
  
			Declare @TempPaymentData as Table (                 
                
			ChargeNo   Numeric(18,0) Primary Key,                    
			PaymentAmt  Numeric(18,2)                
			)                
                
			Declare @TempAdjustmentData as Table (                
                   
			ChargeNo   Numeric(18,0) Primary Key,                    
			AdjustmentAmt  Numeric(18,2)                    
			)  
  
  
			Insert Into @TempData                    
			(  Charge,   BillIns,  PatientID,                    
			  PostDate,  ChargeNo, PatientPayments, PatientAdjustments, PatientName, DOS, CPTCode, Due    
   
			)   
			(
			SELECT DISTINCT A.Amount, A.BillToInsurance, D.BillingId, A.EntryDate, A.ChargeNo, 0 [Payments],  0 [Adjustments],  
			CONCAT(D.LastName, ', ', D.FirstName, ' ', D.MI) [PatientName], A.BillFromDate AS FromDate, A.CPTCode, 0         
								  FROM vw_CHARGE_Latest A(NOLOCK)          
									   INNER JOIN Invoice B(NOLOCK) ON A.InvoiceId = B.Id
									   JOIN PatientCase C(NOLOCK) ON C.Id = B.PatientCaseId
									   JOIN Patient D(NOLOCK) ON C.PatientId = D.Id
									   JOIN [Provider] E(NOLOCK) ON D.ProviderId = E.Id
									   LEFT JOIN CPTCode (NOLOCK) J ON J.CPTCode = A.CPTCode          
									   LEFT JOIN CPTCategory (NOLOCK) K ON K.Id = J.CPTCategoryId
								  WHERE A.IsDeleted = 0
										AND A.ChargeNo > 0          
										AND A.PatientCaseId > 0          
										AND CAST(A.BillFromDate AS DATE) <= @ToDate   
										AND A.DueByFlagCD in ('','patient')
				   --AND  A.BillToInsurance = 0  

			UNION
			SELECT DISTINCT A.Amount, A.BillToInsurance, D.BillingID, A.EntryDate [PostDate], A.ChargeNo, 0 [Payments],  0 [Adjustments],  
			CONCAT(D.LastName, ', ', D.FirstName, ' ', D.MI) [PatientName], A.BillFromDate AS FromDate, A.CPTCode, 0         
								  FROM vw_CHARGE_Latest A(NOLOCK)          
									   INNER JOIN Invoice B(NOLOCK) ON A.InvoiceId = B.Id
									   JOIN PatientCase C(NOLOCK) ON C.Id = B.PatientCaseId
									   JOIN Patient D(NOLOCK) ON C.PatientId = D.Id         
									   JOIN [Provider] E(NOLOCK) ON D.ProviderId = E.Id
									   LEFT JOIN CPTCode (NOLOCK) J ON J.CPTCode = A.CPTCode          
									   LEFT JOIN CPTCategory (NOLOCK) K ON K.Id = J.CPTCategoryId
								  WHERE A.IsDeleted = 0        
										AND A.ChargeNo > 0          
										AND A.PatientCaseId > 0          
										AND CAST(A.BillFromDate AS DATE) <= @ToDate   
				   AND  A.BillToInsurance = 1 AND C.Id NOT IN (
											SELECT Distinct PatientCaseId FROM InsurancePolicy(NOLOCK)
											)

			)



  
  
			Print 'Generate Temp Charges Passed : ' + convert(varchar(30),getdate(),114)                             
  
  
			Insert Into @TempPaymentData                
			( ChargeNo, PaymentAmt)                
			Select Z.ChargeNum, Coalesce(Sum(Z.PaymentOrAdjAmount),0) from vw_PaymentsAdjustments Z                
			Where  z.IsDeleted =0 AND Z.ChargeNum > 0  and Z.PatientCaseId > 0              
			AND Datediff(dd,Z.PaymentEffectiveDate,@ToDate) >= 0 and Z.IsPayment = 1
			Group By ChargeNum                       
                
			Print 'Generate Temp Payments Passed : ' + convert(varchar(30),getdate(),114)                
  
  
		   Insert Into @TempAdjustmentData(ChargeNo, AdjustmentAmt)                
		   Select Z.ChargeNum, Coalesce(Sum(Z.PaymentOrAdjAmount),0)   
			from vw_PaymentsAdjustments Z                
		   Where  z.IsDeleted =0  AND Z.ChargeNum > 0   and Z.PatientCaseId > 0                 
		   AND Datediff(dd,Z.PaymentEffectiveDate,@ToDate) >= 0   and Z.IsPayment = 0                 
		   Group By ChargeNum
  
			Print 'Generate Temp Adjustments Passed : ' + convert(varchar(30),getdate(),114)  
  
  
  
			update @TempData                   
			Set PatientPayments = B.PaymentAmt                 
			From @TempData A  join @TempPaymentData B On A.ChargeNo = B.ChargeNo  
  
                
			Print 'Update Patient Payments Passed Chargewise: ' + convert(varchar(30),getdate(),114)                             
                
			update @TempData                    
			Set PatientAdjustments = B.AdjustmentAmt                 
			From @TempData A  join @TempAdjustmentData B On A.ChargeNo = B.ChargeNo     
  
  
			Print 'Update Patient Adjustments Passed Chargewise: ' + convert(varchar(30),getdate(),114)                            
          
			update @TempData                    
			Set Due = (A.Charge - (A.PatientPayments + A.PatientAdjustments))  
			From @TempData A  
  
			Print 'Update Patient Due Amount: ' + convert(varchar(30),getdate(),114)       
  
  
     
			SELECT PatientID As AccountNo,  PatientName, DOS, CPTCode, Charge, PatientPayments, PatientAdjustments,   
			Due from @TempData   
			WHERE Due > 0  Order By PatientName       
        
  
END;





GO



CREATE PROCEDURE rpt_GetPaymentDetails     @FromDate  datetime = NULL,     @ToDate   datetime = NULL,     @ProviderID  int = -1    AS         SELECT @ToDate = DATEADD(day, -1, @ToDate)        	 Declare @report as Table (          PaymentDate datetime, PerformingProvider varchar(50), BillingProvider varchar(50),           CPTCode varchar(10),           Qty int, Total decimal(10,2)     )                -- supply charges billed to the company     -- only select these to report if we're not filtered by a specific provider    IF @ProviderID = -1      INSERT INTO @report      EXEC usp_GetPaymentsToCompany @FromDate, @ToDate         INSERT INTO @report     EXEC usp_GetPaymentsToDoctors @FromDate, @ToDate, @ProviderID          DECLARE  


@TotalQty int, @TotalTotal decimal(10, 2)     SELECT  @TotalQty = SUM(Qty), @TotalTotal = SUM(Total)     FROM  @report              SELECT  0 as IsTotal, CAST(PaymentDate AS DATE) AS PaymentDate, PerformingProvider, BillingProvider, CPTCode as [Procedure], Qty,        '$' + CONVERT(varchar(12), Total) as Total     FROM  @report where PaymentDate IS NOT NULL         UNION           SELECT  1 as IsTotal, NULL, 'TOTAL', '', '', @TotalQty,        '$' + CONVERT(varchar(12), @TotalTotal) as Total   



  WHERE  @TotalQty > 0          ORDER BY IsTotal, CAST(PaymentDate AS DATE), PerformingProvider, BillingProvider, CPTCode 



GO

--rpt_InsuranceAgaingPatientReport '18 May 2021',3
CREATE PROCEDURE rpt_InsuranceAgaingPatientReport
@ToDate date='10 Nov 2020',
@InsuranceCompanyId INT = -1   
AS
BEGIN
	
		declare @temp table 
		(
		InsuranceCompanyID INT,
			CompanyName VARCHAR(200),
			CompanyCode VARCHAR(20),	
			DueAmount		Money,
			ZeroDay       Money,            
			ThirtyDays    Money,            
			SixtyDays     Money,            
			NinetyDays    Money,            
			OneTwentyDays Money ,
			PatientCaseId INT,
			TotalOwing MONEY
				 
		)

				DECLARE @TempInsPolicy AS TABLE            
				(
				InsCompanyId       INT,            
				 PatientId          INT,            
				 PolicyId           BIGINT,            
				 CaseNumber         NUMERIC(18, 0),            
				 InsLevel           INT,            
				 PlanEffectiveDate  DATE,            
				 PlanExpirationDate DATE,            
				 PRIMARY KEY(PatientId, PolicyId)  ,
				 CompanyName VARCHAR(200),
				 CompanyCode VARCHAR(20)
				);            

					INSERT INTO @TempInsPolicy            
					(InsCompanyId,      
					 PatientId,            
					 PolicyId,            
					 CaseNumber,            
					 InsLevel,            
					 PlanEffectiveDate,            
					 PlanExpirationDate,
					 CompanyName,
					 CompanyCode
					)            
                    SELECT ip2.InsuranceCompanyID,            
                           ip2.PatientCaseId [PatientID],     
                           ip2.Id [PolicyID],            
                           pc.CaseIdNumber [CaseNumber],            
                           ip2.InsuranceLevel [Level],            
                           ip2.PlanEffectiveDate,            
                           ip2.PlanExpirationDate,
						   B.CompanyName,B.CompanyCode
                    FROM InsurancePolicy ip2(NOLOCK)	
					inner join InsuranceCompany B ON B.Id=ip2.InsuranceCompanyId
					Left Join PatientCase pc ON pc.Id = ip2.PatientCaseId
					


		--select * from @TempInsPolicy

		insert into @temp(CompanyCode,CompanyName,ZeroDay,ThirtyDays,SixtyDays,NinetyDays,OneTwentyDays,PatientCaseId,InsuranceCompanyID)
		select 
		--dbo.ufn_ActiveInsuranceForCaseNo_InsuranceCompanyName(BillFromDate,1,PatientCaseId)[InsuranceCompany],
		B.CompanyCode,B.CompanyName,
							CASE WHEN(DATEDIFF(dd,CAST(ISNULL(ShiftDate,BillFromDate) AS DATE), @ToDate) <= 29) THEN DueAmount ELSE 0 END[ZeroDay],
							CASE WHEN(DATEDIFF(dd, CAST(ISNULL(ShiftDate,BillFromDate) AS DATE), @ToDate) >= 30) AND (DATEDIFF(dd, CAST(ISNULL(ShiftDate,BillFromDate) AS DATE), @ToDate) <= 59) THEN DueAmount ELSE 0 END[ThirtyDays],            
			  CASE WHEN(DATEDIFF(dd, CAST(ISNULL(ShiftDate,BillFromDate) AS DATE), @ToDate) >= 60) AND (DATEDIFF(dd, CAST(ISNULL(ShiftDate,BillFromDate) AS DATE), @ToDate) <= 89) THEN DueAmount ELSE 0 END[SixtyDays],                               
						 CASE WHEN(DATEDIFF(dd, CAST(ISNULL(ShiftDate,BillFromDate) AS DATE), @ToDate) >= 90) AND (DATEDIFF(dd, CAST(ISNULL(ShiftDate,BillFromDate) AS DATE), @ToDate) <= 9999999) THEN DueAmount ELSE 0 END[NinetyDays],            
			 CASE WHEN(DATEDIFF(dd, CAST(ISNULL(ShiftDate,BillFromDate) AS DATE), @ToDate) >= 120) THEN DueAmount ELSE 0 END[OneTwentyDays],
						  PatientCaseId,B.InsCompanyId
		from vw_GetChargeForPendingPayment A
		inner join @TempInsPolicy B on A.PatientCaseId=B.PatientId
		where IsDeleted=0 and DueByFlagCD in  ('Secondary','PRIMARY') and DueAmount>0 and CAST(ISNULL(ShiftDate,BillFromDate) AS DATE)>'1 May 2020' and CAST(ISNULL(ShiftDate,A.BillFromDate) AS DATE)<=@ToDate
		AND			B.PlanEffectiveDate <= A.BillFromDate
									AND			(B.PlanExpirationDate IS NULL
										OR		B.PlanExpirationDate >= A.BillFromDate)
										AND B.InsLevel in (CASE WHEN A.DueByFlagCD='Primary' THEN 1 WHEN A.DueByFlagCD='Secondary' THEN 2 END)--(1)
										


		update @temp set TotalOwing=(ZeroDay+ThirtyDays+SixtyDays+NinetyDays)
		
		

		select CONCAT ( B.LastName, ',', B.FirstName, ' ', ISNULL(B.MI,'') )[PatientName],B.Id[AccountNo],B.DOB,
		SUM(ZeroDay)ZeroDays,SUM(ThirtyDays)ThirtyDays,SUM(SixtyDays)SixtyDays,SUM(NinetyDays)NintyDays,SUM(TotalOwing)TotalOwing ,'' AS PaymentPlan
		,    (Select Top 1 CAST(CreatedDate AS DATE) AS PaymentDate from Payment(NOLOCK) where PatientId = B.Id  order by PaymentDate desc) AS LastPaymentDate
		from @temp A
		Inner join Patient B (NOLOCK) ON B.DefaultCaseId=A.PatientCaseId
		WHERE (A.InsuranceCompanyID = @InsuranceCompanyId OR @InsuranceCompanyId = -1)  
		group by B.FirstName,B.LastName,B.DOB,B.MI,B.Id order by FirstName asc

END





GO

