                           ip2.InsuranceLevel [Level],            
                           ip2.PlanEffectiveDate,            
                           ip2.PlanExpirationDate,
						   B.CompanyName,B.CompanyCode
                    FROM InsurancePolicy ip2(NOLOCK)	
					inner join InsuranceCompany B ON B.Id=ip2.InsuranceCompanyId
					Left Join PatientCase pc ON pc.Id = ip2.PatientCaseId
					


		--select * from @TempInsPolicy

		insert into @temp(CompanyCode,CompanyName,ZeroDay,ThirtyDays,SixtyDays,NinetyDays,OneTwentyDays,PatientCaseId,InsuranceCompanyID)
		select 
		--dbo.ufn_ActiveInsuranceForCaseNo_InsuranceCompanyName(BillFromDate,1,PatientCaseId)[InsuranceCompany],
		B.CompanyCode,B.CompanyName,
							CASE WHEN(DATEDIFF(dd,CAST(ISNULL(ShiftDate,BillFromDate) AS DATE), @ToDate) <= 29) THEN DueAmount ELSE 0 END[ZeroDay],
							CASE WHEN(DATEDIFF(dd, CAST(ISNULL(ShiftDate,BillFromDate) AS DATE), @ToDate) >= 30) AND (DATEDIFF(dd, CAST(ISNULL(ShiftDate,BillFromDate) AS DATE), @ToDate) <= 59) THEN DueAmount ELSE 0 END[ThirtyDays],            
			  CASE WHEN(DATEDIFF(dd, CAST(ISNULL(ShiftDate,BillFromDate) AS DATE), @ToDate) >= 60) AND (DATEDIFF(dd, CAST(ISNULL(ShiftDate,BillFromDate) AS DATE), @ToDate) <= 89) THEN DueAmount ELSE 0 END[SixtyDays],                               
						 CASE WHEN(DATEDIFF(dd, CAST(ISNULL(ShiftDate,BillFromDate) AS DATE), @ToDate) >= 90) AND (DATEDIFF(dd, CAST(ISNULL(ShiftDate,BillFromDate) AS DATE), @ToDate) <= 9999999) THEN DueAmount ELSE 0 END[NinetyDays],            
			 CASE WHEN(DATEDIFF(dd, CAST(ISNULL(ShiftDate,BillFromDate) AS DATE), @ToDate) >= 120) THEN DueAmount ELSE 0 END[OneTwentyDays],
						  PatientCaseId,B.InsCompanyId
		from vw_GetChargeForPendingPayment A
		inner join @TempInsPolicy B on A.PatientCaseId=B.PatientId
		where IsDeleted=0 and DueByFlagCD in  ('Secondary','PRIMARY') and DueAmount>0 and CAST(ISNULL(ShiftDate,BillFromDate) AS DATE)>'1 May 2020' and CAST(ISNULL(ShiftDate,A.BillFromDate) AS DATE)<=@ToDate
		AND			B.PlanEffectiveDate <= A.BillFromDate
									AND			(B.PlanExpirationDate IS NULL
										OR		B.PlanExpirationDate >= A.BillFromDate)
										AND B.InsLevel in (CASE WHEN A.DueByFlagCD='Primary' THEN 1 WHEN A.DueByFlagCD='Secondary' THEN 2 END)--(1)
										


		update @temp set TotalOwing=(ZeroDay+ThirtyDays+SixtyDays+NinetyDays)
		
		

		select InsuranceCompanyID,CompanyCode,CompanyName,SUM(ZeroDay)ZeroDays,SUM(ThirtyDays)ThirtyDays,SUM(SixtyDays)SixtyDays,SUM(NinetyDays)NintyDays,SUM(TotalOwing)TotalOwing from @temp
		group by InsuranceCompanyID,CompanyCode,CompanyName order by CompanyName asc

END




