--EXEC rpt_LabActivityByOrderingProviderReport '2019-01-01', '2019-09-30'
CREATE PROCEDURE [dbo].[rpt_LabActivityByOrderingProviderReport]                       
 @FromDate datetime = NULL,                                        
 @ToDate  datetime = NULL,                                        
 @Providers VARCHAR(MAX) = NULL      
AS                                       
                      
;WITH Charges AS                       
(                      
 SELECT
 --Year(ISNULL(v.SHIFTDate, v.FromDate)) YearNo, 
 --Month(ISNULL(v.SHIFTDate, v.FromDate)) MonthNo,                      
  Year(inv.CreatedDate) YearNo,     
 Month(inv.CreatedDate) MonthNo,  
                         
    refDoc.ID,                       
     refDoc.FirstName, refDoc.LastName ,                      
    COUNT(1) TChargeCount,                        
    CAST(SUM(v.Amount) AS DECIMAL(10,2)) TotalCharge                      
 FROM  vw_CHARGE_Latest v (NOLOCK) 
  JOIN Invoice inv (NOLOCK) on inv.ID = v.InvoiceId
  JOIN ReferringDoctor refDoc (NOLOCK) on inv.RefDoctorId = refDoc.Id
  --WHERE  (@FromDate IS NULL OR (cast(ISNULL(SHIFTDate, v.FromDate) as date) >=@FromDate AND cast(ISNULL(SHIFTDate, v.FromDate) as date)<=@ToDate  ))                          
  WHERE  (@FromDate IS NULL OR (cast(inv.CreatedDate as date) >=@FromDate AND cast(inv.CreatedDate as date)<=@ToDate  ))
  AND v.ChargeNo > 0 AND v.PatientCaseId > 0                                            
  AND v.IsDeleted =0
 GROUP BY refDoc.FirstName, refDoc.LastName, refDoc.Id ,   
    --Month(ISNULL(v.SHIFTDate, v.FromDate)),                      
    --Year(ISNULL(v.SHIFTDate, v.FromDate))  
	Month(inv.CreatedDate),                      
	Year(inv.CreatedDate)
 ),                     
                      
 Payment AS                      
 (                      
    SELECT 	
	 refDoc.ID,                       
     refDoc.FirstName, refDoc.LastName ,                    
    Month(PaymentEffectiveDate) MonthNo,                      
    Year(PaymentEffectiveDate)YearNo,                      
    CAST(SUM(PaymentOrAdjAmount) AS DECIMAL(10,2)) TotalPayment,
	 COUNT(1) TPaymentCount   
     From vw_PaymentsAdjustments v (NOLOCK)                     
	JOIN Invoice inv (NOLOCK) on inv.AccessionNumber = v.AccessionNumber
    JOIN ReferringDoctor refDoc (NOLOCK) on inv.RefDoctorId = refDoc.Id
    WHERE ((CAST(v.PaymentEffectiveDate AS DATE) >= CAST(@FromDate AS DATE)        
                         OR @FromDate IS NULL)        
                        AND (CAST(v.PaymentEffectiveDate AS DATE) <= CAST(@ToDate AS DATE)        
                             OR @ToDate IS NULL))    
    AND v.ChargeNum > 0 AND v.PatientCaseId > 0      
    AND v.IsDeleted =0 AND v.IsPayment = 1
    GROUP BY  refDoc.FirstName, refDoc.LastName, refDoc.ID ,                       
    Month(PaymentEffectiveDate) ,                      
    Year(PaymentEffectiveDate)                      
                      
),


 adj as                       
 (                      
      SELECT refDoc.ID,                       
     refDoc.FirstName, refDoc.LastName ,                    
     Month(PaymentEffectiveDate) MonthNo,                      
    Year(PaymentEffectiveDate)YearNo,                      
    CAST(SUM(PaymentOrAdjAmount) AS DECIMAL(10, 2)) TotalAdjustment ,
	 COUNT(1) TAdjustmentCount
     From vw_PaymentsAdjustments v (NOLOCK)                     
 JOIN Invoice inv (NOLOCK) on inv.AccessionNumber = v.AccessionNumber
  JOIN ReferringDoctor refDoc (NOLOCK) on inv.RefDoctorId = refDoc.ID  
    WHERE ((CAST(v.PaymentEffectiveDate AS DATE) >= CAST(@FromDate AS DATE)        
  OR @FromDate IS NULL)        
                        AND (CAST(v.PaymentEffectiveDate AS DATE) <= CAST(@ToDate AS DATE)        
                             OR @ToDate IS NULL))    
     AND v.ChargeNum > 0 AND v.PatientCaseId > 0      
    AND v.IsDeleted =0 AND v.IsPayment = 0
	    GROUP BY   refDoc.FirstName, refDoc.LastName, refDoc.ID ,        
     Month(PaymentEffectiveDate) ,                      
    Year(PaymentEffectiveDate)                      
                      
 ), 

 unAll as                      
 (                      
     SELECT FirstName,                      
    LastName ,                      
    ID,                      
    C.MonthNo,                      
    C.YearNo,
	C.TChargeCount
    FROM   Charges C  (NOLOCK)          
                          
    UNION ALL                      
    SELECT FirstName,                      
    LastName ,                      
    ID,                      
    C.MonthNo,                      
    C.YearNo,
	C.TPaymentCount
    FROM   Payment c   (NOLOCK)            
                      
                  
    UNION ALL                      
    SELECT FirstName,                      
    LastName ,                      
    ID,                      
    C.MonthNo,                      
    C.YearNo,
	C.TAdjustmentCount
    FROM   adj c  (NOLOCK)                    
),                      
AllData AS(                      
    SELECT DISTINCT
	convert(varchar(4), u.YearNo) + '-' + convert(varchar(2),u.MonthNo) PostMonth,
	ISNULL(U.LastName + ' ' + u.FirstName, '') ReferringPhysician, 
	ISNULL(C.TChargeCount, 0) AS ChargeSpecimens,
    ISNULL(C.TotalCharge, 0) ChargeTotal,  
	--(ISNULL(C.TotalCharge, 0) / (Select SUM(ISNULL(chg.TotalCharge, 0)) from Charges chg )) AS ChargesPercentage,
	0 AS ChargesPercentage,
	ISNULL(P.TPaymentCount, 0) AS PaymentSpecimens,
    ISNULL(P.TotalPayment, 0) PaymentTotal,   
	--(ISNULL(P.TotalPayment, 0) / (Select SUM(ISNULL(pmt.TotalPayment, 0)) from Payment pmt )) AS PaymentPercentage,	
	 0 AS PaymentPercentage,	
	ISNULL(A.TAdjustmentCount, 0) AS AdjustmentSpecimens,
    ISNULL(A.TotalAdjustment, 0) AdjustmentTotal,  
	--ISNULL((ISNULL(A.TotalAdjustment, 0) / (Select SUM(ISNULL(adjt.TotalAdjustment, 0)) from adj adjt)), 0) AS AdjustmentPercentage,		
	 0 AS AdjustmentPercentage,		
	(ISNULL(C.TotalCharge, 0) - (ISNULL(P.TotalPayment, 0) + ISNULL(A.TotalAdjustment, 0))) AS NetActivity
	
                      
    FROM unAll u  (NOLOCK)                     
    LEFT JOIN Charges c (NOLOCK) on  C.ID = u.ID and C.MonthNo=U.MonthNo AND C.YearNo=U.YearNo                      
                      
    LEFT JOIN Payment p (NOLOCK) on                      
    p.ID = u.ID and p.MonthNo=U.MonthNo AND p.YearNo=U.YearNo                      
                      
  LEFT JOIN adj a (NOLOCK) on                      
    a.ID = u.ID and a.MonthNo=U.MonthNo AND a.YearNo=U.YearNo  
	
)                      
SELECT PostMonth, ReferringPhysician, ChargeSpecimens, ChargeTotal, CAST(ChargesPercentage AS DECIMAL(10, 2)) AS ChargesPercentage,
PaymentSpecimens, PaymentTotal, CAST(PaymentPercentage AS DECIMAL(10, 2)) AS PaymentPercentage,
AdjustmentSpecimens, AdjustmentTotal, CAST(AdjustmentPercentage AS DECIMAL(10, 2)) AS AdjustmentPercentage, NetActivity
 FROM AllData where ReferringPhysician <> '' AND ChargeTotal > 0



--Select * from Charges;
--Select * from Payment;
--Select * from adj;




GO


--EXEC rpt_LabActivityByPayerReport '2019-01-01', '2019-09-30'
CREATE  PROCEDURE [dbo].[rpt_LabActivityByPayerReport]                       
 @FromDate datetime = NULL,                                        
 @ToDate  datetime = NULL,                                        
 @InsuranceCompanies VARCHAR(MAX) = NULL      
AS                                       
                      
;WITH Charges AS                       
(                      
 SELECT
 --Year(ISNULL(v.SHIFTDate, v.FromDate)) YearNo, 
 --Month(ISNULL(v.SHIFTDate, v.FromDate)) MonthNo,                                              
 Year(inv.CreatedDate) YearNo,     
 Month(inv.CreatedDate) MonthNo,  
    com.Id [InsuranceCompanyId],                       
     com.CompanyName,                      
    COUNT(1) TChargeCount,                        
    CAST(SUM(v.Amount) AS DECIMAL(10,2)) TotalCharge                      
 FROM  vw_CHARGE_Latest v (NOLOCK) 
  JOIN Invoice inv (NOLOCK) on inv.ID = v.InvoiceId
  LEFT JOIN InsuranceCompany com (NOLOCK) on com.Id = dbo.ufn_ActiveInsuranceForCaseNo(v.BillFromDate, 1, v.PatientCaseId)
  --WHERE  (@FromDate IS NULL OR (cast(ISNULL(SHIFTDate, v.FromDate) as date) >=@FromDate AND cast(ISNULL(SHIFTDate, v.FromDate) as date)<=@ToDate  ))                          
  WHERE  (@FromDate IS NULL OR (cast(inv.CreatedDate as date) >=@FromDate AND cast(inv.CreatedDate as date)<=@ToDate  ))                          
  AND v.ChargeNo > 0 AND v.PatientCaseId > 0                                            
  AND v.IsDeleted = 0
 GROUP BY com.Id, com.CompanyName,                                
    --Month(ISNULL(v.SHIFTDate, v.FromDate)),                      
    --Year(ISNULL(v.SHIFTDate, v.FromDate))    
	Month(inv.CreatedDate),                      
	Year(inv.CreatedDate)
 ),                     
                      
 Payment AS                      
 (                      
    SELECT 	
	com.Id [InsuranceCompanyId],                       
     com.CompanyName,                    
    Month(PaymentEffectiveDate) MonthNo,                      
    Year(PaymentEffectiveDate)YearNo,                      
    CAST(SUM(PaymentOrAdjAmount) AS DECIMAL(10,2)) TotalPayment,
	 COUNT(1) TPaymentCount   
     From vw_PaymentsAdjustments v (NOLOCK)                     
	JOIN Invoice inv (NOLOCK) on inv.AccessionNumber = v.AccessionNumber
	Left Join InsurancePolicy ipo (NOLOCK) ON ipo.PatientCaseId = inv.PatientCaseId
  LEFT JOIN InsuranceCompany com (NOLOCK) on com.Id = ipo.InsuranceCompanyId
    WHERE ((CAST(v.PaymentEffectiveDate AS DATE) >= CAST(@FromDate AS DATE)        
                         OR @FromDate IS NULL)        
                        AND (CAST(v.PaymentEffectiveDate AS DATE) <= CAST(@ToDate AS DATE)        
                             OR @ToDate IS NULL))    
     AND v.ChargeNum > 0 AND v.PatientCaseId > 0      
    AND v.IsDeleted =0 AND v.IsPayment = 1
	    GROUP BY  com.Id,                       
     com.CompanyName,                       
    Month(PaymentEffectiveDate) ,                      
    Year(PaymentEffectiveDate)                      
                      
),


 adj as                       
 (                      
      SELECT com.Id [InsuranceCompanyId],                       
     com.CompanyName,                      
     Month(PaymentEffectiveDate) MonthNo,                      
    Year(PaymentEffectiveDate)YearNo,                      
    CAST(SUM(PaymentOrAdjAmount) AS DECIMAL(10, 2)) TotalAdjustment ,
	 COUNT(1) TAdjustmentCount
     From vw_PaymentsAdjustments v (NOLOCK)                     
 JOIN Invoice inv (NOLOCK) on inv.AccessionNumber = v.AccessionNumber
 Left Join InsurancePolicy ipo (NOLOCK) ON ipo.PatientCaseId = inv.PatientCaseId
  LEFT JOIN InsuranceCompany com (NOLOCK) on com.Id = ipo.InsuranceCompanyId 
    WHERE ((CAST(v.PaymentEffectiveDate AS DATE) >= CAST(@FromDate AS DATE)        
                         OR @FromDate IS NULL)    
                        AND (CAST(v.PaymentEffectiveDate AS DATE) <= CAST(@ToDate AS DATE)        
                             OR @ToDate IS NULL))    
    AND v.ChargeNum > 0 AND v.PatientCaseId > 0      
    AND v.IsDeleted = 0 AND v.IsPayment = 0                                     
    GROUP BY   com.Id,                       
     com.CompanyName,           
     Month(PaymentEffectiveDate) ,                      
    Year(PaymentEffectiveDate)                      
                      
 ), 

 unAll as                      
 (                      
     SELECT CompanyName,                          
    InsuranceCompanyId,                      
    C.MonthNo,                      
    C.YearNo,
	C.TChargeCount
    FROM   Charges C  (NOLOCK)          
                          
    UNION ALL                      
    SELECT CompanyName,                          
    InsuranceCompanyID,               
    C.MonthNo,                      
    C.YearNo,
	C.TPaymentCount
    FROM   Payment c   (NOLOCK)            
                      
                  
    UNION ALL                      
    SELECT CompanyName,                          
    InsuranceCompanyID,               
    C.MonthNo,                      
    C.YearNo,
	C.TAdjustmentCount
    FROM   adj c  (NOLOCK)                    
),                      
AllData AS(                      
    SELECT DISTINCT
	convert(varchar(4), u.YearNo) + '-' + convert(varchar(2),u.MonthNo) PostMonth,
	ISNULL(U.CompanyName, '') InsuranceCompany, 
	ISNULL(C.TChargeCount, 0) AS ChargeSpecimens,
    ISNULL(C.TotalCharge, 0) ChargeTotal,  
	0 AS ChargesPercentage,
	ISNULL(P.TPaymentCount, 0) AS PaymentSpecimens,
    ISNULL(P.TotalPayment, 0) PaymentTotal,   
	0 AS PaymentPercentage,
	ISNULL(A.TAdjustmentCount, 0) AS AdjustmentSpecimens,
    ISNULL(A.TotalAdjustment, 0) AdjustmentTotal,                         
	0 AS AdjustmentPercentage,
	(ISNULL(C.TotalCharge, 0) - (ISNULL(P.TotalPayment, 0) + ISNULL(A.TotalAdjustment, 0))) AS NetActivity
	
                      
    FROM unAll u  (NOLOCK)                     
    LEFT JOIN Charges c (NOLOCK) on  C.InsuranceCompanyID = u.InsuranceCompanyID and C.MonthNo=U.MonthNo AND C.YearNo=U.YearNo                      
                      
    LEFT JOIN Payment p (NOLOCK) on                      
    p.InsuranceCompanyID = u.InsuranceCompanyID and p.MonthNo=U.MonthNo AND p.YearNo=U.YearNo                      
                      
  LEFT JOIN adj a (NOLOCK) on                      
    a.InsuranceCompanyID = u.InsuranceCompanyID and a.MonthNo=U.MonthNo AND a.YearNo=U.YearNo  
	
)                      
SELECT * FROM AllData where InsuranceCompany <> '' AND ChargeTotal > 0



--Select * from Charges;
--Select * from Payment;
--Select * from adj;




GO

--rpt_PatientAgaingReport '10 Dec 2023'
CREATE PROCEDURE rpt_PatientAgaingReport
@ToDate date='10 Nov 2023'
AS
BEGIN
	
		declare @temp table 
		(
			PatientId   int,              
			PatientName  Nvarchar(500),	
			DueAmount		Money,
			ZeroDay       Money,            
			ThirtyDays    Money,            
			SixtyDays     Money,            
			NinetyDays    Money,            
			OneTwentyDays Money ,
			PatientCaseId INT,
			TotalOwing MONEY
				 
		)

		insert into @temp(PatientId,PatientName,ZeroDay,ThirtyDays,SixtyDays,NinetyDays,OneTwentyDays)
		select  B.Id,CONCAT ( B.LastName, ',', B.FirstName, ' ', ISNULL(B.MI,'') ),CASE WHEN(DATEDIFF(dd,CAST(ISNULL(ShiftDate,BillFromDate) AS DATE), @ToDate) <= 29) THEN DueAmount ELSE 0 END[ZeroDay],
							CASE WHEN(DATEDIFF(dd, CAST(ISNULL(ShiftDate,BillFromDate) AS DATE), @ToDate) >= 30) AND (DATEDIFF(dd, CAST(ISNULL(ShiftDate,BillFromDate) AS DATE), @ToDate) <= 59) THEN DueAmount ELSE 0 END[ThirtyDays],            
			  CASE WHEN(DATEDIFF(dd, CAST(ISNULL(ShiftDate,BillFromDate) AS DATE), @ToDate) >= 60) AND (DATEDIFF(dd, CAST(ISNULL(ShiftDate,BillFromDate) AS DATE), @ToDate) <= 89) THEN DueAmount ELSE 0 END[SixtyDays],                               
						 CASE WHEN(DATEDIFF(dd, CAST(ISNULL(ShiftDate,BillFromDate) AS DATE), @ToDate) >= 90) AND (DATEDIFF(dd, CAST(ISNULL(ShiftDate,BillFromDate) AS DATE), @ToDate) <= 119) THEN DueAmount ELSE 0 END[NinetyDays],            
			 CASE WHEN(DATEDIFF(dd, CAST(ISNULL(ShiftDate,BillFromDate) AS DATE), @ToDate) >= 120) THEN DueAmount ELSE 0 END[OneTwentyDays]
		from vw_GetChargeForPendingPayment A
		inner join Patient(NOLOCK) B ON B.DefaultCaseId=A.PatientCaseId
		where IsDeleted=0 and DueByFlagCD in  ('Patient','') and DueAmount>0 and  CAST(ISNULL(ShiftDate,A.BillFromDate) AS DATE)<=@ToDate
		--AND			B.PlanEffectiveDate <= A.BillFromDate
		--							AND			(B.PlanExpirationDate IS NULL
		--								OR		B.PlanExpirationDate >= A.BillFromDate)
		--								AND B.InsLevel in (CASE WHEN A.DueByFlagCD='Primary' THEN 1 WHEN A.DueByFlagCD='Secondary' THEN 2 END)--(1)
										


		update @temp set TotalOwing=(ZeroDay+ThirtyDays+SixtyDays+NinetyDays+OneTwentyDays)
		
		

		select PatientId,PatientName,SUM(ZeroDay)ZeroDays,SUM(ThirtyDays)ThirtyDays,SUM(SixtyDays)SixtyDays,SUM(NinetyDays)NintyDays,SUM(OneTwentyDays)OneTwentyDays,SUM(TotalOwing)TotalOwing from @temp
		group by PatientId,PatientName order by PatientName asc

END





GO

CREATE PROCEDURE [dbo].[rpt_PatientAndInsARStatusReport]
(    
@FromDate   DATETIME = NULL,      
@ToDate   DATETIME = NULL              
)
AS    
     
Declare @PatientHeader varchar(10)
Set @PatientHeader = 'PATIENT'

Declare @InsuranceHeader varchar(10)
Set @InsuranceHeader = 'INSURANCE'

Declare @TempPatientCaseData as Table (  
CaseNo  Int,
BillIns  Bit
)   


Declare @TempPatientChargeData as Table (  
ChargeNo  Numeric(18,0) Primary Key,  
--PatientID  int,  
BillIns  Bit,
Charge Numeric(18, 2)
)        
    
    
Declare @TempPaymentData as Table (
PaymentAmt Numeric(18,2),
PayorInsurance int,
PayorPatient int
)                  
                  
Declare @TempAdjustmentData as Table (                     
AdjustmentAmt Numeric(18,2),
PayorInsurance int,
PayorPatient int
)   

Declare @TempARStatusData as Table (   
Header VARCHAR(10),
Accounts int,
Charges Numeric(18, 2),
Payments Numeric(18,2) ,                 
Adjustments Numeric(18,2),                      
EndingBalance Numeric(18,2)                      
)  


Insert Into @TempPatientCaseData
(CaseNo, BillIns)
SELECT DISTINCT PatientCaseId, BillToInsurance from vw_CHARGE_Latest A
						where A.IsDeleted =0
                            AND A.ChargeNo > 0      
                            AND A.PatientCaseId > 0      
                            AND CAST(A.BillFromDate AS DATE) BETWEEN CAST(@FromDate AS DATE) AND CAST(@ToDate AS DATE)



Insert Into @TempPatientChargeData                      
(ChargeNo, BillIns, Charge)    
SELECT DISTINCT A.ChargeNo, A.BillToInsurance, A.Amount
 FROM vw_CHARGE_Latest A (NOLOCK)    
 JOIN @TempPatientCaseData B ON A.PatientCaseId = B.CaseNo
        --INNER JOIN BL_Invoices B(NOLOCK) ON A.InvoiceNo = B.ID      
        --                   JOIN BL_Cases C(NOLOCK) ON C.CaseNumber = B.CaseNo      
        --                   JOIN Patient D(NOLOCK) ON C.PatientID = D.PatientID      
        --                   JOIN [user] E(NOLOCK) ON D.ProviderID = E.UserID                                      
        --                   LEFT JOIN Procedurecodelist(NOLOCK) J ON J.CPTCode = A.CPTCode      
        --                   LEFT JOIN PM_CPTCategories(NOLOCK) K ON K.ID = J.Category      
                      --WHERE A.CaseNo IN (Select CaseNo from @TempPatientCaseData)
                            --AND CAST(A.FromDate AS DATE) BETWEEN CAST(@FromDate AS DATE) AND CAST(@ToDate AS DATE)
							
  
Print 'Generate Temp Charges Passed : ' + convert(varchar(30),getdate(),114)                  
  

Insert Into @TempARStatusData                      
(Header, Accounts, Charges, Payments, Adjustments, EndingBalance)    
(SELECT @PatientHeader, COUNT(*), 0, 0, 0, 0
                      FROM @TempPatientCaseData bch      
                      WHERE BillIns = 0)

Print 'Generate Temp ARStatus Patient Cases Count Passed : ' + convert(varchar(30),getdate(),114)


Insert Into @TempARStatusData                      
(Header, Accounts, Charges, Payments, Adjustments, EndingBalance)    
(SELECT @InsuranceHeader, COUNT(*), 0, 0, 0, 0
                      FROM @TempPatientCaseData bch      
                      WHERE BillIns = 1)
  
Print 'Generate Temp ARStatus Insurance Cases Count Passed : ' + convert(varchar(30),getdate(),114)


update @TempARStatusData                     
Set Charges = (Select Coalesce(Sum(Charge), 0) from @TempPatientChargeData where BillIns = 0)
where Header = @PatientHeader


Print 'Update Patient Charges Passed : ' + convert(varchar(30),getdate(),114)    


update @TempARStatusData                     
Set Charges =  (Select Coalesce(Sum(Charge), 0) from @TempPatientChargeData where BillIns = 1)
where Header = @InsuranceHeader


Print 'Update Insurance Charges Passed : ' + convert(varchar(30),getdate(),114)   


Insert Into @TempPaymentData                  
 (PaymentAmt, PayorInsurance, PayorPatient)                  
 Select Z.PaidAmount,V.InsuranceCompanyId [Z.PayorInsurance], V.PatientId [Z.PayorPatient] from vw_GetChargeForPendingPayment Z 
 join @TempPatientChargeData B On Z.ChargeNo = B.ChargeNo
 left join PatientCase p ON p.Id = Z.PatientCaseId
  left join InsurancePolicy inp ON inp.PatientCaseId = Z.PatientCaseId
  left join Voucher V ON V.patientId = p.PatientId or V.InsuranceCompanyId = inp.InsuranceCompanyId
 Where z.IsDeleted =0  AND Z.ChargeNo > 0  and Z.PatientCaseId > 0              
 AND CAST(PaymentEffectiveDate AS DATE) BETWEEN CAST(@FromDate AS DATE) AND CAST(@ToDate AS DATE)                         
                  
Print 'Generate Temp Total Payments Chargewise Passed : ' + convert(varchar(30),getdate(),114)  
  
  
  
Insert Into @TempAdjustmentData(AdjustmentAmt, PayorInsurance, PayorPatient)                  
   Select Z.TotalAdjustment,V.InsuranceCompanyId [PayorInsurance],V.PatientId [PayorPatient] from vw_GetChargeForPendingPayment Z                  
   join @TempPatientChargeData B On Z.ChargeNo = B.ChargeNo
   left join PatientCase p ON p.Id = Z.PatientCaseId
  left join InsurancePolicy inp ON inp.PatientCaseId = Z.PatientCaseId
  left join Voucher V ON V.patientId = p.PatientId or V.InsuranceCompanyId = inp.InsuranceCompanyId
   Where  z.IsDeleted =0  AND Z.ChargeNo > 0   and Z.PatientCaseId > 0                   
   AND CAST(PaymentEffectiveDate AS DATE) BETWEEN CAST(@FromDate AS DATE) AND CAST(@ToDate AS DATE)          
    
Print 'Generate Temp Total Adjustments Chargewise Passed : ' + convert(varchar(30),getdate(),114)    



update @TempARStatusData                     
Set Payments =  (Select Coalesce(Sum(PaymentAmt), 0) from @TempPaymentData where PayorPatient Is Not Null)                   
where Header = @PatientHeader

Print 'Update Patient Payments Passed : ' + convert(varchar(30),getdate(),114)    
    

update @TempARStatusData                     
Set Adjustments = (Select Coalesce(Sum(AdjustmentAmt), 0) from @TempAdjustmentData where PayorPatient Is Not Null)                  
where Header = @PatientHeader

Print 'Update Patient Adjustments Passed : ' + convert(varchar(30),getdate(),114)


	  
update @TempARStatusData                     
Set Payments = (Select Coalesce(Sum(PaymentAmt), 0) from @TempPaymentData where PayorInsurance Is Not Null)                   
where Header = @InsuranceHeader

Print 'Update Insurance Payments Passed : ' + convert(varchar(30),getdate(),114) 
                  

update @TempARStatusData                     
Set Adjustments = (Select Coalesce(Sum(AdjustmentAmt), 0) from @TempAdjustmentData where PayorInsurance Is Not Null)                   
where Header = @InsuranceHeader

Print 'Update Insurance Adjustments Passed : ' + convert(varchar(30),getdate(),114)

            
update @TempARStatusData                      
Set EndingBalance = (A.Charges - (A.Payments + A.Adjustments))    
From @TempARStatusData A    
    
Print 'Update Ending Balance Amount: ' + convert(varchar(30),getdate(),114)     
  
  
  
  
   
 SELECT * from @TempARStatusData 


 EXEC rpt_PatientAndInsTotalARStatusReport


                             
                             
  
  
   
   

GO

