update @TempARStatusData                      
Set EndingBalance = (A.Charges - (A.Payments + A.Adjustments))    
From @TempARStatusData A    
    
Print 'Update Ending Balance Amount: ' + convert(varchar(30),getdate(),114)     
  
  
  
  
   
