--rpt_PatientChargeStatement '3934','06/12/2020','1/1/2026','','False','1'
CREATE PROCEDURE [dbo].[rpt_PatientChargeStatement]
@PatientId nvarchar(500), 
@FromDate DATETIME = NULL,  
@ToDate DATETIME = NULL,  
@Message NVARCHAR(500)='', 
@IsBulkStatement VARCHAR(10)='False',
@IsAllCharges INT=0
AS           
BEGIN           

IF @IsBulkStatement!='True'
BEGIN
	EXEC usp_ImportChargesInDataWareHouseTable_PatientWise @PatientId
END

          
DECLARE @Temp TABLE           
(           
  Id varchar(20) null,           
  Address1 nvarchar(100) null,           
  Address2 nvarchar(100) null,           
  BillAddress1 nvarchar(100) null,           
  BillAddress2 nvarchar(100) null,           
  BillCity nvarchar(100) null,           
  BillState nvarchar(100) null,           
  BillZip nvarchar(100) null,           
  City nvarchar(100) null,           
  FirstName nvarchar(100) null,           
  LastName nvarchar(100) null,           
  State nvarchar(100) null,           
  ZipCode nvarchar(100) null,           
  FacilityAddress1 nvarchar(100) null,           
  FacilityAddress2 nvarchar(100) null,           
  FacilityCity nvarchar(100) null,           
  ContactName nvarchar(100) null,           
  FacilityDescription nvarchar(100) null,           
  Name nvarchar(100) null,           
  Phone nvarchar(100) null,           
  FacilityState nvarchar(100) null,           
  FacilityZipCode nvarchar(100) null,           
  PatientId int null,           
  CreatedDate nvarchar(100) null,           
  DOS nvarchar(100) null,           
  Description nvarchar(100) null,           
  CPTCode nvarchar(100) null,           
  Amount decimal(18,2) null,           
  PaidAmount decimal(18,2) null,           
  TotalAdjustment decimal(18,2) null,           
  DueAmount decimal(18,2) null,           
  DueByFlagCD nvarchar(100) null,
  GFirstName nvarchar(100) null,           
  GLastName nvarchar(100) null,
  PatientPayment Decimal (18,2) NULL,
  UnAppliedPayment MONEY NULL
 );           
    
  IF @IsAllCharges=0
  BEGIN
	      INSERT INTO @Temp           
		  SELECT ISNULL(A.BillingID,A.Id) [Id], PT.Address1, PT.Address2, PT.BillAddress1, PT.BillAddress2, PT.BillCity, PT.BillState, PT.BillZip, PT.City,PT.FirstName,PT.LastName,
			PT.State, PT.ZipCode,           
		   '' [FacilityAddress1], '' [FacilityAddress2], '' [FacilityCity], '', '', ''
		   , '', '' [FacilityState], '' [FacilityZipCode],  
		   PT.Id [PatientId], A.CreatedDate, A.DosDate [DOS], A.Description, A.CPTCode, 
			CASE WHEN A.InsuranceCompanyName ='SelfP' THEN    
				CASE WHEN A.CPTCode IN ('H2017','H2019') THEN  
				   CASE WHEN ISNULL(CPS.ProfessionalAbbreviation,'') IN ('RN','LPN') THEN 0 ELSE A.ChargeAmount END		
				WHEN A.CPTCode IN ('T1002','T1003','90785') THEN  0 ELSE A.ChargeAmount END
				ELSE A.ChargeAmount END [Amount]     
		   ,CASE WHEN ISNULL(A.PatientPayment,0)>0 THEN (A.Payment -A.PatientPayment) else A.Payment END [PaidAmount], 
		   A.Adjustment [TotalAdjustment], A.DueAmount, A.DueBy [DueByFlagCD],
		   CASE WHEN ISNULL(IG.GuarantorRel,'Self')='Self' THEN PT.FirstName ELSE IG.FirstName END[GFirstName],
		   CASE WHEN ISNULL(IG.GuarantorRel,'Self')='Self' THEN PT.LastName ELSE IG.LastName END[GLastName],ISNULL(A.PatientPayment,0)  ,0 [UnAppliedPayment]
		   FROM ChargesReportData(NOLOCK) A
		   inner join Patient (NOLOCK)PT           ON PT.DefaultCaseId=A.PatientCaseId          
		   INNER JOIN Provider (NOLOCK) CPR ON CPR.Id=A.PerforingProviderId
		   LEFT JOIN ConfigPractitionerService CPS ON CPS.Id=CPR.PractitionerServiceId
		   LEFT JOIN InsuranceGuarantor IG ON IG.PatientID=PT.Id
		   WHERE A.Deleted!='Yes'
		   AND PT.Id IN (select Value from dbo.tfn_Split(@PatientId,','))   
		   AND (CAST(A.DosDate AS DATE) >= CAST(@FromDate AS DATE)  OR @FromDate IS NULL)   
		   AND (CAST(A.DosDate AS DATE) <= CAST(@ToDate AS DATE)  OR @ToDate IS NULL)   
		   AND A.DueAmount > 0    -- commented on 03 Nov 2020
		   AND (A.DueBy in ('','patient')  ) and ISNULL(ChargePrimaryCompanyType,'')!='Medicaid' AND ISNULL(ChargeSecondaryCompanyType,'')!='Medicaid' AND ISNULL(ChargeTertiaryCompanyType,'')!='Medicaid'
  END
  ELSE
  BEGIN
	INSERT INTO @Temp           
		  SELECT ISNULL(A.BillingID,A.Id) [Id], PT.Address1, PT.Address2, PT.BillAddress1, PT.BillAddress2, PT.BillCity, PT.BillState, PT.BillZip, PT.City,PT.FirstName,PT.LastName,
			PT.State, PT.ZipCode,           
		   '' [FacilityAddress1], '' [FacilityAddress2], '' [FacilityCity], '', '', ''
		   , '', '' [FacilityState], '' [FacilityZipCode],  
		   PT.Id [PatientId], A.CreatedDate, A.DosDate [DOS], A.Description, A.CPTCode, 
			CASE WHEN A.InsuranceCompanyName ='SelfP' THEN    
				CASE WHEN A.CPTCode IN ('H2017','H2019') THEN  
				   CASE WHEN ISNULL(CPS.ProfessionalAbbreviation,'') IN ('RN','LPN') THEN 0 ELSE A.ChargeAmount END		
				WHEN A.CPTCode IN ('T1002','T1003','90785') THEN  0 ELSE A.ChargeAmount END
				ELSE A.ChargeAmount END [Amount]     
		   ,CASE WHEN ISNULL(A.PatientPayment,0)>0 THEN (A.Payment -A.PatientPayment) else A.Payment END [PaidAmount], 
		   A.Adjustment [TotalAdjustment], 		   
		   CASE WHEN A.DueBy in ('','patient') THEN A.DueAmount ELSE 0 END [DueAmount],
		   A.DueBy [DueByFlagCD],
		   CASE WHEN ISNULL(IG.GuarantorRel,'Self')='Self' THEN PT.FirstName ELSE IG.FirstName END[GFirstName],
		   CASE WHEN ISNULL(IG.GuarantorRel,'Self')='Self' THEN PT.LastName ELSE IG.LastName END[GLastName],ISNULL(A.PatientPayment,0)  ,0 [UnAppliedPayment]
		   FROM ChargesReportData (NOLOCK)A
		   inner join Patient (NOLOCK)PT           ON PT.DefaultCaseId=A.PatientCaseId          
		   INNER JOIN Provider (NOLOCK) CPR ON CPR.Id=A.PerforingProviderId
		   LEFT JOIN ConfigPractitionerService CPS ON CPS.Id=CPR.PractitionerServiceId
		   LEFT JOIN InsuranceGuarantor IG ON IG.PatientID=PT.Id
		   WHERE  A.DueAmount >= 0 AND A.Deleted!='Yes'
		   AND PT.Id IN (select Value from dbo.tfn_Split(@PatientId,','))   
		   AND (CAST(A.DosDate AS DATE) >= CAST(@FromDate AS DATE)  OR @FromDate IS NULL)   
		   AND (CAST(A.DosDate AS DATE) <= CAST(@ToDate AS DATE)  OR @ToDate IS NULL)   
  END
  

   

  DECLARE @RemitAddress1 NVARCHAR(100)          
  DECLARE @RemitAddress2 NVARCHAR(100)          
  DECLARE @RemitCity NVARCHAR(100)          
  DECLARE @RemitState NVARCHAR(100)     
  DECLARE @RemitZipCode NVARCHAR(100)          
  DECLARE @RemitPhone NVARCHAR(100)


  DECLARE @SettingTable TABLE
  (
	SettingValue VARCHAR(200),
	SettingCD VARCHAR(200)
  )

  INSERT INTO @SettingTable
  SELECT SettingValue,B.SettingCD FROM AppSetting A          
  INNER JOIN ConfigSetting B ON A.SettingCD=B.SettingCD          
  INNER JOIN ConfigSettingGroup C ON C.SettingGroupCD=B.SettingGroupCD          
  WHERE C.SettingGroupCD='PatientStatementConfiguration' 

          
  SELECT @RemitAddress1=SettingValue FROM @SettingTable WHERE SettingCD='Address1'          
          
  SELECT @RemitAddress2=SettingValue FROM @SettingTable WHERE  SettingCD='Address2'          
          
  SELECT @RemitCity=SettingValue FROM @SettingTable WHERE  SettingCD='City'          
          
  SELECT @RemitState=SettingValue FROM @SettingTable WHERE  SettingCD='State'          
          
  SELECT @RemitPhone=SettingValue FROM @SettingTable WHERE  SettingCD='Phone'          
          
  SELECT @RemitZipCode=SettingValue  FROM @SettingTable WHERE  SettingCD='ZipCode'          



  DECLARE @PatId INT
	SELECT  @PatId=MIN(PatientId) FROM @Temp 

	WHILE @PatId IS NOT NULL
	BEGIN
		Declare @UnappliedApyment MONEY
		SELECT @UnappliedApyment=SUM(Amount) from PortalPayment (NOLOCK) WHERE PatientId=@PatId AND ISNULL(IsCommitted,0)=0 AND IsDeleted!=1

		DECLARE @UnappliedAmountPosted MONEY
		SELECT @UnappliedAmountPosted=SUM(C.PaidAmount) from PortalPayment A(NOLOCK) 
		INNER JOIN PortalPaymentChild B ON A.Id=B.PortalPaymentId
		INNER JOIN PaymentCharge C on C.PaymentId=B.PaymentId
			WHERE PatientId=@PatId AND ISNULL(IsCommitted,0)=0 AND IsDeleted!=1

		SET @UnappliedApyment=@UnappliedApyment-ISNULL(@UnappliedAmountPosted,0)

		


		Declare @BillingId VARCHAR(20)
		SELECT @BillingId=ISNULL(BillingID,Id) from Patient(NOLOCK) WHERE Id=@PatId		
	
		DECLARE @UnMatchedPayment MONEY
		SELECT @UnMatchedPayment=SUM(CAST(Amount AS MONEY)) FROM DynmoPayments(NOLOCK) WHERE AccountNumber=@BillingId AND PaymentType!=2 AND ISNULL(PortalPaymentId,0)=0

		DECLARE @UnMatchedPaymentCreditCard MONEY
		SELECT @UnMatchedPaymentCreditCard=SUM(CAST(Amount AS MONEY)) FROM DynmoPayments(NOLOCK) WHERE AccountNumber=@BillingId AND PaymentType=2 
		AND ISNULL(PortalPaymentId,0)=0 AND PaymentConfirmationCode is not null and TransactionId is not null

		IF ISNULL(@UnappliedApyment,0)>0
		BEGIN
			IF ISNULL(@UnMatchedPayment,0)>0
			BEGIN
				SET @UnappliedApyment=@UnappliedApyment+@UnMatchedPayment;
			END
			IF ISNULL(@UnMatchedPaymentCreditCard,0)>0
			BEGIN
				SET @UnappliedApyment=@UnappliedApyment+@UnMatchedPaymentCreditCard;
			END
		END
		ELSE IF ISNULL(@UnMatchedPayment,0)>0
		BEGIN
			SET @UnappliedApyment=@UnMatchedPayment;
			IF ISNULL(@UnMatchedPaymentCreditCard,0)>0
			BEGIN
				SET @UnappliedApyment=@UnappliedApyment+@UnMatchedPaymentCreditCard;
			END
		END
		ELSE IF ISNULL(@UnMatchedPaymentCreditCard,0)>0
		BEGIN
				SET @UnappliedApyment=@UnMatchedPaymentCreditCard;
		END

		UPDATE @Temp SET UnAppliedPayment=@UnappliedApyment WHERE PatientId=@PatId

		SELECT  @PatId=MIN(PatientId) FROM @Temp  WHERE PatientId>@PatId
	END

	DECLARE @OnlinePaymentBarCodeImage VARCHAR(100)
	DECLARE @OnlinePaymentURL VARCHAR(100)

	SELECT @OnlinePaymentBarCodeImage=OnlinePaymentBarCodeImage,@OnlinePaymentURL=OnlinePaymentURL FROM Practice


   SELECT Id,Address1,Address2,BillAddress1,BillAddress2,BillCity,BillState,BillZip,City,FirstName,LastName,State,ZipCode,FacilityAddress1,
FacilityAddress2,FacilityCity,ContactName,FacilityDescription,Name,Phone,FacilityState,FacilityZipCode,PatientId,CreatedDate,
DOS,Description,CPTCode,Amount,
CASE WHEN Amount=0 THEN 0 ELSE   PaidAmount END [PaidAmount],
CASE WHEN Amount=0 THEN 0 ELSE   TotalAdjustment END [TotalAdjustment],
CASE WHEN Amount=0 THEN 0 ELSE   DueAmount END [DueAmount],
DueByFlagCD,GFirstName,GLastName,PatientPayment
   ,@RemitAddress1[RemitAddress1],@RemitAddress2[RemitAddress2],@RemitCity[RemitCity],@RemitPhone[RemitPhone],          
   @RemitState[RemitState],@RemitZipCode[RemitZipCode],@Message[Message],@UnappliedApyment[UnAppliedPayment],
   @OnlinePaymentBarCodeImage[OnlinePaymentBarCodeImage],@OnlinePaymentURL[OnlinePaymentURL]
   FROM @Temp   
   WHERE Amount>0
   Group By Id ,           
   Address1 ,           
   Address2 ,           
   BillAddress1 ,           
   BillAddress2 ,           
   BillCity ,           
   BillState ,           
   BillZip ,           
   City ,           
   FirstName ,           
LastName ,           
   State ,           
   ZipCode ,           
   FacilityAddress1 ,           
   FacilityAddress2 ,           
   FacilityCity ,           
   ContactName ,           
   FacilityDescription ,           
   Name ,           
   Phone ,           
   FacilityState ,           
   FacilityZipCode ,           
   PatientId , 
   CreatedDate ,  
 DOS,
 Description ,           
   CPTCode ,           
   Amount,           
    PaidAmount,           
   TotalAdjustment ,           
   DueAmount ,           
   DueByFlagCD,GFirstName ,           
   GLastName,PatientPayment ORDER BY CAST(DOS AS DATE) DESC;  
   --[CompanyId],           
   --CompanyName;           
   END   
GO

CREATE PROCEDURE [dbo].[rpt_PatientChargeStatement_05162024]
@PatientId nvarchar(50),          
@ToDate DATETIME = NULL,  
@Message NVARCHAR(500)=''            
AS           
BEGIN           
          
DECLARE @Temp TABLE           
(           
  Id varchar(20) null,           
  Address1 nvarchar(100) null,           
  Address2 nvarchar(100) null,           
  BillAddress1 nvarchar(100) null,           
  BillAddress2 nvarchar(100) null,           
  BillCity nvarchar(100) null,           
  BillState nvarchar(100) null,           
  BillZip nvarchar(100) null,           
  City nvarchar(100) null,           
  FirstName nvarchar(100) null,           
  LastName nvarchar(100) null,           
  State nvarchar(100) null,           
  ZipCode nvarchar(100) null,           
  FacilityAddress1 nvarchar(100) null,           
  FacilityAddress2 nvarchar(100) null,           
  FacilityCity nvarchar(100) null,           
  ContactName nvarchar(100) null,           
  FacilityDescription nvarchar(100) null,           
  Name nvarchar(100) null,           
  Phone nvarchar(100) null,           
  FacilityState nvarchar(100) null,           
  FacilityZipCode nvarchar(100) null,           
  PatientId int null,           
  CreatedDate nvarchar(100) null,           
  DOS nvarchar(100) null,           
  Description nvarchar(100) null,           
  CPTCode nvarchar(100) null,           
  Amount decimal(18,2) null,           
  PaidAmount decimal(18,2) null,           
  TotalAdjustment decimal(18,2) null,           
  DueAmount decimal(18,2) null,           
  DueByFlagCD nvarchar(100) null,
  GFirstName nvarchar(100) null,           
  GLastName nvarchar(100) null
  
  --[CompanyId] int ,          
  --CompanyName nvarchar(100) null          
 );           
  
 ;WITH Payments AS           
 (           
   SELECT ISNULL(PT.BillingID,PT.Id) [Id], PT.Address1, PT.Address2, PT.BillAddress1, PT.BillAddress2, PT.BillCity, PT.BillState, PT.BillZip, PT.City,PT.FirstName,PT.LastName,
    PT.State, PT.ZipCode,           
   FCT.Address1 [FacilityAddress1], FCT.Address2 [FacilityAddress2], FCT.City [FacilityCity], FCT.ContactName, FCT.FacilityDescription, FCT.Name          
   , FCT.Phone, FCT.State [FacilityState], FCT.ZipCode [FacilityZipCode],  
   PT.Id [PatientId], PV.CreatedDate, PV.DOS, PV.Description, PV.CPTCode, 
    CASE WHEN dbo.ufn_ActiveInsuranceForCaseNo_InsuranceCompanyCode(PV.DOS,1,PV.PatientCaseId) ='SelfP' THEN    
		CASE WHEN PV.CPTCode IN ('H2017','H2019') THEN  
		   CASE WHEN ISNULL(CPS.ProfessionalAbbreviation,'') IN ('RN','LPN') THEN 0 ELSE PV.Amount END		
		WHEN PV.CPTCode IN ('T1002','T1003','90785') THEN  0 ELSE PV.Amount END
		ELSE PV.Amount END [Amount]   
  -- CASE WHEN dbo.ufn_ActiveInsuranceForCaseNo_InsuranceCompanyCode(PV.DOS,1,PV.PatientCaseId) ='SelfP' THEN 
  -- CASE WHEN ISNULL(CPS.ProfessionalAbbreviation,'') IN ('RN','LPN') THEN 
		--CASE WHEN PV.CPTCode IN ('H2017','H2019') THEN 0 ELSe PV.Amount END
		--ELSE PV.Amount END
  -- ELSE PV.Amount END [Amount]   
   , (PV.TotalPaidAmount) [PaidAmount], PV.TotalAdjustment, PV.DueAmount, PV.DueByFlagCD,
   CASE WHEN ISNULL(IG.GuarantorRel,'Self')='Self' THEN PT.FirstName ELSE IG.FirstName END[GFirstName],
   CASE WHEN ISNULL(IG.GuarantorRel,'Self')='Self' THEN PT.LastName ELSE IG.LastName END[GLastName]   
   --,IC.Id [CompanyId], IC.CompanyName           
   FROM Patient (NOLOCK)PT           
   INNER JOIN Provider (NOLOCK) PR ON PT.ProviderId=PR.Id           
   INNER JOIN Facility (NOLOCK) FCT ON PR.FacilityId = FCT.Id           
   INNER JOIN PatientCase (NOLOCK)PC ON PC.PatientId = PT.Id           
   LEFT JOIN vw_GetChargeForPendingPaymentForStatement (NOLOCK) PV ON PV.PatientCaseId = PC.Id           
   --LEFT JOIN InsurancePolicy (NOLOCK) IP ON (PV.PatientCaseId = IP.PatientCaseId  
   --)  
   --LEFT JOIN InsuranceCompany (NOLOCK) IC ON IC.Id = IP.InsuranceCompanyId           
   LEFT JOIN Charge (NOLOCK) BLC ON BLC.Id=PV.Id           
   INNER JOIN Provider (NOLOCK) CPR ON CPR.Id=BLC.PerformingProviderId
   LEFT JOIN ConfigPractitionerService CPS ON CPS.Id=CPR.PractitionerServiceId
   LEFT JOIN InsuranceGuarantor IG ON IG.PatientID=PT.Id
   LEFT JOIN PaymentCharge(NOLOCK) pyc on BLC.Id = pyc.ChargeId           
   LEFT JOIN Payment(NOLOCK) p on p.Id = pyc.PaymentId           
   LEFT JOIN Voucher(NOLOCK) v on v.Id = p.VoucherId and v.IsCommitted = 1           
   LEFT JOIN PaymentAdjustment(NOLOCK) pa on pa.PaymentChargeId = pc.Id AND pa.IsDenial = 0 AND pa.IsAccounted = 1           
   WHERE BLC.IsDeleted <> 1   
   AND PT.Id IN (@PatientId)   
   --AND ((CAST(BLC.BillFromDate AS DATE) >= CAST(@FromDate AS DATE) OR @FromDate IS NULL) 
   AND (CAST(BLC.BillFromDate AS DATE) <= CAST(@ToDate AS DATE)  
   OR @ToDate IS NULL)   
   AND PV.DueAmount > 0    -- commented on 03 Nov 2020
   AND (PV.DueByFlagCD = '' OR LOWER(PV.DueByFlagCD) = 'patient')  
 ),  
   
 Amounts AS           
 (  
   select Id ,           
   Address1 ,           
   Address2 ,           
   BillAddress1 ,   
   BillAddress2 ,        
   BillCity ,           
   BillState ,           
   BillZip ,           
   City ,           
   FirstName ,           
   LastName ,           
   State ,           
   ZipCode ,           
   FacilityAddress1 ,   
   FacilityAddress2 ,           
   FacilityCity ,           
   ContactName ,           
   FacilityDescription ,           
   Name ,           
   Phone ,           
   FacilityState ,           
   FacilityZipCode ,           
   PatientId ,           
   CreatedDate ,   
   DOS,
   Description ,           
   CPTCode ,           
   Amount,           
   PaidAmount,           
   TotalAdjustment ,           
   Amount [DueAmount],       
   DueByFlagCD,GFirstName ,           
   GLastName
    from Payments  
   --[CompanyId],           
   --CompanyName from Payments           
 )           
  
  INSERT INTO @Temp           
  SELECT * FROM Payments;          
          
  DECLARE @RemitAddress1 NVARCHAR(100)          
  DECLARE @RemitAddress2 NVARCHAR(100)          
  DECLARE @RemitCity NVARCHAR(100)          
  DECLARE @RemitState NVARCHAR(100)          
  DECLARE @RemitZipCode NVARCHAR(100)          
  DECLARE @RemitPhone NVARCHAR(100)          
          
  SELECT @RemitAddress1=SettingValue FROM AppSetting A          
  INNER JOIN ConfigSetting B ON A.SettingCD=B.SettingCD          
  INNER JOIN ConfigSettingGroup C ON C.SettingGroupCD=B.SettingGroupCD          
  WHERE C.SettingGroupCD='PatientStatementConfiguration' AND B.SettingCD='Address1'          
          
  SELECT @RemitAddress2=SettingValue FROM AppSetting A          
  INNER JOIN ConfigSetting B ON A.SettingCD=B.SettingCD          
  INNER JOIN ConfigSettingGroup C ON C.SettingGroupCD=B.SettingGroupCD          
  WHERE C.SettingGroupCD='PatientStatementConfiguration' AND B.SettingCD='Address2'          
          
  SELECT @RemitCity=SettingValue FROM AppSetting A          
  INNER JOIN ConfigSetting B ON A.SettingCD=B.SettingCD          
  INNER JOIN ConfigSettingGroup C ON C.SettingGroupCD=B.SettingGroupCD          
  WHERE C.SettingGroupCD='PatientStatementConfiguration' AND B.SettingCD='City'          
          
  SELECT @RemitState=SettingValue FROM AppSetting A          
  INNER JOIN ConfigSetting B ON A.SettingCD=B.SettingCD          
  INNER JOIN ConfigSettingGroup C ON C.SettingGroupCD=B.SettingGroupCD          
  WHERE C.SettingGroupCD='PatientStatementConfiguration' AND B.SettingCD='State'          
          
  SELECT @RemitPhone=SettingValue FROM AppSetting A          
  INNER JOIN ConfigSetting B ON A.SettingCD=B.SettingCD          
  INNER JOIN ConfigSettingGroup C ON C.SettingGroupCD=B.SettingGroupCD          
  WHERE C.SettingGroupCD='PatientStatementConfiguration' AND B.SettingCD='Phone'          
          
  SELECT @RemitZipCode=SettingValue FROM AppSetting A          
  INNER JOIN ConfigSetting B ON A.SettingCD=B.SettingCD          
  INNER JOIN ConfigSettingGroup C ON C.SettingGroupCD=B.SettingGroupCD          
  WHERE C.SettingGroupCD='PatientStatementConfiguration' AND B.SettingCD='ZipCode'          
          
   SELECT Id,Address1,Address2,BillAddress1,BillAddress2,BillCity,BillState,BillZip,City,FirstName,LastName,State,ZipCode,FacilityAddress1,
FacilityAddress2,FacilityCity,ContactName,FacilityDescription,Name,Phone,FacilityState,FacilityZipCode,PatientId,CreatedDate,
DOS,Description,CPTCode,Amount,
CASE WHEN Amount=0 THEN 0 ELSE   PaidAmount END [PaidAmount],
CASE WHEN Amount=0 THEN 0 ELSE   TotalAdjustment END [TotalAdjustment],
CASE WHEN Amount=0 THEN 0 ELSE   DueAmount END [DueAmount],
DueByFlagCD,GFirstName,GLastName
   ,@RemitAddress1[RemitAddress1],@RemitAddress2[RemitAddress2],@RemitCity[RemitCity],@RemitPhone[RemitPhone],          
   @RemitState[RemitState],@RemitZipCode[RemitZipCode],@Message[Message]
   FROM @Temp   
   WHERE Amount>0
   Group By Id ,           
   Address1 ,           
   Address2 ,           
   BillAddress1 ,           
   BillAddress2 ,           
   BillCity ,           
   BillState ,           
   BillZip ,           
   City ,           
   FirstName ,           
LastName ,           
   State ,           
   ZipCode ,           
   FacilityAddress1 ,           
   FacilityAddress2 ,           
   FacilityCity ,           
   ContactName ,           
   FacilityDescription ,           
   Name ,           
   Phone ,           
   FacilityState ,           
   FacilityZipCode ,           
   PatientId ,           
   CreatedDate ,  
   DOS,
 Description ,           
   CPTCode ,           
   Amount,           
   PaidAmount,           
   TotalAdjustment ,           
   DueAmount ,           
   DueByFlagCD,GFirstName ,           
   GLastName ORDER BY CAST(DOS AS DATE) DESC;  
   --[CompanyId],           
   --CompanyName;           
   END   

GO

--rpt_PatientChargeStatement '203','06/12/2020','null','False','0'
CREATE PROCEDURE [dbo].[rpt_PatientChargeStatement_Rohit]
@PatientId nvarchar(500), 
@FromDate DATETIME = NULL,  
@ToDate DATETIME = NULL,  
@Message NVARCHAR(500)='', 
@IsBulkStatement VARCHAR(10)='False',
@IsAllCharges INT=0
AS           
BEGIN           

IF @IsBulkStatement!='True'
BEGIN
	EXEC usp_ImportChargesInDataWareHouseTable_PatientWise @PatientId
END

          
DECLARE @Temp TABLE           
(           
  Id varchar(20) null,           
  Address1 nvarchar(100) null,           
  Address2 nvarchar(100) null,           
  BillAddress1 nvarchar(100) null,           
  BillAddress2 nvarchar(100) null,           
  BillCity nvarchar(100) null,           
  BillState nvarchar(100) null,           
  BillZip nvarchar(100) null,           
  City nvarchar(100) null,           
  FirstName nvarchar(100) null,           
  LastName nvarchar(100) null,           
  State nvarchar(100) null,           
  ZipCode nvarchar(100) null,           
  FacilityAddress1 nvarchar(100) null,           
  FacilityAddress2 nvarchar(100) null,           
  FacilityCity nvarchar(100) null,           
  ContactName nvarchar(100) null,           
  FacilityDescription nvarchar(100) null,           
  Name nvarchar(100) null,           
  Phone nvarchar(100) null,           
  FacilityState nvarchar(100) null,           
  FacilityZipCode nvarchar(100) null,           
  PatientId int null,           
  CreatedDate nvarchar(100) null,           
  DOS nvarchar(100) null,           
  Description nvarchar(100) null,           
  CPTCode nvarchar(100) null,           
  Amount decimal(18,2) null,           
  PaidAmount decimal(18,2) null,           
  TotalAdjustment decimal(18,2) null,           
  DueAmount decimal(18,2) null,           
  DueByFlagCD nvarchar(100) null,
  GFirstName nvarchar(100) null,           
  GLastName nvarchar(100) null,
  PatientPayment Decimal (18,2) NULL,
  UnAppliedPayment MONEY NULL
 );           
    
  IF @IsAllCharges=0
  BEGIN
	      INSERT INTO @Temp           
		  SELECT ISNULL(A.BillingID,A.Id) [Id], PT.Address1, PT.Address2, PT.BillAddress1, PT.BillAddress2, PT.BillCity, PT.BillState, PT.BillZip, PT.City,PT.FirstName,PT.LastName,
			PT.State, PT.ZipCode,           
		   '' [FacilityAddress1], '' [FacilityAddress2], '' [FacilityCity], '', '', ''
		   , '', '' [FacilityState], '' [FacilityZipCode],  
		   PT.Id [PatientId], A.CreatedDate, A.DosDate [DOS], A.Description, A.CPTCode, 
			CASE WHEN A.InsuranceCompanyName ='SelfP' THEN    
				CASE WHEN A.CPTCode IN ('H2017','H2019') THEN  
				   CASE WHEN ISNULL(CPS.ProfessionalAbbreviation,'') IN ('RN','LPN') THEN 0 ELSE A.ChargeAmount END		
				WHEN A.CPTCode IN ('T1002','T1003','90785') THEN  0 ELSE A.ChargeAmount END
				ELSE A.ChargeAmount END [Amount]     
		   ,CASE WHEN ISNULL(A.PatientPayment,0)>0 THEN (A.Payment -A.PatientPayment) else A.Payment END [PaidAmount], 
		   A.Adjustment [TotalAdjustment], A.DueAmount, A.DueBy [DueByFlagCD],
		   CASE WHEN ISNULL(IG.GuarantorRel,'Self')='Self' THEN PT.FirstName ELSE IG.FirstName END[GFirstName],
		   CASE WHEN ISNULL(IG.GuarantorRel,'Self')='Self' THEN PT.LastName ELSE IG.LastName END[GLastName],ISNULL(A.PatientPayment,0)  ,0 [UnAppliedPayment]
		   FROM ChargesReportData(NOLOCK) A
		   inner join Patient (NOLOCK)PT           ON PT.DefaultCaseId=A.PatientCaseId          
		   INNER JOIN Provider (NOLOCK) CPR ON CPR.Id=A.PerforingProviderId
		   LEFT JOIN ConfigPractitionerService CPS ON CPS.Id=CPR.PractitionerServiceId
		   LEFT JOIN InsuranceGuarantor IG ON IG.PatientID=PT.Id
		   WHERE A.Deleted!='Yes'
		   AND PT.Id IN (select Value from dbo.tfn_Split(@PatientId,','))   
		   AND (CAST(A.DosDate AS DATE) >= CAST(@FromDate AS DATE)  OR @FromDate IS NULL)   
		   AND (CAST(A.DosDate AS DATE) <= CAST(@ToDate AS DATE)  OR @ToDate IS NULL)   
		   AND A.DueAmount > 0    -- commented on 03 Nov 2020
		   AND (A.DueBy in ('','patient')  ) and ISNULL(ChargePrimaryCompanyType,'')!='Medicaid' AND ISNULL(ChargeSecondaryCompanyType,'')!='Medicaid' AND ISNULL(ChargeTertiaryCompanyType,'')!='Medicaid'
  END
  ELSE
  BEGIN
	INSERT INTO @Temp           
		  SELECT ISNULL(A.BillingID,A.Id) [Id], PT.Address1, PT.Address2, PT.BillAddress1, PT.BillAddress2, PT.BillCity, PT.BillState, PT.BillZip, PT.City,PT.FirstName,PT.LastName,
			PT.State, PT.ZipCode,           
		   '' [FacilityAddress1], '' [FacilityAddress2], '' [FacilityCity], '', '', ''
		   , '', '' [FacilityState], '' [FacilityZipCode],  
		   PT.Id [PatientId], A.CreatedDate, A.DosDate [DOS], A.Description, A.CPTCode, 
			CASE WHEN A.InsuranceCompanyName ='SelfP' THEN    
				CASE WHEN A.CPTCode IN ('H2017','H2019') THEN  
				   CASE WHEN ISNULL(CPS.ProfessionalAbbreviation,'') IN ('RN','LPN') THEN 0 ELSE A.ChargeAmount END		
				WHEN A.CPTCode IN ('T1002','T1003','90785') THEN  0 ELSE A.ChargeAmount END
				ELSE A.ChargeAmount END [Amount]     
		   ,CASE WHEN ISNULL(A.PatientPayment,0)>0 THEN (A.Payment -A.PatientPayment) else A.Payment END [PaidAmount], 
		   A.Adjustment [TotalAdjustment], 		   
		   CASE WHEN A.DueBy in ('','patient') THEN A.DueAmount ELSE 0 END [DueAmount],
		   A.DueBy [DueByFlagCD],
		   CASE WHEN ISNULL(IG.GuarantorRel,'Self')='Self' THEN PT.FirstName ELSE IG.FirstName END[GFirstName],
		   CASE WHEN ISNULL(IG.GuarantorRel,'Self')='Self' THEN PT.LastName ELSE IG.LastName END[GLastName],ISNULL(A.PatientPayment,0)  ,0 [UnAppliedPayment]
		   FROM ChargesReportData (NOLOCK)A
		   inner join Patient (NOLOCK)PT           ON PT.DefaultCaseId=A.PatientCaseId          
		   INNER JOIN Provider (NOLOCK) CPR ON CPR.Id=A.PerforingProviderId
		   LEFT JOIN ConfigPractitionerService CPS ON CPS.Id=CPR.PractitionerServiceId
		   LEFT JOIN InsuranceGuarantor IG ON IG.PatientID=PT.Id
		   WHERE  A.DueAmount >= 0 AND A.Deleted!='Yes'
		   AND PT.Id IN (select Value from dbo.tfn_Split(@PatientId,','))   
		   AND (CAST(A.DosDate AS DATE) >= CAST(@FromDate AS DATE)  OR @FromDate IS NULL)   
		   AND (CAST(A.DosDate AS DATE) <= CAST(@ToDate AS DATE)  OR @ToDate IS NULL)   
  END
  

   

  DECLARE @RemitAddress1 NVARCHAR(100)          
  DECLARE @RemitAddress2 NVARCHAR(100)          
  DECLARE @RemitCity NVARCHAR(100)          
  DECLARE @RemitState NVARCHAR(100)     
  DECLARE @RemitZipCode NVARCHAR(100)          
  DECLARE @RemitPhone NVARCHAR(100)


  DECLARE @SettingTable TABLE
  (
	SettingValue VARCHAR(200),
	SettingCD VARCHAR(200)
  )

  INSERT INTO @SettingTable
  SELECT SettingValue,B.SettingCD FROM AppSetting A          
  INNER JOIN ConfigSetting B ON A.SettingCD=B.SettingCD          
  INNER JOIN ConfigSettingGroup C ON C.SettingGroupCD=B.SettingGroupCD          
  WHERE C.SettingGroupCD='PatientStatementConfiguration' 

          
  SELECT @RemitAddress1=SettingValue FROM @SettingTable WHERE SettingCD='Address1'          
          
  SELECT @RemitAddress2=SettingValue FROM @SettingTable WHERE  SettingCD='Address2'          
          
  SELECT @RemitCity=SettingValue FROM @SettingTable WHERE  SettingCD='City'          
          
  SELECT @RemitState=SettingValue FROM @SettingTable WHERE  SettingCD='State'          
          
  SELECT @RemitPhone=SettingValue FROM @SettingTable WHERE  SettingCD='Phone'          
          
  SELECT @RemitZipCode=SettingValue  FROM @SettingTable WHERE  SettingCD='ZipCode'          



  DECLARE @PatId INT
	SELECT  @PatId=MIN(PatientId) FROM @Temp 

	WHILE @PatId IS NOT NULL
	BEGIN
		Declare @UnappliedApyment MONEY
		SELECT @UnappliedApyment=SUM(Amount) from PortalPayment (NOLOCK) WHERE PatientId=@PatId AND ISNULL(IsCommitted,0)=0 AND IsDeleted!=1

		DECLARE @UnappliedAmountPosted MONEY
		SELECT @UnappliedAmountPosted=SUM(C.PaidAmount) from PortalPayment A(NOLOCK) 
		INNER JOIN PortalPaymentChild B ON A.Id=B.PortalPaymentId
		INNER JOIN PaymentCharge C on C.PaymentId=B.PaymentId
			WHERE PatientId=@PatId AND ISNULL(IsCommitted,0)=0 AND IsDeleted!=1

		SET @UnappliedApyment=@UnappliedApyment-ISNULL(@UnappliedAmountPosted,0)


		Declare @BillingId VARCHAR(20)
		SELECT @BillingId=ISNULL(BillingID,Id) from Patient(NOLOCK) WHERE Id=@PatId		
	
		DECLARE @UnMatchedPayment MONEY
		SELECT @UnMatchedPayment=SUM(CAST(Amount AS MONEY)) FROM DynmoPayments(NOLOCK) WHERE AccountNumber=@BillingId AND PaymentType!=2 AND ISNULL(PortalPaymentId,0)=0

		DECLARE @UnMatchedPaymentCreditCard MONEY
		SELECT @UnMatchedPaymentCreditCard=SUM(CAST(Amount AS MONEY)) FROM DynmoPayments(NOLOCK) WHERE AccountNumber=@BillingId AND PaymentType=2 
		AND ISNULL(PortalPaymentId,0)=0 AND PaymentConfirmationCode is not null and TransactionId is not null

		IF ISNULL(@UnappliedApyment,0)>0
		BEGIN
			IF ISNULL(@UnMatchedPayment,0)>0
			BEGIN
				SET @UnappliedApyment=@UnappliedApyment+@UnMatchedPayment;
			END
			IF ISNULL(@UnMatchedPaymentCreditCard,0)>0
			BEGIN
				SET @UnappliedApyment=@UnappliedApyment+@UnMatchedPaymentCreditCard;
			END
		END
		ELSE IF ISNULL(@UnMatchedPayment,0)>0
		BEGIN
			SET @UnappliedApyment=@UnMatchedPayment;
			IF ISNULL(@UnMatchedPaymentCreditCard,0)>0
			BEGIN
				SET @UnappliedApyment=@UnappliedApyment+@UnMatchedPaymentCreditCard;
			END
		END
		ELSE IF ISNULL(@UnMatchedPaymentCreditCard,0)>0
		BEGIN
				SET @UnappliedApyment=@UnMatchedPaymentCreditCard;
		END

		UPDATE @Temp SET UnAppliedPayment=@UnappliedApyment WHERE PatientId=@PatId

		SELECT  @PatId=MIN(PatientId) FROM @Temp  WHERE PatientId>@PatId
	END

	DECLARE @OnlinePaymentBarCodeImage VARCHAR(100)
	DECLARE @OnlinePaymentURL VARCHAR(100)

	SELECT @OnlinePaymentBarCodeImage=OnlinePaymentBarCodeImage,@OnlinePaymentURL=OnlinePaymentURL FROM Practice


   SELECT Id,Address1,Address2,BillAddress1,BillAddress2,BillCity,BillState,BillZip,City,FirstName,LastName,State,ZipCode,FacilityAddress1,
FacilityAddress2,FacilityCity,ContactName,FacilityDescription,Name,Phone,FacilityState,FacilityZipCode,PatientId,CreatedDate,
DOS,Description,CPTCode,Amount,
CASE WHEN Amount=0 THEN 0 ELSE   PaidAmount END [PaidAmount],
CASE WHEN Amount=0 THEN 0 ELSE   TotalAdjustment END [TotalAdjustment],
CASE WHEN Amount=0 THEN 0 ELSE   DueAmount END [DueAmount],
DueByFlagCD,GFirstName,GLastName,PatientPayment
   ,@RemitAddress1[RemitAddress1],@RemitAddress2[RemitAddress2],@RemitCity[RemitCity],@RemitPhone[RemitPhone],          
   @RemitState[RemitState],@RemitZipCode[RemitZipCode],@Message[Message],@UnappliedApyment[UnAppliedPayment],
   @OnlinePaymentBarCodeImage[OnlinePaymentBarCodeImage],@OnlinePaymentURL[OnlinePaymentURL]
   FROM @Temp   
   WHERE Amount>0
   Group By Id ,           
   Address1 ,           
   Address2 ,           
   BillAddress1 ,           
   BillAddress2 ,           
   BillCity ,           
   BillState ,           
   BillZip ,           
   City ,           
   FirstName ,           
LastName ,           
   State ,           
   ZipCode ,           
   FacilityAddress1 ,           
   FacilityAddress2 ,           
   FacilityCity ,           
   ContactName ,           
   FacilityDescription ,           
   Name ,           
   Phone ,           
   FacilityState ,           
   FacilityZipCode ,           
   PatientId , 
   CreatedDate ,  
 DOS,
 Description ,           
   CPTCode ,           
   Amount,           
    PaidAmount,           
   TotalAdjustment ,           
   DueAmount ,           
   DueByFlagCD,GFirstName ,           
   GLastName,PatientPayment ORDER BY CAST(DOS AS DATE) DESC;  
   --[CompanyId],           
   --CompanyName;           
   END   

GO

--rpt_PatientChargeStatementXML 5276
CREATE PROCEDURE [dbo].[rpt_PatientChargeStatementXML]
@PatientId nvarchar(MAX),          
@ToDate DATETIME = NULL,  
@Message NVARCHAR(500)=''  
          
AS           
BEGIN           

Set @Message = 'For any billing questions please dial 724-728-8411'

DECLARE @PayByWeb NVARCHAR(50)
SET @PayByWeb = ''

DECLARE @PayByPhoneNumber NVARCHAR(50)
SET @PayByPhoneNumber = ''


DECLARE @DunningMessage NVARCHAR(150)
SET @DunningMessage = 'Payment in full is due upon receipt. If you are unable to pay in full, please contact our office immediately.'

DECLARE @Note NVARCHAR(100)
SET @Note = ''
          
DECLARE @Temp TABLE           
(           
  Id int null,           
  Address1 nvarchar(100) null,           
  Address2 nvarchar(100) null,           
  BillAddress1 nvarchar(100) null,           
  BillAddress2 nvarchar(100) null,           
  BillCity nvarchar(100) null,           
  BillState nvarchar(100) null,           
  BillZip nvarchar(100) null,           
  City nvarchar(100) null,           
  FirstName nvarchar(100) null,             
  LastName nvarchar(100) null,           
  State nvarchar(100) null,           
  ZipCode nvarchar(100) null,           
  FacilityAddress1 nvarchar(100) null,           
  FacilityAddress2 nvarchar(100) null,           
  FacilityCity nvarchar(100) null,           
  ContactName nvarchar(100) null,           
  FacilityDescription nvarchar(100) null,           
  Name nvarchar(100) null,           
  Phone nvarchar(100) null,           
  FacilityState nvarchar(100) null,           
  FacilityZipCode nvarchar(100) null,           
  PatientId int null,           
  CreatedDate nvarchar(100) null,           
  DOS nvarchar(100) null,           
  Description nvarchar(100) null,           
  CPTCode nvarchar(100) null,           
  Amount decimal(18,2) null,           
  PaidAmount decimal(18,2) null,           
  TotalAdjustment decimal(18,2) null,           
  DueAmount decimal(18,2) null,           
  DueByFlagCD nvarchar(100) null,
  ChargeId INT NULL,
  GuarantorFirstName nvarchar(100) null,     
  GuarantorLastName nvarchar(100) null,     
  GuarantorAddress1 nvarchar(100) null,
  GuarantorAddress2 nvarchar(100) null,
  GuarantorCity nvarchar(100) null, 
  GuarantorState nvarchar(100) null,
  GuarantorZip nvarchar(100) null,
  MiddleName nvarchar(20) null ,
  ShiftDate DATE
  --[CompanyId] int ,          
  --CompanyName nvarchar(100) null          
 );           
  
 ;WITH Payments AS           
 (           
   SELECT PT.Id, PT.Address1, PT.Address2, PT.BillAddress1, PT.BillAddress2, PT.BillCity, PT.BillState, PT.BillZip, PT.City, PT.FirstName, PT.LastName, PT.State, PT.ZipCode,           
   FCT.Address1 [FacilityAddress1], FCT.Address2 [FacilityAddress2], FCT.City [FacilityCity], FCT.ContactName, FCT.FacilityDescription, FCT.Name          
   , FCT.Phone, FCT.State [FacilityState], FCT.ZipCode [FacilityZipCode],  
   PT.Id [PatientId], PV.CreatedDate, PV.DOS, PV.Description, PV.CPTCode, PV.Amount, (PV.PaidAmount) [PaidAmount], PV.TotalAdjustment, PV.DueAmount, PV.DueByFlagCD,
   PV.Id as ChargeId, IG.FirstName as GuarantorFirstName,IG.LastName as GuarantorLastName,IG.Address1 as GuarantorAddress1,IG.Address2 as GuarantorAddress2, IG.City as GuarantorCity, 
   IG.State as GuarantorState,IG.Zip as GuarantorZip, PT.MI as MiddleName,PV.ShiftDate
   --,IC.Id [CompanyId], IC.CompanyName           
   FROM Patient (NOLOCK)PT           
   INNER JOIN Provider (NOLOCK) PR ON PT.ProviderId=PR.Id           
   INNER JOIN Facility (NOLOCK) FCT ON PR.FacilityId = FCT.Id           
   INNER JOIN PatientCase (NOLOCK)PC ON PC.PatientId = PT.Id           
   LEFT JOIN vw_GetChargeForPendingPaymentForStatement (NOLOCK) PV ON PV.PatientCaseId = PC.Id           
   --LEFT JOIN InsurancePolicy (NOLOCK) IP ON (PV.PatientCaseId = IP.PatientCaseId  
   --)  
   --LEFT JOIN InsuranceCompany (NOLOCK) IC ON IC.Id = IP.InsuranceCompanyId           
LEFT JOIN Charge (NOLOCK) BLC ON BLC.Id=PV.Id           
   LEFT JOIN PaymentCharge(NOLOCK) pyc on BLC.Id = pyc.ChargeId           
   LEFT JOIN Payment(NOLOCK) p on p.Id = pyc.PaymentId           
   LEFT JOIN Voucher(NOLOCK) v on v.Id = p.VoucherId and v.IsCommitted = 1           
   LEFT JOIN PaymentAdjustment(NOLOCK) pa on pa.PaymentChargeId = pc.Id AND pa.IsDenial = 0 AND pa.IsAccounted = 1           
   LEFT JOIN InsuranceGuarantor(NOLOCK) IG ON IG.PatientID=PT.Id
   WHERE BLC.IsDeleted <> 1   
   AND ((PT.Id IN (SELECT [Value] FROM dbo.tfn_Split(@PatientId, ',') ) OR @PatientId IS NULL OR @PatientId =''))   
   --AND ((CAST(BLC.BillFromDate AS DATE) >= CAST(@FromDate AS DATE) OR @FromDate IS NULL)           
   AND (CAST(BLC.BillFromDate AS DATE) <= CAST(@ToDate AS DATE)  
   OR @ToDate IS NULL)   
   AND PV.DueAmount > 0    -- commented on 03 Nov 2020
   AND (PV.DueByFlagCD = '' OR LOWER(PV.DueByFlagCD) = 'patient')  
 ),  
   
 Amounts AS           
 (  
   select Id ,           
   Address1 ,           
   Address2 ,           
   BillAddress1 ,        
   BillAddress2 ,        
   BillCity ,           
   BillState ,           
   BillZip ,           
   City ,           
   FirstName ,           
   LastName ,           
   State ,           
   ZipCode ,           
   FacilityAddress1 ,   
   FacilityAddress2 ,           
   FacilityCity ,           
   ContactName ,           
   FacilityDescription ,           
   Name ,           
   Phone ,           
   FacilityState ,           
   FacilityZipCode ,           
   PatientId ,           
   CreatedDate ,   
   DOS,
   Description ,           
   CPTCode ,           
   Amount,           
   PaidAmount,           
   TotalAdjustment ,           
   Amount [DueAmount],       
   DueByFlagCD, ChargeId,
   GuarantorFirstName,    
   GuarantorLastName,
  GuarantorAddress1,
  GuarantorAddress2,
  GuarantorCity, 
  GuarantorState,
  GuarantorZip, MiddleName from Payments  
   --[CompanyId],           
   --CompanyName from Payments           
 )           
  
  INSERT INTO @Temp           
  SELECT * FROM Payments;          
          
  DECLARE @RemitAddress1 NVARCHAR(100)          
  DECLARE @RemitAddress2 NVARCHAR(100)          
  DECLARE @RemitCity NVARCHAR(100)          
  DECLARE @RemitState NVARCHAR(100)          
  DECLARE @RemitZipCode NVARCHAR(100)          
  DECLARE @RemitPhone NVARCHAR(100)          
          
  SELECT @RemitAddress1=SettingValue FROM AppSetting A          
  INNER JOIN ConfigSetting B ON A.SettingCD=B.SettingCD          
  INNER JOIN ConfigSettingGroup C ON C.SettingGroupCD=B.SettingGroupCD          
  WHERE C.SettingGroupCD='PatientStatementConfiguration' AND B.SettingCD='Address1'          
          
  SELECT @RemitAddress2=SettingValue FROM AppSetting A          
  INNER JOIN ConfigSetting B ON A.SettingCD=B.SettingCD          
  INNER JOIN ConfigSettingGroup C ON C.SettingGroupCD=B.SettingGroupCD          
  WHERE C.SettingGroupCD='PatientStatementConfiguration' AND B.SettingCD='Address2'          
          
  SELECT @RemitCity=SettingValue FROM AppSetting A          
  INNER JOIN ConfigSetting B ON A.SettingCD=B.SettingCD          
  INNER JOIN ConfigSettingGroup C ON C.SettingGroupCD=B.SettingGroupCD          
  WHERE C.SettingGroupCD='PatientStatementConfiguration' AND B.SettingCD='City'          
          
  SELECT @RemitState=SettingValue FROM AppSetting A          
  INNER JOIN ConfigSetting B ON A.SettingCD=B.SettingCD          
  INNER JOIN ConfigSettingGroup C ON C.SettingGroupCD=B.SettingGroupCD          
  WHERE C.SettingGroupCD='PatientStatementConfiguration' AND B.SettingCD='State'          
          
  SELECT @RemitPhone=SettingValue FROM AppSetting A    
  INNER JOIN ConfigSetting B ON A.SettingCD=B.SettingCD          
  INNER JOIN ConfigSettingGroup C ON C.SettingGroupCD=B.SettingGroupCD          
  WHERE C.SettingGroupCD='PatientStatementConfiguration' AND B.SettingCD='Phone'          
          
  SELECT @RemitZipCode=SettingValue FROM AppSetting A          
  INNER JOIN ConfigSetting B ON A.SettingCD=B.SettingCD          
  INNER JOIN ConfigSettingGroup C ON C.SettingGroupCD=B.SettingGroupCD          
  WHERE C.SettingGroupCD='PatientStatementConfiguration' AND B.SettingCD='ZipCode'          
          
   SELECT *,@RemitAddress1[RemitAddress1],@RemitAddress2[RemitAddress2],@RemitCity[RemitCity],@RemitPhone[RemitPhone],          
   @RemitState[RemitState],@RemitZipCode[RemitZipCode],@Message[Message], @PayByWeb [PayByWeb], @PayByPhoneNumber [PayByPhoneNumber], @DunningMessage [DunningMessage], 
   @Note [Note],ShiftDate
   FROM @Temp Group By Id ,           
   Address1 ,           
   Address2 ,           
   BillAddress1 ,           
   BillAddress2 ,           
   BillCity ,           
   BillState ,           
   BillZip ,           
   City ,           
   FirstName ,           
   LastName ,           
   State ,           
   ZipCode ,           
   FacilityAddress1 ,           
   FacilityAddress2 ,           
   FacilityCity ,           
   ContactName ,           
   FacilityDescription ,           
   Name ,           
   Phone ,           
   FacilityState ,           
   FacilityZipCode ,           
   PatientId ,           
   CreatedDate ,  
   DOS,
 Description ,           
   CPTCode ,           
   Amount,           
   PaidAmount,           
   TotalAdjustment ,           
   DueAmount ,           
   DueByFlagCD,
   ChargeId,
   GuarantorFirstName,     
   GuarantorLastName,
  GuarantorAddress1,
  GuarantorAddress2,
  GuarantorCity, 
  GuarantorState,
  GuarantorZip, MiddleName,ShiftDate;  
   --[CompanyId],           
   --CompanyName;           
   END 

GO


CREATE PROCEDURE [dbo].[rpt_PatientDOSCPAODetailReport] @FromDate DATETIME      = NULL,          
                                                @ToDate   DATETIME      = NULL,          
                                                @CPTCodes VARCHAR(MAX) = NULL          
AS          
         BEGIN          
             DECLARE @TempData AS TABLE          
(AcctNo       NUMERIC(18, 0),          
 PatientName  NVARCHAR(500),          
 ProviderName NVARCHAR(500),          
 CompanyId    NUMERIC(18, 0),          
 CompanyName  NVARCHAR(500),          
 DOS          DATE,          
 CPTCode      NVARCHAR(50),          
 Modifiers    NVARCHAR(50),          
 ChargeAmt    NUMERIC(18, 2),          
 PriDX        NVARCHAR(50),          
 POS          NVARCHAR(50),          
 ChargeNo     NUMERIC(18, 0),          
 Payments     NUMERIC(18, 2),          
 Adjustments  NUMERIC(18, 2),          
 PaymentBat   NVARCHAR(100),          
 PostDate     DATE,        
 ProviderId  int          
);          
             INSERT INTO @TempData          
(AcctNo,          
 PatientName,          
 ProviderName,          
 CompanyId,          
 CompanyName,          
 DOS,          
 CPTCode,          
 Modifiers,          
 ChargeAmt,          
 PriDX,          
 POS,          
 ChargeNo,          
 Payments,          
 Adjustments,          
 PaymentBat,          
 PostDate,        
 ProviderId           
) 
             EXEC usp_dos          
                  @FromDate,          
                  @ToDate;       
             
             SELECT t.AcctNo,          
                    t.PatientName,          
                    t.DOS,          
                    t.PostDate [PostingDate],          
                    t.CPTCode [CPT],          
                    t.ChargeAmt [Charge],          
                    t.Payments,          
                    t.Adjustments,          
                    t.ChargeAmt - (t.Payments + t.Adjustments) [Owed],          
                    t.PostDate [LastPayment],          
                    t.CompanyName [InsuranceName],          
                    STUFF(          
(          
    SELECT ','+Z3.BatchNo
    FROM Payment (NOLOCK) Z2    
	Left Join Voucher (NOLOCK) V On Z2.VoucherId = V.Id     
         LEFT JOIN PaymentBatch(NOLOCK) Z3 ON Z3.Id = V.PaymentBatchId 
    WHERE Z2.PatientId = t.acctno FOR XML PATH('')          
), 1, 1, '') [PaymentBatches],        
t.ProviderId,
t.ProviderName          
             FROM @TempData t          
             WHERE ((t.CPTCode IN (SELECT [Value] FROM dbo.tfn_Split(@CPTCodes, ',') ) OR @CPTCodes IS NULL OR @CPTCodes =''));         
         END;    
    
    
   --usp_PatientDOSCPAODetailReport '20180301','20180331','99213'



GO


CREATE PROCEDURE [dbo].[rpt_PaymentDeposits]              
@DepositID BIGINT=NULL,              
@FromDate datetime = null,              
@ToDate datetime = null,
@PracticeId INT = 0              
AS              
BEGIN              
 SELECT dp.Id [DepositID],            
  DepositTypeID,            
  convert(varchar(20),convert(date,dp.ModifiedDate))as ModifiedDate,            
  CAST(dp.Amount AS decimal(18,2))Amount,            
  dc.Description[DepositType],            
  ISNULL(bb.BatchNo,'') BatchNumber,              
  dp.Description,              
  dp.PaymentBatchId [BatchID],            
  dp.ModifiedBy,            
  dp.EffectiveDate,            
  dp.ReferenceNo  ,      
  InsuranceCompanyId [PayerId] ,  
  i.CompanyName,  
  CONCAT(p.LastName , ' ' ,p.FirstName) [PatientName],  
  a.[FileName]  ,    
   ISNULL( dc.IsSelfpayment , CAST(0 as BIT) )    IsSelfpayment ,
   dp.PracticeId 
   FROM Voucher dp              
   INNER JOIN DepositType dc on dc.Id=dp.DepositTypeID              
   LEFT JOIN ChargeBatch bb ON bb.Id=dp.PaymentBatchId    
   LEFT JOIN AttFile a ON a.TableIdValue = dp.Id     
   LEFT JOIN InsuranceCompany i ON i.Id = dp.InsuranceCompanyId  
   LEFT JOIN Patient p ON p.Id = dp.InsuranceCompanyId  
  
   WHERE (@DepositID IS NULL OR  dp.Id =@DepositID)              
   and              
  --  CAST(dp.EffectiveDate AS DATE) >= @FromDate and   CAST(dp.EffectiveDate AS DATE) <=@ToDate            
   (@FromDate is null) OR (CAST(dp.EffectiveDate AS DATE) IS NULL OR (CAST(dp.EffectiveDate AS DATE) between @FromDate and @ToDate))              
   AND dp.PracticeId = @PracticeId
   --AND ISNULL(IsCommitted,0)=1              
END 


GO

--rpt_PaymentDepositsReport '1 April 2022', '30 April 2022',NULL,0
CREATE PROCEDURE [dbo].[rpt_PaymentDepositsReport]@FromDate DATE = NULL,          @ToDate   DATE = NULL,@InsuranceCompanyId	INT=NULL,@IsExcel BIT=0AS          BEGIN           IF @IsExcel=1	BEGIN	 SELECT CASE WHEN ISNULL(InsuranceCompanyId,0)>0  THEN ins.CompanyName ELSE (pt.LastName+', '+Pt.FirstName)+' - Patient' END [CompanyName],	 dc.Description [DepositType],CONVERT(VARCHAR(10),dp.EffectiveDate, 101)[DepositDate],CAST(Amount AS DECIMAL(18, 2)) Deposit,	 CASE WHEN dp.IsMatchedWithBank is null then 'Not Synced yet' WHEN dp.IsMatchedWithBank=0 THEN 'No' WHEN dp.IsMatchedWithBank=1 THEN 'Yes' END [BankMatched]     FROM Voucher dp(NOLOCK)  
   LEFT JOIN DepositType dc(NOLOCK) ON dc.Id = dp.DepositTypeId        	 LEFT JOIN InsuranceCompany ins (NOLOCK) ON ins.Id = dp.InsuranceCompanyId    	 LEFT JOIN Patient pt (NOLOCK) ON pt.Id = dp.PatientId     WHERE  ((CAST(ISNULL(dp.EffectiveDate,dp.CreatedDate) AS DATE) >= CAST(@FromDate AS DATE)OR @FromDate IS NULL)          		 AND (CAST(ISNULL(dp.EffectiveDate,dp.CreatedDate) AS DATE) <= CAST(@ToDate AS DATE)          		 OR @ToDate IS NULL)) AND ISNULL	(dp.IsCommitted,0)=1 AND dp.PaymentSourceCD not in  ('BulkAdjustment_Payment' ,'BalanceAdjustment_Payment')
		 AND (@InsuranceCompanyId IS NULL OR dp.InsuranceCompanyId= @InsuranceCompanyId)	ORDER BY dp.CreatedDate ;		RETURN;	END	SELECT '' AS Totals,0 AS TotalAmount,dp.CreatedBy,CAST(Amount AS DECIMAL(18, 2)) Deposit,dc.Description [DepositType],          			dp.Description AS DateDescription,CONVERT(VARCHAR(10), dp.EffectiveDate, 101)[DepositDate],ins.CompanyName              FROM Voucher dp(NOLOCK)             LEFT JOIN DepositType dc(NOLOCK) ON dc.Id = dp.DepositTypeId        	 LEFT JOIN InsuranceCompany ins (NOLOCK) ON ins.Id = dp.InsuranceCompanyId             WHERE  ((CAST(ISNULL(dp.EffectiveDate,dp.CreatedDate) AS DATE) >= CAST(@FromDate AS DATE)OR @FromDate IS NULL)          		 AND (CAST(ISNULL(dp.EffectiveDate,dp.CreatedDate) AS DATE) <= CAST(@ToDate AS DATE)          		 OR @ToDate IS NULL)) AND ISNULL	(dp.IsCommitted,0)=1 AND dp.PaymentSourceCD not in  ('BulkAdjustment_Payment' ,'BalanceAdjustment_Payment')
		 AND (@InsuranceCompanyId IS NULL OR dp.InsuranceCompanyId= @InsuranceCompanyId)	ORDER BY dp.CreatedDate ;	SELECT 'RecordedDepositTotals' AS RecordedDepositTotals,SUM(Amount) DepositAmount          	FROM Voucher (NOLOCK)             
	WHERE((CAST(ISNULL(EffectiveDate,CreatedDate) AS DATE) >= CAST(@FromDate AS DATE)	OR @FromDate IS NULL) 	AND (CAST(ISNULL(EffectiveDate,CreatedDate) AS DATE) <= CAST(@ToDate AS DATE) OR @ToDate IS NULL)) 	AND ISNULL(IsCommitted,0)=1 AND PaymentSourceCD not in  ('BulkAdjustment_Payment' ,'BalanceAdjustment_Payment')	AND (@InsuranceCompanyId IS NULL OR Voucher.InsuranceCompanyId= @InsuranceCompanyId); 	SELECT 'MonthlyPostings' AS MonthlyPostingsTotals,SUM(PaymentOrAdjAmount) PostingAmount
		FROM vw_PaymentsAdjustments pat(NOLOCK)       
		INNER JOIN Voucher vc ON pat.VoucherId = vc.Id
	WHERE pat.PatientCaseId > 0 AND pat.ChargeNum > 0 AND pat.IsDeleted = 0 AND pat.IsPayment = 1
	and vc.Id in 
	(SELECT dp.Id         
	FROM Voucher dp (NOLOCK)             
	WHERE((CAST(ISNULL(EffectiveDate,CreatedDate) AS DATE) >= CAST(@FromDate AS DATE)	OR @FromDate IS NULL) 	AND (CAST(ISNULL(EffectiveDate,CreatedDate) AS DATE) <= CAST(@ToDate AS DATE) OR @ToDate IS NULL)) 	AND ISNULL(IsCommitted,0)=1 AND PaymentSourceCD  not in  ('BulkAdjustment_Payment' ,'BalanceAdjustment_Payment')	AND (@InsuranceCompanyId IS NULL OR dp.InsuranceCompanyId= @InsuranceCompanyId)
	)    SELECT ISNULL(dc.Description, '') [DepositTypeName],SUM(Amount) DepositTypeTotalAmount          		FROM Voucher bd(NOLOCK) 
		LEFT JOIN DepositType dc(NOLOCK) ON dc.Id = bd.DepositTypeId        	WHERE((CAST(ISNULL(bd.EffectiveDate,bd.CreatedDate)AS DATE) >= CAST(@FromDate AS DATE)              OR @FromDate IS NULL) AND (CAST(ISNULL(bd.EffectiveDate,bd.CreatedDate) AS DATE) <= CAST(@ToDate AS DATE)          		OR @ToDate IS NULL))  AND ISNULL(bd.IsCommitted,0)=1		AND (@InsuranceCompanyId IS NULL OR bd.InsuranceCompanyId= @InsuranceCompanyId)	GROUP BY dc.Description;   		
	END; 


GO

CREATE PROCEDURE rpt_PaymentsToDoctors            
 @FromDate  datetime = NULL,                
 @ToDate   datetime = NULL,                
 @ProviderID  int = -1                
AS                
                 
 -- all charges except supplies and antepartum codes (billed to doc) - applied & unapplied                
 SELECT  CAST(PaymentEffectiveDate AS DATE) [PaymentEffectiveDate],            
  p.LastName [DoctorLastName], p.LastName [BillingDoctorLastName], v.CPTCode [ProcedureCode],                
    COUNT(1) TCount,                
    CAST(SUM(PaymentOrAdjAmount) as decimal(10,2))   Total              
 FROM  vw_PaymentsAdjustments v             
 LEFT JOIN [Provider] p ON p.Id = v.PerformingProviderId            
             
 LEFT JOIN vw_CHARGE_Latest c on c.ChargeNo = v.ChargeNum           
 --LEFT JOIN   BL_Claims cl on cl.INVOICE_NO = c.InvoiceNo            
 WHERE  v.PatientCaseId > 0                        
                   AND v.ChargeNum > 0                        
                   AND v.IsDeleted =0            
       AND v.IsPayment = 1      
       AND ((CAST(v.PaymentEffectiveDate AS DATE) >= CAST(@FromDate AS DATE)                        
                         OR @FromDate IS NULL)                        
                        AND (CAST(v.PaymentEffectiveDate AS DATE) <= CAST(@ToDate AS DATE)              
      OR @ToDate IS NULL))      
   AND (v.PerformingProviderId = @ProviderID OR @ProviderID = -1)
                  
 GROUP BY CAST(PaymentEffectiveDate AS DATE), p.LastName, p.FirstName, p.LastName, v.CPTCode 
GO

CREATE PROC [dbo].[rpt_pm_PrimaryPaymentsApplied]  
 @FromDate datetime = NULL,  
 @ToDate  datetime = NULL  
AS  
  
 SELECT  InsuranceCompany,  
    BillingID,  
    Patient,  
    DOS,  
    ProcedureCode,  
    Charge,  
    InsPayment,  
    InsAdjustment,  
    PtPayment,  
    PaymentDate,  
    PrimaryDXCode,  
    PrimaryDXDesc  
 FROM  dbo.tfn_pm_PrimaryPaymentsApplied(@FromDate, @ToDate)  
 ORDER BY InsuranceCompany, [Address], ProcedureCode,  
    DOS, Patient, Charge  
   
 SELECT 12, 5, 7, 12, 7, 6, 5, 5, 5, 5, 5, 15  

GO

--rpt_PostingPaymentByCptCodeByPostDate '1 July 2021','31 July 2021'
CREATE PROCEDURE rpt_PostingPaymentByCptCodeByPostDate
@FromDate DATE,
@ToDate DATE,
@ProviderId INT=NULL,
@FacilityId INT=NULL,
@InsuranceCompanyId INT=NULL,
@AuxillaryProviderId int = NULL,
@RefferingProviderId int = NULL,
@IsExcel BIT=0
AS
BEGIN

	DECLARE @Temp TABLE
	(
		CPTCode VARCHAR(10),
		ChargeId INT,
		Amount MONEY,
		Payments MONEY,
		Adjustments MONEY
	)

	INSERT INTO @Temp
	SELECT CPTCode,ChargeId,Amount,SUM(PaidAmount)[Payments],SUM(Adjustment)[Adjustments] FROM (
	SELECT D.CPTCode,A.Id,A.ChargeId,D.Amount,A.PaidAmount,ISNULL(SUM(C.Amount),0)[Adjustment]
					FROM PaymentCharge(NOLOCK) A
					INNER JOIN Charge (NOLOCK)D ON D.Id=A.ChargeId 
					INNER JOIN Invoice (NOLOCK)INV ON INV.Id=D.InvoiceId
					INNER JOIN Payment (NOLOCK) B ON A.PaymentId=B.Id
					INNER JOIN Voucher (NOLOCK) V ON B.VoucherId=V.Id									
					LEFT JOIN PaymentAdjustment (NOLOCK) C ON C.PaymentChargeId=A.Id and C.IsAccounted = 1   and C.IsDenial = 0 
				WHERE CAST(B.CreatedDate AS DATE)>=CAST(@FromDate AS DATE) AND CAST(B.CreatedDate AS DATE)<=CAST(@ToDate AS DATE)
					AND (@ProviderId IS NULL OR @ProviderId=D.PerformingProviderId)
					AND (@FacilityId IS NULL OR @FacilityId=D.PerformingFacilityId)
					AND (@InsuranceCompanyId IS NULL OR @InsuranceCompanyId=V.InsuranceCompanyId)
					AND  (@AuxillaryProviderId is NULL OR @AuxillaryProviderId = INV.AuxillaryProviderId)  
					AND  (@RefferingProviderId is NULL OR @RefferingProviderId = INV.RefDoctorId)
					AND D.IsDeleted=0			  
				GROUP BY D.CPTCode,A.Id,A.ChargeId,A.PaidAmount,D.Amount
				)
				BB
				GROUP BY CPTCode,Amount,ChargeId

	SELECT CPTCode,SUM(Amount)[Charges],SUM(Payments)[Payments],SUM(Adjustments)[Adjustment] from @Temp
	GROUP BY CPTCode
	ORDER BY CPTCode
		

END

GO

--rpt_PostingPaymentByDate '1 Sep 2022','2 Sep 2022'
CREATE PROCEDURE rpt_PostingPaymentByDate
@FromDate DATE,
@ToDate DATE,
@ProviderId INT=NULL,
@FacilityId INT=NULL,
@InsuranceCompanyId INT=NULL,
@AuxillaryProviderId int = NULL,
@RefferingProviderId int = NULL,
@IsExcel BIT=0
AS
BEGIN

	IF @IsExcel=0
	BEGIN
	SELECT A.ChargeId,B.PatientId,(P.LastName+', '+P.FirstName)[PatientName],D.BillFromDate[DosDate],D.Amount,A.PaidAmount,
		CASE WHEN B.IsReversed =0 THEN 'Received' ELSE 'Reversed' END[PaymentType],
		CASE WHEN B.PaymentSourceCD ='ERA_PAYMENT' THEN 'ERA' ELSE 'Manual' END[PaymentSource],
		CASE WHEN V.IsSelfPayment =0 THEN 'Insurance' ELSE 'Patient' END[PayerType],
		B .PayorControl,A.ModifiedDate[PaymentPostDate],
		V.EffectiveDate[PaymentEffectiveDate],V.ReferenceNo[CheckNumber],
		SUM(C.Amount)[Adjustment],D.PerformingProviderId,(F.LastName+', '+F.FirstName)[Provider],
		D.PerformingFacilityId,G.FacilityDescription,V.InsuranceCompanyId,INS.CompanyName
			FROM PaymentCharge(NOLOCK) A
			INNER JOIN Charge (NOLOCK)D ON D.Id=A.ChargeId 
			INNER JOIN Invoice (NOLOCK)INV ON INV.Id=D.InvoiceId
			INNER JOIN Payment (NOLOCK) B ON A.PaymentId=B.Id
			INNER JOIN Voucher (NOLOCK) V ON B.VoucherId=V.Id
			INNER JOIN Patient (NOLOCK)P ON P.Id=B.PatientId
			INNER JOIN Provider (NOLOCK)F ON F.Id=D.PerformingProviderId
			LEFT JOIN Facility (NOLOCK)G ON G.Id=D.PerformingFacilityId
			LEFT JOIN InsuranceCompany (NOLOCK)INS ON INS.Id=V.InsuranceCompanyId
			LEFT JOIN PaymentAdjustment (NOLOCK) C ON C.PaymentChargeId=A.Id and C.IsAccounted = 1   and C.IsDenial = 0
		WHERE CAST(B.CreatedDate AS DATE)>=@FromDate AND CAST(B.CreatedDate AS DATE)<=@ToDate
		AND (@ProviderId IS NULL OR @ProviderId=D.PerformingProviderId)
		AND (@FacilityId IS NULL OR @FacilityId=D.PerformingFacilityId)
		AND (@InsuranceCompanyId IS NULL OR @InsuranceCompanyId=V.InsuranceCompanyId)
		AND  (@AuxillaryProviderId is NULL OR @AuxillaryProviderId = INV.AuxillaryProviderId)  
		  AND  (@RefferingProviderId is NULL OR @RefferingProviderId = INV.RefDoctorId)  
		GROUP BY A.ChargeId,A.PaidAmount,B.PatientId,B.IsReversed,B.PaymentSourceCD,B .PayorControl,V.EffectiveDate,V.ReferenceNo,
		D.BillFromDate,D.Amount,A.ModifiedDate,P.FirstName,P.LastName,V.IsSelfPayment,F.FirstName,F.LastName,D.PerformingProviderId,
		D.PerformingFacilityId,G.FacilityDescription,V.InsuranceCompanyId,INS.CompanyName
		ORDER BY P.LastName ASC
	END
	ELSE
	BEGIN
		SELECT (P.LastName+', '+P.FirstName)[PatientName],CONVERT(varchar,D.BillFromDate,1)[DosDate],D.Amount,A.PaidAmount,SUM(C.Amount)[Adjustment],
		CASE WHEN B.IsReversed =0 THEN 'Received' ELSE 'Reversed' END[PaymentType],
		CASE WHEN B.PaymentSourceCD ='ERA_PAYMENT' THEN 'ERA' ELSE 'Manual' END[PaymentSource],
		CASE WHEN V.IsSelfPayment =0 THEN 'Insurance' ELSE 'Patient' END[PayerType],
		B .PayorControl,CONVERT(varchar,A.ModifiedDate,1)[PaymentPostDate],
		CONVERT(varchar,V.EffectiveDate,1)[PaymentEffectiveDate],V.ReferenceNo[CheckNumber],
		(F.LastName+', '+F.FirstName)[Provider],
		G.FacilityDescription[Facility],INS.CompanyName
			FROM PaymentCharge(NOLOCK) A
			INNER JOIN Charge (NOLOCK)D ON D.Id=A.ChargeId 
			INNER JOIN Invoice (NOLOCK)INV ON INV.Id=D.InvoiceId
			INNER JOIN Payment (NOLOCK) B ON A.PaymentId=B.Id
			INNER JOIN Voucher (NOLOCK) V ON B.VoucherId=V.Id
			INNER JOIN Patient (NOLOCK)P ON P.Id=B.PatientId
			INNER JOIN Provider (NOLOCK)F ON F.Id=D.PerformingProviderId
			LEFT JOIN Facility (NOLOCK)G ON G.Id=D.PerformingFacilityId
			LEFT JOIN InsuranceCompany (NOLOCK)INS ON INS.Id=V.InsuranceCompanyId
			LEFT JOIN PaymentAdjustment (NOLOCK) C ON C.PaymentChargeId=A.Id and C.IsAccounted = 1   and C.IsDenial = 0
		WHERE CAST(B.CreatedDate AS DATE)>=@FromDate AND CAST(B.CreatedDate AS DATE)<=@ToDate
		AND (@ProviderId IS NULL OR @ProviderId=D.PerformingProviderId)
		AND (@FacilityId IS NULL OR @FacilityId=D.PerformingFacilityId)
		AND (@InsuranceCompanyId IS NULL OR @InsuranceCompanyId=V.InsuranceCompanyId)
		AND  (@AuxillaryProviderId is NULL OR @AuxillaryProviderId = INV.AuxillaryProviderId)  
		  AND  (@RefferingProviderId is NULL OR @RefferingProviderId = INV.RefDoctorId)  
		GROUP BY A.ChargeId,A.PaidAmount,B.PatientId,B.IsReversed,B.PaymentSourceCD,B .PayorControl,V.EffectiveDate,V.ReferenceNo,
		D.BillFromDate,D.Amount,A.ModifiedDate,P.FirstName,P.LastName,V.IsSelfPayment,F.FirstName,F.LastName,D.PerformingProviderId,
		D.PerformingFacilityId,G.FacilityDescription,V.InsuranceCompanyId,INS.CompanyName
		ORDER BY P.LastName ASC

	END
		

END


GO


	CREATE PROCEDURE dbo.sp_alterdiagram
	(
		@diagramname 	sysname,
		@owner_id	int	= null,
		@version 	int,
		@definition 	varbinary(max)
	)
	WITH EXECUTE AS 'dbo'
	AS
	BEGIN
		set nocount on
	
		declare @theId 			int
		declare @retval 		int
		declare @IsDbo 			int
		
		declare @UIDFound 		int
		declare @DiagId			int
		declare @ShouldChangeUID	int
	
		if(@diagramname is null)
		begin
			RAISERROR ('Invalid ARG', 16, 1)
			return -1
		end
	
		execute as caller;
		select @theId = DATABASE_PRINCIPAL_ID();	 
		select @IsDbo = IS_MEMBER(N'db_owner'); 
		if(@owner_id is null)
			select @owner_id = @theId;
		revert;
	
		select @ShouldChangeUID = 0
		select @DiagId = diagram_id, @UIDFound = principal_id from dbo.sysdiagrams where principal_id = @owner_id and name = @diagramname 
		
		if(@DiagId IS NULL or (@IsDbo = 0 and @theId <> @UIDFound))
		begin
			RAISERROR ('Diagram does not exist or you do not have permission.', 16, 1);
			return -3
		end
	
		if(@IsDbo <> 0)
		begin
			if(@UIDFound is null or USER_NAME(@UIDFound) is null) -- invalid principal_id
			begin
				select @ShouldChangeUID = 1 ;
			end
		end

		-- update dds data			
		update dbo.sysdiagrams set definition = @definition where diagram_id = @DiagId ;

		-- change owner
		if(@ShouldChangeUID = 1)
			update dbo.sysdiagrams set principal_id = @theId where diagram_id = @DiagId ;

		-- update dds version
		if(@version is not null)
			update dbo.sysdiagrams set version = @version where diagram_id = @DiagId ;

		return 0
	END
	
GO


	CREATE PROCEDURE dbo.sp_creatediagram
	(
		@diagramname 	sysname,
		@owner_id		int	= null, 	
		@version 		int,
		@definition 	varbinary(max)
	)
	WITH EXECUTE AS 'dbo'
	AS
	BEGIN
		set nocount on
	
		declare @theId int
		declare @retval int
		declare @IsDbo	int
		declare @userName sysname
		if(@version is null or @diagramname is null)
		begin
			RAISERROR (N'E_INVALIDARG', 16, 1);
			return -1
		end
	
		execute as caller;
		select @theId = DATABASE_PRINCIPAL_ID(); 
		select @IsDbo = IS_MEMBER(N'db_owner');
		revert; 
		
		if @owner_id is null
		begin
			select @owner_id = @theId;
		end
		else
		begin
			if @theId <> @owner_id
			begin
				if @IsDbo = 0
				begin
					RAISERROR (N'E_INVALIDARG', 16, 1);
					return -1
				end
				select @theId = @owner_id
			end
		end
		-- next 2 line only for test, will be removed after define name unique
		if EXISTS(select diagram_id from dbo.sysdiagrams where principal_id = @theId and name = @diagramname)
		begin
			RAISERROR ('The name is already used.', 16, 1);
			return -2
		end
	
		insert into dbo.sysdiagrams(name, principal_id , version, definition)
				VALUES(@diagramname, @theId, @version, @definition) ;
		
		select @retval = @@IDENTITY 
		return @retval
	END
	
GO


