	CREATE PROCEDURE dbo.sp_helpdiagrams
	(
		@diagramname sysname = NULL,
		@owner_id int = NULL
	)
	WITH EXECUTE AS N'dbo'
	AS
	BEGIN
		DECLARE @user sysname
		DECLARE @dboLogin bit
		EXECUTE AS CALLER;
			SET @user = USER_NAME();
			SET @dboLogin = CONVERT(bit,IS_MEMBER('db_owner'));
		REVERT;
		SELECT
			[Database] = DB_NAME(),
			[Name] = name,
			[ID] = diagram_id,
			[Owner] = USER_NAME(principal_id),
			[OwnerID] = principal_id
		FROM
			sysdiagrams
		WHERE
			(@dboLogin = 1 OR USER_NAME(principal_id) = @user) AND
			(@diagramname IS NULL OR name = @diagramname) AND
			(@owner_id IS NULL OR principal_id = @owner_id)
		ORDER BY
			4, 5, 1
	END
	
GO


	CREATE PROCEDURE dbo.sp_renamediagram
	(
		@diagramname 		sysname,
		@owner_id		int	= null,
		@new_diagramname	sysname
	
	)
	WITH EXECUTE AS 'dbo'
	AS
	BEGIN
		set nocount on
		declare @theId 			int
		declare @IsDbo 			int
		
		declare @UIDFound 		int
		declare @DiagId			int
		declare @DiagIdTarg		int
		declare @u_name			sysname
		if((@diagramname is null) or (@new_diagramname is null))
		begin
			RAISERROR ('Invalid value', 16, 1);
			return -1
		end
	
		EXECUTE AS CALLER;
		select @theId = DATABASE_PRINCIPAL_ID();
		select @IsDbo = IS_MEMBER(N'db_owner'); 
		if(@owner_id is null)
			select @owner_id = @theId;
		REVERT;
	
		select @u_name = USER_NAME(@owner_id)
	
		select @DiagId = diagram_id, @UIDFound = principal_id from dbo.sysdiagrams where principal_id = @owner_id and name = @diagramname 
		if(@DiagId IS NULL or (@IsDbo = 0 and @UIDFound <> @theId))
		begin
			RAISERROR ('Diagram does not exist or you do not have permission.', 16, 1)
			return -3
		end
	
		-- if((@u_name is not null) and (@new_diagramname = @diagramname))	-- nothing will change
		--	return 0;
	
		if(@u_name is null)
			select @DiagIdTarg = diagram_id from dbo.sysdiagrams where principal_id = @theId and name = @new_diagramname
		else
			select @DiagIdTarg = diagram_id from dbo.sysdiagrams where principal_id = @owner_id and name = @new_diagramname
	
		if((@DiagIdTarg is not null) and  @DiagId <> @DiagIdTarg)
		begin
			RAISERROR ('The name is already used.', 16, 1);
			return -2
		end		
	
		if(@u_name is null)
			update dbo.sysdiagrams set [name] = @new_diagramname, principal_id = @theId where diagram_id = @DiagId
		else
			update dbo.sysdiagrams set [name] = @new_diagramname where diagram_id = @DiagId
		return 0
	END
	
GO


	CREATE PROCEDURE dbo.sp_upgraddiagrams
	AS
	BEGIN
		IF OBJECT_ID(N'dbo.sysdiagrams') IS NOT NULL
			return 0;
	
		CREATE TABLE dbo.sysdiagrams
		(
			name sysname NOT NULL,
			principal_id int NOT NULL,	-- we may change it to varbinary(85)
			diagram_id int PRIMARY KEY IDENTITY,
			version int,
	
			definition varbinary(max)
			CONSTRAINT UK_principal_name UNIQUE
			(
				principal_id,
				name
			)
		);


		/* Add this if we need to have some form of extended properties for diagrams */
		/*
		IF OBJECT_ID(N'dbo.sysdiagram_properties') IS NULL
		BEGIN
			CREATE TABLE dbo.sysdiagram_properties
			(
				diagram_id int,
				name sysname,
				value varbinary(max) NOT NULL
			)
		END
		*/

		IF OBJECT_ID(N'dbo.dtproperties') IS NOT NULL
		begin
			insert into dbo.sysdiagrams
			(
				[name],
				[principal_id],
				[version],
				[definition]
			)
			select	 
				convert(sysname, dgnm.[uvalue]),
				DATABASE_PRINCIPAL_ID(N'dbo'),			-- will change to the sid of sa
				0,							-- zero for old format, dgdef.[version],
				dgdef.[lvalue]
			from dbo.[dtproperties] dgnm
				inner join dbo.[dtproperties] dggd on dggd.[property] = 'DtgSchemaGUID' and dggd.[objectid] = dgnm.[objectid]	
				inner join dbo.[dtproperties] dgdef on dgdef.[property] = 'DtgSchemaDATA' and dgdef.[objectid] = dgnm.[objectid]
				
			where dgnm.[property] = 'DtgSchemaNAME' and dggd.[uvalue] like N'_EA3E6268-D998-11CE-9454-00AA00A3F36E_' 
			return 2;
		end
		return 1;
	END
	
GO

CREATE PROC usp_90DaysBalanceFinal
@MonthId INT=1,
@YearId INT=2023
AS
BEGIN
	
	--TRUNCATE TABLE ChargeBalanceAR90		
	DECLARE @CPAReportCreateDate DATE
	SELECT @CPAReportCreateDate=CAST(MAX(CreatedDate) AS DATE) from CPAReportMonthYearWise

	--IF EXISTS(SELECT NULL FROM ChargeBalanceAR90 WHERE  CPAReportCreateDate=@CPAReportCreateDate)
	--BEGIN
	--	RETURN;
	--END

	DECLARE @ParentId INT
	SELECT @ParentId=MIN(Id) from CPAReportMonthYearWise WHERE CAST(CreatedDate AS DATE)=@CPAReportCreateDate
	
	WHILE @ParentId IS NOT NULL
	BEGIN
		SELECT @MonthId=MonthId FROM CPAReportMonthYearWise WHERE Id=@ParentId
		
		DECLARE @ChildId INT	
		SELECT @ChildId=MIN (Id) FROM CPAReportMonthYearWiseChild WHERE CPAReportMonthYearWiseId=@ParentId
		
		WHILE @ChildId IS NOT NULL
		BEGIN
			SELECT @YearId=YearId FROM CPAReportMonthYearWiseChild WHERE Id=@ChildId

			DECLARE @ChargeAmount MONEY=0
			DECLARE @ChargeBalance1 MONEY=0
			DECLARE @ChargeBalance2 MONEY=0
			DECLARE @ChargeBalance3 MONEY=0
			DECLARE @ChargeBalance4 MONEY=0
			DECLARE @ChargeBalance5 MONEY=0
			DECLARE @ChargeBalance6 MONEY=0
			DECLARE @ChargeBalance7 MONEY=0
			DECLARE @ChargeBalance8 MONEY=0
			DECLARE @ChargeBalance9 MONEY=0
			DECLARE @ChargeBalance10 MONEY=0
			DECLARE @ChargeBalance11 MONEY=0
			DECLARE @ChargeBalance12 MONEY=0

			DECLARE @MonthPayment1 MONEY=0
			DECLARE @MonthPayment2 MONEY=0
			DECLARE @MonthPayment3 MONEY=0
			DECLARE @MonthPayment4 MONEY=0
			DECLARE @MonthPayment5 MONEY=0
			DECLARE @MonthPayment6 MONEY=0
			DECLARE @MonthPayment7 MONEY=0
			DECLARE @MonthPayment8 MONEY=0
			DECLARE @MonthPayment9 MONEY=0
			DECLARE @MonthPayment10 MONEY=0
			DECLARE @MonthPayment11 MONEY=0
			DECLARE @MonthPayment12 MONEY=0
			DECLARE @WriteOffAmount MONEY=0			

			DECLARE @CPAReportMonthYearWiseId INT

			SELECT @CPAReportMonthYearWiseId=B.Id,@ChargeAmount=B.ChargeAmount,@WriteOffAmount=B.WriteOffAmount,
					@MonthPayment1=ISNULL(A.MonthPayment1,0)+ISNULL(A.MonthAdjustment1,0)+ISNULL(A.MonthWriteOff1,0),
					@MonthPayment2=ISNULL(A.MonthPayment2,0)+ISNULL(A.MonthAdjustment2,0)+ISNULL(A.MonthWriteOff2,0),
					@MonthPayment3=ISNULL(A.MonthPayment3,0)+ISNULL(A.MonthAdjustment3,0)+ISNULL(A.MonthWriteOff3,0),
					@MonthPayment4=ISNULL(A.MonthPayment4,0)+ISNULL(A.MonthAdjustment4,0)+ISNULL(A.MonthWriteOff4,0),
					@MonthPayment5=ISNULL(A.MonthPayment5,0)+ISNULL(A.MonthAdjustment5,0)+ISNULL(A.MonthWriteOff5,0),
					@MonthPayment6=ISNULL(A.MonthPayment6,0)+ISNULL(A.MonthAdjustment6,0)+ISNULL(A.MonthWriteOff6,0),
					@MonthPayment7=ISNULL(A.MonthPayment7,0)+ISNULL(A.MonthAdjustment7,0)+ISNULL(A.MonthWriteOff7,0),
					@MonthPayment8=ISNULL(A.MonthPayment8,0)+ISNULL(A.MonthAdjustment8,0)+ISNULL(A.MonthWriteOff8,0),
					@MonthPayment9=ISNULL(A.MonthPayment9,0)+ISNULL(A.MonthAdjustment9,0)+ISNULL(A.MonthWriteOff9,0),
					@MonthPayment10=ISNULL(A.MonthPayment10,0)+ISNULL(A.MonthAdjustment10,0)+ISNULL(A.MonthWriteOff10,0),
					@MonthPayment11=ISNULL(A.MonthPayment11,0)+ISNULL(A.MonthAdjustment11,0)+ISNULL(A.MonthWriteOff11,0),
					@MonthPayment12=ISNULL(A.MonthPayment12,0)+ISNULL(A.MonthAdjustment12,0)+ISNULL(A.MonthWriteOff12,0)
			FROM  CPAReportMonthYearWiseChild A 
			INNER JOIN CPAReportMonthYearWise B on A.CPAReportMonthYearWiseId=B.Id
			WHERE A.Id=@ChildId

			DECLARE @PrevChargeBalance MONEY=0		
			SELECT TOP 1 @PrevChargeBalance=ChargeBalance12 FROM ChargeBalanceAR90 WHERE CPAReportMonthYearWiseId=@CPAReportMonthYearWiseId ORDER BY Id DESC
			IF @PrevChargeBalance>0
			BEGIN
				SET @ChargeAmount=@PrevChargeBalance
			END

				IF @MonthPayment1>0
				BEGIN
					SET @ChargeBalance1=@ChargeAmount-@MonthPayment1; 
				END
				ELSE
				BEGIN
					SET @ChargeBalance1=@ChargeAmount
				END
				IF @MonthPayment2>0
				BEGIN
					IF @ChargeBalance1=0 SET @ChargeBalance1=@ChargeAmount
					SET @ChargeBalance2=@ChargeBalance1-@MonthPayment2
				END
				IF @MonthPayment3>0
					IF @ChargeBalance2=0 SET @ChargeBalance2=@ChargeAmount
					SET @ChargeBalance3=@ChargeBalance2-@MonthPayment3

				IF @MonthPayment4>0
					IF @ChargeBalance3=0 SET @ChargeBalance3=@ChargeAmount
					SET @ChargeBalance4=@ChargeBalance3-@MonthPayment4
				IF @MonthPayment5>0
					IF @ChargeBalance4=0 SET @ChargeBalance4=@ChargeAmount
					SET @ChargeBalance5=@ChargeBalance4-@MonthPayment5
				IF @MonthPayment6>0
					IF @ChargeBalance5=0 SET @ChargeBalance5=@ChargeAmount
					SET @ChargeBalance6=@ChargeBalance5-@MonthPayment6
				IF @MonthPayment7>0
					IF @ChargeBalance6=0 SET @ChargeBalance6=@ChargeAmount
					SET @ChargeBalance7=@ChargeBalance6-@MonthPayment7		
				IF @MonthPayment8>0
					IF @ChargeBalance7=0 SET @ChargeBalance7=@ChargeAmount
					SET @ChargeBalance8=@ChargeBalance7-@MonthPayment8
				IF @MonthPayment9>0
					IF @ChargeBalance8=0 SET @ChargeBalance8=@ChargeAmount
					SET @ChargeBalance9=@ChargeBalance8-@MonthPayment9
				IF @MonthPayment10>0
					IF @ChargeBalance9=0 SET @ChargeBalance9=@ChargeAmount
					SET @ChargeBalance10=@ChargeBalance9-@MonthPayment10
				IF @MonthPayment11>0
					IF @ChargeBalance10=0 SET @ChargeBalance10=@ChargeAmount
					SET @ChargeBalance11=@ChargeBalance10-@MonthPayment11
				IF @MonthPayment12>0
					IF @ChargeBalance11=0 SET @ChargeBalance11=@ChargeAmount
					SET @ChargeBalance12=@ChargeBalance11-@MonthPayment12

			
			--IF NOT EXISTS(SELECT NULL FROM ChargeBalanceAR90 WHERE YearId=@YearId AND MonthId=@MonthId AND CAST(CreatedDate AS DATE)= CAST(GETDATE() AS DATE) )
			--BEGIN
				INSERT INTO ChargeBalanceAR90(ChargeAmount,WriteOffAmount,MonthId,YearId,ChargeBalance1,ChargeBalance2,ChargeBalance3,ChargeBalance4,
					ChargeBalance5,ChargeBalance6,ChargeBalance7,ChargeBalance8,ChargeBalance9,ChargeBalance10,ChargeBalance11,
					ChargeBalance12,CreatedDate,ModifiedDate,CPAReportCreateDate,CPAReportMonthYearWiseId)
				VALUES(@ChargeAmount,@WriteOffAmount,@MonthId,@YearId,@ChargeBalance1,@ChargeBalance2,@ChargeBalance3,@ChargeBalance4,
					@ChargeBalance5,@ChargeBalance6,@ChargeBalance7,@ChargeBalance8,@ChargeBalance9,@ChargeBalance10,@ChargeBalance11,
					@ChargeBalance12,GETDATE(),GETDATE(),@CPAReportCreateDate,@CPAReportMonthYearWiseId)
			--END

			SELECT @ChildId=MIN (Id) FROM CPAReportMonthYearWiseChild WHERE CPAReportMonthYearWiseId=@ParentId AND Id>@ChildId
		END
		SELECT @ParentId=MIN(Id) FROM CPAReportMonthYearWise WHERE CAST(CreatedDate AS DATE)=@CPAReportCreateDate AND Id>@ParentId
		
	END	
END

--ALTER TABLE ChargeBalanceAR90 ADD CPAReportMonthYearWiseId INT

--select * from ChargeBalanceAR90

GO

CREATE PROCEDURE usp_AddInsurancePolicyByPatientId
	@PatientId INT,
	@InsLevel INT,
	@InsuranceCompanyId INT,
	@PolicyNumber VARCHAR(20)
AS
BEGIN
	
	INSERT INTO InsurancePolicyHolder(UId,PatientId,FirstName,LastName,Address1,Address2,City,State,Zip,HomePhone,BusPhone,DOB,Sex,PHRel,CreatedBy,CreatedDate,ModifiedBy,ModifiedDate)
	SELECT NEWID(),Id,FirstName,LastName,Address1,Address2,City,State,ZipCode,PhoneNumber,WorkPhoneNumber,DOB,Sex,'Self','Admin',GetDate(),'Admin',GetDate() FROM Patient WHERE Id=@PatientId
	
	DECLARE @PHID INT
	SET @PHID=SCOPE_IDENTITY();


	INSERT INTO InsurancePolicy(UId,PatientCaseId,InsuranceCompanyId,PolicyNumber,PlanEffectiveDate,PHFirstName,PHLastName,PHRelationshipToPatient,PHID,CreatedBy,CreatedDate,ModifiedBy,ModifiedDate,InsuranceLevel)
	SELECT NEWID(),DefaultCaseId,@InsuranceCompanyId,@PolicyNumber,'1 May 2021',FirstName,LastName ,'Self',@PHID,'Admin',GetDate(),'Admin',GetDate(),@InsLevel FROM Patient WHERE Id=@PatientId
	
END





GO

CREATE procedure [dbo].[usp_ChargesByRevenueReport]    (              
@FromDate DATETIME =  null,                     
@ToDate DateTIME  =  null                
)                 
as            
Begin        			 
			     
Print 'Execution Started : ' + convert(varchar(30),getdate(),114)      
             
Declare @TempData as Table (            
AcctNo   int,        
PatientName  Nvarchar(500),            
ProviderName Nvarchar(500),            
InsCompanyId  int,        
CompanyName  Nvarchar(500),            
CompanyCode  Nvarchar(500),            
DOS    Date,            
CPTCode   Nvarchar(50),            
Modifiers  Nvarchar(50),            
ChargeAmt  Numeric(18,2),            
PriDX   Nvarchar(50),            
POS    Nvarchar(50),            
ChargeNo  Numeric(18,0) Primary Key,            
Payments  Numeric(18,2),            
Adjustments  Numeric(18,2),            
PaymentBat  Nvarchar(100),            
Due    Numeric(18,2),            
RevenueCenterName Nvarchar(500),                  
ShiftDate Date,        
FromDate Date,        
CaseNumber Numeric(18,0),
PostDate Date           
            
)            

Declare @Temp1 as Table (   
 SerialNo NVARCHAR(50),
 Label NVARCHAR(200),
 RevenueCenterName NVARCHAR(500),
 Amount money 
)

Declare @Temp2 as Table (   
 SerialNo NVARCHAR(50),
 Label NVARCHAR(200),
 RevenueCenterName NVARCHAR(500),
 Amount money 
)

Declare @Temp3 as Table (   
 SerialNo NVARCHAR(50),
 Label NVARCHAR(200),
 RevenueCenterName NVARCHAR(500),
 Amount money 
)
Declare @Temp4 as Table (   
 SerialNo NVARCHAR(50),
 Label NVARCHAR(200),
 RevenueCenterName NVARCHAR(500),
 Amount money 
)
        
Declare @TempPayment1 as Table (   
 SerialNo NVARCHAR(50),
 Label NVARCHAR(200),
 RevenueCenterName NVARCHAR(500),
 Amount money 
)

Declare @TempPayment2 as Table (   
 SerialNo NVARCHAR(50),
 Label NVARCHAR(200),
 RevenueCenterName NVARCHAR(500),
 Amount money 
)

Declare @TempPayment3 as Table (   
 SerialNo NVARCHAR(50),
 Label NVARCHAR(200),
 RevenueCenterName NVARCHAR(500),
 Amount money 
)
Declare @TempPayment4 as Table (   
 SerialNo NVARCHAR(50),
 Label NVARCHAR(200),
 RevenueCenterName NVARCHAR(500),
 Amount money 
)

Declare @TempAdjustment1 as Table (   
 SerialNo NVARCHAR(50),
 Label NVARCHAR(200),
 RevenueCenterName NVARCHAR(500),
 Amount money 
)

Declare @TempAdjustment2 as Table (   
 SerialNo NVARCHAR(50),
 Label NVARCHAR(200),
 RevenueCenterName NVARCHAR(500),
 Amount money 
)

Declare @TempAdjustment3 as Table (   
 SerialNo NVARCHAR(50),
 Label NVARCHAR(200),
 RevenueCenterName NVARCHAR(500),
 Amount money 
)
Declare @TempAdjustment4 as Table (   
 SerialNo NVARCHAR(50),
 Label NVARCHAR(200),
 RevenueCenterName NVARCHAR(500),
 Amount money 
)
           
Declare @TempPaymentData as Table (         
        
ChargeNo   Numeric(18,0) ,
PaymentDate		Date,            
PaymentAmt  Numeric(18,2),
RevenueCenterName Nvarchar(500)
Primary Key (ChargeNo, PaymentDate)
        
)        
        
Declare @TempAdjustmentData as Table (        
           
ChargeNo   Numeric(18,0) , 
AdjustmentDate	Date,           
AdjustmentAmt  Numeric(18,2),
RevenueCenterName Nvarchar(500)
Primary Key (ChargeNo, AdjustmentDate)            
)        
        
     
            
Insert Into @TempData            
(  AcctNo,   PatientName,  ProviderName,            
  InsCompanyId,  CompanyName ,  DOS,            
  CPTCode,  Modifiers,   ChargeAmt,            
  PriDX,   POS,    ChargeNo,            
  Payments,  Adjustments,  PaymentBat,            
  Due,   RevenueCenterName,  
   CompanyCode,        
   FromDate, CaseNumber, PostDate        
)            
select DISTINCT D.Id [PatientID],  CONCAT ( D.LastName, ',', D.FirstName, ' ', D.MI ) [PatientName],  CONCAT(E.LastName, ',', E.FirstName) ,                         
  0,'',     Cast(A.BillFromDate as date) ,                        
      A.CPTCode [CPT], CONCAT(A.Mod1, A.Mod2, A.Mod3, A.Mod4) [Mods],       
	  A.Amount,                        
   '', '', A.ChargeNo,            
   0 [Payments],  0 [Adjustments],  '',            
   0 [Due],   Isnull(K.CategoryName,'Non Revenue Center') [RevenueCenterName],    ''   [CompanyCode],
    A.BillFromDate, C.CaseIdNumber, A.EntryDate        
from vw_CHARGE_Latest A  (NOLOCK)          
            
INNER JOIN Invoice B (NOLOCK) ON A.InvoiceId=B.Id and A.IsDeleted =0 AND A.ChargeNo > 0  And A.PatientCaseId > 0 
join  PatientCase C (NOLOCK) ON C.Id = B.PatientCaseId             
join Patient D (NOLOCK) ON C.PatientId = D.Id             
join [Provider] E (NOLOCK) ON D.ProviderID = E.Id            
            
--left join BL_Inv_dx H (NOLOCK) ON H.InvoiceID = B.ID and H.DiagnosisNumber = 1            
--join BL_POS_Config I (NOLOCK) ON I.Code = A.PlaceOfService         
left join CPTCode  (NOLOCK) J ON J.CPTCode = A.CPTCode            
left join CPTCategory (NOLOCK) K ON K.ID = J.CPTCategoryId            
            
WHERE  CAST(A.BillFromDate AS DATE) between @FromDate and  @ToDate
           
        
Print 'SQL Passed : ' + convert(varchar(30),getdate(),114)        
        
        
Insert Into @TempPaymentData        
( ChargeNo, PaymentDate, PaymentAmt, RevenueCenterName)        
Select Z.ChargeNo, Z.PaymentEffectiveDate, Coalesce(Sum(Z.PaidAmount),0), IsNull(K.[CategoryName],'Non Revenue Center') [RevenueCenterName] 
from vw_GetChargeForPendingPayment Z   
left join CPTCode  (NOLOCK) J ON J.CPTCode = Z.CPTCode            
left join CPTCategory (NOLOCK) K ON K.Id = J.CPTCategoryId      
Where  z.IsDeleted =0    AND Z.ChargeNo > 0 AND Z.PatientCaseId > 0       
and Datediff(dd,Z.PaymentEffectiveDate,@ToDate) >= 0   
   
Group By ChargeNo, Z.PaymentEffectiveDate, IsNull(K.[CategoryName],'Non Revenue Center')               
        
Insert Into @TempAdjustmentData        
(ChargeNo, AdjustmentDate, AdjustmentAmt, RevenueCenterName)        
Select Z.ChargeNo, Z.PaymentEffectiveDate, Coalesce(Sum(Z.PaidAmount),0), IsNull(K.[CategoryName],'Non Revenue Center') [RevenueCenterName] 
from vw_GetChargeForPendingPayment Z  
left join CPTCode  (NOLOCK) J ON J.CPTCode = Z.CPTCode            
left join CPTCategory (NOLOCK) K ON K.Id = J.CPTCategoryId      
Where z.IsDeleted =0    AND Z.ChargeNo > 0    AND Z.PatientCaseId > 0       
and Datediff(dd,Z.PaymentEffectiveDate,@ToDate) >= 0              
Group By ChargeNo, Z.PaymentEffectiveDate, IsNull(K.[CategoryName],'Non Revenue Center')              
        
Print 'Generatae Temp Payment and Adjustment Passed : ' + convert(varchar(30),getdate(),114)        
        

INSERT INTO @Temp1  (   
 SerialNo ,
 Label ,
 RevenueCenterName ,
 Amount  
)
Select 1 [SerialNo], 'CHARGES' [Name], A.RevenueCenterName [Rev],
Sum(A.ChargeAmt)[CURRENTTHISYEAR]
from @TempData A 
Where CAST(A.FromDate AS DATE) between @FromDate and @ToDate
Group By  A.RevenueCenterName
Order By 1 Asc   

INSERT INTO @TempPayment1  (   
 SerialNo ,
 Label ,
 RevenueCenterName ,
 Amount  
)
Select 2 [SerialNo], 'PAYMENTS',B.RevenueCenterName [Rev], Sum(B.PaymentAmt ) [CURRENTTHISYEAR] from @TempPaymentData B 
Where B.PaymentDate between @FromDate and @ToDate
Group By  B.RevenueCenterName
Order By 1 Asc

INSERT INTO @TempAdjustment1  (   
 SerialNo ,
 Label ,
 RevenueCenterName ,
 Amount  
)
Select 3 [SerialNo], 'ADJUSTMENTS', C.RevenueCenterName [Rev], Sum(C.AdjustmentAmt ) [CURRENTTHISYEAR]
from @TempAdjustmentData C 
Where C.AdjustmentDate between @FromDate and @ToDate
Group By  C.RevenueCenterName
Order By [SerialNo], [Rev] Asc


INSERT INTO @Temp2  (   
 SerialNo ,
 Label ,
 RevenueCenterName ,
Amount  
)
Select 1 [SerialNo], 'CHARGES' [Name], A.RevenueCenterName [Rev],
Sum(A.ChargeAmt)[CURRENTLASTYEAR]
from @TempData A Where  A.FromDate between DATEADD(YEAR, -1, @FromDate) and DATEADD(YEAR, -1, @ToDate)
Group By  A.RevenueCenterName
--Order By 1 Asc   

INSERT INTO @TempPayment2  (   
 SerialNo ,
 Label ,
 RevenueCenterName ,
 Amount  
)
Select 2 [SerialNo], 'PAYMENTS',B.RevenueCenterName [Rev], Sum(B.PaymentAmt ) [CURRENTLASTYEAR] from @TempPaymentData B 
Where B.PaymentDate between DATEADD(YEAR, -1, @FromDate) and DATEADD(YEAR, -1, @ToDate)
Group By  B.RevenueCenterName
--Order By 1 Asc
--UNION

INSERT INTO @TempAdjustment2  (   
 SerialNo ,
 Label ,
 RevenueCenterName ,
 Amount  
)
Select 3 [SerialNo], 'ADJUSTMENTS', C.RevenueCenterName [Rev], Sum(C.AdjustmentAmt ) [CURRENTLASTYEAR]
from @TempAdjustmentData C 
Where C.AdjustmentDate between DATEADD(YEAR, -1, @FromDate) and DATEADD(YEAR, -1, @ToDate)
Group By  C.RevenueCenterName
--Order By [SerialNo], [Rev] Asc


INSERT INTO @Temp3  (   
 SerialNo ,
 Label ,
 RevenueCenterName ,
 Amount  
)
(Select 1 [SerialNo], 'CHARGES' [Name], A.RevenueCenterName [Rev],
Sum(A.ChargeAmt)[FISCALCURRENTYEAR]
from @TempData A Where YEAR(A.FromDate) between YEAR(@FromDate) and YEAR(@ToDate)
Group By  A.RevenueCenterName)
--Order By 1 Asc   
--UNION

INSERT INTO @TempPayment3  (   
 SerialNo ,
 Label ,
 RevenueCenterName ,
 Amount  
)
Select 2 [SerialNo], 'PAYMENTS',B.RevenueCenterName [Rev], Sum(B.PaymentAmt ) [FISCALCURRENTYEAR] from @TempPaymentData B 
Where YEAR(B.PaymentDate) between YEAR(@FromDate) and YEAR(@ToDate)
Group By  B.RevenueCenterName
--Order By 1 Asc
--UNION


INSERT INTO @TempAdjustment3  (   
 SerialNo ,
 Label ,
 RevenueCenterName ,
 Amount  
)
Select 3 [SerialNo], 'ADJUSTMENTS', C.RevenueCenterName [Rev], Sum(C.AdjustmentAmt ) [FISCALCURRENTYEAR]
from @TempAdjustmentData C 
Where YEAR(C.AdjustmentDate) between YEAR(@FromDate) and YEAR(@ToDate)
Group By  C.RevenueCenterName
--Order By [SerialNo], [Rev] Asc


INSERT INTO @Temp4  (   
 SerialNo ,
 Label ,
 RevenueCenterName ,
 Amount  
)
(Select 1 [SerialNo], 'CHARGES' [Name], A.RevenueCenterName [Rev],
Sum(A.ChargeAmt)[FISCALLASTYEAR]
from @TempData A Where YEAR(ISNULL(A.ShiftDate,A.FromDate)) between YEAR(@FromDate)-1 and YEAR(@ToDate)-1
Group By  A.RevenueCenterName)
--Order By 1 Asc   
--UNION

INSERT INTO @TempPayment4  (   
 SerialNo ,
 Label ,
 RevenueCenterName ,
 Amount  
)
Select 2 [SerialNo], 'PAYMENTS',B.RevenueCenterName [Rev], Sum(B.PaymentAmt ) [FISCALLASTYEAR] from @TempPaymentData B 
Where YEAR(B.PaymentDate) between YEAR(@FromDate)-1 and YEAR(@ToDate)-1
Group By  B.RevenueCenterName
--Order By 1 Asc
--UNION


INSERT INTO @TempAdjustment4  (   
 SerialNo ,
 Label ,
 RevenueCenterName ,
 Amount  
)
Select 3 [SerialNo], 'ADJUSTMENTS', C.RevenueCenterName [Rev], Sum(C.AdjustmentAmt ) [FISCALLASTYEAR]
from @TempAdjustmentData C 
Where YEAR(C.AdjustmentDate) between YEAR(@FromDate)-1 and YEAR(@ToDate)-1
Group By  C.RevenueCenterName
--Order By [SerialNo], [Rev] Asc

SELECT t1.Label,t1.RevenueCenterName [Category],t1.Amount [THISYEAR], t2.Amount [LASTYEAR],

 CAST(CASE   
                  WHEN t1.Amount = 0 or  t2.Amount= 0   
             THEN 0  
                  ELSE (t1.Amount - t2.Amount) / ISNULL(t2.Amount, 1) * 100  
             END AS MONEY) [PCTVAR],  

t3.Amount [FISCALTHISYEAR], t4.Amount [FISCALLASTYEAR],
 CAST(CASE   
                  WHEN t3.Amount = 0 or  t4.Amount= 0   
             THEN 0  
                  ELSE (t3.Amount - t4.Amount) / ISNULL(t4.Amount, 1) * 100  
             END AS MONEY) [PCTVAR1]  
FROM @Temp1 t1 LEFT JOIN @Temp2 t2 ON t1.RevenueCenterName = t2.RevenueCenterName
LEFT JOIN @Temp3 t3 ON t3.RevenueCenterName = t1.RevenueCenterName
LEFT JOIN @Temp4 t4 ON t4.RevenueCenterName = t1.RevenueCenterName

SELECT tp1.Label,tp1.RevenueCenterName [Category],tp1.Amount [THISYEAR], tp2.Amount [LASTYEAR],
CAST(CASE   
                  WHEN tp1.Amount = 0 or  tp2.Amount= 0   
             THEN 0  
                  ELSE (tp1.Amount - tp2.Amount) / ISNULL(tp2.Amount, 1) * 100  
             END AS MONEY) [PCTVAR],
tp3.Amount [FISCALTHISYEAR], tp4.Amount [FISCALLASTYEAR]
,
 CAST(CASE   
                  WHEN tp3.Amount = 0 or  tp4.Amount= 0   
             THEN 0  
                  ELSE (tp3.Amount - tp4.Amount) / ISNULL(tp4.Amount, 1) * 100  
             END AS MONEY) [PCTVAR1]   
FROM @TempPayment1 tp1 LEFT JOIN @TempPayment2 tp2 ON tp1.RevenueCenterName = tp2.RevenueCenterName
LEFT JOIN @TempPayment3 tp3 ON tp3.RevenueCenterName = tp1.RevenueCenterName
LEFT JOIN @TempPayment4 tp4 ON tp4.RevenueCenterName = tp1.RevenueCenterName

SELECT ta1.Label,ta1.RevenueCenterName [Category],ta1.Amount [THISYEAR], ta2.Amount [LASTYEAR],
CAST(CASE   
                  WHEN ta1.Amount = 0 or  ta2.Amount= 0   
             THEN 0  
                  ELSE (ta1.Amount - ta2.Amount) / ISNULL(ta2.Amount, 1) * 100  
             END AS MONEY) [PCTVAR],
ta3.Amount [FISCALTHISYEAR], ta4.Amount [FISCALLASTYEAR] 
,
 CAST(CASE   
                  WHEN ta3.Amount = 0 or  ta4.Amount= 0   
             THEN 0  
                  ELSE (ta3.Amount - ta4.Amount) / ISNULL(ta4.Amount, 1) * 100  
             END AS MONEY) [PCTVAR1]  
FROM @TempAdjustment1 ta1 LEFT JOIN @TempAdjustment2 ta2 ON ta1.RevenueCenterName = ta2.RevenueCenterName
LEFT JOIN @TempAdjustment3 ta3 ON ta3.RevenueCenterName = ta1.RevenueCenterName
LEFT JOIN @TempAdjustment4 ta4 ON ta4.RevenueCenterName = ta1.RevenueCenterName


End


GO

CREATE PROCEDURE [dbo].[usp_ChargeSnapShotsMonthWise]
AS
BEGIN

	DECLARE @MonthId INT
	DECLARE @YearId INT

	--SELECT @MonthId=DATEPART(MONTH,GETDATE()),@YearId=DATEPART(YEAR,GETDATE()) FROM ChargesReportDataSnapShots(NOLOCK)

	--IF EXISTS(SELECT NULL FROM ChargesReportDataSnapShots(NOLOCK) WHERE DATEPART(MONTH,CreatedDate)=@MonthId AND DATEPART(YEAR,GETDATE())=@YearId)
	--BEGIN
	--	RETURN;
	--END

	--DECLARE @EndDate DATE =EOMONTH(GETDATE())
	--IF(CAST(GETDATE() AS DATE)<>CAST(@EndDate AS DATE))
	--BEGIN
	--	RETURN;
	--END


	DECLARE @DataTable TABLE
	(
		DosDateFrom DATE,
		DosDateTo DATE,		
		TotalSamples INT,
		ChargeAmount MONEY,
		ExpectedAmount MONEY,
		Payment MONEY,
		Adjustment MONEY,
		DenialAmount MONEY,
		DueAmount MONEY,
		WriteOff MONEY
	)

	DECLARE @Temp TABLE
	(
		Id INT IDENTITY(1,1),
		FromDate DATETIME,
		ToDate DATETIME
	)

	DECLARE @Date DATETIME =GetDate();

	INSERT INTO @Temp
	SELECT DATEADD(mm, DATEDIFF(mm, 0, GETDATE()), 0),GETDATE()


	DECLARE @Count INT=0
	WHILE DATEADD(mm, DATEDIFF(mm, 0, @Date) - 1, 0)>=DATEADD(yy, DATEDIFF(yy, 0, GETDATE()), 0)
	BEGIN
			INSERT INTO @Temp
			SELECT DATEADD(mm, DATEDIFF(mm, 0, @Date) - 1, 0),DATEADD(DAY, -(DAY(@Date)), @Date)
			SET @Date=DATEADD(mm,-1,@Date)
			SET @Count=@Count+1
	END
	DECLARE @Id INT
	SELECT @Id=MAX(Id) FROM @Temp

		WHILE @Id IS NOT NULL
		BEGIN
			DECLARE @DosFromDate DATE=NULL
			DECLARE @DosToDate DATE=NULL
		
			SELECT @DosFromDate=CAST(FromDate AS DATE),@DosToDate=CAST(ToDate AS DATE) FROM @Temp WHERE Id=@Id

			DECLARE @TotalSamples INT=0
				DECLARE @TotalDenials INT=0
				DECLARE @ChargeAmount MONEY=0
				DECLARE @ExpectedAmount MONEY=0
				DECLARE @Payment MONEY=0
				DECLARE @Adjustment MONEY=0
				DECLARE @DenialAmount MONEY=0
				DECLARE @DueAmount MONEY=0
				DECLARE @WriteOff MONEY=0
								
				DECLARE @PaymentFromDate DATE=NULL
				DECLARE @PaymentToDate DATE=NULL
	

				SELECT DISTINCT @TotalSamples=COUNT(InvoiceId)
				FROM ChargesReportData(NOLOCK) where CAST(ChargePostDate AS DATE)>=@DosFromDate and CAST(ChargePostDate AS DATE)<=@DosToDate	
	
				SELECT @ChargeAmount=SUM(ChargeAmount),@ExpectedAmount=SUM(FeeAmount),@Payment=SUM(Payment),@Adjustment=SUM(Adjustment),@WriteOff=SUM(WriteOffAmount) 
				FROM ChargesReportData (NOLOCK) where CAST(ChargePostDate AS DATE)>=@DosFromDate and CAST(ChargePostDate AS DATE)<=@DosToDate	

				SELECT @Adjustment=SUM(Adjustment) FROM ChargesReportData (NOLOCK)
				where (CAST(ChargePostDate AS DATE)>=@DosFromDate and CAST(ChargePostDate AS DATE)<=@DosToDate) AND Denial='No'

				SELECT @Adjustment=SUM(Adjustment) FROM ChargesReportData (NOLOCK)
				where (CAST(ChargePostDate AS DATE)>=@DosFromDate and CAST(ChargePostDate AS DATE)<=@DosToDate) AND Denial='No'

				SELECT @DenialAmount=SUM(ChargeAmount) FROM ChargesReportData (NOLOCK) 
				where (CAST(ChargePostDate AS DATE)>=@DosFromDate and CAST(ChargePostDate AS DATE)<=@DosToDate)
				AND Denial='Yes'

				SELECT @DueAmount=SUM(DueAmount) FROM ChargesReportData (NOLOCK) 
				where (CAST(ChargePostDate AS DATE)>=@DosFromDate and CAST(ChargePostDate AS DATE)<=@DosToDate) 				AND Denial='No'

				INSERT INTO @DataTable
				SELECT @DosFromDate[DosFromDate],@DosToDate[DosToDate],@TotalSamples[TotalSamples],@ChargeAmount[ChargeAmount],
				@ExpectedAmount[ExpectedAmount],@Payment[Payment],@Adjustment[Adjustment],@DenialAmount,@DueAmount,@WriteOff
								

			
			SELECT @Id=MAX(Id) FROM @Temp WHERE Id<@Id
		END
	SELECT * FROM @DataTable
	INSERT INTO ChargesReportDataSnapShots (UId,PracticeId,DosDateFrom,DosDateTo,TotalSamples,ChargeAmount,ExpectedAmount,Payment,Adjustment,DenialAmount,DueAmount,WriteOff)
	SELECT NEWID(),1,MIN(DosDateFrom),MAX(DosDateTo),SUM(TotalSamples),SUM(ChargeAmount),SUM(ExpectedAmount),SUM(Payment),SUM(Adjustment),SUM(DenialAmount),SUM(DueAmount),SUM(WriteOff)
	FROM @DataTable
	
	DECLARE @ChargeSnapShotId INT=SCOPE_IDENTITY()

	INSERT INTO ChargesReportDataSnapShotsChild (ChargesReportDataSnapShotsId,DosDateFrom,DosDateTo,TotalSamples,ChargeAmount,ExpectedAmount,Payment,Adjustment,DenialAmount,DueAmount,WriteOff)
	SELECT @ChargeSnapShotId,DosDateFrom,DosDateTo,TotalSamples,ChargeAmount,ExpectedAmount,Payment,Adjustment,DenialAmount,DueAmount,WriteOff
	FROM @DataTable


END


GO

CREATE PROCEDURE usp_ChargeSnapShotsMonthWise_Consolidated
AS
BEGIN

	
	BEGIN TRANSACTION TR_SaveScnapShotsData
	BEGIN TRY
			----------------------------------AUTUMN Clinic Insertion Start--------------

			INSERT INTO ChargesReportDataSnapShots_All (UId,PracticeId,DosDateFrom,DosDateTo,TotalSamples,ChargeAmount,ExpectedAmount,Payment,Adjustment,DenialAmount,DueAmount,WriteOff,DBName,PracticeName)
			SELECT NEWID(),PracticeId,DosDateFrom,DosDateTo,TotalSamples,ChargeAmount,ExpectedAmount,Payment,Adjustment,DenialAmount,DueAmount,WriteOff,'AUTUMN','Clinic'
			FROM PI_ATC_CLINIC.dbo.ChargesReportDataSnapShots(NOLOCK) WHERE ISNULL(IsTransered,0)=0

			DECLARE @ClinicId INT
			SET @ClinicId=SCOPE_IDENTITY()

			UPDATE PI_ATC_CLINIC.dbo.ChargesReportDataSnapShots SET IsTransered=1 WHERE ISNULL(IsTransered,0)=0
			
			INSERT INTO ChargesReportDataSnapShotsChild_All (ChargesReportDataSnapShotsId,DosDateFrom,DosDateTo,TotalSamples,ChargeAmount,ExpectedAmount,
						Payment,Adjustment,DenialAmount,DueAmount,WriteOff,DBName,PracticeName)
			SELECT @ClinicId,DosDateFrom,DosDateTo,TotalSamples,ChargeAmount,ExpectedAmount,Payment,Adjustment,DenialAmount,DueAmount,WriteOff,'AUTUMN','Clinic'
			FROM PI_ATC_CLINIC.dbo.ChargesReportDataSnapShotsChild WHERE ISNULL(IsTransered,0)=0

			UPDATE PI_ATC_CLINIC.dbo.ChargesReportDataSnapShotsChild SET IsTransered=1 WHERE ISNULL(IsTransered,0)=0

			----------------------------------AUTUMN Clinic Insertion End--------------

			----------------------------------AUTUMN LAB Insertion Start--------------

			INSERT INTO ChargesReportDataSnapShots_All (UId,PracticeId,DosDateFrom,DosDateTo,TotalSamples,ChargeAmount,ExpectedAmount,Payment,Adjustment,DenialAmount,DueAmount,WriteOff,DBName,PracticeName)
			SELECT NEWID(),PracticeId,DosDateFrom,DosDateTo,TotalSamples,ChargeAmount,ExpectedAmount,Payment,Adjustment,DenialAmount,DueAmount,WriteOff,'AUTUMN','LAB'
			FROM PI_ATC_LAB.dbo.ChargesReportDataSnapShots(NOLOCK) WHERE ISNULL(IsTransered,0)=0

			DECLARE @LABId INT
			SET @LABId=SCOPE_IDENTITY()

			UPDATE PI_ATC_LAB.dbo.ChargesReportDataSnapShots SET IsTransered=1 WHERE ISNULL(IsTransered,0)=0
			
			INSERT INTO ChargesReportDataSnapShotsChild_All (ChargesReportDataSnapShotsId,DosDateFrom,DosDateTo,TotalSamples,ChargeAmount,ExpectedAmount,
						Payment,Adjustment,DenialAmount,DueAmount,WriteOff,DBName,PracticeName)
			SELECT @LABId,DosDateFrom,DosDateTo,TotalSamples,ChargeAmount,ExpectedAmount,Payment,Adjustment,DenialAmount,DueAmount,WriteOff,'AUTUMN','LAB'
			FROM PI_ATC_LAB.dbo.ChargesReportDataSnapShotsChild WHERE ISNULL(IsTransered,0)=0

			UPDATE PI_ATC_LAB.dbo.ChargesReportDataSnapShotsChild SET IsTransered=1 WHERE ISNULL(IsTransered,0)=0

			----------------------------------AUTUMN LAB Insertion End--------------

			

		COMMIT TRANSACTION TR_SaveScnapShotsData
	END TRY
	BEGIN CATCH
		ROLLBACK TRANSACTION TR_SaveScnapShotsData
	END CATCH

END


GO

