CREATE PROCEDURE [dbo].[usp_CollectionPercentageReport]  (          
@FromDate DATETIME =  null,                 
@ToDate DateTIME  =  null            
)             
as        
Begin        
Print 'Execution Started : ' + convert(varchar(30),getdate(),114)    

SET @ToDate = EOMONTH(Cast(@ToDate as date)) 
SET @FromDate = DateAdd(month, -12, Cast(@ToDate as date));  
SET @FromDate = DateAdd(DAY, 1, Cast(@FromDate as date));  

    
Declare @TempOutputData as Table (     
    
DOSMonth   date ,    
TotCharges  Numeric(18,2),    
TotAdjustments Numeric(18,2),    
TotPayments Numeric(18,2),    
TotDue  Numeric(18,2),    
Perc  Numeric(18,2)    
)    
    
Insert Into  @TempOutputData    
(DOSMonth, TotCharges)    
select    
  CAST(A.BillFromDate AS DATE) ,                    
       sum(A.Amount)                  
from vw_CHARGE_Latest A  (NOLOCK)      
        
INNER JOIN Invoice B (NOLOCK) ON A.InvoiceId = B.Id and A.IsDeleted = 0
 and A.ChargeNo > 0 And A.PatientCaseId > 0 --and A.BillIns = 1    
join  PatientCase C (NOLOCK) ON C.Id = B.PatientCaseId         
join Patient D (NOLOCK) ON C.PatientId = D.Id         
join [Provider] E (NOLOCK) ON D.ProviderID = E.Id        
        
--join BL_Inv_dx H (NOLOCK) ON H.InvoiceID = B.ID and H.DiagnosisNumber = 1        
--join BL_POS_Config I (NOLOCK) ON I.Code = A.PlaceOfService          
left join CPTCode J (NOLOCK)  ON J.CPTCode = A.CPTCode        
left join CPTCategory K (NOLOCK) ON K.Id = J.CPTCategoryId        
        
WHERE  CAST(A.BillFromDate AS DATE) between @FromDate and  @ToDate     
Group By CAST(A.BillFromDate AS DATE)    
    
Print 'SQL Passed : ' + convert(varchar(30),getdate(),114)    
    
    
Insert Into  @TempOutputData    
(DOSMonth, TotPayments)    
Select cast(Z.PaymentEffectiveDate as date), Coalesce(Sum(Z.PaidAmount),0) from vw_GetChargeForPendingPayment Z    
Where  z.IsDeleted =0
and cast(Z.PaymentEffectiveDate as date) between @FromDate and  @ToDate And Z.ChargeNo > 0 And Z.PatientCaseId > 0    
Group By cast(Z.PaymentEffectiveDate  as date)         
    
Insert Into  @TempOutputData    
(DOSMonth, TotAdjustments)    
Select cast(Z.PaymentEffectiveDate as date), Coalesce(Sum(Z.TotalAdjustment),0) from vw_GetChargeForPendingPayment Z    
Where z.IsDeleted =0       
and cast(Z.PaymentEffectiveDate as date) between @FromDate and  @ToDate And Z.ChargeNo > 0 And Z.PatientCaseId > 0    
Group By cast(Z.PaymentEffectiveDate as date)          
    
Print 'Generatae Temp Payment and Adjustment Passed : ' + convert(varchar(30),getdate(),114)    
    
Select Cast(Datepart(YYYY,DOSMonth) as nvarchar(4)) + '-' + cast(DATEPart(month,DOSMonth) as nvarchar(2)),      
Cast(Datepart(YYYY,DOSMonth) as nvarchar(4)) + '-' + cast(DATENAME(month,DOSMonth) as nvarchar(20)) [DOSMonth],     
ISNULL(sum(TotCharges),0) [TotalCharges],     
ISNULL(sum(totpayments),0) [ActualReceipt],     
ISNUll(sum(totadjustments),0) [TotalAdjustments],     
ISNULL(sum(TotCharges) -  sum(totadjustments),0) [ExpectedReceipt],      
ISNULL((Sum(totpayments) / (sum(TotCharges) -  sum(totadjustments))) * 100,0)  [PercentCollected]     
from @TempOutputData    
Group By Cast(Datepart(YYYY,DOSMonth) as nvarchar(4)) + '-' + cast(DATEPart(month,DOSMonth) as nvarchar(2)),
Cast(Datepart(YYYY,DOSMonth) as nvarchar(4)) + '-' + cast(DATENAME(month,DOSMonth) as nvarchar(20))    
Order BY 1 asc    
End

--usp_CollectionPercentageReport '20171001' , '20180930'


GO

