create PROCEDURE usp_CPAReportYearMonthWise
AS
BEGIN

		--IF EXISTS(SELECT NULL FROM CPAReportMonthYearWise WHERE CAST(CreatedDate AS DATE)=CAST(GETDATE() AS DATE))
		--BEGIN
		--	RETURN;
		--END


		DECLARE @Date DATE
		SELECT @Date=MIN(DosDate) from ChargesReportData
		
		--TRUNCATE TABLE CPAReportMonthYearWise
		--TRUNCATE TABLE CPAReportMonthYearWiseChild
			   		
		DECLARE @Temp TABLE
		(
			Id INT IDENTITY(1,1),
			StartDate DATE,
			EndDate DATE
		)


		DECLARE @StartDate DATE
		DECLARE @EndDate DATE

		WHILE @Date<= EOMONTH(GETDATE())   --EOMONTH(DATEADD(MOnth,-1,GETDATE()))
		BEGIN
			SET @StartDate = DATEFROMPARTS(YEAR(@Date ), MONTH(@Date ), '01');
			SET @EndDate= EOMONTH(@Date)
			SET @Date=DATEADD(mm,1,@Date)
	
			DECLARE @DenialAmount MONEY=0
			DECLARE @ChargeAmount MONEY=0
			DECLARE @FeeAmount MONEY=0
			DECLARE @PaymentCharge MONEY=0
			DECLARE @Adjustment MONEY=0
			DECLARE @MonthId INT=0
			DECLARE @YearId INT=0
			DECLARE @WriteOff MONEY=0
			DECLARE @DueAmount MONEY=0
			DECLARE @TotalRecoverableAmount MONEY=0

			SET @MonthId=DATEPART(MONTH,@StartDate)
			SET @YearId=DATEPART(YEAR,@StartDate)

			SELECT @ChargeAmount=SUM(ChargeAmount),@FeeAmount=SUM(FeeAmount),@PaymentCharge=SUM(Payment),@WriteOff=SUM(WriteOffAmount)  
			FROM ChargesReportData(NOLOCK) WHERE DosDate>=@StartDate AND DosDate<=@EndDate AND Deleted='NO'

			SELECT @Adjustment=SUM(Adjustment) 
				FROM ChargesReportData (NOLOCK) 
			WHERE (CAST(DosDate AS DATE)>=@StartDate and CAST(DosDate AS DATE)<=@EndDate) AND Denial='No' AND Deleted='NO'
			AND ISNULL(WriteOffAmount ,0)=0

			SELECT @DueAmount=SUM(DueAmount) FROM ChargesReportData (NOLOCK) 
			WHERE (CAST(DosDate AS DATE)>=@StartDate and CAST(DosDate AS DATE)<=@EndDate) AND Denial='No' AND Deleted='NO'

			SELECT @DenialAmount=SUM(ChargeAmount) FROM ChargesReportData (NOLOCK) WHERE (CAST(DosDate AS DATE)>=@StartDate and CAST(DosDate AS DATE)<=@EndDate) AND Denial='Yes' AND Deleted='NO'

			SET @TotalRecoverableAmount =@DueAmount+@DenialAmount

			IF NOT EXISTS(SELECT NULL FROM CPAReportMonthYearWise WHERE CAST(CreatedDate AS DATE)=CAST(GETDATE() AS DATE) AND YearId=@YearId AND MonthId=@MonthId)
			BEGIN
				INSERT INTO CPAReportMonthYearWise(YearId,MonthId,ChargeAmount,ExpectedAmount,DenialAmount,CreatedDate,ModifiedDate,Payment,Adjustment,WriteOffAmount,DueAmount,TotalRecoverableAmount)
				Values(@YearId,@MonthId,@ChargeAmount,@FeeAmount,@DenialAmount,GETDATE(),GETDATE(),@PaymentCharge,@Adjustment,@WriteOff,@DueAmount,@TotalRecoverableAmount)
			END
		END

		DECLARE @CPAReportId INT
		SELECT @CPAReportId=MIN(Id) FROM CPAReportMonthYearWise (NOLOCK) WHERE CAST(CreatedDate AS DATE)=CAST(GETDATE() AS DATE)

		WHILE @CPAReportId IS NOT NULL
		BEGIN
			DECLARE @PaymentTemp TABLE
			(
				Id INT IDENTITY(1,1),
				CPAReportMonthYearWiseId INT,
				StartDate DATE,
				EndDate DATE
			)
			DECLARE @PaymentMonthId INT=0
			DECLARE @PaymentYearId INT=0

			SELECT @PaymentMonthId=MonthId,@PaymentYearId =YearId FROM CPAReportMonthYearWise WHERE Id=@CPAReportId
			
			DECLARE @PaymentStartDate DATE
			DECLARE @ChargeStartDate DATE
			DECLARE @ChargeEndDate DATE

			SET @PaymentStartDate = DATEFROMPARTS(@PaymentYearId, @PaymentMonthId, '01');

			SET @ChargeStartDate=@PaymentStartDate
			SET @ChargeEndDate=EOMONTH(@PaymentStartDate)

			WHILE @PaymentStartDate<=EOMONTH(GETDATE())
			BEGIN
				DECLARE @PaymentEndDate DATE
				DECLARE @Payment MONEY
				DECLARE @WriteOffChild MONEY
				DECLARE @AdjustmentChild MONEY
				DECLARE @TempPaymentMonthId INT=0

				SET @PaymentEndDate =EOMONTH(@PaymentStartDate)
				
				SELECT @Payment=SUM(ISNULL(Payment,0)) FROM ChargesReportData WHERE ChargeId in (
					SELECT ChargeId FROM ChargesReportData WHERE DosDate>=@ChargeStartDate AND DosDate<=@ChargeEndDate)
				AND (CAST(RemitDate AS DATE)>=@PaymentStartDate AND CAST(RemitDate AS DATE)<=@PaymentEndDate) AND Deleted='NO'

				SELECT @AdjustmentChild=SUM(ISNULL(Adjustment,0)) FROM ChargesReportData WHERE ChargeId in (
					SELECT ChargeId FROM ChargesReportData WHERE DosDate>=@ChargeStartDate AND DosDate<=@ChargeEndDate)
				AND (CAST(RemitDate AS DATE)>=@PaymentStartDate AND CAST(RemitDate AS DATE)<=@PaymentEndDate) AND Denial='No'
				AND ISNULL(WriteOffAmount ,0)=0 AND Deleted='NO'

				SELECT @WriteOffChild=SUM(WriteOffAmount) FROM ChargesReportData WHERE ChargeId in (
					SELECT ChargeId FROM ChargesReportData WHERE DosDate>=@ChargeStartDate AND DosDate<=@ChargeEndDate)
				AND (CAST(RemitDate AS DATE)>=@PaymentStartDate AND CAST(RemitDate AS DATE)<=@PaymentEndDate) AND Denial='No'
				AND ISNULL(WriteOffAmount ,0)>0 AND Deleted='NO'

				DECLARE @CPAReportMonthYearWiseChildId INT=0

				IF NOT EXISTS(SELECT NULL FROM CPAReportMonthYearWiseChild(NOLOCK) WHERE YearId=DATEPART(YEAR,@PaymentStartDate) AND CPAReportMonthYearWiseId=@CPAReportId)
				BEGIN
					INSERT INTO CPAReportMonthYearWiseChild(CPAReportMonthYearWiseId,YearId,CreatedDate,ModifiedDate)
					Values(@CPAReportId,DATEPART(YEAR,@PaymentStartDate),GetDate(),GetDate())
					
					SET @CPAReportMonthYearWiseChildId=SCOPE_IDENTITY();
				END
				ELSE
				BEGIN
					SELECT @CPAReportMonthYearWiseChildId=Id FROM CPAReportMonthYearWiseChild(NOLOCK) WHERE YearId=DATEPART(YEAR,@PaymentStartDate) AND CPAReportMonthYearWiseId=@CPAReportId
				END

				SET @TempPaymentMonthId=DATEPART(MONTH,@PaymentStartDate)
				IF(@TempPaymentMonthId=1)
					UPDATE CPAReportMonthYearWiseChild SET MonthPayment1=@Payment,MonthAdjustment1=@AdjustmentChild,MonthWriteOff1=@WriteOffChild WHERE Id=@CPAReportMonthYearWiseChildId
				IF(@TempPaymentMonthId=2)
					UPDATE CPAReportMonthYearWiseChild SET MonthPayment2=@Payment,MonthAdjustment2=@AdjustmentChild,MonthWriteOff2=@WriteOffChild WHERE Id=@CPAReportMonthYearWiseChildId
				IF(@TempPaymentMonthId=3)
					UPDATE CPAReportMonthYearWiseChild SET MonthPayment3=@Payment,MonthAdjustment3=@AdjustmentChild,MonthWriteOff3=@WriteOffChild WHERE Id=@CPAReportMonthYearWiseChildId
				IF(@TempPaymentMonthId=4)
					UPDATE CPAReportMonthYearWiseChild SET MonthPayment4=@Payment,MonthAdjustment4=@AdjustmentChild,MonthWriteOff4=@WriteOffChild WHERE Id=@CPAReportMonthYearWiseChildId
				IF(@TempPaymentMonthId=5)
					UPDATE CPAReportMonthYearWiseChild SET MonthPayment5=@Payment,MonthAdjustment5=@AdjustmentChild,MonthWriteOff5=@WriteOffChild WHERE Id=@CPAReportMonthYearWiseChildId
				IF(@TempPaymentMonthId=6)
					UPDATE CPAReportMonthYearWiseChild SET MonthPayment6=@Payment,MonthAdjustment6=@AdjustmentChild,MonthWriteOff6=@WriteOffChild WHERE Id=@CPAReportMonthYearWiseChildId
				IF(@TempPaymentMonthId=7)
					UPDATE CPAReportMonthYearWiseChild SET MonthPayment7=@Payment,MonthAdjustment7=@AdjustmentChild,MonthWriteOff7=@WriteOffChild WHERE Id=@CPAReportMonthYearWiseChildId
				IF(@TempPaymentMonthId=8)
					UPDATE CPAReportMonthYearWiseChild SET MonthPayment8=@Payment,MonthAdjustment8=@AdjustmentChild,MonthWriteOff8=@WriteOffChild WHERE Id=@CPAReportMonthYearWiseChildId
				IF(@TempPaymentMonthId=9)
					UPDATE CPAReportMonthYearWiseChild SET MonthPayment9=@Payment,MonthAdjustment9=@AdjustmentChild,MonthWriteOff9=@WriteOffChild WHERE Id=@CPAReportMonthYearWiseChildId
				IF(@TempPaymentMonthId=10)
					UPDATE CPAReportMonthYearWiseChild SET MonthPayment10=@Payment,MonthAdjustment10=@AdjustmentChild,MonthWriteOff10=@WriteOffChild WHERE Id=@CPAReportMonthYearWiseChildId
				IF(@TempPaymentMonthId=11)
					UPDATE CPAReportMonthYearWiseChild SET MonthPayment11=@Payment,MonthAdjustment11=@AdjustmentChild,MonthWriteOff11=@WriteOffChild WHERE Id=@CPAReportMonthYearWiseChildId
				IF(@TempPaymentMonthId=12)
					UPDATE CPAReportMonthYearWiseChild SET MonthPayment12=@Payment,MonthAdjustment12=@AdjustmentChild,MonthWriteOff12=@WriteOffChild WHERE Id=@CPAReportMonthYearWiseChildId


				SET @PaymentStartDate=DATEADD(MONTH,1,@PaymentStartDate)
			END

			SELECT @CPAReportId=MIN(Id) FROM CPAReportMonthYearWise (NOLOCK) WHERE CAST(CreatedDate AS DATE)=CAST(GETDATE() AS DATE)
			AND Id>@CPAReportId
		END

END

GO

CREATE PROCEDURE [dbo].[usp_DenialManagementAgingCount]            
@FromDays  INT=NULL,      
@ToDays   INT=NULL,      
@CategoryID  INT=NULL,      
@UserName  VARCHAR(15)=NULL,      
@IsFollowing BIT=NULL,      
@FromAmount  FLOAT=NULL,      
@ToAmount  FLOAT=NULL,      
@TabLabel VARCHAR(15)=NULL      
as      
BEGIN      
    WITH Payments AS              
    (              
			  SELECT Distinct ChargeNo,           
			  Sum(Amount)ChargeAmount,             
				--IsPayment,              
			  SUM(TotalPaidAmount) TPayment  
			  from   vw_GetChargeForPendingPayment V  
			  where v.IsDeleted<>1
			  Group By ChargeNo  
			  ),              
                  
			BLC  AS              
			(              
		      SELECT DISTINCT ChargeNo[ChargeNo],  BLC.BillFromDate[DosDate],PT.Id[Account#],BLC.Amount
			  FROM Charge (NOLOCK)BLC
			  INNER JOIN PatientCase (NOLOCK)BC ON BC.Id=BLC.PatientCaseId
			  INNER JOIN Patient (NOLOCK)PT ON PT.Id=BC.PatientID
			  INNER JOIN Invoice (NOLOCK)I ON I.Id=BLC.InvoiceId     
			  INNER JOIN InsurancePolicy inc on inc.PatientCaseId = BLC.PatientCaseId AND     
			  inc.PlanExpirationDate >= I.BillFromDate     
				AND (    
					 (inc.InsuranceLevel = 1 AND  BLC.DueByFlagCD = 'PRIMARY')     
					 OR (inc.InsuranceLevel = 2 AND BLC.DueByFlagCD = 'SECONDARY')     
					 OR (inc.InsuranceLevel = 3 AND BLC.DueByFlagCD = 'TERNARY')    
					)    
			   INNER JOIN InsuranceCompany (NOLOCK)INS ON INS.Id=inc.InsuranceCompanyId    
			   INNER JOIN ConfigInsuranceCompanyType (NOLOCK)cict ON INS.CompanyTypeId=cict.Id    
			   LEFT JOIN PaymentCharge(NOLOCK) pc on BLC.Id = pc.ChargeId
			   LEFT JOIN Payment(NOLOCK) p on p.Id = pc.PaymentId
			   LEFT JOIN Voucher(NOLOCK) v on v.Id = p.VoucherId and v.IsCommitted = 1
			   LEFT JOIN ActionNote ACN ON ACN.ChargeId=BLC.Id
			   LEFT JOIN DenialQueue MID ON MID.LastNoteId=ACN.Id
			   LEFT JOIN ActionCategory X ON X.Id=ACN.ActionCategoryId
			   WHERE BLC.IsDeleted<> 1
			  AND (@FromDays IS NULL OR (DATEDIFF(DAY, BLC.BillFromDate, GETDATE())>=@FromDays AND DATEDIFF(DAY, BLC.BillFromDate, GETDATE())<=@ToDays))                
		   -- (DATEDIFF(DAY, ISNULL(BLC.EntryDate, BLC.BillFromDate), GETDATE())>=@FromDays AND DATEDIFF(DAY, ISNULL(BLC.EntryDate, BLC.BillFromDate), GETDATE())<=@ToDays))                       
			  AND (X.Id =@CategoryID OR @CategoryID IS NULL)
			  AND (@UserName IS NULL OR MID.AssignedTo=@UserName)
			  AND (@IsFollowing IS NULL OR MID.HasFollowUp=@IsFollowing)
			--ORDER BY BLC.ChgNo DESC                    
    ),
              
    BLWithPayment AS              
    (              
			SELECT  BLC.*,               
			BLC.Amount-(ISNULL( PaidAmount.TPayment,0)+ ISNULL(AdjAmount.TPayment,0)) BalanceAmount
			FROM BLC
			LEFT JOIN Payments PaidAmount ON PaidAmount.ChargeNo=BLC.ChargeNo -- AND PaidAmount.IsPayment=1              
			LEFT JOIN Payments AdjAmount ON AdjAmount.ChargeNo=BLC.ChargeNo -- AND AdjAmount.IsPayment=0              
	),              
	
	BLResp AS              
	(              
			SELECT BLC.*            
			FROM BLWithPayment BLC              
			WHERE BalanceAmount>0              
	)              
              
			SELECT ISNULL(COUNT(DISTINCT [Account#]),0) [AccountCount], ISNULL(SUM(BalanceAmount),0) BalanceAmount,            
			(CAST(@FromDays AS VARCHAR(3))+'-'+CAST(@ToDays AS VARCHAR(3)))  Tag,            
			@FromDays FromDays,            
			@ToDays ToDays,            
			@TabLabel TabLabel            
            
		  FROM  BLResp              
		  WHERE (@FromAmount IS NULL OR BalanceAmount>=@FromAmount)              
			AND (@ToAmount IS NULL OR BalanceAmount<=@ToAmount)              
                
END

GO

CREATE PROCEDURE [dbo].[usp_DenialManagementAgingCountAfterFilter]              
@FromDays  INT=NULL,                  
@ToDays   INT=NULL,                  
@CategoryID  INT=NULL,                  
@UserName  VARCHAR(15)=NULL,                  
@IsFollowing BIT=NULL,                
@FromAmount  FLOAT=NULL,                
