as                
BEGIN                   
              
    WITH Payments AS                
    (                
			SELECT Distinct ChargeNo,             
			Sum(Amount)ChargeAmount,               
			--IsPayment,                
			SUM(TotalPaidAmount) TPayment                 
			from   vw_GetChargeForPendingPayment V              
			where v.IsDeleted <> 1                
			Group By ChargeNo            
    ),                
                    
    BLC  AS                
    (                
			SELECT DISTINCT ChargeNo[ChargeNo],  BLC.BillFromDate[DosDate],PT.Id[Account#],BLC.Amount, BLC.Id     
			FROM Charge (NOLOCK)BLC      
			INNER JOIN PatientCase (NOLOCK)BC ON BC.Id=BLC.PatientCaseId      
			INNER JOIN Patient (NOLOCK)PT ON PT.Id=BC.PatientID   
			INNER JOIN Invoice (NOLOCK)I ON I.Id=BLC.InvoiceId     
			INNER JOIN InsurancePolicy inc on inc.PatientCaseId = BLC.PatientCaseId AND     
			inc.PlanExpirationDate >= I.BillFromDate     
			AND (    
				 (inc.InsuranceLevel = 1 AND  BLC.DueByFlagCD = 'PRIMARY')     
				 OR (inc.InsuranceLevel = 2 AND BLC.DueByFlagCD = 'SECONDARY')     
				 OR (inc.InsuranceLevel = 3 AND BLC.DueByFlagCD = 'TERNARY')    
				)    
			INNER JOIN InsuranceCompany (NOLOCK)INS ON INS.Id=inc.InsuranceCompanyId    
			INNER JOIN ConfigInsuranceCompanyType (NOLOCK)cict ON INS.CompanyTypeId=cict.Id    
			LEFT JOIN PaymentCharge(NOLOCK) pc on BLC.Id = pc.ChargeId
			LEFT JOIN Payment(NOLOCK) p on p.Id = pc.PaymentId
			LEFT JOIN Voucher(NOLOCK) v on v.Id = p.VoucherId and v.IsCommitted = 1
			LEFT JOIN ActionNote ACN ON ACN.ChargeId=BLC.Id
			LEFT JOIN DenialQueue MID ON MID.LastNoteId=ACN.Id
			LEFT JOIN ActionCategory X ON X.Id=ACN.ActionCategoryId
			WHERE BLC.IsDeleted <> 1
			AND (@FromDays IS NULL OR (DATEDIFF(DAY, BLC.BillFromDate, GETDATE())>=@FromDays AND DATEDIFF(DAY, BLC.BillFromDate, GETDATE())<=@ToDays))      
			AND (X.Id =@CategoryID OR @CategoryID IS NULL)      
			AND (@UserName IS NULL OR MID.AssignedTo=@UserName)      
			AND (@IsFollowing IS NULL OR MID.HasFollowUp=@IsFollowing)      
    --ORDER BY BLC.ChgNo DESC                      
    ),                
                
    BLWithPayment AS                
    (                
			SELECT  BLC.*,BLC.Id [ChargeId],                
			BLC.Amount-(ISNULL( PaidAmount.TPayment,0)+ ISNULL(AdjAmount.TPayment,0)) BalanceAmount                
			FROM BLC                   
			LEFT JOIN Payments PaidAmount ON PaidAmount.ChargeNo=BLC.ChargeNo -- AND PaidAmount.IsPayment=1                
			LEFT JOIN Payments AdjAmount ON AdjAmount.ChargeNo=BLC.ChargeNo -- AND AdjAmount.IsPayment=0                
    ),                
    BLResp AS                
    (                
			SELECT BLC.*              
			FROM BLWithPayment BLC                
			WHERE BalanceAmount > 0                
    )                
                
    --SELECT ISNULL(COUNT(DISTINCT [Account#]),0) [AccountCount], ISNULL(SUM(BalanceAmount),0) BalanceAmount,              
    --(CAST(@FromDays AS VARCHAR(3))+'-'+CAST(@ToDays AS VARCHAR(3)))  Tag,              
    --@FromDays FromDays,              
    --@ToDays ToDays,              
    --@TabLabel TabLabel              
        
    SELECT DISTINCT ChargeId [AccountCount],    
	SUM(BalanceAmount) BalanceAmount,    
    (CAST(@FromDays AS VARCHAR(3))+'-'+CAST(@ToDays AS VARCHAR(3)))  Tag,         
    @FromDays FromDays,              
    @ToDays ToDays,              
    @TabLabel TabLabel              
    FROM  BLResp                
    WHERE (@FromAmount IS NULL OR BalanceAmount>=@FromAmount)                
    AND (@ToAmount IS NULL OR BalanceAmount<=@ToAmount)      
	GROUP BY ChargeId    
END

