CREATE PROCEDURE [dbo].[usp_DenialManagementAgingCountForDenailAdjustment]          
 --@FromDays  INT=NULL,              
 --@ToDays   INT=NULL,              
 --@CategoryID  INT=NULL,              
 --@UserName  VARCHAR(15)=NULL,              
 --@IsFollowing BIT=NULL,            
 --@FromAmount  FLOAT=NULL,            
 --@ToAmount  FLOAT=NULL,               
 --@TabLabel VARCHAR(15)=NULL          
AS    
BEGIN               
          
    WITH Payments AS            
    (            
  SELECT DISTINCT ChargeNo,Sum(Amount)ChargeAmount,SUM(TotalPaidAmount) TPayment, V.Id           
   FROM vw_GetChargeForPendingPayment V          
  WHERE v.IsDeleted <> 1    
  Group By ChargeNo, V.Id    
    ),           
                
    BLC  AS            
    (            
   SELECT ChargeNo [ChargeNo], BLC.BillFromDate[DosDate],PT.Id[Account#],BLC.Amount, pc.Id,pa.IsDenial, v.IsSelfPayment , pa.ReasonCode, pa.Amount [AdjustmentAmount]              
   FROM Charge (NOLOCK)BLC              
   INNER JOIN PatientCase (NOLOCK)BC ON BC.Id=BLC.PatientCaseId              
   INNER JOIN Patient (NOLOCK)PT ON PT.Id=BC.PatientID     
   LEFT JOIN PaymentCharge(NOLOCK) pc on BLC.Id = pc.ChargeId                       
   LEFT JOIN Payment(NOLOCK) p on p.Id = pc.PaymentId      
   LEFT JOIN Voucher(NOLOCK) v on v.Id = p.VoucherId and v.IsCommitted = 1    
   INNER JOIN PaymentAdjustment(NOLOCK) pa on pa.PaymentChargeId = pc.Id     

  WHERE BLC.IsDeleted <> 1 AND  pa.IsAccounted = 1 AND  pa.IsDenial = 1 -- AND (BLC.Amount - (p.Amount + p.Adjustment)) > 0    

    ),            
            
    BLWithPayment AS            
    (            
  SELECT  BLC.*,(ISNULL(BLC.Amount,0)-(ISNULL( PaidAmount.TPayment,0)+ ISNULL(AdjAmount.TPayment,0))) BalanceAmount            
   FROM BLC               
  LEFT JOIN Payments PaidAmount ON PaidAmount.ChargeNo=BLC.ChargeNo -- AND PaidAmount.IsSelfPayment=1            
  LEFT JOIN Payments AdjAmount ON AdjAmount.ChargeNo=BLC.ChargeNo  --AND AdjAmount.IsSelfPayment=1      
    ),            
    BLResp AS            
    (            
  SELECT BLC.*  FROM BLWithPayment BLC WHERE BalanceAmount>0            
    )            
            
    SELECT ISNULL(COUNT(DISTINCT Account#),0) [AccountCount], ISNULL(SUM(BalanceAmount),0) BalanceAmount, BLResp.ReasonCode, SUM(AdjustmentAmount) [AdjustmentAmount]    
   --,(CAST(@FromDays AS VARCHAR(3))+'-'+CAST(@ToDays AS VARCHAR(3)))  Tag,@FromDays FromDays,          
   --@ToDays ToDays,@TabLabel TabLabel          
  FROM  BLResp            
  Group By BLResp.ReasonCode    
 --WHERE (@FromAmount IS NULL OR BalanceAmount>=@FromAmount)            
 --   AND (@ToAmount IS NULL OR BalanceAmount<=@ToAmount)            
END

GO

