    BLC  AS          
    (          
  SELECT ChargeNo [ChargeNo],  BLC.BillFromDate[DosDate],PT.Id[Account#],BLC.Amount, pc.Id,pa.IsDenial, v.IsSelfPayment , 
		 pa.ReasonCode, pa.Amount [AdjustmentAmount], BLC.Id [ChargeId]
   FROM Charge (NOLOCK)BLC            
   INNER JOIN PatientCase (NOLOCK)BC ON BC.Id=BLC.PatientCaseId            
   INNER JOIN Patient (NOLOCK)PT ON PT.Id=BC.PatientID   
   LEFT JOIN PaymentCharge(NOLOCK) pc on BLC.Id = pc.ChargeId                     
   LEFT JOIN Payment(NOLOCK) p on p.Id = pc.PaymentId    
   LEFT JOIN Voucher(NOLOCK) v on v.Id = p.VoucherId and v.IsCommitted = 1  
   INNER JOIN PaymentAdjustment(NOLOCK) pa on pa.PaymentChargeId = pc.Id   
   --LEFT JOIN ActionNote ACN ON ACN.ChargeId=BLC.Id      
   --LEFT JOIN DenialQueue MID ON MID.LastNoteId=ACN.Id      
   --LEFT JOIN ActionCategory X ON X.Id=ACN.ActionCategoryId  
   --LEFT JOIN ARSCategoryReasonCode arsc on arsc.NotesCategoryId = ACN.Id        
  WHERE BLC.IsDeleted <> 1 AND  pa.IsAccounted = 1 AND  pa.IsDenial = 1  
  --AND (@FromDays IS NULL OR (DATEDIFF(DAY, BLC.BillFromDate, GETDATE())>=@FromDays AND DATEDIFF(DAY, BLC.BillFromDate, GETDATE())<=@ToDays))            
  --AND (X.Id =@CategoryID OR @CategoryID IS NULL) AND (@UserName IS NULL OR MID.AssignedTo=@UserName)            
  --AND (@IsFollowing IS NULL OR MID.HasFollowUp=@IsFollowing)            
    ),          
          
    BLWithPayment AS          
    (          
  SELECT  BLC.*,(ISNULL(BLC.Amount,0)-(ISNULL( PaidAmount.TPayment,0)+ ISNULL(AdjAmount.TPayment,0))) BalanceAmount , BLC.ChargeId [ChargesId]         
   FROM BLC             
  LEFT JOIN Payments PaidAmount ON PaidAmount.ChargeNo=BLC.ChargeNo -- AND PaidAmount.IsSelfPayment=1          
  LEFT JOIN Payments AdjAmount ON AdjAmount.ChargeNo=BLC.ChargeNo  --AND AdjAmount.IsSelfPayment=1    
    ),          
    BLResp AS          
    (          
  SELECT BLC.*  FROM BLWithPayment BLC WHERE BalanceAmount>0          
    )          
          
    SELECT DISTINCT ChargesId [AccountCount], ISNULL(SUM(BalanceAmount),0) BalanceAmount, BLResp.ReasonCode, SUM(AdjustmentAmount) [AdjustmentAmount]  
   --,(CAST(@FromDays AS VARCHAR(3))+'-'+CAST(@ToDays AS VARCHAR(3)))  Tag,@FromDays FromDays,        
   --@ToDays ToDays,@TabLabel TabLabel        
  FROM  BLResp          
  Group By BLResp.ReasonCode , ChargesId 
 --WHERE (@FromAmount IS NULL OR BalanceAmount>=@FromAmount)          
 --   AND (@ToAmount IS NULL OR BalanceAmount<=@ToAmount)          
END

