CREATE PROCEDURE [dbo].[usp_DenialManagementAgingCountForInsuranceCompany]          
 --@FromDays  INT=NULL,              
 --@ToDays   INT=NULL,              
 --@CategoryID  INT=NULL,              
 --@UserName  VARCHAR(15)=NULL,              
 --@IsFollowing BIT=NULL,            
 --@FromAmount  FLOAT=NULL,            
 --@ToAmount  FLOAT=NULL,               
 --@TabLabel VARCHAR(15)=NULL          
AS    
BEGIN               
          
    WITH Payments AS            
    (            
	  SELECT DISTINCT V.ChargeNo,Sum(V.Amount)ChargeAmount,SUM(V.TotalPaidAmount) TPayment-- , V.IsSelfPayment --, inc.InsuranceCompanyId           
	  FROM vw_GetChargeForPendingPayment V    
	  WHERE v.IsDeleted <> 1 --AND v.IsSelfPayment = 0    
	  Group By V.ChargeNo--, V.IsSelfPayment      
    ),           
                
    BLC  AS            
    (            
	   SELECT ChargeNo[ChargeNo],  BLC.BillFromDate[DosDate],PT.Id[Account#],BLC.Amount, ins.CompanyName, BLC.Id             
	   FROM Charge (NOLOCK)BLC              
	   INNER JOIN PatientCase (NOLOCK)BC ON BC.Id=BLC.PatientCaseId              
	   INNER JOIN Patient (NOLOCK)PT ON PT.Id=BC.PatientID     
	   INNER JOIN Invoice (NOLOCK)I ON I.Id=BLC.InvoiceId     
	   INNER JOIN InsurancePolicy inc on inc.PatientCaseId = BLC.PatientCaseId AND     
	   inc.PlanExpirationDate >= I.BillFromDate     
	   AND (    
		(inc.InsuranceLevel = 1 AND  BLC.DueByFlagCD = 'PRIMARY')     
		OR (inc.InsuranceLevel = 2 AND BLC.DueByFlagCD = 'SECONDARY')     
		OR (inc.InsuranceLevel = 3 AND BLC.DueByFlagCD = 'TERNARY')    
		)    
	   INNER JOIN InsuranceCompany (NOLOCK)INS ON INS.Id=inc.InsuranceCompanyId    
	   LEFT JOIN PaymentCharge(NOLOCK) pc on BLC.Id = pc.ChargeId      
	   LEFT JOIN Payment(NOLOCK) p on p.Id = pc.PaymentId      
	   LEFT JOIN Voucher(NOLOCK) v on v.Id = p.VoucherId and v.IsCommitted = 1                                     
	   WHERE BLC.IsDeleted <> 1 AND v.IsSelfPayment = 0              
    ),            
            
    BLWithPayment AS            
    (            
	  SELECT  BLC.*,(ISNULL(BLC.Amount,0)-(ISNULL( PaidAmount.TPayment,0)+ ISNULL(AdjAmount.TPayment,0))) BalanceAmount            
	  FROM BLC               
	  LEFT JOIN Payments PaidAmount ON PaidAmount.ChargeNo=BLC.ChargeNo -- AND PaidAmount.IsSelfPayment=1            
	  LEFT JOIN Payments AdjAmount ON AdjAmount.ChargeNo=BLC.ChargeNo  --AND AdjAmount.IsSelfPayment=1      
    ),    
    BLResp AS            
    (            
	  SELECT BLC.*  FROM BLWithPayment BLC WHERE BalanceAmount>0            
    )            
            
     SELECT ISNULL(COUNT(DISTINCT [Account#]),0) [AccountCount], ISNULL(SUM(BalanceAmount),0) BalanceAmount, CompanyName         
	 FROM  BLResp     
	 Group By CompanyName                 
END

