CREATE PROCEDURE [dbo].[usp_DenialManagementForCompanyType]                  
AS            
BEGIN                       
                  
    WITH Payments AS                    
    (                    
   SELECT DISTINCT ChargeNo,Sum(Amount)ChargeAmount,SUM(TotalPaidAmount) TPayment, V.Id    
   FROM vw_GetChargeForPendingPaymentForDenial V            
   WHERE v.IsDeleted <> 1    
   Group By ChargeNo, V.Id    
    ),                   
                        
    BLC  AS                    
    (                    
    SELECT ChargeNo[ChargeNo],  BLC.BillFromDate[DosDate],PT.Id[Account#],BLC.Amount, cict.CompanyType, BLC.Id                      
    FROM Charge (NOLOCK)BLC                      
    INNER JOIN PatientCase (NOLOCK)BC ON BC.Id=BLC.PatientCaseId                      
    INNER JOIN Patient (NOLOCK)PT ON PT.Id=BC.PatientID             
    INNER JOIN Invoice (NOLOCK)I ON I.Id=BLC.InvoiceId  
    LEFT JOIN InsurancePolicy inc on inc.PatientCaseId = BLC.PatientCaseId AND               
       ISNULL(inc.PlanExpirationDate, GETDATE()) >= I.BillFromDate               
       AND (              
       (inc.InsuranceLevel = 1 AND  BLC.DueByFlagCD = 'PRIMARY')               
       OR (inc.InsuranceLevel = 2 AND BLC.DueByFlagCD = 'SECONDARY')               
       OR (inc.InsuranceLevel = 3 AND BLC.DueByFlagCD = 'TERNARY')              
       )             
    INNER JOIN InsuranceCompany (NOLOCK)INS ON INS.Id=inc.InsuranceCompanyId  
    INNER JOIN ConfigInsuranceCompanyType (NOLOCK)cict ON INS.CompanyTypeId=cict.Id  
    --LEFT JOIN PaymentCharge(NOLOCK) pc on BLC.Id = pc.ChargeId      
    --LEFT JOIN Payment(NOLOCK) p on p.Id = pc.PaymentId      
    --LEFT JOIN Voucher(NOLOCK) v on v.Id = p.VoucherId      
    --INNER JOIN InsuranceCompany (NOLOCK)INS ON INS.Id=v.InsuranceCompanyId      
    --INNER JOIN ConfigInsuranceCompanyType (NOLOCK)cict ON INS.CompanyTypeId=cict.Id                                 
    WHERE BLC.IsDeleted <> 1    
    ),                    
                    
    BLWithPayment AS                    
    (                    
   SELECT  BLC.*,(ISNULL(BLC.Amount,0)-(ISNULL( PaidAmount.TPayment,0)+ ISNULL(AdjAmount.TPayment,0))) BalanceAmount                    
   FROM BLC                       
   LEFT JOIN Payments PaidAmount ON PaidAmount.ChargeNo=BLC.ChargeNo -- AND PaidAmount.IsSelfPayment=1                    
   LEFT JOIN Payments AdjAmount ON AdjAmount.ChargeNo=BLC.ChargeNo  --AND AdjAmount.IsSelfPayment=1              
    ),                    
    BLResp AS                    
    (                    
   SELECT BLC.*  FROM BLWithPayment BLC WHERE BalanceAmount>0                    
    )                    
                    
    SELECT ISNULL(COUNT(DISTINCT [Account#]),0) [AccountCount], ISNULL(SUM(BalanceAmount),0) BalanceAmount, CompanyType    
    FROM  BLResp  
    Group By CompanyType  
     
END

