CREATE PROCEDURE [dbo].[usp_DenialManagementForTotalAdjustment]                      
AS                
BEGIN                           
                      
    WITH Payments AS                        
    (                        
    SELECT DISTINCT ChargeNo,Sum(Amount)ChargeAmount,SUM(TotalPaidAmount) TPayment, V.Id                       
    FROM vw_GetChargeForPendingPaymentForDenial V                      
    WHERE v.IsDeleted <> 1                
    Group By ChargeNo, V.Id                
    ),                       
                            
    BLC  AS                        
    (                        
  SELECT ChargeNo [ChargeNo], BLC.BillFromDate[DosDate],PT.Id[Account#] ,BLC.Amount,pa.IsDenial, pa.ReasonCode,         
  pa.Amount [AdjustmentAmount]                          
  FROM Charge (NOLOCK)BLC                          
  INNER JOIN PatientCase (NOLOCK)BC ON BC.Id=BLC.PatientCaseId                          
  INNER JOIN Patient (NOLOCK)PT ON PT.Id=BC.PatientID                 
  LEFT JOIN PaymentCharge(NOLOCK) pc on BLC.Id = pc.ChargeId                                   
  --LEFT JOIN Payment(NOLOCK) p on p.Id = pc.PaymentId                  
  --LEFT JOIN Voucher(NOLOCK) v on v.Id = p.VoucherId                 
  INNER JOIN PaymentAdjustment(NOLOCK) pa on pa.PaymentChargeId = pc.Id AND pa.IsDenial = 1                
  WHERE BLC.IsDeleted <> 1 AND  pa.IsAccounted = 1 AND  pa.IsDenial = 1        
    ),                        
                        
    BLWithPayment AS                        
    (                        
    SELECT  BLC.*,(ISNULL(BLC.Amount,0)-(ISNULL( PaidAmount.TPayment,0)+ ISNULL(AdjAmount.TPayment,0))) BalanceAmount                        
    FROM BLC                           
    LEFT JOIN Payments PaidAmount ON PaidAmount.ChargeNo=BLC.ChargeNo -- AND PaidAmount.IsSelfPayment=1                        
    LEFT JOIN Payments AdjAmount ON AdjAmount.ChargeNo=BLC.ChargeNo  --AND AdjAmount.IsSelfPayment=1                  
    ),                        
    BLResp AS                        
    (                        
   SELECT BLC.*  FROM BLWithPayment BLC WHERE BalanceAmount>0                        
    ),    
 BLGROUP AS     
 (    
   SELECT bl.ReasonCode , ISNULL(COUNT(ChargeNo),0) [AccountCount]    
   , ISNULL(BalanceAmount,0) BalanceAmount    
   , SUM(AdjustmentAmount) [AdjustmentAmount] FROM BLResp bl     
   GROUP BY bl.ReasonCode, BalanceAmount    
 )    
             
    SELECT  bl.ReasonCode , ISNULL(COUNT(AccountCount),0) [AccountCount], ISNULL(SUM(BalanceAmount),0) BalanceAmount, SUM(AdjustmentAmount) [AdjustmentAmount]    
    FROM  BLGROUP  bl    
    Group By bl.ReasonCode                        
                        
    --SELECT  bl.ReasonCode , ISNULL(COUNT(DISTINCT Account#),0) [AccountCount], ISNULL(SUM(BalanceAmount),0) BalanceAmount, SUM(AdjustmentAmount) [AdjustmentAmount]                  
    --FROM  BLResp  bl    
    --Group By bl.ReasonCode    
END

GO

CREATE PROCEDURE [dbo].[usp_DenialManagementForTotalAdjustmentCharges]        
--@FilterInput NVARCHAR(20)              
AS            
BEGIN                       
                  
    WITH Payments AS                    
    (                    
  SELECT DISTINCT ChargeNo,Sum(Amount)ChargeAmount,SUM(TotalPaidAmount) TPayment, V.Id                   
  FROM vw_GetChargeForPendingPaymentForDenial V                  
  WHERE v.IsDeleted <> 1            
  Group By ChargeNo, V.Id            
    ),                   
                        
    BLC  AS                    
    (                    
    SELECT ChargeNo [ChargeNo],  BLC.BillFromDate[DosDate],PT.Id[Account#],BLC.Amount, pc.Id,pa.IsDenial,          
    pa.ReasonCode, pa.Amount [AdjustmentAmount], BLC.Id [ChargeId]          
    FROM Charge (NOLOCK)BLC                      
    INNER JOIN PatientCase (NOLOCK)BC ON BC.Id=BLC.PatientCaseId                      
    INNER JOIN Patient (NOLOCK)PT ON PT.Id=BC.PatientID             
    LEFT JOIN PaymentCharge(NOLOCK) pc on BLC.Id = pc.ChargeId                               
    INNER JOIN PaymentAdjustment(NOLOCK) pa on pa.PaymentChargeId = pc.Id             
    WHERE BLC.IsDeleted <> 1 AND  pa.IsAccounted = 1 AND  pa.IsDenial = 1            
    ),                    
                    
    BLWithPayment AS                    
    (                    
   SELECT  BLC.*,(ISNULL(BLC.Amount,0)-(ISNULL( PaidAmount.TPayment,0)+ ISNULL(AdjAmount.TPayment,0))) BalanceAmount , BLC.ChargeId [ChargesId]                   
   FROM BLC                       
   LEFT JOIN Payments PaidAmount ON PaidAmount.ChargeNo=BLC.ChargeNo -- AND PaidAmount.IsSelfPayment=1                    
   LEFT JOIN Payments AdjAmount ON AdjAmount.ChargeNo=BLC.ChargeNo  --AND AdjAmount.IsSelfPayment=1              
    ),  
    BLResp AS  
    (  
    SELECT BLC.*  FROM BLWithPayment BLC WHERE BalanceAmount>0  
    )  
                    
     SELECT DISTINCT ChargesId [AccountCount], ISNULL(BalanceAmount,0) BalanceAmount, SUM(AdjustmentAmount) [AdjustmentAmount],  
     dbo.tfn_PmtAdjustmentReasonCode(ChargesId)[ReasonCode]  
     FROM  BLResp    bl          
     Group By ChargesId, BalanceAmount  
END

GO


CREATE PROCEDURE [dbo].[usp_dos]
(@StartDate DATE,      
 @EndDate   DATE      
)      
AS      
         BEGIN      
             CREATE TABLE #TempData      
(AcctNo       NUMERIC(18, 0),      
 PatientName  NVARCHAR(500),      
 ProviderName NVARCHAR(500),      
 CompanyId    NUMERIC(18, 0),      
 CompanyName  NVARCHAR(500),      
 DOS          DATE,      
 CPTCode      NVARCHAR(50),      
 Modifiers    NVARCHAR(50),      
 ChargeAmt    NUMERIC(18, 2),      
 PriDX        NVARCHAR(50),      
 POS          NVARCHAR(50),      
 ChargeNo     NUMERIC(18, 0),      
 Payments     NUMERIC(18, 2),      
 Adjustments  NUMERIC(18, 2),      
 PaymentBat   NVARCHAR(100),      
 PostDate     DATE,    
 ProviderId   Int      
);      
             INSERT INTO #TempData      
(AcctNo,      
 PatientName,      
 ProviderName,      
 CompanyId,      
 CompanyName,      
 DOS,      
 CPTCode,      
 Modifiers,      
 ChargeAmt,      
 PriDX,      
 POS,      
 ChargeNo,      
 Payments,      
 Adjustments,      
 PaymentBat,      
 PostDate,    
 ProviderId      
)      
                    SELECT D.Id [PatientID],      
                           CONCAT(D.LastName, ', ', D.FirstName, ' ', D.MI) [PatientName],      
                           CONCAT(E.LastName, ', ', E.FirstName),
                           dbo.ufn_ActiveInsuranceForCaseNo(A.BillFromDate, 1, C.Id),      
                           '',      
                            A.BillFromDate,      
                           A.CPTCode [CPT],      
                           CONCAT(A.Mod1, A.Mod2, A.Mod3, A.Mod4) [Mods],      
                           A.Amount,      
                           H.ICDCode [PriDx],      
                           I.Description [POS],      
                           A.ChargeNo,      
                           0,      
                           0,      
                           '',      
                           A.EntryDate,    
         E.Id AS ProviderID        
                    FROM vw_CHARGE_Latest A  (NOLOCK)    
                         INNER JOIN Invoice B (NOLOCK) ON A.InvoiceId = B.Id      
                         JOIN PatientCase C (NOLOCK) ON C.Id = B.PatientCaseId      
                         JOIN Patient D(NOLOCK) ON C.PatientId = D.Id      
                         --JOIN [user] E(NOLOCK) ON D.ProviderID = E.UserID      
						 LEFT JOIN [Provider] E(NOLOCK) ON A.PerformingProviderId = E.Id      
                         LEFT JOIN InvDiagnosis H(NOLOCK) ON H.InvoiceId = B.Id      
                                                     
                         LEFT JOIN ConfigPOS I(NOLOCK) ON I.Code = A.POSId      
                    WHERE CAST(A.BillFromDate AS DATE) BETWEEN @StartDate AND @EndDate
				AND A.IsDeleted = 0 AND A.ChargeNo > 0 AND A.PatientCaseId > 0;      
             UPDATE #TempData      
               SET      
                   CompanyName = J.CompanyName      
             FROM #TempData I      
                  LEFT JOIN InsuranceCompany J (NOLOCK) ON I.CompanyId = J.Id;      
             UPDATE #TempData      
               SET      
                   Payments = J.Payments      
             FROM #TempData I      
                  JOIN      
(      
    SELECT X.acctno,      
           x.PatientName,      
           x.ProviderName,      
           X.CompanyId,      
           x.DOS,      
           x.CPTCode,      
           x.Modifiers,      
           x.ChargeAmt,      
           x.PriDx,      
           x.POS,      
           x.ChargeNo,      
           isnull(SUM(Z.PaymentOrAdjAmount), 0) [Payments]      
    FROM #TempData X      
         LEFT JOIN vw_PaymentsAdjustments Z (NOLOCK) ON Z.ChargeNum = X.ChargeNo                                                          
            AND z.IsDeleted =0 AND Z.ChargeNum > 0 AND Z.PatientCaseId > 0 AND Z.IsPayment = 1
    GROUP BY X.acctno,      
   x.PatientName,      
             x.ProviderName,      
             X.CompanyId,      
             x.DOS,      
             x.CPTCode,      
             x.Modifiers,      
             x.ChargeAmt,      
             x.PriDx,      
             x.POS,      
             x.ChargeNo      
) J ON I.ChargeNo = J.ChargeNo;      
             UPDATE #TempData      
               SET      
                   Adjustments = J.Payments      
             FROM #TempData I      
                  JOIN      
(      
    SELECT X.acctno,      
         x.PatientName,      
           x.ProviderName,      
           X.CompanyId,      
           x.DOS,      
           x.CPTCode,      
           x.Modifiers,      
           x.ChargeAmt,      
           x.PriDx,      
           x.POS,      
           x.ChargeNo,      
           isnull(SUM(Z.PaymentOrAdjAmount), 0) [Payments]      
   FROM #TempData X      
         LEFT JOIN vw_PaymentsAdjustments Z (NOLOCK) ON Z.ChargeNum = X.ChargeNo   
         AND z.IsDeleted = 0  AND Z.ChargeNum > 0 AND Z.PatientCaseId > 0 AND Z.IsPayment = 0
    GROUP BY X.acctno,      
             x.PatientName,      
             x.ProviderName,      
             X.CompanyId,      
             x.DOS,      
             x.CPTCode,      
             x.Modifiers,      
             x.ChargeAmt,      
             x.PriDx,      
             x.POS,      
             x.ChargeNo      
) J ON I.ChargeNo = J.ChargeNo;      
             SELECT *      
             FROM #TempData      
             ORDER BY acctno,      
                      DOS,      
                      CPTCode;      
         END




GO


CREATE  PROCEDURE [dbo].[usp_DOSDetailReport] @FromDate  DATETIME      = NULL,    
                                     @ToDate    DATETIME      = NULL,    
                                     @CPTCodes  VARCHAR(MAX) = NULL,    
                                     @Providers VARCHAR(MAX) = NULL    
AS    
         BEGIN    
             DECLARE @TempData AS TABLE    
(AcctNo       NUMERIC(18, 0),    
 PatientName  NVARCHAR(500),    
 ProviderName NVARCHAR(500),    
 CompanyId    NUMERIC(18, 0),    
 CompanyName  NVARCHAR(500),    
 DOS          DATE,    
 CPTCode      NVARCHAR(50),    
 Modifiers    NVARCHAR(50),    
 ChargeAmt    NUMERIC(18, 2),    
 PriDX        NVARCHAR(50),    
 POS          NVARCHAR(50),    
 ChargeNo     NUMERIC(18, 0),    
 Payments     NUMERIC(18, 2),    
 Adjustments  NUMERIC(18, 2),    
 PaymentBat   NVARCHAR(100),    
 PostDate     DATE,    
 ProviderId   INT    
);    
             INSERT INTO @TempData    
(AcctNo,    
 PatientName,    
 ProviderName,    
 CompanyId,    
 CompanyName,    
 DOS,    
 CPTCode,    
 Modifiers,    
 ChargeAmt,    
 PriDX,    
 POS,    
 ChargeNo,    
 Payments,    
 Adjustments,    
 PaymentBat,    
 PostDate,    
 ProviderId    
)    
             EXEC usp_dos    
                  @FromDate,    
                  @ToDate;    
             SELECT t.AcctNo,    
                    t.PatientName,    
                    t.ProviderName [Provider],    
                    t.CompanyName [PrimaryInsurance],    
                    CAST(t.DOS AS DATE) DOS,    
                    t.CPTCode [CPT],    
                    CONCAT(b.Mod1, b.Mod2, b.Mod3, b.Mod4) [Mods],    
                    t.ChargeAmt [Charge],    
                    t.PriDX,    
                    t.POS,    
                    t.ProviderId    
             FROM @TempData t    
                  LEFT JOIN vw_CHARGE_Latest b (NOLOCK) ON t.ChargeNo = b.ChargeNo    
             WHERE((t.ProviderId IN    
(    
    SELECT [Value]    
    FROM dbo.tfn_Split(@Providers, ',')    
)    
             OR @Providers IS NULL    
             OR @Providers = ''))    
                  AND ((t.CPTCode IN    
(    
    SELECT [Value]    
    FROM dbo.tfn_Split(@CPTCodes, ',')    
)    
             OR @CPTCodes IS NULL    
             OR @CPTCodes = ''));    
         END


		 

GO

CREATE PROCEDURE [dbo].[usp_FindScrubDataForPatientAndCharges]
(  
 @ClaimId INT NULL,  
 @ClaimBatchId INT NULL,  
 @UserId INT NULL,  
 @FacilityId SMALLINT NULL  
)  
AS  
 DECLARE @scrubSql NVARCHAR(MAX);  
 DECLARE @scrubId INT;  
 DECLARE @affectedRows INT = 0;  
  
  
;WITH Charges  
AS  
(  
   SELECT bch.EntryDate,bch.IsDeleted,bch.IsLocked,bch.PatientCaseId,  
     bch.InvoiceId,bch.BillToDate,bch.IsTaxable,bch.BillToInsurance,bch.CPTCode,  
     bch.Mod1,bch.Mod2,bch.Mod3,bch.Mod4,bch.Description,bch.NDCCode,bch.NDCFormat,bch.UnitOfMeasure,bch.DrugQty,  
     bch.TOSId,bch.POSId,bch.PerformingProviderId,bch.PerformingFacilityId,bch.Qty,  
     bch.MultiplyQty,bch.ChargeNo,bch.Discount,bch.Tax,bch.DueByFlagCD,
	CASE
    WHEN bch.BillToInsurance=1 THEN bch.Amount  
	END  as InsuranceCharge,  
	CASE
    WHEN bch.BillToInsurance=0 THEN bch.Amount  
	END  as PatientCharge,  
	bch.BillFromDate,bch.BillToPatient,bch.Deductible,bch.Copay,bch.ModifiedBy,bch.ModifiedDate,bch.Message1,bch.Message2  
   FROM ClaimBatch bb  
     JOIN Claim bc ON bc.ClaimBatchId = bb.ID  
     JOIN ClaimCharge bcs ON bc.Id = bcs.ClaimId   
     Join Charge  ch ON  Ch.Id = bcs.ChargeId  
     CROSS APPLY (SELECT TOP 1  
          bc2.*  
         FROM Charge bc2  
         WHERE bcs.ChargeId = bc2.Id AND  
          bc2.IsDeleted != 1  
         ORDER BY bc2.EntryDate DESC  
   
       ) bch  
   WHERE (@ClaimId IS NULL OR  
      @ClaimId = bc.Id) AND  
     (@claimBatchId IS NULL OR  
      @claimBatchId = bb.ID)  
  
)   
select * into #tmpCharges from  Charges  
  
;WITH PatientClaim  
AS  
(  
 SELECT pc.PatientId [PatientId], clm.InsuranceCompanyID, clmsvc.ClaimId, 
 c.ChargeNo,
 --clmsvc.FromDate,   
  clm.InvoiceId
  --clmsvc.ChargeNumber  
 FROM ClaimBatch bb   
 INNER JOIN Claim clm ON bb.ID = clm.ClaimBatchId  
 INNER JOIN ClaimCharge clmsvc ON clmsvc.ClaimId = clm.Id  
 Inner Join PatientCase pc ON pc.Id = clm.PatientCaseId
Inner JOin Charge c On c.Id = clmsvc.ChargeId
 WHERE (@ClaimId IS NULL OR  
      @ClaimId = clm.Id) AND  
     (@claimBatchId IS NULL OR  
      @claimBatchId = bb.ID)  
)  
SELECT Patient.*,PatientClaim.InvoiceId, PatientClaim.ChargeNo FROM Patient  
inner join PatientClaim ON Patient.Id = PatientClaim.PatientId  
WHERE Patient.Id IN (SELECT distinct PatientId FROM PatientClaim)  
  
SELECT * FROM #tmpCharges  
  
SELECT * FROM InvDiagnosis WHERE InvoiceID IN (SELECT DISTINCT InvoiceId FROM #tmpCharges)  
  
SELECT DISTINCT  
    bs.*, --(SELECT SettingValue FROM AppSetting WHERE SettingCd='ClinicCode') AS ClinicCode  
	''[ClinicCode]
  FROM Scrub bs  
    LEFT JOIN ScrubAssignment sa ON sa.ScrubId = bs.Id  
  WHERE (@FacilityId IS NULL OR  
     @FacilityId = sa.FacilityId) AND  
    (@UserId IS NULL OR  @UserId = sa.CheckoffUserId);

GO

CREATE PROCEDURE usp_GetActionNotesForCatalyst
AS
BEGIN
		SELECT B.CategoryName,ChargeId,Note,CASE WHEN ISNULL(A.HasFollowUp,0) =0 THEN 'No' ELSE 'Yes' END HasFollowUp,
		FollowUpDate,UserName AS CreatedBy,A.CreatedDate,'AUTUMNCLINIC'[Practice]
		 FROM PI_ATC_CLINIC.dbo.ActionNote A (NOLOCK) 
		 LEFT JOIN PI_ATC_CLINIC.dbo.ActionCategory B on B.Id=A.ActionSubCategoryId
		WHERE A.UserName!='System' AND A.NoteSourceCD='NS.CHARGE' AND ISNULL(A.IsTransfered,0)=0
		UNION
		SELECT B.CategoryName,ChargeId,Note,CASE WHEN ISNULL(A.HasFollowUp,0) =0 THEN 'No' ELSE 'Yes' END HasFollowUp,
		FollowUpDate,UserName AS CreatedBy,A.CreatedDate,'AUTUMNLAB'[Practice]
		 FROM PI_ATC_LAB.dbo.ActionNote A (NOLOCK) 
		 LEFT JOIN PI_ATC_LAB.dbo.ActionCategory B on B.Id=A.ActionSubCategoryId
		WHERE A.UserName!='System' AND A.NoteSourceCD='NS.CHARGE' AND ISNULL(A.IsTransfered,0)=0
END




GO

--select * from BankReconciliation where MonthId=7 and YearId=2024-- 425
CREATE PROCEDURE usp_GetAllPracticesVouchers
	@MonthId INT=11,
	@YearId INT=2023
AS
BEGIN

	DECLARE @Vouchers TABLE
	(
		Id INT IDENTITY(1,1),
		CheckNumber VARCHAR(100)
	)

	DECLARE @PaymentsForUpdate TABLE
	(
		CheckNumber VARCHAR(100),
		EffectiveDate DATE,
		DepositType VARCHAR(100),
		PayerName VARCHAR(100),
		DepositAmount MONEY,
		PaymentAmount MONEY,
		PayerId INT,
		VoucherId INT	
	)

	UPDATE PI_ATC_CLINIC.dbo.Voucher SET ReferenceNo='ATCClinic'+CAST(Id as VARCHAR) WHERE ISNULL(ReferenceNo,'')=''

	UPDATE PI_ATC_LAB.dbo.Voucher SET ReferenceNo='ATCLAB'+CAST(Id as VARCHAR) WHERE ISNULL(ReferenceNo,'')=''

	INSERT INTO @Vouchers
	SELECT DISTINCT ReferenceNo from PI_ATC_CLINIC.dbo.Voucher(NOLOCK) A WHERE VoucherTypeCD='PAYMENT' AND ISNULL(A.IsCommitted,0)=1
	 AND DATEPART(Month,A.EffectiveDate)=@MonthId AND DATEPART(YEAR,A.EffectiveDate)=@YearId
	UNION
	SELECT DISTINCT ReferenceNo from PI_ATC_LAB.dbo.Voucher(NOLOCK) A WHERE VoucherTypeCD='PAYMENT' AND ISNULL(A.IsCommitted,0)=1
	AND DATEPART(Month,A.EffectiveDate)=@MonthId AND DATEPART(YEAR,A.EffectiveDate)=@YearId
	

	DELETE FROM BankReconciliation  WHERE DATEPART(Month,ClinicEffectiveDate)=@MonthId AND DATEPART(YEAR,ClinicEffectiveDate)=@YearId
	AND CheckNumber NOT IN (SELECT CheckNumber from @Vouchers)

	--------------------------------Start Clinic Logic ------------------
	INSERT INTO BankReconciliation(CheckNumber,ClinicEffectiveDate,ClinicDepositType,ClinicPayerName,ClinicDepositAmount,ClinicPaymentAmount,ClinicVoucherId,ClinicPayerId,CreatedDate,MonthId,YearId)
	SELECT A.ReferenceNo,A.EffectiveDate,C.Description,B.CompanyName,A.Amount,(SUM(PC.PaidAmount)+SUM(ISNULL(adj.Amount,0))),A.Id,A.InsuranceCompanyId,GETDATE(),@MonthId,@YearId	
			FROM PI_ATC_CLINIC.dbo.Voucher(NOLOCK) A
		LEFT JOIN PI_ATC_CLINIC.dbo.InsuranceCompany(NOLOCK) B on B.Id=A.InsuranceCompanyId	
		LEFT JOIN PI_ATC_CLINIC.dbo.DepositType(NOLOCK) C on C.Id=A.DepositTypeId
		INNER JOIN PI_ATC_CLINIC.dbo.Payment(NOLOCK) P ON P.VoucherId=A.Id
		INNER JOIN PI_ATC_CLINIC.dbo.PaymentCharge(NOLOCK) PC ON PC.PaymentId=P.Id
		INNER JOIN PI_ATC_CLINIC.dbo.Charge CH (NOLOCK) ON CH.Id=PC.ChargeId
		LEFT JOIN PI_ATC_CLINIC.dbo.PaymentAdjustment(NOLOCK) adj ON PC.Id = adj.PaymentChargeId AND adj.IsBonus = 1 AND (adj.IsAccounted = 1 OR adj.IsBonus=1)   AND adj.IsDenial = 0
		WHERE VoucherTypeCD='PAYMENT' AND ISNULL(A.IsCommitted,0)=1 AND CH.IsDeleted=0
		AND DATEPART(Month,A.EffectiveDate)=@MonthId AND DATEPART(YEAR,A.EffectiveDate)=@YearId
		AND A.ReferenceNo in (SElect distinct CheckNumber from @Vouchers)
		AND A.ReferenceNo NOT IN (SELECT DISTINCT CheckNumber FROM BankReconciliation(NOLOCK) WHERE MonthId=@MonthId AND YearId=@YearId)
	GROUP BY B.CompanyName,A.ReferenceNo,C.Description,A.Amount,A.EffectiveDate,A.InsuranceCompanyId,A.Id

	INSERT INTO @PaymentsForUpdate
	SELECT A.ReferenceNo,A.EffectiveDate,C.Description,B.CompanyName,A.Amount,(SUM(PC.PaidAmount)+SUM(ISNULL(adj.Amount,0))),A.InsuranceCompanyId,A.Id
			FROM PI_ATC_CLINIC.dbo.Voucher(NOLOCK) A
		LEFT JOIN PI_ATC_CLINIC.dbo.InsuranceCompany(NOLOCK) B on B.Id=A.InsuranceCompanyId	
		LEFT JOIN PI_ATC_CLINIC.dbo.DepositType(NOLOCK) C on C.Id=A.DepositTypeId
		INNER JOIN PI_ATC_CLINIC.dbo.Payment(NOLOCK) P ON P.VoucherId=A.Id
		INNER JOIN PI_ATC_CLINIC.dbo.PaymentCharge(NOLOCK) PC ON PC.PaymentId=P.Id
		INNER JOIN PI_ATC_CLINIC.dbo.Charge CH (NOLOCK) ON CH.Id=PC.ChargeId
		LEFT JOIN PI_ATC_CLINIC.dbo.PaymentAdjustment(NOLOCK) adj ON PC.Id = adj.PaymentChargeId AND adj.IsBonus = 1 AND (adj.IsAccounted = 1 OR adj.IsBonus=1)   AND adj.IsDenial = 0
		WHERE VoucherTypeCD='PAYMENT' AND ISNULL(A.IsCommitted,0)=1 AND CH.IsDeleted=0
		AND DATEPART(Month,A.EffectiveDate)=@MonthId AND DATEPART(YEAR,A.EffectiveDate)=@YearId
		AND A.ReferenceNo in (SElect distinct CheckNumber from @Vouchers)		
	GROUP BY B.CompanyName,A.ReferenceNo,C.Description,A.Amount,A.EffectiveDate,A.InsuranceCompanyId,A.Id
	
	UPDATE BankReconciliation 
	SET ClinicEffectiveDate=A.EffectiveDate,
		ClinicDepositType=A.DepositType,
		ClinicPayerName=A.PayerName,
		ClinicDepositAmount=A.DepositAmount,
		ClinicPaymentAmount=A.PaymentAmount,
		ClinicPayerId =A.PayerId,
		ClinicVoucherId=A.VoucherId
	FROM BankReconciliation X
	INNER JOIN @PaymentsForUpdate A on X.CheckNumber=A.CheckNumber
	---------------------------------- End Clinic Logic ------------------


	----------------------------------Start LAB Logic ------------------
	INSERT INTO BankReconciliation(CheckNumber,LABEffectiveDate,LABDepositType,LABPayerName,LABDepositAmount,LABPaymentAmount,LABVoucherId,LABPayerId,CreatedDate,MonthId,YearId)
	SELECT A.ReferenceNo,A.EffectiveDate,C.Description,B.CompanyName,A.Amount,(SUM(PC.PaidAmount)+SUM(ISNULL(adj.Amount,0))),A.Id,A.InsuranceCompanyId,GETDATE(),@MonthId,@YearId	
			FROM PI_ATC_LAB.dbo.Voucher(NOLOCK) A
		LEFT JOIN PI_ATC_LAB.dbo.InsuranceCompany(NOLOCK) B on B.Id=A.InsuranceCompanyId	
		LEFT JOIN PI_ATC_LAB.dbo.DepositType(NOLOCK) C on C.Id=A.DepositTypeId
		INNER JOIN PI_ATC_LAB.dbo.Payment(NOLOCK) P ON P.VoucherId=A.Id
		INNER JOIN PI_ATC_LAB.dbo.PaymentCharge(NOLOCK) PC ON PC.PaymentId=P.Id
		INNER JOIN PI_ATC_LAB.dbo.Charge CH (NOLOCK) ON CH.Id=PC.ChargeId
		LEFT JOIN PI_ATC_LAB.dbo.PaymentAdjustment(NOLOCK) adj ON PC.Id = adj.PaymentChargeId AND adj.IsBonus = 1 AND (adj.IsAccounted = 1 OR adj.IsBonus=1)   AND adj.IsDenial = 0
		WHERE VoucherTypeCD='PAYMENT' AND ISNULL(A.IsCommitted,0)=1 AND CH.IsDeleted=0
		AND DATEPART(Month,A.EffectiveDate)=@MonthId AND DATEPART(YEAR,A.EffectiveDate)=@YearId
		AND A.ReferenceNo in (SElect distinct CheckNumber from @Vouchers)
		AND A.ReferenceNo NOT IN (SELECT DISTINCT CheckNumber FROM BankReconciliation(NOLOCK) WHERE MonthId=@MonthId AND YearId=@YearId)
	GROUP BY B.CompanyName,A.ReferenceNo,C.Description,A.Amount,A.EffectiveDate,A.InsuranceCompanyId,A.Id
	
	DELETE FROM @PaymentsForUpdate

	INSERT INTO @PaymentsForUpdate
	SELECT A.ReferenceNo,A.EffectiveDate,C.Description,B.CompanyName,A.Amount,(SUM(PC.PaidAmount)+SUM(ISNULL(adj.Amount,0))),A.InsuranceCompanyId,A.Id
			FROM PI_ATC_LAB.dbo.Voucher(NOLOCK) A
		LEFT JOIN PI_ATC_LAB.dbo.InsuranceCompany(NOLOCK) B on B.Id=A.InsuranceCompanyId	
		LEFT JOIN PI_ATC_LAB.dbo.DepositType(NOLOCK) C on C.Id=A.DepositTypeId
		INNER JOIN PI_ATC_LAB.dbo.Payment(NOLOCK) P ON P.VoucherId=A.Id
		INNER JOIN PI_ATC_LAB.dbo.PaymentCharge(NOLOCK) PC ON PC.PaymentId=P.Id
		INNER JOIN PI_ATC_LAB.dbo.Charge CH (NOLOCK) ON CH.Id=PC.ChargeId
		LEFT JOIN PI_ATC_LAB.dbo.PaymentAdjustment(NOLOCK) adj ON PC.Id = adj.PaymentChargeId AND adj.IsBonus = 1 AND (adj.IsAccounted = 1 OR adj.IsBonus=1)   AND adj.IsDenial = 0
		WHERE VoucherTypeCD='PAYMENT' AND ISNULL(A.IsCommitted,0)=1 AND CH.IsDeleted=0
		AND DATEPART(Month,A.EffectiveDate)=@MonthId AND DATEPART(YEAR,A.EffectiveDate)=@YearId
		AND A.ReferenceNo in (SElect distinct CheckNumber from @Vouchers)		
	GROUP BY B.CompanyName,A.ReferenceNo,C.Description,A.Amount,A.EffectiveDate,A.InsuranceCompanyId,A.Id

	UPDATE BankReconciliation 
	SET LABEffectiveDate=A.EffectiveDate,
		LABDepositType=A.DepositType,
		LABPayerName=A.PayerName,
		LABDepositAmount=A.DepositAmount,
		LABPaymentAmount=A.PaymentAmount,
		LABPayerId =A.PayerId,
		LABVoucherId=A.VoucherId
	FROM BankReconciliation X
	INNER JOIN @PaymentsForUpdate A on X.CheckNumber=A.CheckNumber
	-------------------------------- End LAB Logic ------------------

	
SELECT 0[Id]
	
END


GO

CREATE PROC usp_GetARAging90DaysData
AS
BEGIN
	
	DECLARE @Date DATE=DATEADD(Month,-3,GETDATE())
	DECLARE @YearId INT=DATEPART(YEAR,@Date)	
	DECLARE @MonthId INT=DATEPART(MONTH,@Date)	
	select @MonthId
	
	IF @MonthId=11
	BEGIN
		SELECT MonthId,ChargeAmount,WriteOffAmount,ChargeBalance11[Nov],ChargeBalance12[Dec]  FROM ChargeBalanceAR90 WHERE YearId=@YearId AND MonthId<=@MonthId
	END
	IF @MonthId=10
	BEGIN
		SELECT MonthId,ChargeAmount,WriteOffAmount,ChargeBalance10[Oct],ChargeBalance11[Nov],ChargeBalance12[Dec]  FROM ChargeBalanceAR90 WHERE YearId=@YearId AND MonthId<=@MonthId
	END
	IF @MonthId=9
	BEGIN
		SELECT MonthId,ChargeAmount,WriteOffAmount,ChargeBalance9[Sep],ChargeBalance10[Oct],ChargeBalance11[Nov] FROM ChargeBalanceAR90 WHERE YearId=@YearId AND MonthId<=@MonthId
	END
	IF @MonthId=8
	BEGIN
		SELECT MonthId,ChargeAmount,WriteOffAmount,ChargeBalance8[Aug],ChargeBalance9[Sep],ChargeBalance10[Oct] FROM ChargeBalanceAR90 WHERE YearId=@YearId AND MonthId<=@MonthId
	END
	IF @MonthId=7
	BEGIN
		SELECT ChargeBalance7[July],ChargeBalance8[Aug],ChargeBalance9[Sep] FROM ChargeBalanceAR90 WHERE YearId=@YearId AND MonthId<=@MonthId
	END	
END
--select * from ChargeBalanceAR90

GO

CREATE PROCEDURE [dbo].[usp_GetDenialManagementAgingCountByRange]                
AS                
BEGIN         
 DECLARE @Temp TABLE                
 (                
  ID INT,                
  FromDays INT,                
  ToDays INT  ,              
  TabLabel VARCHAR(50)              
 )                
                
 DECLARE @Temp1 TABLE                
 (                  
  PatientCount INT,                
  BalanceAmount MONEY,                
  Tag VARCHAR(50)  ,              
  FromDays INT,              
  ToDays INT,              
  Category VARCHAR(50)              
 )                
                
 INSERT INTO @Temp                  
 SELECT 1,0,29 ,'Current'                
 INSERT INTO @Temp                  
 SELECT 2,30,59 , '30 Days'                
 INSERT INTO @Temp                  
 SELECT 3,60,89 ,'60 Days'                
 INSERT INTO @Temp                  
 SELECT 4,90,119 , '90 Days'                
 INSERT INTO @Temp                  
 SELECT 5,120,149 ,  '120 Days'                
 INSERT INTO @Temp                  
 SELECT 6,150,15000  ,  'Over'                
                  
                
 DECLARE @ID INT                
 SELECT @ID=MIN(ID) FROM @Temp                
 WHILE @ID IS NOT NULL                
 BEGIN                
  DECLARE @FromDays INT                
  DECLARE @ToDays INT                
  DECLARE @TabLabel VARCHAR(50)              
  SELECT @FromDays=FromDays,@ToDays=ToDays,@TabLabel=TabLabel FROM @Temp WHERE ID=@ID                
  
  INSERT INTO @Temp1                
  EXEC usp_DenialManagementAgingCount @FromDays,@ToDays,@TabLabel=@TabLabel  
    
  SELECT @ID=MIN(ID) FROM @Temp WHERE ID>@ID                
 END                
 SELECT * FROM @Temp1                
END

