CREATE PROCEDURE [dbo].[usp_GetInnetwork]    
(    
@fromDate As DateTime,    
@toDate As DateTime,    
@isInnertWork as int    
)    
AS    
BEGIN    
SELECT CPTCode,i.Id,ch.CPTCode,p.Id,FirstName,ic.Id, ic.CompanyName,     
    LastName,AccessionNumber,Amount,Qty,i.BillFromDate DOSDate       
    FROM Invoice i      
    join PatientCase c on c.Id=i.PatientCaseId       
    join Patient p on c.PatientId= p.Id
    join Charge ch on ch.InvoiceId=i.Id       
    --join DiagnosisCodeList d on d.ID=ch.Diagnoses      
 join InsuranceCompany ic on ic.Id= (dbo.ufn_ActiveInsuranceForCaseNo(ch.BillFromDate,1, C.Id))    
 where (@isInnertWork=0 or (@isInnertWork=1 and ic.IsInnetwork=1) or (@isInnertWork=2 and (ic.IsInnetwork=0 or ic.IsInnetwork is null)))    
  and i.BillFromDate >= @fromDate and i.BillFromDate <= @toDate    
END    
    
    
--EXEC usp_GetInnetwork '2018-07-18','2018-08-08',1



GO

CREATE PROCEDURE [dbo].[usp_GetInsurancewisePaymentReport]   
(
@FromDate datetime=NULL,      
@ToDate  datetime=NULL 
)
AS    
BEGIN    
SELECT ISNULL(INS.CompanyName,'Self')[CompanyName],Datename(Month, V.EffectiveDate)[Month],DATEPART(YEAR, V.EffectiveDate)[Year],SUM(A.PaidAmount)PaidAmount
			FROM PaymentCharge(NOLOCK) A
			INNER JOIN Charge (NOLOCK)D ON D.Id=A.ChargeId 
			INNER JOIN Invoice (NOLOCK)INV ON INV.Id=D.InvoiceId
			INNER JOIN Payment (NOLOCK) B ON A.PaymentId=B.Id
			INNER JOIN Voucher (NOLOCK) V ON B.VoucherId=V.Id
			INNER JOIN Patient (NOLOCK)P ON P.Id=B.PatientId
			INNER JOIN Provider (NOLOCK)F ON F.Id=D.PerformingProviderId
			LEFT JOIN Facility (NOLOCK)G ON G.Id=D.PerformingFacilityId
			LEFT JOIN InsuranceCompany (NOLOCK)INS ON INS.Id=V.InsuranceCompanyId
			LEFT JOIN ConfigInsuranceCompanyType (NOLOCK)CIT ON CIT.Id=INS.CompanyTypeId
			WHERE D.BillFromDate>'1 May 2020' AND D.IsDeleted=0 AND B.IsCommitted=1	
			AND (CAST(@FromDate AS date) IS NULL OR CAST(V.EffectiveDate AS DATE) BETWEEN CAST(@FromDate AS date) AND CAST(@ToDate AS date))
			group by INS.CompanyName,Datename(Month, V.EffectiveDate),DATEPART(YEAR, V.EffectiveDate),DatePart(Month, V.EffectiveDate)			
order by CompanyName,DATEPART(YEAR, V.EffectiveDate),DATEPART(Month, V.EffectiveDate)

END  
    




GO

CREATE procedure [dbo].[usp_GetPatientAgingBalances]
AS
BEGIN 
PRINT 'Execution Started : ' + convert(varchar(30),getdate(),114)                      
	DECLARE @TempData AS TABLE (                  
	FirstName  Nvarchar(500),
	LastName  Nvarchar(500),
	PatientId Numeric(18,0),        
	PatientUId UNIQUEIDENTIFIER,        
	DOS    Datetime,        
	Balance030   Decimal(18,2),                          
	Balance3160  Decimal(18,2),                          
	Balance6190  Decimal(18,2),          
	Balance91120  Decimal(18,2),        
	BalanceOver120  Decimal(18,2),                     
	TotalBalance Decimal(18,2),                      
	ShiftDate Datetime,                      
	FromDate Datetime,                      
	CaseNumber INT,        
	DOB DateTime,        
	PatientAddress VARCHAR(100),        
	LastPayment Datetime,        
	LastStatement Datetime,        
	NumberOfStatement INT,
	BillingId VARCHAR(50),
	UnPostedPayment BIT,
	UnMatchedPayment BIT
	)  
	

	DECLARE @UnPostedPayymentPatient TABLE
	(
		PatientId INT
	)

	INSERT INTO @UnPostedPayymentPatient
	SELECT DISTINCT PatientId FROM PortalPayment WHERE PatientId in (
	SELECT DISTINCT A.PatientId
	FROM ChargesReportData A  (NOLOCK)                          		
	WHERE  A.Deleted='No'  	AND Lower(A.DueBy) in ('','patient')  	AND 	A.DueAmount>0)
	AND IsCommitted=0

	DECLARE @UnMatchedPayymentPatient TABLE
	(
		BillingId VARCHAR(50)
	)
	INSERT INTO @UnMatchedPayymentPatient 
	SELECT Distinct ISNULL(EmrAccountNumber,AccountNumber)BillingId FROM DynmoPayments WHERE Id not in (
		SELECT Id from DynmoPayments(NOLOCK) where PaymentType=2 and ISNULL(PaymentConfirmationCode,'')='')
	AND IsImportInBilling=0 

                       
	INSERT INTO @TempData ( FirstName,LastName,PatientId,PatientUId,DOS,Balance030,Balance3160,Balance6190,Balance91120,BalanceOver120,TotalBalance,ShiftDate,FromDate,CaseNumber,
					DOB,PatientAddress,LastPayment,BillingId,UnPostedPayment,UnMatchedPayment)                          
	SELECT DISTINCT A.FirstName, A.LastName, A.PatientId,A.PatientUId,Cast( A.DosDate as Datetime),0,0,0,0,0,SUM(A.DueAmount),B.ShiftDate,A.DosDate,A.PatientCaseId,        
					A.DOB, '',A.RemitDate,A.BillingID,CASE WHEN C.PatientId IS NULL THEN 0 ELSE 1 END,CASE WHEN D.BillingId IS NULL THEN 0 ELSE 1 END
	FROM ChargesReportData A  (NOLOCK)                          
		INNER JOIN Charge(NOLOCK) B ON A.ChargeId=B.Id
		LEFT JOIN @UnPostedPayymentPatient C ON C.PatientId=A.PatientId
		LEFT JOIN @UnMatchedPayymentPatient D ON D.BillingId=A.BillingID
	WHERE  CAST(ISNULL(A.ChargePostDate, A.DosDate) AS DATE) <=  CAST(GETDATE() AS DATE)                      
	AND A.Deleted='No'  
	AND Lower(A.DueBy) in ('','patient')  
	GROUP BY A.PatientId, A.PatientUId,A.FirstName, A.LastName, B.ShiftDate, A.DosDate, A.PatientCaseId, A.DOB,A.RemitDate,A.BillingID,C.PatientId,D.BillingId
	having SUM(A.DueAmount)<>0
	        
	Print 'SQL Passed : ' + convert(varchar(30),getdate(),114)                      
                   
	UPDATE @TempData 
		SET Balance030 = Case when (Datediff(dd,ISNULL(ShiftDate,DOS), CAST(GETDATE() AS DATE)) <= 29) Then TotalBalance Else 0 End,                          
			Balance3160 = Case when (Datediff(dd,ISNULL(ShiftDate,DOS), CAST(GETDATE() AS DATE)) >= 30) And (Datediff(dd,ISNULL(ShiftDate,DOS), CAST(GETDATE() AS DATE)) <= 59) Then TotalBalance  Else 0 End,                          
			Balance6190 = Case when (Datediff(dd,ISNULL(ShiftDate,DOS),CAST(GETDATE() AS DATE)) >= 60) And (Datediff(dd,ISNULL(ShiftDate,DOS),CAST(GETDATE() AS DATE)) <= 89) Then TotalBalance  Else 0 End,                          
			Balance91120 = Case when (Datediff(dd,ISNULL(ShiftDate,DOS),CAST(GETDATE() AS DATE)) >= 90) And (Datediff(dd,ISNULL(ShiftDate,DOS),CAST(GETDATE() AS DATE)) <= 119) Then TotalBalance  Else 0 End,                          
			BalanceOver120 = Case when (Datediff(dd,ISNULL(ShiftDate,DOS),CAST(GETDATE() AS DATE)) >= 120)  Then TotalBalance  Else 0 End                     
                         
	Print 'update aging Passed : ' + convert(varchar(30),getdate(),114)                      
                      
	UPDATE @TempData SET TotalBalance =  Balance030 +  Balance3160   + Balance6190   + Balance91120 + BalanceOver120                      

	--select * from @TempData
                        
--Aging By Patient                          
	SELECT X.PatientId,X.PatientUId,X.FirstName,X.LastName,SUM(X.Balance030) AS Balance030,SUM(x.Balance3160) AS Balance3160,SUM(X.Balance6190) AS Balance6190,SUM(X.Balance91120) AS Balance91120,
			SUM(X.BalanceOver120) AS BalanceOver120,SUM(X.TotalBalance) AS TotalBalance, X.CaseNumber,MAX(X.DOB) AS DOB,X.PatientAddress AS PatientAddress,0 [AppliedAmount],      
			MAX(X.LastPayment) AS LastPayment,MAX(bps.LastStatement) AS LastStatement,MAX(bps.StatementsNumber) as NumberOfStatements,X.UnPostedPayment,X.UnMatchedPayment,X.BillingId
	FROM @TempData X            	
	CROSS APPLY (          
				 SELECT MAX(ps.CreatedDate) AS LastStatement, COUNT(ps.ID) AS StatementsNumber          
				 FROM PatientStatement(NOLOCK) ps          
				 WHERE ps.PatientId = X.PatientID -- AND ps.CaseNumber= X.CaseNumber          
				) bps          
	-- Where TotalBalance <> 0 check condition it was working        
	Group By X.PatientId, X.FirstName, X.LastName, X.CaseNumber, X.DOB,X.PatientAddress, X.PatientUId,X.UnPostedPayment,X.UnMatchedPayment,X.BillingId
	Order by PatientId                                                  
	Print 'Ageing By Patient Passed : ' + convert(varchar(30),getdate(),114)                          
End 

GO

--usp_GetPatientAgingBalances_BatchStatement '0CC04B16-5455-4898-8126-ABB44A053993'
CREATE procedure [dbo].[usp_GetPatientAgingBalances_BatchStatement]
	@BatchStatementUId VARCHAR(100)
AS
BEGIN 
	DECLARE @BatchStatementId INT

	SELECT @BatchStatementId=Id FROM Batchstatement WHERE Uid=@BatchStatementUId

	PRINT 'Execution Started : ' + convert(varchar(30),getdate(),114)                      
	DECLARE @TempData AS TABLE (                  
	FirstName  Nvarchar(500),
	LastName  Nvarchar(500),
	PatientId Numeric(18,0),        
	PatientUId UNIQUEIDENTIFIER,        
	DOS    Datetime,        
	Balance030   Decimal(18,2),                          
	Balance3160  Decimal(18,2),                          
	Balance6190  Decimal(18,2),          
	Balance91120  Decimal(18,2),        
	BalanceOver120  Decimal(18,2),                     
	TotalBalance Decimal(18,2),                      
	ShiftDate Datetime,                      
	FromDate Datetime,                      
	CaseNumber INT,        
	DOB DateTime,        
	PatientAddress VARCHAR(100),        
	LastPayment Datetime,        
	LastStatement Datetime,        
	NumberOfStatement INT
	
	)                          
                       
	INSERT INTO @TempData ( FirstName,LastName,PatientId,PatientUId,DOS,Balance030,Balance3160,Balance6190,Balance91120,BalanceOver120,TotalBalance,ShiftDate,FromDate,CaseNumber,
					DOB,PatientAddress)                          
	SELECT DISTINCT D.FirstName, D.LastName, D.Id,D.UId,Cast( A.BillFromDate as Datetime),0,0,0,0,0,SUM(A.DueAmount),A.ShiftDate,A.BillFromDate,D.DefaultCaseId,        
					D.DOB, CONCAT(D.Address1, D.Address2, D.City, D.[State], D.ZipCode)
	FROM vw_GetChargeForPendingPayment A  (NOLOCK)                          
		INNER JOIN Invoice B (NOLOCK) ON A.InvoiceId=B.ID                   
		--INNER JOIN  PatientCase C (NOLOCK) ON C.Id = B.PatientCaseId        
		INNER JOIN Patient D (NOLOCK) ON A.PatientCaseId = D.DefaultCaseId
		         
	WHERE  CAST(ISNULL(A.EntryDate, A.BillFromDate) AS DATE) <=  CAST(GETDATE() AS DATE)                      
	AND A.IsDeleted <> 1  AND A.ChargeNo > 0  And A.PatientCaseId > 0 --and A.BillToInsurance = 0        	
	AND (A.DueByFlagCD = '' OR LOWER(A.DueByFlagCD) = 'patient')  
	AND D.Id in (SELECT PatientId FROM PatientStatement WHERE BatchStatementId=@BatchStatementId)
	GROUP BY D.Id, D.UId,D.FirstName, D.LastName, A.ShiftDate, A.BillFromDate, D.DefaultCaseId, D.DOB, D.Address1, D.Address2, D.City, D.[State], D.ZipCode  
	having SUM(A.DueAmount)<>0
	        


	Print 'SQL Passed : ' + convert(varchar(30),getdate(),114)                      
                   
	UPDATE @TempData 
		SET Balance030 = Case when (Datediff(dd,ISNULL(ShiftDate,DOS), CAST(GETDATE() AS DATE)) <= 29) Then TotalBalance Else 0 End,                          
			Balance3160 = Case when (Datediff(dd,ISNULL(ShiftDate,DOS), CAST(GETDATE() AS DATE)) >= 30) And (Datediff(dd,ISNULL(ShiftDate,DOS), CAST(GETDATE() AS DATE)) <= 59) Then TotalBalance  Else 0 End,                          
			Balance6190 = Case when (Datediff(dd,ISNULL(ShiftDate,DOS),CAST(GETDATE() AS DATE)) >= 60) And (Datediff(dd,ISNULL(ShiftDate,DOS),CAST(GETDATE() AS DATE)) <= 89) Then TotalBalance  Else 0 End,                          
			Balance91120 = Case when (Datediff(dd,ISNULL(ShiftDate,DOS),CAST(GETDATE() AS DATE)) >= 90) And (Datediff(dd,ISNULL(ShiftDate,DOS),CAST(GETDATE() AS DATE)) <= 119) Then TotalBalance  Else 0 End,                          
			BalanceOver120 = Case when (Datediff(dd,ISNULL(ShiftDate,DOS),CAST(GETDATE() AS DATE)) >= 120)  Then TotalBalance  Else 0 End                     
                         
	Print 'update aging Passed : ' + convert(varchar(30),getdate(),114)                      
                      
	UPDATE @TempData SET TotalBalance =  Balance030 +  Balance3160   + Balance6190   + Balance91120 + BalanceOver120                      
                        
--Aging By Patient                          
	SELECT X.PatientID,X.PatientUId,X.FirstName,X.LastName,SUM(X.Balance030) AS Balance030,SUM(x.Balance3160) AS Balance3160,SUM(X.Balance6190) AS Balance6190,SUM(X.Balance91120) AS Balance91120,
			SUM(X.BalanceOver120) AS BalanceOver120,SUM(X.TotalBalance) AS TotalBalance, X.CaseNumber,MAX(X.DOB) AS DOB,X.PatientAddress AS PatientAddress,0 [AppliedAmount],      
			MAX(pa.LastPayment) AS LastPayment,MAX(bps.LastStatement) AS LastStatement,MAX(bps.StatementsNumber) as NumberOfStatements
	FROM @TempData X            
	CROSS APPLY (        
					 SELECT MAX(P.CreatedDate) LastPayment         
					 FROM PaymentCharge(NOLOCK) bpa          
					 LEFT JOIN Payment(NOLOCK) P On bpa.PaymentId = P.Id        
					 WHERE P.PatientId = X.PatientId) pa          
	CROSS APPLY (          
				 SELECT MAX(ps.CreatedDate) AS LastStatement, COUNT(ps.ID) AS StatementsNumber          
				 FROM PatientStatement(NOLOCK) ps          
				 WHERE X.PatientId = ps.PatientID -- AND ps.CaseNumber= X.CaseNumber          
				) bps          
	-- Where TotalBalance <> 0 check condition it was working        
	Group By X.PatientId, X.FirstName, X.LastName, X.CaseNumber, X.DOB,X.PatientAddress, X.PatientUId
	Order by LastName
	Print 'Ageing By Patient Passed : ' + convert(varchar(30),getdate(),114)                          
End 

GO

CREATE procedure usp_GetPatientForAutoStatment
@Days INT
AS
BEGIN 
PRINT 'Execution Started : ' + convert(varchar(30),getdate(),114)                      
	DECLARE @TempData AS TABLE (                  
	
	PatientId Numeric(18,0),        
	PatientUId UNIQUEIDENTIFIER	  
	)                          
                       
	INSERT INTO @TempData ( PatientId,PatientUId)                          
	SELECT DISTINCT  D.Id,D.UId
	FROM vw_GetChargeForPendingPayment A  (NOLOCK)                          
		INNER JOIN Invoice B (NOLOCK) ON A.InvoiceId=B.ID                   
		--INNER JOIN  PatientCase C (NOLOCK) ON C.Id = B.PatientCaseId        
		INNER JOIN Patient D (NOLOCK) ON A.PatientCaseId = D.DefaultCaseId		         
	WHERE  CAST(ISNULL(A.EntryDate, A.BillFromDate) AS DATE) <=  CAST(GETDATE() AS DATE)                      
	AND A.IsDeleted <> 1  AND A.ChargeNo > 0  And A.PatientCaseId > 0 --and A.BillToInsurance = 0        	
	AND (A.DueByFlagCD = '' OR LOWER(A.DueByFlagCD) = 'patient') 
	AND A.BillFromDate>'1 May 2020'
	AND D.Id  NOT in  (select PatientId from PatientStatement(NOLOCK) group by PatientId having (Datediff(dd,MAX(CAST(CreatedDate AS DATE)), CAST(GETDATE() AS DATE)) <= @Days))
	GROUP BY D.Id, D.UId,D.FirstName, D.LastName, A.EntryDate, A.BillFromDate, D.DefaultCaseId, D.DOB, D.Address1, D.Address2, D.City, D.[State], D.ZipCode  
	having SUM(A.DueAmount)>0
	
	--select * from @TempData
	DECLARe @Id INT
	SELECt @Id= MIN (PatientId) from  @TempData
	DECLARE @Count INT=0
	DECLARe @Result NVARCHAR(MAX)=''
	WHILE @Id IS NOT NULL
	BEGIN
		DECLARE @Uid NVARCHAR(50)
		SELECt @Uid= PatientUId from  @TempData WHERE PatientId=@Id

		IF @Count=0
		BEGIN
			SET @Result=@Uid
		END
		ELSE
		BEGIN
		SET @Result=@Result+','+@Uid
		END
		SELECt @Id= MIN (PatientId) from  @TempData WHERE PatientId>@Id
		set @Count=@Count+1
	END

	SELECt @Result [Result]
End 


GO


CREATE PROCEDURE usp_GetPaymentsToCompany       @FromDate  datetime = NULL,       @ToDate   datetime = NULL      AS              SELECT @ToDate = DATEADD(day, -1, @ToDate)              DECLARE @PRACTICE_NAME varchar(35)       SELECT @PRACTICE_NAME
 = Name FROM Facility WHERE Id = 2             SELECT  PaymentEffectiveDate, @PRACTICE_NAME, @Practice_NAME, CPTCode,           COUNT(1),           CAST(SUM(PaymentOrAdjAmount) as decimal(10,2))       FROM  vw_PaymentsAdjustments pmt      WHERE pmt.PatientCaseId > 0                       AND pmt.ChargeNum > 0                       AND pmt.IsDeleted =0                     AND ((CAST(pmt.PaymentEffectiveDate AS DATE) >= CAST(@FromDate AS DATE)                             OR @FromDate IS NULL)               
             AND (CAST(pmt.PaymentEffectiveDate AS DATE) <= CAST(@ToDate AS DATE)                                 OR @ToDate IS NULL))							 AND pmt.IsPayment = 1            --AND ProcedureCode IN (SELECT CPTCode             --  FROM ProcedureCode_Supplies             --  WHERE Exclude = 1)       GROUP BY PaymentEffectiveDate, CPTCode


GO


CREATE PROCEDURE usp_GetPaymentsToDoctors       @FromDate  datetime = NULL,       @ToDate   datetime = NULL,       @ProviderID  int = -1      AS               SELECT  PaymentEffectiveDate, pro.LastName AS PerformingDoctorLastName, prov.LastName AS 
BillingDoctorLastName, CPTCode,          COUNT(1),          CAST(SUM(PaymentOrAdjAmount) as decimal(10,2))       FROM  vw_PaymentsAdjustments pmt LEFT JOIN [Provider] pro on pro.Id = pmt.PerformingProviderId LEFT JOIN [Provider] prov on pro.Id = pmt.BillingDoctorID WHERE      	pmt.PatientCaseId > 0                       AND pmt.ChargeNum > 0                       AND pmt.IsDeleted =0    				   AND pmt.IsPayment =1       AND ((CAST(pmt.PaymentEffectiveDate AS DATE) >= CAST(@FromDate AS DATE)               
              OR @FromDate IS NULL)                            AND (CAST(pmt.PaymentEffectiveDate AS DATE) <= CAST(@ToDate AS DATE)                                 OR @ToDate IS NULL))  AND  (@ProviderID = -1 OR pro.Id = @ProviderID)               GROUP BY PaymentEffectiveDate, pro.LastName, prov.LastName, CPTCode


GO

CREATE PROCEDURE usp_GetPaymentWareHouseReportData
@FromDate DATE,
@ToDate DATE
AS
BEGIN
	
	SELECT Id,ChargeId,ChargePostDate,DosDate,CPTCode,Description,ChargeRowNumber,
		CASE WHEN (ROW_NUMBER() OVER(PARTITION BY A.ChargeId ORDER BY A.ChargeId ASC))=1 THEN A.ChargeAmount ELSE 0 END ChargeAmount,
		Payment,Adjustment,PaymentPostDate,RemitDate,PatientId,BillingID,FirstName,LastName,DOB,
		PatientUId,PerformingProviderUId,PatientCaseUId,InvoiceUId,PatientName,AccessionNumber,Aging,AgingText,AgingByPostDate,AgingByPostDateText,DepositCreationDate,CreatedDate,
		InvoiceId,DepositType,PCID,HasDenial,IsAccounted 
	FROM PaymentReportData(NOLOCK) A WHERE RemitDate>=@FromDate AND RemitDate<=@ToDate
END

GO

CREATE PROCEDURE usp_GetTableForMonthReport
@CurrentDate DATE
AS
BEGIN
	DECLARE @Count INT=1
DECLARE @Date DATE=DATEADD(DAY,-90,@CurrentDate)
DECLARE @YearId INT=DATEPART(YEAR,@Date)	
DECLARE @MonthId INT=DATEPART(MONTH,@Date)	
--SELECT @YearId [@YearId],@MonthId[@MonthId]

DECLARE @Temp TABLE
(
	Id INT IDENTITY(1,1),
	MonthId INT,
	YearId INT,
	StartDate DATE,
	EndDate DATE
)

WHILE @YearId>=2022
BEGIN	
	DECLARE @TempCount INT=0

	WHILE @Count<=@MonthId
	BEGIN			
		
		IF @MonthId=1
		BEGIN
		--SELECT @MonthId,@YearId,100
		INSERT INTO @Temp(MonthId,YearId)SELECT @MonthId,@YearId
			IF @YearId>2022 
			BEGIN
				IF @TempCount=0
				BEGIN				
					SET @MonthId=12
					SET @TempCount=1					
				END
			END			
			--INSERT INTO @Temp(MonthId,YearId)SELECT @MonthId,@YearId
			break;
		END
		ELSE
		BEGIN
		INSERT INTO @Temp(MonthId,YearId)SELECT @MonthId,@YearId	
			SET @MonthId=@MonthId-1			
		END
		--Break;

		
	END
	SET @YearId=@YearId-1
END

		DECLARE @Id INT
		SELECT @Id=MIN(Id) FROM @Temp
		WHILE @Id IS NOT NULL
		BEGIN
	
			DECLARE @StartDate DATE
			DECLARE @EndDate DATE
	

			SELECT @StartDate=CAST(MonthId AS VARCHAR)+'/01/'+CAST(YearId as VARCHAR) FROM @Temp WHERE Id=@Id
			IF @Id=1
			BEGIN
				SET @EndDate=@Date
			END
			ELSE
			BEGIN
				SET @EndDate=EOMONTH(@StartDate)	
			END
			UPDATE @Temp SET StartDate=@StartDate,EndDate=@EndDate WHERE Id=@Id

			SELECT @Id=MIN(Id) FROM @Temp WHERE Id>@Id
		END
		select * from @Temp
END

GO

