CREATE PROC USP_ImportCatalystAllChargeIntoWareHouseTable
AS
BEGIN

		DECLARE @PatientNoteClinic TABLE
		(
			PatientId INT,
			PatientNote VARCHAR(1000),
			NoteCreatedDate DATE,
			NoteCreatedBy VARCHAR(20)
		)
		INSERT INTO @PatientNoteClinic(PatientId,PatientNote,NoteCreatedDate,NoteCreatedBy)
		SELECT PatientId,Note,CAST(CreatedDate AS DATE)[CreatedDate],CreatedBy 
			FROM PI_ATC_CLINIC.dbo.ActionNote(NOLOCK) A WHERE A.NoteSourceCD='NS.PATIENT' 
		AND CreatedDate=(SELECT MAX(B.CreatedDate) FROM PI_ATC_CLINIC.dbo.ActionNote(NOLOCK) B 
		WHERE B.NoteSourceCD='NS.PATIENT' AND B.PatientId=A.PatientId)

		DECLARE @PatientNoteLAB TABLE
		(
			PatientId INT,
			PatientNote VARCHAR(1000),
			NoteCreatedDate DATE,
			NoteCreatedBy VARCHAR(20)
		)
		INSERT INTO @PatientNoteLAB(PatientId,PatientNote,NoteCreatedDate,NoteCreatedBy)
		SELECT PatientId,Note,CAST(CreatedDate AS DATE)[CreatedDate],CreatedBy 
			FROM PI_ATC_LAB.dbo.ActionNote(NOLOCK) A WHERE A.NoteSourceCD='NS.PATIENT' 
		AND CreatedDate=(SELECT MAX(B.CreatedDate) FROM PI_ATC_LAB.dbo.ActionNote(NOLOCK) B 
		WHERE B.NoteSourceCD='NS.PATIENT' AND B.PatientId=A.PatientId)


		DECLARE @PrimaryInsuranceClinic TABLE
		(
			InvoiceId INT,
			InsuranceCompanyId INT,
			PolicyNo VARCHAR(20),
			PolicyHolderName VARCHAR(200),
			PolicyHolderDOB VARCHAR(20),
			PolicyHolderRelation VARCHAR(20),
			InsuranceCompanyName VARCHAR(200),
			CompanyType VARCHAR(50)
		)
		INSERT INTO @PrimaryInsuranceClinic
		SELECT InvoiceId,InsuranceCompanyId,PolicyNo,PolicyHolderName,PolicyHolderDOB,B.Description,C.CompanyName ,D.CompanyType
		from Claim (NOLOCK)A
		LEFT JOIN ConfigRelationship(NOLOCK) B on B.Id=A.PolicyHolderRelation
		LEFT JOIN InsuranceCompany(NOLOCK) C on C.Id=A.InsuranceCompanyId
		LEFT JOIN ConfigInsuranceCompanyType D on D.Id=C.CompanyTypeId
		WHERE A.Id IN (SELECT MAX(Id) FROM Claim(NOLOCK) B WHERE B.InvoiceId=A.InvoiceId)

		DECLARE @PrimaryInsuranceLab TABLE
		(
			InvoiceId INT,
			InsuranceCompanyId INT,
			PolicyNo VARCHAR(20),
			PolicyHolderName VARCHAR(200),
			PolicyHolderDOB VARCHAR(20),
			PolicyHolderRelation VARCHAR(20),
			InsuranceCompanyName VARCHAR(200),
			CompanyType VARCHAR(50)
		)
		INSERT INTO @PrimaryInsuranceLab
		SELECT InvoiceId,InsuranceCompanyId,PolicyNo,PolicyHolderName,PolicyHolderDOB,B.Description,C.CompanyName ,D.CompanyType
		from PI_ATC_LAB.dbo.Claim (NOLOCK)A
		LEFT JOIN PI_ATC_LAB.dbo.ConfigRelationship(NOLOCK) B on B.Id=A.PolicyHolderRelation
		LEFT JOIN PI_ATC_LAB.dbo.InsuranceCompany(NOLOCK) C on C.Id=A.InsuranceCompanyId
		LEFT JOIN PI_ATC_LAB.dbo.ConfigInsuranceCompanyType D on D.Id=C.CompanyTypeId
		WHERE A.Id IN (SELECT MAX(Id) FROM PI_ATC_LAB.dbo.Claim(NOLOCK) B WHERE B.InvoiceId=A.InvoiceId)


		DECLARE @ChargeNotesClinic TABLE
		(
			CategoryName VARCHAR(100),
			ChargeId INT,
			Note VARCHAR(2000),
			HasFollowUp VARCHAR(10),
			FollowUpDate DATE,
			ChargeNoteCreatedBy VARCHAR(100),
			ChargeNoteCreatedDate DATE
		)

		INSERT INTO @ChargeNotesClinic
		SELECT B.CategoryName,ChargeId,Note,CASE WHEN ISNULL(A.HasFollowUp,0) =0 THEN 'No' ELSE 'Yes' END HasFollowUp,
		FollowUpDate,UserName AS CreatedBy,A.CreatedDate
		 FROM PI_ATC_CLINIC.dbo.ActionNote A (NOLOCK) 
		 LEFT JOIN PI_ATC_CLINIC.dbo.ActionCategory B on B.Id=A.ActionSubCategoryId
		WHERE A.UserName!='System' AND A.NoteSourceCD='NS.CHARGE' AND ISNULL(A.IsTransfered,0)=0
		AND A.CreatedDate=(SELECT MAX(CreatedDate) FROM PI_ATC_CLINIC.dbo.ActionNote(NOLOCK) X WHERE X.ChargeId=A.ChargeId AND X.UserName!='System' AND X.NoteSourceCD='NS.CHARGE')
		
		DECLARE @ChargeNotesLab TABLE
		(
			CategoryName VARCHAR(100),
			ChargeId INT,
			Note VARCHAR(2000),
			HasFollowUp VARCHAR(10),
			FollowUpDate DATE,
			ChargeNoteCreatedBy VARCHAR(100),
			ChargeNoteCreatedDate DATE
		)

		INSERT INTO @ChargeNotesLab
		SELECT B.CategoryName,ChargeId,Note,CASE WHEN ISNULL(A.HasFollowUp,0) =0 THEN 'No' ELSE 'Yes' END HasFollowUp,
		FollowUpDate,UserName AS CreatedBy,A.CreatedDate
		 FROM PI_ATC_LAB.dbo.ActionNote A (NOLOCK) 
		 LEFT JOIN PI_ATC_LAB.dbo.ActionCategory B on B.Id=A.ActionSubCategoryId
		WHERE A.UserName!='System' AND A.NoteSourceCD='NS.CHARGE' AND ISNULL(A.IsTransfered,0)=0
		AND A.CreatedDate=(SELECT MAX(CreatedDate) FROM PI_ATC_LAB.dbo.ActionNote(NOLOCK) X WHERE X.ChargeId=A.ChargeId AND X.UserName!='System' AND X.NoteSourceCD='NS.CHARGE')  
		
		
		TRUNCATE TABLE ChargesForCatalystExcel
		INSERT INTO ChargesForCatalystExcel(FirstName,LastName,DOB,Sex,visit_id,mrn,ChargePostDate,dos,specimen_id,insurance_name,financial_class,physician,npi,billing_status,payer_status,ChargeId,CPTCode,ServiceDescription,
				PrimaryDX,DX2,DX3,DX4,Mod1,Mod2,Mod3,Mod4,ChargeAmount,billing_date,PaidAmount,totaladj,carc_code,RemitDate,Adjudicated,Check_number,InsuranceCompanyName,DepositFinancialClass,
				policy_number,facility,mr_upload_date,ar_note,last_touch_date,ReviewNeeded,Billable,ReviewComments,AccessionNumber,PatientAddress1,PatientAddress2,PatientState,PatientCity,
				PatientZip,ERAmount,ServiceClassification,SourceDB,PatientNote,NoteCreatedBy,NoteCreatedDate,POSId,DueBy,ClaimId,DueAmount,CategoryName,FollowUpDate,HasFollowUp,Note,
				ChargeNoteCreatedBy,ChargeNoteCreatedDate,PaymentPostingDate)
		SELECT DISTINCT B.FirstName,B.LastName,CONVERT(varchar,B.DOB,101)DOB,B.Sex,A.InvoiceId [visit_id],B.Id [mrn],CONVERT(varchar,A.CreatedDate,101)[ChargePostDate],
		CONVERT(varchar,A.BillFromDate,101)[dos],A.AccessionNumber[specimen_id],
				--A.InsuranceCompanyName[insurance_name],
			CASE WHEN VC.IsSelfPayment=1 Then 'Self' ELSE	INS.CompanyName END [insurance_name],
				ICT.CompanyType[financial_class],(PD.LastName+' '+PD.FirstName)[physician],PDI.Identifier[npi],
				CASE WHEN CLM.SentDate is not NULL then 'Billed' ELSE 'Not Billed' END [billing_status],
				CASE WHEN (A.PaymentReceived=1 AND CLM.SentDate IS NOT NULL) THEN 'Received' WHEN (A.PaymentReceived=0 AND CLM.SentDate IS NOT NULL) THEN 'NOT Received' END [payer_status],
				A.Id[ChargeId],A.CPTCode,A.Description[ServiceDescription],A.ICD1 PrimaryDX,A.ICD2 DX2,A.ICD3 DX3,A.ICD4 DX4,A.Mod1,A.Mod2,A.Mod3,A.Mod4,
				--A.ChargeAmount,
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY A.Id ORDER BY A.Id ASC))=1 THEN A.ChargeAmount ELSE 0 END[ChargeAmount],
				CONVERT(varchar,CLM.SentDate,101)[billing_date],
				--ROW_NUMBER() OVER(PARTITION BY PC.Id ORDER BY PC.Id ASC),				
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY PC.Id ORDER BY PC.Id ASC))=1 THEN PC.PaidAmount ELSE 0 END[PaidAmount],
				--PC.PaidAmount,
				PA.Amount [totaladj],
				PA.ReasonCode [carc_code],								
				CONVERT(varchar,VC.EffectiveDate,101)[RemitDate],
				CASE WHEN (A.PaymentReceived=1 AND CLM.SentDate IS NOT NULL) THEN 'YES' WHEN (A.PaymentReceived=0 AND CLM.SentDate IS NOT NULL) THEN 'No' END [Adjudicated],
				VC.ReferenceNo[Check_number],ISNULL(A.InsuranceCompanyName,PINS.InsuranceCompanyName)[InsuranceCompanyName],ISNULL(A.FinancialClass,PINS.CompanyType)[DepositFinancialClass],
				dbo.ufn_ActiveInsuranceForCaseNo_PolicyNumber(A.BillFromDate,1,A.PatientCaseId)[policy_number],				
				ISNULL(FC.ChildFacilityName,'Other')[facility],
				--FCI.Identifier [Facility NPI],
				null [mr_upload_date],null [ar_note],null [last_touch_date],A.ReviewNeeded,A.Billable,A.ReviewComments,A.AccessionNumber,
				B.Address1[PatientAddress1],B.Address2[PatientAddress2],B.State[PatientState],B.City[PatientCity],B.ZipCode[PatientZip],
				--A.FeeAmount[ERAmount]
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY A.Id ORDER BY A.Id ASC))=1 THEN A.FeeAmount ELSE 0 END[ERAmount]
				, CASE WHEN INV.InvoiceType=1 THEN 'MH' WHEN INV.InvoiceType=2 THEN 'SUD' ELSE 'NA' END[ServiceClassification] ,'Clinic' SourceDB,
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY B.Id ORDER BY B.Id ASC))=1 THEN PatientNote ELSE '' END[PatientNote],
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY B.Id ORDER BY B.Id ASC))=1 THEN NoteCreatedBy ELSE '' END[NoteCreatedBy],
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY B.Id ORDER BY B.Id ASC))=1 THEN CONVERT(varchar,NoteCreatedDate,101) ELSE '' END[NoteCreatedDate]		,
				A.POSId,A.DueByFlagCD[DueBy],CLM.PatientAccountNumber AS ClaimId
				--CASE WHEN (ROW_NUMBER() OVER(PARTITION BY A.Id ORDER BY A.Id ASC))=1 THEN CLM.PatientAccountNumber ELSE '' END ClaimId	
				,A.DueAmount
				,CHNote.CategoryName,CHNote.FollowUpDate,CHNote.HasFollowUp,CHNote.Note,CHNote.ChargeNoteCreatedBy,CHNote.ChargeNoteCreatedDate,PC.ModifiedDate
		FROM vw_GetChargeForPendingPayment_Dashboard A
		INNER JOIN Patient(NOLOCK) B on B.DefaultCaseId=A.PatientCaseId		
		LEFT JOIN Provider(NOLOCK) PD ON PD.Id=A.PerformingProviderId
		LEFT JOIN ProviderIdentity PDI ON PDI.ProviderId=PD.Id and TypeId=1
		LEFT JOIN Claim (NOLOCK) CLM ON CLM.Id=A.ClaimId
		LEFT JOIN PaymentCharge (NOLOCK) PC ON PC.ChargeId=A.Id 
		LEFT JOIN PaymentAdjustment (NOLOCK) PA ON PA.PaymentChargeId=PC.Id
		LEFT JOIN Payment(NOLOCK) PP ON PP.Id=PC.PaymentId
		LEFT JOIN InsuranceCompany(NOLOCK) INS ON INS.Id=PP.PatientInsuranceCompanyId
		LEFT JOIN ConfigInsuranceCompanyType(NOLOCK) ICT  ON ICT.Id=INS.CompanyTypeId
		LEFT JOIN Voucher(NOLOCK) VC ON VC.Id=PP.VoucherId
		LEFT JOIN Facility(NOLOCK) FC ON FC.Id=A.PerformingFacilityId	
		LEFT JOIN FacilityIdentity (NOLOCK) FCI ON FCI.FacilityId=FC.Id AND FCI.TypeId=1	
		INNER JOIN Invoice(NOLOCK) INV on INV.Id=A.InvoiceId
		LEFT JOIN @PatientNoteClinic PNC ON PNC.PatientId=B.Id
		LEFT JOIN @PrimaryInsuranceClinic PINS ON PINS.InvoiceId=INV.Id
		LEFT JOIN @ChargeNotesClinic CHNote ON CHNote.ChargeId=A.Id
		
		UNION
		
		SELECT DISTINCT B.FirstName,B.LastName,CONVERT(varchar,B.DOB,101)DOB,B.Sex,A.InvoiceId [visit_id],B.Id [mrn],CONVERT(varchar,A.CreatedDate,101)[ChargePostDate],
		CONVERT(varchar,A.BillFromDate,101)[dos],A.AccessionNumber[specimen_id],
				--A.InsuranceCompanyName[insurance_name],
			CASE WHEN VC.IsSelfPayment=1 Then 'Self' ELSE	INS.CompanyName END [insurance_name],
				ICT.CompanyType[financial_class],(PD.LastName+' '+PD.FirstName)[physician],PD.NPI [npi],
				CASE WHEN CLM.SentDate is not NULL then 'Billed' ELSE 'Not Billed' END [billing_status],
				CASE WHEN (A.PaymentReceived=1 AND CLM.SentDate IS NOT NULL) THEN 'Received' WHEN (A.PaymentReceived=0 AND CLM.SentDate IS NOT NULL) THEN 'NOT Received' END [payer_status],
				A.Id[ChargeId],A.CPTCode,CPT.Description[ServiceDescription],A.ICD1 PrimaryDX,A.ICD2 DX2,A.ICD3 DX3,A.ICD4 DX4,A.Mod1,A.Mod2,A.Mod3,A.Mod4,
				--A.ChargeAmount,
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY A.Id ORDER BY A.Id ASC))=1 THEN A.ChargeAmount ELSE 0 END[ChargeAmount],
				CONVERT(varchar,CLM.SentDate,101)[billing_date],
				--ROW_NUMBER() OVER(PARTITION BY PC.Id ORDER BY PC.Id ASC),				
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY PC.Id ORDER BY PC.Id ASC))=1 THEN PC.PaidAmount ELSE 0 END[PaidAmount],
				--PC.PaidAmount,
				PA.Amount [totaladj],
				PA.ReasonCode [carc_code],								
				CONVERT(varchar,VC.EffectiveDate,101)[RemitDate],
				CASE WHEN (A.PaymentReceived=1 AND CLM.SentDate IS NOT NULL) THEN 'YES' WHEN (A.PaymentReceived=0 AND CLM.SentDate IS NOT NULL) THEN 'No' END [Adjudicated],
				VC.ReferenceNo[Check_number],ISNULL(A.InsuranceCompanyName,PINS.InsuranceCompanyName)[InsuranceCompanyName],ISNULL(A.FinancialClass,PINS.CompanyType)[DepositFinancialClass],
				PI_ATC_LAB.dbo.ufn_ActiveInsuranceForCaseNo_PolicyNumber(A.BillFromDate,1,A.PatientCaseId)[policy_number],				
				ISNULL(FC.Name,'Other')[facility],
				--FCI.Identifier [Facility NPI],
				null [mr_upload_date],null [ar_note],null [last_touch_date],A.ReviewNeeded,A.Billable,A.ReviewComments,A.AccessionNumber,
				B.Address1[PatientAddress1],B.Address2[PatientAddress2],B.State[PatientState],B.City[PatientCity],B.ZipCode[PatientZip],
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY A.Id ORDER BY A.Id ASC))=1 THEN
					CASE WHEN A.CPTCode='80305' THEN 10.1 
					WHEN A.CPTCode='80307' THEN 53.87 
					WHEN A.CPTCode='G0480' THEN 85.82 
					WHEN A.CPTCode='G0481' THEN 117.44
					WHEN A.CPTCode='G0482' THEN 149.08 ELSE 0 END				
				ELSE 0 END	[ERAmount]
				, 'LAB'[ServiceClassification] ,'LAB' SourceDB,
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY B.Id ORDER BY B.Id ASC))=1 THEN PatientNote ELSE '' END[PatientNote],
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY B.Id ORDER BY B.Id ASC))=1 THEN NoteCreatedBy ELSE '' END[NoteCreatedBy],
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY B.Id ORDER BY B.Id ASC))=1 THEN CONVERT(varchar,NoteCreatedDate,101) ELSE '' END[NoteCreatedDate]		,
				A.POSId,A.DueByFlagCD[DueBy],CLM.PatientAccountNumber AS ClaimId
				--CASE WHEN (ROW_NUMBER() OVER(PARTITION BY A.Id ORDER BY A.Id ASC))=1 THEN CLM.PatientAccountNumber ELSE '' END ClaimId		
				,A.DueAmount	
				,CHNote.CategoryName,CHNote.FollowUpDate,CHNote.HasFollowUp,CHNote.Note,CHNote.ChargeNoteCreatedBy,CHNote.ChargeNoteCreatedDate,PC.ModifiedDate
		FROM PI_ATC_LAB.dbo.vw_GetChargeForPendingPayment_Dashboard A
		INNER JOIN PI_ATC_LAB.dbo.Patient(NOLOCK) B on B.DefaultCaseId=A.PatientCaseId				
		LEFT JOIN PI_ATC_LAB.dbo.Claim (NOLOCK) CLM ON CLM.Id=A.ClaimId
		LEFT JOIN PI_ATC_LAB.dbo.PaymentCharge (NOLOCK) PC ON PC.ChargeId=A.Id 
		LEFT JOIN PI_ATC_LAB.dbo.PaymentAdjustment (NOLOCK) PA ON PA.PaymentChargeId=PC.Id
		LEFT JOIN PI_ATC_LAB.dbo.Payment(NOLOCK) PP ON PP.Id=PC.PaymentId
		LEFT JOIN PI_ATC_LAB.dbo.InsuranceCompany(NOLOCK) INS ON INS.Id=PP.PatientInsuranceCompanyId
		LEFT JOIN PI_ATC_LAB.dbo.ConfigInsuranceCompanyType(NOLOCK) ICT  ON ICT.Id=INS.CompanyTypeId		
		LEFT JOIN PI_ATC_LAB.dbo.Voucher(NOLOCK) VC ON VC.Id=PP.VoucherId
		LEFT JOIN PI_ATC_LAB.dbo.Facility(NOLOCK) FC ON FC.Id=A.PerformingFacilityId	
		LEFT JOIN PI_ATC_LAB.dbo.FacilityIdentity (NOLOCK) FCI ON FCI.FacilityId=FC.Id AND FCI.TypeId=1	
		LEFT JOIN PI_ATC_LAB.dbo.CptCode (NOLOCK) CPT ON CPT.CPTCode=A.CPTCode
		INNER JOIN PI_ATC_LAB.dbo.Invoice(NOLOCK) INV on INV.Id=A.InvoiceId
		LEFT JOIN PI_ATC_LAB.dbo.ReferringDoctor(NOLOCK) PD ON PD.Id=INV.RefDoctorId
		LEFT JOIN @PatientNoteLAB PNC ON PNC.PatientId=B.Id
		LEFT JOIN @PrimaryInsuranceClinic PINS ON PINS.InvoiceId=INV.Id
		LEFT JOIN @ChargeNotesLab CHNote ON CHNote.ChargeId=A.Id
		
END


GO

-- LEVE DB  -- Updated now
CREATE PROCEDURE [dbo].[usp_ImportChargesInDataWareHouseTable]
AS
BEGIN
	
	TRUNCATE TABLE ChargesReportData

	

		DECLARE @Temp TABLE
		(
			Id INT Identity(1,1),
			MinRange		INT,
			MaxRange		INT,
			Description		VARCHAR(50)
		)
		INSERT INTO @Temp
		SELECT 0,29,'30'
		INSERT INTO @Temp
		SELECT 30,59,'60'
		INSERT INTO @Temp
		SELECT 60,89,'90'
		INSERT INTO @Temp
		SELECT 90,119,'120'
		INSERT INTO @Temp
		SELECT 120,2000,'120+'

		DECLARE @PatientPayment TABLE
		(
			ChargeId INT,
			PaidAmount MONEY
		)
		INSERT INTO @PatientPayment
		SELECT A.ChargeId,SUM(A.PaidAmount) from PaymentCharge(NOLOCK) A
			INNER JOIN Payment(NOLOCK) B ON A.PaymentId=B.Id 
			INNER JOIN Voucher (NOLOCK) C ON C.Id=B.VoucherId
		WHERE IsSelfPayment=1 AND A.PaidAmount>0
		GROUP BY A.ChargeId

		DECLARE @PrimaryInsurance TABLE
		(
			InvoiceId INT,
			InsuranceCompanyId INT,
			PolicyNo VARCHAR(20),
			PolicyHolderName VARCHAR(200),
			PolicyHolderDOB VARCHAR(20),
			PolicyHolderRelation VARCHAR(20),
			InsuranceCompanyName VARCHAR(200),
			CompanyType VARCHAR(50),
			PatientAccountNumber VARCHAR(100),
			ICNNumber VARCHAR(100),
			SentDate DATETIME,
			PriorAuthorizationNumber VARCHAR(50)
		)
		INSERT INTO @PrimaryInsurance
		SELECT InvoiceId,InsuranceCompanyId,PolicyNo,PolicyHolderName,PolicyHolderDOB,B.Description,ISNULL(C.CompanyName,A.ClaimToAddress1) ,D.CompanyType,
		A.PatientAccountNumber,A.PatientControlNumber,A.SentDate,CT.PriorAuthorizationNumber
		from Claim (NOLOCK)A
		LEFT JOIN ConfigRelationship(NOLOCK) B on B.Id=A.PolicyHolderRelation
		LEFT JOIN InsuranceCompany(NOLOCK) C on C.Id=A.InsuranceCompanyId
		LEFT JOIN ConfigInsuranceCompanyType D on D.Id=C.CompanyTypeId
		LEFT JOIN ClaimTotal(NOLOCK) CT on CT.ClaimId=A.Id AND CT.PriorAuthorizationNumber is not null
		WHERE A.Id IN (SELECT MAX(Id) FROM Claim B WHERE B.InvoiceId=A.InvoiceId  AND B.InsLevel=1)

		DECLARE @SecondaryInsurance TABLE
		(
			InvoiceId INT,
			InsuranceCompanyId INT,
			PolicyNo VARCHAR(20),
			PolicyHolderName VARCHAR(200),
			PolicyHolderDOB VARCHAR(20),
			PolicyHolderRelation VARCHAR(20),
			InsuranceCompanyName VARCHAR(200),
			CompanyType VARCHAR(50),
			PatientAccountNumber VARCHAR(100),
			ICNNumber VARCHAR(100),
			SentDate DATETIME,
			PriorAuthorizationNumber VARCHAR(50)
		)
		INSERT INTO @SecondaryInsurance
		SELECT InvoiceId,InsuranceCompanyId,PolicyNo,PolicyHolderName,PolicyHolderDOB,B.Description,ISNULL(C.CompanyName,A.ClaimToAddress1) ,D.CompanyType,
		A.PatientAccountNumber,A.PatientControlNumber,A.SentDate,CT.PriorAuthorizationNumber
		from Claim (NOLOCK)A
		LEFT JOIN ConfigRelationship(NOLOCK) B on B.Id=A.PolicyHolderRelation
		LEFT JOIN InsuranceCompany(NOLOCK) C on C.Id=A.InsuranceCompanyId
		LEFT JOIN ConfigInsuranceCompanyType D on D.Id=C.CompanyTypeId
		LEFT JOIN ClaimTotal(NOLOCK) CT on CT.ClaimId=A.Id AND CT.PriorAuthorizationNumber is not null
		WHERE A.Id IN (SELECT MAX(Id) FROM Claim B WHERE B.InvoiceId=A.InvoiceId  AND B.InsLevel=2)


		DECLARE @ChargeNotes TABLE
		(
			CategoryName VARCHAR(100),
			ChargeId INT,
			Note VARCHAR(2000),
			HasFollowUp VARCHAR(10),
			FollowUpDate DATE,
			ChargeNoteCreatedBy VARCHAR(100),
			ChargeNoteCreatedDate DATE
		)

		INSERT INTO @ChargeNotes
		SELECT B.CategoryName,ChargeId,Note,CASE WHEN ISNULL(A.HasFollowUp,0) =0 THEN 'No' ELSE 'Yes' END HasFollowUp,
		FollowUpDate,UserName AS CreatedBy,A.CreatedDate
		 FROM ActionNote A (NOLOCK) 
		 LEFT JOIN ActionCategory B on B.Id=A.ActionSubCategoryId
		WHERE A.UserName!='System' AND A.NoteSourceCD='NS.CHARGE' AND ISNULL(A.IsTransfered,0)=0
		AND A.CreatedDate=(SELECT MAX(CreatedDate) FROM ActionNote(NOLOCK) X WHERE X.ChargeId=A.ChargeId AND X.UserName!='System' AND X.NoteSourceCD='NS.CHARGE')


		DECLARE @TempAdjustmentCode TABLE
		(
			ChargeId INT,
			ReasonCode VARCHAR(2000)
		)

		INSERT INTO @TempAdjustmentCode
		SELECT  distinct  ChargeId,ReasonCode  
		FROM PaymentAdjustment A(NOLOCK)      
		INNER JOIN PaymentCharge B(NOLOCK) ON A.PaymentChargeId=B.Id  		
		INNER JOIN Payment C(NOLOCK) ON C.Id=B.PaymentId
		INNER JOIN Voucher D(NOLOCK) ON D.Id=C.VoucherId
		WHERE D.Id=(SELECT TOP 1 Id FROM Voucher(NOLOCK) WHERE Id=C.VoucherId ORDER BY EffectiveDate DESC)
		AND B.Id=(SELECT MAX(Id) FROM PaymentCharge(NOLOCK) WHERE ChargeId=B.ChargeId  and PaidAmount>=0)  
		--SELECT  distinct  ChargeId,ReasonCode  FROM PaymentAdjustment A(NOLOCK)      
		--INNER JOIN PaymentCharge B(NOLOCK) ON A.PaymentChargeId=B.Id  			

		DECLARE @AdjustmentCode TABLE
		(
			ChargeId INT,
			ReasonCode VARCHAR(2000)
		)

		INSERT INTO @AdjustmentCode
		SELECT  ChargeId,STRING_AGG(ReasonCode,', ')  FROM 
		@TempAdjustmentCode
		GROUP BY ChargeId


		DECLARE @TempPaymentRemarkCode TABLE
		(
			ChargeId INT,
			RemarkCode VARCHAR(2000),
			Solution VARCHAR(MAX)
		)
		INSERT INTO @TempPaymentRemarkCode
		SELECT  distinct ChargeId, X.RemarkCode,(CAST(D.StepNumber AS VARCHAR)+'. '+ D.Solution)[Solution]
			FROM PaymentRemarkCode X(NOLOCK)      
		INNER JOIN  PaymentCharge A(NOLOCK) ON A.Id=X.PaymentChargeId
		INNER JOIN Payment(NOLOCK) B ON B.Id=A.PaymentId
		INNER JOIN Voucher (NOLOCK) C ON C.Id=B.VoucherId
		LEFT JOIN RemarkCodeSolution D ON D.RemarkCode=X.RemarkCode
		WHERE A.Id=(SELECT MAX(Id) FROM PaymentCharge(NOLOCK) WHERE ChargeId=A.ChargeId  and PaidAmount>=0)  
		AND C.Id=(SELECT TOP 1 Id FROM Voucher(NOLOCK) WHERE Id=B.VoucherId ORDER BY EffectiveDate DESC) 

		
		DECLARE @PaymentRemarkCode TABLE
		(
			ChargeId INT,
			RemarkCode VARCHAR(2000),
			Solution VARCHAR(MAX)
		)
		INSERT INTO @PaymentRemarkCode
		SELECT  ChargeId,STRING_AGG(RemarkCode,', '),STRING_AGG(Solution,' ')  FROM (
		SELECT  ChargeId,RemarkCode,STRING_AGG(Solution,' ')[Solution]  FROM 
		@TempPaymentRemarkCode
		GROUP BY ChargeId,RemarkCode) A
		Group by ChargeId
		--INSERT INTO @PaymentRemarkCode
		--SELECT  ChargeId,STRING_AGG(RemarkCode,', '),STRING_AGG(Solution,' ')  FROM 
		--@TempPaymentRemarkCode
		--GROUP BY ChargeId

		

		
		DECLARE @PaymentChargeTable TABLE
		(
			ChargeId INT,
			PaymentPostingDate DATE,
			PaymentEffective DATE
		)
		INSERT INTO @PaymentChargeTable
		SELECT ChargeId,A.ModifiedDate,C.EffectiveDate from PaymentCharge(NOLOCK) A 
		INNER JOIN Payment B ON B.Id=A.PaymentId
		INNER JOIN Voucher C ON C.Id=B.VoucherId
		WHERE  C.Id=(SELECT TOP 1 Id FROM Voucher(NOLOCK) WHERE Id=B.VoucherId ORDER BY EffectiveDate DESC) AND
		A.Id=(SELECT MAX(Id) FROM PaymentCharge(NOLOCK) WHERE ChargeId=A.ChargeId )

	

		DECLARE @TempPaymentAdjustmentCode TABLE
		(
			ChargeId INT,
			ReasonCode varchar(5000),
			IsForWriteOff BIT
		)

		INSERT INTO @TempPaymentAdjustmentCode
		SELECT  distinct ChargeId, ISNULL(C.Description,''),C.IsForWriteOff
		FROM PaymentAdjustment A(NOLOCK)      
		INNER JOIN PaymentCharge B(NOLOCK) ON A.PaymentChargeId=B.Id   
		LEFT JOIN vw_ConfigAdjustmentReasonCode C on A.ReasonCode=REPLACE(C.ReasonCode,'-','')		
		
		
		
		DECLARE @PaymentAdjustmentCode TABLE
		(
			ChargeId INT,
			ReasonCode varchar(5000)			
		)
	

		INSERT INTO @PaymentAdjustmentCode
		SELECT  ChargeId,STRING_AGG(ReasonCode,', ')  FROM 
			@TempPaymentAdjustmentCode WHERE IsForWriteOff =0
		GROUP BY ChargeId

		DECLARE @WriteOffAdjustmentCode TABLE
		(
			ChargeId INT,
			ReasonCode varchar(5000)			
		)
	

		INSERT INTO @WriteOffAdjustmentCode
		SELECT  ChargeId,STRING_AGG(ReasonCode,', ')  FROM 
			@TempPaymentAdjustmentCode WHERE IsForWriteOff =1
		GROUP BY ChargeId
	

		DECLARE @WriteOffTable TABLE
		(
			ChargeId INT,
			Amount MONEY		
		)
		INSERT INTO @WriteOffTable
		SELECT A.ChargeId,SUM(Amount) from (
		SELECT distinct pc.ChargeId,pa.Amount
		FROM PaymentCharge(NOLOCK) pc
		LEFT JOIN PaymentAdjustment(NOLOCK) pa on pc.Id = pa.PaymentChargeId and pa.IsAccounted = 1   and pa.IsDenial = 0   
		INNER JOIN @TempPaymentAdjustmentCode arc on arc.ChargeId=pc.ChargeId AND ISNULL(IsForWriteOff,0)=1 
		AND pc.ChargeId=9111) A
		Group BY A.ChargeId
		
		
		
	
	
		
			INSERT INTO ChargesReportData (ChargeId,ChargeUId,ChargePostDate,DosDate,CptCode,Description,ChargeAmount,Payment,Adjustment,DueAmount,Aging,AgingText,AdjustmentCode,RemarkCodes,Denial,
								InsuranceCompanyId,InsuranceCompanyName,CompanyType,PerforingProviderId,PerforingProviderName,PaymentReceived,ClaimId,ClaimSentDate,ClaimStatus,
								PerformingFacilityId,PerformingFacilityName,DenialAmount,DueBy,ClaimSent,PaymentPostDate,RemitDate,
								InvoiceId,PatientCaseId,PatientId,BillingID,FirstName,LastName,DOB,PatientUId,PerformingProviderUId,PatientCaseUId,InvoiceUId,PatientName,
								AccessionNumber,AgingByPostDate,AgingByPostDateText,FeeAmount,ReasonCodeDescription,WriteOffAmount,WriteOffReasonCode,PatientPayment,COGs
								,BillProviderId,BillProviderName,BillFacilityId,BillFacilityName,OrderringProviderId,OrderringProviderName,SupervisingProviderId,SupervisingProviderName,
								POS,AuthorizationNumber,Mod1,Mod2,Mod3,Mod4,ICD1,ICD2,ICD3,ICD4,QTY,PatientPhone,PatientSSN,PerformingQualification,OrderringQualification,RollUpQty,
								RollUpAccessions,IsRollUp,Deleted,RollUpRefAccession,PrimaryInsuranceCompanyId,PrimaryPolicyNo,PrimaryPolicyHolderName,PrimaryPolicyHolderDOB,
								PrimaryPolicyHolderRelation,PrimaryInsuranceCompanyName,PrimaryCompanyType
								,SecondaryInsuranceCompanyId,SecondaryPolicyNo,SecondaryPolicyHolderName,SecondaryPolicyHolderDOB,SecondaryPolicyHolderRelation,SecondaryInsuranceCompanyName,SecondaryCompanyType
								,Date30,Date60,Date90,Date120,NoteCategoryName,ChargeNote,ChargeNoteDate,IsBillable,NonBillableComments,EmrBillingId,
								PatientAccountNumber,ICNNumber,PatientAccountNumberSecondary,ICNNumberSecondary,AssignedTo,AssignedBy,AssignedDate,
								WriteOffRequestReasonCode,WriteOffRequestComment,WriteOffRequestStatus,WriteOffRequestDate,
								WriteOffRequestBy,WriteOffRequestModifiedDate,InWriteOffQueue,WriteOffRequestReasonCodeDesc,PrimarySentDate,SecondarySentDate,
								IsRejected,RejectedPIN,PerformingProfessionalAbbreviation,PatientStatementCount,PrimaryPriorAuthorizationNumber,SecondaryPriorAuthorizationNumber,
								ReviewNeeded,ReviewComments,Solution)
			SELECT DISTINCT  A.Id,A.UId,A.CreatedDate,A.BillFromDate,A.CPTCode,A.Description,A.Amount,A.PaidAmount,A.TotalAdjustment,A.DueAmount,cast(DATEDIFF(Day,A.BillFromDate,GETDATE())  as varchar)Aging,
			(SELECT Description FROM @Temp where (cast(DATEDIFF(Day,A.BillFromDate,GETDATE())  as varchar))>=MinRange and (cast(DATEDIFF(Day,A.BillFromDate,GETDATE())  as varchar))<=MaxRange) AgingTextt,
			ADC.ReasonCode,		PRC.RemarkCode,		
			CASE WHEN CC.HasDenial=1 AND A.DueAmount>0 THEN 'Yes' ELSE 'No' END,
			A.InsuranceCompanyId,A.InsuranceCompanyName,A.FinancialClass,A.PerformingProviderId,(PR.FirstName+' '+PR.LastName),
			CASE WHEN PaymentReceived=1 THEN 'Yes' ELSE 'No' END,
			A.ClaimId,CLM.SentDate,'' [ClaimStatus], A.PerformingFacilityId,ISNULL(FC.ChildFacilityName,FC.Name)[PerformingFacility],
			CASE WHEN CC.HasDenial=1 AND A.DueAmount>0 THEN A.Amount ELSE 0 END,UPPER(CASE WHEN DueByFlagCD='' THEN 'PATIENT' ELSE DueByFlagCD END)[DueByFlagCD],
			CASE WHEN CLM.SentDate is null THEN 'No' ELSE 'Yes' END,
			PCT.PaymentPostingDate,PCT.PaymentEffective,		
			A.InvoiceId,A.PatientCaseId,PT.Id[PatientId],PT.BillingID,PT.FirstName,PT.LastName,PT.DOB,PT.UId,LOWER(PR.UId),PTC.UId,INV.UId,(PT.LastName+', '+PT.FirstName),
			A.AccessionNumber,cast(DATEDIFF(Day,A.CreatedDate,GETDATE())  as varchar)AgingByPostDate,
			(SELECT Description FROM @Temp where (cast(DATEDIFF(Day,A.CreatedDate,GETDATE())  as varchar))>=MinRange and (cast(DATEDIFF(Day,A.CreatedDate,GETDATE())  as varchar))<=MaxRange) AgingByPostDateText,
			INV.FeeAmount,
			PAC.ReasonCode,
			WRO.Amount [WriteOffAmount],
			WORC.ReasonCode,
			PP.PaidAmount[PatientPayment],ISNULL(CPT.Cogs,1)[Cogs],
			INV.BillProviderId,(PB.FirstName+', '+PB.LastName),INV.BillFacilityId,ISNULL(BFC.ChildFacilityName,BFC.Name),
			INV.OrderringProviderId,(OPB.FirstName+', '+OPB.LastName),INV.SupervisingProviderId,(SPB.FirstName+', '+SPB.LastName),A.POSId,
			ISNULL(AuthorizationNumber,''),A.Mod1,A.Mod2,A.Mod3,A.Mod4,A.ICD1,A.ICD2,A.ICD3,A.ICD4,A.Qty,PT.MobilePhoneNumber,PT.SSN,PCPS.ProvidingService,OCPS.ProvidingService,
			0,--rohit--(SELECT SUM(Qty) FROM Charge(NOLOCK) WHERE RefChargeId=A.Id and IsLocked=1 and IsDeleted=1),
			'',--rohit--(SELECT STRING_AGG(AccessionNumber, ', ') FROM vw_GetChargeForPendingPayment(NOLOCK) WHERE RefChargeId=A.Id and IsLocked=1 and IsDeleted=1),
			CASE WHEN A.IsLocked=1 THEN 'YES' ELSE 'NO' END,CASE WHEN A.IsDeleted=1 THEN 'YES' ELSE 'NO' END,
			'',--rohit--(SELECT AccessionNumber FROM vw_GetChargeForPendingPayment_Dashboard(NOLOCK) WHERE Id=A.RefChargeId),
			PIns.InsuranceCompanyId,PIns.PolicyNo,PIns.PolicyHolderName,PIns.PolicyHolderDOB,PIns.PolicyHolderRelation,PIns.InsuranceCompanyName,PIns.CompanyType
			,SIns.InsuranceCompanyId,SIns.PolicyNo,SIns.PolicyHolderName,SIns.PolicyHolderDOB,SIns.PolicyHolderRelation,SIns.InsuranceCompanyName,SIns.CompanyType,
			DATEADD(MONTH,1,A.CreatedDate),DATEADD(MONTH,2,A.CreatedDate),DATEADD(MONTH,3,A.CreatedDate),DATEADD(MONTH,4,A.CreatedDate),
			ChNotes.CategoryName[NoteCategoryName],ChNotes.Note[ChargeNote],ChNotes.ChargeNoteCreatedDate,INV.IsBillable,INV.NonBillableComments,
			PT.EmrBillingId,PIns.PatientAccountNumber,PIns.ICNNumber,SIns.PatientAccountNumber,SIns.ICNNumber,DQ.AssignedTo,DQ.AssignedBy,DQ.AssignedDate,
			CIWO.ReasonCode,CIWO.Comments,
			CASE WHEN CIWO.StatusId=1 THEN 'Pending' WHEN CIWO.StatusId=2 THEN 'Approved' WHEN CIWO.StatusId=3 THEN 'Rejected' END,
			CIWO.CreatedDate,CIWO.CreatedBy,CIWO.ModifiedDate,CASE WHEN ISNULL(CIWO.Id,0)=0  Then 0 ELSE 1 END,
			'',--rohit--vCAS.Description,
			PIns.SentDate,SIns.SentDate,
			ISNULL(INV.IsRejected,0),INV.RejectedPIN,PCPS.ProfessionalAbbreviation,A.PatientStatementCount,PIns.PriorAuthorizationNumber,SIns.PriorAuthorizationNumber,
			INV.ReviewNeeded,INV.ReviewComments,PRC.Solution
			FROM vw_GetChargeForPendingPayment_Dashboard A		
			LEFT JOIN Invoice(NOLOCK) INV ON INV.Id=A.InvoiceId
			LEFT JOIN Patient(NOLOCK) PT ON PT.DefaultCaseId=A.PatientCaseId
			LEFT JOIN PatientCase(NOLOCK) PTC ON PTC.PatientId=PT.Id
			LEFT JOIN ChargeStat(NOLOCK) CC ON CC.Id=A.Id
			LEFT JOIN Claim (NOLOCK)CLM ON CLM.Id=A.ClaimId
			LEFT JOIN Provider (NOLOCK)PR ON PR.Id=A.PerformingProviderId
			LEFT JOIN Provider (NOLOCK)PB ON PB.Id=INV.BillProviderId
			LEFT JOIN Provider (NOLOCK)SPB ON SPB.Id=INV.SupervisingProviderId
			LEFT JOIN Provider (NOLOCK)OPB ON OPB.Id=INV.OrderringProviderId
			LEFT JOIN Facility(NOLOCK) FC ON FC.Id=A.PerformingFacilityId	
			LEFT JOIN Facility(NOLOCK) BFC ON BFC.Id=INV.BillFacilityId
			LEFT JOIN PatientAuthorizationNumber(NOLOCK) PAN ON PAN.Id=INV.AuthorizationNumberId
			LEFT JOIN @PatientPayment PP ON PP.ChargeId=A.Id
			LEFT JOIN CPTCode CPT(NOLOCK) ON CPT.CPTCode=A.CPTCode
			LEFT JOIN ConfigPractitionerService(NOLOCK) PCPS ON PCPS.Id=PR.PractitionerServiceId
			LEFT JOIN ConfigPractitionerService(NOLOCK) OCPS ON OCPS.Id=OPB.PractitionerServiceId
			LEFT JOIN @PrimaryInsurance PIns ON PIns.InvoiceId=A.InvoiceId
			LEFT JOIN @SecondaryInsurance SIns ON SIns.InvoiceId=A.InvoiceId
			LEFT JOIN @ChargeNotes ChNotes ON ChNotes.ChargeId=A.Id
			LEFT JOIN DenialQueue(NOLOCK) DQ ON DQ.ChargeId=A.Id
			LEFT JOIN ChargeInWriteOff(NOLOCK) CIWO ON CIWO.ChargeId=A.Id
			LEFT JOIN @AdjustmentCode ADC ON ADC.ChargeId=A.Id
			LEFT JOIN @PaymentRemarkCode PRC ON PRC.ChargeId=A.Id
			LEFT JOIN @WriteOffTable WRO ON WRO.ChargeId=A.Id
			LEFT JOIN @WriteOffAdjustmentCode WORC ON WORC.ChargeId=A.Id			
			LEFT JOIN @PaymentChargeTable PCT ON PCT.ChargeId=A.Id
			LEFT JOIN @PaymentAdjustmentCode PAC ON PAC.ChargeId=A.Id 
			--LEFT JOIN vw_ConfigAdjustmentReasonCode vCAS ON vCAS.ReasonCode=CIWO.ReasonCode
			

		update ChargesReportData SET ChargePrimaryCompanyId=B.InsuranceCompanyId,ChargePrimaryCompanyName=ISNULL(C.CompanyName,''),ChargePrimaryCompanyType=ISNULL(D.CompanyType,'')
		FROM ChargesReportData A
		left join InsurancePolicy(NOLOCK) B on B.PatientCaseId=A.PatientCaseId
		left join InsuranceCompany C (NOLOCK) ON C.Id=B.InsuranceCompanyId
		left join ConfigInsuranceCompanyType (NOLOCK) D on D.Id=C.CompanyTypeId
		where B.IsActive=1 AND 
			B.PlanEffectiveDate <= CAST(A.DosDate AS DATE)
				 AND   (B.PlanExpirationDate IS NULL  
				  OR  B.PlanExpirationDate >= CAST(A.DosDate AS DATE))  
				  AND B.InsuranceLevel =1

		update ChargesReportData SET ChargeSecondaryCompanyId=B.InsuranceCompanyId,ChargeSecondaryCompanyName=ISNULL(C.CompanyName,''),ChargeSecondaryCompanyType=ISNULL(D.CompanyType,'')
		FROM ChargesReportData A
		left join InsurancePolicy(NOLOCK) B on B.PatientCaseId=A.PatientCaseId
		left join InsuranceCompany C (NOLOCK) ON C.Id=B.InsuranceCompanyId
		left join ConfigInsuranceCompanyType (NOLOCK) D on D.Id=C.CompanyTypeId
		where B.IsActive=1 AND 
			B.PlanEffectiveDate <= CAST(A.DosDate AS DATE)
				 AND   (B.PlanExpirationDate IS NULL  
				  OR  B.PlanExpirationDate >= CAST(A.DosDate AS DATE))  
				  AND B.InsuranceLevel =2

		update ChargesReportData SET ChargeTertiaryCompanyId=B.InsuranceCompanyId,ChargeTertiaryCompanyName=ISNULL(C.CompanyName,''),ChargeTertiaryCompanyType=ISNULL(D.CompanyType,'')
		FROM ChargesReportData A
		left join InsurancePolicy(NOLOCK) B on B.PatientCaseId=A.PatientCaseId
		left join InsuranceCompany C (NOLOCK) ON C.Id=B.InsuranceCompanyId
		left join ConfigInsuranceCompanyType (NOLOCK) D on D.Id=C.CompanyTypeId
		where B.IsActive=1 AND 
			B.PlanEffectiveDate <= CAST(A.DosDate AS DATE)
				 AND   (B.PlanExpirationDate IS NULL  
				  OR  B.PlanExpirationDate >= CAST(A.DosDate AS DATE))  
				  AND B.InsuranceLevel =3

        
		update ChargesReportData set ChargePrimaryCompanyType='' where ChargePrimaryCompanyType is null
		update ChargesReportData set ChargeSecondaryCompanyType='' where ChargeSecondaryCompanyType is null
		update ChargesReportData set ChargeTertiaryCompanyType='' where ChargeTertiaryCompanyType is null

		UPDATE ChargesReportData SET IsMedicaidCharge=1 WHERE ISNULL(ChargePrimaryCompanyType,'')='Medicaid' OR ISNULL(ChargeSecondaryCompanyType,'')='Medicaid' OR ISNULL(ChargeTertiaryCompanyType,'')='Medicaid'


			update ChargesReportData set ReasonCode1=B.ReasonCode1,ReasonCode2=B.ReasonCode2,ReasonCode3=B.ReasonCode3,ReasonCode4=B.ReasonCode4,
			RemarkCode1=B.RemarkCode1,RemarkCode2=B.RemarkCode2,RemarkCode3=B.RemarkCode3,RemarkCode4=B.RemarkCode4
			from ChargesReportData A		
			cross apply [dbo].[tfn_Split_ChargeReport_AdjustmentsCodes](A.ChargeId,A.AdjustmentCode,',') B 	

			update ChargesReportData set RemarkCode1=B.RemarkCode1,RemarkCode2=B.RemarkCode2,RemarkCode3=B.RemarkCode3,RemarkCode4=B.RemarkCode4
			from ChargesReportData A		
			cross apply [dbo].[tfn_Split_ChargeReport_RemarkCodes](A.ChargeId,A.RemarkCodes,',') B 	

			update ChargesReportData set InsuranceCompanyName='' where InsuranceCompanyName is null		

			Declare @Table TABLE
			(
				Id INT,
				InvoiceId INT,
				ChargeAmount Money,
				FeeAmount MONEY,
				RowId INT	
			)
			INSERT INTO @TABLE
			SELECT A.Id,A.InvoiceId,A.ChargeAmount,A.FeeAmount,(ROW_NUMBER() OVER(PARTITION BY A.InvoiceId ORDER BY A.InvoiceId ASC,A.ChargeAmount Desc)) from ChargesReportData A where AccessionNumber in (
			SELECT AccessionNumber from ChargesReportData group by AccessionNumber having COUNT(AccessionNumber)>1)
					   
			UPDATE CHARGESREPORTDATA SET FEEAMOUNT=0 WHERE ID IN (
			SELECT ID FROM @TABLE  WHERE ROWID=2)

			update ChargesReportData SET Remark1Desc=B.RemarkMessage
			 FROM ChargesReportData A 
			 LEFT JOIN ConfigERARemarkCodes B ON B.RemarkCode=A.RemarkCode1
			 WHERE A.RemarkCode1 IS NOT NULL AND Denial='Yes'

			 update ChargesReportData SET Remark2Desc=B.RemarkMessage
			 FROM ChargesReportData A 
			 LEFT JOIN ConfigERARemarkCodes B ON B.RemarkCode=A.RemarkCode2
			 WHERE A.RemarkCode2 IS NOT NULL AND Denial='Yes'

			 update ChargesReportData SET Remark3Desc=B.RemarkMessage
			 FROM ChargesReportData A 
			 LEFT JOIN ConfigERARemarkCodes B ON B.RemarkCode=A.RemarkCode3
			 WHERE A.RemarkCode3 IS NOT NULL AND Denial='Yes'

			 update ChargesReportData SET Remark4Desc=B.RemarkMessage
			 FROM ChargesReportData A 
			 LEFT JOIN ConfigERARemarkCodes B ON B.RemarkCode=A.RemarkCode4
			 WHERE A.RemarkCode4 IS NOT NULL AND Denial='Yes'

END

GO

CREATE PROCEDURE [dbo].[usp_ImportChargesInDataWareHouseTable_PatientWise] 
@PatientId INT
AS
BEGIN
	
	BEGIN TRY
		BEGIN TRANSACTION TR_DataWareHouse
		
		DELETE FROM ChargesReportData WHERE PatientId=@PatientId

		DECLARe @PatientCaseId INT
		SELECT @PatientCaseId=DefaultCaseId from Patient (NOLOCK) WHERE Id=@PatientId




			DECLARE @Temp TABLE
			(
				Id INT Identity(1,1),
				MinRange		INT,
				MaxRange		INT,
				Description		VARCHAR(50)
			)
			INSERT INTO @Temp
			SELECT 0,29,'30'
			INSERT INTO @Temp
			SELECT 30,59,'60'
			INSERT INTO @Temp
			SELECT 60,89,'90'
			INSERT INTO @Temp
			SELECT 90,119,'120'
			INSERT INTO @Temp
			SELECT 120,2000,'120+'

			DECLARE @PatientPayment TABLE
			(
				ChargeId INT,
				PaidAmount MONEY
			)
			INSERT INTO @PatientPayment
			SELECT A.ChargeId,SUM(A.PaidAmount) from PaymentCharge(NOLOCK) A
				INNER JOIN Payment(NOLOCK) B ON A.PaymentId=B.Id 
				INNER JOIN Voucher (NOLOCK) C ON C.Id=B.VoucherId
			WHERE IsSelfPayment=1 AND A.PaidAmount>0  AND B.PatientId=@PatientId
			GROUP BY A.ChargeId

			DECLARE @PrimaryInsurance TABLE
			(
				InvoiceId INT,
				InsuranceCompanyId INT,
				PolicyNo VARCHAR(20),
				PolicyHolderName VARCHAR(200),
				PolicyHolderDOB VARCHAR(20),
				PolicyHolderRelation VARCHAR(20),
				InsuranceCompanyName VARCHAR(200),
				CompanyType VARCHAR(50),
				PatientAccountNumber VARCHAR(100),
				ICNNumber VARCHAR(100),
				SentDate DATETIME
			)
			INSERT INTO @PrimaryInsurance
			SELECT InvoiceId,InsuranceCompanyId,PolicyNo,PolicyHolderName,PolicyHolderDOB,B.Description,ISNULL(C.CompanyName,A.ClaimToAddress1) ,D.CompanyType,
			A.PatientAccountNumber,A.PatientControlNumber,A.SentDate
			from Claim (NOLOCK)A
			LEFT JOIN ConfigRelationship(NOLOCK) B on B.Id=A.PolicyHolderRelation
			LEFT JOIN InsuranceCompany(NOLOCK) C on C.Id=A.InsuranceCompanyId
			LEFT JOIN ConfigInsuranceCompanyType D on D.Id=C.CompanyTypeId
			WHERE A.Id IN (SELECT MAX(Id) FROM Claim B WHERE B.InvoiceId=A.InvoiceId  AND B.InsLevel=1  AND PatientCaseId=@PatientCaseId)
			AND A.PatientCaseId=@PatientCaseId

			DECLARE @SecondaryInsurance TABLE
			(
				InvoiceId INT,
				InsuranceCompanyId INT,
				PolicyNo VARCHAR(20),
				PolicyHolderName VARCHAR(200),
				PolicyHolderDOB VARCHAR(20),
				PolicyHolderRelation VARCHAR(20),
				InsuranceCompanyName VARCHAR(200),
				CompanyType VARCHAR(50),
				PatientAccountNumber VARCHAR(100),
				ICNNumber VARCHAR(100),
				SentDate DATETIME
			)
			INSERT INTO @SecondaryInsurance
			SELECT InvoiceId,InsuranceCompanyId,PolicyNo,PolicyHolderName,PolicyHolderDOB,B.Description,ISNULL(C.CompanyName,A.ClaimToAddress1) ,D.CompanyType,
			A.PatientAccountNumber,A.PatientControlNumber,A.SentDate
			from Claim (NOLOCK)A
			LEFT JOIN ConfigRelationship(NOLOCK) B on B.Id=A.PolicyHolderRelation
			LEFT JOIN InsuranceCompany(NOLOCK) C on C.Id=A.InsuranceCompanyId
			LEFT JOIN ConfigInsuranceCompanyType D on D.Id=C.CompanyTypeId
			WHERE A.Id IN (SELECT MAX(Id) FROM Claim B WHERE B.InvoiceId=A.InvoiceId  AND B.InsLevel=2  AND PatientCaseId=@PatientCaseId)
			AND A.PatientCaseId=@PatientCaseId

			DECLARE @ChargeNotes TABLE
			(
				CategoryName VARCHAR(100),
				ChargeId INT,
				Note VARCHAR(2000),
				HasFollowUp VARCHAR(10),
				FollowUpDate DATE,
				ChargeNoteCreatedBy VARCHAR(100),
				ChargeNoteCreatedDate DATE
			)

			INSERT INTO @ChargeNotes
		SELECT B.CategoryName,ChargeId,Note,CASE WHEN ISNULL(A.HasFollowUp,0) =0 THEN 'No' ELSE 'Yes' END HasFollowUp,
		FollowUpDate,UserName AS CreatedBy,A.CreatedDate
		 FROM ActionNote A (NOLOCK) 
		 LEFT JOIN ActionCategory B on B.Id=A.ActionSubCategoryId
		WHERE A.UserName!='System' AND A.NoteSourceCD='NS.CHARGE' AND ISNULL(A.IsTransfered,0)=0
		AND A.CreatedDate=(SELECT MAX(CreatedDate) FROM ActionNote(NOLOCK) X WHERE X.ChargeId=A.ChargeId AND X.UserName!='System' AND X.NoteSourceCD='NS.CHARGE' AND X.PatientId=@PatientId)
		AND A.PatientId=@PatientId


			DECLARE @TempAdjustmentCode TABLE
			(
				ChargeId INT,
				ReasonCode VARCHAR(2000)
			)

			INSERT INTO @TempAdjustmentCode
			SELECT  distinct  ChargeId,ReasonCode  FROM PaymentAdjustment A(NOLOCK)      
			INNER JOIN PaymentCharge B(NOLOCK) ON A.PaymentChargeId=B.Id  			
			INNER JOIN Payment C (NOLOCK) ON C.Id=B.PaymentId
			WHERE C.PatientId=@PatientId

			DECLARE @AdjustmentCode TABLE
			(
				ChargeId INT,
				ReasonCode VARCHAR(2000)
			)

			INSERT INTO @AdjustmentCode
			SELECT  ChargeId,STRING_AGG(ReasonCode,', ')  FROM 
			@TempAdjustmentCode
			GROUP BY ChargeId

			DECLARE @TempPaymentRemarkCode TABLE
			(
				ChargeId INT,
				RemarkCode VARCHAR(2000)
			)

			INSERT INTO @TempPaymentRemarkCode
			SELECT  distinct ChargeId, RemarkCode FROM PaymentRemarkCode A(NOLOCK)      
			INNER JOIN PaymentCharge B(NOLOCK) ON A.PaymentChargeId=B.Id   
			INNER JOIN Payment C (NOLOCK) ON C.Id=B.PaymentId
			WHERE C.PatientId=@PatientId
			

			DECLARE @PaymentRemarkCode TABLE
			(
				ChargeId INT,
				RemarkCode VARCHAR(2000)
			)

			INSERT INTO @PaymentRemarkCode
			SELECT  ChargeId,STRING_AGG(RemarkCode,', ')  FROM 
			@TempPaymentRemarkCode
			GROUP BY ChargeId

			DECLARE @WriteOffTable TABLE
			(
				ChargeId INT,
				Amount MONEY
			)
			INSERT INTO @WriteOffTable
			SELECT  pc.ChargeId,SUM(pa.Amount)
			FROM PaymentCharge(NOLOCK) pc
			INNER JOIN Payment C (NOLOCK) ON C.Id=pc.PaymentId
			LEFT JOIN PaymentAdjustment(NOLOCK) pa on pc.Id = pa.PaymentChargeId and pa.IsAccounted = 1   and pa.IsDenial = 0   
			INNER JOIN AdjustmentReasonCode(NOLOCK) arc on REPLACE(arc.ReasonCode,'-','')=pa.ReasonCode AND ISNULL(IsForWriteOff,0)=1
			WHERE C.PatientId=@PatientId
			GROUP BY pc.ChargeId

		
			DECLARE @PaymentChargeTable TABLE
			(
				ChargeId INT,
				PaymentPostingDate DATE,
				PaymentEffective DATE
			)
			INSERT INTO @PaymentChargeTable
			SELECT ChargeId,A.ModifiedDate,C.EffectiveDate 
			from PaymentCharge(NOLOCK) A 
			INNER JOIN Payment B ON B.Id=A.PaymentId
			INNER JOIN Voucher C ON C.Id=B.VoucherId
			WHERE A.Id=(SELECT MAX(Id) FROM PaymentCharge(NOLOCK) WHERE ChargeId=A.ChargeId) 
			AND B.PatientId=@PatientId

	

			DECLARE @TempPaymentAdjustmentCode TABLE
			(
				ChargeId INT,
				ReasonCode varchar(5000),
				IsForWriteOff BIT
			)

			INSERT INTO @TempPaymentAdjustmentCode
			SELECT  distinct ChargeId, ISNULL(C.Description,''),C.IsForWriteOff
			FROM PaymentAdjustment A(NOLOCK)      
			INNER JOIN PaymentCharge B(NOLOCK) ON A.PaymentChargeId=B.Id   
			LEFT JOIN vw_ConfigAdjustmentReasonCode C on A.ReasonCode=REPLACE(C.ReasonCode,'-','')	
			INNER JOIN Payment D ON D.Id=B.PaymentId
			WHERE D.PatientId=@PatientId
		
		
			DECLARE @PaymentAdjustmentCode TABLE
			(
				ChargeId INT,
				ReasonCode varchar(5000),
				IsForWriteOff BIT
			)
	

			INSERT INTO @PaymentAdjustmentCode
			SELECT  ChargeId,STRING_AGG(ReasonCode,', '),IsForWriteOff  FROM 
				@TempPaymentAdjustmentCode
			GROUP BY ChargeId,IsForWriteOff
	
	

	
	
			INSERT INTO ChargesReportData (ChargeId,ChargeUId,ChargePostDate,DosDate,CptCode,Description,ChargeAmount,Payment,Adjustment,DueAmount,Aging,AgingText,AdjustmentCode,RemarkCodes,Denial,
									InsuranceCompanyId,InsuranceCompanyName,CompanyType,PerforingProviderId,PerforingProviderName,PaymentReceived,ClaimId,ClaimSentDate,ClaimStatus,
									PerformingFacilityId,PerformingFacilityName,DenialAmount,DueBy,ClaimSent,PaymentPostDate,RemitDate,
									InvoiceId,PatientCaseId,PatientId,BillingID,FirstName,LastName,DOB,PatientUId,PerformingProviderUId,PatientCaseUId,InvoiceUId,PatientName,
									AccessionNumber,AgingByPostDate,AgingByPostDateText,FeeAmount,ReasonCodeDescription,WriteOffAmount,WriteOffReasonCode,PatientPayment,COGs
									,BillProviderId,BillProviderName,BillFacilityId,BillFacilityName,OrderringProviderId,OrderringProviderName,SupervisingProviderId,SupervisingProviderName,
									POS,AuthorizationNumber,Mod1,Mod2,Mod3,Mod4,ICD1,ICD2,ICD3,ICD4,QTY,PatientPhone,PatientSSN,PerformingQualification,OrderringQualification,RollUpQty,
									RollUpAccessions,IsRollUp,Deleted,RollUpRefAccession,PrimaryInsuranceCompanyId,PrimaryPolicyNo,PrimaryPolicyHolderName,PrimaryPolicyHolderDOB,
									PrimaryPolicyHolderRelation,PrimaryInsuranceCompanyName,PrimaryCompanyType
									,SecondaryInsuranceCompanyId,SecondaryPolicyNo,SecondaryPolicyHolderName,SecondaryPolicyHolderDOB,SecondaryPolicyHolderRelation,SecondaryInsuranceCompanyName,SecondaryCompanyType
									,Date30,Date60,Date90,Date120,NoteCategoryName,ChargeNote,ChargeNoteDate,IsBillable,NonBillableComments,EmrBillingId,
									PatientAccountNumber,ICNNumber,PatientAccountNumberSecondary,ICNNumberSecondary,AssignedTo,AssignedBy,AssignedDate,
									WriteOffRequestReasonCode,WriteOffRequestComment,WriteOffRequestStatus,WriteOffRequestDate,
									WriteOffRequestBy,WriteOffRequestModifiedDate,InWriteOffQueue,WriteOffRequestReasonCodeDesc,PrimarySentDate,SecondarySentDate,
									IsRejected,RejectedPIN,PerformingProfessionalAbbreviation)
			SELECT DISTINCT  A.Id,A.UId,A.CreatedDate,A.BillFromDate,A.CPTCode,A.Description,A.Amount,A.PaidAmount,A.TotalAdjustment,A.DueAmount,cast(DATEDIFF(Day,A.BillFromDate,GETDATE())  as varchar)Aging,
			(SELECT Description FROM @Temp where (cast(DATEDIFF(Day,A.BillFromDate,GETDATE())  as varchar))>=MinRange and (cast(DATEDIFF(Day,A.BillFromDate,GETDATE())  as varchar))<=MaxRange) AgingTextt,
			ADC.ReasonCode,		PRC.RemarkCode,		
			CASE WHEN CC.HasDenial=1 AND A.DueAmount>0 THEN 'Yes' ELSE 'No' END,
			A.InsuranceCompanyId,A.InsuranceCompanyName,A.FinancialClass,A.PerformingProviderId,(PR.FirstName+', '+PR.LastName),
			CASE WHEN PaymentReceived=1 THEN 'Yes' ELSE 'No' END,
			A.ClaimId,CLM.SentDate,'' [ClaimStatus], A.PerformingFacilityId,ISNULL(FC.ChildFacilityName,FC.Name)[PerformingFacility],
			CASE WHEN CC.HasDenial=1 AND A.DueAmount>0 THEN A.Amount ELSE 0 END,UPPER(CASE WHEN DueByFlagCD='' THEN 'PATIENT' ELSE DueByFlagCD END)[DueByFlagCD],
			CASE WHEN CLM.SentDate is null THEN 'No' ELSE 'Yes' END,
			PCT.PaymentPostingDate,PCT.PaymentEffective,		
			A.InvoiceId,A.PatientCaseId,PT.Id[PatientId],PT.BillingID,PT.FirstName,PT.LastName,PT.DOB,PT.UId,LOWER(PR.UId),PTC.UId,INV.UId,(PT.LastName+', '+PT.FirstName),
			A.AccessionNumber,cast(DATEDIFF(Day,A.CreatedDate,GETDATE())  as varchar)AgingByPostDate,
			(SELECT Description FROM @Temp where (cast(DATEDIFF(Day,A.CreatedDate,GETDATE())  as varchar))>=MinRange and (cast(DATEDIFF(Day,A.CreatedDate,GETDATE())  as varchar))<=MaxRange) AgingByPostDateText,
			INV.FeeAmount,
			'',--PAC.ReasonCode,
			WRO.Amount [WriteOffAmount],
			'',--PAC.ReasonCode,
			PP.PaidAmount[PatientPayment],ISNULL(CPT.Cogs,1)[Cogs],
			INV.BillProviderId,(PB.FirstName+', '+PB.LastName),INV.BillFacilityId,ISNULL(BFC.ChildFacilityName,BFC.Name),
			INV.OrderringProviderId,(OPB.FirstName+', '+OPB.LastName),INV.SupervisingProviderId,(SPB.FirstName+', '+SPB.LastName),A.POSId,
			ISNULL(AuthorizationNumber,''),A.Mod1,A.Mod2,A.Mod3,A.Mod4,A.ICD1,A.ICD2,A.ICD3,A.ICD4,A.Qty,PT.PhoneNumber,PT.SSN,PCPS.ProvidingService,OCPS.ProvidingService,
			0,--rohit--(SELECT SUM(Qty) FROM Charge(NOLOCK) WHERE RefChargeId=A.Id and IsLocked=1 and IsDeleted=1),
			'',--rohit--(SELECT STRING_AGG(AccessionNumber, ', ') FROM vw_GetChargeForPendingPayment(NOLOCK) WHERE RefChargeId=A.Id and IsLocked=1 and IsDeleted=1),
			CASE WHEN A.IsLocked=1 THEN 'YES' ELSE 'NO' END,CASE WHEN A.IsDeleted=1 THEN 'YES' ELSE 'NO' END,
			'',--rohit--(SELECT AccessionNumber FROM vw_GetChargeForPendingPayment_Dashboard(NOLOCK) WHERE Id=A.RefChargeId),
			PIns.InsuranceCompanyId,PIns.PolicyNo,PIns.PolicyHolderName,PIns.PolicyHolderDOB,PIns.PolicyHolderRelation,PIns.InsuranceCompanyName,PIns.CompanyType
			,SIns.InsuranceCompanyId,SIns.PolicyNo,SIns.PolicyHolderName,SIns.PolicyHolderDOB,SIns.PolicyHolderRelation,SIns.InsuranceCompanyName,SIns.CompanyType,
			DATEADD(MONTH,1,A.CreatedDate),DATEADD(MONTH,2,A.CreatedDate),DATEADD(MONTH,3,A.CreatedDate),DATEADD(MONTH,4,A.CreatedDate),
			ChNotes.CategoryName[NoteCategoryName],ChNotes.Note[ChargeNote],ChNotes.ChargeNoteCreatedDate,INV.IsBillable,INV.NonBillableComments,
			PT.EmrBillingId,PIns.PatientAccountNumber,PIns.ICNNumber,SIns.PatientAccountNumber,SIns.ICNNumber,DQ.AssignedTo,DQ.AssignedBy,DQ.AssignedDate,
			CIWO.ReasonCode,CIWO.Comments,
			CASE WHEN CIWO.StatusId=1 THEN 'Pending' WHEN CIWO.StatusId=2 THEN 'Approved' WHEN CIWO.StatusId=3 THEN 'Rejected' END,
			CIWO.CreatedDate,CIWO.CreatedBy,CIWO.ModifiedDate,CASE WHEN ISNULL(CIWO.Id,0)=0  Then 0 ELSE 1 END,
			'',--rohit--vCAS.Description,
			PIns.SentDate,SIns.SentDate,
			ISNULL(INV.IsRejected,0),INV.RejectedPIN,PCPS.ProfessionalAbbreviation
			FROM vw_GetChargeForPendingPayment_Dashboard A		
			LEFT JOIN Invoice(NOLOCK) INV ON INV.Id=A.InvoiceId
			LEFT JOIN Patient(NOLOCK) PT ON PT.DefaultCaseId=A.PatientCaseId
			LEFT JOIN PatientCase(NOLOCK) PTC ON PTC.PatientId=PT.Id
			LEFT JOIN ChargeStat(NOLOCK) CC ON CC.Id=A.Id
			LEFT JOIN Claim (NOLOCK)CLM ON CLM.Id=A.ClaimId
			LEFT JOIN Provider (NOLOCK)PR ON PR.Id=A.PerformingProviderId
			LEFT JOIN Provider (NOLOCK)PB ON PB.Id=INV.BillProviderId
			LEFT JOIN Provider (NOLOCK)SPB ON SPB.Id=INV.SupervisingProviderId
			LEFT JOIN Provider (NOLOCK)OPB ON OPB.Id=INV.OrderringProviderId
			LEFT JOIN Facility(NOLOCK) FC ON FC.Id=A.PerformingFacilityId	
			LEFT JOIN Facility(NOLOCK) BFC ON BFC.Id=INV.BillFacilityId
			LEFT JOIN PatientAuthorizationNumber(NOLOCK) PAN ON PAN.Id=INV.AuthorizationNumberId
			LEFT JOIN @PatientPayment PP ON PP.ChargeId=A.Id
			LEFT JOIN CPTCode CPT(NOLOCK) ON CPT.CPTCode=A.CPTCode
			LEFT JOIN ConfigPractitionerService(NOLOCK) PCPS ON PCPS.Id=PR.PractitionerServiceId
			LEFT JOIN ConfigPractitionerService(NOLOCK) OCPS ON OCPS.Id=OPB.PractitionerServiceId
			LEFT JOIN @PrimaryInsurance PIns ON PIns.InvoiceId=A.InvoiceId
			LEFT JOIN @SecondaryInsurance SIns ON SIns.InvoiceId=A.InvoiceId
			LEFT JOIN @ChargeNotes ChNotes ON ChNotes.ChargeId=A.Id
			LEFT JOIN DenialQueue(NOLOCK) DQ ON DQ.ChargeId=A.Id
			LEFT JOIN ChargeInWriteOff(NOLOCK) CIWO ON CIWO.ChargeId=A.Id
			LEFT JOIN @AdjustmentCode ADC ON ADC.ChargeId=A.Id
			LEFT JOIN @PaymentRemarkCode PRC ON PRC.ChargeId=A.Id
			LEFT JOIN @WriteOffTable WRO ON WRO.ChargeId=A.Id
			LEFT JOIN @PaymentChargeTable PCT ON PCT.ChargeId=A.Id
			--LEFT JOIN @PaymentAdjustmentCode PAC ON PAC.ChargeId=A.Id 
			WHERE A.PatientCaseId=@PatientCaseId
			--LEFT JOIN vw_ConfigAdjustmentReasonCode vCAS ON vCAS.ReasonCode=CIWO.ReasonCode


			update ChargesReportData set ReasonCode1=B.ReasonCode1,ReasonCode2=B.ReasonCode2,ReasonCode3=B.ReasonCode3,ReasonCode4=B.ReasonCode4,
			RemarkCode1=B.RemarkCode1,RemarkCode2=B.RemarkCode2,RemarkCode3=B.RemarkCode3,RemarkCode4=B.RemarkCode4
			from ChargesReportData A		
			cross apply [dbo].[tfn_Split_ChargeReport_AdjustmentsCodes](A.ChargeId,A.AdjustmentCode,',') B 	
			WHERE A.PatientId=@PatientId

			update ChargesReportData set RemarkCode1=B.RemarkCode1,RemarkCode2=B.RemarkCode2,RemarkCode3=B.RemarkCode3,RemarkCode4=B.RemarkCode4
			from ChargesReportData A		
			cross apply [dbo].[tfn_Split_ChargeReport_RemarkCodes](A.ChargeId,A.RemarkCodes,',') B 	
			WHERE A.PatientId=@PatientId

			update ChargesReportData set InsuranceCompanyName='' where InsuranceCompanyName is null AND PatientId=@PatientId


			update ChargesReportData SET ChargePrimaryCompanyId=B.InsuranceCompanyId,ChargePrimaryCompanyName=ISNULL(C.CompanyName,''),ChargePrimaryCompanyType=ISNULL(D.CompanyType,'')
			FROM ChargesReportData A
			left join InsurancePolicy(NOLOCK) B on B.PatientCaseId=A.PatientCaseId
			left join InsuranceCompany C (NOLOCK) ON C.Id=B.InsuranceCompanyId
			left join ConfigInsuranceCompanyType (NOLOCK) D on D.Id=C.CompanyTypeId
			where B.IsActive=1 AND 
				B.PlanEffectiveDate <= CAST(A.DosDate AS DATE)
					 AND   (B.PlanExpirationDate IS NULL  
					  OR  B.PlanExpirationDate >= CAST(A.DosDate AS DATE))  
					  AND B.InsuranceLevel =1 AND A.PatientId=@PatientId

			update ChargesReportData SET ChargeSecondaryCompanyId=B.InsuranceCompanyId,ChargeSecondaryCompanyName=ISNULL(C.CompanyName,''),ChargeSecondaryCompanyType=ISNULL(D.CompanyType,'')
		FROM ChargesReportData A
		left join InsurancePolicy(NOLOCK) B on B.PatientCaseId=A.PatientCaseId
		left join InsuranceCompany C (NOLOCK) ON C.Id=B.InsuranceCompanyId
		left join ConfigInsuranceCompanyType (NOLOCK) D on D.Id=C.CompanyTypeId
		where B.IsActive=1 AND 
			B.PlanEffectiveDate <= CAST(A.DosDate AS DATE)
				 AND   (B.PlanExpirationDate IS NULL  
				  OR  B.PlanExpirationDate >= CAST(A.DosDate AS DATE))  
				  AND B.InsuranceLevel =2 AND A.PatientId=@PatientId

		update ChargesReportData SET ChargeTertiaryCompanyId=B.InsuranceCompanyId,ChargeTertiaryCompanyName=ISNULL(C.CompanyName,''),ChargeTertiaryCompanyType=ISNULL(D.CompanyType,'')
		FROM ChargesReportData A
		left join InsurancePolicy(NOLOCK) B on B.PatientCaseId=A.PatientCaseId
		left join InsuranceCompany C (NOLOCK) ON C.Id=B.InsuranceCompanyId
		left join ConfigInsuranceCompanyType (NOLOCK) D on D.Id=C.CompanyTypeId
		where B.IsActive=1 AND 
			B.PlanEffectiveDate <= CAST(A.DosDate AS DATE)
				 AND   (B.PlanExpirationDate IS NULL  
				  OR  B.PlanExpirationDate >= CAST(A.DosDate AS DATE))  
				  AND B.InsuranceLevel =3 AND A.PatientId=@PatientId

		update ChargesReportData set ChargePrimaryCompanyType='' where ChargePrimaryCompanyType is null AND PatientId=@PatientId
		update ChargesReportData set ChargeSecondaryCompanyType='' where ChargeSecondaryCompanyType is null AND PatientId=@PatientId
		update ChargesReportData set ChargeTertiaryCompanyType='' where ChargeTertiaryCompanyType is null AND PatientId=@PatientId

		UPDATE ChargesReportData SET IsMedicaidCharge=1 WHERE  PatientId=@PatientId AND (ISNULL(ChargePrimaryCompanyType,'')='Medicaid'
		OR ISNULL(ChargeSecondaryCompanyType,'')='Medicaid' OR ISNULL(ChargeTertiaryCompanyType,'')='Medicaid')


			DELETE From ChargesReportData_Consolidate WHERE PatientId=@PatientId and DBName='Clinic'

			INSERT INTO ChargesReportData_Consolidate(ChargeId,ChargePostDate,DosDate,CptCode,Description,ChargeAmount,Payment,Adjustment,DueAmount,Aging,AgingText,AdjustmentCode,Denial,InsuranceCompanyId,
				InsuranceCompanyName,CompanyType,PerforingProviderId,PerforingProviderName,PaymentReceived,ClaimId,ClaimSentDate,ClaimStatus,PerformingFacilityId,
				PerformingFacilityName,CreatedDate,DenialAmount,DueBy,ClaimSent,PaymentPostDate,RemitDate,InvoiceId,PatientCaseId,BillingID,FirstName,LastName,DOB,
				PatientId,PatientUId,InvoiceUId,PatientCaseUId,PerformingProviderUId,PatientName,AccessionNumber,AgingByPostDate,AgingByPostDateText,FeeAmount,ReasonCodeDescription,WriteOffAmount,
				DBName,WriteOffReasonCode,PatientPayment,COGs,BillProviderId,BillProviderName,BillFacilityId,BillFacilityName,OrderringProviderId,OrderringProviderName,SupervisingProviderId,SupervisingProviderName,
								POS,AuthorizationNumber,Mod1,Mod2,Mod3,Mod4,ICD1,ICD2,ICD3,ICD4,QTY,PatientPhone,PatientSSN,PerformingQualification,OrderringQualification,RollUpQty,
								RollUpAccessions,IsRollUp,Deleted,RollUpRefAccession,PrimaryInsuranceCompanyId,PrimaryPolicyNo,PrimaryPolicyHolderName,PrimaryPolicyHolderDOB,
								PrimaryPolicyHolderRelation,PrimaryInsuranceCompanyName,PrimaryCompanyType
								,SecondaryInsuranceCompanyId,SecondaryPolicyNo,SecondaryPolicyHolderName,SecondaryPolicyHolderDOB,SecondaryPolicyHolderRelation,SecondaryInsuranceCompanyName,SecondaryCompanyType
								,Date30,Date60,Date90,Date120,RemarkCodes,ReasonCode1,ReasonCode2,ReasonCode3,ReasonCode4,RemarkCode1,RemarkCode2,RemarkCode3,RemarkCode4,
								RefDcotorId,RefDcotorName,NoteCategoryName,ChargeNote,ChargeNoteDate,EmrBillingId,IsBillable,
								NonBillableComments,PatientAccountNumber,ICNNumber,PatientAccountNumberSecondary,ICNNumberSecondary,AssignedTo,
								AssignedBy,AssignedDate,InWriteOffQueue,WriteOffRequestReasonCode,WriteOffRequestReasonCodeDesc,WriteOffRequestComment,WriteOffRequestStatus,
								WriteOffRequestDate,WriteOffRequestBy,WriteOffRequestModifiedDate,IsRejected,RejectedPIN)
			SELECT ChargeId,ChargePostDate,DosDate,CptCode,Description,ChargeAmount,Payment,Adjustment,DueAmount,Aging,AgingText,AdjustmentCode,Denial,InsuranceCompanyId,
				InsuranceCompanyName,CompanyType,PerforingProviderId,PerforingProviderName,PaymentReceived,ClaimId,ClaimSentDate,ClaimStatus,PerformingFacilityId,
				PerformingFacilityName,CreatedDate,DenialAmount,DueBy,ClaimSent,PaymentPostDate,RemitDate,InvoiceId,PatientCaseId,BillingID,FirstName,LastName,DOB,
				PatientId,PatientUId,InvoiceUId,PatientCaseUId,PerformingProviderUId,PatientName,AccessionNumber,AgingByPostDate,AgingByPostDateText,ISNULL(FeeAmount,0)FeeAmount,
				ReasonCodeDescription,WriteOffAmount,'Clinic',WriteOffReasonCode,PatientPayment,COGs,
				BillProviderId,BillProviderName,BillFacilityId,BillFacilityName,OrderringProviderId,OrderringProviderName,SupervisingProviderId,SupervisingProviderName,
								POS,AuthorizationNumber,Mod1,Mod2,Mod3,Mod4,ICD1,ICD2,ICD3,ICD4,QTY,PatientPhone,PatientSSN,PerformingQualification,OrderringQualification,RollUpQty,
								RollUpAccessions,IsRollUp,Deleted,RollUpRefAccession,PrimaryInsuranceCompanyId,PrimaryPolicyNo,PrimaryPolicyHolderName,PrimaryPolicyHolderDOB,
								PrimaryPolicyHolderRelation,PrimaryInsuranceCompanyName,PrimaryCompanyType
								,SecondaryInsuranceCompanyId,SecondaryPolicyNo,SecondaryPolicyHolderName,SecondaryPolicyHolderDOB,SecondaryPolicyHolderRelation,SecondaryInsuranceCompanyName,SecondaryCompanyType
								,Date30,Date60,Date90,Date120,RemarkCodes,ReasonCode1,ReasonCode2,ReasonCode3,ReasonCode4,RemarkCode1,RemarkCode2,RemarkCode3,RemarkCode4,
								RefDcotorId,RefDcotorName,NoteCategoryName,ChargeNote,ChargeNoteDate,EmrBillingId,IsBillable,
								NonBillableComments,PatientAccountNumber,ICNNumber,PatientAccountNumberSecondary,ICNNumberSecondary,AssignedTo,
								AssignedBy,AssignedDate,InWriteOffQueue,WriteOffRequestReasonCode,WriteOffRequestReasonCodeDesc,WriteOffRequestComment,WriteOffRequestStatus,
								WriteOffRequestDate,WriteOffRequestBy,WriteOffRequestModifiedDate,IsRejected,RejectedPIN
			FROM ChargesReportData WHERE PatientId=@PatientId

		COMMIT TRANSACTION TR_DataWareHouse
	END TRY
	BEGIN CATCH
		ROLLBACK TRANSACTION TR_DataWareHouse
	END CATCH
END

GO

CREATE PROCEDURE [dbo].[usp_ImportChargesInDataWareHouseTable_RefreshPatient] 
@PatientId INT
AS
BEGIN
	
	BEGIN TRY
		BEGIN TRANSACTION TR_DataWareHouse
		
		DELETE FROM ChargesReportData WHERE PatientId=@PatientId

		DECLARe @PatientCaseId INT
		SELECT @PatientCaseId=DefaultCaseId from Patient (NOLOCK) WHERE Id=@PatientId




			DECLARE @Temp TABLE
			(
				Id INT Identity(1,1),
				MinRange		INT,
				MaxRange		INT,
				Description		VARCHAR(50)
			)
			INSERT INTO @Temp
			SELECT 0,29,'30'
			INSERT INTO @Temp
			SELECT 30,59,'60'
			INSERT INTO @Temp
			SELECT 60,89,'90'
			INSERT INTO @Temp
			SELECT 90,119,'120'
			INSERT INTO @Temp
			SELECT 120,2000,'120+'

			DECLARE @PatientPayment TABLE
			(
				ChargeId INT,
				PaidAmount MONEY
			)
			INSERT INTO @PatientPayment
			SELECT A.ChargeId,SUM(A.PaidAmount) from PaymentCharge(NOLOCK) A
				INNER JOIN Payment(NOLOCK) B ON A.PaymentId=B.Id 
				INNER JOIN Voucher (NOLOCK) C ON C.Id=B.VoucherId
			WHERE IsSelfPayment=1 AND A.PaidAmount>0  AND B.PatientId=@PatientId
			GROUP BY A.ChargeId

			DECLARE @PrimaryInsurance TABLE
			(
				InvoiceId INT,
				InsuranceCompanyId INT,
				PolicyNo VARCHAR(20),
				PolicyHolderName VARCHAR(200),
				PolicyHolderDOB VARCHAR(20),
				PolicyHolderRelation VARCHAR(20),
				InsuranceCompanyName VARCHAR(200),
				CompanyType VARCHAR(50),
				PatientAccountNumber VARCHAR(100),
				ICNNumber VARCHAR(100),
				SentDate DATETIME
			)
			INSERT INTO @PrimaryInsurance
			SELECT InvoiceId,InsuranceCompanyId,PolicyNo,PolicyHolderName,PolicyHolderDOB,B.Description,ISNULL(C.CompanyName,A.ClaimToAddress1) ,D.CompanyType,
			A.PatientAccountNumber,A.PatientControlNumber,A.SentDate
			from Claim (NOLOCK)A
			LEFT JOIN ConfigRelationship(NOLOCK) B on B.Id=A.PolicyHolderRelation
			LEFT JOIN InsuranceCompany(NOLOCK) C on C.Id=A.InsuranceCompanyId
			LEFT JOIN ConfigInsuranceCompanyType D on D.Id=C.CompanyTypeId
			WHERE A.Id IN (SELECT MAX(Id) FROM Claim B WHERE B.InvoiceId=A.InvoiceId  AND B.InsLevel=1  AND PatientCaseId=@PatientCaseId)
			AND A.PatientCaseId=@PatientCaseId

			DECLARE @SecondaryInsurance TABLE
			(
				InvoiceId INT,
				InsuranceCompanyId INT,
				PolicyNo VARCHAR(20),
				PolicyHolderName VARCHAR(200),
				PolicyHolderDOB VARCHAR(20),
				PolicyHolderRelation VARCHAR(20),
				InsuranceCompanyName VARCHAR(200),
				CompanyType VARCHAR(50),
				PatientAccountNumber VARCHAR(100),
				ICNNumber VARCHAR(100),
				SentDate DATETIME
			)
			INSERT INTO @SecondaryInsurance
			SELECT InvoiceId,InsuranceCompanyId,PolicyNo,PolicyHolderName,PolicyHolderDOB,B.Description,ISNULL(C.CompanyName,A.ClaimToAddress1) ,D.CompanyType,
			A.PatientAccountNumber,A.PatientControlNumber,A.SentDate
			from Claim (NOLOCK)A
			LEFT JOIN ConfigRelationship(NOLOCK) B on B.Id=A.PolicyHolderRelation
			LEFT JOIN InsuranceCompany(NOLOCK) C on C.Id=A.InsuranceCompanyId
			LEFT JOIN ConfigInsuranceCompanyType D on D.Id=C.CompanyTypeId
			WHERE A.Id IN (SELECT MAX(Id) FROM Claim B WHERE B.InvoiceId=A.InvoiceId  AND B.InsLevel=2  AND PatientCaseId=@PatientCaseId)
			AND A.PatientCaseId=@PatientCaseId

			DECLARE @ChargeNotes TABLE
			(
				CategoryName VARCHAR(100),
				ChargeId INT,
				Note VARCHAR(2000),
				HasFollowUp VARCHAR(10),
				FollowUpDate DATE,
				ChargeNoteCreatedBy VARCHAR(100),
				ChargeNoteCreatedDate DATE
			)

			INSERT INTO @ChargeNotes
		SELECT B.CategoryName,ChargeId,Note,CASE WHEN ISNULL(A.HasFollowUp,0) =0 THEN 'No' ELSE 'Yes' END HasFollowUp,
		FollowUpDate,UserName AS CreatedBy,A.CreatedDate
		 FROM ActionNote A (NOLOCK) 
		 LEFT JOIN ActionCategory B on B.Id=A.ActionSubCategoryId
		WHERE A.UserName!='System' AND A.NoteSourceCD='NS.CHARGE' AND ISNULL(A.IsTransfered,0)=0
		AND A.CreatedDate=(SELECT MAX(CreatedDate) FROM ActionNote(NOLOCK) X WHERE X.ChargeId=A.ChargeId AND X.UserName!='System' AND X.NoteSourceCD='NS.CHARGE' AND X.PatientId=@PatientId)
		AND A.PatientId=@PatientId


			DECLARE @TempAdjustmentCode TABLE
			(
				ChargeId INT,
				ReasonCode VARCHAR(2000)
			)

			INSERT INTO @TempAdjustmentCode
			SELECT  distinct  ChargeId,ReasonCode  FROM PaymentAdjustment A(NOLOCK)      
			INNER JOIN PaymentCharge B(NOLOCK) ON A.PaymentChargeId=B.Id  			
			INNER JOIN Payment C (NOLOCK) ON C.Id=B.PaymentId
			WHERE C.PatientId=@PatientId

			DECLARE @AdjustmentCode TABLE
			(
				ChargeId INT,
				ReasonCode VARCHAR(2000)
			)

			INSERT INTO @AdjustmentCode
			SELECT  ChargeId,STRING_AGG(ReasonCode,', ')  FROM 
			@TempAdjustmentCode
			GROUP BY ChargeId

			DECLARE @TempPaymentRemarkCode TABLE
			(
				ChargeId INT,
				RemarkCode VARCHAR(2000)
			)

			INSERT INTO @TempPaymentRemarkCode
			SELECT  distinct ChargeId, RemarkCode FROM PaymentRemarkCode A(NOLOCK)      
			INNER JOIN PaymentCharge B(NOLOCK) ON A.PaymentChargeId=B.Id   
			INNER JOIN Payment C (NOLOCK) ON C.Id=B.PaymentId
			WHERE C.PatientId=@PatientId
			

			DECLARE @PaymentRemarkCode TABLE
			(
				ChargeId INT,
				RemarkCode VARCHAR(2000)
			)

			INSERT INTO @PaymentRemarkCode
			SELECT  ChargeId,STRING_AGG(RemarkCode,', ')  FROM 
			@TempPaymentRemarkCode
			GROUP BY ChargeId

			DECLARE @WriteOffTable TABLE
			(
				ChargeId INT,
				Amount MONEY
			)
			INSERT INTO @WriteOffTable
			SELECT  pc.ChargeId,SUM(pa.Amount)
			FROM PaymentCharge(NOLOCK) pc
			INNER JOIN Payment C (NOLOCK) ON C.Id=pc.PaymentId
			LEFT JOIN PaymentAdjustment(NOLOCK) pa on pc.Id = pa.PaymentChargeId and pa.IsAccounted = 1   and pa.IsDenial = 0   
			INNER JOIN AdjustmentReasonCode(NOLOCK) arc on REPLACE(arc.ReasonCode,'-','')=pa.ReasonCode AND ISNULL(IsForWriteOff,0)=1
			WHERE C.PatientId=@PatientId
			GROUP BY pc.ChargeId

		
			DECLARE @PaymentChargeTable TABLE
			(
				ChargeId INT,
				PaymentPostingDate DATE,
				PaymentEffective DATE
			)
			INSERT INTO @PaymentChargeTable
			SELECT ChargeId,A.ModifiedDate,C.EffectiveDate 
			from PaymentCharge(NOLOCK) A 
			INNER JOIN Payment B ON B.Id=A.PaymentId
			INNER JOIN Voucher C ON C.Id=B.VoucherId
			WHERE A.Id=(SELECT MAX(Id) FROM PaymentCharge(NOLOCK) WHERE ChargeId=A.ChargeId) 
			AND B.PatientId=@PatientId

	

			DECLARE @TempPaymentAdjustmentCode TABLE
			(
				ChargeId INT,
				ReasonCode varchar(5000),
				IsForWriteOff BIT
			)

			INSERT INTO @TempPaymentAdjustmentCode
			SELECT  distinct ChargeId, ISNULL(C.Description,''),C.IsForWriteOff
			FROM PaymentAdjustment A(NOLOCK)      
			INNER JOIN PaymentCharge B(NOLOCK) ON A.PaymentChargeId=B.Id   
			LEFT JOIN vw_ConfigAdjustmentReasonCode C on A.ReasonCode=REPLACE(C.ReasonCode,'-','')	
			INNER JOIN Payment D ON D.Id=B.PaymentId
			WHERE D.PatientId=@PatientId
		
		
			DECLARE @PaymentAdjustmentCode TABLE
			(
				ChargeId INT,
				ReasonCode varchar(5000),
				IsForWriteOff BIT
			)
	

			INSERT INTO @PaymentAdjustmentCode
			SELECT  ChargeId,STRING_AGG(ReasonCode,', '),IsForWriteOff  FROM 
				@TempPaymentAdjustmentCode
			GROUP BY ChargeId,IsForWriteOff
	
	

	
	
			INSERT INTO ChargesReportData (ChargeId,ChargeUId,ChargePostDate,DosDate,CptCode,Description,ChargeAmount,Payment,Adjustment,DueAmount,Aging,AgingText,AdjustmentCode,RemarkCodes,Denial,
									InsuranceCompanyId,InsuranceCompanyName,CompanyType,PerforingProviderId,PerforingProviderName,PaymentReceived,ClaimId,ClaimSentDate,ClaimStatus,
									PerformingFacilityId,PerformingFacilityName,DenialAmount,DueBy,ClaimSent,PaymentPostDate,RemitDate,
									InvoiceId,PatientCaseId,PatientId,BillingID,FirstName,LastName,DOB,PatientUId,PerformingProviderUId,PatientCaseUId,InvoiceUId,PatientName,
									AccessionNumber,AgingByPostDate,AgingByPostDateText,FeeAmount,ReasonCodeDescription,WriteOffAmount,WriteOffReasonCode,PatientPayment,COGs
									,BillProviderId,BillProviderName,BillFacilityId,BillFacilityName,OrderringProviderId,OrderringProviderName,SupervisingProviderId,SupervisingProviderName,
									POS,AuthorizationNumber,Mod1,Mod2,Mod3,Mod4,ICD1,ICD2,ICD3,ICD4,QTY,PatientPhone,PatientSSN,PerformingQualification,OrderringQualification,RollUpQty,
									RollUpAccessions,IsRollUp,Deleted,RollUpRefAccession,PrimaryInsuranceCompanyId,PrimaryPolicyNo,PrimaryPolicyHolderName,PrimaryPolicyHolderDOB,
									PrimaryPolicyHolderRelation,PrimaryInsuranceCompanyName,PrimaryCompanyType
									,SecondaryInsuranceCompanyId,SecondaryPolicyNo,SecondaryPolicyHolderName,SecondaryPolicyHolderDOB,SecondaryPolicyHolderRelation,SecondaryInsuranceCompanyName,SecondaryCompanyType
									,Date30,Date60,Date90,Date120,NoteCategoryName,ChargeNote,ChargeNoteDate,IsBillable,NonBillableComments,EmrBillingId,
									PatientAccountNumber,ICNNumber,PatientAccountNumberSecondary,ICNNumberSecondary,AssignedTo,AssignedBy,AssignedDate,
									WriteOffRequestReasonCode,WriteOffRequestComment,WriteOffRequestStatus,WriteOffRequestDate,
									WriteOffRequestBy,WriteOffRequestModifiedDate,InWriteOffQueue,WriteOffRequestReasonCodeDesc,PrimarySentDate,SecondarySentDate,
									IsRejected,RejectedPIN,PerformingProfessionalAbbreviation)
			SELECT DISTINCT  A.Id,A.UId,A.CreatedDate,A.BillFromDate,A.CPTCode,A.Description,A.Amount,A.PaidAmount,A.TotalAdjustment,A.DueAmount,cast(DATEDIFF(Day,A.BillFromDate,GETDATE())  as varchar)Aging,
			(SELECT Description FROM @Temp where (cast(DATEDIFF(Day,A.BillFromDate,GETDATE())  as varchar))>=MinRange and (cast(DATEDIFF(Day,A.BillFromDate,GETDATE())  as varchar))<=MaxRange) AgingTextt,
			ADC.ReasonCode,		PRC.RemarkCode,		
			CASE WHEN CC.HasDenial=1 AND A.DueAmount>0 THEN 'Yes' ELSE 'No' END,
			A.InsuranceCompanyId,A.InsuranceCompanyName,A.FinancialClass,A.PerformingProviderId,(PR.FirstName+', '+PR.LastName),
			CASE WHEN PaymentReceived=1 THEN 'Yes' ELSE 'No' END,
			A.ClaimId,CLM.SentDate,'' [ClaimStatus], A.PerformingFacilityId,ISNULL(FC.ChildFacilityName,FC.Name)[PerformingFacility],
			CASE WHEN CC.HasDenial=1 AND A.DueAmount>0 THEN A.Amount ELSE 0 END,UPPER(CASE WHEN DueByFlagCD='' THEN 'PATIENT' ELSE DueByFlagCD END)[DueByFlagCD],
			CASE WHEN CLM.SentDate is null THEN 'No' ELSE 'Yes' END,
			PCT.PaymentPostingDate,PCT.PaymentEffective,		
			A.InvoiceId,A.PatientCaseId,PT.Id[PatientId],PT.BillingID,PT.FirstName,PT.LastName,PT.DOB,PT.UId,LOWER(PR.UId),PTC.UId,INV.UId,(PT.LastName+', '+PT.FirstName),
			A.AccessionNumber,cast(DATEDIFF(Day,A.CreatedDate,GETDATE())  as varchar)AgingByPostDate,
			(SELECT Description FROM @Temp where (cast(DATEDIFF(Day,A.CreatedDate,GETDATE())  as varchar))>=MinRange and (cast(DATEDIFF(Day,A.CreatedDate,GETDATE())  as varchar))<=MaxRange) AgingByPostDateText,
			INV.FeeAmount,
			PAC.ReasonCode,
			WRO.Amount [WriteOffAmount],
			PAC.ReasonCode,
			PP.PaidAmount[PatientPayment],ISNULL(CPT.Cogs,1)[Cogs],
			INV.BillProviderId,(PB.FirstName+', '+PB.LastName),INV.BillFacilityId,ISNULL(BFC.ChildFacilityName,BFC.Name),
			INV.OrderringProviderId,(OPB.FirstName+', '+OPB.LastName),INV.SupervisingProviderId,(SPB.FirstName+', '+SPB.LastName),A.POSId,
			ISNULL(AuthorizationNumber,''),A.Mod1,A.Mod2,A.Mod3,A.Mod4,A.ICD1,A.ICD2,A.ICD3,A.ICD4,A.Qty,PT.PhoneNumber,PT.SSN,PCPS.ProvidingService,OCPS.ProvidingService,
			0,--rohit--(SELECT SUM(Qty) FROM Charge(NOLOCK) WHERE RefChargeId=A.Id and IsLocked=1 and IsDeleted=1),
			'',--rohit--(SELECT STRING_AGG(AccessionNumber, ', ') FROM vw_GetChargeForPendingPayment(NOLOCK) WHERE RefChargeId=A.Id and IsLocked=1 and IsDeleted=1),
			CASE WHEN A.IsLocked=1 THEN 'YES' ELSE 'NO' END,CASE WHEN A.IsDeleted=1 THEN 'YES' ELSE 'NO' END,
			'',--rohit--(SELECT AccessionNumber FROM vw_GetChargeForPendingPayment_Dashboard(NOLOCK) WHERE Id=A.RefChargeId),
			PIns.InsuranceCompanyId,PIns.PolicyNo,PIns.PolicyHolderName,PIns.PolicyHolderDOB,PIns.PolicyHolderRelation,PIns.InsuranceCompanyName,PIns.CompanyType
			,SIns.InsuranceCompanyId,SIns.PolicyNo,SIns.PolicyHolderName,SIns.PolicyHolderDOB,SIns.PolicyHolderRelation,SIns.InsuranceCompanyName,SIns.CompanyType,
			DATEADD(MONTH,1,A.CreatedDate),DATEADD(MONTH,2,A.CreatedDate),DATEADD(MONTH,3,A.CreatedDate),DATEADD(MONTH,4,A.CreatedDate),
			ChNotes.CategoryName[NoteCategoryName],ChNotes.Note[ChargeNote],ChNotes.ChargeNoteCreatedDate,INV.IsBillable,INV.NonBillableComments,
			PT.EmrBillingId,PIns.PatientAccountNumber,PIns.ICNNumber,SIns.PatientAccountNumber,SIns.ICNNumber,DQ.AssignedTo,DQ.AssignedBy,DQ.AssignedDate,
			CIWO.ReasonCode,CIWO.Comments,
			CASE WHEN CIWO.StatusId=1 THEN 'Pending' WHEN CIWO.StatusId=2 THEN 'Approved' WHEN CIWO.StatusId=3 THEN 'Rejected' END,
			CIWO.CreatedDate,CIWO.CreatedBy,CIWO.ModifiedDate,CASE WHEN ISNULL(CIWO.Id,0)=0  Then 0 ELSE 1 END,
			'',--rohit--vCAS.Description,
			PIns.SentDate,SIns.SentDate,
			ISNULL(INV.IsRejected,0),INV.RejectedPIN,PCPS.ProfessionalAbbreviation
			FROM vw_GetChargeForPendingPayment_Dashboard A		
			LEFT JOIN Invoice(NOLOCK) INV ON INV.Id=A.InvoiceId
			LEFT JOIN Patient(NOLOCK) PT ON PT.DefaultCaseId=A.PatientCaseId
			LEFT JOIN PatientCase(NOLOCK) PTC ON PTC.PatientId=PT.Id
			LEFT JOIN ChargeStat(NOLOCK) CC ON CC.Id=A.Id
			LEFT JOIN Claim (NOLOCK)CLM ON CLM.Id=A.ClaimId
			LEFT JOIN Provider (NOLOCK)PR ON PR.Id=A.PerformingProviderId
			LEFT JOIN Provider (NOLOCK)PB ON PB.Id=INV.BillProviderId
			LEFT JOIN Provider (NOLOCK)SPB ON SPB.Id=INV.SupervisingProviderId
			LEFT JOIN Provider (NOLOCK)OPB ON OPB.Id=INV.OrderringProviderId
			LEFT JOIN Facility(NOLOCK) FC ON FC.Id=A.PerformingFacilityId	
			LEFT JOIN Facility(NOLOCK) BFC ON BFC.Id=INV.BillFacilityId
			LEFT JOIN PatientAuthorizationNumber(NOLOCK) PAN ON PAN.Id=INV.AuthorizationNumberId
			LEFT JOIN @PatientPayment PP ON PP.ChargeId=A.Id
			LEFT JOIN CPTCode CPT(NOLOCK) ON CPT.CPTCode=A.CPTCode
			LEFT JOIN ConfigPractitionerService(NOLOCK) PCPS ON PCPS.Id=PR.PractitionerServiceId
			LEFT JOIN ConfigPractitionerService(NOLOCK) OCPS ON OCPS.Id=OPB.PractitionerServiceId
			LEFT JOIN @PrimaryInsurance PIns ON PIns.InvoiceId=A.InvoiceId
			LEFT JOIN @SecondaryInsurance SIns ON SIns.InvoiceId=A.InvoiceId
			LEFT JOIN @ChargeNotes ChNotes ON ChNotes.ChargeId=A.Id
			LEFT JOIN DenialQueue(NOLOCK) DQ ON DQ.ChargeId=A.Id
			LEFT JOIN ChargeInWriteOff(NOLOCK) CIWO ON CIWO.ChargeId=A.Id
			LEFT JOIN @AdjustmentCode ADC ON ADC.ChargeId=A.Id
			LEFT JOIN @PaymentRemarkCode PRC ON PRC.ChargeId=A.Id
			LEFT JOIN @WriteOffTable WRO ON WRO.ChargeId=A.Id
			LEFT JOIN @PaymentChargeTable PCT ON PCT.ChargeId=A.Id
			LEFT JOIN @PaymentAdjustmentCode PAC ON PAC.ChargeId=A.Id 
			WHERE A.PatientCaseId=@PatientCaseId
			--LEFT JOIN vw_ConfigAdjustmentReasonCode vCAS ON vCAS.ReasonCode=CIWO.ReasonCode


			update ChargesReportData set ReasonCode1=B.ReasonCode1,ReasonCode2=B.ReasonCode2,ReasonCode3=B.ReasonCode3,ReasonCode4=B.ReasonCode4,
			RemarkCode1=B.RemarkCode1,RemarkCode2=B.RemarkCode2,RemarkCode3=B.RemarkCode3,RemarkCode4=B.RemarkCode4
			from ChargesReportData A		
			cross apply [dbo].[tfn_Split_ChargeReport_AdjustmentsCodes](A.ChargeId,A.AdjustmentCode,',') B 	
			WHERE A.PatientId=@PatientId

			update ChargesReportData set RemarkCode1=B.RemarkCode1,RemarkCode2=B.RemarkCode2,RemarkCode3=B.RemarkCode3,RemarkCode4=B.RemarkCode4
			from ChargesReportData A		
			cross apply [dbo].[tfn_Split_ChargeReport_RemarkCodes](A.ChargeId,A.RemarkCodes,',') B 	
			WHERE A.PatientId=@PatientId

			update ChargesReportData set InsuranceCompanyName='' where InsuranceCompanyName is null AND PatientId=@PatientId

			DELETE From ChargesReportData_Consolidate WHERE PatientId=@PatientId and DBName='Clinic'

			INSERT INTO ChargesReportData_Consolidate(ChargeId,ChargePostDate,DosDate,CptCode,Description,ChargeAmount,Payment,Adjustment,DueAmount,Aging,AgingText,AdjustmentCode,Denial,InsuranceCompanyId,
				InsuranceCompanyName,CompanyType,PerforingProviderId,PerforingProviderName,PaymentReceived,ClaimId,ClaimSentDate,ClaimStatus,PerformingFacilityId,
				PerformingFacilityName,CreatedDate,DenialAmount,DueBy,ClaimSent,PaymentPostDate,RemitDate,InvoiceId,PatientCaseId,BillingID,FirstName,LastName,DOB,
				PatientId,PatientUId,InvoiceUId,PatientCaseUId,PerformingProviderUId,PatientName,AccessionNumber,AgingByPostDate,AgingByPostDateText,FeeAmount,ReasonCodeDescription,WriteOffAmount,
				DBName,WriteOffReasonCode,PatientPayment,COGs,BillProviderId,BillProviderName,BillFacilityId,BillFacilityName,OrderringProviderId,OrderringProviderName,SupervisingProviderId,SupervisingProviderName,
								POS,AuthorizationNumber,Mod1,Mod2,Mod3,Mod4,ICD1,ICD2,ICD3,ICD4,QTY,PatientPhone,PatientSSN,PerformingQualification,OrderringQualification,RollUpQty,
								RollUpAccessions,IsRollUp,Deleted,RollUpRefAccession,PrimaryInsuranceCompanyId,PrimaryPolicyNo,PrimaryPolicyHolderName,PrimaryPolicyHolderDOB,
								PrimaryPolicyHolderRelation,PrimaryInsuranceCompanyName,PrimaryCompanyType
								,SecondaryInsuranceCompanyId,SecondaryPolicyNo,SecondaryPolicyHolderName,SecondaryPolicyHolderDOB,SecondaryPolicyHolderRelation,SecondaryInsuranceCompanyName,SecondaryCompanyType
								,Date30,Date60,Date90,Date120,RemarkCodes,ReasonCode1,ReasonCode2,ReasonCode3,ReasonCode4,RemarkCode1,RemarkCode2,RemarkCode3,RemarkCode4,
								RefDcotorId,RefDcotorName,NoteCategoryName,ChargeNote,ChargeNoteDate,EmrBillingId,IsBillable,
								NonBillableComments,PatientAccountNumber,ICNNumber,PatientAccountNumberSecondary,ICNNumberSecondary,AssignedTo,
								AssignedBy,AssignedDate,InWriteOffQueue,WriteOffRequestReasonCode,WriteOffRequestReasonCodeDesc,WriteOffRequestComment,WriteOffRequestStatus,
								WriteOffRequestDate,WriteOffRequestBy,WriteOffRequestModifiedDate,IsRejected,RejectedPIN)
			SELECT ChargeId,ChargePostDate,DosDate,CptCode,Description,ChargeAmount,Payment,Adjustment,DueAmount,Aging,AgingText,AdjustmentCode,Denial,InsuranceCompanyId,
				InsuranceCompanyName,CompanyType,PerforingProviderId,PerforingProviderName,PaymentReceived,ClaimId,ClaimSentDate,ClaimStatus,PerformingFacilityId,
				PerformingFacilityName,CreatedDate,DenialAmount,DueBy,ClaimSent,PaymentPostDate,RemitDate,InvoiceId,PatientCaseId,BillingID,FirstName,LastName,DOB,
				PatientId,PatientUId,InvoiceUId,PatientCaseUId,PerformingProviderUId,PatientName,AccessionNumber,AgingByPostDate,AgingByPostDateText,ISNULL(FeeAmount,0)FeeAmount,
				ReasonCodeDescription,WriteOffAmount,'Clinic',WriteOffReasonCode,PatientPayment,COGs,
				BillProviderId,BillProviderName,BillFacilityId,BillFacilityName,OrderringProviderId,OrderringProviderName,SupervisingProviderId,SupervisingProviderName,
								POS,AuthorizationNumber,Mod1,Mod2,Mod3,Mod4,ICD1,ICD2,ICD3,ICD4,QTY,PatientPhone,PatientSSN,PerformingQualification,OrderringQualification,RollUpQty,
								RollUpAccessions,IsRollUp,Deleted,RollUpRefAccession,PrimaryInsuranceCompanyId,PrimaryPolicyNo,PrimaryPolicyHolderName,PrimaryPolicyHolderDOB,
								PrimaryPolicyHolderRelation,PrimaryInsuranceCompanyName,PrimaryCompanyType
								,SecondaryInsuranceCompanyId,SecondaryPolicyNo,SecondaryPolicyHolderName,SecondaryPolicyHolderDOB,SecondaryPolicyHolderRelation,SecondaryInsuranceCompanyName,SecondaryCompanyType
								,Date30,Date60,Date90,Date120,RemarkCodes,ReasonCode1,ReasonCode2,ReasonCode3,ReasonCode4,RemarkCode1,RemarkCode2,RemarkCode3,RemarkCode4,
								RefDcotorId,RefDcotorName,NoteCategoryName,ChargeNote,ChargeNoteDate,EmrBillingId,IsBillable,
								NonBillableComments,PatientAccountNumber,ICNNumber,PatientAccountNumberSecondary,ICNNumberSecondary,AssignedTo,
								AssignedBy,AssignedDate,InWriteOffQueue,WriteOffRequestReasonCode,WriteOffRequestReasonCodeDesc,WriteOffRequestComment,WriteOffRequestStatus,
								WriteOffRequestDate,WriteOffRequestBy,WriteOffRequestModifiedDate,IsRejected,RejectedPIN
			FROM ChargesReportData WHERE PatientId=@PatientId
			
			SELECT 0 [Id]			

		COMMIT TRANSACTION TR_DataWareHouse
	END TRY
	BEGIN CATCH
		ROLLBACK TRANSACTION TR_DataWareHouse
	END CATCH
END

GO

CREATE PROCEDURE usp_ImportExcelData
AS
BEGIN
	
	DECLARE @Id INT
	
	
	
	
	DECLARE @ChargeBatchId INT
	SELECT @ChargeBatchId=MAX(Id) FROM ChargeBatch 

	DECLARE @BillProviderId INT=7 -- it will be SUD ATC provider
	DECLARE @BillFacilityId INT=4

	
	
	SELECT @Id=Min(Id) FROM ATC_DATA(NOLOCK)
	
	WHILE @Id IS NOT NULL
	BEGIN
		DECLARE @PatientCaseId INT
		DECLARE @BillingId VARCHAR(10)
		DECLARE @AccessionNumber VARCHAR(20)
		DECLARE @IcdCodes VARCHAR(200)
		DECLARE @BillFromDate DATETIME
		DECLARE @PerfomingNPI VARCHAR(20)
		DECLARE @PerformingProviderId INT
		DECLARE @PerformingFacilityId INT
		DECLARE @InvoiceId INT
		DECLARE @Mod1 VARCHAR(10)=''	
		DECLARE @ICD1 VARCHAR(10)=''
		DECLARE @ICD2 VARCHAR(10)=''
		DECLARE @ICD3 VARCHAR(10)=''
		DECLARE @ICD4 VARCHAR(10)=''

		SELECT @BillingId=MedicalRecord,@AccessionNumber=OrderNumber,@BillFromDate =OrderDate,
			@PerfomingNPI=CollectingProviderNPI,@Mod1=Modifer,@PerformingFacilityId=PerformingFacilityId,
			@IcdCodes=ICDCodes
		FROM ATC_DATA WHERE Id=@Id



		DECLARE @TempIcdCodes TABLE
		(
			Id INT,
			Value VARCHAR(20)
		)
		delete from @TempIcdCodes

		INSERT INTO @TempIcdCodes
		SELECT * FROM dbo.tfn_Split(@IcdCodes,',')
		DECLARE @Counter INT=0
		DECLARE @IcdId INT
		SELECT @IcdId=MIN (Id) FROM @TempIcdCodes WHERE Value not in ('F11.10','F11.13','F15.10','F43.8')

		
		--select * from @TempIcdCodes
		SET @ICD1=''
		SET @ICD2=''
		SET @ICD3=''
		SET @ICD4=''
		WHILE @IcdId IS NOT NULL
		BEGIN
			IF @Counter=0
				SELECT @ICD1= REPLACE(Value,'.','') FROM @TempIcdCodes WHERE Id=@IcdId
			IF @Counter=1
				SELECT @ICD2= REPLACE(Value,'.','') FROM @TempIcdCodes WHERE Id=@IcdId
			IF @Counter=2
				SELECT @ICD3= REPLACE(Value,'.','') FROM @TempIcdCodes WHERE Id=@IcdId
			IF @Counter=3
				SELECT @ICD4= REPLACE(Value,'.','') FROM @TempIcdCodes WHERE Id=@IcdId

			SET @Counter=@Counter+1;
			SELECT @IcdId=MIN (Id) FROM @TempIcdCodes WHERE Value not in ('F11.10','F11.13','F15.10','F43.8')
			AND Id>@IcdId
		END
		--SELECT @IcdCodes,@ICD1[@ICD1],@ICD2[@ICD2],@ICD3[@ICD3],@ICD4[@ICD4]


		
		SELECT @PatientCaseId=DefaultCaseId FROM Patient WHERE BillingID=@BillingId

		SELECT @PerformingProviderId=ProviderId FROM ProviderIdentity WHERE Identifier=@PerfomingNPI

		INSERT INTO Invoice(UId,PracticeId,PatientCaseId,ChargeBatchId,AccessionNumber,EntryDate,
			BillFromDate,BillToDate,BillProviderId,BillFacilityId,FacilityId,AuthorizationNumberId,
			CreatedBy,CreatedDate,ModifiedBy,ModifiedDate,AccEmploy,AccAuto,AccOther,IsDeleted,
			FromTime,ToTime,PerformingProviderId,IsAROldCharges,InvoiceType,ReviewNeeded,IsBillable,FeeAmount)	
		SELECT NEWID(),1,@PatientCaseId,@ChargeBatchId,@AccessionNumber,GETDATE(),
				CAST(@BillFromDate AS DATE),CAST(@BillFromDate AS DATE),@BillProviderId,@BillFacilityId,@BillFacilityId,0,
				'Admin',GETDATE(),'Admin',GETDATE(),0,0,0,0,
				@BillFromDate,DATEADD(MINUTE,10,@BillFromDate),@PerformingProviderId,0,2,0,1,15.0		
		SET @InvoiceId=SCOPE_IDENTITY()

		DECLARE @ChargeNo INT
		SELECT @ChargeNo=MAX(ChargeNo)+1 FROM Charge(NOLOCK) 

		INSERT INTO Charge( UId,PracticeId,EntryDate,BillFromDate,BillToDate,ChargeNo,IsDeleted,IsLocked,PatientCaseId,InvoiceId,IsTaxable,BillToInsurance,BillToPatient,
		BillToClinic,CPTCode,Mod1,Mod2,Mod3,Mod4,ICD1,ICD2,ICD3,ICD4,Description,NDCCode,NDCFormat,TOSId,POSId,PerformingProviderId,PerformingFacilityId,Qty,
		MultiplyQty,Amount,Discount,Tax,CoIns,CoPay,Deductible,DueByFlagCD,CreatedBy,CreatedDate,ModifiedBy,ModifiedDate,PatientStatementCount,ScrubError,
		Comments,Message1,Message2)		
		SELECT top 1 NEWID(),1,GETDATE(),@BillFromDate,@BillFromDate,@ChargeNo,0,0,@PatientCaseId, @InvoiceId,
				0,1,0,0,'H0048',@Mod1,'','','',@ICD1,@ICD2,@ICD3,@ICD4,
				'URINE DRUG SCREEN','',0,'09','11',@PerformingProviderId,@PerformingFacilityId,1,0,
				14.50,0,0,0,0,0,'PRIMARY','Admin',GETDATE(),'Amin',GETDATE(),0,0,'','',''
		
		INSERT INTO  InvDiagnosis(InvoiceId,ICDCode,Description,IsICD10)		
		SELECT @InvoiceId,REPLACE(A.Value,'.',''),B.Description,0 from @TempIcdCodes A
		LEFT JOIN ICDCode B on REPLACE (A.Value,'.','')=B.Code
		WHERE Value not in ('F11.10','F11.13','F15.10','F43.8')

		SELECT @Id=Min(Id) FROM ATC_DATA(NOLOCK) WHERE Id>@Id
	END
END
GO

CREATE PROCEDURE [dbo].[usp_ImportPaymentsInDataWareHouseTable]
AS
BEGIN
	
	
			DECLARE @Temp TABLE
			(
				Id INT Identity(1,1),
				MinRange		INT,
				MaxRange		INT,
				Description		VARCHAR(50)
			)
			INSERT INTO @Temp
			SELECT 0,29,'30'
			INSERT INTO @Temp
			SELECT 30,59,'60'
			INSERT INTO @Temp
			SELECT 60,89,'90'
			INSERT INTO @Temp
			SELECT 90,119,'120'
			INSERT INTO @Temp
			SELECT 120,2000,'120+'


		

			TRUNCATE TABLE PaymentReportData
			
			INSERT INTO PaymentReportData(ChargeId,ChargePostDate,DosDate,CPTCode,Description,ChargeRowNumber,ChargeAmount,PCID,Payment,Adjustment,PaymentPostDate,
										RemitDate,PatientId,BillingID,FirstName,LastName,DOB,PatientUId,PerformingProviderUId,PatientCaseUId,InvoiceUId,PatientName,
										AccessionNumber,Aging,AgingText,AgingByPostDate,AgingByPostDateText,DepositCreationDate,InvoiceId,DepositType,HasDenial,
										IsAccounted)
			SELECT distinct A.Id,A.CreatedDate,A.BillFromDate,A.CPTCode,A.Description,
			(ROW_NUMBER() OVER(PARTITION BY A.Id ORDER BY A.Id ASC))ChargeRowNumber,
			A.ChargeAmount,
			--CASE WHEN (ROW_NUMBER() OVER(PARTITION BY A.Id ORDER BY A.Id ASC))=1 THEN A.ChargeAmount ELSE 0 END[Amount],
			PC.Id,
			CASE WHEN (ROW_NUMBER() OVER(PARTITION BY PC.Id ORDER BY PC.Id asc))=1 THEN PC.PaidAmount+ISNULL(adj.Amount,0) ELSE 0 END[PaidAmount],	
			--PC.PaidAmount,
			PA.Amount,
						PC.ModifiedDate[PaymentPostDate],VC.EffectiveDate[RemitDate],
						PT.Id[PatientId],PT.BillingID,PT.FirstName,PT.LastName,PT.DOB,PT.UId,LOWER(PR.UId),PTC.UId,INV.UId,(PT.LastName+', '+PT.FirstName),A.AccessionNumber,
						cast(DATEDIFF(Day,A.BillFromDate,GETDATE())  as varchar)Aging,
						(SELECT Description FROM @Temp where (cast(DATEDIFF(Day,A.BillFromDate,GETDATE())  as varchar))>=MinRange and (cast(DATEDIFF(Day,A.BillFromDate,GETDATE())  as varchar))<=MaxRange) AgingTextt,
						cast(DATEDIFF(Day,A.CreatedDate,GETDATE())  as varchar)AgingByPostDate,
						(SELECT Description FROM @Temp where (cast(DATEDIFF(Day,A.CreatedDate,GETDATE())  as varchar))>=MinRange and (cast(DATEDIFF(Day,A.CreatedDate,GETDATE())  as varchar))<=MaxRange) AgingByPostDateText,
						VC.CreatedDate,A.InvoiceId,DT.Description,CC.HasDenial,PA.IsAccounted
				FROM PaymentCharge PC (NOLOCK)       
				INNER  JOIN Payment PP (NOLOCK) ON PC.PaymentId=PP.Id
				INNER JOIN vw_GetChargeForPendingPayment_Dashboard A (NOLOCK) ON A.Id=PC.ChargeId
				LEFT JOIN Invoice(NOLOCK) INV ON INV.Id=A.InvoiceId
				LEFT JOIN Patient(NOLOCK) PT ON PT.DefaultCaseId=A.PatientCaseId
				LEFT JOIN PatientCase(NOLOCK) PTC ON PTC.PatientId=PT.Id
				LEFT JOIN Provider (NOLOCK)PR ON PR.Id=A.PerformingProviderId				
				LEFT JOIN Voucher(NOLOCK) VC ON VC.Id=PP.VoucherId
				LEFT JOIN PaymentAdjustment(NOLOCK) PA ON PA.PaymentChargeId=PC.Id --AND PA.IsAccounted=1
				LEFT JOIN PaymentAdjustment(NOLOCK) adj ON PC.Id = adj.PaymentChargeId AND adj.IsBonus = 1 AND (adj.IsAccounted = 1 OR adj.IsBonus=1)   AND adj.IsDenial = 0
				LEFT JOIN DepositType  (NOLOCK) DT ON DT.Id=VC.DepositTypeId
				LEFT JOIN ChargeStat(NOLOCK) CC ON CC.Id=A.Id
			WHERE A.IsDeleted=0 AND VC.IsCommitted=1
			--AND PP.VoucherId in 
			--(SELECT dp.Id         
			--FROM Voucher dp (NOLOCK)             
			--WHERE  dp.PaymentSourceCD not in  ('BulkAdjustment_Payment' ,'BalanceAdjustment_Payment')	
			--) 
END

GO

CREATE PROCEDURE usp_InsertDataInCollectionPercentageTable
AS
BEGIN
	
	TRUNCATE TABLE ReportCollectionPercentage
	DECLARE @Temp TABLE 							
	(							
		Id INT,						
		ZeroDays MONEY,						
		ThirtyDays MONEY,						
		SixtyDays MONEY,						
		NinetyDays MONEY,							
		PerforingProviderName VARCHAR(200),							
		PrimaryInsuranceCompanyName VARCHAR(200),						
		Payment MONEY,						
		Adjustment MONEY,						
		DenialAmount MONEY,						
		WriteOffAmount MONEY,						
		DueAmount MONEY,						
		Denial VARCHAR(10),						
		FeeAmount MONEY,
		PrimaryInsuranceCompanyId INT,
		PerforingProviderId INT
	)							
	INSERT INTO @Temp							
	SELECT A.ChargeId,CASE WHEN(DATEDIFF(dd,CAST(A.DosDate AS DATE), GETDATE()) <= 29) THEN A.ChargeAmount ELSE 0 END,							
							CASE WHEN(DATEDIFF(dd, CAST(A.DosDate AS DATE), GETDATE()) >= 30) AND (DATEDIFF(dd, CAST(A.DosDate AS DATE), GETDATE()) <= 59) THEN A.ChargeAmount ELSE 0 END[ThirtyDays],            
			  CASE WHEN(DATEDIFF(dd, CAST(A.DosDate AS DATE), GETDATE()) >= 60) AND (DATEDIFF(dd, CAST(A.DosDate AS DATE), GETDATE()) <= 89) THEN A.ChargeAmount ELSE 0 END[SixtyDays],                               				
						 CASE WHEN(DATEDIFF(dd, CAST(A.DosDate AS DATE), GETDATE()) >= 90) AND (DATEDIFF(dd, CAST(A.DosDate AS DATE), GETDATE()) <= 9999999) THEN A.ChargeAmount ELSE 0 END[NinetyDays],	
						 A.PerforingProviderName,ISNULL(A.PrimaryInsuranceCompanyName,A.InsuranceCompanyName),A.Payment,A.Adjustment[Adjustment],A.ChargeAmount[DenialAmount],A.WriteOffAmount,A.DueAmount,	
						 A.Denial,A.FeeAmount,ISNULL(A.PrimaryInsuranceCompanyId,A.InsuranceCompanyId),A.PerforingProviderId
	FROM ChargesReportData(NOLOCK) A
	WHERE A.Deleted='NO'							
							
INSERT INTO ReportCollectionPercentage(PerforingProviderName,PrimaryInsuranceCompanyName,ZeroDays,ThirtyDays,SixtyDays,NinetyDays,Payment,Adjustment,DenialAmount,WriteOffAmount,DueAmount,
											FeeAmount,CollectionPercentage,PrimaryInsuranceCompanyId,PerforingProviderId)		
SELECT A.PerforingProviderName,A.PrimaryInsuranceCompanyName[InsuranceCompany],SUM(A.ZeroDays)[ZeroDays],SUM(A.ThirtyDays)[ThirtyDays],SUM(A.SixtyDays)[SixtyDays],SUM(A.NinetyDays)[NinetyDays],							
		SUM(A.Payment)[Payment],SUM(C.Adjustment)[Adjustment],(SUM(B.ZeroDays)+SUM(B.ThirtyDays)+SUM(B.SixtyDays)+SUM(B.NinetyDays))[Denial],					
			ISNULL(SUM(A.WriteOffAmount),0) [WriteOffAmount],SUM(C.DueAmount)[DueAmount],				
			SUM(A.FeeAmount)[ERAmount],CASE WHEN ISNULL(SUM(A.FeeAmount),1)>0 THEN ((ISNULL(SUM(A.Payment),0)/ISNULL(SUM(A.FeeAmount),1))*100) ELSE 0 END[Collection%],
			A.PrimaryInsuranceCompanyId,A.PerforingProviderId
	FROM @Temp A						
	LEFT JOIN @Temp B ON B.Id=A.Id AND B.Denial='Yes'						
	LEFT JOIN @Temp C ON C.Id=A.Id AND C.Denial='No'						
	GROUP BY A.PerforingProviderName,A.PrimaryInsuranceCompanyName,A.PrimaryInsuranceCompanyId,A.PerforingProviderId
	ORDER BY  A.PerforingProviderName,A.PrimaryInsuranceCompanyName	
	
	EXEC usp_InsertDataInCollectionPercentageTableChild

END
GO

CREATE PROCEDURE usp_InsertDataInCollectionPercentageTableChild
AS
BEGIN
	TRUNCATE TABLE ReportCollectionPercentageChild
	DECLARE @Temp TABLE 							
	(							
		Id INT,						
		ZeroDays MONEY,						
		ThirtyDays MONEY,						
		SixtyDays MONEY,						
		NinetyDays MONEY,							
		PerforingProviderName VARCHAR(200),							
		PrimaryInsuranceCompanyName VARCHAR(200),						
		Payment MONEY,						
		Adjustment MONEY,						
		DenialAmount MONEY,						
		WriteOffAmount MONEY,						
		DueAmount MONEY,						
		Denial VARCHAR(10),						
		FeeAmount MONEY,
		PrimaryInsuranceCompanyId INT,
		PerforingProviderId INT
	)							
	INSERT INTO @Temp							
	SELECT A.ChargeId,CASE WHEN(DATEDIFF(dd,CAST(A.DosDate AS DATE), GETDATE()) <= 29) THEN A.ChargeAmount ELSE 0 END,							
							CASE WHEN(DATEDIFF(dd, CAST(A.DosDate AS DATE), GETDATE()) >= 30) AND (DATEDIFF(dd, CAST(A.DosDate AS DATE), GETDATE()) <= 59) THEN A.ChargeAmount ELSE 0 END[ThirtyDays],            
			  CASE WHEN(DATEDIFF(dd, CAST(A.DosDate AS DATE), GETDATE()) >= 60) AND (DATEDIFF(dd, CAST(A.DosDate AS DATE), GETDATE()) <= 89) THEN A.ChargeAmount ELSE 0 END[SixtyDays],                               				
						 CASE WHEN(DATEDIFF(dd, CAST(A.DosDate AS DATE), GETDATE()) >= 90) AND (DATEDIFF(dd, CAST(A.DosDate AS DATE), GETDATE()) <= 9999999) THEN A.ChargeAmount ELSE 0 END[NinetyDays],	
						 A.PerforingProviderName,ISNULL(A.PrimaryInsuranceCompanyName,A.InsuranceCompanyName),A.Payment,A.Adjustment[Adjustment],A.ChargeAmount[DenialAmount],A.WriteOffAmount,A.DueAmount,	
						 A.Denial,A.FeeAmount,ISNULL(A.PrimaryInsuranceCompanyId,A.InsuranceCompanyId),A.PerforingProviderId
	FROM ChargesReportData(NOLOCK) A
	WHERE A.Deleted='NO'						

	INSERT INTO ReportCollectionPercentageChild(ChargeId,PerforingProviderName,PrimaryInsuranceCompanyName,ZeroDays,ThirtyDays,SixtyDays,NinetyDays,Payment,Adjustment,DenialAmount,WriteOffAmount,DueAmount,
											FeeAmount,CollectionPercentage,PrimaryInsuranceCompanyId,PerforingProviderId)
	SELECT A.Id,A.PerforingProviderName,A.PrimaryInsuranceCompanyName[InsuranceCompany],A.ZeroDays,A.ThirtyDays,A.SixtyDays,A.NinetyDays,
		A.Payment,C.Adjustment,(B.ZeroDays+B.ThirtyDays+B.SixtyDays+B.NinetyDays)[Denial],					
			ISNULL(A.WriteOffAmount,0) [WriteOffAmount],C.DueAmount[DueAmount],				
			A.FeeAmount[ERAmount],CASE WHEN ISNULL(A.FeeAmount,1)>0 THEN ((ISNULL(A.Payment,0)/ISNULL(A.FeeAmount,1))*100) ELSE 0 END[Collection%]	,
			A.PrimaryInsuranceCompanyId,A.PerforingProviderId
	FROM @Temp A						
	LEFT JOIN @Temp B ON B.Id=A.Id AND B.Denial='Yes'						
	LEFT JOIN @Temp C ON C.Id=A.Id AND C.Denial='No'						
	--GROUP BY A.PerforingProviderName,A.PrimaryInsuranceCompanyName
	ORDER BY  A.PerforingProviderName,A.PrimaryInsuranceCompanyName
END

GO

