CREATE PROCEDURE usp_insertorupdatechargestat
AS 
BEGIN
    MERGE chargestat AS TARGET 
    using [charge] AS SOURCE 
    ON ( TARGET.id = source.id ) 

    WHEN matched  THEN 
      UPDATE SET TARGET.charges = ( CASE 
                                      WHEN multiplyqty = 1 THEN 
                                      Source.amount * qty 
                                      ELSE Source.amount 
                                    END ), 
                 TARGET.actionstatusid = (SELECT TOP 1 actioncategoryid 
                                          FROM   actionnote (nolock) 
                                          WHERE  chargeid = TARGET.id 
                                                 AND isnote = 1), 
                 --TARGET.insurancecompanyid = CASE WHEN ISNULL(TARGET.insurancecompanyid,0)<=0 THEN (SELECT dbo.ufn_ActiveInsuranceForCaseNo(source.BillFromDate,(CASE WHEN source.DueByFlagCD='Primary' THEN 1 WHEN source.DueByFlagCD='Secondary' THEN 2 END),source.PatientCaseId)) ELSE TARGET.insurancecompanyid END, 
				 --TARGET.insurancecompanyid = (SELECT dbo.ufn_ActiveInsuranceForCaseNo(source.BillFromDate,1,source.PatientCaseId)),
                 TARGET.payments = (SELECT Sum(paidamount) 
                                    FROM   payment(nolock) p 
                                           JOIN paymentcharge(nolock) pc 
                                             ON pc.paymentid = p.id 
                                                AND pc.chargeid = TARGET.id ), 
                 TARGET.adjustments = (SELECT Sum(pa.amount) 
                                       FROM payment(nolock) p 
                                              JOIN paymentcharge(nolock) pc 
                                                ON pc.paymentid = p.id 
                                              JOIN paymentadjustment(nolock) pa 
                                                ON pa.paymentchargeid = pc.id 
                                                   AND pc.chargeid = TARGET.id 
                                                   AND pa.isdenial = 0                                                    
												   AND pa.IsAccounted=1), 
				TARGET.denials = CASE WHEN TARGET.payments>0 THEN 0 ELSE ((SELECT top 1 pa.IsDenial
                                   FROM paymentcharge(nolock) pc                                             
                                          JOIN paymentadjustment(nolock) pa 
                                            ON pa.paymentchargeid = pc.id 
                                               AND pc.chargeid = TARGET.id 
											   WHERE pa.IsDenial=1 and pc.PaymentId in 
											   (select MAX(X.Id) from Payment X 
											   inner join PaymentCharge Y on X.Id=Y.PaymentId
											   inner join PaymentAdjustment Z on Y.Id=Z.PaymentChargeId
											   where Y.ChargeId=TARGET.id 
											   )
										
                                  ))END, 
               --  TARGET.denials = CASE WHEN TARGET.payments>0 THEN 0 ELSE ((SELECT Top 1 CASE WHEN pa.isdenial=1 then  pa.amount else 0 end 
               --                    FROM payment(nolock) p 
               --                           JOIN paymentcharge(nolock) pc 
               --                             ON pc.paymentid = p.id AND p.IsReversed=0
               --                           JOIN paymentadjustment(nolock) pa 
               --                             ON pa.paymentchargeid = pc.id 
               --                                AND pc.chargeid = TARGET.id                                                                                             										   
												   --order by pa.CreatedDate desc 
               --                   ))END, 
                 TARGET.hasdenial = CASE WHEN TARGET.denials > 0 THEN
				 CASE WHEN TARGET.payments>0 then 0 else 1 end
				  ELSE 0 END,
				  TARGET.DueByFlag=source.DueByFlagCD
							
			
    WHEN NOT matched  BY target  THEN 
      INSERT (id,charges,insurancecompanyid) 
      VALUES (SOURCE.id,SOURCE.amount,dbo.ufn_ActiveInsuranceForCaseNo(source.BillFromDate,1,source.PatientCaseId))
	WHEN NOT MATCHED BY SOURCE    THEN 
	delete ;


	DECLARE @TempInsPolicy AS TABLE              
    (  
    InsCompanyId       INT,              
     PatientCaseId          INT,              
     PlanEffectiveDate  DATE,              
     PlanExpirationDate DATE ,
	 InsLevel INT
    );              
  


update ChargeStat set  InsuranceCompanyId=B.InsuranceCompanyId
	FROM ChargeStat(NOLOCK) A
inner join Charge (NOLOCK)C on A.id=C.id
left join InsurancePolicy(NOLOCK) B on B.PatientCaseId=C.PatientCaseId
AND B.IsActive=1 
AND
	B.PlanEffectiveDate <= CAST(C.BillFromDate  AS DATE)
         AND   (B.PlanExpirationDate IS NULL  
          OR  B.PlanExpirationDate >= CAST(C.BillFromDate  AS DATE))  
          AND B.InsuranceLevel in (CASE WHEN lower(C.DueByFlagCD)='primary' THEN 1 WHEN lower(C.DueByFlagCD)='secondary' THEN 2 ELSE 1 END)

--update ChargeStat SET InsuranceCompanyId=B.InsCompanyId 
--	FROM ChargeStat(NOLOCK) A
--inner join Charge (NOLOCK)C on A.id=C.id
--left join @TempInsPolicy B on B.PatientCaseId=B.PatientCaseId
--where
--	B.PlanEffectiveDate <= C.BillFromDate  
--         AND   (B.PlanExpirationDate IS NULL  
--          OR  B.PlanExpirationDate >= C.BillFromDate)  
--          AND B.InsLevel in (1)  

select 1
END

GO

CREATE Procedure [dbo].[usp_MethaSoft_CreateAccession]
AS
BEGIN
	
	DECLARE @Temp TABLE
	(
		Id INT IDENTITY(1,1),
		DosDate DATE,
		EmrPatientId INT
	)
	INSERT INTO @Temp (DosDate,EmrPatientId)
	SELECT DosDate,EMRPatientId
		FROM MethaSoftInvoice 
	WHERE IsSentToEMR=0 AND ISNULL(IsDeleted,0)=0
	group by DosDate,EMRPatientId
	having count(DosDate)>1

	--select * from @Temp


	DECLARE @Id INT
	SELECT @Id=MIN(Id) FROM @Temp 

	WHILE @Id IS NOT NULL 
	BEGIN
		DECLARE @EmrPatientId INT
		DECLARE @DosDate DATE

		SELECT @EmrPatientId=EmrPatientId,@DosDate=DosDate FROM @Temp WHERE Id=@Id
		
		DECLARe @MathaSoftId INT
		DECLARe @MathaSoftMinId INT
		DECLARE @CptCode VARCHAR(10)
		SELECT @MathaSoftId=MAX(Id) FROM MethaSoftInvoice WHERE EMRPatientId=@EmrPatientId AND DosDate=@DosDate AND IsSentToEMR=0 AND ISNULL(IsDeleted,0)=0
		SELECT @MathaSoftMinId=MIN(Id) FROM MethaSoftInvoice WHERE EMRPatientId=@EmrPatientId AND DosDate=@DosDate AND IsSentToEMR=0 AND ISNULL(IsDeleted,0)=0

		SELECT @CptCode=CptCode FROM MethaSoftInvoice WHERE Id=@MathaSoftId

		UPDATE MethaSoftInvoice set CptCode=CptCode+','+@CptCode WHERE EMRPatientId=@EmrPatientId AND DosDate=@DosDate AND Id=@MathaSoftMinId
		
		UPDATE MethaSoftInvoice SET IsDeleted=1, Comments='Deleted for merge J and T Code' WHERE Id=@MathaSoftId

		SELECT @Id=MIN(Id) FROM @Temp WHERE Id>@Id		
	END

		SELECT 0 [Id];
END

GO

