CREATE Procedure [dbo].[usp_PatientConsolidation]
@FromPatientId INT,
@ToPatientId INT
AS
BEGIN

	DECLARE @ToPatientCaseId INT
	DECLARE @FromPatientCaseId INT
	
	SELECT @FromPatientCaseId=DefaultCaseId FROM Patient WHERE Id=@FromPatientId
	SELECT @ToPatientCaseId=DefaultCaseId FROM Patient WHERE Id=@ToPatientId

	UPDATE ActionNote SET PatientId=@ToPatientId WHERE PatientId=@FromPatientId
	UPDATE PatientNote SET PatientId=@ToPatientId WHERE PatientId=@FromPatientId
	UPDATE Payment SET PatientId=@ToPatientId WHERE PatientId=@FromPatientId
	UPDATE Voucher SET PatientId=@ToPatientId WHERE PatientId=@FromPatientId

	UPDATE Invoice SET PatientCaseId=@ToPatientCaseId WHERE PatientCaseId=@FromPatientCaseId
	UPDATE Charge SET PatientCaseId=@ToPatientCaseId WHERE PatientCaseId=@FromPatientCaseId
	UPDATE DrugCharge SET PatientCaseId=@ToPatientCaseId WHERE PatientCaseId=@FromPatientCaseId
	UPDATE Claim SET PatientCaseId=@ToPatientCaseId WHERE PatientCaseId=@FromPatientCaseId
	update PatientStatement SET PatientId=@ToPatientId WHERE PatientId=@FromPatientId
	update PortalPayment SET PatientId=@ToPatientId WHERE PatientId=@FromPatientId
	update PatientAlert SET PatientId=@ToPatientId WHERE PatientId=@FromPatientId

	
	
	


