CREATE PROC usp_PatientIntegrationWPA
AS
BEGIN
	DECLARE @Id INT

	SELECt @Id=MIN (Id) from temp_patient

	WHILE @Id IS NOT NULL
	BEGIN

		INSERT INTO Patient (UId,PracticeId,DoctorUserId,CreatedBy,CreatedDate,ModifiedBy,ModifiedDate,IsBadPatient,LastName,FirstName,MI,DOB,ProviderId,PhoneNumber,BillingID,SSN,Sex,
							Address1,City,State,ZipCode,MobilePhoneNumber,WorkPhoneNumber,BillAddress1,BillCity,BillState,BillZip,Ethnicity,MaritalStatus,BillType)
		SELECT NEWID(),1,0,'Admin',GETDATE(),'Admin',GETDATE(),0,LastName,FirstName,Middle,CAST(Dob as DATE),27,HomePhone,BillingId,SSN,Gender,
				Address1,CITY,State,ZipCode,CellPhone,WorkPhone,Address1,CITY,State,ZipCode,Ethnicity,substring(MaritalStatus,0,10),2	from temp_patient(NOLOCK) where Id=@Id

		DECLARE @PatientId INT
		SET @PatientId=SCOPE_IDENTITY()

		DECLARE @CaseIdNumber VARCHAR(15)
		SET @CaseIdNumber=(@PatientId*100)+1;

		INSERT INTO PatientCase(UId,PracticeId,CaseIdNumber,PatientId,CreatedBy,CreatedDate,ModifiedBy,ModifiedDate)
		SELECT NEWID(),1,@CaseIdNumber,@PatientId,'Admin',GETDATE(),'Admin',GETDATE()

		DECLARE @DefaultCaseId INT
		SET @DefaultCaseId =SCOPE_IDENTITY();

		Update Patient SEt DefaultCaseId=@DefaultCaseId WHERE Id=@PatientId


		-- Get Insurance Company		
		DECLARE @PrimaryInsName  NVARCHAR(200)
		DECLARE @PriInsPolicy  NVARCHAR(200)
		DECLARE @SecondaryInsName  NVARCHAR(200)
		DECLARE @SecInsPolicy  NVARCHAR(200)
		DECLARE @TeritiaryInsName  NVARCHAR(200)
		DECLARE @TerInsPolicy NVARCHAR(200)

		DECLARE @PrimaryInsId INT=0
		DECLARE @SecondaryInsId INT=0
		DECLARE @TerInsId INT=0


		DECLARE @GuarantorRelationship VARCHAR(50)
		DECLARE @GuarantorFname VARCHAR(50)
		DECLARE @GuarantorLname VARCHAR(50)
		

		SELECT @PrimaryInsName=PrimaryInsName,@PriInsPolicy=PriInsPolicy,@SecondaryInsName=SecondaryInsName,@SecInsPolicy=SecInsPolicy,
			@TeritiaryInsName=TeritiaryInsName,@TerInsPolicy=TerInsPolicy,@GuarantorRelationship=GuarantorRelationship,@GuarantorFname=GuarantorFname,
			@GuarantorLname=GuarantorLname FROM temp_patient where Id=@Id
		IF ISNULL(@PrimaryInsName,'')!=''
		BEGIN
			SELECT @PrimaryInsId=Id from InsuranceCompany WHERE CompanyName=@PrimaryInsName
		END
		IF ISNULL(@SecondaryInsName,'')!=''
		BEGIN
			SELECT @SecondaryInsId=Id from InsuranceCompany WHERE CompanyName=@SecondaryInsName
		END
		IF ISNULL(@TeritiaryInsName,'')!=''
		BEGIN
			SELECT @TerInsId=Id from InsuranceCompany WHERE CompanyName=@TeritiaryInsName
		END
		IF ISNULL(@PrimaryInsId,0)>0
		BEGIN
			exec usp_AddInsurancePolicyByPatientId @PatientId,1,@PrimaryInsId,@PriInsPolicy
		END
		IF ISNULL(@SecondaryInsId,0)>0
		BEGIN
			exec usp_AddInsurancePolicyByPatientId @PatientId,2,@SecondaryInsId,@SecInsPolicy
		END
		IF ISNULL(@TerInsId,0)>0
		BEGIN
			exec usp_AddInsurancePolicyByPatientId @PatientId,3,@TerInsId,@TerInsPolicy
		END

		IF ISNULL(@GuarantorRelationship,'')!=''
		BEGIN
			IF(LOWER( @GuarantorRelationship)='self')
			BEGIN
				INSERT INTO InsuranceGuarantor(PatientID,GuarantorNumber,FirstName,LastName,Address1,Address2,City,State,Zip,HomePhone,BusPhone,DOB,GuarantorRel,MobilePhone,ModifiedBy,ModifiedDate,MaritalStatus)
				SELECT Id,0,FirstName,LastName,Address1,Address2,City,State,ZipCode,PhoneNumber,WorkPhoneNumber,DOB,'Self',MobilePhoneNumber,ModifiedBy,ModifiedDate,MaritalStatus FROM Patient WHERE Id=@PatientId
			END
			ELSE
			BEGIN
				INSERT INTO InsuranceGuarantor(PatientID,GuarantorNumber,FirstName,LastName,GuarantorRel,ModifiedBy,ModifiedDate)
				SELECT @PatientId,0,@GuarantorFname,@GuarantorLname,@GuarantorRelationship,'Admin',GETDATE() FROM Patient WHERE Id=@PatientId
			END
		END
		
		
		SELECt @Id=MIN (Id) from temp_patient WHERE Id>@Id	
	END

END

GO

--usp_PaymentByAccession '1 oct 2019','31 oct 2019'  
CREATE PROCEDURE usp_PaymentByAccession  
 @FromDate DATE,  
 @ToDate  DATE  
AS  
BEGIN  
 --SELECT * FROM Payment WHERE CAST(CreatedDate AS date)>=@FromDate AND CAST(CreatedDate AS date)>=@ToDate  
 --29532  
  
 DECLARE @Payment AS TABLE  
 (  
  AccessionNumber VARCHAR(20),  
  Amount MONEY  
 )  
  
 DECLARE @Adjustment AS TABLE  
 (  
  AccessionNumber VARCHAR(20),  
  Amount MONEY  
 )  
  
 -- Payments   
 INSERT INTO @Payment  
 SELECT INV.AccessionNumber,Sum(PaidAmount)   
  FROM PaymentCharge(NOLOCK) PC   
 INNER JOIN Payment(NOLOCK) PP ON PC.PaymentId=PP.Id AND CAST(PP.CreatedDate AS date)>=@FromDate   
  AND CAST(PP.CreatedDate AS date)<=@ToDate AND PP.IsCommitted=1   
 INNER JOIN Charge (NOLOCK) CC ON CC.Id=PC.ChargeId  And CC.IsDeleted = 0
 INNER JOIN Invoice (NOLOCK)INV ON INV.Id=CC.InvoiceId   
 GROUP BY INV.AccessionNumber ORDER BY AccessionNumber  
  
 --Adjustments  
 INSERT INTO @Adjustment  
 SELECT INV.AccessionNumber,Sum(PA.Amount)   
  FROM  PaymentAdjustment PA (NOLOCK)    
 INNER JOIN PaymentCharge (NOLOCK) PC ON PA.PaymentChargeId=PC.Id  
 INNER JOIN Payment(NOLOCK) PP ON PC.PaymentId=PP.Id AND CAST(PP.CreatedDate AS date)>=@FromDate   
  AND CAST(PP.CreatedDate AS date)<=@ToDate AND PP.IsCommitted=1   
 INNER JOIN Charge (NOLOCK) CC ON CC.Id=PC.ChargeId And CC.IsDeleted = 0 
 INNER JOIN Invoice (NOLOCK)INV ON INV.Id=CC.InvoiceId  
 --WHERE PA.IsAccounted=1  
 GROUP BY INV.AccessionNumber ORDER BY AccessionNumber  
  
 --1043  
 SELECT A.AccessionNumber,SUM(D.Amount)[TotalCharges],A.Amount[Payment],B.Amount[Adjustment],COUNT(D.Id)[CptCount]  
  FROM @Payment A  
 INNER JOIN @Adjustment B ON A.AccessionNumber=B.AccessionNumber  
 INNER JOIN Invoice C ON C.AccessionNumber=A.AccessionNumber  
 INNER JOIN Charge (NOLOCK) D ON D.InvoiceId=C.Id  And D.IsDeleted = 0
 GROUP BY A.AccessionNumber,A.Amount,B.Amount  
  
  
END  
GO

CREATE PROCEDURE [dbo].[usp_PaymentDeposits]              
@DepositID BIGINT=NULL,              
@FromDate datetime = null,              
@ToDate datetime = null,
@PracticeId INT = 0              
AS              
BEGIN              
 SELECT dp.Id [DepositID],            
  DepositTypeID,            
  convert(varchar(20),convert(date,dp.ModifiedDate))as ModifiedDate,            
  CAST(dp.Amount AS decimal(18,2))Amount,            
  dc.Description[DepositType],            
  ISNULL(bb.BatchNo,'') BatchNumber,              
  dp.Description,              
  dp.PaymentBatchId [BatchID],            
  dp.ModifiedBy,            
  dp.EffectiveDate,            
  dp.ReferenceNo  ,      
  InsuranceCompanyId [PayerId] ,  
  i.CompanyName,  
  CONCAT(p.LastName , ' ' ,p.FirstName) [PatientName],  
  a.[FileName]  ,    
   ISNULL( dc.IsSelfpayment , CAST(0 as BIT) )    IsSelfpayment ,
   dp.PracticeId 
   FROM Voucher dp              
   INNER JOIN DepositType dc on dc.Id=dp.DepositTypeID              
   LEFT JOIN ChargeBatch bb ON bb.Id=dp.PaymentBatchId    
   LEFT JOIN AttFile a ON a.TableIdValue = dp.Id     
   LEFT JOIN InsuranceCompany i ON i.Id = dp.InsuranceCompanyId  
   LEFT JOIN Patient p ON p.Id = dp.InsuranceCompanyId  
  
   WHERE (@DepositID IS NULL OR  dp.Id =@DepositID)              
   and              
  --  CAST(dp.EffectiveDate AS DATE) >= @FromDate and   CAST(dp.EffectiveDate AS DATE) <=@ToDate            
   (@FromDate is null) OR (CAST(dp.EffectiveDate AS DATE) IS NULL OR (CAST(dp.EffectiveDate AS DATE) between @FromDate and @ToDate))              
   AND dp.PracticeId = @PracticeId
   --AND ISNULL(IsCommitted,0)=1              
END 


GO

  
CREATE PROCEDURE [dbo].[usp_PostDetail]    
(@StartDate DATE,    
 @EndDate   DATE    
)    
AS    
         BEGIN    
             CREATE TABLE #TempData    
(AcctNo       NUMERIC(18, 0),    
 PatientName  NVARCHAR(500),    
 ProviderName NVARCHAR(500),    
 CompanyId    NUMERIC(18, 0),    
 CompanyName  NVARCHAR(500),    
 DOS          DATE,    
 CPTCode      NVARCHAR(50),    
 Modifiers    NVARCHAR(50),    
 ChargeAmt    NUMERIC(18, 2),    
 PriDX        NVARCHAR(50),    
 POS          NVARCHAR(50),    
 ChargeNo     NUMERIC(18, 0),    
 Payments     NUMERIC(18, 2),    
 Adjustments  NUMERIC(18, 2),    
 PaymentBat   NVARCHAR(100),    
 PostDate     DATE,    
 CPTDesc      NVARCHAR(200)    
);    
             INSERT INTO #TempData    
(AcctNo,    
 PatientName,    
 ProviderName,    
 CompanyId,    
 CompanyName,    
 DOS,    
 CPTCode,    
 Modifiers,    
 ChargeAmt,    
 PriDX,    
 POS,    
 ChargeNo,    
 Payments,    
 Adjustments,    
 PaymentBat,    
 PostDate,    
 CPTDesc    
)    
                    SELECT D.Id [PatientID],    
                           CONCAT(D.LastName, ',', D.FirstName, ' ', D.MI) [PatientName],    
                           CONCAT(E.LastName, ',', E.FirstName),    
                           dbo.ufn_ActiveInsuranceForCaseNo(A.BillFromDate, 1, C.Id),    
                           '',    
                           CAST(A.BillFromDate AS DATE),    
                           A.CPTCode [CPT],    
                           CONCAT(A.Mod1, A.Mod2, A.Mod3, A.Mod4) [Mods],    
                           A.Amount,    
                           --H.ICD9_CM [PriDx],    
         '' [PriDx],    
                           I.Description [POS],           
                           A.ChargeNo,    
                           0,    
                           0,    
                           '',    
                           A.EntryDate,    
                           A.Description    
                    FROM vw_CHARGE_Latest A (NOLOCK)    
                         INNER JOIN Invoice B (NOLOCK) ON A.InvoiceId = B.Id   
                         JOIN PatientCase C (NOLOCK) ON C.Id = B.PatientCaseId    
                         JOIN Patient D(NOLOCK) ON C.PatientId = D.Id    
                         JOIN [Provider] E(NOLOCK) ON D.ProviderId = E.Id    
                         --JOIN BL_Inv_dx H(NOLOCK) ON H.InvoiceID = B.ID   AND H.DiagnosisNumber = 1    
                         LEFT JOIN ConfigPOS I(NOLOCK) ON I.Code = A.POSId    
                    WHERE CAST(A.BillFromDate AS DATE) between @StartDate and @EndDate        
    AND A.PatientCaseId > 0 AND A.ChargeNo > 0 AND A.IsDeleted = 0;    
             UPDATE #TempData    
               SET    
                   CompanyName = J.CompanyName    
             FROM #TempData I    
                  LEFT JOIN InsuranceCompany J (NOLOCK) ON I.CompanyId = J.Id;    
             UPDATE #TempData    
               SET    
                   Payments = J.Payments    
             FROM #TempData I    
                  JOIN    
(    
    SELECT X.acctno,    
           x.PatientName,    
           x.ProviderName,    
           X.CompanyId,    
           x.DOS,    
           x.CPTCode,    
           x.Modifiers,    
           x.ChargeAmt,    
           x.PriDx,    
           x.POS,    
           x.ChargeNo,    
           isnull(SUM(Z.PaymentOrAdjAmount), 0) [Payments]    
    FROM #TempData X    
         LEFT JOIN vw_PaymentsAdjustments Z (NOLOCK) ON Z.ChargeNum = X.ChargeNo                                                   
                                               AND z.IsDeleted = 0   AND z.PatientCaseId > 0  AND z.ChargeNum > 0 AND z.IsPayment =1   
    GROUP BY X.acctno,    
             x.PatientName,    
             x.ProviderName,    
             X.CompanyId,    
             x.DOS,    
             x.CPTCode,    
             x.Modifiers,    
             x.ChargeAmt,    
             x.PriDx,    
             x.POS,    
             x.ChargeNo    
) J ON I.ChargeNo = J.ChargeNo;    
             UPDATE #TempData    
               SET    
                   Adjustments = J.Payments    
             FROM #TempData I    
                  JOIN    
(    
    SELECT X.acctno,    
           x.PatientName,    
x.ProviderName,    
   X.CompanyId,    
           x.DOS,    
           x.CPTCode,    
           x.Modifiers,    
           x.ChargeAmt,    
           x.PriDx,    
           x.POS,    
           x.ChargeNo,    
           isnull(SUM(Z.PaymentOrAdjAmount), 0) [Payments]    
    FROM #TempData X    
         LEFT JOIN vw_PaymentsAdjustments Z (NOLOCK) ON Z.ChargeNum = X.ChargeNo    
                                               AND Z.IsPayment = 0  AND z.IsDeleted = 0  
           AND z.PatientCaseId > 0    
           AND z.ChargeNum > 0    
    GROUP BY X.acctno,    
             x.PatientName,    
             x.ProviderName,    
             X.CompanyId,    
             x.DOS,    
             x.CPTCode,    
             x.Modifiers,    
             x.ChargeAmt,    
             x.PriDx,    
             x.POS,    
             x.ChargeNo    
) J ON I.ChargeNo = J.ChargeNo;    
             SELECT *    
             FROM #TempData    
             ORDER BY acctno,    
                      DOS,    
                      CPTCode;    
         END;  
  
  
  
GO


CREATE PROC [dbo].[usp_PracticeAnalysisReport]        
(   
@FromDate   DATE,
@ToDate   DATE        
)        
AS        
         BEGIN                            
           
             SELECT ISNULL(cat.[CategoryName], 'Non Revenue Center') [RevenueCentreName],        
                    pc.CPTCode,        
                    pc.[Description] [CPTDesc],                            
				ch.Amount [StandardCharge],        
                    COUNT(*) [Units],                            
				(ch.Amount * COUNT(*)) [TotalCharges]        
             FROM vw_CHARGE_Latest ch (NOLOCK)       
                  INNER JOIN Invoice B(NOLOCK) ON ch.InvoiceId = B.ID          
                  JOIN PatientCase C(NOLOCK) ON C.Id = B.PatientCaseId          
                  JOIN Patient D(NOLOCK) ON C.PatientID = D.Id          
                  JOIN [Provider] E(NOLOCK) ON D.ProviderId = E.Id      
                  LEFT JOIN CPTCode pc (NOLOCK) ON pc.CPTCode = ch.CPTCode                          
                  LEFT JOIN CPTCategory cat (NOLOCK) ON cat.Id = pc.CPTCategoryId        
             WHERE CAST(ch.BillFromDate AS DATE) between @FromDate and  @ToDate   
                   AND ch.PatientCaseId > 0        
                   AND ch.ChargeNo > 0        
                   AND ch.IsDeleted =0      
             GROUP BY cat.[CategoryName],        
                      pc.CPTCode,        
                      pc.[Description],        
                      --fc.Charge_Facility        
				  ch.Amount
             ORDER BY cat.[CategoryName],        
                      pc.CPTCode;   			  
				  
         END;


GO

CREATE PROC usp_ReportARChargesMonthWiseNew
AS
BEGIN

	DECLARE @15Days INT
		SELECT @15Days=DATEPART(DAY,GETDATE())		
		DECLARE @Value BIT=0
		IF @15Days=15
		BEGIN
			SELECT '15 Date'
			SET @Value=1
		END
		ELSE
		BEGIN
			IF CAST(EOMONTH(GETDATE()) AS DATE)=CAST(GETDATE() AS DATE)
			BEGIN
				SET @Value=1
			END
		END
		IF @Value=0
		BEGIN

			RETURN
		END

	DECLARE @CurrentDate DATE=GETDATE()
	DECLARE @Temp TABLE
	(
		Id INT,
		MonthId INT,
		YearId INT,
		StartDate DATE,
		EndDate DATE
	)
	INSERT INTO @Temp
	EXEC usp_GetTableForMonthReport @CurrentDate

	DECLARE @YearTable TABLE
	(
		Id INT IDENTITY(1,1),
		YearId INT
	)

	INSERT INTO @YearTable
	SELECT DISTINCT YearId FROM @Temp

	DECLARE @TableYearId INT
	SELECT @TableYearId=MIN(YearId) FROM @YearTable
	WHILE @TableYearId IS NOT NULL
	BEGIN
		--SELECT @TableYearId

		DECLARE @ReportARChargesMonthWiseId INT
		INSERT INTO ReportARChargesMonthWise (YearId,MonthId,CreatedDate) SELECT @TableYearId,DATEPART(MONTH,GETDATE()),GETDATE()
		SET @ReportARChargesMonthWiseId=SCOPE_IDENTITY()
		
		DECLARE @TableMonthId INT
		SELECT @TableMonthId=MIN(MonthId) FROM @Temp WHERE YearId=@TableYearId
		WHILE @TableMonthId IS NOT NULL
		BEGIN
			DECLARE @StartDate DATETIME
			DECLARE @EndDate DATETIME
			DECLARE @ChargeBalance MONEY
			DECLARE @Count INT

			SELECT @StartDate=StartDate,@EndDate=EndDate FROM @Temp WHERE MonthId=@TableMonthId AND YearId=@TableYearId

			SELECT @ChargeBalance=SUM(DueAmount) FROM ChargesReportData WHERE DosDate>=@StartDate AND DosDate<=@EndDate 
			AND Deleted='No' AND DueAmount>0	AND 	IsBillable=1
			
			
			SET @Count =@TableMonthId			

			IF @Count=1 UPDATE ReportARChargesMonthWise SET Jan=@ChargeBalance WHERE Id =@ReportARChargesMonthWiseId;
				IF @Count=2 UPDATE ReportARChargesMonthWise SET Feb=@ChargeBalance WHERE Id =@ReportARChargesMonthWiseId;
				IF @Count=3 UPDATE ReportARChargesMonthWise SET March=@ChargeBalance WHERE Id =@ReportARChargesMonthWiseId;
				IF @Count=4 UPDATE ReportARChargesMonthWise SET April=@ChargeBalance WHERE Id =@ReportARChargesMonthWiseId;
				IF @Count=5 UPDATE ReportARChargesMonthWise SET May=@ChargeBalance WHERE Id =@ReportARChargesMonthWiseId;
				IF @Count=6 UPDATE ReportARChargesMonthWise SET June=@ChargeBalance WHERE Id =@ReportARChargesMonthWiseId;
				IF @Count=7 UPDATE ReportARChargesMonthWise SET July=@ChargeBalance WHERE Id =@ReportARChargesMonthWiseId;
				IF @Count=8 UPDATE ReportARChargesMonthWise SET Aug=@ChargeBalance WHERE Id =@ReportARChargesMonthWiseId;
				IF @Count=9 UPDATE ReportARChargesMonthWise SET Sep=@ChargeBalance WHERE Id =@ReportARChargesMonthWiseId;
				IF @Count=10 UPDATE ReportARChargesMonthWise SET Oct=@ChargeBalance WHERE Id =@ReportARChargesMonthWiseId;
				IF @Count=11 UPDATE ReportARChargesMonthWise SET Nov=@ChargeBalance WHERE Id =@ReportARChargesMonthWiseId;
				IF @Count=12 UPDATE ReportARChargesMonthWise SET [Dec]=@ChargeBalance WHERE Id =@ReportARChargesMonthWiseId;	
			
			SELECT @TableMonthId=MIN(MonthId) FROM @Temp WHERE YearId=@TableYearId AND MonthId>@TableMonthId
		END



		SELECT @TableYearId=MIN(YearId) FROM @YearTable WHERE YearId>@TableYearId
	END
END


GO

CREATE PROC [dbo].[USP_ReportDataForCatalystAllCharges]--4778
AS
BEGIN

	SELECT FirstName,LastName,DOB,Sex,visit_id,mrn,ChargePostDate,dos,specimen_id,insurance_name,financial_class,physician,npi,billing_status,payer_status,ChargeId,CPTCode,ServiceDescription,
			PrimaryDX,DX2,DX3,DX4,Mod1,Mod2,Mod3,Mod4,ChargeAmount,billing_date,PaidAmount,totaladj,carc_code,RemitDate,Adjudicated,Check_number,InsuranceCompanyName,DepositFinancialClass,
			policy_number,facility,mr_upload_date,ar_note,last_touch_date,ReviewNeeded,Billable,ReviewComments,AccessionNumber,PatientAddress1,PatientAddress2,PatientState,PatientCity,
			PatientZip,ERAmount,ServiceClassification,SourceDB,PatientNote,NoteCreatedBy,NoteCreatedDate,POSId,DueBy,ClaimId,DueAmount,CategoryName,FollowUpDate,HasFollowUp,Note,
			ChargeNoteCreatedBy,ChargeNoteCreatedDate,PaymentPostingDate
	FROM ChargesForCatalystExcel
	RETURN;


		DECLARE @PatientNoteClinic TABLE
		(
			PatientId INT,
			PatientNote VARCHAR(1000),
			NoteCreatedDate DATE,
			NoteCreatedBy VARCHAR(20)
		)
		INSERT INTO @PatientNoteClinic(PatientId,PatientNote,NoteCreatedDate,NoteCreatedBy)
		SELECT PatientId,Note,CAST(CreatedDate AS DATE)[CreatedDate],CreatedBy 
			FROM PI_ATC_CLINIC.dbo.ActionNote(NOLOCK) A WHERE A.NoteSourceCD='NS.PATIENT' 
		AND CreatedDate=(SELECT MAX(B.CreatedDate) FROM PI_ATC_CLINIC.dbo.ActionNote(NOLOCK) B 
		WHERE B.NoteSourceCD='NS.PATIENT' AND B.PatientId=A.PatientId)

		DECLARE @PatientNoteLAB TABLE
		(
			PatientId INT,
			PatientNote VARCHAR(1000),
			NoteCreatedDate DATE,
			NoteCreatedBy VARCHAR(20)
		)
		INSERT INTO @PatientNoteLAB(PatientId,PatientNote,NoteCreatedDate,NoteCreatedBy)
		SELECT PatientId,Note,CAST(CreatedDate AS DATE)[CreatedDate],CreatedBy 
			FROM PI_ATC_LAB.dbo.ActionNote(NOLOCK) A WHERE A.NoteSourceCD='NS.PATIENT' 
		AND CreatedDate=(SELECT MAX(B.CreatedDate) FROM PI_ATC_LAB.dbo.ActionNote(NOLOCK) B 
		WHERE B.NoteSourceCD='NS.PATIENT' AND B.PatientId=A.PatientId)


		DECLARE @PrimaryInsuranceClinic TABLE
		(
			InvoiceId INT,
			InsuranceCompanyId INT,
			PolicyNo VARCHAR(20),
			PolicyHolderName VARCHAR(200),
			PolicyHolderDOB VARCHAR(20),
			PolicyHolderRelation VARCHAR(20),
			InsuranceCompanyName VARCHAR(200),
			CompanyType VARCHAR(50)
		)
		INSERT INTO @PrimaryInsuranceClinic
		SELECT InvoiceId,InsuranceCompanyId,PolicyNo,PolicyHolderName,PolicyHolderDOB,B.Description,C.CompanyName ,D.CompanyType
		from Claim (NOLOCK)A
		LEFT JOIN ConfigRelationship(NOLOCK) B on B.Id=A.PolicyHolderRelation
		LEFT JOIN InsuranceCompany(NOLOCK) C on C.Id=A.InsuranceCompanyId
		LEFT JOIN ConfigInsuranceCompanyType D on D.Id=C.CompanyTypeId
		WHERE A.Id IN (SELECT MAX(Id) FROM Claim(NOLOCK) B WHERE B.InvoiceId=A.InvoiceId)

		DECLARE @PrimaryInsuranceLab TABLE
		(
			InvoiceId INT,
			InsuranceCompanyId INT,
			PolicyNo VARCHAR(20),
			PolicyHolderName VARCHAR(200),
			PolicyHolderDOB VARCHAR(20),
			PolicyHolderRelation VARCHAR(20),
			InsuranceCompanyName VARCHAR(200),
			CompanyType VARCHAR(50)
		)
		INSERT INTO @PrimaryInsuranceLab
		SELECT InvoiceId,InsuranceCompanyId,PolicyNo,PolicyHolderName,PolicyHolderDOB,B.Description,C.CompanyName ,D.CompanyType
		from PI_ATC_LAB.dbo.Claim (NOLOCK)A
		LEFT JOIN PI_ATC_LAB.dbo.ConfigRelationship(NOLOCK) B on B.Id=A.PolicyHolderRelation
		LEFT JOIN PI_ATC_LAB.dbo.InsuranceCompany(NOLOCK) C on C.Id=A.InsuranceCompanyId
		LEFT JOIN PI_ATC_LAB.dbo.ConfigInsuranceCompanyType D on D.Id=C.CompanyTypeId
		WHERE A.Id IN (SELECT MAX(Id) FROM PI_ATC_LAB.dbo.Claim(NOLOCK) B WHERE B.InvoiceId=A.InvoiceId)


		DECLARE @ChargeNotesClinic TABLE
		(
			CategoryName VARCHAR(100),
			ChargeId INT,
			Note VARCHAR(2000),
			HasFollowUp VARCHAR(10),
			FollowUpDate DATE,
			ChargeNoteCreatedBy VARCHAR(100),
			ChargeNoteCreatedDate DATE
		)

		INSERT INTO @ChargeNotesClinic
		SELECT B.CategoryName,ChargeId,Note,CASE WHEN ISNULL(A.HasFollowUp,0) =0 THEN 'No' ELSE 'Yes' END HasFollowUp,
		FollowUpDate,UserName AS CreatedBy,A.CreatedDate
		 FROM PI_ATC_CLINIC.dbo.ActionNote A (NOLOCK) 
		 LEFT JOIN PI_ATC_CLINIC.dbo.ActionCategory B on B.Id=A.ActionSubCategoryId
		WHERE A.UserName!='System' AND A.NoteSourceCD='NS.CHARGE' AND ISNULL(A.IsTransfered,0)=0
		AND A.CreatedDate=(SELECT MAX(CreatedDate) FROM PI_ATC_CLINIC.dbo.ActionNote(NOLOCK) X WHERE X.ChargeId=A.ChargeId AND X.UserName!='System' AND X.NoteSourceCD='NS.CHARGE')
		
		DECLARE @ChargeNotesLab TABLE
		(
			CategoryName VARCHAR(100),
			ChargeId INT,
			Note VARCHAR(2000),
			HasFollowUp VARCHAR(10),
			FollowUpDate DATE,
			ChargeNoteCreatedBy VARCHAR(100),
			ChargeNoteCreatedDate DATE
		)

		INSERT INTO @ChargeNotesLab
		SELECT B.CategoryName,ChargeId,Note,CASE WHEN ISNULL(A.HasFollowUp,0) =0 THEN 'No' ELSE 'Yes' END HasFollowUp,
		FollowUpDate,UserName AS CreatedBy,A.CreatedDate
		 FROM PI_ATC_LAB.dbo.ActionNote A (NOLOCK) 
		 LEFT JOIN PI_ATC_LAB.dbo.ActionCategory B on B.Id=A.ActionSubCategoryId
		WHERE A.UserName!='System' AND A.NoteSourceCD='NS.CHARGE' AND ISNULL(A.IsTransfered,0)=0
		AND A.CreatedDate=(SELECT MAX(CreatedDate) FROM PI_ATC_LAB.dbo.ActionNote(NOLOCK) X WHERE X.ChargeId=A.ChargeId AND X.UserName!='System' AND X.NoteSourceCD='NS.CHARGE')  
		
		
		TRUNCATE TABLE ChargesForCatalystExcel
		INSERT INTO ChargesForCatalystExcel(FirstName,LastName,DOB,Sex,visit_id,mrn,ChargePostDate,dos,specimen_id,insurance_name,financial_class,physician,npi,billing_status,payer_status,ChargeId,CPTCode,ServiceDescription,
				PrimaryDX,DX2,DX3,DX4,Mod1,Mod2,Mod3,Mod4,ChargeAmount,billing_date,PaidAmount,totaladj,carc_code,RemitDate,Adjudicated,Check_number,InsuranceCompanyName,DepositFinancialClass,
				policy_number,facility,mr_upload_date,ar_note,last_touch_date,ReviewNeeded,Billable,ReviewComments,AccessionNumber,PatientAddress1,PatientAddress2,PatientState,PatientCity,
				PatientZip,ERAmount,ServiceClassification,SourceDB,PatientNote,NoteCreatedBy,NoteCreatedDate,POSId,DueBy,ClaimId,DueAmount,CategoryName,FollowUpDate,HasFollowUp,Note,
				ChargeNoteCreatedBy,ChargeNoteCreatedDate)
		SELECT DISTINCT B.FirstName,B.LastName,CONVERT(varchar,B.DOB,101)DOB,B.Sex,A.InvoiceId [visit_id],B.Id [mrn],CONVERT(varchar,A.CreatedDate,101)[ChargePostDate],
		CONVERT(varchar,A.BillFromDate,101)[dos],A.AccessionNumber[specimen_id],
				--A.InsuranceCompanyName[insurance_name],
			CASE WHEN VC.IsSelfPayment=1 Then 'Self' ELSE	INS.CompanyName END [insurance_name],
				ICT.CompanyType[financial_class],(PD.LastName+' '+PD.FirstName)[physician],PDI.Identifier[npi],
				CASE WHEN CLM.SentDate is not NULL then 'Billed' ELSE 'Not Billed' END [billing_status],
				CASE WHEN (A.PaymentReceived=1 AND CLM.SentDate IS NOT NULL) THEN 'Received' WHEN (A.PaymentReceived=0 AND CLM.SentDate IS NOT NULL) THEN 'NOT Received' END [payer_status],
				A.Id[ChargeId],A.CPTCode,A.Description[ServiceDescription],A.ICD1 PrimaryDX,A.ICD2 DX2,A.ICD3 DX3,A.ICD4 DX4,A.Mod1,A.Mod2,A.Mod3,A.Mod4,
				--A.ChargeAmount,
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY A.Id ORDER BY A.Id ASC))=1 THEN A.ChargeAmount ELSE 0 END[ChargeAmount],
				CONVERT(varchar,CLM.SentDate,101)[billing_date],
				--ROW_NUMBER() OVER(PARTITION BY PC.Id ORDER BY PC.Id ASC),				
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY PC.Id ORDER BY PC.Id ASC))=1 THEN PC.PaidAmount ELSE 0 END[PaidAmount],
				--PC.PaidAmount,
				PA.Amount [totaladj],
				PA.ReasonCode [carc_code],								
				CONVERT(varchar,VC.EffectiveDate,101)[RemitDate],
				CASE WHEN (A.PaymentReceived=1 AND CLM.SentDate IS NOT NULL) THEN 'YES' WHEN (A.PaymentReceived=0 AND CLM.SentDate IS NOT NULL) THEN 'No' END [Adjudicated],
				VC.ReferenceNo[Check_number],ISNULL(A.InsuranceCompanyName,PINS.InsuranceCompanyName)[InsuranceCompanyName],ISNULL(A.FinancialClass,PINS.CompanyType)[DepositFinancialClass],
				dbo.ufn_ActiveInsuranceForCaseNo_PolicyNumber(A.BillFromDate,1,A.PatientCaseId)[policy_number],				
				ISNULL(FC.ChildFacilityName,'Other')[facility],
				--FCI.Identifier [Facility NPI],
				null [mr_upload_date],null [ar_note],null [last_touch_date],A.ReviewNeeded,A.Billable,A.ReviewComments,A.AccessionNumber,
				B.Address1[PatientAddress1],B.Address2[PatientAddress2],B.State[PatientState],B.City[PatientCity],B.ZipCode[PatientZip],
				--A.FeeAmount[ERAmount]
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY A.Id ORDER BY A.Id ASC))=1 THEN A.FeeAmount ELSE 0 END[ERAmount]
				, CASE WHEN INV.InvoiceType=1 THEN 'MH' WHEN INV.InvoiceType=2 THEN 'SUD' ELSE 'NA' END[ServiceClassification] ,'Clinic' SourceDB,
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY B.Id ORDER BY B.Id ASC))=1 THEN PatientNote ELSE '' END[PatientNote],
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY B.Id ORDER BY B.Id ASC))=1 THEN NoteCreatedBy ELSE '' END[NoteCreatedBy],
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY B.Id ORDER BY B.Id ASC))=1 THEN CONVERT(varchar,NoteCreatedDate,101) ELSE '' END[NoteCreatedDate]		,
				A.POSId,A.DueByFlagCD[DueBy],CLM.PatientAccountNumber AS ClaimId
				--CASE WHEN (ROW_NUMBER() OVER(PARTITION BY A.Id ORDER BY A.Id ASC))=1 THEN CLM.PatientAccountNumber ELSE '' END ClaimId	
				,A.DueAmount
				,CHNote.CategoryName,CHNote.FollowUpDate,CHNote.HasFollowUp,CHNote.Note,CHNote.ChargeNoteCreatedBy,CHNote.ChargeNoteCreatedDate
		FROM vw_GetChargeForPendingPayment_Dashboard A
		INNER JOIN Patient(NOLOCK) B on B.DefaultCaseId=A.PatientCaseId		
		LEFT JOIN Provider(NOLOCK) PD ON PD.Id=A.PerformingProviderId
		LEFT JOIN ProviderIdentity PDI ON PDI.ProviderId=PD.Id and TypeId=1
		LEFT JOIN Claim (NOLOCK) CLM ON CLM.Id=A.ClaimId
		LEFT JOIN PaymentCharge (NOLOCK) PC ON PC.ChargeId=A.Id 
		LEFT JOIN PaymentAdjustment (NOLOCK) PA ON PA.PaymentChargeId=PC.Id
		LEFT JOIN Payment(NOLOCK) PP ON PP.Id=PC.PaymentId
		LEFT JOIN InsuranceCompany(NOLOCK) INS ON INS.Id=PP.PatientInsuranceCompanyId
		LEFT JOIN ConfigInsuranceCompanyType(NOLOCK) ICT  ON ICT.Id=INS.CompanyTypeId
		LEFT JOIN Voucher(NOLOCK) VC ON VC.Id=PP.VoucherId
		LEFT JOIN Facility(NOLOCK) FC ON FC.Id=A.PerformingFacilityId	
		LEFT JOIN FacilityIdentity (NOLOCK) FCI ON FCI.FacilityId=FC.Id AND FCI.TypeId=1	
		INNER JOIN Invoice(NOLOCK) INV on INV.Id=A.InvoiceId
		LEFT JOIN @PatientNoteClinic PNC ON PNC.PatientId=B.Id
		LEFT JOIN @PrimaryInsuranceClinic PINS ON PINS.InvoiceId=INV.Id
		LEFT JOIN @ChargeNotesClinic CHNote ON CHNote.ChargeId=A.Id
		
		UNION
		
		SELECT DISTINCT B.FirstName,B.LastName,CONVERT(varchar,B.DOB,101)DOB,B.Sex,A.InvoiceId [visit_id],B.Id [mrn],CONVERT(varchar,A.CreatedDate,101)[ChargePostDate],
		CONVERT(varchar,A.BillFromDate,101)[dos],A.AccessionNumber[specimen_id],
				--A.InsuranceCompanyName[insurance_name],
			CASE WHEN VC.IsSelfPayment=1 Then 'Self' ELSE	INS.CompanyName END [insurance_name],
				ICT.CompanyType[financial_class],(PD.LastName+' '+PD.FirstName)[physician],PDI.Identifier[npi],
				CASE WHEN CLM.SentDate is not NULL then 'Billed' ELSE 'Not Billed' END [billing_status],
				CASE WHEN (A.PaymentReceived=1 AND CLM.SentDate IS NOT NULL) THEN 'Received' WHEN (A.PaymentReceived=0 AND CLM.SentDate IS NOT NULL) THEN 'NOT Received' END [payer_status],
				A.Id[ChargeId],A.CPTCode,CPT.Description[ServiceDescription],A.ICD1 PrimaryDX,A.ICD2 DX2,A.ICD3 DX3,A.ICD4 DX4,A.Mod1,A.Mod2,A.Mod3,A.Mod4,
				--A.ChargeAmount,
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY A.Id ORDER BY A.Id ASC))=1 THEN A.ChargeAmount ELSE 0 END[ChargeAmount],
				CONVERT(varchar,CLM.SentDate,101)[billing_date],
				--ROW_NUMBER() OVER(PARTITION BY PC.Id ORDER BY PC.Id ASC),				
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY PC.Id ORDER BY PC.Id ASC))=1 THEN PC.PaidAmount ELSE 0 END[PaidAmount],
				--PC.PaidAmount,
				PA.Amount [totaladj],
				PA.ReasonCode [carc_code],								
				CONVERT(varchar,VC.EffectiveDate,101)[RemitDate],
				CASE WHEN (A.PaymentReceived=1 AND CLM.SentDate IS NOT NULL) THEN 'YES' WHEN (A.PaymentReceived=0 AND CLM.SentDate IS NOT NULL) THEN 'No' END [Adjudicated],
				VC.ReferenceNo[Check_number],ISNULL(A.InsuranceCompanyName,PINS.InsuranceCompanyName)[InsuranceCompanyName],ISNULL(A.FinancialClass,PINS.CompanyType)[DepositFinancialClass],
				PI_ATC_LAB.dbo.ufn_ActiveInsuranceForCaseNo_PolicyNumber(A.BillFromDate,1,A.PatientCaseId)[policy_number],				
				ISNULL(FC.Name,'Other')[facility],
				--FCI.Identifier [Facility NPI],
				null [mr_upload_date],null [ar_note],null [last_touch_date],A.ReviewNeeded,A.Billable,A.ReviewComments,A.AccessionNumber,
				B.Address1[PatientAddress1],B.Address2[PatientAddress2],B.State[PatientState],B.City[PatientCity],B.ZipCode[PatientZip],
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY A.Id ORDER BY A.Id ASC))=1 THEN
					CASE WHEN A.CPTCode='80305' THEN 10.1 
					WHEN A.CPTCode='80307' THEN 53.87 
					WHEN A.CPTCode='G0480' THEN 85.82 
					WHEN A.CPTCode='G0481' THEN 117.44
					WHEN A.CPTCode='G0482' THEN 149.08 ELSE 0 END				
				ELSE 0 END	[ERAmount]
				, 'LAB'[ServiceClassification] ,'LAB' SourceDB,
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY B.Id ORDER BY B.Id ASC))=1 THEN PatientNote ELSE '' END[PatientNote],
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY B.Id ORDER BY B.Id ASC))=1 THEN NoteCreatedBy ELSE '' END[NoteCreatedBy],
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY B.Id ORDER BY B.Id ASC))=1 THEN CONVERT(varchar,NoteCreatedDate,101) ELSE '' END[NoteCreatedDate]		,
				A.POSId,A.DueByFlagCD[DueBy],CLM.PatientAccountNumber AS ClaimId
				--CASE WHEN (ROW_NUMBER() OVER(PARTITION BY A.Id ORDER BY A.Id ASC))=1 THEN CLM.PatientAccountNumber ELSE '' END ClaimId		
				,A.DueAmount	
				,CHNote.CategoryName,CHNote.FollowUpDate,CHNote.HasFollowUp,CHNote.Note,CHNote.ChargeNoteCreatedBy,CHNote.ChargeNoteCreatedDate
		FROM PI_ATC_LAB.dbo.vw_GetChargeForPendingPayment_Dashboard A
		INNER JOIN PI_ATC_LAB.dbo.Patient(NOLOCK) B on B.DefaultCaseId=A.PatientCaseId		
		LEFT JOIN PI_ATC_LAB.dbo.Provider(NOLOCK) PD ON PD.Id=A.PerformingProviderId
		LEFT JOIN PI_ATC_LAB.dbo.ProviderIdentity PDI ON PDI.ProviderId=PD.Id and TypeId=1
		LEFT JOIN PI_ATC_LAB.dbo.Claim (NOLOCK) CLM ON CLM.Id=A.ClaimId
		LEFT JOIN PI_ATC_LAB.dbo.PaymentCharge (NOLOCK) PC ON PC.ChargeId=A.Id 
		LEFT JOIN PI_ATC_LAB.dbo.PaymentAdjustment (NOLOCK) PA ON PA.PaymentChargeId=PC.Id
		LEFT JOIN PI_ATC_LAB.dbo.Payment(NOLOCK) PP ON PP.Id=PC.PaymentId
		LEFT JOIN PI_ATC_LAB.dbo.InsuranceCompany(NOLOCK) INS ON INS.Id=PP.PatientInsuranceCompanyId
		LEFT JOIN PI_ATC_LAB.dbo.ConfigInsuranceCompanyType(NOLOCK) ICT  ON ICT.Id=INS.CompanyTypeId		
		LEFT JOIN PI_ATC_LAB.dbo.Voucher(NOLOCK) VC ON VC.Id=PP.VoucherId
		LEFT JOIN PI_ATC_LAB.dbo.Facility(NOLOCK) FC ON FC.Id=A.PerformingFacilityId	
		LEFT JOIN PI_ATC_LAB.dbo.FacilityIdentity (NOLOCK) FCI ON FCI.FacilityId=FC.Id AND FCI.TypeId=1	
		LEFT JOIN PI_ATC_LAB.dbo.CptCode (NOLOCK) CPT ON CPT.CPTCode=A.CPTCode
		INNER JOIN Invoice(NOLOCK) INV on INV.Id=A.InvoiceId
		LEFT JOIN @PatientNoteLAB PNC ON PNC.PatientId=B.Id
		LEFT JOIN @PrimaryInsuranceClinic PINS ON PINS.InvoiceId=INV.Id
		LEFT JOIN @ChargeNotesLab CHNote ON CHNote.ChargeId=A.Id
		
END







GO

CREATE PROC [dbo].[USP_ReportDataForCatalystAllCharges_Test]--4778
AS
BEGIN

		DECLARE @PatientNoteClinic TABLE
		(
			PatientId INT,
			PatientNote VARCHAR(1000),
			NoteCreatedDate DATE,
			NoteCreatedBy VARCHAR(20)
		)
		INSERT INTO @PatientNoteClinic(PatientId,PatientNote,NoteCreatedDate,NoteCreatedBy)
		SELECT PatientId,Note,CAST(CreatedDate AS DATE)[CreatedDate],CreatedBy 
			FROM PI_ATC_CLINIC.dbo.ActionNote(NOLOCK) A WHERE A.NoteSourceCD='NS.PATIENT' 
		AND CreatedDate=(SELECT MAX(B.CreatedDate) FROM PI_ATC_CLINIC.dbo.ActionNote(NOLOCK) B 
		WHERE B.NoteSourceCD='NS.PATIENT' AND B.PatientId=A.PatientId)

		DECLARE @PatientNoteLAB TABLE
		(
			PatientId INT,
			PatientNote VARCHAR(1000),
			NoteCreatedDate DATE,
			NoteCreatedBy VARCHAR(20)
		)
		INSERT INTO @PatientNoteLAB(PatientId,PatientNote,NoteCreatedDate,NoteCreatedBy)
		SELECT PatientId,Note,CAST(CreatedDate AS DATE)[CreatedDate],CreatedBy 
			FROM PI_ATC_LAB.dbo.ActionNote(NOLOCK) A WHERE A.NoteSourceCD='NS.PATIENT' 
		AND CreatedDate=(SELECT MAX(B.CreatedDate) FROM PI_ATC_LAB.dbo.ActionNote(NOLOCK) B 
		WHERE B.NoteSourceCD='NS.PATIENT' AND B.PatientId=A.PatientId)


		DECLARE @PrimaryInsuranceClinic TABLE
		(
			InvoiceId INT,
			InsuranceCompanyId INT,
			PolicyNo VARCHAR(20),
			PolicyHolderName VARCHAR(200),
			PolicyHolderDOB VARCHAR(20),
			PolicyHolderRelation VARCHAR(20),
			InsuranceCompanyName VARCHAR(200),
			CompanyType VARCHAR(50)
		)
		INSERT INTO @PrimaryInsuranceClinic
		SELECT InvoiceId,InsuranceCompanyId,PolicyNo,PolicyHolderName,PolicyHolderDOB,B.Description,C.CompanyName ,D.CompanyType
		from Claim (NOLOCK)A
		LEFT JOIN ConfigRelationship(NOLOCK) B on B.Id=A.PolicyHolderRelation
		LEFT JOIN InsuranceCompany(NOLOCK) C on C.Id=A.InsuranceCompanyId
		LEFT JOIN ConfigInsuranceCompanyType D on D.Id=C.CompanyTypeId
		WHERE A.Id IN (SELECT MAX(Id) FROM Claim B WHERE B.InvoiceId=A.InvoiceId)

		DECLARE @PrimaryInsuranceLab TABLE
		(
			InvoiceId INT,
			InsuranceCompanyId INT,
			PolicyNo VARCHAR(20),
			PolicyHolderName VARCHAR(200),
			PolicyHolderDOB VARCHAR(20),
			PolicyHolderRelation VARCHAR(20),
			InsuranceCompanyName VARCHAR(200),
			CompanyType VARCHAR(50)
		)
		INSERT INTO @PrimaryInsuranceLab
		SELECT InvoiceId,InsuranceCompanyId,PolicyNo,PolicyHolderName,PolicyHolderDOB,B.Description,C.CompanyName ,D.CompanyType
		from PI_ATC_LAB.dbo.Claim (NOLOCK)A
		LEFT JOIN PI_ATC_LAB.dbo.ConfigRelationship(NOLOCK) B on B.Id=A.PolicyHolderRelation
		LEFT JOIN PI_ATC_LAB.dbo.InsuranceCompany(NOLOCK) C on C.Id=A.InsuranceCompanyId
		LEFT JOIN PI_ATC_LAB.dbo.ConfigInsuranceCompanyType D on D.Id=C.CompanyTypeId
		WHERE A.Id IN (SELECT MAX(Id) FROM PI_ATC_LAB.dbo.Claim B WHERE B.InvoiceId=A.InvoiceId)


		SELECT DISTINCT B.FirstName,B.LastName,CONVERT(varchar,B.DOB,101)DOB,B.Sex,A.InvoiceId [visit_id],B.Id [mrn],CONVERT(varchar,A.CreatedDate,101)[ChargePostDate],
		CONVERT(varchar,A.BillFromDate,101)[dos],A.AccessionNumber[specimen_id],
				--A.InsuranceCompanyName[insurance_name],
			CASE WHEN VC.IsSelfPayment=1 Then 'Self' ELSE	INS.CompanyName END [insurance_name],
				ICT.CompanyType[financial_class],(PD.LastName+' '+PD.FirstName)[physician],PDI.Identifier[npi],
				CASE WHEN CLM.SentDate is not NULL then 'Billed' ELSE 'Not Billed' END [billing_status],
				CASE WHEN (A.PaymentReceived=1 AND CLM.SentDate IS NOT NULL) THEN 'Received' WHEN (A.PaymentReceived=0 AND CLM.SentDate IS NOT NULL) THEN 'NOT Received' END [payer_status],
				A.Id[ChargeId],A.CPTCode,A.Description[ServiceDescription],A.ICD1 PrimaryDX,A.ICD2 DX2,A.ICD3 DX3,A.ICD4 DX4,A.Mod1,A.Mod2,A.Mod3,A.Mod4,
				--A.ChargeAmount,
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY A.Id ORDER BY A.Id ASC))=1 THEN A.ChargeAmount ELSE 0 END[ChargeAmount],
				CONVERT(varchar,CLM.SentDate,101)[billing_date],
				--ROW_NUMBER() OVER(PARTITION BY PC.Id ORDER BY PC.Id ASC),				
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY PC.Id ORDER BY PC.Id ASC))=1 THEN PC.PaidAmount ELSE 0 END[PaidAmount],
				--PC.PaidAmount,
				PA.Amount [totaladj],
				PA.ReasonCode [carc_code],								
				CONVERT(varchar,VC.EffectiveDate,101)[RemitDate],
				CASE WHEN (A.PaymentReceived=1 AND CLM.SentDate IS NOT NULL) THEN 'YES' WHEN (A.PaymentReceived=0 AND CLM.SentDate IS NOT NULL) THEN 'No' END [Adjudicated],
				VC.ReferenceNo[Check_number],ISNULL(A.InsuranceCompanyName,PINS.InsuranceCompanyName)[InsuranceCompanyName],ISNULL(A.FinancialClass,PINS.CompanyType)[DepositFinancialClass],
				dbo.ufn_ActiveInsuranceForCaseNo_PolicyNumber(A.BillFromDate,1,A.PatientCaseId)[policy_number],				
				ISNULL(FC.ChildFacilityName,'Other')[facility],
				--FCI.Identifier [Facility NPI],
				null [mr_upload_date],null [ar_note],null [last_touch_date],A.ReviewNeeded,A.Billable,A.ReviewComments,A.AccessionNumber,
				B.Address1[PatientAddress1],B.Address2[PatientAddress2],B.State[PatientState],B.City[PatientCity],B.ZipCode[PatientZip],
				--A.FeeAmount[ERAmount]
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY A.Id ORDER BY A.Id ASC))=1 THEN A.FeeAmount ELSE 0 END[ERAmount]
				, CASE WHEN INV.InvoiceType=1 THEN 'MH' WHEN INV.InvoiceType=2 THEN 'SUD' ELSE 'NA' END[ServiceClassification] ,'Clinic' SourceDB,
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY B.Id ORDER BY B.Id ASC))=1 THEN PatientNote ELSE '' END[PatientNote],
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY B.Id ORDER BY B.Id ASC))=1 THEN NoteCreatedBy ELSE '' END[NoteCreatedBy],
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY B.Id ORDER BY B.Id ASC))=1 THEN CONVERT(varchar,NoteCreatedDate,101) ELSE '' END[NoteCreatedDate]		,
				A.POSId,A.DueByFlagCD[DueBy],CLM.PatientAccountNumber AS ClaimId
				--CASE WHEN (ROW_NUMBER() OVER(PARTITION BY A.Id ORDER BY A.Id ASC))=1 THEN CLM.PatientAccountNumber ELSE '' END ClaimId	
				,A.DueAmount	
		FROM vw_GetChargeForPendingPayment_Dashboard A
		INNER JOIN Patient(NOLOCK) B on B.DefaultCaseId=A.PatientCaseId		
		LEFT JOIN Provider(NOLOCK) PD ON PD.Id=A.PerformingProviderId
		LEFT JOIN ProviderIdentity PDI ON PDI.ProviderId=PD.Id and TypeId=1
		LEFT JOIN Claim (NOLOCK) CLM ON CLM.Id=A.ClaimId
		LEFT JOIN PaymentCharge (NOLOCK) PC ON PC.ChargeId=A.Id 
		LEFT JOIN PaymentAdjustment (NOLOCK) PA ON PA.PaymentChargeId=PC.Id
		LEFT JOIN Payment(NOLOCK) PP ON PP.Id=PC.PaymentId
		LEFT JOIN InsuranceCompany(NOLOCK) INS ON INS.Id=PP.PatientInsuranceCompanyId
		LEFT JOIN ConfigInsuranceCompanyType(NOLOCK) ICT  ON ICT.Id=INS.CompanyTypeId
		LEFT JOIN Voucher(NOLOCK) VC ON VC.Id=PP.VoucherId
		LEFT JOIN Facility(NOLOCK) FC ON FC.Id=A.PerformingFacilityId	
		LEFT JOIN FacilityIdentity (NOLOCK) FCI ON FCI.FacilityId=FC.Id AND FCI.TypeId=1	
		INNER JOIN Invoice(NOLOCK) INV on INV.Id=A.InvoiceId
		LEFT JOIN @PatientNoteClinic PNC ON PNC.PatientId=B.Id
		LEFT JOIN @PrimaryInsuranceClinic PINS ON PINS.InvoiceId=INV.Id
		
		UNION
		
		SELECT DISTINCT B.FirstName,B.LastName,CONVERT(varchar,B.DOB,101)DOB,B.Sex,A.InvoiceId [visit_id],B.Id [mrn],CONVERT(varchar,A.CreatedDate,101)[ChargePostDate],
		CONVERT(varchar,A.BillFromDate,101)[dos],A.AccessionNumber[specimen_id],
				--A.InsuranceCompanyName[insurance_name],
			CASE WHEN VC.IsSelfPayment=1 Then 'Self' ELSE	INS.CompanyName END [insurance_name],
				ICT.CompanyType[financial_class],(PD.LastName+' '+PD.FirstName)[physician],PDI.Identifier[npi],
				CASE WHEN CLM.SentDate is not NULL then 'Billed' ELSE 'Not Billed' END [billing_status],
				CASE WHEN (A.PaymentReceived=1 AND CLM.SentDate IS NOT NULL) THEN 'Received' WHEN (A.PaymentReceived=0 AND CLM.SentDate IS NOT NULL) THEN 'NOT Received' END [payer_status],
				A.Id[ChargeId],A.CPTCode,CPT.Description[ServiceDescription],A.ICD1 PrimaryDX,A.ICD2 DX2,A.ICD3 DX3,A.ICD4 DX4,A.Mod1,A.Mod2,A.Mod3,A.Mod4,
				--A.ChargeAmount,
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY A.Id ORDER BY A.Id ASC))=1 THEN A.ChargeAmount ELSE 0 END[ChargeAmount],
				CONVERT(varchar,CLM.SentDate,101)[billing_date],
				--ROW_NUMBER() OVER(PARTITION BY PC.Id ORDER BY PC.Id ASC),				
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY PC.Id ORDER BY PC.Id ASC))=1 THEN PC.PaidAmount ELSE 0 END[PaidAmount],
				--PC.PaidAmount,
				PA.Amount [totaladj],
				PA.ReasonCode [carc_code],								
				CONVERT(varchar,VC.EffectiveDate,101)[RemitDate],
				CASE WHEN (A.PaymentReceived=1 AND CLM.SentDate IS NOT NULL) THEN 'YES' WHEN (A.PaymentReceived=0 AND CLM.SentDate IS NOT NULL) THEN 'No' END [Adjudicated],
				VC.ReferenceNo[Check_number],ISNULL(A.InsuranceCompanyName,PINS.InsuranceCompanyName)[InsuranceCompanyName],ISNULL(A.FinancialClass,PINS.CompanyType)[DepositFinancialClass],
				PI_ATC_LAB.dbo.ufn_ActiveInsuranceForCaseNo_PolicyNumber(A.BillFromDate,1,A.PatientCaseId)[policy_number],				
				ISNULL(FC.Name,'Other')[facility],
				--FCI.Identifier [Facility NPI],
				null [mr_upload_date],null [ar_note],null [last_touch_date],A.ReviewNeeded,A.Billable,A.ReviewComments,A.AccessionNumber,
				B.Address1[PatientAddress1],B.Address2[PatientAddress2],B.State[PatientState],B.City[PatientCity],B.ZipCode[PatientZip],
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY A.Id ORDER BY A.Id ASC))=1 THEN
					CASE WHEN A.CPTCode='80305' THEN 10.1 
					WHEN A.CPTCode='80307' THEN 53.87 
					WHEN A.CPTCode='G0480' THEN 85.82 
					WHEN A.CPTCode='G0481' THEN 117.44
					WHEN A.CPTCode='G0482' THEN 149.08 ELSE 0 END				
				ELSE 0 END	[ERAmount]
				, 'LAB'[ServiceClassification] ,'LAB' SourceDB,
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY B.Id ORDER BY B.Id ASC))=1 THEN PatientNote ELSE '' END[PatientNote],
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY B.Id ORDER BY B.Id ASC))=1 THEN NoteCreatedBy ELSE '' END[NoteCreatedBy],
				CASE WHEN (ROW_NUMBER() OVER(PARTITION BY B.Id ORDER BY B.Id ASC))=1 THEN CONVERT(varchar,NoteCreatedDate,101) ELSE '' END[NoteCreatedDate]		,
				A.POSId,A.DueByFlagCD[DueBy],CLM.PatientAccountNumber AS ClaimId
				--CASE WHEN (ROW_NUMBER() OVER(PARTITION BY A.Id ORDER BY A.Id ASC))=1 THEN CLM.PatientAccountNumber ELSE '' END ClaimId		
				,A.DueAmount	
		FROM PI_ATC_LAB.dbo.vw_GetChargeForPendingPayment_Dashboard A
		INNER JOIN PI_ATC_LAB.dbo.Patient(NOLOCK) B on B.DefaultCaseId=A.PatientCaseId		
		LEFT JOIN PI_ATC_LAB.dbo.Provider(NOLOCK) PD ON PD.Id=A.PerformingProviderId
		LEFT JOIN PI_ATC_LAB.dbo.ProviderIdentity PDI ON PDI.ProviderId=PD.Id and TypeId=1
		LEFT JOIN PI_ATC_LAB.dbo.Claim (NOLOCK) CLM ON CLM.Id=A.ClaimId
		LEFT JOIN PI_ATC_LAB.dbo.PaymentCharge (NOLOCK) PC ON PC.ChargeId=A.Id 
		LEFT JOIN PI_ATC_LAB.dbo.PaymentAdjustment (NOLOCK) PA ON PA.PaymentChargeId=PC.Id
		LEFT JOIN PI_ATC_LAB.dbo.Payment(NOLOCK) PP ON PP.Id=PC.PaymentId
		LEFT JOIN PI_ATC_LAB.dbo.InsuranceCompany(NOLOCK) INS ON INS.Id=PP.PatientInsuranceCompanyId
		LEFT JOIN PI_ATC_LAB.dbo.ConfigInsuranceCompanyType(NOLOCK) ICT  ON ICT.Id=INS.CompanyTypeId		
		LEFT JOIN PI_ATC_LAB.dbo.Voucher(NOLOCK) VC ON VC.Id=PP.VoucherId
		LEFT JOIN PI_ATC_LAB.dbo.Facility(NOLOCK) FC ON FC.Id=A.PerformingFacilityId	
		LEFT JOIN PI_ATC_LAB.dbo.FacilityIdentity (NOLOCK) FCI ON FCI.FacilityId=FC.Id AND FCI.TypeId=1	
		LEFT JOIN PI_ATC_LAB.dbo.CptCode (NOLOCK) CPT ON CPT.CPTCode=A.CPTCode
		INNER JOIN Invoice(NOLOCK) INV on INV.Id=A.InvoiceId
		LEFT JOIN @PatientNoteLAB PNC ON PNC.PatientId=B.Id
		LEFT JOIN @PrimaryInsuranceClinic PINS ON PINS.InvoiceId=INV.Id
		
END





GO

CREATE PROC USP_ReportDataForCatalystByAccession
AS
BEGIN
		SELECT B.FirstName,B.LastName,B.DOB,B.Sex,'' [visit_id],'' [mrn],CAST(A.BillFromDate as DATE)[dos],A.AccessionNumber[specimen_id],CAST(A.BillFromDate AS DATE)[accession_date],
				A.InsuranceCompanyName[insurance_name],ICT.CompanyType[financial_class],(PD.LastName+' '+PD.FirstName)[physician],PDI.Identifier[npi],'' [practicename],'' [account_manager],
				'' [group_name],CASE WHEN CLM.SentDate is not NULL then 'Billed' ELSE 'Not Billed' END [billing_status],''[case_type],
				CASE WHEN (A.PaymentReceived=1 AND CLM.SentDate IS NOT NULL) THEN 'Received' WHEN (A.PaymentReceived=0 AND CLM.SentDate IS NOT NULL) THEN 'NOT Received' END [payer_status],
				SUM(A.ChargeAmount)[charge], null [result_date],CAST(CLM.SentDate AS DATE)[billing_date],SUM(A.PaidAmount)[totalpaid],SUM(A.TotalAdjustment)[totaladj],
				--(SELECT DueAmount from vw_GetChargeForPendingPayment_Dashboard where AccessionNumber=A.AccessionNumber and DueByFlagCD in ('','patient') and DueAmount>0)[totalPR],
				X.DueAmount [totalPR],
				CAST(VC.EffectiveDate AS DATE)[RemitDate],
				CASE WHEN (A.PaymentReceived=1 AND CLM.SentDate IS NOT NULL) THEN 'YES' WHEN (A.PaymentReceived=0 AND CLM.SentDate IS NOT NULL) THEN 'No' END [Adjudicated],
				VC.ReferenceNo[Check_number],null [carc_code],dbo.ufn_ActiveInsuranceForCaseNo_PolicyNumber(A.BillFromDate,1,A.PatientCaseId)[policy_number],				
				ISNULL(FC.ChildFacilityName,FC.Name)[facility],
				null [mr_upload_date],null [ar_note],null [last_touch_date]
		FROM vw_GetChargeForPendingPayment_Dashboard A
		INNER JOIN Patient(NOLOCK) B on B.DefaultCaseId=A.PatientCaseId
		LEFT JOIN InsuranceCompany(NOLOCK) INS ON INS.Id=A.InsuranceCompanyId
		LEFT JOIN ConfigInsuranceCompanyType(NOLOCK) ICT  ON ICT.Id=INS.CompanyTypeId
		LEFT JOIN Provider(NOLOCK) PD ON PD.Id=A.PerformingProviderId
		LEFT JOIN ProviderIdentity PDI ON PDI.ProviderId=PD.Id and TypeId=1
		LEFT JOIN Claim (NOLOCK) CLM ON CLM.Id=A.ClaimId
		LEFT JOIN PaymentCharge (NOLOCK) PC ON PC.ChargeId=A.Id and pc.ModifiedDate=(select MAX(ModifiedDate) from PaymentCharge pc1(NOLOCK) where pc1.ChargeId=pc.ChargeId)
		LEFT JOIN Payment(NOLOCK) PP ON PP.Id=PC.PaymentId
		LEFT JOIN Voucher(NOLOCK) VC ON VC.Id=PP.VoucherId
		LEFT JOIN Facility(NOLOCK) FC ON FC.Id=A.PerformingFacilityId		
		LEFT JOIN vw_GetChargeForPendingPayment_Dashboard X on X.AccessionNumber=A.AccessionNumber and X.DueByFlagCD in ('','patient') and X.DueAmount>0
		GROUP BY A.AccessionNumber,B.FirstName,B.LastName,B.DOB,B.Sex,CAST(A.BillFromDate as DATE),CAST(A.BillFromDate AS DATE),A.InsuranceCompanyName,ICT.CompanyType,
		PD.LastName,PD.FirstName,PDI.Identifier,CLM.SentDate,A.PaymentReceived,CAST(VC.EffectiveDate AS DATE),ISNULL(FC.ChildFacilityName,FC.Name),VC.ReferenceNo,		
		dbo.ufn_ActiveInsuranceForCaseNo_PolicyNumber(A.BillFromDate,1,A.PatientCaseId),X.DueAmount
END
GO


CREATE PROCEDURE [dbo].[usp_RunDenialDashboard]
AS
BEGIN
	DECLARE @val AS INT=1
	WHILE @val<=2
	BEGIN
			EXEC usp_insertorupdatechargestat
			SET @Val=@Val+1
	END

	update ChargeStat set HasDenial=1 where Denials>0
END
GO


CREATE PROCEDURE [dbo].[usp_RunScrub124]
@Charges ChargeType READONLY,
@ScrubId INT,
@PracticeCode NVARCHAR(25)

AS
BEGIN

--select 2 [FacilityId], 'AHO' [ClinicCode], '231' [CaseNo], 9 [ChargeNumber], 10 [ScrubId], GETDATE() ActionDate,'' Message,'a' ScrubName
		
		DECLARE @ClinicCode NVARCHAR(25) = @PracticeCode 
		SELECT DISTINCT Charge.PerformingFacilityId AS FacilityId,
		 @ClinicCode  [ClinicCode],
		
		Charge.PatientCaseId AS CaseNo,
		  Charge.ChargeNo AS ChargeNumber,
		@ScrubId AS ScrubId, CAST(Charge.NDCFormat AS NVARCHAR(MAX)) AS Message, 
		Charge.BillFromDate AS ActionDate 
		FROM @Charges Charge 
		CROSS APPLY (SELECT TOP 1 c.* 
					FROM Claim c 
					JOIN ClaimCharge svc ON svc.ClaimId = c.Id 
					--AND svc.InvoiceNumber = c.INVOICE_NO 
					WHERE svc.ChargeId = Charge.Id 
					--AND svc.InvoiceNumber = Charge.InvoiceNo 
					ORDER BY c.ClaimDate DESC) Claim 
	WHERE Claim.Frequency = 1 AND (SUBSTRING(Charge.CPTCode, 1, 1) = 'J' OR 
	Charge.CPTCode IN ('90658', 'Q2037', '90649', '90632', '90714', '90715', '90670', '90746', '90636', '90707', '90732', '90736'))
	AND (ISNULL(Charge.NDCCode,'')='' OR Charge.NDCFormat<>4 OR ISNULL(Charge.UnitOfMeasure,0)=0 
	OR ISNULL(Charge.DrugQty,0)=0) 
	AND Charge.EntryDate > '2017-01-10' 
	AND Charge.ChargeNo NOT IN (SELECT SR.ChargeNumber 
							FROM ScrubCoding SR 
							LEFT JOIN ScrubAssignment SA ON SR.FacilityId = SA.FacilityId 
							AND SR.ScrubId = SA.ScrubId 
							AND SR.ScrubResultId = SA.ScrubResultId 
							WHERE ISNULL(SR.ClinicCode, '') = ISNULL(@ClinicCode, '') AND SR.ScrubId = @ScrubId 
							AND SA.CheckoffDate IS NULL AND Charge.PatientCaseId = SR.PatientCaseId)
	ORDER BY CaseNo DESC;
END



GO


CREATE PROCEDURE [dbo].[usp_RunScrub81EM] @Charges ChargeType READONLY, @ScrubId INT ,
@PracticeCode NVARCHAR(25)
AS 
BEGIN
   --DECLARE @BL_Charges  BL_ChargeType
   --DECLARE @ClinicCode NVARCHAR(25) = (SELECT TOP (1) ClinicCode FROM Configuration)
   DECLARE @ClinicCode NVARCHAR(25) = @PracticeCode 
   SELECT
      MAX(Charge.PerformingFacilityId) AS FacilityId,
      @ClinicCode AS ClinicCode,
	  Charge.PatientCaseId [CaseNo],
      --(
      --   SELECT
      --      CaseIdNumber 
      --   FROM
      --      PatientCase 
      --   where
      --      Id = Charge.PatientCaseId
      --)
      --AS CaseNo,
      Charge.ChargeNo AS ChargeNumber,
      @ScrubId AS ScrubId,
      CONCAT('Needs mod 25 bc', 
      (
         SELECT
            STUFF((
            SELECT
               ',' + ' CPT:' + CPTCode + ' DOS: ' + CONVERT(VARCHAR(12), BillFromDate, 101) 
            FROM
               @Charges FOR XML PATH('')), 1, 1, '')
      )
) AS Message,
      Charge.BillFromDate AS ActionDate 
   FROM
      @Charges Charge CROSS APPLY (
      SELECT
         TOP 1 c.* 
      FROM
         Claim c 
         JOIN
            ClaimCharge svc 
            ON svc.ClaimId = c.Id 
         Join
            Charge ch 
            On ch.Id = svc.ChargeId 
            AND c.InvoiceId = ch.InvoiceId 
      WHERE
         svc.ChargeId = Charge.Id 
         AND c.InvoiceId = Charge.InvoiceId 
      ORDER BY
         c.ClaimDate DESC) Claim 
         JOIN
            Charge Charge1 
            ON Charge1.PatientCaseId = Charge.PatientCaseId 
            AND Charge1.BillFromDate = Charge.BillFromDate CROSS APPLY (
            SELECT
               TOP 1 c.* 
            FROM
               Claim c 
               JOIN
                  ClaimCharge svc 
                  ON svc.ClaimId = c.Id 
               Join
                  Charge ch 
                  On ch.Id = svc.ChargeId 
                  AND c.InvoiceId = ch.InvoiceId 
            WHERE
               svc.ChargeId = Charge1.Id 
               AND c.InvoiceId = Charge1.InvoiceId 
            ORDER BY
               c.ClaimDate DESC) Claim1 
               JOIN
                  dbo.FSCharge FeeCharge 
                  ON Charge1.CPTCode = FeeCharge.CPTCode 						--AND FeeCharge.EffectiveDate = CAST(CAST(DATEPART(YEAR, Charge.FromDate) AS VARCHAR) + '-01-01' AS DATETIME) 
                  AND FeeCharge.Modifier = '' 						--AND FeeCharge.GlobalPeriod IN ('000', '010', 'XXX') 
                  AND Charge1.CPTCode BETWEEN '10000' AND '69999' 
                  AND Charge1.CPTCode NOT IN 
                  (
                     '36415',
                     '36416'
                  )
               JOIN
                  dbo.[Provider] U 
                  ON Charge.PerformingProviderId = U.Id 
               JOIN
                  dbo.[Provider] U1 
                  ON Charge1.PerformingProviderId = U1.Id 
                  AND U.SpecialtyID = U1.SpecialtyID 
            WHERE
               Claim.Frequency = 1 
               AND Claim1.Frequency = 1 
               AND Charge.CPTCode BETWEEN '99201' AND '99292' 
               AND '25' NOT IN 
               (
                  Charge.Mod1,
                  Charge.Mod2
               )
               AND CAST(
               CASE
                  WHEN
                     Charge.Mod3 != '' 
                     AND Charge.Mod4 = '' 
                  THEN
                     CASE
                        WHEN
                           Charge.Mod3 NOT IN 
                           (
                              '25'
                           )
                        THEN
                           1 
                        ELSE
                           0 
                     END
                     WHEN
                        Charge.Mod3 != '' 
                        AND Charge.Mod4 != '' 
                     THEN
                        CASE
                        WHEN
                     Charge.Mod3 NOT IN 
                              (
                                 '25'
                              )
                              AND Charge.Mod4 NOT IN 
                              (
                                 '25'
                              )
                           THEN
                              1 
                           ELSE
                              0 
                        END
                        ELSE
                           1 
               END
               AS BIT) = 1 
               AND 'CCIB' NOT IN 
               (
                  Charge.Message1, Charge.Message2
               )
               --AND (Charge.Amount - Charge.InsuranceBalance) = 0 
               AND Charge.BillFromDate >= '2010-08-01' 
               AND ISNULL(@ClinicCode, '') = 'TSB' 
               AND 
               (
                  SELECT
                     TOP 1 Value 
                  FROM
                     ScrubConfig 
                  WHERE
                     ScrubId = 'EMNeedsMod25' 
                     AND [Definition] = 'EXCLUDEINS'
               )
               IN 
               (
(
                  SELECT
                     InsuranceCompanyID 
                  FROM
                     dbo.Claim 
                  WHERE
                     dbo.Claim.InvoiceId = Charge.InvoiceId),
                     (
                        SELECT
                           InsuranceCompanyId 
                        FROM
                           dbo.Claim 
                        WHERE
                           dbo.Claim.InvoiceId = Charge1.InvoiceId 
                     )
               )
               AND Charge.PatientCaseId NOT IN 
               (
                  SELECT
                     Charge2.PatientCaseId 
                  FROM
                     Charge AS Charge2 
                     JOIN
                        dbo.FSCharge FeeCharge1 
                        ON Charge2.CPTCode = FeeCharge1.CPTCode 								--AND DATEPART(YEAR,FeeCharge1.EffectiveDate) =
                        -- (SELECT TOP 1 MAX(DATEPART(YEAR, FeeCharge2.EffectiveDate)) 
                        --												FROM  FSCharge FeeCharge2)
                        AND FeeCharge1.Modifier = '' 								--AND FeeCharge1.GlobalPeriod IN ('090') 
                        AND Charge2.CPTCode BETWEEN '10000' AND '69999' CROSS APPLY (
                        SELECT
                           TOP 1 c.* 
                        FROM
                           Claim c 
                           JOIN
                              ClaimCharge svc 
                              ON svc.ClaimId = c.Id 
                           Join
                              Charge ch 
                              On ch.Id = svc.ChargeId 
                              AND c.InvoiceId = ch.InvoiceId 
                        WHERE
                           svc.ChargeId = Charge2.Id 
                           AND c.InvoiceId = Charge2.InvoiceId 
                        ORDER BY
                           c.ClaimDate DESC) Claim2 
                        WHERE
                           Claim2.Frequency = 1 
                           AND Charge2.PatientCaseId = Charge.PatientCaseId 
                           AND Charge2.BillFromDate = Charge.BillFromDate
               )
               AND Charge.ChargeNo NOT IN 
               (
                  SELECT
                     SR.ChargeNumber 
                  FROM
                     dbo.ScrubAssignment SA 
                     JOIN
                        dbo.ScrubCoding SR 
                        ON SR.ScrubId = SA.ScrubId 
                        AND SA.ScrubResultId = SR.ScrubResultId 
                  WHERE
                     SA.CheckoffUserId = '' 
                     AND SA.ScrubId = @ScrubId
            )
            GROUP BY
               Charge.PatientCaseId,
               Charge.BillFromDate,
               Charge.CPTCode,
               Charge.ChargeNo;
END


GO


CREATE PROCEDURE [dbo].[usp_RunScrub82EM]
@Charges  ChargeType READONLY,
@ScrubId INT,
@PracticeCode NVARCHAR(25)

AS
BEGIN
	--DECLARE @ClinicCode NVARCHAR(25) = (SELECT TOP (1) ClinicCode FROM Configuration);
	DECLARE @ClinicCode NVARCHAR(25) = @PracticeCode
	SELECT MAX(Charge.PerformingFacilityId) AS FacilityId, @ClinicCode AS ClinicCode,
				--(SELECT CaseIdNumber FROM PatientCase where Id = Charge.PatientCaseId) 
				Charge.PatientCaseId AS CaseNo,	
	Charge.ChargeNo AS ChargeNumber,
		@ScrubId AS ScrubId,CONCAT('Needs mod 24 bc', 
		(SELECT STUFF((SELECT ',' + ' CPT:' + CPTCode + ' DOS: ' + CONVERT(VARCHAR(12), BillFromDate, 101)
	FROM  @Charges FOR XML PATH('')), 1, 1,''))) AS Message,Charge.BillFromDate AS ActionDate  FROM @Charges Charge1 
	
	CROSS APPLY (SELECT TOP 1 c.* 
				FROM Claim c 
				JOIN ClaimCharge svc ON svc.ClaimId = c.Id 
				JOIN Charge ch ON ch.Id = svc.ChargeId
				AND ch.InvoiceId = c.InvoiceId
				WHERE svc.ChargeId = Charge1.Id 
				AND ch.InvoiceId = Charge1.InvoiceId 
				ORDER BY c.ClaimDate DESC) Claim1
	JOIN dbo.FSCharge FeeCharge ON Charge1.CPTCode = FeeCharge.CPTCode 
					--AND FeeCharge.EffectiveDate = CAST(CAST(DATEPART(YEAR, Charge1.BillFromDate) AS VARCHAR) + '-01-01' AS DATETIME) 
					AND FeeCharge.Modifier = ''
					 --AND FeeCharge.GlobalPeriod IN ('010', '090') 
	JOIN Charge Charge ON Charge.PatientCaseId = Charge1.PatientCaseId 
	AND 
				--DATEADD(DAY, CAST(FeeCharge.GlobalPeriod AS INT) * -1, 
				Charge.BillFromDate < Charge1.BillFromDate
				 AND Charge1.BillFromDate < Charge.BillFromDate    
	CROSS APPLY (SELECT TOP 1 c.* FROM Claim c JOIN ClaimCharge svc ON svc.ClaimId = c.Id 
	JOIN Charge ch ON ch.Id = svc.ChargeId
	AND ch.InvoiceId = c.InvoiceId 
				WHERE svc.ChargeId = Charge.Id 
				AND c.InvoiceId = Charge.InvoiceId 
				ORDER BY c.FromDate DESC) Claim
	JOIN dbo.[Provider] U ON Charge.PerformingProviderId = U.Id 
	JOIN dbo.[Provider] U1 ON Charge1.PerformingProviderId = U1.Id 
	AND U.SpecialtyID = U1.SpecialtyID  
	WHERE Claim.Frequency = 0 AND Claim1.Frequency = 1 AND Charge.CPTCode BETWEEN '99201' AND '99292'
	 AND Charge1.CPTCode BETWEEN '10000' AND '69999' 
	AND Charge1.CPTCode NOT IN ('36415', '36415') AND Charge.CPTCode != '99024' AND '24' NOT IN (Charge.Mod1, Charge.Mod2) AND 
	Charge1.Mod1 NOT IN ('AS', '80', '81', '82') AND Charge1.Mod2 NOT IN ('AS', '80', '81', '82') 
	AND CAST(CASE WHEN Charge1.Mod3 != '' AND Charge1.Mod4 = '' THEN CASE WHEN Charge1.Mod3 NOT IN ('24','AS','80','81','82') THEN 1 ELSE 0 END 
				WHEN Charge1.Mod3 != '' AND Charge1.Mod4 != '' THEN CASE WHEN Charge1.Mod3 NOT IN ('24','AS','80', '81', '82') 
				AND Charge1.Mod4 NOT IN ('24', 'AS', '80', '81', '82') THEN 1 ELSE 0 END ELSE 1 END AS BIT) = 1 
				--AND (Charge.Charge - Charge.InsuranceBalance) = 0
				 AND Charge.BillFromDate >= '2010-08-01' 
				AND 'CCIB' NOT IN (Charge.Message1, Charge.Message2) AND Charge.ChargeNo 
				NOT IN (SELECT SR.ChargeNumber FROM 
						dbo.ScrubAssignment SA 
						JOIN dbo.ScrubCoding SR ON SR.ScrubId = SA.ScrubId AND SR.ScrubResultId = SA.ScrubResultId 
						WHERE SA.CheckoffUserId = '' AND SA.ScrubId = @ScrubId)  
	GROUP BY Charge.PatientCaseId,    Charge.BillFromDate,    Charge.CPTCode,    Charge.ChargeNo;
END


GO


CREATE PROCEDURE [dbo].[usp_RunScrub83EM]
@Charges  ChargeType READONLY,
@ScrubId INT,
@PracticeCode NVARCHAR(25)

AS
BEGIN
	--DECLARE @ClinicCode NVARCHAR(25) = (SELECT TOP (1) ClinicCode FROM Configuration);
	DECLARE @ClinicCode NVARCHAR(25) = @PracticeCode
	SELECT MAX(Charge.PerformingFacilityId) AS FacilityId, @ClinicCode AS ClinicCode, 
				--(SELECT CaseIdNumber FROM PatientCase where Id = Charge.PatientCaseId) 
				Charge.PatientCaseId AS CaseNo,
	 Charge.ChargeNo AS ChargeNumber,
		@ScrubId AS ScrubId,CONCAT('Needs mod 57 bc',
		 (SELECT STUFF((SELECT ',' + ' CPT:' + CPTCode + ' DOS: ' + CONVERT(VARCHAR(12), BillFromDate, 101)
													FROM @Charges FOR XML PATH('')), 1, 1,''))) AS Message,
		Charge.BillFromDate AS ActionDate 
	FROM @Charges Charge 
	CROSS APPLY (SELECT TOP 1 c.* FROM Claim c 
				JOIN ClaimCharge svc ON svc.ClaimId= c.Id 
				JOIN Charge ch ON ch.InvoiceId = c.InvoiceId
				AND svc.ChargeId = ch.Id
				 WHERE svc.ChargeId = Charge.Id 
				AND c.InvoiceId = Charge.InvoiceId 
				ORDER BY c.ClaimDate DESC) Claim
	JOIN Charge Charge1 ON Charge.PatientCaseId = Charge1.PatientCaseId AND DATEADD(DAY, -1, Charge1.BillFromDate) <= Charge.BillFromDate 
			AND Charge1.BillFromDate >= Charge.BillFromDate    
	CROSS APPLY (SELECT TOP 1 c.* FROM Claim c 
				JOIN ClaimCharge svc ON svc.ClaimId = c.Id 
				JOIN Charge ch ON ch.Id = svc.ChargeId
				AND ch.InvoiceId = c.InvoiceId 
				WHERE svc.ChargeId = Charge1.Id 
				AND ch.InvoiceId = Charge1.InvoiceId
				 ORDER BY c.ClaimDate DESC) Claim1
	JOIN dbo.[Provider] U ON Charge.PerformingProviderId = U.Id 
	JOIN dbo.[Provider] U1 ON Charge1.PerformingProviderId = U1.Id 
	AND U.SpecialtyID = U1.SpecialtyID
	JOIN dbo.FSCharge FeeCharge ON Charge1.CPTCode = FeeCharge.CPTCode 
			--AND FeeCharge.EffectiveDate = CAST(CAST(DATEPART(YEAR, Charge.FromDate) AS VARCHAR) + '-01-01' AS DATETIME) 
			AND FeeCharge.Modifier = '' 
			--AND FeeCharge.GlobalPeriod IN ('090', '90') 
			AND Charge1.CPTCode BETWEEN '10000' AND '69999'  
	WHERE Claim.Frequency = 1 AND Claim1.Frequency = 1 AND Charge.CPTCode BETWEEN '99201' AND '99292'
	 AND Charge.Mod1 NOT IN ('57', 'AS', '80', '81', '82') 
	AND Charge.Mod2 NOT IN ('57', 'AS', '80', '81', '82') 
	AND CAST(CASE WHEN Charge.Mod3 != '' AND Charge.Mod4 = '' THEN CASE WHEN Charge.Mod3 NOT IN ('57') THEN 1 ELSE 0 END 
		WHEN Charge.Mod3 != '' AND Charge.Mod4 != '' THEN 
		CASE WHEN Charge.Mod3 NOT IN ('57') AND Charge.Mod4 NOT IN ('57') THEN 1 ELSE 0 END ELSE 1 END AS BIT) = 1 
	--AND (Charge.Charge - Charge.InsuranceBalance) = 0 
	AND Charge1.CPTCode NOT IN ('36415', '36415') 
	AND Charge.BillFromDate >= '2010-08-01' 
	AND NOT ('24' IN (Charge.Mod1, Charge.Mod2) 
	AND Charge.BillFromDate = Charge1.BillFromDate)
	AND 'CCIB' NOT IN (Charge.Message1, Charge.Message2) 
	AND Charge.ChargeNo NOT IN (SELECT SR.ChargeNumber FROM ScrubAssignment SA 
							JOIN dbo.ScrubCoding SR ON SR.ScrubId = SA.ScrubId AND SR.ScrubResultId = SA.ScrubResultId 
							WHERE SA.CheckoffUserId = '' AND SA.ScrubId = @ScrubId)
	GROUP BY Charge.PatientCaseId,    Charge.BillFromDate,    Charge.CPTCode,    Charge.ChargeNo;
END


GO

CREATE PROCEDURE [dbo].[usp_RunScrub84EM]
@Charges  ChargeType READONLY,
@ScrubId INT,
@PracticeCode NVARCHAR(25)

AS
BEGIN
		--DECLARE @ClinicCode NVARCHAR(25) = (SELECT TOP (1) ClinicCode FROM Configuration);
		DECLARE @ClinicCode NVARCHAR(25) = @PracticeCode
		SELECT MAX(Charge.PerformingFacilityId) AS FacilityId, @ClinicCode AS ClinicCode,
		 --(SELECT CaseIdNumber FROM PatientCase where Id = Charge1.PatientCaseId) AS CaseNo,
		 Charge1.PatientCaseId [CaseNo],
		 MAX(Charge1.ChargeNo) AS ChargeNumber,
			@ScrubId AS ScrubId,CONCAT('Needs mod 58, 59, 78, 79 bc', 
			(SELECT STUFF((SELECT ',' + ' CPT:' + CPTCode + ' DOS: ' + CONVERT(VARCHAR(12), BillFromDate, 101)
			FROM  @Charges FOR XML PATH('')), 1, 1, ''))) AS Message,Charge1.BillFromDate AS ActionDate  
		FROM @Charges Charge 
		CROSS APPLY (SELECT TOP 1 c.* 
					FROM Claim c 
					JOIN ClaimCharge svc ON svc.ClaimId = c.Id 
					JOIN Charge ch ON ch.Id = svc.ChargeId
					AND ch.InvoiceId = c.InvoiceId 
					WHERE svc.ChargeId = Charge.Id 
					AND c.InvoiceId = Charge.InvoiceId 
					ORDER BY c.ClaimDate DESC) Claim
		JOIN dbo.FSCharge FeeCharge ON Charge.CPTCode = FeeCharge.CPTCode 
			--AND FeeCharge.EffectiveDate = CAST(CAST(DATEPART(YEAR, Charge.FromDate) AS VARCHAR) + '-01-01' AS DATETIME) 
			AND FeeCharge.Modifier = '' 
			--AND FeeCharge.GlobalPeriod IN ('010', '090')    
		JOIN Charge Charge1 ON Charge.PatientCaseId = Charge1.PatientCaseId 
			--AND DATEADD(DAY, CAST(FeeCharge.GlobalPeriod AS INT) * -1, Charge1.BillFromDate) < Charge.BillFromDate 
			AND Charge.BillFromDate < Charge1.BillFromDate    
		CROSS APPLY (SELECT TOP 1 c.* 
						FROM Claim c 
						JOIN ClaimCharge svc ON svc.ClaimId = c.Id 
					JOIN Charge ch ON ch.Id = svc.ChargeId
					AND ch.InvoiceId = c.InvoiceId 
					WHERE svc.ChargeId = Charge1.Id 
					AND c.InvoiceId = Charge1.InvoiceId 
					ORDER BY c.ClaimDate DESC) Claim1
		CROSS APPLY (SELECT InsuranceCompanyId FROM dbo.Claim WHERE dbo.Claim.InvoiceId = Charge1.InvoiceId) InsCompany
		JOIN dbo.[Provider] U ON Charge.PerformingProviderId = U.Id
		JOIN dbo.[Provider] U1 ON Charge1.PerformingProviderId = U1.Id AND U.SpecialtyID = U1.SpecialtyID  
		WHERE Claim.Frequency = 1 AND Claim1.Frequency = 1 
		AND 'CCIB' NOT IN (Charge.Message1, Charge.Message2, Charge1.Message1, Charge1.Message2)
		AND CAST(CASE WHEN Charge1.BillFromDate >= '2015-01-01' 
		AND (SELECT CompanyTypeId FROM dbo.InsuranceCompany IC WHERE IC.Id = InsCompany.InsuranceCompanyId) = 
			(SELECT Id FROM ConfigInsuranceCompanyType WHERE CompanyType = 'Medicare') THEN 
			CASE WHEN Charge1.Mod1 NOT IN ('58','59','78','79','51','76','AS','80','81','82','XE','XS','XP','XU') 
			AND	Charge1.Mod2 NOT IN ('58', '59', '78', '79', '51', '76', 'AS', '80', '81', '82', 'XE', 'XS', 'XP', 'XU') 
			AND	CAST(CASE WHEN Charge1.Mod3 != '' AND Charge1.Mod4 = '' THEN 
			CASE WHEN Charge1.Mod3 NOT IN ('58', '59', '78', '79', '51', '76', 'AS', '80', '81', '82', 'XE', 'XS', 'XP','XU') THEN 1 ELSE 0 END
			WHEN Charge1.Mod3 != '' AND Charge1.Mod4 != '' THEN CASE 
			WHEN Charge1.Mod3 NOT IN ('58', '59', '78', '79', '51', '76', 'AS', '80', '81', '82', 'XE', 'XS', 'XP','XU') 
			AND Charge1.Mod4 NOT IN ('58', '59', '78', '79', '51', '76', 'AS', '80', '81', '82', 'XE', 'XS', 'XP','XU') 
			THEN 1 ELSE 0 END ELSE 1 END AS BIT) = 1 THEN 1 ELSE 0 END ELSE CASE 
			WHEN Charge1.Mod1 NOT IN ('58', '59', '78', '79', '51', '76', 'AS', '80', '81', '82') 
			AND Charge1.Mod2 NOT IN ('58', '59', '78', '79', '51', '76', 'AS', '80', '81', '82') AND CAST(CASE WHEN Charge1.Mod3 != '' 
			AND Charge1.Mod4 = '' THEN CASE WHEN Charge1.Mod3 NOT IN ('58', '59', '78', '79', '51', '76', 'AS', '80', '81', '82') 
			THEN 1 ELSE 0 END
			WHEN Charge1.Mod3 != '' AND Charge1.Mod4 != '' THEN CASE 
			WHEN Charge1.Mod3 NOT IN ('58', '59', '78', '79', '51', '76', 'AS', '80', '81', '82') 
			AND Charge1.Mod4 NOT IN ('58', '59', '78', '79', '51', '76', 'AS', '80', '81', '82') 
			THEN 1 ELSE 0 END ELSE 1 END AS BIT) = 1 THEN 1 ELSE 0 END END AS BIT) = 1 
			--AND (Charge1.Charge - Charge1.InsuranceBalance) = 0 
			AND Charge1.BillFromDate >= '2015-09-21' 
			AND 'CCIB' NOT IN (Charge1.Message1, Charge1.Message2) AND 'NC' != Charge1.Mod1 AND 'NF' != Charge1.Mod2 
			AND Charge1.ChargeNo NOT IN (SELECT SR.ChargeNumber 
										FROM  dbo.ScrubAssignment SA JOIN dbo.ScrubCoding SR ON SR.ScrubId = SA.ScrubId 
										AND SR.ScrubResultId = SA.ScrubResultId WHERE SA.CheckoffUserId = ''
										 AND SA.ScrubId = @ScrubId)
	GROUP BY Charge1.PatientCaseId,    Charge1.BillFromDate,    Charge1.CPTCode;
END



GO


CREATE PROCEDURE [dbo].[usp_RunScrub86EM]
@Charges  ChargeType READONLY,
@ScrubId INT,
@PracticeCode NVARCHAR(25)
AS
BEGIN
		--DECLARE @ClinicCode NVARCHAR(25) = (SELECT TOP (1) ClinicCode FROM Configuration);
		DECLARE @ClinicCode NVARCHAR(25) = @PracticeCode
		SELECT MAX(Charge.PerformingFacilityId) AS FacilityId, @ClinicCode AS ClinicCode,
				--(SELECT CaseIdNumber FROM PatientCase where Id = Charge.PatientCaseId) 
				Charge.PatientCaseId AS CaseNo,
		 Charge.ChargeNo AS ChargeNumber,
			@ScrubId AS ScrubId,CE.Col2 +' need modifier 24,25 or 57 with '+ CE.Col1 AS Message,Charge.BillFromDate AS ActionDate  
		FROM @Charges AS Charge    
		CROSS APPLY (SELECT TOP 1 c.* 
					FROM Claim c 
					JOIN ClaimCharge svc ON svc.ClaimId = c.Id 
					--AND svc.InvoiceNumber = c.INVOICE_NO 
					--WHERE svc.ChargeNumber = Charge.ChgNo 
					--AND svc.InvoiceNumber = Charge.InvoiceNo 
					ORDER BY c.ClaimDate DESC) Claim
		JOIN Charge Charge1 ON Charge.PatientCaseId = Charge1.PatientCaseId 
		AND Charge.BillFromDate = Charge1.BillFromDate 
		CROSS APPLY (SELECT TOP 1 c.* 
					FROM Claim c 
					JOIN ClaimCharge svc ON svc.ClaimId = c.Id 
					--AND svc.InvoiceNumber = c.INVOICE_NO
					--WHERE svc.ChargeNumber = Charge1.ChgNo
					-- AND svc.InvoiceNumber = Charge1.InvoiceNo 
					 ORDER BY c.ClaimDate DESC) Claim1
					 
		JOIN dbo.[ConfigScrubsCCIEdit] AS CE ON Charge.CPTCode = CE.Col1 
		AND Charge1.CPTCode = CE.Col2 
		JOIN dbo.[Provider] U ON Charge.PerformingProviderId = U.Id 
		JOIN dbo.[Provider] U1 ON Charge1.PerformingProviderId = U1.Id AND U.SpecialtyID = U1.SpecialtyID  
		WHERE Claim.Frequency = 1 AND Claim1.Frequency = 1 AND Charge.BillFromDate >= DATEADD(YEAR, -1, GETDATE()) 
		AND Charge.Mod1 NOT IN ('80', '81', '82', 'AS') AND Charge.Mod2 NOT IN ('80', '81', '82', 'AS') 
		AND 'CCIB' NOT IN (ISNULL(Charge.Message1, ''), ISNULL(Charge.Message2, ''))
		AND CAST(CASE WHEN CE.Del_date = '0001-01-01' THEN CASE WHEN Charge.BillFromDate >= CE.EffectiveDate 
		THEN 1 ELSE 0 END ELSE 
		CASE WHEN Charge.BillFromDate BETWEEN CE.EffectiveDate AND CE.Del_date THEN 1 ELSE 0 END END AS BIT) = 1 
		AND CAST(CASE WHEN CE.Mod = 1 THEN CASE WHEN CE.Col2 >= 99201 THEN CASE WHEN Charge1.Mod1 NOT IN ('24', '25', '57') 
		AND Charge1.Mod2 NOT IN ('24', '25', '57') AND CAST(CASE WHEN Charge1.Mod3 != '' AND Charge1.Mod4 = '' THEN 
		CASE WHEN Charge1.Mod3 NOT IN ('24', '25', '57') THEN 1 ELSE 0 END WHEN Charge1.Mod3 != '' AND Charge1.Mod4 != '' THEN 
		CASE WHEN Charge1.Mod3 NOT IN ('24', '25', '57') AND Charge1.Mod4 NOT IN ('24', '25', '57') THEN 1 ELSE 0 END 
		ELSE 1 END AS BIT) = 1 THEN 1 ELSE 0 END ELSE 
		CASE WHEN Charge1.Mod1 NOT IN ('59', 'XE', 'XS', 'XP', 'XU') AND Charge1.Mod2 NOT IN ('59', 'XE', 'XS', 'XP', 'XU') AND 
		(NOT ('RT' IN (Charge.Mod1, Charge.Mod2) AND 'LT' IN (Charge1.Mod1, Charge1.Mod2)) AND NOT 
			('LT' IN (Charge.Mod1, Charge.Mod2)  AND 'RT' IN (Charge1.Mod1, Charge1.Mod2))) 
		AND CAST(CASE WHEN Charge1.Mod3 != '' AND Charge1.Mod4 = '' THEN 
		CASE WHEN Charge1.Mod3 NOT IN ('59', 'XE', 'XS', 'XP', 'XU') THEN 1 ELSE 0 END WHEN Charge1.Mod3 != '' AND Charge1.Mod4 != '' THEN 
		CASE WHEN Charge1.Mod3 NOT IN ('59', 'XE', 'XS', 'XP', 'XU') AND Charge1.Mod4 != '59' THEN 1 ELSE 0 END ELSE 1 END AS BIT) = 1 THEN 1 
		ELSE 0 END END ELSE 0 END AS BIT) = 1 AND Charge1.Amount > 0 
		AND Charge1.EntryDate > DATEADD(MONTH, -3, GETDATE()) 
		--AND (Charge1.Amount - Charge1.InsuranceBalance) = 0 
		AND CE.Col2 NOT IN ('G0008', 'G0009', 'G00010') 
		AND NOT ('PSL' = ISNULL(@ClinicCode, '') AND CE.Col2 IN ('76000', '69990') AND 
			((SELECT TOP 1 CompanyTypeId FROM  dbo.InsuranceCompany IC WHERE IC.Id = Claim1.InsuranceCompanyId) 
				IN (SELECT Id FROM ConfigInsuranceCompanyType WHERE CompanyType = 'Medicare') OR Claim1.InsuranceCompanyID 
				IN (SELECT [Value] FROM ScrubConfig WHERE ScrubId = 'CCIEDIT' AND  [Definition] = 'EXCLUDEINS')))
		AND 'CCIB' NOT IN (ISNULL(Charge1.Message1, ''), ISNULL(Charge1.Message2, '')) 
		AND Charge.ChargeNo NOT IN 
					(SELECT SR.ChargeNumber 
						FROM dbo.ScrubAssignment SA 
					JOIN ScrubCoding SR ON SA.ScrubId = SR.ScrubId AND SR.ScrubResultId = SA.ScrubResultId 
					WHERE SA.CheckoffUserId = '' AND SA.ScrubId = @ScrubId AND ISNULL(SR.ClinicCode, '') = ISNULL(@ClinicCode, '')
					AND (Select CaseIdNumber From PatientCase where Id = Charge.PatientCaseId) = SR.PatientCaseId)
		GROUP BY Charge.PatientCaseId,    Charge.ChargeNo,    Charge.BillFromDate,    Charge1.ChargeNo,CE.Col2,CE.Col1;
END


GO

CREATE PROCEDURE usp_SaveClaimStatusInquiry
@ClaimId INT,
@ErrorCode VARCHAR(20),
@ErrorMessage VARCHAR(200)
AS
BEGIN
	DECLARE @Id INT

	INSERT INTO ClaimStatusInquiry(PracticeId,ClaimId,CreatedDate)
	SELECT 1,@ClaimId,GETDATE()

	SET @Id=SCOPE_IDENTITY()

	INSERT INTO ClaimStatusInquiryChild(ClaimStatusInquiryId,CategoryCode,StatuCode,CategoryCodeDescription,StatuCodeDescription,Soruce,ErrorMessage)
	SELECT @Id,@ErrorCode,@ErrorCode,@ErrorMessage,@ErrorMessage,'824',@ErrorMessage

END
GO

CREATE PROCEDURE USP_SyncDepositsWithChasePayments
@MonthId INT,
@YearId INT
AS
BEGIN
	INSERT INTO ChasePaymentChild(ChasePaymentId,BankReconciliationId,CreatedDate,CreatedBy)
	SELECT B.Id[ChasePaymentId],A.Id[BankReconciliationId],GETDATE(),'talbothealth'
		FROM BankReconciliation(NOLOCK) A
	LEFT JOIN ChasePayments(NOLOCK) B on B.Description like CONCAT('%', A.CheckNumber, '%') 
	WHERE A.MonthId=@MonthId and A.YearId=@YearId AND B.Amount=(ISNULL(ClinicPaymentAmount,0)+ISNULL(LABPaymentAmount,0)+ISNULL(ResPaymentAmount,0))
	AND B.MonthId=@MonthId AND B.YearId=@YearId
	AND A.Id NOT in (SELECT DISTINCT BankReconciliationId FROM ChasePaymentChild(NOLOCK))
	
	SELECT 0 [Id];
END
GO

CREATE procedure [dbo].[usp_UpdateChargesforerapaymentforchargesnotfound]
@eraRootid int=1822,
@flag bit=1
as
begin
	
	DECLARE @temp Table
	(
		Id INT IDENTITY(1,1),
		ERAClaimChargePaymentID INT,
		PatientId varchar(10),
		DosDate Date,
		CPTCode VARCHAR(10)
	)
	insert into @temp(PatientId,DosDate,CPTCode,ERAClaimChargePaymentID)
	select SUBSTRING((select   top 1 value from dbo.tfn_Split_EraClaim(B.PatientControlNumber,'-')), 4, LEN((select   top 1 value from dbo.tfn_Split_EraClaim(B.PatientControlNumber,'-')))),A.ServiceDate,A.CPTCode,A.Id
	from ERAClaimChargePayment A
	inner join ERAClaim B on A.ERAClaimID=B.Id
	where ERARootID=@eraRootid and B.StatusId<>2

	declare @temp1 table
	(
	ERAClaimChargePaymentID int,
	chagenumber int

	)
	select * from @temp

	insert into @temp1
	select A.ERAClaimChargePaymentID,B.ChargeNo from @temp A
	inner join Charge B on CAST(A.DosDate as date)=cast(B.BillFromDate as date) and A.CPTCode=B.CPTCode
	inner join Patient C on C.Id=cast(A.PatientId as int)
	where C.DefaultCaseId=B.PatientCaseId and B.IsDeleted=0

	select * from @temp1


	if @flag=1
	begin 
		update ERAClaimChargePayment set ChgNo=B.chagenumber from ERAClaimChargePayment 
	inner join @temp1 B on B.ERAClaimChargePaymentID=ERAClaimChargePayment.Id

	update ERAClaim set IsReprocessRecord=1 where ERARootID=@eraRootid and StatusId<>2
	end
	
	

end


GO

CREATE Procedure usp_UpdateDueByWhereBlank
AS
BEGIN
	UPDATE .Charge set DueByFlagCD='Primary' where Id in (
	SELECT Id from vw_GetChargeForPendingPayment where BillToInsurance=1 and DueByFlagCD='' and DueAmount>0 and IsDeleted=0)
END

