CREATE PROCEDURE usp_UpdatePayerControlNumberToClaims
AS
BEGIN

	CREATE TABLE #Temp
	(	
	PatientControlNumber VARCHAR(50),
	PayerClaimControlNumber VARCHAR(50)
	)

	INSERT INTO #Temp
	select PatientControlNumber,PayerClaimControlNumber FROM ERAClaim(NOLOCK) A WHERE Id IN
	(SELECT MAX(Id) FROM ERAClaim(NOLOCK) group by PatientControlNumber)
	and ISNULL(SendAckToClaim ,0)=0

	
	--select B.PatientAccountNumber,* from Claim(NOLOCK) B
	--left join @Temp A on A.PatientControlNumber=B.PatientAccountNumber
	--where A.PatientControlNumber=B.PatientAccountNumber
	IF EXISTS (SELECT NULL FROM #Temp)
	BEGIN		
			BEGIN TRANSACTION TR_UpdatePayerControlNumber
			BEGIN TRY
		
				UPDATE Claim SET PatientControlNumber=A.PayerClaimControlNumber FROM Claim B
					LEFT JOIN #Temp A on A.PatientControlNumber=B.PatientAccountNumber
				WHERE A.PatientControlNumber=B.PatientAccountNumber

				UPDATE ERAClaim SET SendAckToClaim=1 WHERE ISNULL(SendAckToClaim,0)=0

				COMMIT TRANSACTION TR_UpdatePayerControlNumber
			END TRY
			BEGIN CATCH
				ROLLBACK TRANSACTION TR_UpdatePayerControlNumber
			END CATCH
	END	
	DROP TABLE #Temp
	SELECT 100
END


GO

CREATE Procedure usp_UpdatePlaidPayment_Voucher
 @XmlData NVARCHAR(MAX),
 @IsMatchedWithBank BIT=0,
 @Practice VARCHAR(20)=''
AS    
BEGIN    
    
 DECLARE @iDocument INT    
 DECLARE @biz_UpdateTable TABLE    
 (    
  VoucherId INT,    
  PlaidPaymentId INT  
 )    
    
    
 BEGIN TRY    
		  BEGIN TRANSACTION UpdatePlaidPayment_Voucher    
      
		  EXEC SP_XML_PREPAREDOCUMENT @iDocument OUTPUT,@XmlData    
		  INSERT INTO @biz_UpdateTable(VoucherId,PlaidPaymentId)    
		  SELECT VoucherId,PlaidPaymentId FROM OPENXML (@iDocument,'/ArrayOfVoucherPlaidUpdateDTO/VoucherPlaidUpdateDTO',2)    
		  WITH    
		  (    
		   VoucherId INT,    
		   PlaidPaymentId INT   
		  )    
      
		 EXEC SP_XML_REMOVEDOCUMENT @iDocument    
		
		IF @Practice='LAB'
		  BEGIN
			  UPDATE PI_ATC_LAB.dbo.Voucher SET IsMatchedWithBank=@IsMatchedWithBank FROM PI_ATC_LAB.dbo.Voucher A
			  INNER JOIN @biz_UpdateTable B ON A.Id=B.VoucherId
		END
		IF @Practice='CLINIC'
		  BEGIN
			  UPDATE PI_ATC_CLINIC.dbo.Voucher SET IsMatchedWithBank=@IsMatchedWithBank FROM PI_ATC_CLINIC.dbo.Voucher A
			  INNER JOIN @biz_UpdateTable B ON A.Id=B.VoucherId
		END
		

		UPDATE PI_ATC_CLINIC.dbo.PlaidPayment SET VoucherId=B.VoucherId,MatchedSource=@Practice FROM PI_ATC_CLINIC.dbo.PlaidPayment A
		INNER JOIN @biz_UpdateTable B ON A.Id=B.PlaidPaymentId
  

  
	--select * from @biz_UpdateTable
    
  COMMIT TRANSACTION UpdatePlaidPayment_Voucher    
     
 END TRY    
 BEGIN CATCH      
  ROLLBACK TRANSACTION UpdatePlaidPayment_Voucher      
 END CATCH     
END


GO

CREATE PROCEDURE usp_VoucherPosting
AS
BEGIN
	DECLARE @FromDate DATE='1 Nov 2022'
	DECLARE @ToDate DATE='31 Jan 2023'

		DECLARE @Temp TABLE
		(
		PostingDate DATE,
		RemitgDate DATE,
		PostedBy VARCHAR(30),
		CheckNo VARCHAR(50),
		CheckAmount MONEY,
		Paid MONEY,
		Diff Money,
		PostedCount INT,
		CompanyName VARCHAR(200),
		FinancialClass VARCHAR(100)
		)

		INSERT INTO @Temp(PostingDate,RemitgDate,PostedBy,CheckNo,CheckAmount,Paid,PostedCount,CompanyName,FinancialClass)
			SELECT A.CreatedDate[PostingDate],A.EffectiveDate[RemitgDate],A.CreatedBy[PostedBy],A.ReferenceNo[CheckNo],
					A.Amount[CheckAmount],
					(SELECT SUM(PaidAmount) FROM PaymentCharge(NOLOCK) X 
						INNER JOIN Payment(NOLOCK) Y ON Y.Id=X.PaymentId
					WHERE Y.VoucherId=A.Id	)[Paid],
					(SELECT COUNT(Id) FROM Payment(NOLOCK) WHERE VoucherId=A.Id)[PostedCount],
					B.CompanyName,C.CompanyType[Financial_Class]
			FROM Voucher (NOLOCK)A
			LEFT JOIN InsuranceCompany B ON A.InsuranceCompanyId=B.Id
			LEFT JOIN ConfigInsuranceCompanyType C ON C.Id=B.CompanyTypeId
			WHERE CAST(A.CreatedDate AS DATE)>=@FromDate AND CAST(A.CreatedDate AS DATE)<=@ToDate
		
			UPDATE @Temp SET Diff=CheckAmount-Paid
			
			SELECT * FROM @Temp
END

GO

CREATE PROCEDURE [dbo].[usp_WeeklyChargeInfoReport]          
@FromDate   DATETIME = NULL,          
@ToDate   DATETIME = NULL          
AS          
         BEGIN                                   
         DECLARE @TempData AS TABLE          
(AcctNo       NUMERIC(18, 0),          
 PatientName  NVARCHAR(500),          
 ProviderName NVARCHAR(500),          
 CompanyId    NUMERIC(18, 0),          
 CompanyName  NVARCHAR(500),          
 DOS          DATE,          
 CPTCode      NVARCHAR(50),          
 Modifiers    NVARCHAR(50),          
 ChargeAmt    NUMERIC(18, 2),          
 PriDX        NVARCHAR(50),          
 POS          NVARCHAR(50),          
 ChargeNo     NUMERIC(18, 0),          
 Payments     NUMERIC(18, 2),          
 Adjustments  NUMERIC(18, 2),          
 PaymentBat   NVARCHAR(100),          
 PostDate     DATE,          
 CPTDesc      NVARCHAR(100)          
);          
             INSERT INTO @TempData          
(AcctNo,          
 PatientName,          
 ProviderName,          
 CompanyId,          
 CompanyName,          
 DOS,          
 CPTCode,          
 Modifiers,          
 ChargeAmt,          
 PriDX,          
 POS,          
 ChargeNo,          
 Payments,          
 Adjustments,          
 PaymentBat,          
 PostDate,          
 CPTDesc          
)          
             EXEC usp_PostDetail          
                  @FromDate,          
                  @ToDate;          
             SELECT t.DOS,          
                    t.AcctNo AccountNo,          
                    t.PatientName,          
                    t.CPTCode,          
                    t.CPTDesc [Description],          
                    t.ChargeAmt [Charge],          
                    t.POS          
             FROM @TempData t;  	   		   
		        
         END      

GO



