CREATE TRIGGER [dbo].[trg_ActionCategory_Update] ON [dbo].[ActionCategory]
AFTER UPDATE
AS
	DECLARE @Id_ins int
	DECLARE @UId_ins uniqueidentifier
	DECLARE @PracticeId_ins int
	DECLARE @ParentCategoryId_ins int
	DECLARE @CategoryName_ins varchar(200)
	DECLARE @IsAttachmentRequired_ins bit
	DECLARE @DefaultNote_ins  varchar(1000)
	DECLARE @IsActive_ins bit
	DECLARE @HasFollowUp_ins bit
	DECLARE @ResponseByCD_ins varchar(50)
	DECLARE @FollowUpPeriodCD_ins varchar(50)
	DECLARE @CreatedBy_ins varchar(15)
	DECLARE @CreatedDate_ins datetime
	DECLARE @ModifiedBy_ins varchar(50)
	DECLARE @ModifiedDate_ins datetime


	DECLARE @Id_del int
	DECLARE @UId_del uniqueidentifier
	DECLARE @PracticeId_del int
	DECLARE @ParentCategoryId_del int
	DECLARE @CategoryName_del varchar(200)
	DECLARE @IsAttachmentRequired_del bit
	DECLARE @DefaultNote_del  varchar(1000)
	DECLARE @IsActive_del bit
	DECLARE @HasFollowUp_del bit
	DECLARE @ResponseByCD_del varchar(50)
	DECLARE @FollowUpPeriodCD_del varchar(50)
	DECLARE @CreatedBy_del varchar(15)
	DECLARE @CreatedDate_del datetime
	DECLARE @ModifiedBy_del varchar(50)
	DECLARE @ModifiedDate_del datetime

	DECLARE @HXComments varchar(800)
	DECLARE @Separator varchar(2)

		DECLARE cur_Update_ActionCategory CURSOR LOCAL FOR
		SELECT	[Id]
		FROM	inserted

	DECLARE @Id int

	OPEN cur_Update_ActionCategory
	FETCH NEXT FROM cur_Update_ActionCategory INTO @Id

	WHILE @@FETCH_STATUS = 0
	BEGIN

		SET @HXComments = 'Changed Fields: '
		SET @Separator = ''

		SELECT	@Id_ins = [Id], 
				@UId_ins = [UId], 
				@PracticeId_ins = [PracticeId], 
				@ParentCategoryId_ins = [ParentCategoryId], 
				@CategoryName_ins = [CategoryName], 
				@IsAttachmentRequired_ins = [IsAttachmentRequired]	,
				@DefaultNote_ins = [DefaultNote],
				@IsActive_ins = [IsActive],
				@HasFollowUp_ins = [HasFollowUp],
				@ResponseByCD_ins = [ResponseByCD],
				@FollowUpPeriodCD_ins = [FollowUpPeriodCD],
				@CreatedBy_ins = [CreatedBy],
				@CreatedDate_ins = [CreatedDate],
				@ModifiedBy_ins = [ModifiedBy],
				@ModifiedDate_ins = [ModifiedDate]

		FROM	inserted
		WHERE	[Id] = @Id

		SELECT	@Id_del = [Id], 
				@UId_del = [UId], 
				@PracticeId_del = [PracticeId], 
				@ParentCategoryId_del = [ParentCategoryId], 
				@CategoryName_del = [CategoryName], 
				@IsAttachmentRequired_del = [IsAttachmentRequired],				
				@DefaultNote_del = [DefaultNote]	,
				@IsActive_del = [IsActive],
				@HasFollowUp_del = [HasFollowUp],
				@ResponseByCD_del = [ResponseByCD],
				@FollowUpPeriodCD_del = [FollowUpPeriodCD],
				@CreatedBy_del = [CreatedBy],
				@CreatedDate_del = [CreatedDate],
				@ModifiedBy_del = [ModifiedBy],
				@ModifiedDate_del = [ModifiedDate]
							
		FROM	deleted
		WHERE	[Id] = @Id

		IF	(@Id_ins <> @Id_del)
				OR (@Id_ins IS NULL AND @Id_del IS NOT NULL)
				OR (@Id_ins IS NOT NULL AND @Id_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'Id', 
					@Separator = ', '

		IF	(@UId_ins <> @UId_del)
				OR (@UId_ins IS NULL AND @UId_del IS NOT NULL)
				OR (@UId_ins IS NOT NULL AND @UId_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'UId', 
					@Separator = ', '
					
						IF	(@PracticeId_ins <> @PracticeId_del)
				OR (@PracticeId_ins IS NULL AND @PracticeId_del IS NOT NULL)
				OR (@PracticeId_ins IS NOT NULL AND @PracticeId_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'PracticeId', 
					@Separator = ', '

		IF	(@ParentCategoryId_ins <> @ParentCategoryId_del)
				OR (@ParentCategoryId_ins IS NULL AND @ParentCategoryId_del IS NOT NULL)
				OR (@ParentCategoryId_ins IS NOT NULL AND @ParentCategoryId_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'ParentCategoryId', 
					@Separator = ', '

		IF	(@CategoryName_ins <> @CategoryName_del)
				OR (@CategoryName_ins IS NULL AND @CategoryName_del IS NOT NULL)
				OR (@CategoryName_ins IS NOT NULL AND @CategoryName_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'CategoryName', 
					@Separator = ', '

		IF	(@IsAttachmentRequired_ins <> @IsAttachmentRequired_del)
				OR (@IsAttachmentRequired_ins IS NULL AND @IsAttachmentRequired_del IS NOT NULL)
				OR (@IsAttachmentRequired_ins IS NOT NULL AND @IsAttachmentRequired_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'IsAttachmentRequired', 
					@Separator = ', '

		IF	(@DefaultNote_ins <> @DefaultNote_del)
				OR (@DefaultNote_ins IS NULL AND @DefaultNote_del IS NOT NULL)
				OR (@DefaultNote_ins IS NOT NULL AND @DefaultNote_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'DefaultNote', 
					@Separator = ', '
					
		IF	(@IsActive_ins <> @IsActive_del)
				OR (@IsActive_ins IS NULL AND @IsActive_del IS NOT NULL)
				OR (@IsActive_ins IS NOT NULL AND @IsActive_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'IsActive', 
					@Separator = ', '

		IF	(@HasFollowUp_ins <> @HasFollowUp_del)
				OR (@HasFollowUp_ins IS NULL AND @HasFollowUp_del IS NOT NULL)
				OR (@HasFollowUp_ins IS NOT NULL AND @HasFollowUp_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'HasFollowUp', 
					@Separator = ', '

		IF	(@ResponseByCD_ins <> @ResponseByCD_del)
				OR (@ResponseByCD_ins IS NULL AND @ResponseByCD_del IS NOT NULL)
				OR (@ResponseByCD_ins IS NOT NULL AND @ResponseByCD_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'ResponseByCD', 
					@Separator = ', '

IF	(@FollowUpPeriodCD_ins <> @FollowUpPeriodCD_del)
				OR (@FollowUpPeriodCD_ins IS NULL AND @FollowUpPeriodCD_del IS NOT NULL)
				OR (@FollowUpPeriodCD_ins IS NOT NULL AND @FollowUpPeriodCD_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'FollowUpPeriodCD', 
					@Separator = ', '

	IF	(@CreatedBy_ins <> @CreatedBy_del)
				OR (@CreatedBy_ins IS NULL AND @CreatedBy_del IS NOT NULL)
				OR (@CreatedBy_ins IS NOT NULL AND @CreatedBy_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'CreatedBy', 
					@Separator = ', '
	
	IF	(@CreatedDate_ins <> @CreatedDate_del)
				OR (@CreatedDate_ins IS NULL AND @CreatedDate_del IS NOT NULL)
				OR (@CreatedDate_ins IS NOT NULL AND @CreatedDate_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'CreatedDate', 
					@Separator = ', '


	IF	(@ModifiedBy_ins <> @ModifiedBy_del)
				OR (@ModifiedBy_ins IS NULL AND @ModifiedBy_del IS NOT NULL)
				OR (@ModifiedBy_ins IS NOT NULL AND @ModifiedBy_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'ModifiedBy', 
					@Separator = ', '


	IF	(@ModifiedDate_ins <> @ModifiedDate_del)
				OR (@ModifiedDate_ins IS NULL AND @ModifiedDate_del IS NOT NULL)
				OR (@ModifiedDate_ins IS NOT NULL AND @ModifiedDate_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'ModifiedDate', 
					@Separator = ', '

		IF @HXComments <> 'Changed Fields: '
			INSERT INTO H_ActionCategory(					
					ActionCategoryId,
					UId,
					PracticeId,
					ParentCategoryId,
					[CategoryName],
					IsAttachmentRequired,
					DefaultNote,
					IsActive,
					HasFollowUp,
					ResponseByCD,
					FollowUpPeriodCD,
					CreatedBy,
					CreatedDate,
					ModifiedBy,
					ModifiedDate,
					ActivityType,
					HXComments)
			SELECT	
					Id,	
					UId,				
					PracticeId,
					ParentCategoryId,
					[CategoryName],
					IsAttachmentRequired,		
					DefaultNote,
					IsActive,	
					HasFollowUp,
					ResponseByCD,
					FollowUpPeriodCD,
					CreatedBy,
					CreatedDate,
					ModifiedBy,
					ModifiedDate,
					'UPDATED', 
					@HXComments
			FROM	inserted
			WHERE	[Id] = @Id

		FETCH NEXT FROM cur_Update_ActionCategory INTO @Id
	END

	CLOSE cur_Update_ActionCategory
	DEALLOCATE cur_Update_ActionCategory


GO



