CREATE TRIGGER [dbo].[trg_AttFile_Update] ON [dbo].[AttFile]
AFTER UPDATE
AS
	DECLARE @Id_ins int
	DECLARE @UId_ins uniqueidentifier
	DECLARE @PracticeId_ins int
	DECLARE @FileName_ins varchar(200)
	DECLARE @FullPath_ins varchar(4000)
	DECLARE @AttFileTableId_ins int
	DECLARE @TableIdValue_ins int
	DECLARE @CreatedBy_ins varchar(15)
	DECLARE @CreatedDate_ins datetime
	DECLARE @ModifiedBy_ins varchar(50)
	DECLARE @ModifiedDate_ins datetime
	
	DECLARE @Id_del int
	DECLARE @UId_del uniqueidentifier
	DECLARE @PracticeId_del int	
	DECLARE @FileName_del varchar(200)
	DECLARE @FullPath_del varchar(4000)
	DECLARE @AttFileTableId_del int
	DECLARE @TableIdValue_del int
DECLARE @CreatedBy_del varchar(15)
	DECLARE @CreatedDate_del datetime
	DECLARE @ModifiedBy_del varchar(50)
	DECLARE @ModifiedDate_del datetime
	
	DECLARE @HXComments varchar(800)
	DECLARE @Separator varchar(2)

		DECLARE cur_Update_AttFile CURSOR LOCAL FOR
		SELECT	[Id]
		FROM	inserted

	DECLARE @Id int

	OPEN cur_Update_AttFile
	FETCH NEXT FROM cur_Update_AttFile INTO @Id

	WHILE @@FETCH_STATUS = 0
	BEGIN

		SET @HXComments = 'Changed Fields: '
		SET @Separator = ''

		SELECT	@Id_ins = [Id],  
				@UId_ins = [UId], 
				@PracticeId_ins = [PracticeId], 
				@FileName_ins = [FileName],
				@FullPath_ins = [FullPath], 
				@AttFileTableId_ins = [AttFileTableId],
				@TableIdValue_ins = [TableIdValue],
				@CreatedBy_ins = [CreatedBy],
				@CreatedDate_ins = [CreatedDate],
				@ModifiedBy_ins = [ModifiedBy],
				@ModifiedDate_ins = [ModifiedDate]
				
		FROM	inserted
		WHERE	[Id] = @Id

		SELECT	@Id_del = [Id], 
				@UId_del = [UId], 
				@PracticeId_del = [PracticeId], 
				@FileName_del = [FileName],
				@FullPath_del = [FullPath], 
				@AttFileTableId_del = [AttFileTableId],
				@TableIdValue_del = [TableIdValue],
				@CreatedBy_del = [CreatedBy],
				@CreatedDate_del = [CreatedDate],
				@ModifiedBy_del = [ModifiedBy],
				@ModifiedDate_del = [ModifiedDate]
				
							
		FROM	deleted
		WHERE	[Id] = @Id

		IF	(@Id_ins <> @Id_del)
				OR (@Id_ins IS NULL AND @Id_del IS NOT NULL)
				OR (@Id_ins IS NOT NULL AND @Id_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'Id', 
					@Separator = ', '

		IF	(@UId_ins <> @UId_del)
				OR (@UId_ins IS NULL AND @UId_del IS NOT NULL)
				OR (@UId_ins IS NOT NULL AND @UId_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'UId', 
					@Separator = ', '
					
		IF	(@PracticeId_ins <> @PracticeId_del)
				OR (@PracticeId_ins IS NULL AND @PracticeId_del IS NOT NULL)
				OR (@PracticeId_ins IS NOT NULL AND @PracticeId_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'PracticeId', 
					@Separator = ', '
	
		IF	(@FileName_ins <> @FileName_del)
				OR (@FileName_ins IS NULL AND @FileName_del IS NOT NULL)
				OR (@FileName_ins IS NOT NULL AND @FileName_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'FileName', 
					@Separator = ', '
					
		
		IF	(@FullPath_ins <> @FullPath_del)
				OR (@FullPath_ins IS NULL AND @FullPath_del IS NOT NULL)
				OR (@FullPath_ins IS NOT NULL AND @FullPath_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'FullPath', 
					@Separator = ', '

			IF	(@AttFileTableId_ins <> @AttFileTableId_del)
				OR (@AttFileTableId_ins IS NULL AND @AttFileTableId_del IS NOT NULL)
				OR (@AttFileTableId_ins IS NOT NULL AND @AttFileTableId_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'AttFileTableId', 
					@Separator = ', '

		IF	(@TableIdValue_ins <> @TableIdValue_del)
				OR (@TableIdValue_ins IS NULL AND @TableIdValue_del IS NOT NULL)
				OR (@TableIdValue_ins IS NOT NULL AND @TableIdValue_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'TableIdValue', 
					@Separator = ', '
	
	
	IF	(@CreatedBy_ins <> @CreatedBy_del)
				OR (@CreatedBy_ins IS NULL AND @CreatedBy_del IS NOT NULL)
				OR (@CreatedBy_ins IS NOT NULL AND @CreatedBy_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'CreatedBy', 
					@Separator = ', '
	
	IF	(@CreatedDate_ins <> @CreatedDate_del)
				OR (@CreatedDate_ins IS NULL AND @CreatedDate_del IS NOT NULL)
				OR (@CreatedDate_ins IS NOT NULL AND @CreatedDate_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'CreatedDate', 
					@Separator = ', '


	IF	(@ModifiedBy_ins <> @ModifiedBy_del)
				OR (@ModifiedBy_ins IS NULL AND @ModifiedBy_del IS NOT NULL)
				OR (@ModifiedBy_ins IS NOT NULL AND @ModifiedBy_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'ModifiedBy', 
					@Separator = ', '


	IF	(@ModifiedDate_ins <> @ModifiedDate_del)
				OR (@ModifiedDate_ins IS NULL AND @ModifiedDate_del IS NOT NULL)
				OR (@ModifiedDate_ins IS NOT NULL AND @ModifiedDate_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'ModifiedDate', 
					@Separator = ', '
					

		IF @HXComments <> 'Changed Fields: '
			INSERT INTO H_AttFile(					
					AttFileId,	
					UId,			
					PracticeId,
					FileName,	
					FullPath,
					AttFileTableId,	
					TableIdValue,
					CreatedBy,
					CreatedDate,
					ModifiedBy,
					ModifiedDate,
					ActivityType,
					HXComments)
			SELECT	
