					FullPath,
					AttFileTableId,	
					TableIdValue,
					CreatedBy,
					CreatedDate,
					ModifiedBy,
					ModifiedDate,
					'UPDATED', 
					@HXComments
			FROM	inserted
			WHERE	[Id] = @Id

		FETCH NEXT FROM cur_Update_AttFile INTO @Id
	END

	CLOSE cur_Update_AttFile
	DEALLOCATE cur_Update_AttFile


GO



