DECLARE @ClaimId INT
DECLARE @PerformingDoctorId INT

DECLARE @PayerName VARCHAR(50)

SELECT @ClaimId=Id,@PerformingDoctorId=PerformingDoctorId,@PayerName=PayerName  FROM inserted  
IF(@PerformingDoctorId=13 AND @PayerName='Medicaid of Ohio')
BEGIN
	UPDATE Claim SET IsLoop2420E=1 WHERE Id=@ClaimId 
END

