CREATE TRIGGER [dbo].[trg_ClaimBatch_Update] ON [dbo].[ClaimBatch]
AFTER UPDATE
AS
	Declare	@Id_ins	int	
Declare	@UId_ins	uniqueidentifier
Declare	@PracticeId_ins	int	
Declare	@ClearingHouseId_ins	smallint	
Declare	@DateMade_ins	date	
Declare	@UserName_ins	varchar(50)
Declare	@FromDate_ins	date	
Declare	@ToDate_ins	date	
Declare	@FirstSent_ins	date	
Declare	@LastSent_ins	date	
Declare	@ClaimCount_ins	smallint	
Declare	@Total_ins	decimal	
Declare	@ScrubStatus_ins	tinyint	
Declare	@ScrubSent_ins	datetime	
Declare	@BatchStatus_ins	int	
Declare	@ModifiedBy_ins	varchar(15)
Declare	@ModifiedDate_ins	datetime
Declare	@FilePath_ins	nvarchar(120)


	Declare	@Id_del	int	
Declare	@UId_del	uniqueidentifier
Declare	@PracticeId_del	int	
Declare	@ClearingHouseId_del	smallint	
Declare	@DateMade_del	date	
Declare	@UserName_del	varchar(50)
Declare	@FromDate_del	date	
Declare	@ToDate_del	date	
Declare	@FirstSent_del	date	
Declare	@LastSent_del	date	
Declare	@ClaimCount_del	smallint	
Declare	@Total_del	decimal	
Declare	@ScrubStatus_del	tinyint	
Declare	@ScrubSent_del	datetime	
Declare	@BatchStatus_del	int	
Declare	@ModifiedBy_del	varchar(15)
Declare	@ModifiedDate_del	datetime
Declare	@FilePath_del	nvarchar(120)


	DECLARE @HXComments varchar(800)
	DECLARE @Separator varchar(2)

		DECLARE cur_Update_ClaimBatch CURSOR LOCAL FOR
		SELECT	[Id]
		FROM	inserted

	DECLARE @Id int

	OPEN cur_Update_ClaimBatch
	FETCH NEXT FROM cur_Update_ClaimBatch INTO @Id

	WHILE @@FETCH_STATUS = 0
	BEGIN

		SET @HXComments = 'Changed Fields: '
		SET @Separator = ''

		SELECT	
		@Id_ins	 = Id,
@UId_ins	 = [UId],
@PracticeId_ins	 = PracticeId,
@ClearingHouseId_ins	 = ClearingHouseId,
@DateMade_ins	 = DateMade,
@UserName_ins	 = UserName,
@FromDate_ins	 = FromDate,
@ToDate_ins	 = ToDate,
@FirstSent_ins	 = FirstSent,
@LastSent_ins	 = LastSent,
@ClaimCount_ins	 = ClaimCount,
@Total_ins	 = Total,
@ScrubStatus_ins	 = ScrubStatus,
@ScrubSent_ins	 = ScrubSent,
@BatchStatus_ins	 = BatchStatus,
@ModifiedBy_ins	 = ModifiedBy,
@ModifiedDate_ins	 = ModifiedDate,
@FilePath_ins	 = FilePath

		FROM	inserted
		WHERE	[Id] = @Id

		SELECT			@Id_del	 = Id,
@UId_del	 = [UId],
@PracticeId_del	 = PracticeId,
@ClearingHouseId_del	 = ClearingHouseId,
@DateMade_del	 = DateMade,
@UserName_del	 = UserName,
@FromDate_del	 = FromDate,
@ToDate_del	 = ToDate,
@FirstSent_del	 = FirstSent,
@LastSent_del	 = LastSent,
@ClaimCount_del	 = ClaimCount,
@Total_del	 = Total,
@ScrubStatus_del	 = ScrubStatus,
@ScrubSent_del	 = ScrubSent,
@BatchStatus_del	 = BatchStatus,
@ModifiedBy_del	 = ModifiedBy,
@ModifiedDate_del	 = ModifiedDate,
@FilePath_del	 = FilePath
				
		FROM	deleted
		WHERE	[Id] = @Id

		IF	(@Id_ins <> @Id_del)
				OR (@Id_ins IS NULL AND @Id_del IS NOT NULL)
				OR (@Id_ins IS NOT NULL AND @Id_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'Id', 
					@Separator = ', '

	

		IF	(@UId_ins <> @UId_del)
				OR (@UId_ins IS NULL AND @UId_del IS NOT NULL)
				OR (@UId_ins IS NOT NULL AND @UId_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'UId', 
					@Separator = ', '

		IF	(@PracticeId_ins <> @PracticeId_del)
				OR (@PracticeId_ins IS NULL AND @PracticeId_del IS NOT NULL)
				OR (@PracticeId_ins IS NOT NULL AND @PracticeId_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'PracticeId', 
					@Separator = ', '

		IF	(@ClearingHouseId_ins <> @ClearingHouseId_del)
				OR (@ClearingHouseId_ins IS NULL AND @ClearingHouseId_del IS NOT NULL)
				OR (@ClearingHouseId_ins IS NOT NULL AND @ClearingHouseId_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'ClearingHouseId', 
					@Separator = ', '

		IF	(@DateMade_ins <> @DateMade_del)
				OR (@DateMade_ins IS NULL AND @DateMade_del IS NOT NULL)
				OR (@DateMade_ins IS NOT NULL AND @DateMade_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'DateMade', 
					@Separator = ', '

					IF	(@UserName_ins <> @UserName_del)
				OR (@UserName_ins IS NULL AND @UserName_del IS NOT NULL)
				OR (@UserName_ins IS NOT NULL AND @UserName_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'UserName', 
					@Separator = ', '

					IF	(@FromDate_ins <> @FromDate_del)
				OR (@FromDate_ins IS NULL AND @FromDate_del IS NOT NULL)
				OR (@FromDate_ins IS NOT NULL AND @FromDate_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'FromDate', 
					@Separator = ', '

					IF	(@ToDate_ins <> @ToDate_del)
				OR (@ToDate_ins IS NULL AND @ToDate_del IS NOT NULL)
				OR (@ToDate_ins IS NOT NULL AND @ToDate_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'ToDate', 
					@Separator = ', '

					IF	(@FirstSent_ins <> @FirstSent_del)
				OR (@FirstSent_ins IS NULL AND @FirstSent_del IS NOT NULL)
				OR (@FirstSent_ins IS NOT NULL AND @FirstSent_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'FirstSent', 
					@Separator = ', '

					IF	(@LastSent_ins <> @LastSent_del)
				OR (@LastSent_ins IS NULL AND @LastSent_del IS NOT NULL)
				OR (@LastSent_ins IS NOT NULL AND @LastSent_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'LastSent', 
					@Separator = ', '

			IF	(@ClaimCount_ins <> @ClaimCount_del)
				OR (@ClaimCount_ins IS NULL AND @ClaimCount_del IS NOT NULL)
				OR (@ClaimCount_ins IS NOT NULL AND @ClaimCount_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'ClaimCount', 
					@Separator = ', '

						IF	(@Total_ins <> @Total_del)
				OR (@Total_ins IS NULL AND @Total_del IS NOT NULL)
				OR (@Total_ins IS NOT NULL AND @Total_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'Total', 
					@Separator = ', '

