				OR (@Flags_ins IS NOT NULL AND @Flags_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'Flags', 
					@Separator = ', '

						IF	(@ModifiedBy_ins <> @ModifiedBy_del)
				OR (@ModifiedBy_ins IS NULL AND @ModifiedBy_del IS NOT NULL)
				OR (@ModifiedBy_ins IS NOT NULL AND @ModifiedBy_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'ModifiedBy', 
					@Separator = ', '

						IF	(@ModifiedDate_ins <> @ModifiedDate_del)
				OR (@ModifiedDate_ins IS NULL AND @ModifiedDate_del IS NOT NULL)
				OR (@ModifiedDate_ins IS NOT NULL AND @ModifiedDate_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'ModifiedDate', 
					@Separator = ', '

					
		IF @HXComments <> 'Changed Fields: '
			INSERT INTO h_ClaimTotal(				
ClaimTotalId,
ClaimId,
PageNumber,
LabCharges,
TotalCharges,
AmountPaid,
BalanceDue,
OutsideLab,
Reserved19,
MedicaidResubmissionCode,
OriginalReferenceNumber,
NumKind,
PriorAuthorizationNumber,
Flags,
ModifiedBy,
ModifiedDate,
ActivityType,
HXComments)					
			SELECT	
					Id,
ClaimId,
PageNumber,
LabCharges,
TotalCharges,
AmountPaid,
BalanceDue,
OutsideLab,
Reserved19,
MedicaidResubmissionCode,
OriginalReferenceNumber,
NumKind,
PriorAuthorizationNumber,
Flags,
ModifiedBy,
ModifiedDate,			
					'UPDATED', 
					@HXComments
			FROM	inserted
			WHERE	[Id] = @Id
			
		FETCH NEXT FROM cur_Update_ClaimTotal INTO @Id
	END

	CLOSE cur_Update_ClaimTotal
	DEALLOCATE cur_Update_ClaimTotal


GO



