		DECLARE @Password_del     nvarchar(50)
		DECLARE @Host_del     nvarchar(100)
		DECLARE @HostPort_del     int
		DECLARE @WorkingDirectory_del     nvarchar(100)
		DECLARE @AcknowledgementRequested_del     bit
		DECLARE @TestMode_del     bit
		DECLARE @ClaimDirectory_del     varchar(100)
		DECLARE @ClaimExtension_del     varchar(10)
		DECLARE @ERAExtension_del     varchar(10)
		DECLARE @AckDirectory_del     varchar(100)
		DECLARE @AckExtension_del     varchar(10)
