		DECLARE @CreatedDate_del     datetime
		DECLARE @ModifiedBy_del     varchar(15)
		DECLARE @ModifiedDate_del     datetime
		DECLARE @FOLDERNAME_del     nvarchar(15) 

		DECLARE @HXComments varchar(800)
		DECLARE @Separator varchar(2)

		DECLARE cur_Update_Clearinghouse CURSOR LOCAL FOR
		SELECT	[Id]
		FROM	inserted

	DECLARE @Id int

	OPEN cur_Update_Clearinghouse
	FETCH NEXT FROM cur_Update_Clearinghouse INTO @Id

	WHILE @@FETCH_STATUS = 0
	BEGIN

		SET @HXComments = 'Changed Fields: '
		SET @Separator = ''

		SELECT	@Id_ins = [Id], 
				@UId_ins = [UId], 
				@PracticeId_ins=[PracticeId],
				@Name_ins=[Name],
