				@ERADirectory_ins=[ERADirectory],
				@TransactionType_ins=[TransactionType],
				@IsActive_ins=[IsActive],
				@CreatedBy_ins=[CreatedBy],
				@CreatedDate_ins=[CreatedDate],
				@ModifiedBy_ins = [ModifiedBy],
				@ModifiedDate_ins = [ModifiedDate],
				@FOLDERNAME_ins=[FOLDERNAME]

		FROM	inserted
		WHERE	[Id] = @Id

		SELECT	@Id_del = [Id], 
				@UId_del = [UId], 
				@PracticeId_del=[PracticeId],
				@Name_del=[Name],
				@SENDER_ID_del=[SENDER_ID],
				@RECVR_ID_del=[RECVR_ID],
				@SENDERCODE_del=[SENDERCODE],
				@RECVRCODE_del=[RECVRCODE],
