			SELECT	@HXComments = @HXComments + @Separator + 'SENDERCODE', 
					@Separator = ', '

		IF	(@RECVRCODE_ins <> @RECVRCODE_del)
				OR (@RECVRCODE_ins IS NULL AND @RECVRCODE_del IS NOT NULL)
				OR (@RECVRCODE_ins IS NOT NULL AND @RECVRCODE_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'RECVRCODE', 
