			SELECT	@HXComments = @HXComments + @Separator + 'DisplayName', 
					@Separator = ', '

					

		IF @HXComments <> 'Changed Fields: '
			INSERT INTO h_DefaultReasonCode(					
DefaultReasonCodeId,
PracticeId,
