			SELECT	@HXComments = @HXComments + @Separator + 'FacililityZip', 
					@Separator = ', '

			IF	(@EraPayment_ins <> @EraPayment_del)
				OR (@EraPayment_ins IS NULL AND @EraPayment_del IS NOT NULL)
				OR (@EraPayment_ins IS NOT NULL AND @EraPayment_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'EraPayment', 
