			IF	(@PaymentCreditDebitFlag_ins <> @PaymentCreditDebitFlag_del)
				OR (@PaymentCreditDebitFlag_ins IS NULL AND @PaymentCreditDebitFlag_del IS NOT NULL)
				OR (@PaymentCreditDebitFlag_ins IS NOT NULL AND @PaymentCreditDebitFlag_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'PaymentCreditDebitFlag', 
					@Separator = ', '

			IF	(@PaymentMethod_ins <> @PaymentMethod_del)
				OR (@PaymentMethod_ins IS NULL AND @PaymentMethod_del IS NOT NULL)
				OR (@PaymentMethod_ins IS NOT NULL AND @PaymentMethod_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'PaymentMethod', 
					@Separator = ', '

			IF	(@PaymentFormat_ins <> @PaymentFormat_del)
				OR (@PaymentFormat_ins IS NULL AND @PaymentFormat_del IS NOT NULL)
				OR (@PaymentFormat_ins IS NOT NULL AND @PaymentFormat_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'PaymentFormat', 
