			SELECT	@HXComments = @HXComments + @Separator + 'CheckNumber', 
					@Separator = ', '
	
	
	IF	(@PaymentEffectiveDate_ins <> @PaymentEffectiveDate_del)
				OR (@PaymentEffectiveDate_ins IS NULL AND @PaymentEffectiveDate_del IS NOT NULL)
				OR (@PaymentEffectiveDate_ins IS NOT NULL AND @PaymentEffectiveDate_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'PaymentEffectiveDate', 
					@Separator = ', '
	
	IF	(@PracticeId_ins <> @PracticeId_del)
				OR (@PracticeId_ins IS NULL AND @PracticeId_del IS NOT NULL)
				OR (@PracticeId_ins IS NOT NULL AND @PracticeId_del IS NULL)
