				OR (@ProiderName_ins IS NOT NULL AND @ProiderName_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'ProiderName', 
					@Separator = ', '


	IF	(@ProiderNPI_ins <> @ProiderNPI_del)
				OR (@ProiderNPI_ins IS NULL AND @ProiderNPI_del IS NOT NULL)
				OR (@ProiderNPI_ins IS NOT NULL AND @ProiderNPI_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'ProiderNPI', 
					@Separator = ', '
					
					IF	(@CreateDate_ins <> @CreateDate_del)
				OR (@CreateDate_ins IS NULL AND @CreateDate_del IS NOT NULL)
				OR (@CreateDate_ins IS NOT NULL AND @CreateDate_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'CreateDate', 
					@Separator = ', '
					
		IF @HXComments <> 'Changed Fields: '
			INSERT INTO H_ERARoot(					
					ERARootId,	
					FileName,			
					InsuranceCompanyName,
					InsuranceCompanyAddress1,
					InsuranceCompanyAddress2,	
					InsuranceCompanyCity,
					InsuranceCompanyState,
					InsuranceCompanyZip,
					FacililityName,
					FacililityAddress2,
					FacililityAddress1,
					FacililityCity,
					FacililityState,
					FacililityZip,
					EraPayment,
					PaymentCreditDebitFlag,
					PaymentMethod,
					PaymentFormat,
					CheckNumber,
					PaymentEffectiveDate,
					PracticeId,
					ProiderName,
					ProiderNPI,
					CreateDate,
					ActivityType,
					HXComments)
			SELECT	
					Id,		
					FileName,			
					InsuranceCompanyName,
					InsuranceCompanyAddress1,
					InsuranceCompanyAddress2,	
					InsuranceCompanyCity,
					InsuranceCompanyState,
					InsuranceCompanyZip,
					FacililityName,
					FacililityAddress2,
					FacililityAddress1,
					FacililityCity,
					FacililityState,
					FacililityZip,
					EraPayment,
					PaymentCreditDebitFlag,
					PaymentMethod,
					PaymentFormat,
					CheckNumber,
					PaymentEffectiveDate,
					PracticeId,
					ProiderName,
					ProiderNPI,
					CreateDate,
					'UPDATED', 
					@HXComments
			FROM	inserted
			WHERE	[Id] = @Id

		FETCH NEXT FROM cur_Update_ERARoot INTO @Id
	END

	CLOSE cur_Update_ERARoot
	DEALLOCATE cur_Update_ERARoot


GO




