CREATE TRIGGER [dbo].[trg_Facility_Update] ON [dbo].[Facility]
AFTER UPDATE
AS
	    DECLARE @Id_ins		smallint
		DECLARE @UId_ins		uniqueidentifier
		DECLARE @PracticeId_ins		int
		DECLARE @Name_ins		varchar(35)
		DECLARE @Address1_ins		varchar(35)
		DECLARE @Address2_ins		varchar(35)
		DECLARE @City_ins		varchar(35)
		DECLARE @State_ins		char(2)
		DECLARE @ZipCode_ins		varchar(10)
		DECLARE @Phone_ins		varchar(25)
		DECLARE @FacilityCode_ins		varchar(5)
		DECLARE @FacilityDescription_ins		varchar(50)
		DECLARE @Fax_ins		varchar(25)
		DECLARE @POSCode_ins		varchar(2)
		DECLARE @LocationCode_ins		varchar(5)
		DECLARE @TimeZone_ins		varchar(100)
		DECLARE @ServiceTypeCode_ins		varchar(2)
		DECLARE @ContactName_ins		varchar(100)
		DECLARE @FacilitySubTypeId_ins		int
		DECLARE @DefaultProviderId_ins		smallint
		DECLARE @IsActive_ins		bit
		DECLARE @CreatedBy_ins		varchar(15)
		DECLARE @CreatedDate_ins		datetime
		DECLARE @ModifiedBy_ins		varchar(15)
		DECLARE @ModifiedDate_ins		datetime
		DECLARE @IsDefault_ins		bit

		DECLARE @Id_del		smallint
		DECLARE @UId_del		uniqueidentifier
		DECLARE @PracticeId_del		int
		DECLARE @Name_del		varchar(35)
		DECLARE @Address1_del		varchar(35)
		DECLARE @Address2_del		varchar(35)
		DECLARE @City_del		varchar(35)
		DECLARE @State_del		char(2)
		DECLARE @ZipCode_del		varchar(10)
		DECLARE @Phone_del		varchar(25)
		DECLARE @FacilityCode_del		varchar(5)
		DECLARE @FacilityDescription_del		varchar(50)
		DECLARE @Fax_del		varchar(25)
		DECLARE @POSCode_del		varchar(2)
		DECLARE @LocationCode_del		varchar(5)
		DECLARE @TimeZone_del		varchar(100)
		DECLARE @ServiceTypeCode_del		varchar(2)
		DECLARE @ContactName_del		varchar(100)
		DECLARE @FacilitySubTypeId_del		int
		DECLARE @DefaultProviderId_del		smallint
		DECLARE @IsActive_del		bit
		DECLARE @CreatedBy_del		varchar(15)
		DECLARE @CreatedDate_del		datetime
		DECLARE @ModifiedBy_del		varchar(15)
		DECLARE @ModifiedDate_del		datetime
		DECLARE @IsDefault_del		bit	 

		DECLARE @HXComments varchar(800)
		DECLARE @Separator varchar(2)

		DECLARE cur_Update_Facility CURSOR LOCAL FOR
		SELECT	[Id]
		FROM	inserted

	DECLARE @Id int

	OPEN cur_Update_Facility
	FETCH NEXT FROM cur_Update_Facility INTO @Id

	WHILE @@FETCH_STATUS = 0
	BEGIN

		SET @HXComments = 'Changed Fields: '
		SET @Separator = ''

		SELECT	@Id_ins = [Id], 
				@UId_ins = [UId], 
				@PracticeId_ins = [PracticeId], 
				@Name_ins = [Name], 
				@Address1_ins = [Address1], 
				@Address2_ins = [Address2]	,
				@City_ins=[City],
				@State_ins = [State],
				@ZipCode_ins=[ZipCode],
				@Phone_ins=[Phone],
				@FacilityCode_ins=[FacilityCode],
				@FacilityDescription_ins=[FacilityDescription],
				@Fax_ins=[Fax],
				@POSCode_ins=[POSCode],
				@LocationCode_ins=[LocationCode],
				@TimeZone_ins=[TimeZone],
				@ServiceTypeCode_ins=[ServiceTypeCode],
				@ContactName_ins=[ContactName],
				@FacilitySubTypeId_ins=[FacilitySubTypeId],
				@DefaultProviderId_ins=[DefaultProviderId],
				@IsActive_ins = [IsActive],
				@CreatedBy_ins = [CreatedBy],
				@CreatedDate_ins = [CreatedDate],
				@ModifiedBy_ins = [ModifiedBy],
				@ModifiedDate_ins = [ModifiedDate],
				@IsDefault_ins=[IsDefault]

		FROM	inserted
		WHERE	[Id] = @Id

		SELECT	@Id_del = [Id], 
				@UId_del = [UId], 
				@PracticeId_del = [PracticeId], 
				@Name_del = [Name], 
				@Address1_del = [Address1], 
				@Address2_del = [Address2]	,
				@City_del=[City],
				@State_del = [State],
				@ZipCode_del=[ZipCode],
				@Phone_del=[Phone],
				@FacilityCode_del=[FacilityCode],
				@FacilityDescription_del=[FacilityDescription],
				@Fax_del=[Fax],
				@POSCode_del=[POSCode],
				@LocationCode_del=[LocationCode],
				@TimeZone_del=[TimeZone],
				@ServiceTypeCode_del=[ServiceTypeCode],
				@ContactName_del=[ContactName],
				@FacilitySubTypeId_del=[FacilitySubTypeId],
				@DefaultProviderId_del=[DefaultProviderId],
				@IsActive_del = [IsActive],
				@CreatedBy_del = [CreatedBy],
				@CreatedDate_del = [CreatedDate],
				@ModifiedBy_del = [ModifiedBy],
				@ModifiedDate_del = [ModifiedDate],
				@IsDefault_del=[IsDefault]
							
		FROM	deleted
		WHERE	[Id] = @Id

		IF	(@Id_ins <> @Id_del)
				OR (@Id_ins IS NULL AND @Id_del IS NOT NULL)
				OR (@Id_ins IS NOT NULL AND @Id_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'Id', 
					@Separator = ', '

		IF	(@UId_ins <> @UId_del)
				OR (@UId_ins IS NULL AND @UId_del IS NOT NULL)
				OR (@UId_ins IS NOT NULL AND @UId_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'UId', 
					@Separator = ', '
					
						IF	(@PracticeId_ins <> @PracticeId_del)
				OR (@PracticeId_ins IS NULL AND @PracticeId_del IS NOT NULL)
				OR (@PracticeId_ins IS NOT NULL AND @PracticeId_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'PracticeId', 
					@Separator = ', '

		IF	( @Name_ins <>  @Name_del)
				OR (@Name_ins IS NULL AND @Name_del IS NOT NULL)
				OR (@Name_ins IS NOT NULL AND @Name_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'Name', 
					@Separator = ', '

		IF	( @Address1_ins <> @Address1_del)
				OR (@Address1_ins IS NULL AND @Address1_del IS NOT NULL)
				OR (@Address1_ins IS NOT NULL AND @Address1_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + '@Address1', 
					@Separator = ', '

		IF	(@Address2_ins <> @Address2_del)
				OR (@Address2_ins IS NULL AND @Address2_del IS NOT NULL)
				OR (@Address2_ins IS NOT NULL AND @Address2_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'Address2', 
					@Separator = ', '

		IF	( @City_ins <> @City_del)
				OR (@City_ins IS NULL AND @City_del IS NOT NULL)
				OR (@City_ins IS NOT NULL AND @City_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + '@City', 
					@Separator = ', '

		IF	( @State_ins <> @State_del)
				OR (@State_ins IS NULL AND @State_del IS NOT NULL)
				OR (@State_ins IS NOT NULL AND @State_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'State', 
					@Separator = ', '

		IF	( @ZipCode_ins <> @ZipCode_del)
				OR (@ZipCode_ins IS NULL AND @ZipCode_del IS NOT NULL)
				OR (@ZipCode_ins IS NOT NULL AND @ZipCode_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'ZipCode', 
					@Separator = ', '

		IF	( @Phone_ins <> @Phone_del)
				OR (@Phone_ins IS NULL AND @Phone_del IS NOT NULL)
				OR (@Phone_ins IS NOT NULL AND @Phone_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'Phone', 
					@Separator = ', '

		IF	( @FacilityCode_ins <> @FacilityCode_del)
				OR (@FacilityCode_ins IS NULL AND @FacilityCode_del IS NOT NULL)
				OR (@FacilityCode_ins IS NOT NULL AND @FacilityCode_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'FacilityCode', 
					@Separator = ', '				
		

		IF	( @FacilityDescription_ins <> @FacilityDescription_del)
				OR (@FacilityDescription_ins IS NULL AND @FacilityDescription_del IS NOT NULL)
				OR (@FacilityDescription_ins IS NOT NULL AND @FacilityDescription_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'FacilityDescription', 
					@Separator = ', '

		IF	( @Fax_ins <> @Fax_del)
				OR (@Fax_ins IS NULL AND @Fax_del IS NOT NULL)
				OR (@Fax_ins IS NOT NULL AND @Fax_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'Fax', 
					@Separator = ', '

       IF	( @POSCode_ins <> @POSCode_del)
				OR (@POSCode_ins IS NULL AND @POSCode_del IS NOT NULL)
				OR (@POSCode_ins IS NOT NULL AND @POSCode_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'POSCode', 
					@Separator = ', '
		IF	( @LocationCode_ins <> @LocationCode_del)
				OR (@LocationCode_ins IS NULL AND @LocationCode_del IS NOT NULL)
				OR (@LocationCode_ins IS NOT NULL AND @LocationCode_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'LocationCode', 
					@Separator = ', '

		IF	(  @TimeZone_ins <> @TimeZone_del)
				OR (@TimeZone_ins IS NULL AND @TimeZone_del IS NOT NULL)
				OR (@TimeZone_ins IS NOT NULL AND @TimeZone_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'TimeZone', 
