		IF	(   @ServiceTypeCode_ins <> @ServiceTypeCode_del)
				OR (@ServiceTypeCode_ins IS NULL AND @ServiceTypeCode_del IS NOT NULL)
				OR (@ServiceTypeCode_ins IS NOT NULL AND @ServiceTypeCode_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'ServiceTypeCode', 
					@Separator = ', '
		IF	(   @ContactName_ins <> @ContactName_del)
				OR (@ContactName_ins IS NULL AND @ContactName_del IS NOT NULL)
				OR (@ContactName_ins IS NOT NULL AND @ContactName_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'ContactName', 
					@Separator = ', '
		IF	(   @FacilitySubTypeId_ins <> @FacilitySubTypeId_del)
				OR (@FacilitySubTypeId_ins IS NULL AND @FacilitySubTypeId_del IS NOT NULL)
				OR (@FacilitySubTypeId_ins IS NOT NULL AND @FacilitySubTypeId_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'FacilitySubTypeId', 
					@Separator = ', '
	    IF	(   @DefaultProviderId_ins <> @DefaultProviderId_del)
				OR (@DefaultProviderId_ins IS NULL AND @DefaultProviderId_del IS NOT NULL)
				OR (@DefaultProviderId_ins IS NOT NULL AND @DefaultProviderId_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'TimeZone', 
					@Separator = ', '

	    IF	(@IsActive_ins <> @IsActive_del)
				OR (@IsActive_ins IS NULL AND @IsActive_del IS NOT NULL)
				OR (@IsActive_ins IS NOT NULL AND @IsActive_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'IsActive', 
					@Separator = ', '

	  IF	(@CreatedBy_ins <> @CreatedBy_del)
				OR (@CreatedBy_ins IS NULL AND @CreatedBy_del IS NOT NULL)
				OR (@CreatedBy_ins IS NOT NULL AND @CreatedBy_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'CreatedBy', 
					@Separator = ', '
	
	  IF	(@CreatedDate_ins <> @CreatedDate_del)
				OR (@CreatedDate_ins IS NULL AND @CreatedDate_del IS NOT NULL)
				OR (@CreatedDate_ins IS NOT NULL AND @CreatedDate_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'CreatedDate', 
					@Separator = ', '


	  IF	(@ModifiedBy_ins <> @ModifiedBy_del)
				OR (@ModifiedBy_ins IS NULL AND @ModifiedBy_del IS NOT NULL)
				OR (@ModifiedBy_ins IS NOT NULL AND @ModifiedBy_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'ModifiedBy', 
					@Separator = ', '


	IF	(@ModifiedDate_ins <> @ModifiedDate_del)
				OR (@ModifiedDate_ins IS NULL AND @ModifiedDate_del IS NOT NULL)
				OR (@ModifiedDate_ins IS NOT NULL AND @ModifiedDate_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'ModifiedDate', 
					@Separator = ', '
    IF	(@IsDefault_ins <> @IsDefault_del)
				OR (@IsDefault_ins IS NULL AND @IsDefault_del IS NOT NULL)
				OR (@IsDefault_ins IS NOT NULL AND @IsDefault_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'IsDefault', 
			        @Separator = ', '
		IF @HXComments <> 'Changed Fields: '
			INSERT INTO H_Facility(	
									FacilityId,
									UId,
									PracticeId,
									Name,
									Address1,
