CREATE TRIGGER [dbo].[trg_FacilityIdentity_Update] ON [dbo].[FacilityIdentity]
AFTER UPDATE
AS
	    DECLARE @Id_ins int
		DECLARE @FacilityId_ins smallint
		DECLARE @UId_ins uniqueidentifier
		DECLARE @TypeId_ins smallint
		DECLARE @Identifier_ins varchar(50)
		DECLARE @ActiveDate_ins datetime
		DECLARE @InactiveDate_ins datetime
		DECLARE @ModifiedBy_ins varchar(15)
		DECLARE @ModifiedDate_ins datetime


		DECLARE @Id_del int
		DECLARE @FacilityId_del smallint
		DECLARE @UId_del uniqueidentifier
		DECLARE @TypeId_del smallint
		DECLARE @Identifier_del varchar(50)
		DECLARE @ActiveDate_del datetime
		DECLARE @InactiveDate_del datetime
		DECLARE @ModifiedBy_del varchar(15)
		DECLARE @ModifiedDate_del datetime

		DECLARE @HXComments varchar(800)
		DECLARE @Separator varchar(2)

		DECLARE cur_Update_FacilityIdentity CURSOR LOCAL FOR
		SELECT	[Id]
		FROM	inserted

	DECLARE @Id int

	OPEN cur_Update_FacilityIdentity
	FETCH NEXT FROM cur_Update_FacilityIdentity INTO @Id

	WHILE @@FETCH_STATUS = 0
	BEGIN

		SET @HXComments = 'Changed Fields: '
		SET @Separator = ''

		SELECT	@Id_ins = [Id], 
				@FacilityId_ins=[FacilityId],
				@UId_ins = [UId], 
				@TypeId_ins=[TypeId],
				@Identifier_ins=[Identifier],
				@ActiveDate_ins=[ActiveDate],
				@InactiveDate_ins=[InactiveDate],
				@ModifiedBy_ins = [ModifiedBy],
				@ModifiedDate_ins = [ModifiedDate]

		FROM	inserted
		WHERE	[Id] = @Id

		SELECT	@Id_del = [Id], 
				@FacilityId_del=[FacilityId],
				@UId_del = [UId], 
				@TypeId_del=[TypeId],
				@Identifier_del=[Identifier],
				@ActiveDate_del=[ActiveDate],
				@InactiveDate_del=[InactiveDate],
				@ModifiedBy_del = [ModifiedBy],
				@ModifiedDate_del = [ModifiedDate]
							
		FROM	deleted
		WHERE	[Id] = @Id

		IF	(@Id_ins <> @Id_del)
				OR (@Id_ins IS NULL AND @Id_del IS NOT NULL)
				OR (@Id_ins IS NOT NULL AND @Id_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'Id', 
					@Separator = ', '

		IF	(@FacilityId_ins <> @FacilityId_del)
				OR (@FacilityId_ins IS NULL AND @FacilityId_del IS NOT NULL)
				OR (@FacilityId_ins IS NOT NULL AND @FacilityId_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'FacilityId', 
					@Separator = ', '

		IF	(@UId_ins <> @UId_del)
				OR (@UId_ins IS NULL AND @UId_del IS NOT NULL)
				OR (@UId_ins IS NOT NULL AND @UId_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'UId', 
					@Separator = ', '				
		

		IF	( @TypeId_ins <>  @TypeId_del)
				OR (@TypeId_ins IS NULL AND @TypeId_del IS NOT NULL)
				OR (@TypeId_ins IS NOT NULL AND @TypeId_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'TypeId', 
					@Separator = ', '

		IF	( @Identifier_ins <> @Identifier_del)
				OR (@Identifier_ins IS NULL AND @Identifier_del IS NOT NULL)
				OR (@Identifier_ins IS NOT NULL AND @Identifier_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'Identifier', 
					@Separator = ', '

		IF	(@ActiveDate_ins <> @ActiveDate_del)
				OR (@ActiveDate_ins IS NULL AND @ActiveDate_del IS NOT NULL)
				OR (@ActiveDate_ins IS NOT NULL AND @ActiveDate_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'ActiveDate', 
					@Separator = ', '

		IF	( @InactiveDate_ins <> @InactiveDate_del)
				OR (@InactiveDate_ins IS NULL AND @InactiveDate_del IS NOT NULL)
				OR (@InactiveDate_ins IS NOT NULL AND @InactiveDate_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'InactiveDate', 
					@Separator = ', '		


	  IF	(@ModifiedBy_ins <> @ModifiedBy_del)
				OR (@ModifiedBy_ins IS NULL AND @ModifiedBy_del IS NOT NULL)
				OR (@ModifiedBy_ins IS NOT NULL AND @ModifiedBy_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'ModifiedBy', 
					@Separator = ', '


	IF	(@ModifiedDate_ins <> @ModifiedDate_del)
				OR (@ModifiedDate_ins IS NULL AND @ModifiedDate_del IS NOT NULL)
				OR (@ModifiedDate_ins IS NOT NULL AND @ModifiedDate_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'ModifiedDate', 
					@Separator = ', '
		IF @HXComments <> 'Changed Fields: '
			INSERT INTO H_FacilityIdentity(	
									FacilityIdentityId,
									UId,
									FacilityId,
									TypeId,
									Identifier,
									ActiveDate,
									InactiveDate,
									ModifiedBy,
									ModifiedDate,
									ActivityType,
									HXComments
)
			SELECT	
									Id,	
									UId,
									FacilityId,
									TypeId,
									Identifier,
									ActiveDate,
									InactiveDate,
									ModifiedBy,
									ModifiedDate,
									'UPDATED', 
									@HXComments
			FROM	inserted
			WHERE	[Id] = @Id

		FETCH NEXT FROM cur_Update_FacilityIdentity INTO @Id
	END

	CLOSE cur_Update_FacilityIdentity
	DEALLOCATE cur_Update_FacilityIdentity


GO



