CREATE TRIGGER [dbo].[trg_FSCharge_Update] ON [dbo].[FSCharge]
AFTER UPDATE
AS

	

	DECLARE @FeeScheduleId_ins  smallint
	DECLARE @CPTCode_ins  varchar
	DECLARE @Modifier_ins  varchar
	DECLARE @FacilityCharge_ins  money
	DECLARE @NonFacilityCharge_ins  money
	DECLARE @CreatedDate_ins  datetime
	DECLARE @CreatedBy_ins  varchar
	DECLARE @ModifiedDate_ins  datetime
	DECLARE @ModifiedBy_ins  varchar
	DECLARE @InsuranceCompayId_ins  int
	DECLARE @ProviderId_ins  int
	DECLARE @CommunityCharge_ins  money
	DECLARE @QualificationId_ins  int
	DECLARE @Modifier2_ins varchar
	DECLARE @Modifier3_ins varchar
	DECLARE @Modifier4_ins varchar

	
	DECLARE @FeeScheduleId_del  smallint
	DECLARE @CPTCode_del  varchar
	DECLARE @Modifier_del  varchar
	DECLARE @FacilityCharge_del  money
	DECLARE @NonFacilityCharge_del  money
	DECLARE @CreatedDate_del  datetime
	DECLARE @CreatedBy_del  varchar
	DECLARE @ModifiedDate_del  datetime
	DECLARE @ModifiedBy_del  varchar
	DECLARE @InsuranceCompayId_del  int
	DECLARE @ProviderId_del  int
	DECLARE @CommunityCharge_del  money
	DECLARE @QualificationId_del  int
	DECLARE @Modifier2_del varchar
	DECLARE @Modifier3_del varchar
	DECLARE @Modifier4_del varchar

	
	DECLARE @HXComments varchar(800)
	DECLARE @Separator varchar(2)

		DECLARE cur_Update_FSCharge CURSOR LOCAL FOR
		SELECT	Id
		FROM	inserted

	DECLARE @Id INT

	OPEN cur_Update_FSCharge
	FETCH NEXT FROM cur_Update_FSCharge INTO @Id

	WHILE @@FETCH_STATUS = 0
	BEGIN

		SET @HXComments = 'Changed Fields: '
		SET @Separator = ''

		SELECT	@FeeScheduleId_ins  =FeeScheduleId,
				@CPTCode_ins  =CPTCode,
				@Modifier_ins  =Modifier,
				@FacilityCharge_ins  =FacilityCharge,
				@NonFacilityCharge_ins  =NonFacilityCharge,
				@CreatedDate_ins  =CreatedDate,
				@CreatedBy_ins  =CreatedBy,
				@ModifiedDate_ins  =ModifiedDate,
				@ModifiedBy_ins  =ModifiedBy,
				@InsuranceCompayId_ins  =InsuranceCompayId,
				@ProviderId_ins  =ProviderId,
				@CommunityCharge_ins  =CommunityCharge,
				@QualificationId_ins  =QualificationId,
				@Modifier2_ins=Modifier2,
				@Modifier3_ins=Modifier3,
				@Modifier4_ins=Modifier4
				
		FROM	inserted
		WHERE	Id = @Id

		SELECT	@FeeScheduleId_del  =FeeScheduleId,
				@CPTCode_del  =CPTCode,
				@Modifier_del  =Modifier,
				@FacilityCharge_del  =FacilityCharge,
				@NonFacilityCharge_del  =NonFacilityCharge,				
				@ModifiedDate_del  =ModifiedDate,
				@ModifiedBy_del  =ModifiedBy,
				@InsuranceCompayId_del  =InsuranceCompayId,
