				@CommunityCharge_del  =CommunityCharge,
				@QualificationId_del  =QualificationId,
				@CreatedDate_del  =CreatedDate,
				@CreatedBy_del =CreatedBy,
				@Modifier2_del=Modifier2,
				@Modifier3_del=Modifier3,
				@Modifier4_del=Modifier4
		FROM	deleted
		WHERE	Id = @Id

		IF	(@FeeScheduleId_ins <> @FeeScheduleId_del)
				OR (@FeeScheduleId_ins IS NULL AND @FeeScheduleId_del IS NOT NULL)
				OR (@FeeScheduleId_ins IS NOT NULL AND @FeeScheduleId_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'FeeScheduleId', 
					@Separator = ', '

		IF	(@CPTCode_ins <> @CPTCode_del)
				OR (@CPTCode_ins IS NULL AND @CPTCode_del IS NOT NULL)
				OR (@CPTCode_ins IS NOT NULL AND @CPTCode_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + '@CPTCode', 
					@Separator = ', '
					
		IF	(@Modifier_ins <> @Modifier_del)
				OR (@Modifier_ins IS NULL AND @Modifier_del is NOT NULL)
				OR (@Modifier_ins IS NOT NULL AND @Modifier_del is NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'Modifier', 
					@Separator = ', '
	
		IF	(@FacilityCharge_ins <> @FacilityCharge_del)
				OR (@FacilityCharge_ins IS NULL AND @FacilityCharge_del IS NOT NULL)
				OR (@FacilityCharge_ins IS NOT NULL AND @FacilityCharge_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'FacilityCharge', 
					@Separator = ', '
					
		
		IF	(@NonFacilityCharge_ins <> @NonFacilityCharge_del)
				OR (@NonFacilityCharge_ins IS NULL AND @NonFacilityCharge_del IS NOT NULL)
				OR (@NonFacilityCharge_ins IS NOT NULL AND @NonFacilityCharge_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'NonFacilityCharge', 
					@Separator = ', '

			

			IF	(@InsuranceCompayId_ins <> @InsuranceCompayId_del)
				OR (@InsuranceCompayId_ins IS NULL AND @InsuranceCompayId_del IS NOT NULL)
				OR (@InsuranceCompayId_ins IS NOT NULL AND @InsuranceCompayId_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'InsuranceCompayId', 
					@Separator = ', '

			IF	(@ProviderId_ins <> @ProviderId_del)
				OR (@ProviderId_ins IS NULL AND @ProviderId_del IS NOT NULL)
				OR (@ProviderId_ins IS NOT NULL AND @ProviderId_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'ProviderId', 
					@Separator = ', '
			
			IF	(@CreatedBy_ins <> @CreatedBy_del)
						OR (@CreatedBy_ins IS NULL AND @CreatedBy_del IS NOT NULL)
						OR (@CreatedBy_ins IS NOT NULL AND @CreatedBy_del IS NULL)
					SELECT	@HXComments = @HXComments + @Separator + 'CreatedBy', 
							@Separator = ', '
	
			IF	(@CreatedDate_ins <> @CreatedDate_del)
