						OR (@CreatedDate_ins IS NOT NULL AND @CreatedDate_del IS NULL)
					SELECT	@HXComments = @HXComments + @Separator + 'CreatedDate', 
							@Separator = ', '


			IF	(@ModifiedBy_ins <> @ModifiedBy_del)
						OR (@ModifiedBy_ins IS NULL AND @ModifiedBy_del IS NOT NULL)
						OR (@ModifiedBy_ins IS NOT NULL AND @ModifiedBy_del IS NULL)
					SELECT	@HXComments = @HXComments + @Separator + 'ModifiedBy', 
							@Separator = ', '


			IF	(@ModifiedDate_ins <> @ModifiedDate_del)
						OR (@ModifiedDate_ins IS NULL AND @ModifiedDate_del IS NOT NULL)
						OR (@ModifiedDate_ins IS NOT NULL AND @ModifiedDate_del IS NULL)
					SELECT	@HXComments = @HXComments + @Separator + 'ModifiedDate', 
							@Separator = ', '

			
			IF	(@CommunityCharge_ins <> @CommunityCharge_del)
						OR (@CommunityCharge_ins IS NULL AND @CommunityCharge_del IS NOT NULL)
						OR (@CommunityCharge_ins IS NOT NULL AND @CommunityCharge_del IS NULL)
					SELECT	@HXComments = @HXComments + @Separator + 'CommunityCharge', 
							@Separator = ', '

			IF	(@QualificationId_ins <> @QualificationId_del)
						OR (@QualificationId_ins IS NULL AND @QualificationId_del IS NOT NULL)
						OR (@QualificationId_ins IS NOT NULL AND @QualificationId_del IS NULL)
					SELECT	@HXComments = @HXComments + @Separator + 'QualificationId', 
							@Separator = ', '
		
			IF	(@Modifier2_ins <> @Modifier2_del)
