						OR (@Modifier3_ins IS NULL AND @Modifier3_del IS NOT NULL)
						OR (@Modifier3_ins IS NOT NULL AND @Modifier3_del IS NULL)
					SELECT	@HXComments = @HXComments + @Separator + 'Modifier3', 
