						OR (@Modifier4_ins IS NOT NULL AND @Modifier4_del IS NULL)
					SELECT	@HXComments = @HXComments + @Separator + 'Modifier4', 
							@Separator = ', '
							

					
		IF @HXComments <> 'Changed Fields: '
			INSERT INTO H_FSCharge(														
	FSChargeId,
	FeeScheduleId,
	CPTCode,
	Modifier,
	FacilityCharge,
	NonFacilityCharge,
	InsuranceCompayId,
ProviderId,
CommunityCharge,
QualificationId,
	CreatedBy,
	CreatedDate,
	ModifiedBy,
	ModifiedDate,
	Modifier2,
Modifier3,
Modifier4,
	ActivityType,
	HXComments	
)
			SELECT	
	Id,
	FeeScheduleId,
	CPTCode,
	Modifier,
	FacilityCharge,
	NonFacilityCharge,
	InsuranceCompayId,
ProviderId,
CommunityCharge,
QualificationId,CreatedBy,
	CreatedDate,
	ModifiedBy,
	ModifiedDate,
	Modifier2,
Modifier3,
Modifier4,
						'UPDATED', 
					@HXComments
			FROM	inserted
			WHERE	Id = @Id

		FETCH NEXT FROM cur_Update_FSCharge INTO @Id
	END

	CLOSE cur_Update_FSCharge
	DEALLOCATE cur_Update_FSCharge
	


GO



