CREATE TRIGGER [dbo].[trg_ICDCode_Update] ON [dbo].[ICDCode]
AFTER UPDATE
AS

DECLARE @ID_ins	int
DECLARE @UId_ins	uniqueidentifier
DECLARE @PracticeId_ins	int
DECLARE @VisitType_ins	tinyint
DECLARE @Code_ins	varchar(10)
DECLARE @Description_ins	varchar(255)
DECLARE @DefaultPlan_ins	varchar(5000)
DECLARE @Common_ins	bit
DECLARE @SNOMEDCT_ins	varchar(20)
DECLARE @CodeSystem_ins	varchar(10)
DECLARE @ICD_10Code_ins	varchar(8)
DECLARE @SendToBilling_ins	bit
DECLARE @ShowInActiveProblems_ins	bit
DECLARE @IsActive_ins	bit
DECLARE @CreatedBy_ins	varchar(15)
DECLARE @CreatedDate_ins	datetime
DECLARE @ModifiedBy_ins	varchar(15)
DECLARE @ModifiedDate_ins	datetime

DECLARE @ID_del	int
DECLARE @UId_del	uniqueidentifier
DECLARE @PracticeId_del	int
DECLARE @VisitType_del	tinyint
DECLARE @Code_del	varchar(10)
DECLARE @Description_del	varchar(255)
DECLARE @DefaultPlan_del	varchar(5000)
DECLARE @Common_del	bit
DECLARE @SNOMEDCT_del	varchar(20)
DECLARE @CodeSystem_del	varchar(10)
DECLARE @ICD_10Code_del	varchar(8)
DECLARE @SendToBilling_del	bit
DECLARE @ShowInActiveProblems_del	bit
DECLARE @IsActive_del	bit
DECLARE @CreatedBy_del	varchar(15)
DECLARE @CreatedDate_del	datetime
DECLARE @ModifiedBy_del	varchar(15)
DECLARE @ModifiedDate_del	datetime

	DECLARE @HXComments varchar(800)
	DECLARE @Separator varchar(2)

	DECLARE cur_Update_ICDCode CURSOR LOCAL FOR
	SELECT	[ID]
	FROM	inserted

	DECLARE @ID int

	OPEN cur_Update_ICDCode
	FETCH NEXT FROM cur_Update_ICDCode INTO @ID

	WHILE @@FETCH_STATUS = 0
	BEGIN

		SET @HXComments = 'Changed Fields: '
		SET @Separator = ''

		SELECT	@ID_ins = [ID],
				@UId_ins =  [UId],
				@PracticeId_ins =  [PracticeId],
				@VisitType_ins =  [VisitType],
				@Code_ins =  [Code],
				@Description_ins =  [Description],
				@DefaultPlan_ins =  [DefaultPlan],
				@Common_ins =  [Common],
				@SNOMEDCT_ins =  [SNOMEDCT],
				@CodeSystem_ins =  [CodeSystem],
				@ICD_10Code_ins =  [ICD_10Code],
				@SendToBilling_ins =  [SendToBilling],
				@ShowInActiveProblems_ins =  [ShowInActiveProblems],
				@IsActive_ins =  [IsActive],
				@CreatedBy_ins =  [CreatedBy],
				@CreatedDate_ins =  [CreatedDate],
				@ModifiedBy_ins =  [ModifiedBy],
				@ModifiedDate_ins =  [ModifiedDate]

		FROM	inserted
		WHERE	[ID] = @ID

		SELECT	@ID_del = [ID],
				@UId_del =  [UId],
				@PracticeId_del =  [PracticeId],
				@VisitType_del =  [VisitType],
				@Code_del =  [Code],
				@Description_del =  [Description],
				@DefaultPlan_del =  [DefaultPlan],
				@Common_del =  [Common],
				@SNOMEDCT_del =  [SNOMEDCT],
				@CodeSystem_del =  [CodeSystem],
				@ICD_10Code_del =  [ICD_10Code],
				@SendToBilling_del =  [SendToBilling],
				@ShowInActiveProblems_del =  [ShowInActiveProblems],
				@IsActive_del =  [IsActive],
				@CreatedBy_del =  [CreatedBy],
				@CreatedDate_del =  [CreatedDate],
				@ModifiedBy_del =  [ModifiedBy],
				@ModifiedDate_del =  [ModifiedDate]
							
		FROM	deleted
		WHERE	[ID] = @ID

		IF	(@ID_ins <> @ID_del)
				OR (@ID_ins IS NULL AND @ID_del IS NOT NULL)
				OR (@ID_ins IS NOT NULL AND @ID_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'ID', 
					@Separator = ', '

		IF	(@UId_ins <> @UId_del)
				OR (@UId_ins IS NULL AND @UId_del IS NOT NULL)
				OR (@UId_ins IS NOT NULL AND @UId_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'UId', 
					@Separator = ', '
					
						IF	(@PracticeId_ins <> @PracticeId_del)
				OR (@PracticeId_ins IS NULL AND @PracticeId_del IS NOT NULL)
				OR (@PracticeId_ins IS NOT NULL AND @PracticeId_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'PracticeId', 
					@Separator = ', '

		IF	(@VisitType_ins <> @VisitType_del)
				OR (@VisitType_ins IS NULL AND @VisitType_del IS NOT NULL)
				OR (@VisitType_ins IS NOT NULL AND @VisitType_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'VisitType', 
					@Separator = ', '

		IF	(@Code_ins <> @Code_del)
				OR (@Code_ins IS NULL AND @Code_del IS NOT NULL)
				OR (@Code_ins IS NOT NULL AND @Code_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'Code', 
					@Separator = ', '

		IF	(@Description_ins <> @Description_del)
				OR (@Description_ins IS NULL AND @Description_del IS NOT NULL)
				OR (@Description_ins IS NOT NULL AND @Description_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'Description', 
					@Separator = ', '

		IF	(@DefaultPlan_ins <> @DefaultPlan_del)
				OR (@DefaultPlan_ins IS NULL AND @DefaultPlan_del IS NOT NULL)
				OR (@DefaultPlan_ins IS NOT NULL AND @DefaultPlan_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'DefaultPlan', 
					@Separator = ', '
					
		IF	(@Common_ins <> @Common_del)
				OR (@Common_ins IS NULL AND @Common_del IS NOT NULL)
				OR (@Common_ins IS NOT NULL AND @Common_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'Common', 
					@Separator = ', '

		IF	(@SNOMEDCT_ins <> @SNOMEDCT_del)
				OR (@SNOMEDCT_ins IS NULL AND @SNOMEDCT_del IS NOT NULL)
				OR (@SNOMEDCT_ins IS NOT NULL AND @SNOMEDCT_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'SNOMEDCT', 
					@Separator = ', '

		IF	(@CodeSystem_ins <> @CodeSystem_del)
				OR (@CodeSystem_ins IS NULL AND @CodeSystem_del IS NOT NULL)
				OR (@CodeSystem_ins IS NOT NULL AND @CodeSystem_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'CodeSystem', 
					@Separator = ', '

IF	(@ICD_10Code_ins <> @ICD_10Code_del)
				OR (@ICD_10Code_ins IS NULL AND @ICD_10Code_del IS NOT NULL)
				OR (@ICD_10Code_ins IS NOT NULL AND @ICD_10Code_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'ICD_10Code', 
					@Separator = ', '

IF	(@SendToBilling_ins <> @SendToBilling_del)
				OR (@SendToBilling_ins IS NULL AND @SendToBilling_del IS NOT NULL)
				OR (@SendToBilling_ins IS NOT NULL AND @SendToBilling_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'SendToBilling', 
					@Separator = ', '

IF	(@ShowInActiveProblems_ins <> @ShowInActiveProblems_del)
				OR (@ShowInActiveProblems_ins IS NULL AND @ShowInActiveProblems_del IS NOT NULL)
				OR (@ShowInActiveProblems_ins IS NOT NULL AND @ShowInActiveProblems_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'ShowInActiveProblems', 
					@Separator = ', '

IF	(@IsActive_ins <> @IsActive_del)
				OR (@IsActive_ins IS NULL AND @IsActive_del IS NOT NULL)
				OR (@IsActive_ins IS NOT NULL AND @IsActive_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'IsActive', 
					@Separator = ', ' 

IF	(@CreatedBy_ins <> @CreatedBy_del)
				OR (@CreatedBy_ins IS NULL AND @CreatedBy_del IS NOT NULL)
				OR (@CreatedBy_ins IS NOT NULL AND @CreatedBy_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'CreatedBy', 
					@Separator = ', '

IF	(@CreatedDate_ins <> @CreatedDate_del)
				OR (@CreatedDate_ins IS NULL AND @CreatedDate_del IS NOT NULL)
				OR (@CreatedDate_ins IS NOT NULL AND @CreatedDate_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'CreatedDate', 
					@Separator = ', '

IF	(@ModifiedBy_ins <> @ModifiedBy_del)
				OR (@ModifiedBy_ins IS NULL AND @ModifiedBy_del IS NOT NULL)
				OR (@ModifiedBy_ins IS NOT NULL AND @ModifiedBy_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'ModifiedBy', 
					@Separator = ', '

IF	(@ModifiedDate_ins <> @ModifiedDate_del)
				OR (@ModifiedDate_ins IS NULL AND @ModifiedDate_del IS NOT NULL)
				OR (@ModifiedDate_ins IS NOT NULL AND @ModifiedDate_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'ModifiedDate', 
					@Separator = ', '

		IF @HXComments <> 'Changed Fields: '
			INSERT INTO H_ICDCode(					
					ICDCodeId,
					UId,
					PracticeId,
					VisitType,
					Code,
					Description,
					DefaultPlan,
					Common,
					SNOMEDCT,
					CodeSystem,
					ICD_10Code,
					SendToBilling,
					ShowInActiveProblems,
					IsActive,
					CreatedBy,
					CreatedDate,
					ModifiedBy,
					ModifiedDate,
					ActivityType,
					HXComments)
			SELECT	
					ID,	
					UId,
					PracticeId,
					VisitType,
					Code,
					Description,
					DefaultPlan,
					Common,
					SNOMEDCT,
					CodeSystem,
					ICD_10Code,
					SendToBilling,
					ShowInActiveProblems,
					IsActive,
					CreatedBy,
					CreatedDate,
					ModifiedBy,
					ModifiedDate,
					'UPDATED', 
					@HXComments
			FROM	inserted
			WHERE	[ID] = @ID

		FETCH NEXT FROM cur_Update_ICDCode INTO @ID
	END

	CLOSE cur_Update_ICDCode
	DEALLOCATE cur_Update_ICDCode


GO



