	FETCH NEXT FROM cur_Update_InsuranceGuarantor INTO @Id

	WHILE @@FETCH_STATUS = 0
	BEGIN

		SET @HXComments = 'Changed Fields: '
		SET @Separator = ''

		SELECT
 @PatientID_ins	=	 PatientID	,
 @GuarantorNumber_ins	=	 GuarantorNumber	,
