CREATE TRIGGER [dbo].[trg_InvDiagnosis_Update] ON [dbo].[InvDiagnosis]
AFTER UPDATE
AS
	DECLARE @Id_ins int
	DECLARE @InvoiceId_ins int
	DECLARE @ICDCode_ins varchar(10)
	DECLARE @Description_ins varchar(255)
	DECLARE @IsICD10_ins bit

	DECLARE @Id_del int
	DECLARE @InvoiceId_del int
	DECLARE @ICDCode_del varchar(10)
	DECLARE @Description_del varchar(255)
	DECLARE @IsICD10_del bit

	DECLARE @HXComments varchar(800)
	DECLARE @Separator varchar(2)

		DECLARE cur_Update_InvDiagnosis CURSOR LOCAL FOR
		SELECT	[Id]
		FROM	inserted

	DECLARE @Id int

	OPEN cur_Update_InvDiagnosis
	FETCH NEXT FROM cur_Update_InvDiagnosis INTO @Id

	WHILE @@FETCH_STATUS = 0
	BEGIN

		SET @HXComments = 'Changed Fields: '
		SET @Separator = ''

		SELECT	@Id_ins = [Id], 
				@InvoiceId_ins = [InvoiceId], 
				@ICDCode_ins = [ICDCode], 
				@Description_ins = [Description], 
				@IsICD10_ins = [IsICD10]				
		FROM	inserted
		WHERE	[Id] = @Id

		SELECT	@Id_del = [Id], 
				@InvoiceId_del = [InvoiceId], 
				@ICDCode_del = [ICDCode], 
				@Description_del = [Description], 
				@IsICD10_del = [IsICD10]				
		FROM	deleted
		WHERE	[Id] = @Id

		IF	(@Id_ins <> @Id_del)
				OR (@Id_ins IS NULL AND @Id_del IS NOT NULL)
				OR (@Id_ins IS NOT NULL AND @Id_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'Id', 
					@Separator = ', '

		IF	(@InvoiceId_ins <> @InvoiceId_del)
				OR (@InvoiceId_ins IS NULL AND @InvoiceId_del IS NOT NULL)
				OR (@InvoiceId_ins IS NOT NULL AND @InvoiceId_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'InvocieId', 
					@Separator = ', '

		IF	(@ICDCode_ins <> @ICDCode_del)
				OR (@ICDCode_ins IS NULL AND @ICDCode_del IS NOT NULL)
				OR (@ICDCode_ins IS NOT NULL AND @ICDCode_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'ICDCode', 
					@Separator = ', '

		IF	(@Description_ins <> @Description_del)
				OR (@Description_ins IS NULL AND @Description_del IS NOT NULL)
				OR (@Description_ins IS NOT NULL AND @Description_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'Description', 
					@Separator = ', '

		IF	(@IsICD10_ins <> @IsICD10_del)
				OR (@IsICD10_ins IS NULL AND @IsICD10_del IS NOT NULL)
				OR (@IsICD10_ins IS NOT NULL AND @IsICD10_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'IsICD10', 
					@Separator = ', '

		

		IF @HXComments <> 'Changed Fields: '
			INSERT INTO h_InvDiagnosis(					
					InvDiagnosisId,
					InvoiceId,
					ICDCode,
					[Description],
					IsICD10,
					ActivityType,
					HXComments)
			SELECT	
					Id,					
					InvoiceId,
					ICDCode,
					[Description],
					IsICD10,										
					'UPDATED', 
					@HXComments
			FROM	inserted
			WHERE	[Id] = @Id

		FETCH NEXT FROM cur_Update_InvDiagnosis INTO @Id
	END

	CLOSE cur_Update_InvDiagnosis
	DEALLOCATE cur_Update_InvDiagnosis


GO



