CREATE TRIGGER [dbo].[trg_PatientAuthorizationNumber_Update] ON [dbo].[PatientAuthorizationNumber]
AFTER UPDATE
AS

	DECLARE @Id_ins INT
	DECLARE @UId_ins uniqueidentifier
	DECLARE @InsurancePolicyId_ins BIGINT
	DECLARE @AuthorizationNumber_ins	VARCHAR(50)
	DECLARE @EffectiveDate_ins DATE
	DECLARE @ExpirationDate_ins DATE
	DECLARE @CreatedBy_ins VARCHAR(15)
	DECLARE @CreatedDate_ins DATE
	DECLARE @ModifiedBy_ins VARCHAR(15)
	DECLARE @ModifiedDate_ins DATE
	
	DECLARE @IsNotiFyToEMRTemp BIT

	DECLARE @Id_del INT
	DECLARE @UId_del uniqueidentifier
	DECLARE @InsurancePolicyId_del BIGINT
	DECLARE @AuthorizationNumber_del	VARCHAR(50)
	DECLARE @EffectiveDate_del DATE
	DECLARE @ExpirationDate_del DATE
	DECLARE @CreatedBy_del VARCHAR(15)
	DECLARE @CreatedDate_del DATE
	DECLARE @ModifiedBy_del VARCHAR(15)
	DECLARE @ModifiedDate_del DATE

	DECLARE @HXComments varchar(800)
	DECLARE @Separator varchar(2)

		DECLARE cur_Update_PatientAuthorizationNumber CURSOR LOCAL FOR
		SELECT	[Id]
		FROM	inserted

	DECLARE @Id int

	OPEN cur_Update_PatientAuthorizationNumber
	FETCH NEXT FROM cur_Update_PatientAuthorizationNumber INTO @Id

	WHILE @@FETCH_STATUS = 0
	BEGIN

		SET @HXComments = 'Changed Fields: '
		SET @Separator = ''

		SELECT	@Id_ins=Id,
				@UId_ins=UId,
				@InsurancePolicyId_ins=InsurancePolicyId,
				@AuthorizationNumber_ins=AuthorizationNumber,
				@EffectiveDate_ins=EffectiveDate,
				@ExpirationDate_ins=ExpirationDate,
				@CreatedBy_ins=CreatedBy,
				@CreatedDate_ins=CreatedDate,
				@ModifiedBy_ins=ModifiedBy,
				@ModifiedDate_ins=ModifiedDate
		FROM	inserted
		WHERE	[Id] = @Id

		SELECT	@Id_del=Id,
				@UId_del=UId,
				@InsurancePolicyId_del=InsurancePolicyId,
				@AuthorizationNumber_del=AuthorizationNumber,
				@EffectiveDate_del=EffectiveDate,
				@ExpirationDate_del=ExpirationDate,
				@CreatedBy_del=CreatedBy,
				@CreatedDate_del=CreatedDate,
				@ModifiedBy_del=ModifiedBy,
				@ModifiedDate_del=ModifiedDate
		FROM	deleted
		WHERE	[Id] = @Id

		IF	(@AuthorizationNumber_del <> @AuthorizationNumber_ins)				
		BEGIN
			SET @IsNotiFyToEMRTemp=1
			SELECT	@HXComments = @HXComments + @Separator + 'AuthorizationNumber', 
					@Separator = ', '
		END
			

		IF	(@EffectiveDate_del <> @EffectiveDate_ins)				
		BEGIN
			SET @IsNotiFyToEMRTemp=1
			SELECT	@HXComments = @HXComments + @Separator + 'EffectiveDate', 
					@Separator = ', '
		END
			

		IF	(@ExpirationDate_del <> @ExpirationDate_ins)
		BEGIN
			SET @IsNotiFyToEMRTemp=1
			SELECT	@HXComments = @HXComments + @Separator + 'ExpirationDate', 
					@Separator = ', '
		END
			


		

	IF @IsNotiFyToEMRTemp=1
	BEGIN
		UPDATE InsurancePolicy SET IsNotifyToEMR=0 WHERE Id=@InsurancePolicyId_ins
	END


		IF @HXComments <> 'Changed Fields: '
			INSERT INTO H_PatientAuthorizationNumber(PatientAuthorizationNumberId,UId,InsurancePolicyId,AuthorizationNumber,EffectiveDate,ExpirationDate,
								CreatedBy,CreatedDate,ModifiedBy,ModifiedDate,Activitytype,HXComments					
					)
			SELECT	
					Id,	
					UId,InsurancePolicyId,AuthorizationNumber,EffectiveDate,ExpirationDate,CreatedBy,CreatedDate,ModifiedBy,ModifiedDate,
					'UPDATED', 
					@HXComments
			FROM	inserted
			WHERE	[Id] = @Id

		FETCH NEXT FROM cur_Update_PatientAuthorizationNumber INTO @Id
	END

	CLOSE cur_Update_PatientAuthorizationNumber
	DEALLOCATE cur_Update_PatientAuthorizationNumber


GO


