	DECLARE   @ModifiedDate_del date

	DECLARE @HXComments varchar(800)
	DECLARE @Separator varchar(2)

		DECLARE cur_Update_PaymentAdjustment CURSOR LOCAL FOR
		SELECT	[Id]
		FROM	inserted

	DECLARE @Id int

	OPEN cur_Update_PaymentAdjustment
	FETCH NEXT FROM cur_Update_PaymentAdjustment INTO @Id

	WHILE @@FETCH_STATUS = 0
	BEGIN

		SET @HXComments = 'Changed Fields: '
		SET @Separator = ''

		SELECT @Id_ins =[Id],
			   @UId_ins =[UId],
			   @PaymentChargeId_ins =[PaymentChargeId],
			   @ReasonCode_ins =[ReasonCode],
			   @Amount_ins =[Amount],
			   @IsAccounted_ins =[IsAccounted],
			   @CreatedBy_ins =[CreatedBy],
			   @CreatedDate_ins =[CreatedDate],
			   @ModifiedBy_ins=[ModifiedBy],
			   @ModifiedDate_ins =[ModifiedDate]

		FROM	inserted
		WHERE	[Id] = @Id

		SELECT	@Id_del =[Id],
			    @UId_del =[UId],
			    @PaymentChargeId_del =[PaymentChargeId],
			    @ReasonCode_del =[ReasonCode],
			    @Amount_del =[Amount],
			    @IsAccounted_del =[IsAccounted],
			    @CreatedBy_del =[CreatedBy],
			    @CreatedDate_del =[CreatedDate],
			    @ModifiedBy_del=[ModifiedBy],
			    @ModifiedDate_del =[ModifiedDate]
							
		FROM	deleted
		WHERE	[Id] = @Id

		IF	(@Id_ins <> @Id_del)
				OR (@Id_ins IS NULL AND @Id_del IS NOT NULL)
				OR (@Id_ins IS NOT NULL AND @Id_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'Id', 
					@Separator = ', '

		IF	(@UId_ins <> @UId_del)
