			SELECT	@HXComments = @HXComments + @Separator + 'ModifiedDate', 
					@Separator = ', '	

		IF @HXComments <> 'Changed Fields: '
			INSERT INTO H_PaymentAdjustment(					
					PaymentAdjustmentId,
					UId,
					PaymentChargeId,
					ReasonCode,
					Amount,
