			    @PaymentChargeId_del =[PaymentChargeId],
			    @RemarkCode_del =[RemarkCode],
			    @CreatedDate_del =[CreatedDate],
			    @CreatedBy_del =[CreatedBy]
							
		FROM	deleted
		WHERE	[Id] = @Id

		IF	(@Id_ins <> @Id_del)
				OR (@Id_ins IS NULL AND @Id_del IS NOT NULL)
				OR (@Id_ins IS NOT NULL AND @Id_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'Id', 
					@Separator = ', '

		IF	(@PaymentChargeId_ins <> @PaymentChargeId_del)
				OR (@PaymentChargeId_ins IS NULL AND @PaymentChargeId_del IS NOT NULL)
				OR (@PaymentChargeId_ins IS NOT NULL AND @PaymentChargeId_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'PaymentChargeId', 
					@Separator = ', '
					
		IF	(@RemarkCode_ins <> @RemarkCode_del)
				OR (@RemarkCode_ins IS NULL AND @RemarkCode_del IS NOT NULL)
				OR (@RemarkCode_ins IS NOT NULL AND @RemarkCode_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'RemarkCode', 
					@Separator = ', '				
		

	IF	(@CreatedBy_ins <> @CreatedBy_del)
				OR (@CreatedBy_ins IS NULL AND @CreatedBy_del IS NOT NULL)
				OR (@CreatedBy_ins IS NOT NULL AND @CreatedBy_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'CreatedBy', 
					@Separator = ', '
	
	IF	(@CreatedDate_ins <> @CreatedDate_del)
				OR (@CreatedDate_ins IS NULL AND @CreatedDate_del IS NOT NULL)
				OR (@CreatedDate_ins IS NOT NULL AND @CreatedDate_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'CreatedDate', 
					@Separator = ', '	

		IF @HXComments <> 'Changed Fields: '
			INSERT INTO H_PaymentRemarkCode(					
					PaymentRemarkCodeId,
					PaymentChargeId,
					RemarkCode,
					CreatedBy,
					CreatedDate,
					ActivityType,
					HXComments)
			SELECT	
					Id,
					PaymentChargeId,
					RemarkCode,
					CreatedBy,
					CreatedDate,
					'UPDATED', 
					@HXComments
			FROM	inserted
			WHERE	[Id] = @Id

		FETCH NEXT FROM cur_Update_PaymentRemarkCode INTO @Id
	END

	CLOSE cur_Update_PaymentRemarkCode
	DEALLOCATE cur_Update_PaymentRemarkCode


GO

