CREATE TRIGGER [dbo].[trg_Provider_Update] ON [dbo].[Provider]
AFTER UPDATE
AS
	DECLARE @Id_ins int
	DECLARE @UId_ins uniqueidentifier
	DECLARE @PracticeId_ins int
	DECLARE @LastName_ins varchar(30)
	DECLARE @FirstName_ins varchar(30)
	DECLARE @Middle_ins varchar(30)
	DECLARE @Suffix_ins varchar(10)
	DECLARE @PUserId_ins smallint
	DECLARE @Prefix_ins  varchar(10)
	DECLARE @FacilityId_ins smallint
	DECLARE @IsActive_ins bit
	DECLARE @License_ins varchar(35)
	DECLARE @TOC_ins bit
	DECLARE @Slot_ins int
	DECLARE @SSN_ins varchar(11)
	DECLARE @SpecialtyId_ins smallint
	DECLARE @Specialty_ins varchar(15)
	DECLARE @BillUnderGroupNPI_ins bit
	DECLARE @Signature_ins varchar(5)
	DECLARE @CreatedBy_ins varchar(15)
	DECLARE @CreatedDate_ins datetime
	DECLARE @ModifiedBy_ins varchar(50)
	DECLARE @ModifiedDate_ins datetime
	DECLARE @IsDefault_ins bit
	
	DECLARE @Id_del int
	DECLARE @UId_del uniqueidentifier
	DECLARE @PracticeId_del int	
	DECLARE @LastName_del varchar(30)
	DECLARE @FirstName_del varchar(30)
	DECLARE @Middle_del varchar(30)
	DECLARE @Suffix_del varchar(10)
	DECLARE @PUserId_del smallint
	DECLARE @Prefix_del varchar(10)
	DECLARE @FacilityId_del smallint
	DECLARE @IsActive_del bit
	DECLARE @License_del varchar(35)
	DECLARE @TOC_del bit
	DECLARE @Slot_del int
	DECLARE @SSN_del varchar(11)
	DECLARE @SpecialtyId_del smallint
	DECLARE @Specialty_del varchar(15)
	DECLARE @BillUnderGroupNPI_del bit	
