	DECLARE @CreatedBy_del varchar(15)
	DECLARE @CreatedDate_del datetime
	DECLARE @ModifiedBy_del varchar(50)
	DECLARE @ModifiedDate_del datetime
	DECLARE @IsDefault_del bit
	
	DECLARE @HXComments varchar(800)
	DECLARE @Separator varchar(2)

		DECLARE cur_Update_Provider CURSOR LOCAL FOR
		SELECT	[Id]
		FROM	inserted

	DECLARE @Id int

	OPEN cur_Update_Provider
	FETCH NEXT FROM cur_Update_Provider INTO @Id

	WHILE @@FETCH_STATUS = 0
	BEGIN

		SET @HXComments = 'Changed Fields: '
		SET @Separator = ''

		SELECT	@Id_ins = [Id],  
				@UId_ins = [UId], 
				@PracticeId_ins = [PracticeId], 
				@LastName_ins = [LastName],
				@FirstName_ins = [FirstName], 
