				@SSN_ins = [SSN],
				@SpecialtyId_ins = [SpecialtyId],
				@Specialty_ins = [Specialty],
				@BillUnderGroupNPI_ins = [BillUnderGroupNPI],
				@Signature_ins = null,
				@CreatedBy_ins = [CreatedBy],
				@CreatedDate_ins = [CreatedDate],
				@ModifiedBy_ins = [ModifiedBy],
				@ModifiedDate_ins = [ModifiedDate],
				@IsDefault_ins = [IsDefault]
				
		FROM	inserted
		WHERE	[Id] = @Id

		SELECT	@Id_del = [Id], 
				@UId_del = [UId], 
				@PracticeId_del = [PracticeId], 
				@LastName_del = [LastName],
				@FirstName_del = [FirstName], 
				@Middle_del = [Middle],
				@Suffix_del = [Suffix],
				@PUserId_del = [PUserId],
				@Prefix_del = [Prefix],
				@FacilityId_del = [FacilityId],
				@IsActive_del = [IsActive],
				@License_del = [License],
				@TOC_del = [TOC],
				@Slot_del = [Slot],
				@SSN_del = [SSN],
				@SpecialtyId_del = [SpecialtyId],
				@Specialty_del = [Specialty],
				@BillUnderGroupNPI_del = [BillUnderGroupNPI],
				@Signature_del = null,
				@CreatedBy_del = [CreatedBy],
				@CreatedDate_del = [CreatedDate],
				@ModifiedBy_del = [ModifiedBy],
				@ModifiedDate_del = [ModifiedDate],
				@IsDefault_del = [IsDefault]
				
							
		FROM	deleted
		WHERE	[Id] = @Id

		IF	(@Id_ins <> @Id_del)
				OR (@Id_ins IS NULL AND @Id_del IS NOT NULL)
				OR (@Id_ins IS NOT NULL AND @Id_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'Id', 
					@Separator = ', '

		IF	(@UId_ins <> @UId_del)
