					@Separator = ', '
					
		IF	(@PracticeId_ins <> @PracticeId_del)
				OR (@PracticeId_ins IS NULL AND @PracticeId_del IS NOT NULL)
				OR (@PracticeId_ins IS NOT NULL AND @PracticeId_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'PracticeId', 
					@Separator = ', '
	
		IF	(@LastName_ins <> @LastName_del)
				OR (@LastName_ins IS NULL AND @LastName_del IS NOT NULL)
				OR (@LastName_ins IS NOT NULL AND @LastName_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'LastName', 
					@Separator = ', '
					
		
		IF	(@FirstName_ins <> @FirstName_del)
