				OR (@Middle_ins IS NOT NULL AND @Middle_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'Middle', 
					@Separator = ', '

			IF	(@Suffix_ins <> @Suffix_del)
				OR (@Suffix_ins IS NULL AND @Suffix_del IS NOT NULL)
				OR (@Suffix_ins IS NOT NULL AND @Suffix_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'Suffix', 
					@Separator = ', '

			IF	(@PUserId_ins <> @PUserId_del)
