				OR (@TOC_ins IS NOT NULL AND @TOC_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'TOC', 
					@Separator = ', '

			IF	(@Slot_ins <> @Slot_del)
				OR (@Slot_ins IS NULL AND @Slot_del IS NOT NULL)
				OR (@Slot_ins IS NOT NULL AND @Slot_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'Slot', 
					@Separator = ', '

			IF	(@SSN_ins <> @SSN_del)
				OR (@SSN_ins IS NULL AND @SSN_del IS NOT NULL)
				OR (@SSN_ins IS NOT NULL AND @SSN_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'SSN', 
					@Separator = ', '

			IF	(@SpecialtyId_ins <> @SpecialtyId_del)
				OR (@SpecialtyId_ins IS NULL AND @SpecialtyId_del IS NOT NULL)
				OR (@SpecialtyId_ins IS NOT NULL AND @SpecialtyId_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'SpecialtyId', 
					@Separator = ', '

			IF	(@Specialty_ins <> @Specialty_del)
				OR (@Specialty_ins IS NULL AND @Specialty_del IS NOT NULL)
				OR (@Specialty_ins IS NOT NULL AND @Specialty_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'Specialty', 
					@Separator = ', '

			IF	(@BillUnderGroupNPI_ins <> @BillUnderGroupNPI_del)
				OR (@BillUnderGroupNPI_ins IS NULL AND @BillUnderGroupNPI_del IS NOT NULL)
				OR (@BillUnderGroupNPI_ins IS NOT NULL AND @BillUnderGroupNPI_del IS NULL)
			SELECT	@HXComments = @HXComments + @Separator + 'BillUnderGroupNPI', 
					@Separator = ', '

			IF	(@Signature_ins <> @Signature_del)
				OR (@Signature_ins IS NULL AND @Signature_del IS NOT NULL)
