							IF	(@IsDefault_ins <> @IsDefault_del)
						OR (@IsDefault_ins IS NULL AND @IsDefault_del IS NOT NULL)
						OR (@IsDefault_ins IS NOT NULL AND @IsDefault_del IS NULL)
					SELECT	@HXComments = @HXComments + @Separator + 'IsDefault', 
							@Separator = ', '
					

		IF @HXComments <> 'Changed Fields: '
			INSERT INTO H_Provider(					
						ProviderId,
	UId,
	PracticeId,
	LastName,
	FirstName,
	Middle,
	Suffix,
	PUserId,
	Prefix,
	FacilityId,
	IsActive,
	License,
	TOC,
	Slot,
	SSN,
	SpecialtyId,
	Specialty,
	BillUnderGroupNPI,
	Signature,
	CreatedBy,
	CreatedDate,
	ModifiedBy,
	ModifiedDate,
	IsDefault,
	ActivityType,
	HXComments	
)
			SELECT	
	Id,
	UId,
	PracticeId,
	LastName,
	FirstName,
	Middle,
	Suffix,
	PUserId,
	Prefix,
	FacilityId,
	IsActive,
	License,
	TOC,
	Slot,
	SSN,
	SpecialtyId,
	Specialty,
	BillUnderGroupNPI,
	null,
	CreatedBy,
	CreatedDate,
	ModifiedBy,
	ModifiedDate,
	IsDefault,
						'UPDATED', 
					@HXComments
			FROM	inserted
			WHERE	[Id] = @Id

		FETCH NEXT FROM cur_Update_Provider INTO @Id
	END

	CLOSE cur_Update_Provider
	DEALLOCATE cur_Update_Provider
	


GO



